/**
 * acceptDirectConversation — Clears the is_request flag for the current user
 * on a given conversation. Call this when:
 * - User replies to a request conversation
 * - User explicitly accepts from the message requests screen
 *
 * POST /acceptDirectConversation
 * { conversation_id: string (canonical_id) }
 */
import { createClientFromRequest } from 'npm:@base44/sdk@0.8.23';

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user) return Response.json({ error: 'Unauthorized' }, { status: 401 });

    const { conversation_id } = await req.json();
    if (!conversation_id) return Response.json({ error: 'conversation_id required' }, { status: 400 });

    const sr = base44.asServiceRole;
    // conversation_id is the conversation_key (sorted user_id pair)
    const convos = await sr.entities.DirectConversation.filter({ conversation_key: conversation_id });
    if (!convos.length) return Response.json({ error: 'Conversation not found' }, { status: 404 });

    const convo = convos[0];
    // Verify current user is the request_recipient before clearing
    if (convo.request_recipient_id !== user.id && convo.participant_a_id !== user.id && convo.participant_b_id !== user.id) {
      return Response.json({ error: 'Not a participant' }, { status: 403 });
    }

    // Clear is_request flag — conversation becomes normal DM
    // Also update last_message_at so it sorts to top of inbox
    await sr.entities.DirectConversation.update(convo.id, {
      is_request: false,
      request_recipient_id: null,
      last_message_at: new Date().toISOString(),
    });

    // Also clear is_request on all Message records in this conversation
    const msgs = await sr.entities.Message.filter({ conversation_id, is_request: true });
    await Promise.all(msgs.map(m => sr.entities.Message.update(m.id, { is_request: false })));

    return Response.json({ ok: true });
  } catch (err) {
    console.error('[acceptDirectConversation]', err.message);
    return Response.json({ error: err.message }, { status: 500 });
  }
});

/**
 * acknowledgeTimeout — Persists the user's acknowledgment of their active timeout.
 * Writes timeout_acknowledged_for = user.timeout_until on the User record.
 * This suppresses the popup for this exact timeout instance only.
 * If a new timeout is issued later (different timeout_until), acknowledgment won't match → popup shows again.
 */
import { createClientFromRequest } from 'npm:@base44/sdk@0.8.23';

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user) return Response.json({ ok: false, error: 'Unauthorized' }, { status: 401 });

    // User must actually be in timeout to acknowledge it
    if (!user.timeout_until) {
      return Response.json({ ok: false, error: 'No active timeout to acknowledge' }, { status: 400 });
    }

    const now = new Date();
    const timeoutEnd = new Date(user.timeout_until);

    // If timeout already expired, don't bother writing — just return ok
    if (now >= timeoutEnd) {
      return Response.json({ ok: true, already_expired: true });
    }

    // Already acknowledged this same timeout instance
    if (user.timeout_acknowledged_for === user.timeout_until) {
      return Response.json({ ok: true, already_acknowledged: true });
    }

    // Persist acknowledgment tied to this exact timeout_until value
    await base44.asServiceRole.entities.User.update(user.id, {
      timeout_acknowledged_for: user.timeout_until,
    });

    return Response.json({ ok: true, acknowledged_for: user.timeout_until });
  } catch (error) {
    console.error('[acknowledgeTimeout]', error.message);
    return Response.json({ ok: false, error: error.message }, { status: 500 });
  }
});

/**
 * adminAdjustUserCredits
 *
 * Step 2 of the admin credit adjustment flow.
 * Verifies the OTP, then transactionally applies the credit change
 * and writes a full audit log entry.
 *
 * Security guarantees:
 * - Owner-only (xenodekuu@gmail.com)
 * - OTP must be valid, unexpired, unused, matching the exact action params
 * - Max 5 verification attempts per code before it's locked
 * - Idempotency: action_id prevents duplicate execution on retry
 * - Negative balance safe: remove cannot exceed current balance (clamps to 0)
 * - Full immutable audit log entry written on every attempt (success or fail)
 */
import { createClientFromRequest } from 'npm:@base44/sdk@0.8.23';

const OWNER_EMAIL = 'xenodekuu@gmail.com';
const MAX_ATTEMPTS = 5;

Deno.serve(async (req) => {
  const base44 = createClientFromRequest(req);
  let user = null;

  try {
    user = await base44.auth.me();

    // Owner-only gate
    if (!user || user.email !== OWNER_EMAIL) {
      return Response.json({ error: 'Forbidden: owner access only' }, { status: 403 });
    }

    const body = await req.json();
    const {
      code_id,
      verification_code,
      action_id,      // client-generated UUID for idempotency
      target_user_id,
      adjustment_type,
      reason,
    } = body;

    // Always parse as integer — prevents string concatenation bugs (e.g. "1" + 9 = "19")
    const adjustment_amount = parseInt(body.adjustment_amount, 10);

    if (!code_id || !verification_code || !action_id || !target_user_id || !adjustment_type || !reason) {
      return Response.json({ error: 'Missing required fields' }, { status: 400 });
    }
    if (isNaN(adjustment_amount) || adjustment_amount < 1) {
      return Response.json({ error: 'adjustment_amount must be a positive integer' }, { status: 400 });
    }

    // Idempotency check: if action_id already exists, return its result
    const existing = await base44.asServiceRole.entities.AdminCreditAuditLog.filter({ action_id }).catch(() => []);
    if (existing.length > 0) {
      const prev = existing[0];
      if (prev.status === 'success') {
        return Response.json({
          success: true,
          idempotent: true,
          message: 'Action already executed successfully',
          credits_before: prev.credits_before,
          credits_after: prev.credits_after,
        });
      }
    }

    const now = new Date();

    // Fetch the verification code record
    const codeRecords = await base44.asServiceRole.entities.OwnerVerificationCode.filter({ id: code_id }).catch(() => []);
    const codeRecord = codeRecords[0];

    const ip = req.headers.get('cf-connecting-ip') || req.headers.get('x-forwarded-for') || 'unknown';
    const userAgent = req.headers.get('user-agent') || 'unknown';

    // ── VALIDATION CHAIN ──────────────────────────────────────────────────
    if (!codeRecord) {
      await writeAuditLog(base44, { action_id, admin_user_id: user.id, admin_email: user.email, target_user_id, adjustment_type, adjustment_amount, reason, status: 'failed', failure_reason: 'Code record not found', ip_address: ip, user_agent: userAgent });
      return Response.json({ error: 'Verification code not found' }, { status: 400 });
    }

    if (codeRecord.used) {
      await writeAuditLog(base44, { action_id, admin_user_id: user.id, admin_email: user.email, target_user_id, adjustment_type, adjustment_amount, reason, status: 'failed', failure_reason: 'Code already used', verification_code_id: code_id, ip_address: ip, user_agent: userAgent });
      return Response.json({ error: 'Verification code already used' }, { status: 400 });
    }

    if (new Date(codeRecord.expires_at) < now) {
      await writeAuditLog(base44, { action_id, admin_user_id: user.id, admin_email: user.email, target_user_id, adjustment_type, adjustment_amount, reason, status: 'failed', failure_reason: 'Code expired', verification_code_id: code_id, ip_address: ip, user_agent: userAgent });
      return Response.json({ error: 'Verification code has expired. Please request a new one.' }, { status: 400 });
    }

    // Increment attempts BEFORE checking (prevents race condition)
    const newAttempts = (codeRecord.attempts || 0) + 1;
    await base44.asServiceRole.entities.OwnerVerificationCode.update(code_id, { attempts: newAttempts }).catch(() => {});

    if (newAttempts > MAX_ATTEMPTS) {
      await writeAuditLog(base44, { action_id, admin_user_id: user.id, admin_email: user.email, target_user_id, adjustment_type, adjustment_amount, reason, status: 'failed', failure_reason: 'Max attempts exceeded', verification_code_id: code_id, ip_address: ip, user_agent: userAgent });
      return Response.json({ error: 'Too many failed attempts. Code is locked. Request a new code.' }, { status: 429 });
    }

    // Verify the action params match the code record
    if (
      codeRecord.target_user_id !== target_user_id ||
      codeRecord.adjustment_type !== adjustment_type ||
      String(codeRecord.adjustment_amount) !== String(adjustment_amount)
    ) {
      await writeAuditLog(base44, { action_id, admin_user_id: user.id, admin_email: user.email, target_user_id, adjustment_type, adjustment_amount, reason, status: 'failed', failure_reason: 'Code params mismatch', verification_code_id: code_id, ip_address: ip, user_agent: userAgent });
      return Response.json({ error: 'Verification code does not match the requested action' }, { status: 400 });
    }

    // Hash and compare the submitted code
    const submittedHash = await hashCode(verification_code);
    if (submittedHash !== codeRecord.code_hash) {
      const remaining = MAX_ATTEMPTS - newAttempts;
      await writeAuditLog(base44, { action_id, admin_user_id: user.id, admin_email: user.email, target_user_id, adjustment_type, adjustment_amount, reason, status: 'failed', failure_reason: `Wrong code (attempt ${newAttempts}/${MAX_ATTEMPTS})`, verification_code_id: code_id, ip_address: ip, user_agent: userAgent });
      return Response.json({
        error: 'Invalid verification code',
        attempts_remaining: Math.max(0, remaining),
      }, { status: 400 });
    }

    // ── CODE IS VALID — mark as used immediately to prevent replay ──
    await base44.asServiceRole.entities.OwnerVerificationCode.update(code_id, {
      used: true,
      used_at: now.toISOString(),
    });

    // ── APPLY CREDIT CHANGE ───────────────────────────────────────────────
    // Get current banked credits
    const ledgerEntries = await base44.asServiceRole.entities.ReferralRewardLedger.filter({
      user_id: target_user_id,
      credit_state: 'earned',
    }).catch(() => []);
    // Always parseInt — DB may return numeric strings, causing concatenation bugs
    const currentBanked = ledgerEntries.reduce((sum, e) => sum + parseInt(e.credits_remaining || 0, 10), 0);

    let creditsBefore = currentBanked;
    let creditsAfter;
    let appliedAmount = adjustment_amount; // already parseInt'd above

    if (adjustment_type === 'add') {
      // Add credits: create a new ledger entry with admin_adjustment source
      creditsAfter = creditsBefore + appliedAmount;
      await base44.asServiceRole.entities.ReferralRewardLedger.create({
        user_id: target_user_id,
        reward_type: 'recipe_generation_credit',
        credit_amount: appliedAmount,
        credit_state: 'earned',
        credits_remaining: appliedAmount,
        earned_at: now.toISOString(),
        source_referral_attribution_id: `admin_adjustment:${action_id}`,
        revoke_reason: null,
      });
    } else {
      // Remove credits: consume from oldest entries first (FIFO)
      // Safe rule: if removing more than available, remove all (clamp to 0)
      const toRemove = Math.min(adjustment_amount, currentBanked);
      appliedAmount = toRemove;
      creditsAfter = Math.max(0, currentBanked - toRemove);

      if (toRemove === 0) {
        creditsAfter = 0;
      } else {
        let remaining = toRemove;
        const sorted = ledgerEntries
          .filter(e => (e.credits_remaining || 0) > 0)
          .sort((a, b) => new Date(a.created_date) - new Date(b.created_date));

        for (const entry of sorted) {
          if (remaining <= 0) break;
          const available = entry.credits_remaining || 0;
          const consume = Math.min(available, remaining);
          const newRemaining = available - consume;
          const newState = newRemaining <= 0 ? 'consumed' : 'earned';
          await base44.asServiceRole.entities.ReferralRewardLedger.update(entry.id, {
            credits_remaining: newRemaining,
            credit_state: newState,
            consumed_at: newState === 'consumed' ? now.toISOString() : undefined,
            revoke_reason: `admin_removal:${action_id}`,
          });
          remaining -= consume;
        }
      }
    }

    // ── WRITE AUDIT LOG ───────────────────────────────────────────────────
    const targetUsers = await base44.asServiceRole.entities.User.filter({ id: target_user_id }).catch(() => []);
    const targetEmail = targetUsers[0]?.email || 'unknown';

    await writeAuditLog(base44, {
      action_id,
      admin_user_id: user.id,
      admin_email: user.email,
      target_user_id,
      target_user_email: targetEmail,
      adjustment_type,
      adjustment_amount: appliedAmount,
      credits_before: creditsBefore,
      credits_after: creditsAfter,
      reason,
      verification_code_id: code_id,
      verification_status: 'verified',
      status: 'success',
      ip_address: ip,
      user_agent: userAgent,
    });

    // ── CREATE USER REWARD EVENT (real-time popup trigger for recipient) ──
    // Only for credit additions — removals don't get a popup
    if (adjustment_type === 'add' && appliedAmount > 0) {
      await base44.asServiceRole.entities.UserRewardEvent.create({
        recipient_user_id: target_user_id,
        reward_type: 'admin_grant',
        credit_amount: appliedAmount,
        credits_after: creditsAfter,
        custom_message: reason, // admin-entered reason becomes the popup message
        source_action_id: action_id,
        is_seen: false,
      }).catch(err => console.warn('[CREDIT_ADJUST] Failed to create reward event:', err.message));
    }

    console.log(`[CREDIT_ADJUST] VERIFIED admin=${user.email} target=${target_user_id}`);
    console.log(`[CREDIT_ADJUST] before_balance=${creditsBefore} delta_input=${adjustment_amount} applied_delta=${appliedAmount} computed_after=${creditsAfter} stored_after=${creditsAfter}`);
    console.log(`[CREDIT_ADJUST] type=${adjustment_type} clamped=${appliedAmount < adjustment_amount}`);

    return Response.json({
      success: true,
      adjustment_type,
      applied_amount: appliedAmount,
      requested_amount: adjustment_amount,
      credits_before: creditsBefore,
      credits_after: creditsAfter,
      clamped: appliedAmount < adjustment_amount,
      message: `Successfully ${adjustment_type === 'add' ? 'added' : 'removed'} ${appliedAmount} credits`,
    });

  } catch (err) {
    console.error('[adminAdjustUserCredits]', err.message);
    // Write failed audit log
    if (user) {
      await writeAuditLog(base44, {
        action_id: `err_${Date.now()}`,
        admin_user_id: user.id,
        admin_email: user.email,
        target_user_id: 'unknown',
        adjustment_type: 'add',
        adjustment_amount: 0,
        reason: 'internal_error',
        status: 'failed',
        failure_reason: err.message,
      }).catch(() => {});
    }
    return Response.json({ error: err.message }, { status: 500 });
  }
});

async function hashCode(code) {
  const encoder = new TextEncoder();
  const data = encoder.encode(code + '_reciply_credit_salt');
  const hashBuffer = await crypto.subtle.digest('SHA-256', data);
  const hashArray = Array.from(new Uint8Array(hashBuffer));
  return hashArray.map(b => b.toString(16).padStart(2, '0')).join('');
}

async function writeAuditLog(base44, fields) {
  try {
    await base44.asServiceRole.entities.AdminCreditAuditLog.create({
      ...fields,
      timestamp: new Date().toISOString(),
    });
  } catch (err) {
    console.error('[AUDIT_LOG] Failed to write audit log:', err.message);
  }
}

