import { createClientFromRequest } from 'npm:@base44/sdk@0.8.21';

/**
 * Get all content (posts, recipes, comments) for admin panel
 */
Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();

    if (!user || user.role !== 'admin') {
      return Response.json({ ok: false, error: 'Admin access required' }, { status: 403 });
    }

    const { content_type = 'all', search = '', limit = 50 } = await req.json();

    let items = [];

    // Fetch posts (for moderation and appeals)
    if (content_type === 'post' || content_type === 'all') {
      const posts = await base44.asServiceRole.entities.Post.list('-created_date', limit);
      if (search) {
        const q = search.toLowerCase();
        items.push(...posts.filter(p => p.title && p.title.toLowerCase().includes(q)).map(p => ({ ...p, content_type: 'post' })));
      } else {
        items.push(...posts.map(p => ({ ...p, content_type: 'post' })));
      }
    }

    if (content_type === 'recipe' || content_type === 'all') {
      const recipes = await base44.asServiceRole.entities.Recipe.list('-created_date', limit);
      // Only show community/user-posted recipes (source='user'), exclude AI-generated (source='generated')
      const communityRecipes = recipes.filter(r => r.source === 'user' && r.is_public);
      if (search) {
        const q = search.toLowerCase();
        items.push(...communityRecipes.filter(r => r.title && r.title.toLowerCase().includes(q)).map(r => ({ ...r, content_type: 'recipe' })));
      } else {
        items.push(...communityRecipes.map(r => ({ ...r, content_type: 'recipe' })));
      }
    }

    if (content_type === 'comment' || content_type === 'all') {
      const comments = await base44.asServiceRole.entities.PostComment.list('-created_date', limit);
      if (search) {
        const q = search.toLowerCase();
        items.push(...comments.filter(c => c.body && c.body.toLowerCase().includes(q)).map(c => ({ ...c, content_type: 'comment' })));
      } else {
        items.push(...comments.map(c => ({ ...c, content_type: 'comment' })));
      }
    }

    return Response.json({ 
      ok: true, 
      items: items.slice(0, limit),
      total: items.length,
    });
  } catch (error) {
    console.error('adminGetContent error:', error);
    return Response.json({ ok: false, error: error.message }, { status: 500 });
  }
});

