/**
 * adminGetSupportTickets — Returns all SupportTicket records for admin inbox
 * Admin-only. Returns sorted by received_at DESC.
 */
import { createClientFromRequest } from 'npm:@base44/sdk@0.8.25';

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user || user.role !== 'admin') {
      return Response.json({ error: 'Admin access required' }, { status: 403 });
    }

    const tickets = await base44.asServiceRole.entities.SupportTicket.list('-created_date', 200);

    // Filter out soft-deleted tickets
    const active = tickets.filter(t => !t.is_deleted);

    // Sort by received_at if available, then created_date
    const sorted = [...active].sort((a, b) => {
      const aTime = new Date(a.received_at || a.created_date || 0).getTime();
      const bTime = new Date(b.received_at || b.created_date || 0).getTime();
      return bTime - aTime;
    });

    return Response.json({ tickets: sorted });
  } catch (err) {
    console.error('[ADMIN_GET_TICKETS]', err.message);
    return Response.json({ error: err.message }, { status: 500 });
  }
});

import { createClientFromRequest } from 'npm:@base44/sdk@0.8.21';

/**
 * Get all users with search/filter capabilities for admin panel.
 * Batch-joins subscription data to return admin_plan_label: "PRO" | "FREE"
 */
Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();

    if (!user || user.role !== 'admin') {
      return Response.json({ ok: false, error: 'Admin access required' }, { status: 403 });
    }

    const { search = '', limit = 50, status_filter = 'all' } = await req.json();

    let users = await base44.asServiceRole.entities.User.list('-created_date', limit * 2);

    // Filter by status
    if (status_filter !== 'all') {
      users = users.filter(u => u.account_status === status_filter);
    }

    // Search by name or email
    if (search) {
      const q = search.toLowerCase();
      users = users.filter(u =>
        (u.full_name && u.full_name.toLowerCase().includes(q)) ||
        (u.email && u.email.toLowerCase().includes(q))
      );
    }

    const sliced = users.slice(0, limit);

    // Batch-fetch all subscriptions once, then join by email
    let allSubs = [];
    try {
      allSubs = await base44.asServiceRole.entities.Subscription.list('-created_date', 2000);
    } catch (_) {}

    const now = Date.now();
    // Build map: email → isPro
    const subMap = {};
    for (const sub of allSubs) {
      if (!sub.created_by) continue;
      const isActivePro =
        ['pro', 'vip', 'trial'].includes(sub.plan_type) &&
        (
          sub.status === 'active' ||
          sub.status === 'trialing' ||
          (sub.status === 'canceled' && sub.current_period_end && new Date(sub.current_period_end).getTime() > now) ||
          (sub.plan_type === 'trial' && sub.trial_end && new Date(sub.trial_end).getTime() > now)
        );
      if (isActivePro) subMap[sub.created_by] = true;
    }

    const enriched = sliced.map(u => ({
      ...u,
      admin_plan_label: subMap[u.email] ? 'PRO' : 'FREE',
    }));

    return Response.json({
      ok: true,
      users: enriched,
      total: users.length,
    });
  } catch (error) {
    console.error('adminGetUsers error:', error);
    return Response.json({ ok: false, error: error.message }, { status: 500 });
  }
});

/**
 * adminModerateAction — Admin-only: apply a moderation action globally.
 * Actions: remove_content, restore_content, suspend_user, unsuspend_user, dismiss_report, resolve_report
 * Uses moderation_status lifecycle on Post entity.
 * Invalidates related notifications on content removal.
 */
import { createClientFromRequest } from 'npm:@base44/sdk@0.8.20';

const REASON_MAP = {
  spam: { title: 'Spam', description: 'This content was identified as spam or repetitive posting.' },
  duplicate: { title: 'Duplicate Content', description: 'This content duplicates another post.' },
  policy_violation: { title: 'Policy Violation', description: 'This content violates our community guidelines.' },
  misleading_content: { title: 'Misleading Content', description: 'This content contains misleading or inaccurate information.' },
  inappropriate_media: { title: 'Inappropriate Media', description: 'This content contains media that violates our media policy.' },
  copyright_issue: { title: 'Copyright Issue', description: 'This content may infringe on intellectual property rights.' },
  manual_review_action: { title: 'Admin Review', description: 'This content was removed after admin review.' },
  other: { title: 'Policy Violation', description: 'This content was removed for violating our community policies.' },
};

Deno.serve(async (req) => {
  if (req.method !== 'POST') return Response.json({ error: 'Method not allowed' }, { status: 405 });

  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();

    if (!user || user.role !== 'admin') {
      return Response.json({ error: 'Forbidden: Admin access required' }, { status: 403 });
    }

    const {
      action, report_id, target_type, target_id, reporter_user_id,
      reason_code = 'manual_review_action', reason_text = '',
    } = await req.json();
    const sr = base44.asServiceRole;

    switch (action) {

      case 'remove_content': {
        if (target_type === 'post') {
          const posts = await sr.entities.Post.filter({ id: target_id });
          if (!posts[0]) return Response.json({ error: 'Post not found' }, { status: 404 });
          const post = posts[0];

          const reasonInfo = REASON_MAP[reason_code] || REASON_MAP.manual_review_action;

          // Update post to removed_by_moderation lifecycle state (NOT deleted — owner can still see shell)
          await sr.entities.Post.update(target_id, {
            moderation_status: 'removed_by_moderation',
            community_visible: false,
            status: 'removed',
            removed_at: new Date().toISOString(),
            removed_reason_code: reason_code,
            removed_reason_text: reason_text || reasonInfo.description,
            removed_by_admin_id: user.id,
            appeal_status: 'none',
          });

          // Invalidate all public-facing notifications that reference this post
          try {
            const postNotifs = await sr.entities.Notification.filter({ post_id: target_id });
            for (const notif of postNotifs) {
              if (notif.is_active !== false) {
                await sr.entities.Notification.update(notif.id, {
                  is_active: false,
                  invalidated_at: new Date().toISOString(),
                  invalidation_reason: 'post_removed_by_moderation',
                });
              }
            }
            // Also invalidate by recipe_id if the post has one
            if (post.recipe_id) {
              const recipeNotifs = await sr.entities.Notification.filter({ recipe_id: post.recipe_id });
              for (const notif of recipeNotifs.filter(n => n.is_active !== false && n.type !== 'moderation')) {
                await sr.entities.Notification.update(notif.id, {
                  is_active: false,
                  invalidated_at: new Date().toISOString(),
                  invalidation_reason: 'post_removed_by_moderation',
                });
              }
            }
          } catch (e) {
            console.warn('[adminModerateAction] Could not invalidate notifications:', e.message);
          }

          // Send moderation notification to post owner via sendBasicNotification (0-LLM)
          if (post.author_id) {
            const reasonInfo2 = REASON_MAP[reason_code] || REASON_MAP.other;
            await sr.functions.invoke('sendBasicNotification', {
              type: 'system_alert',
              recipientId: post.author_id,
              data: {
                title: 'Your recipe was removed',
                body: `Your recipe "${post.title}" was removed: ${reasonInfo2.title}. Tap to learn more and appeal.`,
                deepLink: `/RemovedPostDetail?id=${target_id}`,
                entityType: 'post',
                entityId: target_id,
              },
            }).catch(() => {});
          }

        } else if (target_type === 'recipe') {
          const recipes = await sr.entities.Recipe.filter({ id: target_id });
          if (recipes[0]) {
            // CRITICAL: set moderation_status NOT just is_public (which collapses to private)
            await sr.entities.Recipe.update(target_id, {
              is_public: false,
              community_visible: false,
              moderation_status: 'removed_by_moderation',
              author_account_status: recipes[0].author_account_status || 'active',
            });
            // Invalidate recipe like/save notifications
            try {
              const recNotifs = await sr.entities.Notification.filter({ recipe_id: target_id });
              for (const notif of recNotifs.filter(n => n.is_active !== false && n.type !== 'moderation')) {
                await sr.entities.Notification.update(notif.id, {
                  is_active: false,
                  invalidated_at: new Date().toISOString(),
                  invalidation_reason: 'post_removed_by_moderation',
                });
              }
            } catch (_) {}
          }
        } else if (target_type === 'comment') {
          const postComments = await sr.entities.PostComment.filter({ id: target_id });
          if (postComments[0]) await sr.entities.PostComment.delete(target_id);
          const groupComments = await sr.entities.GroupPostComment.filter({ id: target_id });
          if (groupComments[0]) await sr.entities.GroupPostComment.delete(target_id);
        } else if (target_type === 'group') {
          const groups = await sr.entities.Group.filter({ id: target_id });
          if (groups[0]) await sr.entities.Group.delete(target_id);
        }

        if (report_id) await sr.entities.Report.update(report_id, { status: 'resolved' });
        return Response.json({ ok: true, action, target_type, target_id });
      }

      case 'restore_content': {
        if (target_type === 'post') {
          const posts = await sr.entities.Post.filter({ id: target_id });
          if (!posts[0]) return Response.json({ error: 'Post not found' }, { status: 404 });

          await sr.entities.Post.update(target_id, {
            moderation_status: 'restored',
            community_visible: true,
            status: 'active',
            removed_at: null,
            removed_reason_code: null,
            removed_reason_text: null,
            removed_by_admin_id: null,
            appeal_status: posts[0].appeal_status === 'under_review' ? 'accepted' : posts[0].appeal_status,
            appeal_reviewed_at: new Date().toISOString(),
            appeal_reviewed_by: user.id,
          });

          // Also restore the linked Recipe's moderation_status
          if (posts[0].recipe_id) {
            await sr.entities.Recipe.update(posts[0].recipe_id, {
              is_public: true,
              community_visible: true,
              moderation_status: 'active',
            }).catch(() => {});
          }

          // Notify owner
          if (posts[0].author_id) {
            await sr.entities.Notification.create({
              type: 'moderation',
              title: 'Your recipe has been restored',
              message: `Good news! Your recipe "${posts[0].title}" has been restored and is now public again.`,
              recipient_id: posts[0].author_id,
              from_user_id: user.id,
              from_user_name: 'Reciply Moderation',
              is_read: false,
              is_active: true,
              post_id: target_id,
              entity_type: 'post',
              entity_id: target_id,
              payload_json: JSON.stringify({ action_type: 'content_restored', post_id: target_id }),
            }).catch(() => {});
          }
        }
        if (report_id) await sr.entities.Report.update(report_id, { status: 'resolved' });
        return Response.json({ ok: true, action, target_type, target_id });
      }

      case 'suspend_user': {
        if (!target_id) return Response.json({ error: 'target_id required' }, { status: 400 });
        await sr.entities.User.update(target_id, { account_status: 'suspended' });
        const userPosts = await sr.entities.Post.filter({ author_id: target_id });
        await Promise.all(userPosts.map(p => sr.entities.Post.update(p.id, {
          community_visible: false,
          author_account_status: 'suspended',
        })));
        const userRecipes = await sr.entities.Recipe.filter({ author_id: target_id, is_public: true });
        await Promise.all(userRecipes.map(r => sr.entities.Recipe.update(r.id, {
          community_visible: false,
          author_account_status: 'suspended',
        })));
        if (report_id) await sr.entities.Report.update(report_id, { status: 'resolved' });
        return Response.json({ ok: true, action, target_id });
      }

      case 'unsuspend_user': {
        if (!target_id) return Response.json({ error: 'target_id required' }, { status: 400 });
        await sr.entities.User.update(target_id, { account_status: 'active' });
        const userPosts = await sr.entities.Post.filter({ author_id: target_id });
        await Promise.all(userPosts.map(p => sr.entities.Post.update(p.id, {
          community_visible: true,
          author_account_status: 'active',
        })));
        const userRecipes = await sr.entities.Recipe.filter({ author_id: target_id });
        await Promise.all(userRecipes.map(r => sr.entities.Recipe.update(r.id, {
          community_visible: true,
          author_account_status: 'active',
        })));
        if (report_id) await sr.entities.Report.update(report_id, { status: 'resolved' });
        return Response.json({ ok: true, action, target_id });
      }

      case 'resolve_report': {
        if (!report_id) return Response.json({ error: 'report_id required' }, { status: 400 });
        await sr.entities.Report.update(report_id, { status: 'resolved' });
        return Response.json({ ok: true, action, report_id });
      }

      case 'dismiss_report': {
        if (!report_id) return Response.json({ error: 'report_id required' }, { status: 400 });
        await sr.entities.Report.update(report_id, { status: 'dismissed' });
        return Response.json({ ok: true, action, report_id });
      }

      case 'mark_in_review': {
        if (!report_id) return Response.json({ error: 'report_id required' }, { status: 400 });
        await sr.entities.Report.update(report_id, { status: 'in_review' });
        return Response.json({ ok: true, action, report_id });
      }

      default:
        return Response.json({ error: `Unknown action: ${action}` }, { status: 400 });
    }

  } catch (err) {
    console.error('[ADMIN_MODERATE_ACTION]', err.message);
    return Response.json({ error: err.message }, { status: 500 });
  }
});

import { createClientFromRequest } from 'npm:@base44/sdk@0.8.23';

/**
 * Enhanced Admin Moderation Actions
 * Supports: warn, timeout (preset durations), ban, remove_post + full audit logging
 * All actions write a ModerationLog record as authoritative audit trail.
 */

const TIMEOUT_DURATIONS = {
  '1h': 1 * 60 * 60 * 1000,
  '1d': 1 * 24 * 60 * 60 * 1000,
  '3d': 3 * 24 * 60 * 60 * 1000,
  '1w': 7 * 24 * 60 * 60 * 1000,
  '1m': 30 * 24 * 60 * 60 * 1000,
  '1y': 365 * 24 * 60 * 60 * 1000,
};

const REASON_MAP = {
  spam: 'This content was identified as spam or repetitive posting.',
  duplicate: 'This content was found to be a duplicate of another post.',
  policy_violation: 'This content violates our community guidelines.',
  misleading_content: 'This content contained misleading or inaccurate information.',
  inappropriate_media: 'This content contained media that violates our media policy.',
  copyright_issue: 'This content may infringe on intellectual property rights.',
  manual_review_action: 'This content was removed after admin review.',
  other: 'This content was removed for violating our community policies.',
};

async function writeAuditLog(sr, { action_type, target_type, target_id, target_summary, performed_by, performed_by_email, reason_text, reason_code, duration_key, timeout_end_at, duration_ms, report_id, metadata_json }) {
  try {
    await sr.entities.ModerationLog.create({
      action_type,
      target_type,
      target_id,
      target_summary: target_summary || '',
      performed_by,
      performed_by_email,
      reason_text: reason_text || null,
      reason_code: reason_code || null,
      duration_key: duration_key || null,
      timeout_end_at: timeout_end_at || null,
      duration_ms: duration_ms || null,
      report_id: report_id || null,
      metadata_json: metadata_json || null,
    });
  } catch (e) {
    console.warn('[adminModerationEnhanced] audit log write failed:', e.message);
  }
}

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();

    if (!user || user.role !== 'admin') {
      return Response.json({ ok: false, error: 'Admin access required' }, { status: 403 });
    }

    const {
      action,
      target_id,
      target_type = 'user',
      reason = '',
      reason_code = null,
      // Timeout-specific
      duration_key = '1d',       // '1h'|'1d'|'3d'|'1w'|'1m'|'1y'
      timeout_end_at = null,     // ISO string if pre-computed by client
      report_id = null,
    } = await req.json();

    const sr = base44.asServiceRole;
    let result = { ok: false };

    // ─── warn_user ────────────────────────────────────────────────────────────
    if (action === 'warn_user') {
      const users = await sr.entities.User.filter({ id: target_id });
      const targetUser = users[0];
      if (!targetUser) return Response.json({ ok: false, error: 'User not found' }, { status: 404 });

      const newWarnCount = (targetUser.warn_count || 0) + 1;
      await sr.entities.User.update(target_id, { warn_count: newWarnCount });

      await writeAuditLog(sr, {
        action_type: 'warn',
        target_type: 'user',
        target_id,
        target_summary: targetUser.email || targetUser.full_name,
        performed_by: user.id,
        performed_by_email: user.email,
        reason_text: reason || null,
        metadata_json: JSON.stringify({ previous_warn_count: targetUser.warn_count || 0, new_warn_count: newWarnCount }),
      });

      await sr.functions.invoke('sendModeractionNotification', {
        user_id: target_id,
        action_type: 'warned',
        reason: reason || 'Community guidelines violation',
        action_date: new Date().toISOString(),
        should_show_modal: true,
      }).catch(() => {});

      result = { ok: true, new_warn_count: newWarnCount };
    }

    // ─── remove_single_warning ───────────────────────────────────────────────
    else if (action === 'remove_single_warning') {
      const users = await sr.entities.User.filter({ id: target_id });
      const targetUser = users[0];
      if (!targetUser) return Response.json({ ok: false, error: 'User not found' }, { status: 404 });
      if ((targetUser.warn_count || 0) <= 0) return Response.json({ ok: false, error: 'No warnings to remove' }, { status: 400 });

      const newWarnCount = (targetUser.warn_count || 0) - 1;
      await sr.entities.User.update(target_id, { warn_count: newWarnCount });

      await writeAuditLog(sr, {
        action_type: 'warning_removed',
        target_type: 'user',
        target_id,
        target_summary: targetUser.email || targetUser.full_name,
        performed_by: user.id,
        performed_by_email: user.email,
        reason_text: reason || null,
        metadata_json: JSON.stringify({ previous_warn_count: targetUser.warn_count, new_warn_count: newWarnCount }),
      });

      result = { ok: true, new_warn_count: newWarnCount };
    }

    // ─── timeout_user ─────────────────────────────────────────────────────────
    else if (action === 'timeout_user') {
      const users = await sr.entities.User.filter({ id: target_id });
      const targetUser = users[0];
      if (!targetUser) return Response.json({ ok: false, error: 'User not found' }, { status: 404 });

      // Compute expiry from duration_key or use provided timeout_end_at
      const durationMs = TIMEOUT_DURATIONS[duration_key] || TIMEOUT_DURATIONS['1d'];
      const expiryAt = timeout_end_at || new Date(Date.now() + durationMs).toISOString();

      await sr.entities.User.update(target_id, {
        timeout_until: expiryAt,
        timeout_reason: reason || null,
        timeout_acknowledged_for: null, // reset ack so popup shows for new timeout instance
      });

      await writeAuditLog(sr, {
        action_type: 'timeout',
        target_type: 'user',
        target_id,
        target_summary: targetUser.email || targetUser.full_name,
        performed_by: user.id,
        performed_by_email: user.email,
        reason_text: reason || null,
        duration_key,
        timeout_end_at: expiryAt,
        duration_ms: durationMs,
        report_id,
      });

      await sr.functions.invoke('sendModeractionNotification', {
        user_id: target_id,
        action_type: 'timeout',
        reason: reason || 'Community guidelines violation',
        duration_days: Math.round(durationMs / (24 * 60 * 60 * 1000) * 10) / 10,
        timeout_until: expiryAt,
        action_date: new Date().toISOString(),
        should_show_modal: true,
      }).catch(() => {});

      result = { ok: true, timeout_until: expiryAt, duration_key };
    }

    // ─── remove_timeout_user ──────────────────────────────────────────────────
    else if (action === 'remove_timeout_user') {
      const users = await sr.entities.User.filter({ id: target_id });
      const targetUser = users[0];
      await sr.entities.User.update(target_id, {
        timeout_until: null,
        timeout_reason: null,
        timeout_acknowledged_for: null,
      });

      await writeAuditLog(sr, {
        action_type: 'timeout',
        target_type: 'user',
        target_id,
        target_summary: targetUser?.email || targetUser?.full_name || '',
        performed_by: user.id,
        performed_by_email: user.email,
        reason_text: 'Timeout removed by admin',
        metadata_json: JSON.stringify({ action: 'remove_timeout' }),
      });

      result = { ok: true };
    }

    // ─── ban_user ─────────────────────────────────────────────────────────────
    else if (action === 'ban_user') {
      const users = await sr.entities.User.filter({ id: target_id });
      const targetUser = users[0];
      if (!targetUser) return Response.json({ ok: false, error: 'User not found' }, { status: 404 });

      await sr.entities.User.update(target_id, {
        account_status: 'suspended',
        banned_until: '2099-12-31',
      });

      // Hide all user content from public
      const userPosts = await sr.entities.Post.filter({ author_id: target_id });
      await Promise.all(userPosts.map(p => sr.entities.Post.update(p.id, {
        community_visible: false,
        author_account_status: 'suspended',
      })));
      const userRecipes = await sr.entities.Recipe.filter({ author_id: target_id, is_public: true });
      await Promise.all(userRecipes.map(r => sr.entities.Recipe.update(r.id, {
        community_visible: false,
        author_account_status: 'suspended',
      })));

      await writeAuditLog(sr, {
        action_type: 'ban',
        target_type: 'user',
        target_id,
        target_summary: targetUser.email || targetUser.full_name,
        performed_by: user.id,
        performed_by_email: user.email,
        reason_text: reason || null,
        report_id,
      });

      await sr.functions.invoke('sendModeractionNotification', {
        user_id: target_id,
        action_type: 'banned',
        reason: reason || 'Permanent ban issued by moderation team.',
        action_date: new Date().toISOString(),
        should_show_modal: true,
      }).catch(() => {});

      result = { ok: true };
    }

    // ─── unban_user ───────────────────────────────────────────────────────────
    else if (action === 'unban_user') {
      const users = await sr.entities.User.filter({ id: target_id });
      const targetUser = users[0];

      await sr.entities.User.update(target_id, {
        account_status: 'active',
        banned_until: null,
      });

      await writeAuditLog(sr, {
        action_type: 'unban',
        target_type: 'user',
        target_id,
        target_summary: targetUser?.email || targetUser?.full_name || '',
        performed_by: user.id,
        performed_by_email: user.email,
        reason_text: reason || null,
      });

      await sr.functions.invoke('sendModeractionNotification', {
        user_id: target_id,
        action_type: 'unbanned',
        reason: 'Your ban has been lifted.',
        action_date: new Date().toISOString(),
        should_show_modal: true,
      }).catch(() => {});

      result = { ok: true };
    }

    // ─── remove_content (post) ────────────────────────────────────────────────
    // CRITICAL: sets moderation_status = removed_by_moderation, NOT is_public = false
    // This is a separate moderation state — must not collapse into normal private
    else if (action === 'remove_content') {
      if (target_type === 'post') {
        const posts = await sr.entities.Post.filter({ id: target_id });
        const post = posts[0];
        if (!post) return Response.json({ ok: false, error: 'Post not found' }, { status: 404 });

        const resolvedReasonCode = reason_code || 'manual_review_action';
        const reasonDescription = reason || REASON_MAP[resolvedReasonCode] || REASON_MAP.manual_review_action;

        // Set moderation lifecycle state — NOT a privacy mutation
        await sr.entities.Post.update(target_id, {
          moderation_status: 'removed_by_moderation',
          community_visible: false,
          status: 'removed',
          removed_at: new Date().toISOString(),
          removed_reason_code: resolvedReasonCode,
          removed_reason_text: reasonDescription,
          removed_by_admin_id: user.id,
          appeal_status: 'none',
        });

        // Also update the linked Recipe if present — mark it with moderation_status
        if (post.recipe_id) {
          await sr.entities.Recipe.update(post.recipe_id, {
            is_public: false,
            community_visible: false,
            moderation_status: 'removed_by_moderation',
          }).catch(() => {});
        }

        // Invalidate existing engagement notifications for this post (likes/saves/etc)
        const postNotifs = await sr.entities.Notification.filter({ post_id: target_id }).catch(() => []);
        for (const notif of postNotifs.filter(n => n.is_active !== false && n.type !== 'moderation')) {
          await sr.entities.Notification.update(notif.id, {
            is_active: false,
            invalidated_at: new Date().toISOString(),
            invalidation_reason: 'post_removed_by_moderation',
          }).catch(() => {});
        }

        // Notify owner — DUPLICATE PROTECTION: only create if no existing content_removed notification exists for this post
        if (post.author_id) {
          const existingRemovalNotifs = await sr.entities.Notification.filter({
            recipient_id: post.author_id,
            post_id: target_id,
            type: 'moderation',
          }).catch(() => []);
          const alreadyNotified = existingRemovalNotifs.some(n => {
            try { return JSON.parse(n.payload_json || '{}')?.action_type === 'content_removed'; } catch { return false; }
          });
          if (!alreadyNotified) {
            await sr.entities.Notification.create({
              type: 'moderation',
              title: 'Your post was removed',
              message: `Your post "${post.title}" was removed due to a moderation decision. Tap to view details and submit an appeal.`,
              recipient_id: post.author_id,
              from_user_id: user.id,
              from_user_name: 'Reciply Moderation',
              is_read: false,
              is_active: true,
              post_id: target_id,
              entity_type: 'post',
              entity_id: target_id,
              payload_json: JSON.stringify({
                action_type: 'content_removed',
                post_id: target_id,
                recipe_id: post.recipe_id || null,
                reason_code: resolvedReasonCode,
                reason_text: reasonDescription,
              }),
            }).catch(() => {});
          }
        }

        await writeAuditLog(sr, {
          action_type: 'remove_post',
          target_type: 'post',
          target_id,
          target_summary: post.title || 'Untitled',
          performed_by: user.id,
          performed_by_email: user.email,
          reason_text: reason || null,
          reason_code: resolvedReasonCode,
          report_id,
        });

      } else if (target_type === 'recipe') {
        // Stand-alone recipe (not linked to a post)
        const recipes = await sr.entities.Recipe.filter({ id: target_id });
        const recipe = recipes[0];
        if (recipe) {
          await sr.entities.Recipe.update(target_id, {
            is_public: false,
            community_visible: false,
            moderation_status: 'removed_by_moderation',
          });
          await writeAuditLog(sr, {
            action_type: 'remove_post',
            target_type: 'recipe',
            target_id,
            target_summary: recipe.title || 'Untitled',
            performed_by: user.id,
            performed_by_email: user.email,
            reason_text: reason || null,
          });
        }
      } else if (target_type === 'comment') {
        await sr.entities.PostComment.filter({ id: target_id }).then(async (rows) => {
          if (rows[0]) await sr.entities.PostComment.delete(target_id);
        }).catch(() => {});
        await sr.entities.GroupPostComment.filter({ id: target_id }).then(async (rows) => {
          if (rows[0]) await sr.entities.GroupPostComment.delete(target_id);
        }).catch(() => {});
      }

      if (report_id) await sr.entities.Report.update(report_id, { status: 'resolved' }).catch(() => {});
      result = { ok: true };
    }

    // ─── restore_content ──────────────────────────────────────────────────────
    else if (action === 'restore_content') {
      if (target_type === 'post') {
        const posts = await sr.entities.Post.filter({ id: target_id });
        const post = posts[0];
        if (!post) return Response.json({ ok: false, error: 'Post not found' }, { status: 404 });

        await sr.entities.Post.update(target_id, {
          moderation_status: 'restored',
          community_visible: true,
          status: 'active',
          removed_at: null,
          removed_reason_code: null,
          removed_reason_text: null,
          removed_by_admin_id: null,
          appeal_status: post.appeal_status === 'submitted' || post.appeal_status === 'under_review' ? 'accepted' : post.appeal_status,
          appeal_reviewed_at: new Date().toISOString(),
          appeal_reviewed_by: user.id,
        });

        // Restore linked recipe if present
        if (post.recipe_id) {
          await sr.entities.Recipe.update(post.recipe_id, {
            is_public: true,
            community_visible: true,
            moderation_status: 'active',
          }).catch(() => {});
        }

        if (post.author_id) {
          await sr.entities.Notification.create({
            type: 'moderation',
            title: 'Your recipe has been restored',
            message: `Good news! Your recipe "${post.title}" has been restored and is now visible again.`,
            recipient_id: post.author_id,
            from_user_id: user.id,
            from_user_name: 'Reciply Moderation',
            is_read: false,
            is_active: true,
            post_id: target_id,
          }).catch(() => {});
        }

        await writeAuditLog(sr, {
          action_type: 'restore_post',
          target_type: 'post',
          target_id,
          target_summary: post.title || 'Untitled',
          performed_by: user.id,
          performed_by_email: user.email,
          reason_text: reason || null,
          report_id,
        });
      }

      if (report_id) await sr.entities.Report.update(report_id, { status: 'resolved' }).catch(() => {});
      result = { ok: true };
    }

    // ─── suspend_user / unsuspend_user ────────────────────────────────────────
    else if (action === 'suspend_user') {
      await sr.entities.User.update(target_id, { account_status: 'suspended' });
      const userPosts = await sr.entities.Post.filter({ author_id: target_id });
      await Promise.all(userPosts.map(p => sr.entities.Post.update(p.id, { community_visible: false, author_account_status: 'suspended' })));
      const userRecipes = await sr.entities.Recipe.filter({ author_id: target_id, is_public: true });
      await Promise.all(userRecipes.map(r => sr.entities.Recipe.update(r.id, { community_visible: false, author_account_status: 'suspended' })));
      if (report_id) await sr.entities.Report.update(report_id, { status: 'resolved' }).catch(() => {});
      await writeAuditLog(sr, { action_type: 'suspend_user', target_type: 'user', target_id, performed_by: user.id, performed_by_email: user.email, reason_text: reason || null });
      result = { ok: true };
    }

    else if (action === 'unsuspend_user') {
      await sr.entities.User.update(target_id, { account_status: 'active' });
      const userPosts = await sr.entities.Post.filter({ author_id: target_id });
      await Promise.all(userPosts.map(p => sr.entities.Post.update(p.id, { community_visible: true, author_account_status: 'active' })));
      const userRecipes = await sr.entities.Recipe.filter({ author_id: target_id });
      await Promise.all(userRecipes.map(r => sr.entities.Recipe.update(r.id, { community_visible: true, author_account_status: 'active' })));
      if (report_id) await sr.entities.Report.update(report_id, { status: 'resolved' }).catch(() => {});
      await writeAuditLog(sr, { action_type: 'unsuspend_user', target_type: 'user', target_id, performed_by: user.id, performed_by_email: user.email });
      result = { ok: true };
    }

    else {
      return Response.json({ ok: false, error: `Unknown action: ${action}` }, { status: 400 });
    }

    return Response.json(result);
  } catch (error) {
    console.error('[adminModerationEnhanced]', error.message);
    return Response.json({ ok: false, error: error.message }, { status: 500 });
  }
});

/**
 * adminRequestCreditVerification
 *
 * Step 1 of the admin credit adjustment flow.
 * Sends a 6-digit OTP to the owner Gmail (xenodekuu@gmail.com) and
 * creates a short-lived OwnerVerificationCode record.
 *
 * Security:
 * - Only the owner admin email can call this
 * - Rate limited: max 5 pending codes (prevents spam)
 * - Code expires in 10 minutes
 * - Code is stored hashed (SHA-256), never plaintext
 */
import { createClientFromRequest } from 'npm:@base44/sdk@0.8.23';

const OWNER_EMAIL = 'xenodekuu@gmail.com';
const CODE_EXPIRY_MINUTES = 10;
const MAX_PENDING_CODES = 5;

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();

    if (!user || user.email !== OWNER_EMAIL) {
      return Response.json({ error: 'Forbidden: owner access only' }, { status: 403 });
    }

    const body = await req.json();
    const { target_user_id, target_user_email, adjustment_type, adjustment_amount, reason } = body;

    if (!target_user_id || !adjustment_type || !adjustment_amount || !reason) {
      return Response.json({ error: 'Missing required fields' }, { status: 400 });
    }
    if (!['add', 'remove'].includes(adjustment_type)) {
      return Response.json({ error: 'adjustment_type must be "add" or "remove"' }, { status: 400 });
    }
    if (typeof adjustment_amount !== 'number' || adjustment_amount < 1 || adjustment_amount > 10000) {
      return Response.json({ error: 'adjustment_amount must be between 1 and 10000' }, { status: 400 });
    }

    const now = new Date();

    // Rate limit: count recent pending codes
    const recentCodes = await base44.asServiceRole.entities.OwnerVerificationCode.filter({
      sent_to_email: OWNER_EMAIL,
      used: false,
    }).catch(() => []);
    const activePending = recentCodes.filter(c => new Date(c.expires_at) > now);
    if (activePending.length >= MAX_PENDING_CODES) {
      return Response.json({
        error: 'Too many pending verification codes. Please wait before requesting another.',
        retry_after_seconds: 60,
      }, { status: 429 });
    }

    // Generate 6-digit OTP
    const code = String(Math.floor(100000 + Math.random() * 900000));
    const expiresAt = new Date(now.getTime() + CODE_EXPIRY_MINUTES * 60 * 1000);
    const codeHash = await hashCode(code);
    const purpose = `credit_adjustment:${target_user_id}:${adjustment_type}:${adjustment_amount}`;

    // Store hashed code FIRST so it exists even if email fails
    const codeRecord = await base44.asServiceRole.entities.OwnerVerificationCode.create({
      code_hash: codeHash,
      purpose,
      target_user_id,
      adjustment_type,
      adjustment_amount,
      reason,
      expires_at: expiresAt.toISOString(),
      used: false,
      attempts: 0,
      sent_to_email: OWNER_EMAIL,
    });

    // Attempt to send OTP email — capture full details for debugging
    const emailResult = await sendVerificationEmail(code, adjustment_type, adjustment_amount, target_user_email, reason, expiresAt);

    console.log(`[CREDIT_VERIFY] Result: email_sent=${emailResult.sent}, status=${emailResult.http_status}, resend_id=${emailResult.resend_id || 'none'}`);
    if (!emailResult.sent) {
      console.error(`[CREDIT_VERIFY] EMAIL FAILED — provider_error: ${emailResult.provider_error}`);
      console.error(`[CREDIT_VERIFY] Response body: ${emailResult.response_body}`);
    }

    return Response.json({
      success: emailResult.sent,
      code_id: codeRecord.id,
      expires_at: expiresAt.toISOString(),
      email_sent: emailResult.sent,
      // Always expose delivery details so the UI can report them clearly
      email_details: {
        recipient: OWNER_EMAIL,
        sender: 'Reciply Admin <onboarding@resend.dev>',
        http_status: emailResult.http_status,
        resend_id: emailResult.resend_id || null,
        provider_error: emailResult.provider_error || null,
      },
      // If email failed, surface the reason so UI can block advancing
      error: emailResult.sent ? undefined : `Email delivery failed: ${emailResult.provider_error || 'Unknown error from Resend'}`,
      message: emailResult.sent
        ? `Verification code sent to ${OWNER_EMAIL}. Expires in ${CODE_EXPIRY_MINUTES} minutes.`
        : `Code created but email delivery FAILED — ${emailResult.provider_error}`,
    });
  } catch (err) {
    console.error('[adminRequestCreditVerification] Fatal:', err.message, err.stack);
    return Response.json({ error: err.message }, { status: 500 });
  }
});

async function hashCode(code) {
  const encoder = new TextEncoder();
  const data = encoder.encode(code + '_reciply_credit_salt');
  const hashBuffer = await crypto.subtle.digest('SHA-256', data);
  return Array.from(new Uint8Array(hashBuffer)).map(b => b.toString(16).padStart(2, '0')).join('');
}

async function sendVerificationEmail(code, type, amount, targetEmail, reason, expiresAt) {
  const RESEND_API_KEY = Deno.env.get('RESEND_API_KEY');
  if (!RESEND_API_KEY) {
    const msg = 'RESEND_API_KEY secret is not configured';
    console.error('[CREDIT_VERIFY]', msg);
    return { sent: false, http_status: null, provider_error: msg, response_body: null };
  }

  const actionText = type === 'add' ? `ADD +${amount}` : `REMOVE -${amount}`;
  const expiryText = expiresAt.toLocaleTimeString('en-IL', { timeZone: 'Asia/Jerusalem', hour: '2-digit', minute: '2-digit' });

  const html = `
    <div style="font-family: Arial, sans-serif; max-width: 500px; margin: 0 auto; padding: 24px; background: #0a0b0f; color: #e2e8f0; border-radius: 12px;">
      <div style="background: linear-gradient(135deg, #dc2626, #991b1b); padding: 16px 24px; border-radius: 8px; margin-bottom: 24px;">
        <h2 style="color: white; margin: 0; font-size: 18px;">⚠️ OWNER ACTION REQUIRED</h2>
        <p style="color: rgba(255,255,255,0.8); margin: 4px 0 0; font-size: 13px;">Reciply Admin Credit Adjustment</p>
      </div>
      <p style="color: #94a3b8; font-size: 14px; margin-bottom: 16px;">A manual credit adjustment has been requested:</p>
      <div style="background: rgba(255,255,255,0.06); border: 1px solid rgba(255,255,255,0.1); border-radius: 8px; padding: 16px; margin-bottom: 20px;">
        <div style="margin-bottom: 8px;"><span style="color: #64748b; font-size: 13px;">Action: </span><span style="color: ${type === 'add' ? '#10b981' : '#ef4444'}; font-weight: bold;">${actionText} credits</span></div>
        <div style="margin-bottom: 8px;"><span style="color: #64748b; font-size: 13px;">Target User: </span><span style="color: #e2e8f0; font-size: 13px;">${targetEmail || 'Unknown'}</span></div>
        <div><span style="color: #64748b; font-size: 13px;">Reason: </span><span style="color: #cbd5e1; font-size: 13px;">${reason}</span></div>
      </div>
      <div style="text-align: center; background: rgba(99,102,241,0.15); border: 2px solid rgba(99,102,241,0.4); border-radius: 12px; padding: 24px; margin-bottom: 20px;">
        <p style="color: #94a3b8; font-size: 13px; margin: 0 0 12px;">Your verification code:</p>
        <div style="font-size: 40px; font-weight: 900; letter-spacing: 8px; color: #818cf8; font-family: monospace;">${code}</div>
        <p style="color: #64748b; font-size: 12px; margin: 12px 0 0;">Expires at ${expiryText} IL time</p>
      </div>
      <p style="color: #475569; font-size: 12px; text-align: center;">If you did not request this, someone may have unauthorized access to your admin account.</p>
    </div>
  `;

  // NOTE: Using resend.dev sandbox sender — works without domain verification.
  // To use a custom sender like security@reciply.app, the domain must be verified in Resend.
  const FROM_SENDER = 'Reciply Admin <onboarding@resend.dev>';

  console.log(`[CREDIT_VERIFY] Sending email via Resend: from="${FROM_SENDER}" to="${OWNER_EMAIL}" subject="Verify Credit Adjustment: ${actionText}"`);

  try {
    const res = await fetch('https://api.resend.com/emails', {
      method: 'POST',
      headers: {
        'Authorization': `Bearer ${RESEND_API_KEY}`,
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({
        from: FROM_SENDER,
        to: [OWNER_EMAIL],
        subject: `🔐 Verify Credit Adjustment: ${actionText} credits`,
        html,
      }),
    });

    const http_status = res.status;
    let responseData = null;
    try { responseData = await res.json(); } catch (_) {}

    const response_body = JSON.stringify(responseData);
    console.log(`[CREDIT_VERIFY] Resend HTTP ${http_status}: ${response_body}`);

    if (res.ok) {
      return { sent: true, http_status, resend_id: responseData?.id || null, response_body };
    } else {
      const provider_error = responseData?.message || responseData?.error || `HTTP ${http_status}`;
      console.error(`[CREDIT_VERIFY] Resend rejected: ${provider_error}`);
      return { sent: false, http_status, provider_error, response_body };
    }
  } catch (err) {
    console.error('[CREDIT_VERIFY] Fetch to Resend failed:', err.message);
    return { sent: false, http_status: null, provider_error: err.message, response_body: null };
  }
}

/**
 * adminReviewAppeal — Full restoration + algorithm reinsertion system.
 *
 * APPEAL APPROVED flow:
 *   1. Validate admin + post state
 *   2. Full atomic state transition:
 *      - moderation_status → active
 *      - appeal_status → accepted
 *      - visibility flags restored
 *      - reinsertion_phase = 'warmup'
 *      - reinsertion_weight = 0.25  (starts dampened, not full boost)
 *      - restored_at, restored_by_admin_id set
 *      - original engagement preserved (no wipe)
 *   3. Audit log written to ModerationLog
 *   4. Owner notification sent
 *
 * REINSERTION PHASE MODEL:
 *   warmup       → reinsertion_weight starts at 0.25
 *                  Scheduled job (progressReinsertionPhases) advances this over 48h
 *   reintegrated → reinsertion_weight = 1.0, full ranking
 *
 * ANTI-ABUSE:
 *   - reinsertion_weight NEVER exceeds 1.0
 *   - restored_at is NOT used as created_at (freshness = original created_date)
 *   - moderation_restore_count tracks repeat restore cycles
 *   - weight advances based on TIME + engagement quality, not just time
 */
import { createClientFromRequest } from 'npm:@base44/sdk@0.8.23';

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user?.id || user.role !== 'admin') {
      return Response.json({ error: 'Admin access required' }, { status: 403 });
    }

    const { post_id, decision, decision_reason = '' } = await req.json();
    if (!post_id || !['accept', 'reject'].includes(decision)) {
      return Response.json({ error: 'post_id and decision (accept|reject) required' }, { status: 400 });
    }

    const sr = base44.asServiceRole;
    const posts = await sr.entities.Post.filter({ id: post_id });
    if (!posts[0]) return Response.json({ error: 'Post not found' }, { status: 404 });
    const post = posts[0];

    // Validate the post is in a reviewable state
    const reviewableStates = ['appealed', 'removed_by_moderation'];
    const reviewableAppeals = ['submitted', 'under_review'];
    if (!reviewableStates.includes(post.moderation_status) && !reviewableAppeals.includes(post.appeal_status)) {
      return Response.json({
        error: 'Post is not in a reviewable state',
        moderation_status: post.moderation_status,
        appeal_status: post.appeal_status,
      }, { status: 400 });
    }

    const now = new Date().toISOString();

    if (decision === 'accept') {
      // ── FULL RESTORATION STATE TRANSITION ─────────────────────────────────────
      // Anti-abuse: track how many times this post has been restored
      const restoreCount = (post.moderation_restore_count || 0) + 1;

      // Starting reinsertion weight — dampened at restore, NOT a boost
      // Repeated restores get even lower starting weight (anti-gaming)
      const startingWeight = restoreCount === 1 ? 0.25 : Math.max(0.10, 0.25 - (restoreCount - 1) * 0.05);

      // Restore original visibility from before removal
      // community_visible was set false by admin removal — restore it
      const wasOriginallyPublic = post.type === 'community';

      await sr.entities.Post.update(post_id, {
        // ── Core moderation state ──
        moderation_status: 'active',
        status: 'active',
        appeal_status: 'accepted',
        appeal_reviewed_at: now,
        appeal_reviewed_by: user.id,
        appeal_decision_reason: decision_reason || null,

        // ── Visibility restoration ──
        community_visible: wasOriginallyPublic,
        personal_profile_visible: true,

        // ── Restoration metadata ──
        restored_at: now,
        restored_by_admin_id: user.id,
        last_moderation_action_at: now,

        // ── Algorithm reinsertion — controlled warmup, NOT instant full boost ──
        reinsertion_phase: 'warmup',
        reinsertion_weight: startingWeight,
        reinsertion_started_at: now,
        moderation_restore_count: restoreCount,

        // ── PRESERVE engagement data — DO NOT WIPE ──
        // like_count, comment_count, save_count, rating_bayes etc. remain untouched
        // created_date remains untouched (freshness uses original date, NOT restored_at)
      });

      // ── CRITICAL: Also restore the linked Recipe entity moderation status ──────
      // The Recipe entity has its own moderation_status field used by:
      //   - RecipeDetail gating (recipeIsModRemoved)
      //   - VipRecipeCard removed UI (isModRemoved)
      //   - homeMyRecipes / profile recipe lists
      // If Recipe.moderation_status stays 'removed_by_moderation', the post will:
      //   - still show removed UI in cards
      //   - still cause RecipeDetail → RemovedPostDetail redirect loop
      //   - still be missing from owner recipe lists
      if (post.recipe_id) {
        await sr.entities.Recipe.update(post.recipe_id, {
          moderation_status: 'active',
          is_public: wasOriginallyPublic,
          community_visible: wasOriginallyPublic,
        }).catch(e => console.warn('[adminReviewAppeal] recipe restore failed:', e.message));
      }

      // ── AUDIT LOG ─────────────────────────────────────────────────────────────
      await sr.entities.ModerationLog.create({
        action_type: 'restore_post',
        target_type: 'post',
        target_id: post_id,
        target_summary: post.title,
        performed_by: user.id,
        performed_by_email: user.email,
        reason_text: decision_reason || 'Appeal accepted',
        metadata_json: JSON.stringify({
          appeal_category: post.appeal_category,
          appeal_message: post.appeal_message,
          reinsertion_weight: startingWeight,
          reinsertion_phase: 'warmup',
          restore_count: restoreCount,
          previous_moderation_status: post.moderation_status,
        }),
      }).catch(e => console.warn('[adminReviewAppeal] audit log failed:', e.message));

      // ── OWNER NOTIFICATION — DUPLICATE PROTECTION ────────────────────────────
      if (post.author_id) {
        const existingAcceptNotifs = await sr.entities.Notification.filter({
          recipient_id: post.author_id,
          post_id,
          type: 'moderation',
        }).catch(() => []);
        const alreadyNotifiedAccepted = existingAcceptNotifs.some(n => {
          try { return JSON.parse(n.payload_json || '{}')?.action_type === 'appeal_accepted'; } catch { return false; }
        });
        if (!alreadyNotifiedAccepted) {
          await sr.entities.Notification.create({
            type: 'moderation',
            title: 'Appeal Accepted',
            message: `Your appeal for "${post.title}" was accepted. Your post is live again.${decision_reason ? ' ' + decision_reason : ''}`,
            recipient_id: post.author_id,
            from_user_id: user.id,
            from_user_name: 'Reciply Moderation',
            is_read: false,
            is_active: true,
            post_id,
            entity_type: 'post',
            entity_id: post_id,
            payload_json: JSON.stringify({
              action_type: 'appeal_accepted',
              post_id,
              recipe_id: post.recipe_id || null,
              decision_reason,
              reinsertion_phase: 'warmup',
            }),
          }).catch(() => {});
        }
      }

      console.log('[adminReviewAppeal] ACCEPTED', {
        post_id, adminId: user.id,
        reinsertion_weight: startingWeight,
        restore_count: restoreCount,
      });

      return Response.json({
        ok: true,
        decision: 'accept',
        post_id,
        reinsertion_phase: 'warmup',
        reinsertion_weight: startingWeight,
        restore_count: restoreCount,
      });

    } else {
      // ── REJECTION ─────────────────────────────────────────────────────────────
      await sr.entities.Post.update(post_id, {
        moderation_status: 'removed_by_moderation',
        appeal_status: 'rejected',
        appeal_reviewed_at: now,
        appeal_reviewed_by: user.id,
        appeal_decision_reason: decision_reason || null,
        last_moderation_action_at: now,
      });

      // Audit log
      await sr.entities.ModerationLog.create({
        action_type: 'remove_post',
        target_type: 'post',
        target_id: post_id,
        target_summary: post.title,
        performed_by: user.id,
        performed_by_email: user.email,
        reason_text: decision_reason || 'Appeal rejected — removal upheld',
        metadata_json: JSON.stringify({
          appeal_category: post.appeal_category,
          decision: 'reject',
        }),
      }).catch(e => console.warn('[adminReviewAppeal] audit log failed:', e.message));

      // DUPLICATE PROTECTION: only one appeal_rejected notification per post
      if (post.author_id) {
        const existingRejectNotifs = await sr.entities.Notification.filter({
          recipient_id: post.author_id,
          post_id,
          type: 'moderation',
        }).catch(() => []);
        const alreadyNotifiedRejected = existingRejectNotifs.some(n => {
          try { return JSON.parse(n.payload_json || '{}')?.action_type === 'appeal_rejected'; } catch { return false; }
        });
        if (!alreadyNotifiedRejected) {
          await sr.entities.Notification.create({
            type: 'moderation',
            title: 'Appeal Declined',
            message: `Your appeal for "${post.title}" was reviewed. The removal decision has been upheld.${decision_reason ? ' ' + decision_reason : ''}`,
            recipient_id: post.author_id,
            from_user_id: user.id,
            from_user_name: 'Reciply Moderation',
            is_read: false,
            is_active: true,
            post_id,
            entity_type: 'post',
            entity_id: post_id,
            payload_json: JSON.stringify({
              action_type: 'appeal_rejected',
              post_id,
              recipe_id: post.recipe_id || null,
              decision_reason,
            }),
          }).catch(() => {});
        }
      }

      console.log('[adminReviewAppeal] REJECTED', { post_id, adminId: user.id });
      return Response.json({ ok: true, decision: 'reject', post_id });
    }

  } catch (error) {
    console.error('[adminReviewAppeal] error:', error);
    return Response.json({ error: error.message }, { status: 500 });
  }
});

/**
 * adminSendPushNotification — Admin notification send pipeline (V2)
 *
 * Upgraded with:
 *   - Deterministic content targeting via resolveNotificationTarget
 *   - Real deep links to specific recipes/posts
 *   - Full destination metadata in FCM payload + history
 *   - Anti-spam cooldown enforcement
 *   - Candidate preview mode (dry_run)
 *   - Detailed delivery logging with reason tracking
 */

import { createClientFromRequest } from 'npm:@base44/sdk@0.8.25';

// ── NOTIFICATION SPECS ───────────────────────────────────────────────────────
const NOTIFICATION_SPECS = {
  daily_reminder: { title: "You've got recipes waiting 🍳", body: "Reciply saved you some ideas for today. Don't let them go to waste", deepLink: '/Home', destination_type: 'home' },
  streak_reminder: { title: 'Your streak is still alive 🔥', body: 'Reciply is counting on you. Cook, log, or create something to keep it going', deepLink: '/Home', destination_type: 'home' },
  streak_continued: { title: "Let's gooo 🎯", body: "Reciply streak secured for today. You're building something real", deepLink: '/Home', destination_type: 'home' },
  streak_lost: { title: 'You were on fire 💔', body: 'Your Reciply streak ended, but you can start again today and go even further', deepLink: '/Home', destination_type: 'home' },
  likes: { title: 'People are loving your recipe ❤️', body: 'Your recipe is getting attention on Reciply.', deepLink: '/Notifications', destination_type: 'notifications' },
  follow: { title: "You've got a new follower 👤", body: 'Someone just followed you on Reciply.', deepLink: '/Notifications', destination_type: 'notifications' },
  comment: { title: 'New comment on your recipe 💬', body: 'Someone interacted with your recipe on Reciply.', deepLink: '/Notifications', destination_type: 'notifications' },
  cook_mode_return: { title: 'Your recipe is waiting 👨‍🍳', body: 'You started something on Reciply. Jump back in!', deepLink: '/Generate', destination_type: 'generate' },
  missing_ingredients: { title: "You're almost ready 🍅", body: "You're just a few ingredients away.", deepLink: '/Pantry', destination_type: 'pantry' },
  limit_reached: { title: 'You reached your limit 🔒', body: "Unlock more and keep creating.", deepLink: '/ProFunnel', destination_type: 'pro_funnel' },
  reset: { title: 'Fresh recipes unlocked 🎉', body: 'Your recipes are ready again.', deepLink: '/Generate', destination_type: 'generate' },
  motivation_chef: { title: "You're becoming a chef 🏆", body: 'Every time you cook, you improve.', deepLink: '/Generate', destination_type: 'generate' },
  motivation_save_money: { title: 'Cooking saves you real money 💰', body: "Every meal at home is money you keep.", deepLink: '/Generate', destination_type: 'generate' },
  motivation_start_cooking: { title: 'Start cooking today 🍽️', body: "Just start once, that's how it begins.", deepLink: '/Generate', destination_type: 'generate' },
};

// Strategy types that require content resolution
const STRATEGY_TYPES = new Set([
  'breakup_style_comeback', 'low_cost_meal_upgrade',
  'takeout_temptation_blocker', 'zero_waste_rescue', 'lazy_energy_saver',
]);

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const admin = await base44.auth.me();
    if (!admin || admin.role !== 'admin') {
      return Response.json({ error: 'Admin access required' }, { status: 403 });
    }

    const body = await req.json();
    const {
      user_id,
      notification_type,
      send_mode = 'now',
      scheduled_time,
      is_admin_override = false,
      dry_run = false, // preview mode — resolve target but don't send
    } = body;

    if (!user_id) return Response.json({ error: 'user_id is required' }, { status: 400 });
    if (!notification_type) return Response.json({ error: 'notification_type is required' }, { status: 400 });

    const sr = base44.asServiceRole;
    const isStrategy = STRATEGY_TYPES.has(notification_type);

    // ── RESOLVE TARGET USER ──────────────────────────────────────────────────
    const users = await sr.entities.User.filter({ id: user_id }, null, 1).catch(() => []);
    const targetUser = users[0];
    if (!targetUser) return Response.json({ error: 'User not found' }, { status: 404 });

    // ── STRATEGY RESOLUTION ──────────────────────────────────────────────────
    let resolvedTarget = null;

    if (isStrategy) {
      const resolveRes = await base44.functions.invoke('resolveNotificationTarget', {
        strategy: notification_type,
        target_user_id: user_id,
      }).catch(err => ({ data: { resolved: false, reason: 'resolve_error', message: err.message } }));

      resolvedTarget = resolveRes.data;

      if (!resolvedTarget?.resolved) {
        if (dry_run) {
          return Response.json({
            preview: true,
            resolved: false,
            reason: resolvedTarget?.reason || 'unknown',
            message: resolvedTarget?.message || 'No content found',
            expiring_ingredients: resolvedTarget?.expiring_ingredients || null,
          });
        }
        // Not a dry run but no content — log and abort
        await logHistory(sr, user_id, notification_type, null, admin.id, 0, 0, 'no_content', {
          reason: resolvedTarget?.reason,
        });
        return Response.json({
          success: false,
          sent: 0,
          reason: resolvedTarget?.reason || 'no_content',
          message: resolvedTarget?.message || 'No matching content found for this strategy.',
        });
      }

      // DRY RUN — return preview without sending
      if (dry_run) {
        return Response.json({
          preview: true,
          resolved: true,
          ...resolvedTarget,
        });
      }
    } else {
      // Normal notification type — use static spec
      if (!NOTIFICATION_SPECS[notification_type]) {
        return Response.json({ error: `Invalid notification_type: ${notification_type}` }, { status: 400 });
      }
    }

    // ── BUILD NOTIFICATION PAYLOAD ───────────────────────────────────────────
    const spec = NOTIFICATION_SPECS[notification_type];
    const title = resolvedTarget?.title || spec?.title || 'Reciply';
    const bodyText = resolvedTarget?.body || spec?.body || '';
    const deepLink = resolvedTarget?.deep_link || spec?.deepLink || '/Home';
    const destinationType = resolvedTarget?.destination_type || spec?.destination_type || 'home';
    const destinationId = resolvedTarget?.destination_id || null;
    const candidateScore = resolvedTarget?.score || null;
    const sendReason = resolvedTarget?.reason || 'admin_manual';

    // ── SCHEDULE MODE ────────────────────────────────────────────────────────
    if (send_mode === 'scheduled' && scheduled_time) {
      await sr.entities.NotificationQueue.create({
        user_id,
        event_id: crypto.randomUUID(),
        dedupe_key: `admin|${user_id}|${notification_type}|${Date.now()}`,
        notification_type,
        title,
        description: bodyText,
        priority: 1,
        status: 'pending',
        scheduled_time,
        is_admin_override,
        admin_user_id: admin.id,
        context: { deep_link: deepLink, destination_type: destinationType, destination_id: destinationId },
      });

      return Response.json({ success: true, scheduled: true, message: `Scheduled for ${scheduled_time}`, deep_link: deepLink, destination_type: destinationType, destination_id: destinationId });
    }

    // ── SEND NOW ─────────────────────────────────────────────────────────────
    const tokens = await sr.entities.DeviceToken.filter({
      created_by: targetUser.email,
      is_enabled: true,
    }).catch(() => []);

    const fcmKey = Deno.env.get('FCM_SERVER_KEY');

    if (!tokens.length) {
      await logHistory(sr, user_id, notification_type, { title, body: bodyText }, admin.id, 0, 0, 'no_tokens', {
        deep_link: deepLink, destination_type: destinationType, destination_id: destinationId, send_reason: sendReason,
      });
      return Response.json({ success: true, sent: 0, total: 0, warning: 'No push devices', deep_link: deepLink, destination_type: destinationType });
    }

    if (!fcmKey) {
      return Response.json({ error: 'FCM_SERVER_KEY not configured' }, { status: 500 });
    }

    let sent = 0;
    const deliveryResults = [];
    const deadTokenIds = [];

    for (const token of tokens) {
      try {
        const resp = await fetch('https://fcm.googleapis.com/fcm/send', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json', 'Authorization': `key=${fcmKey}` },
          body: JSON.stringify({
            to: token.device_token,
            priority: 'high',
            notification: { title, body: bodyText, sound: 'default' },
            data: {
              notification_type,
              title,
              body: bodyText,
              deep_link: deepLink,
              destination_type: destinationType,
              destination_id: destinationId || '',
              send_reason: sendReason,
              created_by_admin: admin.id,
            },
            android: { priority: 'high', notification: { sound: 'default', channel_id: 'reciply_default' } },
          }),
        });

        const result = await resp.json();
        const tokenShort = token.device_token.substring(0, 15) + '...';

        if (result.success === 1) {
          sent++;
          deliveryResults.push({ token: tokenShort, status: 'delivered' });
        } else {
          const errCode = result.results?.[0]?.error || 'unknown';
          deliveryResults.push({ token: tokenShort, status: 'failed', error: errCode });
          if (errCode === 'NotRegistered' || errCode === 'InvalidRegistration') {
            deadTokenIds.push(token.id);
          }
        }
      } catch (err) {
        deliveryResults.push({ token: token.device_token.substring(0, 15) + '...', status: 'error', error: err.message });
      }
    }

    // Clean dead tokens
    for (const deadId of deadTokenIds) {
      await sr.entities.DeviceToken.update(deadId, { is_enabled: false }).catch(() => {});
    }

    // Log history with full destination data
    await logHistory(sr, user_id, notification_type, { title, body: bodyText }, admin.id, sent, tokens.length,
      sent > 0 ? 'delivered' : 'all_failed', {
        deep_link: deepLink,
        destination_type: destinationType,
        destination_id: destinationId,
        send_reason: sendReason,
        candidate_score: candidateScore,
        candidate: resolvedTarget?.candidate || null,
      }
    );

    return Response.json({
      success: sent > 0,
      sent,
      total: tokens.length,
      dead_tokens_cleaned: deadTokenIds.length,
      delivery_results: deliveryResults,
      deep_link: deepLink,
      destination_type: destinationType,
      destination_id: destinationId,
      candidate: resolvedTarget?.candidate || null,
      score: candidateScore,
      message: sent > 0 ? `Delivered to ${sent}/${tokens.length} device(s)` : 'Delivery failed',
    });
  } catch (err) {
    console.error('[adminSendPushNotification] Fatal:', err.message);
    return Response.json({ error: err.message }, { status: 500 });
  }
});

async function logHistory(sr, userId, type, spec, adminId, sent, total, outcome, extra = {}) {
  await sr.entities.NotificationHistory.create({
    user_id: userId,
    notification_type: type,
    title: spec?.title || '',
    description: spec?.body || '',
    sent_at: new Date().toISOString(),
    delivery_status: outcome,
    destination_type: extra.destination_type || 'home',
    destination_id: extra.destination_id || null,
    deep_link: extra.deep_link || '/Home',
    send_reason: extra.send_reason || 'admin_manual',
    candidate_score: extra.candidate_score || null,
    strategy_cooldown_key: `${userId}|${type}|${new Date().toISOString().split('T')[0]}`,
    context: {
      admin_id: adminId,
      fcm_sent: sent,
      fcm_total: total,
      outcome,
      source: 'admin_panel',
      candidate: extra.candidate || null,
    },
  }).catch(err => console.warn('[AdminSend] History log failed:', err.message));
}

/**
 * adminStreakManage — Admin-only streak management endpoint.
 * 
 * AUDIT-HARDENED: Reads target user's actual timezone, sets admin_set_at to
 * protect admin-written values from being overwritten by getStreakState's
 * break-detection logic for 24 hours.
 *
 * Actions:
 *   reset:      Resets streak to 0/broken
 *   set_silver:  Makes streak available (silver flame) — last action = yesterday
 *   set_count:   Sets streak to a specific day count with all required fields
 *
 * Payload: { action, target_user_id, streak_count? }
 */
import { createClientFromRequest } from 'npm:@base44/sdk@0.8.23';

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user?.id) return Response.json({ error: 'Unauthorized' }, { status: 401 });
    if (user.role !== 'admin') return Response.json({ error: 'Admin only' }, { status: 403 });

    const { action, target_user_id, streak_count } = await req.json();
    if (!target_user_id) return Response.json({ error: 'target_user_id required' }, { status: 400 });
    if (!action) return Response.json({ error: 'action required' }, { status: 400 });

    const sr = base44.asServiceRole;
    const now = new Date();

    // ── RESOLVE TARGET USER'S ACTUAL TIMEZONE ──────────────────────────────
    // Priority: StreakState.user_timezone > User.timezone > fallback 'Asia/Jerusalem'
    let targetUserTz = 'Asia/Jerusalem'; // safe fallback
    try {
      const targetUsers = await sr.entities.User.filter({ id: target_user_id });
      if (targetUsers[0]?.timezone) {
        targetUserTz = targetUsers[0].timezone;
      }
    } catch (e) {
      console.warn('[adminStreakManage] Failed to fetch target user timezone:', e.message);
    }

    // Fetch or create streak state
    const existing = await sr.entities.StreakState.filter({ user_id: target_user_id });
    let streak = existing[0];

    // Use StreakState timezone if available (most authoritative)
    if (streak?.user_timezone && streak.user_timezone !== 'UTC') {
      targetUserTz = streak.user_timezone;
    }

    const todayStr = now.toLocaleDateString('en-CA', { timeZone: targetUserTz });

    if (!streak) {
      streak = await sr.entities.StreakState.create({
        user_id: target_user_id,
        current_streak_days: 0,
        longest_streak_days: 0,
        streak_status: 'broken',
        user_timezone: targetUserTz,
        pending_break_popup: false,
        last_streak_action_date_local: todayStr,
        last_streak_action_at: now.toISOString(),
        admin_set_at: now.toISOString(),
      });
      console.log(`[adminStreakManage] Created new StreakState for ${target_user_id}, tz=${targetUserTz}`);
    }

    const beforeState = {
      current_streak_days: streak.current_streak_days,
      streak_status: streak.streak_status,
      last_streak_action_date_local: streak.last_streak_action_date_local,
    };

    let result = {};

    if (action === 'reset') {
      // ── RESET: streak → 0, broken, no popups ──────────────────────────────
      await sr.entities.StreakState.update(streak.id, {
        current_streak_days: 0,
        previous_streak_days: streak.current_streak_days || 0,
        streak_status: 'broken',
        pending_break_popup: false,
        last_streak_action_date_local: todayStr,
        last_streak_action_at: now.toISOString(),
        admin_set_at: now.toISOString(),
        user_timezone: targetUserTz,
        updated_at: now.toISOString(),
      });
      result = {
        action: 'reset',
        new_streak: 0,
        status: 'broken',
        timezone_used: targetUserTz,
        today_local: todayStr,
      };

    } else if (action === 'set_silver') {
      // ── SET SILVER: last action = yesterday → flame shows silver (available) ──
      // Preserve current_streak_days so the count is still visible.
      // FIX: Compute yesterday in the USER'S LOCAL timezone, not UTC.
      // Previously: new Date(now) - 1 day in UTC, then format in user TZ → wrong
      // when TZ offset crosses midnight (e.g. UTC+3 at 21:00 UTC = next day local).
      // Now: use todayStr (already correct local date), subtract 1 day via pure calendar math.
      const todayDateParts = todayStr.split('-').map(Number); // [YYYY, MM, DD]
      const localYesterday = new Date(todayDateParts[0], todayDateParts[1] - 1, todayDateParts[2] - 1);
      const yesterdayStr = `${localYesterday.getFullYear()}-${String(localYesterday.getMonth() + 1).padStart(2, '0')}-${String(localYesterday.getDate()).padStart(2, '0')}`;

      // For last_streak_action_at, use a timestamp that represents yesterday in the user's local TZ
      // (approximate — the exact hour doesn't matter, only the date boundary matters for streak logic)
      const yesterdayTimestamp = new Date(now.getTime() - 24 * 60 * 60 * 1000);

      await sr.entities.StreakState.update(streak.id, {
        streak_status: 'active',
        pending_break_popup: false,
        last_streak_action_date_local: yesterdayStr,
        last_streak_action_at: yesterdayTimestamp.toISOString(),
        admin_set_at: now.toISOString(),
        user_timezone: targetUserTz,
        updated_at: now.toISOString(),
      });
      result = {
        action: 'set_silver',
        current_streak_days: streak.current_streak_days,
        last_action_date: yesterdayStr,
        today_local: todayStr,
        status: 'active (silver/available)',
        timezone_used: targetUserTz,
      };

    } else if (action === 'set_count') {
      // ── SET COUNT: authoritative streak count + all supporting fields ──────
      const count = parseInt(streak_count) || 0;
      const prevDays = streak.current_streak_days || 0;

      await sr.entities.StreakState.update(streak.id, {
        current_streak_days: count,
        longest_streak_days: Math.max(count, streak.longest_streak_days || 0),
        previous_streak_days: prevDays,
        streak_status: count > 0 ? 'active' : 'broken',
        pending_break_popup: false,
        // Set last action to TODAY so getStreakState doesn't see a gap and reset it
        last_streak_action_date_local: todayStr,
        last_streak_action_at: now.toISOString(),
        // Protect from break-detection for 24h
        admin_set_at: now.toISOString(),
        user_timezone: targetUserTz,
        updated_at: now.toISOString(),
      });
      result = {
        action: 'set_count',
        new_streak: count,
        previous: prevDays,
        longest: Math.max(count, streak.longest_streak_days || 0),
        status: count > 0 ? 'active' : 'broken',
        last_action_date: todayStr,
        timezone_used: targetUserTz,
      };

    } else {
      return Response.json({ error: `Unknown action: ${action}` }, { status: 400 });
    }

    // ── READ BACK: Fetch the record we just wrote to confirm persistence ────
    let verifyState = null;
    try {
      const verify = await sr.entities.StreakState.filter({ user_id: target_user_id });
      if (verify[0]) {
        verifyState = {
          current_streak_days: verify[0].current_streak_days,
          streak_status: verify[0].streak_status,
          last_streak_action_date_local: verify[0].last_streak_action_date_local,
          admin_set_at: verify[0].admin_set_at,
          longest_streak_days: verify[0].longest_streak_days,
          user_timezone: verify[0].user_timezone,
        };
      }
    } catch (e) {
      console.warn('[adminStreakManage] verify read-back failed:', e.message);
    }

    return Response.json({
      ok: true,
      target_user_id,
      ...result,
      before: beforeState,
      verified_after: verifyState,
    });
  } catch (error) {
    console.error('[adminStreakManage]', error);
    return Response.json({ error: error.message }, { status: 500 });
  }
});

