/**
 * aiGenerate
 * POST endpoint: enforces quota, records event, increments used.
 * 
 * Body: { recipe, meal_type, cuisine, client_request_id }
 * Returns: { success, event_id, quota }
 * 
 * Idempotency: client_request_id deduplicates retries (no double-charge).
 */
import { createClientFromRequest } from 'npm:@base44/sdk@0.8.6';

function getWeeklyWindow(now, timezone) {
  try {
    const tzDate = new Date(now.toLocaleString('en-US', { timeZone: timezone }));
    const dayOfWeek = tzDate.getDay();
    const daysToMonday = dayOfWeek === 0 ? 6 : dayOfWeek - 1;
    const mondayLocal = new Date(tzDate);
    mondayLocal.setDate(tzDate.getDate() - daysToMonday);
    mondayLocal.setHours(0, 0, 0, 0);
    const offsetMs = now.getTime() - tzDate.getTime();
    const period_start = new Date(mondayLocal.getTime() + offsetMs);
    const period_end = new Date(period_start.getTime() + 7 * 24 * 60 * 60 * 1000);
    return { period_start, period_end };
  } catch (e) {
    return getWeeklyWindowUTC(now);
  }
}

function getWeeklyWindowUTC(now) {
  const d = new Date(now);
  const day = d.getUTCDay();
  const daysToMonday = day === 0 ? 6 : day - 1;
  const monday = new Date(d);
  monday.setUTCDate(d.getUTCDate() - daysToMonday);
  monday.setUTCHours(0, 0, 0, 0);
  const nextMonday = new Date(monday.getTime() + 7 * 24 * 60 * 60 * 1000);
  return { period_start: monday, period_end: nextMonday };
}

const FREE_LIMIT = 2;

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user) return Response.json({ error: 'Unauthorized' }, { status: 401 });

    const body = await req.json();
    const { recipe, meal_type, cuisine, client_request_id } = body;
    if (!recipe) return Response.json({ error: 'recipe payload required' }, { status: 400 });

    // Idempotency: check if this client_request_id already recorded
    if (client_request_id) {
      const existing = await base44.asServiceRole.entities.GeneratedRecipeEvent.filter({
        user_id: user.id,
        client_request_id,
      });
      if (existing.length > 0) {
        // Already processed — return existing event without double-charging
        const evt = existing[0];
        console.log(`[aiGenerate] Idempotent replay for ${client_request_id}`);

        // Return current quota state
        const quotaRows = await base44.asServiceRole.entities.UsageCounter.filter({
          created_by: user.email,
          feature: 'ai_generation_quota',
        });
        const used = quotaRows[0]?.count || 0;
        return Response.json({
          success: true,
          event_id: evt.id,
          idempotent_replay: true,
          quota: { limit: FREE_LIMIT, used, remaining: Math.max(0, FREE_LIMIT - used), is_premium: false },
        });
      }
    }

    // Check subscription
    const subs = await base44.asServiceRole.entities.Subscription.filter({ created_by: user.email });
    const sub = subs[0];
    const isPremium = sub && (sub.status === 'active' || sub.status === 'trialing');

    // Get timezone
    const timezone = user.timezone || 'UTC';
    const now = new Date();
    const { period_start, period_end } = getWeeklyWindow(now, timezone);
    const period_start_iso = period_start.toISOString();
    const period_end_iso = period_end.toISOString();

    // Fetch quota row
    const quotaRows = await base44.asServiceRole.entities.UsageCounter.filter({
      created_by: user.email,
      feature: 'ai_generation_quota',
    });
    let quotaRow = quotaRows[0] || null;

    // Lazy reset if needed
    const needsReset = !quotaRow || quotaRow.period_start !== period_start_iso;
    let used = 0;

    if (!quotaRow) {
      quotaRow = await base44.asServiceRole.entities.UsageCounter.create({
        feature: 'ai_generation_quota',
        week_start_date: period_start_iso.split('T')[0],
        period_start: period_start_iso,
        period_end: period_end_iso,
        count: 0,
        timezone,
      });
      used = 0;
    } else if (needsReset) {
      await base44.asServiceRole.entities.UsageCounter.update(quotaRow.id, {
        period_start: period_start_iso,
        period_end: period_end_iso,
        week_start_date: period_start_iso.split('T')[0],
        count: 0,
        timezone,
      });
      used = 0;
    } else {
      used = quotaRow.count || 0;
    }

    // Enforce limit for free users
    if (!isPremium && used >= FREE_LIMIT) {
      return Response.json({
        code: 'FREE_LIMIT_REACHED',
        message: 'Free limit reached. Resets Monday.',
        quota: { limit: FREE_LIMIT, used, remaining: 0, resets_at: period_end_iso },
      }, { status: 403 });
    }

    // Record generation event (always, even if user doesn't save)
    const eventData = {
      user_id: user.id,
      recipe_title: recipe.title || 'Generated Recipe',
      recipe_payload: JSON.stringify(recipe),
      status: 'generated',
      meal_type: meal_type || '',
      cuisine: cuisine || '',
      period_start: period_start_iso,
      period_end: period_end_iso,
    };
    if (client_request_id) eventData.client_request_id = client_request_id;

    const event = await base44.asServiceRole.entities.GeneratedRecipeEvent.create(eventData);

    // Increment used (only after successful event creation)
    let newUsed = used;
    let remaining = null;

    if (!isPremium) {
      newUsed = used + 1;
      await base44.asServiceRole.entities.UsageCounter.update(quotaRow.id, { count: newUsed });
      remaining = Math.max(0, FREE_LIMIT - newUsed);
      console.log(`[aiGenerate] user=${user.id} used=${newUsed}/${FREE_LIMIT} remaining=${remaining}`);
    }

    return Response.json({
      success: true,
      event_id: event.id,
      quota: isPremium
        ? { is_premium: true, limit: null, used: null, remaining: null, resets_at: null }
        : { is_premium: false, limit: FREE_LIMIT, used: newUsed, remaining, resets_at: period_end_iso },
    });
  } catch (err) {
    console.error('[aiGenerate]', err.message);
    return Response.json({ error: err.message }, { status: 500 });
  }
});

/**
 * aiGenerateAdvanced
 * 
 * Processes AI recipe generation with quota enforcement.
 * - Checks free user quota
 * - Creates AiGenerationEvent
 * - Increments quota.used
 * - Returns updated quota
 * 
 * Idempotent via client_request_id.
 */
import { createClientFromRequest } from 'npm:@base44/sdk@0.8.25';

Deno.serve(async (req) => {
  const startTime = Date.now();
  const requestId = crypto.randomUUID(); // Unique trace ID for entire flow

  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user) return Response.json({ error: 'Unauthorized' }, { status: 401 });

    const body = await req.json();
    const { recipe, meal_type, cuisine, client_request_id, userPrompt } = body;
    if (!recipe) return Response.json({ error: 'recipe payload required' }, { status: 400 });
    if (!client_request_id) return Response.json({ error: 'client_request_id required' }, { status: 400 });

    // Initialize telemetry collector
    const telemetry = {
      request_id: requestId,
      user_id: user.id,
      user_email: user.email,
      raw_user_request: userPrompt || '',
      first_recipe_snapshot: JSON.stringify(recipe),
      validator_result_initial: null,
      missing_concepts_detected: [],
      repair_attempt_1_triggered: false,
      repair_1_constraint_prompt: null,
      repair_1_recipe_snapshot: null,
      validator_result_after_repair_1: null,
      repair_attempt_2_triggered: false,
      repair_2_constraint_prompt: null,
      repair_2_recipe_snapshot: null,
      validator_result_after_repair_2: null,
      final_result: 'rejected', // default, updated on success
      final_accepted_recipe_id: null,
      pricing_allowed: false,
      pricing_result: null,
      image_generation_allowed: false,
      image_generation_result: null,
      auth_error: null,
      error_message: null,
      total_duration_ms: 0,
      metadata: { meal_type, cuisine, client_request_id }
    };

    // ── RECIPE INTEGRITY VALIDATION + AUTO-REPAIR LOOP ──────────────────────
    // Step 1: Validate integrity
    let validRecipe = recipe;
    let validationDebug = null;
    try {
      const integrityResult = await base44.asServiceRole.functions.invoke('recipeIntegrityValidator', {
        recipe,
        userPrompt: userPrompt || ''
      });

      // TELEMETRY: Capture initial validation
      telemetry.validator_result_initial = integrityResult.data || {};
      telemetry.missing_concepts_detected = integrityResult.data?.missing_concepts || [];

      if (integrityResult.data && !integrityResult.data.valid) {
        console.log('[aiGenerateAdvanced] Recipe failed integrity, attempting auto-repair...');
        console.log('[INTEGRITY_FAILED]', {
          missing: integrityResult.data.missing_concepts,
          issues: integrityResult.data.consistency_issues,
        });
        telemetry.repair_attempt_1_triggered = true;
        validationDebug = integrityResult.data;

        // AUTO-REPAIR ATTEMPT 1: Constrained regeneration
        const repairRes1 = await base44.asServiceRole.functions.invoke('autoRepairRecipe', {
          originalRecipe: recipe,
          userPrompt: userPrompt || '',
          failureDebug: validationDebug,
          attemptNumber: 1,
          maxAttempts: 2
        });

        // TELEMETRY: Capture Attempt 1
        telemetry.repair_1_constraint_prompt = repairRes1.data?.constraintPrompt || null;
        telemetry.repair_1_recipe_snapshot = repairRes1.data.repaired ? JSON.stringify(repairRes1.data.recipe) : null;
        telemetry.validator_result_after_repair_1 = repairRes1.data?.validationDebug || null;

        if (repairRes1.data.repaired) {
          console.log('[aiGenerateAdvanced] Auto-repair Attempt 1: SUCCESS');
          validRecipe = repairRes1.data.recipe;
          validationDebug = repairRes1.data.validationDebug;
        } else if (repairRes1.data.shouldRetry) {
          console.log('[aiGenerateAdvanced] Auto-repair Attempt 1: FAILED, retrying with stricter constraints...');
          telemetry.repair_attempt_2_triggered = true;

          // AUTO-REPAIR ATTEMPT 2: Stricter constraints
          const repairRes2 = await base44.asServiceRole.functions.invoke('autoRepairRecipe', {
            originalRecipe: recipe,
            userPrompt: userPrompt || '',
            failureDebug: repairRes1.data.validationDebug,
            attemptNumber: 2,
            maxAttempts: 2
          });

          // TELEMETRY: Capture Attempt 2
          telemetry.repair_2_constraint_prompt = repairRes2.data?.constraintPrompt || null;
          telemetry.repair_2_recipe_snapshot = repairRes2.data.repaired ? JSON.stringify(repairRes2.data.recipe) : null;
          telemetry.validator_result_after_repair_2 = repairRes2.data?.validationDebug || null;

          if (repairRes2.data.repaired) {
            console.log('[aiGenerateAdvanced] Auto-repair Attempt 2: SUCCESS');
            validRecipe = repairRes2.data.recipe;
            validationDebug = repairRes2.data.validationDebug;
          } else {
            console.log('[aiGenerateAdvanced] Auto-repair Attempt 2: FAILED - giving up');

            // TELEMETRY: Log failure
            telemetry.final_result = 'rejected';
            telemetry.error_message = 'Recipe generation failed integrity validation after 2 repair attempts';
            telemetry.total_duration_ms = Date.now() - startTime;
            await base44.asServiceRole.functions.invoke('logAiGenerationTelemetry', telemetry).catch(err =>
              console.warn('[aiGenerateAdvanced] telemetry log failed:', err.message)
            );

            return Response.json({
              error: 'Recipe generation failed integrity validation after 2 repair attempts',
              missing_concepts: repairRes2.data.validationDebug.missing_concepts,
              consistency_issues: repairRes2.data.validationDebug.consistency_issues,
              repairs_attempted: repairRes2.data.validationDebug.repairs_applied
            }, { status: 400 });
          }
        } else {
          // No retry available
          return Response.json({
            error: 'Recipe generation failed integrity validation',
            missing_concepts: validationDebug.missing_concepts,
            consistency_issues: validationDebug.consistency_issues
          }, { status: 400 });
        }
      } else if (integrityResult.data) {
        validationDebug = integrityResult.data.debug;
      }
    } catch (validationErr) {
      console.warn('[aiGenerateAdvanced] Integrity validation error (non-fatal):', validationErr.message);
      // Non-fatal — use original recipe if validation fails
    }

    // Use the validated/repaired recipe for all downstream operations
    const finalRecipeForEvent = validRecipe;

    // ── OWNER OVERRIDE: xenodekuu@gmail.com is always Pro ──────────────────
    const OWNER_EMAIL = 'xenodekuu@gmail.com';
    const isOwner = user.email === OWNER_EMAIL;

    let isPremium = isOwner; // Owner is always premium
    if (!isOwner) {
      // Check subscription — must check BOTH plan_type AND status across ALL records
      const subs = await base44.asServiceRole.entities.Subscription.filter(
        { created_by: user.email },
        null,
        10
      );
      const nowMs = Date.now();
      const ENTITLED_PLAN_TYPES = new Set(['pro', 'vip', 'trial']);
      const activeSub = subs.find(s => {
        if (!ENTITLED_PLAN_TYPES.has(s.plan_type)) return false;
        if (s.status === 'active' || s.status === 'trialing') return true;
        if (s.status === 'grace_period' && s.grace_period_end) return new Date(s.grace_period_end).getTime() > nowMs;
        if (s.status === 'canceled' && s.current_period_end) return new Date(s.current_period_end).getTime() > nowMs;
        return false;
      });
      isPremium = !!activeSub;
    }
    console.log(`[aiGenerateAdvanced] user=${user.id} email=${user.email} isPremium=${isPremium} isOwner=${isOwner}`);

    const userTz = user.timezone || 'UTC';
    const now = new Date();
    const { periodStart, periodEnd } = getWeekWindow(now);

    // Check idempotency: if this client_request_id already exists for this user, return cached event
    const existing = (
      await base44.asServiceRole.entities.AiGenerationEvent.filter(
        {
          user_id: user.id,
          client_request_id,
        },
        null,
        1
      )
    )[0];

    if (existing) {
      // Return quota from cached event
      const quota = (
        await base44.asServiceRole.entities.AiGenerationQuota.filter(
          { user_id: user.id, period_start: periodStart.toISOString() },
          null,
          1
        )
      )[0];
      const remaining = quota ? Math.max(0, quota.limit - quota.used) : 2;
      return Response.json({
        success: true,
        event_id: existing.id,
        quota: isPremium
          ? { is_premium: true, daily_limit: 30 }
          : { is_premium: false, remaining, used: quota?.used || 0, limit: 2 },
      });
    }

    // For free users: enforce quota
    if (!isPremium) {
      const periodStartISO = periodStart.toISOString();
      const periodEndISO = periodEnd.toISOString();
      let quota = (
        await base44.asServiceRole.entities.AiGenerationQuota.filter(
          { user_id: user.id, period_start: periodStartISO },
          null,
          1
        )
      )[0];

      // Create if missing — NEVER reset an existing record
      if (!quota) {
        quota = await base44.asServiceRole.entities.AiGenerationQuota.create({
          user_id: user.id,
          period_start: periodStartISO,
          period_end: periodEndISO,
          limit: 2,
          used: 0,
          timezone: userTz,
          updated_at: now.toISOString(),
        });
      }

      // Fetch banked referral credits
      const ledgerEntries = await base44.asServiceRole.entities.ReferralRewardLedger.filter({
        user_id: user.id,
        credit_state: 'earned',
      }).catch(() => []);
      const bankedCredits = ledgerEntries.reduce((sum, e) => sum + (e.credits_remaining || 0), 0);
      const weeklyRemaining = Math.max(0, quota.limit - quota.used);

      // Check if at limit — base weekly AND banked both exhausted
      if (weeklyRemaining <= 0 && bankedCredits <= 0) {
        return Response.json(
          {
            code: 'FREE_LIMIT_REACHED',
            error: `You've used all ${quota.limit} free weekly generations and all banked credits`,
            quota: { remaining: 0, used: quota.used, limit: quota.limit, banked_referral_credits: 0 },
          },
          { status: 403 }
        );
      }

      // Consumption order:
      // 1. Base weekly allowance first
      // 2. Only after weekly is exhausted, consume banked credits
      let creditSource = 'weekly';
      if (weeklyRemaining > 0) {
        creditSource = 'weekly';
      } else {
        creditSource = 'banked';
      }

      // Create event record — created_date must be set explicitly so Live Feed filters work
      const event = await base44.asServiceRole.entities.AiGenerationEvent.create({
        user_id: user.id,
        recipe_title: finalRecipeForEvent.title || 'Generated Recipe',
        status: 'generated',
        recipe_payload: JSON.stringify(finalRecipeForEvent),
        meal_type: meal_type || '',
        cuisine: cuisine || '',
        period_start: periodStart.toISOString(),
        period_end: periodEnd.toISOString(),
        client_request_id,
        created_date: now.toISOString(),
      });

      // TELEMETRY: Recipe accepted
      telemetry.final_result = 'accepted';
      telemetry.final_accepted_recipe_id = event.id;
      telemetry.pricing_allowed = true;
      telemetry.image_generation_allowed = true;

      let newUsed = quota.used;
      let newBanked = bankedCredits;

      if (creditSource === 'weekly') {
        // Consume from weekly base allowance
        newUsed = quota.used + 1;
        await base44.asServiceRole.entities.AiGenerationQuota.update(quota.id, {
          used: newUsed,
          updated_at: now.toISOString(),
        });
      } else {
        // Consume from banked credits — find oldest earned entry and decrement
        const sortedEntries = ledgerEntries
          .filter(e => (e.credits_remaining || 0) > 0)
          .sort((a, b) => new Date(a.created_date) - new Date(b.created_date));
        if (sortedEntries.length > 0) {
          const entry = sortedEntries[0];
          const newRemaining = Math.max(0, (entry.credits_remaining || 0) - 1);
          const newState = newRemaining <= 0 ? 'consumed' : 'earned';
          await base44.asServiceRole.entities.ReferralRewardLedger.update(entry.id, {
            credits_remaining: newRemaining,
            credit_state: newState,
            consumed_at: newState === 'consumed' ? now.toISOString() : undefined,
          });
          newBanked = Math.max(0, bankedCredits - 1);
        }
      }

      const remaining = Math.max(0, quota.limit - newUsed);
      console.log(`[AI_GEN] user=${user.id} source=${creditSource} used=${newUsed} remaining=${remaining} banked=${newBanked}`);

      // Log telemetry asynchronously (don't block response)
      telemetry.total_duration_ms = Date.now() - startTime;
      base44.asServiceRole.functions.invoke('logAiGenerationTelemetry', telemetry).catch(err =>
        console.warn('[aiGenerateAdvanced] telemetry log failed:', err.message)
      );

      // NOTE: Credit logging is now done by generateRecipeWithQuota at the LLM call site.
      // aiGenerateAdvanced only handles quota accounting — not credit logging.
      return Response.json({
        success: true,
        event_id: event.id,
        credit_source: creditSource,
        quota: {
          is_premium: false,
          remaining,
          used: newUsed,
          limit: 2,
          banked_referral_credits: newBanked,
          total_available: remaining + newBanked,
        },
      });
    } else {
      // ── PRO USER: enforce daily limit + cooldown ──────────────────────────
      // checkProGenerationLimit atomically reserves the slot (increments count,
      // sets generation_in_progress). On idempotent replay, we skip the gate.
      // Fetch banked credits for Pro user (reserve beyond daily 30)
      const proLedgerEntries = await base44.asServiceRole.entities.ReferralRewardLedger.filter({
        user_id: user.id,
        credit_state: 'earned',
      }).catch(() => []);
      const proBankedCredits = proLedgerEntries.reduce((sum, e) => sum + (e.credits_remaining || 0), 0);

      // ── Inline Pro quota check (replaces checkProGenerationLimit call) ──
      const PRO_DAILY_LIMIT = 25; // canonical: 25/day for Pro
      const COOLDOWN_AFTER_N = 10;
      const COOLDOWN_SECONDS = 180;
      const userTzPro = user.timezone || 'UTC';
      const nowPro = new Date();
      const todayKeyPro = (() => {
        try {
          return new Intl.DateTimeFormat('en-CA', { timeZone: userTzPro, year: 'numeric', month: '2-digit', day: '2-digit' }).format(nowPro);
        } catch { return nowPro.toISOString().slice(0, 10); }
      })();

      let proQuotaRec = (await base44.asServiceRole.entities.ProGenerationQuota.filter({ user_id: user.id, day_key: todayKeyPro }).catch(() => []))[0] || null;
      if (!proQuotaRec) {
        try {
          proQuotaRec = await base44.asServiceRole.entities.ProGenerationQuota.create({
            user_id: user.id, day_key: todayKeyPro, daily_count: 0,
            last_generation_started_at: null, generation_in_progress: false,
            timezone: userTzPro, updated_at: nowPro.toISOString(),
          });
        } catch {
          proQuotaRec = (await base44.asServiceRole.entities.ProGenerationQuota.filter({ user_id: user.id, day_key: todayKeyPro }).catch(() => []))[0] || { daily_count: 0 };
        }
      }

      const dailyCountPro = proQuotaRec.daily_count || 0;
      const proLimitReached = dailyCountPro >= PRO_DAILY_LIMIT;

      if (proLimitReached && proBankedCredits <= 0) {
        return Response.json({ allowed: false, reason: 'daily_limit_reached', remaining_today: 0, daily_count: dailyCountPro, message: "You've reached today's 25-generation Pro limit.", error: "Pro daily limit reached" }, { status: 429 });
      }

      // Cooldown check (only if not using banked credits)
      if (!proLimitReached && dailyCountPro >= COOLDOWN_AFTER_N && proQuotaRec.last_generation_started_at) {
        const elapsed = (nowPro.getTime() - new Date(proQuotaRec.last_generation_started_at).getTime()) / 1000;
        const remaining = Math.ceil(COOLDOWN_SECONDS - elapsed);
        if (remaining > 0 && proBankedCredits <= 0) {
          return Response.json({ allowed: false, reason: 'pro_cooldown_active', remaining_seconds: remaining, daily_count: dailyCountPro, message: `Cooldown active — ${remaining}s remaining.`, error: 'Pro cooldown active' }, { status: 429 });
        }
      }

      // Reserve slot (only if not using banked credits — banked doesn't increment daily)
      if (!proLimitReached && proQuotaRec.id) {
        const newCountPro = dailyCountPro + 1;
        await base44.asServiceRole.entities.ProGenerationQuota.update(proQuotaRec.id, {
          daily_count: newCountPro, last_generation_started_at: nowPro.toISOString(),
          generation_in_progress: true, updated_at: nowPro.toISOString(),
        });
        proQuotaRec = { ...proQuotaRec, daily_count: newCountPro };
      }

      const proQuota = { allowed: true, daily_count: proQuotaRec.daily_count, remaining_today: Math.max(0, PRO_DAILY_LIMIT - proQuotaRec.daily_count), cooldown_will_apply: proQuotaRec.daily_count >= COOLDOWN_AFTER_N };
      const usingBankedForPro = proLimitReached && proBankedCredits > 0;
      console.log(`[AI_GEN] Pro gate passed user=${user.id} count=${proQuotaRec.daily_count}/25 banked=${usingBankedForPro}`);

      // Create event record — created_date must be set explicitly so Live Feed filters work
      let event;
      try {
        event = await base44.asServiceRole.entities.AiGenerationEvent.create({
          user_id: user.id,
          recipe_title: finalRecipeForEvent.title || 'Generated Recipe',
          status: 'generated',
          recipe_payload: JSON.stringify(finalRecipeForEvent),
          meal_type: meal_type || '',
          cuisine: cuisine || '',
          client_request_id,
          created_date: nowPro.toISOString(),
        });

        // TELEMETRY: Recipe accepted
        telemetry.final_result = 'accepted';
        telemetry.final_accepted_recipe_id = event.id;
        telemetry.pricing_allowed = true;
        telemetry.image_generation_allowed = true;
      } catch (eventErr) {
        if (!usingBankedForPro && proQuotaRec?.id) {
          await base44.asServiceRole.entities.ProGenerationQuota.update(proQuotaRec.id, { generation_in_progress: false, updated_at: new Date().toISOString() }).catch(() => {});
        }
        throw eventErr;
      }

      let newProBanked = proBankedCredits;

      if (usingBankedForPro) {
        // Consume from banked credits — daily 30 exhausted
        const sortedProEntries = proLedgerEntries
          .filter(e => (e.credits_remaining || 0) > 0)
          .sort((a, b) => new Date(a.created_date) - new Date(b.created_date));
        if (sortedProEntries.length > 0) {
          const entry = sortedProEntries[0];
          const newRemaining = Math.max(0, (entry.credits_remaining || 0) - 1);
          const newState = newRemaining <= 0 ? 'consumed' : 'earned';
          await base44.asServiceRole.entities.ReferralRewardLedger.update(entry.id, {
            credits_remaining: newRemaining,
            credit_state: newState,
            consumed_at: newState === 'consumed' ? new Date().toISOString() : undefined,
          });
          newProBanked = Math.max(0, proBankedCredits - 1);
        }
        console.log(`[AI_GEN] Pro used banked credit. remaining_banked=${newProBanked}`);
      } else {
        // Normal pro daily slot consumed — release in-progress flag
        if (proQuotaRec?.id) {
          base44.asServiceRole.entities.ProGenerationQuota.update(proQuotaRec.id, { generation_in_progress: false, updated_at: new Date().toISOString() }).catch(err =>
            console.warn('[aiGenerateAdvanced] releaseProSlot failed:', err.message)
          );
        }
      }

      // NOTE: Credit logging is now done by generateRecipeWithQuota at the LLM call site.
      // aiGenerateAdvanced only handles quota accounting — not credit logging.

      // Log telemetry asynchronously (don't block response)
      telemetry.total_duration_ms = Date.now() - startTime;
      base44.asServiceRole.functions.invoke('logAiGenerationTelemetry', telemetry).catch(err =>
        console.warn('[aiGenerateAdvanced] telemetry log failed:', err.message)
      );

      return Response.json({
        success: true,
        event_id: event.id,
        credit_source: usingBankedForPro ? 'banked' : 'pro_daily',
        quota: {
          is_premium: true,
          daily_count: proQuota.daily_count,
          remaining_today: usingBankedForPro ? 0 : proQuota.remaining_today,
          daily_limit: 25,
          cooldown_will_apply: proQuota.cooldown_will_apply,
          banked_referral_credits: newProBanked,
        },
      });
    }
  } catch (err) {
    console.error('[aiGenerateAdvanced]', err.message);
    return Response.json({ error: err.message }, { status: 500 });
  }
});

function getWeekWindow(date) {
  // ALWAYS UTC midnight — canonical key. Never apply timezone offsets (causes mismatched keys).
  const dayOfWeek = date.getUTCDay(); // 0=Sun, 1=Mon ... 6=Sat
  const daysToSubtract = dayOfWeek === 0 ? 6 : dayOfWeek - 1;

  const periodStart = new Date(date);
  periodStart.setUTCDate(periodStart.getUTCDate() - daysToSubtract);
  periodStart.setUTCHours(0, 0, 0, 0);

  const periodEnd = new Date(periodStart);
  periodEnd.setUTCDate(periodEnd.getUTCDate() + 7);

  return { periodStart, periodEnd };
}

/**
 * AI GENERATE WITH CONSTRAINTS
 * 
 * Generation function used by auto-repair system.
 * Takes a constraint-injected prompt and generates a recipe with strict validation.
 */

import { createClientFromRequest } from 'npm:@base44/sdk@0.8.25';

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user) return Response.json({ error: 'Unauthorized' }, { status: 401 });

    const { userPrompt, originalUserPrompt, attemptNumber = 1 } = await req.json();

    if (!userPrompt) {
      return Response.json({ error: 'userPrompt required' }, { status: 400 });
    }

    console.log('[aiGenConstraints] Attempt', attemptNumber, 'Prompt length:', userPrompt.length);

    // COST POLICY GUARD
    const policyCheck = await base44.asServiceRole.functions.invoke('costPolicyGuard', {
      event_type: 'llm_call', source: 'ai_recipe', endpoint_name: 'aiGenerateWithConstraints',
      user_id: user.id, provider_name: 'Core.InvokeLLM', model_name: 'automatic',
    }).catch(() => ({ data: { allowed: true, mode: 'error_fallback' } }));
    if (policyCheck.data?.allowed === false) {
      return Response.json({ error: 'Blocked by cost policy', code: 'COST_POLICY_BLOCKED' }, { status: 403 });
    }

    // Call InvokeLLM — minimal system prompt to reduce token cost
    const llmStart = Date.now();
    const genRes = await base44.asServiceRole.integrations.Core.InvokeLLM({
      prompt: `Generate a recipe. Return STRICT JSON only, no explanations.\n\n${userPrompt}`,
      response_json_schema: {
        type: 'object',
        properties: {
          title: { type: 'string', description: 'Recipe title' },
          description: { type: 'string', description: 'Short description' },
          servings: { type: 'number', description: 'Number of servings' },
          prep_time: { type: 'number', description: 'Prep time in minutes' },
          cook_time: { type: 'number', description: 'Cook time in minutes' },
          difficulty: { type: 'string', enum: ['easy', 'medium', 'hard'] },
          cuisine: { type: 'string' },
          meal_type: { type: 'string', enum: ['breakfast', 'lunch', 'dinner', 'snack', 'dessert'] },
          ingredients: {
