/**
 * auditAprilImageEvents — Full detailed list of all April image generation events
 * For reconciliation: compare actual Base44 provider calls vs recorded in database
 */
import { createClientFromRequest } from 'npm:@base44/sdk@0.8.23';

function getMonthBounds(monthKey = '2026-04') {
  const [year, month] = monthKey.split('-').map(Number);
  const start = new Date(Date.UTC(year, month - 1, 1));
  const end = new Date(Date.UTC(year, month, 1)); // exclusive
  return { start, end };
}

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user || user.role !== 'admin') {
      return Response.json({ error: 'Admin only' }, { status: 403 });
    }

    const body = await req.json().catch(() => ({}));
    const monthKey = body.month_key || '2026-04';
    const { start, end } = getMonthBounds(monthKey);

    // Fetch ALL logs for the month
    const allLogs = await base44.asServiceRole.entities.IntegrationCostLog.list('-created_date', 5000).catch(() => []);
    const monthLogs = allLogs.filter(log => {
      const ts = new Date(log.created_date || log.timestamp || 0);
      return ts >= start && ts < end;
    });

    // Extract image generation events only
    const imageEvents = monthLogs.filter(log => log.cost_category === 'image_generation');

    // Compute totals
    const base44Images = imageEvents.filter(log => !log.integration_name?.toLowerCase().includes('together'));
    const togetherImages = imageEvents.filter(log => log.integration_name?.toLowerCase().includes('together'));

    const base44Total = base44Images.length * 7; // 7 credits per Base44 image
    const togetherTotal = 0; // TogetherAI costs no Base44 credits

    // Build detailed event list
    const eventDetails = imageEvents.map((log, idx) => {
      const isTogether = log.integration_name?.toLowerCase().includes('together');
      return {
        index: idx + 1,
        id: log.id,
        timestamp: log.created_date || log.timestamp,
        function_name: log.function_name,
        provider: isTogether ? 'TogetherAI' : 'Base44',
        integration_name: log.integration_name,
        credits: isTogether ? 0 : 7,
        metadata: log.metadata_json ? JSON.parse(log.metadata_json) : {},
      };
    });

    // Fetch monthly aggregated state
    const monthlyState = (await base44.asServiceRole.entities.MonthlyIntegrationUsageState.filter(
      { month_key: monthKey }, null, 1
    ).catch(() => []))[0];

    return Response.json({
      month_key: monthKey,
      period: {
        start: start.toISOString(),
        end: end.toISOString(),
      },
      total_image_events: imageEvents.length,
      base44_image_events: base44Images.length,
      together_image_events: togetherImages.length,

      base44_total_credits: base44Total,
      together_total_credits: togetherTotal,
      combined_total_credits: base44Total + togetherTotal,

      monthly_aggregated_state: monthlyState ? {
        tracked_base44_credits_used: monthlyState.tracked_base44_credits_used,
        current_mode: monthlyState.current_mode,
        threshold_value: monthlyState.threshold_value,
        over_threshold: (monthlyState.tracked_base44_credits_used || 0) >= (monthlyState.threshold_value || 16500),
      } : null,

      reconciliation: {
        raw_log_total: base44Total + togetherTotal,
        aggregated_state_total: monthlyState?.tracked_base44_credits_used || 0,
        delta: Math.abs((base44Total + togetherTotal) - (monthlyState?.tracked_base44_credits_used || 0)),
        match: (base44Total + togetherTotal) === (monthlyState?.tracked_base44_credits_used || 0),
      },

      events: eventDetails,
    });
  } catch (err) {
    console.error('[auditAprilImageEvents] Error:', err.message);
    return Response.json({ error: err.message }, { status: 500 });
  }
});

import { createClientFromRequest } from 'npm:@base44/sdk@0.8.23';

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user?.id) return Response.json({ error: 'Unauthorized' }, { status: 401 });

    const sr = base44.asServiceRole;

    const [allRecipes, users] = await Promise.all([
      sr.entities.Recipe.list('-created_date', 500).catch(() => []),
      sr.entities.User.list(null, 5000).catch(() => []),
    ]);

    const userMap = {};
    for (const u of users) userMap[u.id] = u;

    const eligible = [];
    const blocked = [];

    for (const r of allRecipes) {
      const author = userMap[r.author_id];
      const exclusions = [];

      if (r.is_public !== true) exclusions.push('is_public ≠ true');
      if (r.moderation_status === 'removed_by_moderation') exclusions.push('moderation_status=removed');
      if (r.moderation_status === 'appealed') exclusions.push('moderation_status=appealed');
      if (r.community_visible === false) exclusions.push('community_visible=false');
      if (r.author_account_status === 'suspended' || r.author_account_status === 'deleted') exclusions.push(`author_account_status=${r.author_account_status}`);
      if (author?.account_status === 'suspended' || author?.account_status === 'deleted') exclusions.push(`author.account_status=${author.account_status}`);

      const row = {
        id: r.id,
        title: (r.title || '').slice(0, 60),
        source: r.source,
        is_public: r.is_public,
        community_visible: r.community_visible,
        moderation_status: r.moderation_status,
        author_account_status: r.author_account_status,
        author_real_status: author?.account_status,
        created_date: r.created_date,
      };

      if (exclusions.length === 0) {
        eligible.push(row);
      } else {
        blocked.push({ ...row, exclusions });
      }
    }

    return Response.json({
      total: allRecipes.length,
      eligible_count: eligible.length,
      blocked_count: blocked.length,
      eligible,
      blocked,
    });
  } catch (error) {
    return Response.json({ error: error.message }, { status: 500 });
  }
});

