const UNIT_G = {
  g: 1, gram: 1, grams: 1,
  kg: 1000, kilogram: 1000, kilograms: 1000,
  oz: 28.35, ounce: 28.35, ounces: 28.35,
  lb: 453.6, lbs: 453.6, pound: 453.6, pounds: 453.6,
  cup: 240, cups: 240,
  tbsp: 15, tablespoon: 15, tablespoons: 15,
  tsp: 5, teaspoon: 5, teaspoons: 5,
  ml: 1, l: 1000, liter: 1000, liters: 1000,
};

const PIECE_G = {
  "chicken breast": 150, "chicken thigh": 100, "egg": 50, "large egg": 60,
  "potato": 170, "tomato": 150, "onion": 150, "avocado": 200,
  "banana": 120, "apple": 180, "orange": 180, "lemon": 80, "lime": 65,
  "carrot": 80, "slice": 30, "can": 400, "bunch": 100, "clove": 3,
  "garlic clove": 3, "bell pepper": 180, "cucumber": 200,
};

function evalFraction(str) {
  const s = String(str || '').trim();
  if (s.includes('/')) {
    const [n, d] = s.split('/');
    return parseFloat(n) / parseFloat(d);
  }
  return parseFloat(s) || 0;
}

function parseGrams(amountStr, name) {
  if (!amountStr) return 100;
  const str = String(amountStr).trim();
  const withGrams = str.match(/\(\s*about\s+([\d.]+)\s*g\s*\)/i);
  if (withGrams) return parseFloat(withGrams[1]);
  const justG = str.match(/^([\d.]+)\s*g$/i);
  if (justG) return parseFloat(justG[1]);
  const fracUnit = str.match(/^(\d+\/\d+)\s+([a-z]+[a-z\s]*)$/i);
  if (fracUnit) {
    const qty = evalFraction(fracUnit[1]);
    const unit = fracUnit[2].trim().toLowerCase();
    const gPer = UNIT_G[unit] || UNIT_G[unit.replace(/s$/, '')];
    if (gPer) return qty * gPer;
  }
  const numUnit = str.match(/^([\d.]+)\s+([a-z]+[a-z\s]*)$/i);
  if (numUnit) {
    const qty = parseFloat(numUnit[1]);
    const unit = numUnit[2].trim().toLowerCase();
    const gPer = UNIT_G[unit] || UNIT_G[unit.replace(/s$/, '')];
    if (gPer) return qty * gPer;
    const nameLow = (name || '').toLowerCase();
    for (const [k, v] of Object.entries(PIECE_G)) {
      if (nameLow.includes(k) || k.includes(nameLow.substring(0, 5))) return qty * v;
    }
    return qty * 100;
  }
  const justNum = str.match(/^([\d.]+)$/);
  if (justNum) return parseFloat(justNum[1]);
  return 100;
}

function normalizeName(name) {
  if (!name) return '';
  return name
    .toLowerCase()
    .replace(/[^a-z0-9\s]/g, '')
    .replace(/\b(fresh|dried|frozen|chopped|diced|sliced|minced|shredded|grated|cooked|raw|canned|whole|large|small|medium|boneless|skinless|organic|extra|virgin|ripe|crushed|ground|smoked|roasted|sauteed|toasted)\b/g, '')
    .replace(/\s+/g, ' ')
    .trim();
}

function lookupPrice(name) {
  const norm = normalizeName(name);
  if (PRICE_PER_100G[norm] !== undefined) return PRICE_PER_100G[norm];
  let best = null, bestLen = 0;
  for (const [key, price] of Object.entries(PRICE_PER_100G)) {
    if (key.length > 3 && norm.includes(key) && key.length > bestLen) {
      best = price; bestLen = key.length;
    }
    if (key.length > 3 && key.includes(norm) && norm.length > 3 && norm.length > bestLen) {
      best = price; bestLen = norm.length;
    }
  }
  return best;
}

async function estimatePricing(base44, recipe_id) {
  const recipes = await base44.asServiceRole.entities.Recipe.filter({ id: recipe_id });
  const recipe = recipes[0];
  if (!recipe) return null;

  const servings = Math.max(1, recipe.servings || 1);
  let totalCost = 0;
  let anyMissing = false;

  const updatedGroups = (recipe.ingredients || []).map(group => ({
    ...group,
    items: (group.items || []).map(item => {
      const grams = parseGrams(item.amount, item.name);
      const priceP100g = lookupPrice(item.name);
      if (priceP100g == null) {
        anyMissing = true;
        return { ...item, ingredient_cost: null };
      }
      const cost = (grams * priceP100g) / 100;
      totalCost += cost;
      return { ...item, ingredient_cost: parseFloat(cost.toFixed(4)) };
    }),
  }));

  const finalTotal = anyMissing ? null : parseFloat(totalCost.toFixed(2));
  const finalPerServing = finalTotal != null ? parseFloat((finalTotal / servings).toFixed(2)) : null;

  await base44.asServiceRole.entities.Recipe.update(recipe_id, {
    ingredients: updatedGroups,
    total_cost: finalTotal,
    cost_per_serving: finalPerServing,
  });

  return { total_cost: finalTotal, cost_per_serving: finalPerServing, any_missing: anyMissing };
}

