/**
 * AUTO-REPAIR RECIPE SYSTEM
 * 
 * Takes a failed integrity validation and automatically repairs the recipe
 * by regenerating with strict concept constraints.
 */

import { createClientFromRequest } from 'npm:@base44/sdk@0.8.23';

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user) return Response.json({ error: 'Unauthorized' }, { status: 401 });

    const {
      originalRecipe,
      userPrompt,
      failureDebug,
      attemptNumber = 1,
      maxAttempts = 2
    } = await req.json();

    if (!userPrompt || !failureDebug) {
      return Response.json({
        error: 'userPrompt and failureDebug required',
        repaired: false
      }, { status: 400 });
    }

    // Extract what was missing
    const missingConcepts = failureDebug.missing_concepts || [];
    const consistencyIssues = failureDebug.consistency_issues || [];
    const repairsNeeded = failureDebug.repairs_applied || [];

    console.log('[autoRepair] Attempt', attemptNumber, 'of', maxAttempts);
    console.log('[autoRepair] Missing concepts:', missingConcepts);
    console.log('[autoRepair] Repairs needed:', repairsNeeded);

    // Build CONSTRAINT-INJECTED prompt
    let constraintPrompt = userPrompt;

    // Strict inclusion constraint
    if (missingConcepts.length > 0) {
      const conceptList = missingConcepts.join(', ');
      constraintPrompt += `\n\nCRITICAL: The recipe MUST include ALL of these concepts in the ingredients list: ${conceptList}.\nDo NOT omit any of these.`;
    }

    // Structural rules
    if (repairsNeeded.includes('burger_structure_missing')) {
      constraintPrompt += '\n\nThe burger MUST have an explicit patty (ground beef patty, beef patty, meat patty, or equivalent protein structure).';
    }

    if (repairsNeeded.includes('shawarma_structure_missing')) {
      constraintPrompt += '\n\nThe shawarma MUST include shawarma meat or shawarma-marinated protein (chicken, beef, turkey, lamb).';
    }

    // Consistency rules
    if (consistencyIssues.length > 0) {
      constraintPrompt += '\n\nEnsure all ingredients mentioned in the title, description, or instructions are present in the ingredients array. Do NOT hallucinate structure.';
    }

    // Stricter constraint on attempt 2
    if (attemptNumber === 2) {
      constraintPrompt += '\n\nThis is your final attempt. Prioritize structural correctness above all else. Include every concept and structural element explicitly in the ingredients.';
    }

    console.log('[autoRepair] Constraint prompt length:', constraintPrompt.length);

    // Regenerate with constraints
    const genRes = await base44.asServiceRole.functions.invoke('aiGenerateWithConstraints', {
      userPrompt: constraintPrompt,
      originalUserPrompt: userPrompt,
      attemptNumber
    });

    if (!genRes.data?.recipe) {
      return Response.json({
        error: 'Generation failed',
        repaired: false,
        attemptNumber
      }, { status: 500 });
    }

    const repairedRecipe = genRes.data.recipe;

    // Re-validate the repaired recipe
    const validationRes = await base44.asServiceRole.functions.invoke('recipeIntegrityValidator', {
      recipe: repairedRecipe,
      userPrompt: userPrompt
    });

    const validationResult = validationRes.data;

    return Response.json({
      repaired: validationResult.valid,
      recipe: validationResult.valid ? repairedRecipe : null,
      attemptNumber,
      constraintPrompt: constraintPrompt, // For telemetry logging
      validationDebug: validationResult.debug,
      constraintsApplied: {
        includedMissingConcepts: missingConcepts,
        enforcedStructuralRules: repairsNeeded,
        enforcedConsistency: consistencyIssues.length > 0
      },
      shouldRetry: !validationResult.valid && attemptNumber < maxAttempts
    });

  } catch (error) {
    console.error('[autoRepair] error:', error.message);
    return Response.json({ error: error.message }, { status: 500 });
  }
});

/**
 * AUTO-REPAIR / REGENERATION LOOP WITH CONCEPT CONSTRAINTS
 * 
 * If structural validation fails, regenerates recipe with hard constraints
 * forcing inclusion of all missing required concepts.
 * 
 * Retries up to 2 times with increasing strictness.
 */

import { createClientFromRequest } from 'npm:@base44/sdk@0.8.25';

/**
 * COST REDUCTION: Hard limit of 1 repair attempt (was 2).
 * Total LLM budget per recipe: 1 primary + 1 repair = 2 max.
 */

async function regenerateWithConstraints(base44, userPrompt, missingConcepts, attemptNumber) {
  const conceptList = missingConcepts.join(', ');

  // Single strict prompt — no soft/hard distinction since we only get 1 shot
  const constraintPrompt = `
The user requested: "${userPrompt}"

CRITICAL — STRICT VALIDATION: This recipe MUST include ALL of these concepts:
${missingConcepts.map(c => `- ${c}`).join('\n')}

Each required concept must:
1. Appear in the ingredients list with explicit names
2. Be mentioned in the cooking instructions
3. Be reflected in the dish title or description

You MUST include: ${conceptList}
Return STRICT JSON only. No explanations.
`;

  console.log(`[autoRepairRecipeWithConcepts] Attempt ${attemptNumber}: regenerating with constraints`);

  try {
    // COST POLICY GUARD
    const policyCheck = await base44.asServiceRole.functions.invoke('costPolicyGuard', {
      event_type: 'llm_call', source: 'ai_recipe', endpoint_name: 'autoRepairRecipeWithConcepts',
      provider_name: 'Core.InvokeLLM', model_name: 'automatic',
    }).catch(() => ({ data: { allowed: true, mode: 'error_fallback' } }));
    if (policyCheck.data?.allowed === false) {
      throw new Error('Blocked by cost policy');
    }

    const llmStart = Date.now();
    const result = await base44.integrations.Core.InvokeLLM({
      prompt: `${constraintPrompt}\n\nGenerate a complete recipe JSON following this structure:\n{\n  "title": "...",\n  "description": "...",\n  "ingredients": [{"group": "...", "items": [{"name": "...", "amount": "..."}]}],\n  "steps": [{"step_number": 1, "instruction": "..."}]\n}`,
      response_json_schema: {
        type: 'object',
        properties: {
          title: { type: 'string' },
          description: { type: 'string' },
          ingredients: {
            type: 'array',
            items: {
              type: 'object',
              properties: {
                group: { type: 'string' },
                items: {
                  type: 'array',
                  items: {
                    type: 'object',
                    properties: {
                      name: { type: 'string' },
                      amount: { type: 'string' },
                    },
                    required: ['name', 'amount'],
                  },
                },
              },
            },
          },
          steps: {
            type: 'array',
            items: {
              type: 'object',
              properties: {
                step_number: { type: 'number' },
                instruction: { type: 'string' },
              },
            },
          },
        },
        required: ['title', 'ingredients', 'steps'],
      },
    });
    const llmDuration = Date.now() - llmStart;

    // LOG: cost event for concept-repair LLM call
    base44.asServiceRole.functions.invoke('logSystemEvent', {
      event_type: 'llm_call',
      source: 'ai_recipe',
      endpoint_name: 'autoRepairRecipeWithConcepts',
      origin: 'backend',
      allowed_scope: 'allowed',
      provider_name: 'Core.InvokeLLM',
      model_name: 'automatic',
      request_type: 'json_schema',
      credits_used: 1,
      raw_cost_source: 'inferred_from_usage',
      success: !!(result && result.title),
      duration_ms: llmDuration,
      raw_usage_metadata: { attemptNumber, missing_concepts: missingConcepts },
    }).catch(e => console.warn('[autoRepairRecipeWithConcepts] log failed:', e.message));

    return result;

  } catch (error) {
    console.error(`[autoRepairRecipeWithConcepts] Attempt ${attemptNumber} failed:`, error.message);
    throw error;
  }
}

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const { user_prompt, validation, max_attempts: _ignored } = await req.json();
    // HARD LIMIT: 1 repair attempt max (cost reduction policy)
    const max_attempts = 1;

    if (!user_prompt || !validation) {
      return Response.json({ 
        error: 'user_prompt and validation required' 
      }, { status: 400 });
    }

    if (validation.valid) {
      return Response.json({
        success: true,
        repaired: false,
        message: 'Recipe already valid, no repair needed'
      });
    }

    const missingConcepts = validation.missing_concepts || [];
    let repaired = false;
    let finalRecipe = null;
    let finalValidation = null;

    for (let attempt = 1; attempt <= max_attempts; attempt++) {
      console.log(`[autoRepairRecipeWithConcepts] Attempt ${attempt} of ${max_attempts}`);

      try {
        // Regenerate with constraints
        const regenerated = await regenerateWithConstraints(
          base44,
          user_prompt,
          missingConcepts,
          attempt
        );

        // Re-validate immediately
        const revalidateRes = await base44.asServiceRole.functions.invoke(
          'validateRecipeStructure',
          {
            recipe: regenerated,
            required_concepts: validation.required_concepts || { all_required: missingConcepts }
          }
        );

        const newValidation = revalidateRes.data?.validation;

        if (newValidation.valid) {
          console.log(`[autoRepairRecipeWithConcepts] Attempt ${attempt}: SUCCESS`);
          finalRecipe = regenerated;
          finalValidation = newValidation;
          repaired = true;
          break;
        } else {
          console.log(`[autoRepairRecipeWithConcepts] Attempt ${attempt}: Still invalid, missing: ${newValidation.missing_concepts.join(', ')}`);
        }

      } catch (error) {
        console.error(`[autoRepairRecipeWithConcepts] Attempt ${attempt}: Error`, error.message);
        if (attempt === max_attempts) {
          throw new Error(`Auto-repair failed after ${max_attempts} attempts: ${error.message}`);
        }
      }
    }

    if (!finalRecipe) {
      return Response.json({
        success: false,
        repaired: false,
        error: `Could not repair recipe after ${max_attempts} attempts. Missing: ${missingConcepts.join(', ')}`,
        pricing_allowed: false,
        image_generation_allowed: false
      }, { status: 400 });
    }

    return Response.json({
      success: true,
      repaired,
      recipe: finalRecipe,
      validation: finalValidation,
      pricing_allowed: finalValidation.pricing_allowed,
      image_generation_allowed: finalValidation.image_generation_allowed
    });

  } catch (error) {
    console.error('[autoRepairRecipeWithConcepts] error:', error.message);
    return Response.json({ 
      error: error.message,
      pricing_allowed: false,
      image_generation_allowed: false
    }, { status: 500 });
  }
});

/**
 * backfillCanonicalQuantities
 * 
 * Backfill canonical_base_amount, canonical_base_unit, and allowed_display_units
 * for all existing PantryItem records.
 * 
 * This is a one-time migration function.
 * Run via: base44.functions.invoke('backfillCanonicalQuantities', {})
 */
import { createClientFromRequest } from 'npm:@base44/sdk@0.8.20';

const QuantityConversion = {
  getIngredientType: (category, unit) => {
    const unitLower = (unit || '').toLowerCase();
    if (['cans', 'jars', 'bottles', 'cartons', 'packs'].includes(unitLower)) {
      return 'packaged';
    }
    if (['oils_sauces', 'beverages'].includes(category)) {
      return 'liquids';
    }
    if (['ml', 'l', 'tbsp', 'tsp'].includes(unitLower)) {
      return 'liquids';
    }
    if (['spices'].includes(category) && ['cloves', 'bunch', 'slices'].includes(unitLower)) {
      return 'pieces';
    }
    return 'solids';
  },

  normalizeToCanonical: (rawAmount, rawUnit, ingredientType, packagedMetadata = {}) => {
    const unitLower = (rawUnit || '').toLowerCase();
    const conversionFactors = {
      solids: { g: 1, kg: 0.001, cups: 0.004167, tbsp: 0.06667, tsp: 0.2, oz: 0.03527, lbs: 0.00220462 },
      liquids: { ml: 1, l: 0.001, tbsp: 0.06667, tsp: 0.2, cups: 0.004167, oz: 0.03381 },
      pieces: { pieces: 1, bunch: 0.2, cloves: 1, slices: 1 },
      packaged: { g: 1, kg: 0.001, ml: 1, l: 0.001, tbsp: 0.06667, tsp: 0.2 }
    };

    if (ingredientType === 'packaged' && packagedMetadata?.baseQuantity && packagedMetadata?.baseUnit) {
      const containerInCanonical = QuantityConversion.normalizeToCanonical(
        packagedMetadata.baseQuantity,
        packagedMetadata.baseUnit,
        'solids'
      );
      return rawAmount * containerInCanonical;
    }

    const factors = conversionFactors[ingredientType] || conversionFactors.solids;
    const factor = factors[unitLower] || 1;
    return rawAmount / factor;
  },

  buildAllowedDisplayUnits: (category, ingredientType, hasContainerMetadata = false) => {
    if (ingredientType === 'solids') {
      return ['g', 'kg', 'cups', 'tbsp', 'tsp'];
    }
    if (ingredientType === 'liquids') {
      return ['ml', 'L', 'tbsp', 'tsp', 'cups'];
    }
    if (ingredientType === 'pieces') {
      return ['pieces', 'bunch', 'cloves', 'slices'];
    }
    if (ingredientType === 'packaged') {
      const units = ['g', 'kg', 'ml', 'L', 'tbsp', 'tsp'];
      if (hasContainerMetadata) {
        units.push('cans', 'jars', 'bottles', 'cartons', 'packs');
      }
      return units;
    }
    return ['g'];
  },

  getCanonicalBaseUnit: (ingredientType) => {
    const map = {
      solids: 'g',
      liquids: 'ml',
      pieces: 'pieces',
      packaged: 'g'
    };
    return map[ingredientType] || 'g';
  }
};

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();

    if (!user?.role === 'admin') {
      return new Response(
        JSON.stringify({ error: 'Admin access required' }),
        { status: 403, headers: { 'Content-Type': 'application/json' } }
      );
    }

    // Fetch all pantry items
    const allItems = await base44.asServiceRole.entities.PantryItem.list('-created_date', 10000);

    let updated = 0;
    let failed = 0;
    const errors = [];

    for (const item of allItems) {
      try {
        const ingredientType = QuantityConversion.getIngredientType(item.category, item.unit);

        // Skip if already migrated
        if (item.canonical_base_amount && item.canonical_base_unit && item.allowed_display_units) {
          console.log(`[Backfill] ${item.name} already has canonical fields, skipping`);
          continue;
        }

        const canonicalBaseAmount = QuantityConversion.normalizeToCanonical(
          item.quantity || 0,
          item.unit || 'g',
          ingredientType,
          item.container_base_quantity && item.container_base_unit
            ? { baseQuantity: item.container_base_quantity, baseUnit: item.container_base_unit }
            : null
        );

        const canonicalBaseUnit = QuantityConversion.getCanonicalBaseUnit(ingredientType);
        const allowedDisplayUnits = QuantityConversion.buildAllowedDisplayUnits(
          item.category,
          ingredientType,
          !!(item.container_base_quantity && item.container_base_unit)
        );

        // Update
        await base44.asServiceRole.entities.PantryItem.update(item.id, {
          canonical_base_amount: canonicalBaseAmount,
          canonical_base_unit: canonicalBaseUnit,
          allowed_display_units: allowedDisplayUnits,
        });

        updated++;
        console.log(`[Backfill] ✓ ${item.name}: ${item.quantity} ${item.unit} → ${canonicalBaseAmount} ${canonicalBaseUnit}`);
      } catch (itemErr) {
        failed++;
        const msg = `Failed to backfill ${item.name}: ${itemErr.message}`;
        console.error(`[Backfill] ✗ ${msg}`);
        errors.push(msg);
      }
    }

    return new Response(
      JSON.stringify({
        success: true,
        updated,
        failed,
        total: allItems.length,
        errors: errors.slice(0, 10), // Limit to first 10 errors
      }),
      { status: 200, headers: { 'Content-Type': 'application/json' } }
    );
  } catch (error) {
    console.error('[Backfill] Fatal error:', error.message);
    return new Response(
      JSON.stringify({ error: error.message }),
      { status: 500, headers: { 'Content-Type': 'application/json' } }
    );
  }
});

import { createClientFromRequest } from 'npm:@base44/sdk@0.8.6';

/**
 * Backfill nutrition for recipes missing calories/protein.
 * Estimates from ingredient amounts using a simple lookup table.
 * Admin-only endpoint.
 */

// Simple per-100g nutrition estimates for common ingredient categories
const NUTRIENT_LOOKUP = [
  { keywords: ["chicken", "beef", "pork", "lamb", "turkey", "meat", "protein", "fish", "salmon", "tuna", "shrimp"], cal: 165, prot: 25, carb: 0, fat: 8 },
  { keywords: ["egg"], cal: 155, prot: 13, carb: 1, fat: 11 },
  { keywords: ["cheese", "mozzarella", "cheddar", "parmesan", "feta"], cal: 350, prot: 22, carb: 3, fat: 28 },
  { keywords: ["milk", "cream", "yogurt"], cal: 60, prot: 3.5, carb: 5, fat: 3 },
  { keywords: ["rice", "pasta", "noodle", "quinoa", "oat", "flour", "bread", "grain"], cal: 350, prot: 7, carb: 72, fat: 2 },
  { keywords: ["potato", "sweet potato", "yam"], cal: 90, prot: 2, carb: 20, fat: 0.2 },
  { keywords: ["tomato", "onion", "garlic", "pepper", "carrot", "broccoli", "spinach", "lettuce", "cucumber", "vegetable", "zucchini", "mushroom", "celery"], cal: 30, prot: 2, carb: 6, fat: 0.3 },
  { keywords: ["avocado"], cal: 160, prot: 2, carb: 9, fat: 15 },
  { keywords: ["olive oil", "oil", "butter", "ghee", "coconut oil"], cal: 880, prot: 0, carb: 0, fat: 100 },
  { keywords: ["lemon", "lime", "orange", "apple", "banana", "berry", "fruit"], cal: 50, prot: 0.6, carb: 12, fat: 0.2 },
  { keywords: ["bean", "lentil", "chickpea", "legume", "tofu"], cal: 120, prot: 8, carb: 18, fat: 1 },
  { keywords: ["sugar", "honey", "maple", "syrup"], cal: 300, prot: 0, carb: 75, fat: 0 },
  { keywords: ["almond", "walnut", "cashew", "peanut", "nut", "seed"], cal: 580, prot: 20, carb: 20, fat: 50 },
  { keywords: ["sauce", "paste", "ketchup", "soy", "vinegar", "mustard", "dressing"], cal: 80, prot: 2, carb: 12, fat: 3 },
  { keywords: ["spice", "herb", "salt", "pepper", "cumin", "paprika", "oregano", "basil", "cinnamon", "turmeric"], cal: 10, prot: 0.4, carb: 2, fat: 0.3 },
  { keywords: ["stock", "broth", "water"], cal: 5, prot: 0.5, carb: 0.5, fat: 0.2 },
  { keywords: ["coconut", "coconut milk"], cal: 230, prot: 2, carb: 6, fat: 23 },
];

function parseAmountToGrams(amountStr) {
  if (!amountStr) return 100;
  const s = amountStr.toLowerCase().trim();

  // Extract numeric value
  const numMatch = s.match(/[\d.\/]+/);
  if (!numMatch) return 50; // default for "a pinch", "to taste", etc.

  let num = eval(numMatch[0]); // handles fractions like 1/2

  if (s.includes("kg")) return num * 1000;
  if (s.includes("lb")) return num * 453;
  if (s.includes("oz")) return num * 28;
  if (s.includes("g") && !s.includes("gal")) return num;
  if (s.includes("cup")) return num * 240;
  if (s.includes("tbsp") || s.includes("tablespoon")) return num * 15;
  if (s.includes("tsp") || s.includes("teaspoon")) return num * 5;
  if (s.includes("ml") || s.includes("liter") || s.includes("litre")) return num;
  if (s.includes("slice") || s.includes("piece")) return num * 50;
  if (s.includes("clove")) return num * 5;
  if (s.includes("medium") || s.includes("large") || s.includes("small")) return 100;

  // Default: treat as grams
  return num > 0 ? num : 100;
}

function lookupNutrition(ingredientName) {
  const lower = ingredientName.toLowerCase();
  for (const entry of NUTRIENT_LOOKUP) {
    if (entry.keywords.some(kw => lower.includes(kw))) {
      return entry;
    }
  }
  // Default generic food
  return { cal: 80, prot: 3, carb: 10, fat: 2 };
}

function estimateNutrition(ingredients, servings) {
  let totalCal = 0, totalProt = 0, totalCarb = 0, totalFat = 0;

  for (const group of (ingredients || [])) {
    for (const item of (group.items || [])) {
      const grams = parseAmountToGrams(item.amount);
      const nut = lookupNutrition(item.name || "");
      const factor = grams / 100;
      totalCal  += nut.cal  * factor;
      totalProt += nut.prot * factor;
      totalCarb += nut.carb * factor;
      totalFat  += nut.fat  * factor;
    }
  }

  const s = Math.max(servings || 1, 1);
  return {
    total: { calories: Math.round(totalCal), protein: Math.round(totalProt), carbs: Math.round(totalCarb), fat: Math.round(totalFat) },
    perServing: { calories: Math.round(totalCal / s), protein: Math.round(totalProt / s), carbs: Math.round(totalCarb / s), fat: Math.round(totalFat / s), fiber: 2 }
  };
}

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (user?.role !== 'admin') {
      return Response.json({ error: 'Forbidden' }, { status: 403 });
    }

    const body = await req.json().catch(() => ({}));
    const limit = body.limit || 200;

    // Fetch recipes missing nutrition per serving
    const allRecipes = await base44.asServiceRole.entities.Recipe.list('-created_date', limit);

    const missing = allRecipes.filter(r => {
      const n = r.nutrition_per_serving;
