      } catch (e) {
        errors.push({ id: recipe.id, error: e.message });
      }
    }

    return Response.json({
      success: true,
      scanned: allRecipes.length,
      missing: missing.length,
      updated,
      errors: errors.slice(0, 10),
    });
  } catch (error) {
    return Response.json({ error: error.message }, { status: 500 });
  }
});

