/**
 * backfillReviewAuthorIds — one-time migration
 * Fills in author_id on all RecipeReview records that are missing it,
 * by matching created_by (email) to User.email.
 * Admin-only.
 */
import { createClientFromRequest } from 'npm:@base44/sdk@0.8.23';

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (user?.role !== 'admin') {
      return Response.json({ error: 'Admin only' }, { status: 403 });
    }

    const sr = base44.asServiceRole;

    // Fetch all reviews missing author_id
    const allReviews = await sr.entities.RecipeReview.list('-created_date', 500);
    const missing = allReviews.filter(r => !r.author_id && r.created_by);

    if (missing.length === 0) {
      return Response.json({ ok: true, patched: 0, message: 'All reviews already have author_id' });
    }

    // Get unique emails
    const emails = [...new Set(missing.map(r => r.created_by))];

    // Fetch matching users
    const userMap = {};
    await Promise.allSettled(
      emails.map(async (email) => {
        const users = await sr.entities.User.filter({ email }).catch(() => []);
        if (users[0]) userMap[email] = users[0].id;
      })
    );

    // Patch reviews
    let patched = 0;
    await Promise.allSettled(
      missing.map(async (review) => {
        const userId = userMap[review.created_by];
        if (!userId) return;
        await sr.entities.RecipeReview.update(review.id, { author_id: userId });
        patched++;
      })
    );

    return Response.json({ ok: true, patched, total_missing: missing.length });
  } catch (err) {
    return Response.json({ error: err.message }, { status: 500 });
  }
});

/**
 * backfillShopNameOnRecipes — One-time admin utility to populate shop_name + shop_logo_url
 * on all existing shop recipes that are missing these denormalized fields.
 */
import { createClientFromRequest } from 'npm:@base44/sdk@0.8.25';

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (user?.role !== 'admin') {
      return Response.json({ error: 'Forbidden: Admin access required' }, { status: 403 });
    }

    const sr = base44.asServiceRole;

    // Get all shops
    const shops = await sr.entities.Shop.filter({});
    const shopMap = {};
    for (const s of shops) {
      shopMap[s.id] = { shop_name: s.shop_name, shop_logo_url: s.logo_image_url };
    }

    // Get all shop recipes that are missing shop_name
    const recipes = await sr.entities.Recipe.filter({ is_shop_content: true });
    let updated = 0;

    for (const recipe of recipes) {
      if (!recipe.shop_id) continue;
      const shopData = shopMap[recipe.shop_id];
      if (!shopData) continue;

      // Only update if missing
      if (!recipe.shop_name || !recipe.shop_logo_url) {
        const patch = {};
        if (!recipe.shop_name && shopData.shop_name) patch.shop_name = shopData.shop_name;
        if (!recipe.shop_logo_url && shopData.shop_logo_url) patch.shop_logo_url = shopData.shop_logo_url;
        if (Object.keys(patch).length > 0) {
          await sr.entities.Recipe.update(recipe.id, patch);
          updated++;
        }
      }
    }

    return Response.json({ ok: true, total_recipes: recipes.length, updated });
  } catch (error) {
    console.error('[BACKFILL_SHOP_NAME]', error.message);
    return Response.json({ error: error.message }, { status: 500 });
  }
});

/**
 * backfillUserAggregates — one-time admin function.
 * Recomputes total_ratings_received + avg_rating for all users
 * from their actual Recipe records.
 */
import { createClientFromRequest } from 'npm:@base44/sdk@0.8.23';

const computeVipTier = (n) => {
  if (n >= 50000) return 'mythic';
  if (n >= 10000) return 'legend';
  if (n >= 5000) return 'elite_chef';
  if (n >= 1000) return 'pro_creator';
  if (n >= 500) return 'community_favorite';
  if (n >= 100) return 'trusted_cook';
  if (n >= 50) return 'rising_chef';
  return 'starter_chef';
};

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (user?.role !== 'admin') return Response.json({ error: 'Admin only' }, { status: 403 });

    const sr = base44.asServiceRole;

    // Fetch all public recipes that have reviews
    const allRecipes = await sr.entities.Recipe.filter({ is_public: true }, '-created_date', 500).catch(() => []);

    // Group by author_id
    const byAuthor = {};
    for (const r of allRecipes) {
      if (!r.author_id) continue;
      if (!byAuthor[r.author_id]) byAuthor[r.author_id] = [];
      byAuthor[r.author_id].push(r);
    }

    let updated = 0;
    for (const [authorId, recipes] of Object.entries(byAuthor)) {
      const totalRatings = recipes.reduce((s, r) => s + (r.review_count || 0), 0);
      const totalRatingSum = recipes.reduce((s, r) => s + (r.avg_rating || 0) * (r.review_count || 0), 0);
      const overallAvg = totalRatings > 0 ? Math.round((totalRatingSum / totalRatings) * 10) / 10 : 0;

      const existing = await sr.entities.UserAggregates.filter({ user_id: authorId }).catch(() => []);
      const aggData = {
        user_id: authorId,
        total_ratings_received: totalRatings,
        avg_rating: overallAvg,
        vip_tier: computeVipTier(totalRatings),
        updated_at: new Date().toISOString(),
      };
      if (existing[0]) {
        await sr.entities.UserAggregates.update(existing[0].id, aggData).catch(() => {});
      } else {
        await sr.entities.UserAggregates.create(aggData).catch(() => {});
      }
      updated++;
    }

    return Response.json({ ok: true, authors_updated: updated });
  } catch (error) {
    console.error('[backfillUserAggregates] error:', error.message);
    return Response.json({ error: error.message }, { status: 500 });
  }
});

/**
 * batchComputeRecipePricing — Background Job for Bulk Pricing Computation
 * 
 * PART 7: BACKGROUND ENRICHMENT FOR SCALE (10k+/day)
 * 
 * Handles:
 * - Idempotent backfill of existing recipes
 * - Batch recomputation when canonical ingredients are updated
 * - Queue-based processing for high volume
 * - Progress tracking and failure logging
 * 
 * Invoked by:
 * - Scheduled automation every 1 hour
 * - Manual admin trigger for backfill
 * - Entity automation on CanonicalIngredient update
 */

import { createClientFromRequest } from 'npm:@base44/sdk@0.8.25';

const BATCH_SIZE = 100; // Process N recipes per invocation
const MAX_PROCESSING_TIME_MS = 55000; // Leave 5s buffer for serverless timeout

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();

    // Allow admin-only or scheduled invocation
    if (user && user.role !== 'admin') {
      return Response.json({ error: 'Forbidden: Admin access required' }, { status: 403 });
    }

    const { mode, recipe_ids, reason, limit } = await req.json() || {};

    // MODE 1: BACKFILL (Find recipes without pricing summary and compute)
    if (mode === 'backfill' || !mode) {
      return handleBackfill(base44, limit || BATCH_SIZE);
    }

    // MODE 2: RECOMPUTE (Specific recipe IDs, e.g., after canonical update)
    if (mode === 'recompute') {
      return handleRecompute(base44, recipe_ids, reason);
    }

    // MODE 3: REPAIR (Find recipes with suspicious pricing and fix)
    if (mode === 'repair') {
      return handleRepair(base44, limit || BATCH_SIZE);
    }

    return Response.json({ error: 'Invalid mode: backfill|recompute|repair' }, { status: 400 });
  } catch (error) {
    console.error('[batchComputeRecipePricing] error:', error.message);
    return Response.json({ error: error.message }, { status: 500 });
  }
});

async function handleBackfill(base44, limit) {
  const startTime = Date.now();

  // COST OPTIMIZATION: Only fetch recipes that DON'T already have pricing on the entity itself.
  // The repricingAdapter writes total_cost directly to Recipe — if it's >0, pricing is done.
  // This eliminates the expensive cross-entity join with RecipePricingSummary.
  const publicRecipes = await base44.asServiceRole.entities.Recipe.filter(
    { is_public: true },
    'created_date',
    limit * 2 // fetch extra to filter
  );

  // Filter to only unpriced recipes (no total_cost or total_cost=0)
  const toPrice = publicRecipes
    .filter(r => !r.total_cost || r.total_cost <= 0)
    .slice(0, limit);

  // EARLY EXIT: Nothing to price
  if (toPrice.length === 0) {
    console.log(`[batchComputeRecipePricing] backfill: all ${publicRecipes.length} public recipes already priced`);
    return Response.json({ mode: 'backfill', total_processed: 0, already_priced: publicRecipes.length, processing_time_ms: Date.now() - startTime });
  }

  let successCount = 0;
  let failureCount = 0;
  const failures = [];

  for (const recipe of toPrice) {
    if (Date.now() - startTime > MAX_PROCESSING_TIME_MS) break; // Stop if timeout imminent

    try {
      const response = await base44.asServiceRole.functions.invoke('computeRecipePricingV2', {
        recipe_id: recipe.id,
        recompute_reason: 'backfill',
      });

      if (response.data?.summary) {
        successCount++;
      } else {
        failureCount++;
        failures.push({ recipe_id: recipe.id, error: 'empty_response' });
      }
    } catch (error) {
      failureCount++;
      failures.push({ recipe_id: recipe.id, error: error.message });
    }
  }

  console.log(`[batchComputeRecipePricing] backfill completed: ${successCount} success, ${failureCount} failures`);

  return Response.json({
    mode: 'backfill',
    total_processed: toPrice.length,
    success_count: successCount,
    failure_count: failureCount,
    failures: failures.slice(0, 10),
    processing_time_ms: Date.now() - startTime,
  });
}

async function handleRecompute(base44, recipeIds, reason) {
  if (!recipeIds || !Array.isArray(recipeIds) || recipeIds.length === 0) {
    return Response.json({ error: 'recipe_ids array required' }, { status: 400 });
  }

  const startTime = Date.now();
  let successCount = 0;
  let failureCount = 0;

  for (const recipe_id of recipeIds) {
    if (Date.now() - startTime > MAX_PROCESSING_TIME_MS) break;

    try {
      await base44.asServiceRole.functions.invoke('computeRecipePricingV2', {
        recipe_id,
        recompute_reason: reason || 'manual_recompute',
      });
      successCount++;
    } catch (error) {
      failureCount++;
      console.warn(`[batchComputeRecipePricing] recompute failed for ${recipe_id}: ${error.message}`);
    }
  }

  console.log(`[batchComputeRecipePricing] recompute completed: ${successCount} success, ${failureCount} failures`);

  return Response.json({
    mode: 'recompute',
    recipes_processed: recipeIds.length,
    success_count: successCount,
    failure_count: failureCount,
    processing_time_ms: Date.now() - startTime,
  });
}

async function handleRepair(base44, limit) {
  const startTime = Date.now();

  // Find recipes with suspicious pricing
  const summaries = await base44.asServiceRole.entities.RecipePricingSummary.filter(
    { pricing_status: 'unresolved' },
    'computed_at',
    limit
  );

  let successCount = 0;
  let skipCount = 0;

  for (const summary of summaries) {
    if (Date.now() - startTime > MAX_PROCESSING_TIME_MS) break;

    // Check if recipe was updated since pricing
    const recipe = await base44.asServiceRole.entities.Recipe.filter({ id: summary.recipe_id });
    if (!recipe[0]) {
      skipCount++;
      continue;
    }

    const recipeDateMs = new Date(recipe[0].updated_date).getTime();
    const pricingDateMs = new Date(summary.computed_at).getTime();

    if (recipeDateMs > pricingDateMs) {
      // Recipe changed since pricing — recompute
      try {
        await base44.asServiceRole.functions.invoke('computeRecipePricingV2', {
          recipe_id: summary.recipe_id,
          recompute_reason: 'repair_stale',
        });
        successCount++;
      } catch (error) {
        console.warn(`[batchComputeRecipePricing] repair failed for ${summary.recipe_id}: ${error.message}`);
      }
    } else {
      skipCount++;
    }
  }

  console.log(`[batchComputeRecipePricing] repair completed: ${successCount} recomputed, ${skipCount} skipped`);

  return Response.json({
    mode: 'repair',
    summaries_reviewed: summaries.length,
    recomputed_count: successCount,
    skipped_count: skipCount,
    processing_time_ms: Date.now() - startTime,
  });
}

import { createClientFromRequest } from 'npm:@base44/sdk@0.8.20';

/**
 * blockUser — Creates a block record AND removes all follow relationships
 * between the two users (both directions).
 */
Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user) return Response.json({ error: 'Unauthorized' }, { status: 401 });

    const { target_user_id } = await req.json();
    if (!target_user_id) return Response.json({ error: 'target_user_id required' }, { status: 400 });
    if (target_user_id === user.id) return Response.json({ error: 'Cannot block yourself' }, { status: 400 });

    const sr = base44.asServiceRole;

    // Get target user info for caching
    let targetName = '';
    let targetAvatar = '';
    try {
      const targets = await sr.entities.User.filter({ id: target_user_id });
      if (targets.length > 0) {
        targetName = targets[0].display_name || targets[0].full_name || '';
        targetAvatar = targets[0].avatar_url || '';
      }
    } catch (e) {
      console.warn('[blockUser] could not fetch target user info:', e.message);
    }

    // Check if already blocked
    const existing = await sr.entities.BlockedUser.filter({
      blocker_id: user.id,
      blocked_id: target_user_id,
    });

    if (existing.length === 0) {
      await sr.entities.BlockedUser.create({
        blocker_id: user.id,
        blocked_id: target_user_id,
        blocked_name: targetName,
        blocked_avatar: targetAvatar,
        blocked_at: new Date().toISOString(),
      });
    }

    // Remove ALL follow relationships both directions (Follow entity) — handles duplicates too
    const [followAtoB, followBtoA, followAtoB2, followBtoA2] = await Promise.all([
      sr.entities.Follow.filter({ follower_id: user.id, followed_id: target_user_id }).catch(() => []),
      sr.entities.Follow.filter({ follower_id: target_user_id, followed_id: user.id }).catch(() => []),
      // Also query by followed_id to catch any index mismatches
      sr.entities.Follow.filter({ followed_id: user.id, follower_id: target_user_id }).catch(() => []),
      sr.entities.Follow.filter({ followed_id: target_user_id, follower_id: user.id }).catch(() => []),
    ]);
    const allFollowRows = [...followAtoB, ...followBtoA, ...followAtoB2, ...followBtoA2];
    const uniqueFollowIds = [...new Set(allFollowRows.map(f => f.id))];
    await Promise.all(uniqueFollowIds.map(id => sr.entities.Follow.delete(id).catch(() => {})));
    console.log(`[blockUser] Removed ${uniqueFollowIds.length} follow rows`);

    // Also clean up UserFollow entity (legacy)
    const [ufAtoB, ufBtoA] = await Promise.all([
      sr.entities.UserFollow.filter({ follower_id: user.id, following_id: target_user_id }).catch(() => []),
      sr.entities.UserFollow.filter({ follower_id: target_user_id, following_id: user.id }).catch(() => []),
    ]);
    await Promise.all([...ufAtoB, ...ufBtoA].map(f => sr.entities.UserFollow.delete(f.id).catch(() => {})));

    // Also clean up any FollowRequests
    const [frAtoB, frBtoA] = await Promise.all([
      sr.entities.FollowRequest.filter({ requester_id: user.id, target_id: target_user_id }).catch(() => []),
      sr.entities.FollowRequest.filter({ requester_id: target_user_id, target_id: user.id }).catch(() => []),
    ]);
    await Promise.all([...frAtoB, ...frBtoA].map(f => sr.entities.FollowRequest.delete(f.id).catch(() => {})));

    console.log(`[blockUser] user=${user.id} blocked target=${target_user_id}, removed follow relationships`);
    return Response.json({ ok: true, is_blocked: true });
  } catch (error) {
    console.error('[blockUser] error:', error.message);
    return Response.json({ error: error.message }, { status: 500 });
  }
});

/**
 * buildAudienceProfile — Builds/updates a user's audience profile from onboarding + behavior.
 * 
 * Called after onboarding completes, and periodically from behavior signals.
 * Creates a weighted audience-fit profile that drives recommendation ranking.
 * 
 * AUDIENCE DIMENSIONS:
 *   budget, high_protein, comfort, health_focused, quick_simple,
 *   family_style, beginner_friendly, adventurous, dessert_lover
 * 
 * DETERMINISTIC. NO LLM.
 */
import { createClientFromRequest } from 'npm:@base44/sdk@0.8.25';

// Audience dimension definitions: what signals contribute to each
const GOAL_TO_AUDIENCE = {
  'save_money': { budget: 1.5 },
  'eat_healthy': { health_focused: 1.5 },
  'lose_weight': { health_focused: 1.2, budget: 0.3 },
  'gain_muscle': { high_protein: 1.8 },
  'high_protein': { high_protein: 1.5 },
  'muscle_gain': { high_protein: 1.5 },
  'bulking': { high_protein: 1.2, comfort: 0.5 },
  'weight_loss': { health_focused: 1.5 },
  'low_calorie': { health_focused: 1.2 },
  'cutting': { health_focused: 1.0, high_protein: 0.8 },
  'quick_meals': { quick_simple: 1.5 },
  'learn_cooking': { beginner_friendly: 1.5 },
  'explore_cuisines': { adventurous: 1.5 },
  'meal_prep': { quick_simple: 0.8, budget: 0.5 },
  'family_cooking': { family_style: 1.5, comfort: 0.5 },
  'comfort_food': { comfort: 1.5 },
  'desserts': { dessert_lover: 1.5 },
  'impress_guests': { adventurous: 1.0, comfort: 0.5 },
};

const DIET_TO_TAGS = {
  'vegan': ['vegan'],
  'vegetarian': ['vegetarian'],
  'pescatarian': ['pescatarian'],
  'keto': ['keto', 'low-carb'],
  'paleo': ['paleo'],
  'gluten_free': ['gluten-free'],
  'dairy_free': ['dairy-free'],
  'halal': ['halal'],
  'kosher': ['kosher'],
};

const COOKING_LEVEL_AUDIENCE = {
  'beginner': { beginner_friendly: 1.5, quick_simple: 0.5 },
  'intermediate': { adventurous: 0.3 },
  'advanced': { adventurous: 0.8 },
};

// Behavior-to-audience mapping for interaction learning
const TAG_TO_AUDIENCE = {
  'high-protein': { high_protein: 0.3 },
  'protein': { high_protein: 0.3 },
  'budget': { budget: 0.3 },
  'cheap': { budget: 0.3 },
  'quick': { quick_simple: 0.3 },
  'easy': { beginner_friendly: 0.2, quick_simple: 0.2 },
  'comfort': { comfort: 0.3 },
  'healthy': { health_focused: 0.3 },
  'light': { health_focused: 0.2 },
  'family': { family_style: 0.3 },
  'kid-friendly': { family_style: 0.3, beginner_friendly: 0.2 },
  'dessert': { dessert_lover: 0.3 },
  'vegan': { health_focused: 0.2 },
  'vegetarian': { health_focused: 0.1 },
  'keto': { high_protein: 0.2, health_focused: 0.2 },
  'low-calorie': { health_focused: 0.3 },
};

function addWeights(target, source) {
  for (const [dim, weight] of Object.entries(source)) {
    target[dim] = (target[dim] || 0) + weight;
  }
}

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user) return Response.json({ error: 'Unauthorized' }, { status: 401 });

    const body = await req.json().catch(() => ({}));
    const targetUserId = body.user_id || user.id;

    // Only admin can build other users' profiles
    if (targetUserId !== user.id && user.role !== 'admin') {
      return Response.json({ error: 'Forbidden' }, { status: 403 });
    }

    const sr = base44.asServiceRole;

    // Fetch user data
    const users = await sr.entities.User.filter({ id: targetUserId }, null, 1).catch(() => []);
    const targetUser = users[0];
    if (!targetUser) return Response.json({ error: 'User not found' }, { status: 404 });

    // ── 1. ONBOARDING SIGNALS ────────────────────────────────────────────────
    const audienceWeights = {};
    const cuisineAffinity = {};
    const tagAffinity = {};
    const onboardingSignals = {};

    // Goals
    const goals = Array.isArray(targetUser.goals) ? targetUser.goals : [];
    onboardingSignals.goals = goals;
    for (const goal of goals) {
      const mapping = GOAL_TO_AUDIENCE[goal];
      if (mapping) addWeights(audienceWeights, mapping);
    }

    // Dietary preferences
    const dietaryPrefs = Array.isArray(targetUser.dietary_preferences) ? targetUser.dietary_preferences : [];
    onboardingSignals.dietary_preferences = dietaryPrefs;
    for (const diet of dietaryPrefs) {
      const tags = DIET_TO_TAGS[diet] || [];
      for (const t of tags) tagAffinity[t] = (tagAffinity[t] || 0) + 2.0; // Strong signal from onboarding
    }

    // Allergens
    const prefs = await sr.entities.UserPreference.filter({ owner_id: targetUserId }).catch(() => []);
    const userPref = prefs[0] || {};
    if (userPref.allergens_enabled && userPref.allergens_list) {
      onboardingSignals.allergens = userPref.allergens_list;
    }

    // Cooking level
    const cookingLevel = targetUser.cooking_level || 'beginner';
    onboardingSignals.cooking_level = cookingLevel;
    const levelMapping = COOKING_LEVEL_AUDIENCE[cookingLevel];
    if (levelMapping) addWeights(audienceWeights, levelMapping);

    // Preferred cuisines from onboarding
    const prefCuisines = Array.isArray(targetUser.preferred_cuisines) ? targetUser.preferred_cuisines : [];
    onboardingSignals.preferred_cuisines = prefCuisines;
    for (const c of prefCuisines) {
      cuisineAffinity[c] = (cuisineAffinity[c] || 0) + 2.0;
    }

    // ── 2. BEHAVIOR LEARNING (likes, saves, opens) ──────────────────────────
    const [likes, saves, liveEvents] = await Promise.all([
      sr.entities.Like.filter({ user_id: targetUserId, target_type: 'recipe' }, '-created_date', 100).catch(() => []),
      sr.entities.RecipeSave.filter({ created_by: targetUser.email }, '-created_date', 100).catch(() => []),
      sr.entities.LiveEvent.filter({ user_id: targetUserId }, '-timestamp', 200).catch(() => []),
    ]);

    let interactionCount = likes.length + saves.length;

    // Get recipe details for liked/saved to extract cuisine + tags
    const engagedIds = [...new Set([
      ...likes.map(l => l.target_id),
      ...saves.map(s => s.recipe_id),
    ])].filter(Boolean).slice(0, 50);

    if (engagedIds.length > 0) {
      // Batch fetch recipes
      const recipes = await sr.entities.Recipe.filter(
        { is_public: true }, '-created_date', 200
      ).catch(() => []);

      const engagedRecipes = recipes.filter(r => engagedIds.includes(r.id));

      for (const recipe of engagedRecipes) {
        // Cuisine affinity from behavior
        if (recipe.cuisine) {
          cuisineAffinity[recipe.cuisine] = (cuisineAffinity[recipe.cuisine] || 0) + 0.5;
        }
        // Tag affinity from behavior
        for (const tag of (recipe.tags || [])) {
          tagAffinity[tag] = (tagAffinity[tag] || 0) + 0.3;
          // Map tags to audience dimensions
          const tagMapping = TAG_TO_AUDIENCE[tag.toLowerCase()];
          if (tagMapping) addWeights(audienceWeights, tagMapping);
        }
        // Cost sensitivity from behavior
        if (recipe.cost_per_serving && recipe.cost_per_serving < 5) {
          audienceWeights.budget = (audienceWeights.budget || 0) + 0.1;
        }
        // Difficulty → beginner/quick signals
        if (recipe.difficulty === 'easy') {
          audienceWeights.beginner_friendly = (audienceWeights.beginner_friendly || 0) + 0.1;
          audienceWeights.quick_simple = (audienceWeights.quick_simple || 0) + 0.1;
        }
      }
    }

    // Notification click behavior
    const notifClicks = liveEvents.filter(e => e.event_type === 'click_notification');
    interactionCount += notifClicks.length;
    for (const click of notifClicks) {
      const strategy = click.metadata?.notification_type || click.metadata?.strategy;
      if (strategy) {
        // Clicking a strategy notification = mild positive signal for related dimension
        if (strategy.includes('cost') || strategy.includes('budget')) audienceWeights.budget = (audienceWeights.budget || 0) + 0.2;
        if (strategy.includes('lazy') || strategy.includes('energy')) audienceWeights.quick_simple = (audienceWeights.quick_simple || 0) + 0.2;
        if (strategy.includes('waste') || strategy.includes('rescue')) audienceWeights.health_focused = (audienceWeights.health_focused || 0) + 0.1;
      }
    }

    // ── 3. DETERMINE MATURITY ────────────────────────────────────────────────
    let maturity = 'cold_start';
    if (interactionCount >= 50) maturity = 'mature';
    else if (interactionCount >= 15) maturity = 'warm';
    else if (interactionCount >= 3) maturity = 'warming';

    // ── 4. UPSERT PROFILE ────────────────────────────────────────────────────
    const existing = await sr.entities.UserAudienceProfile.filter(
      { user_id: targetUserId }, null, 1
    ).catch(() => []);

    const profileData = {
      user_id: targetUserId,
      onboarding_signals: onboardingSignals,
      audience_weights: audienceWeights,
      cuisine_affinity: cuisineAffinity,
      tag_affinity: tagAffinity,
      interaction_count: interactionCount,
      profile_maturity: maturity,
      last_updated: new Date().toISOString(),
    };

    if (existing[0]) {
      await sr.entities.UserAudienceProfile.update(existing[0].id, profileData);
    } else {
      await sr.entities.UserAudienceProfile.create(profileData);
    }

