/**
 * BUILD IMAGE PROMPT — STRICT FORMAT FOR FLUX.1-SCHNELL
 * 
 * Generates a deterministic, structured prompt that forces:
 * 1. Ingredient visibility
 * 2. Critical component emphasis
 * 3. No missing elements
 * 4. FLUX.1-schnell optimization
 */

import { createClientFromRequest } from 'npm:@base44/sdk@0.8.23';

const CONCEPT_IMAGE_RULES = {
  'burger': {
    critical_components: ['grilled beef patties', 'burger patties', 'meat patties visible'],
    description: 'burger with clearly visible grilled patties',
  },
  'shawarma': {
    critical_components: ['shawarma meat filling', 'sliced meat layers', 'meat strips visible'],
    description: 'shawarma with meat filling clearly visible',
  },
  'sandwich': {
    critical_components: ['bread visible', 'sandwich structure clear'],
    description: 'sandwich with bread structure visible',
  },
};

function normalizeString(s) {
  return s.toLowerCase().replace(/[^a-z0-9 ]/g, ' ').trim();
}

function detectConcepts(recipe) {
  const text = [
    recipe.title,
    recipe.description,
    recipe.ingredients?.flatMap(g => g.items?.map(i => i.name)).join(' '),
    recipe.steps?.map(s => s.instruction).join(' '),
  ].filter(Boolean).join(' ');

  const normalized = normalizeString(text);
  const detected = [];

  if (normalized.includes('burger') || normalized.includes('patty')) {
    detected.push('burger');
  }
  if (normalized.includes('shawarma') || normalized.includes('doner')) {
    detected.push('shawarma');
  }
  if (normalized.includes('sandwich')) {
    detected.push('sandwich');
  }

  return detected;
}

function extractKeyIngredients(recipe) {
  const ingredients = [];
  const seen = new Set();

  if (recipe.ingredients) {
    for (const group of recipe.ingredients) {
      if (group.items) {
        for (const item of group.items) {
          const name = item.name?.toLowerCase().trim();
          if (name && !seen.has(name) && name.length > 2) {
            ingredients.push(name);
            seen.add(name);
            if (ingredients.length >= 6) break; // Limit to 6 key ingredients
          }
        }
      }
    }
  }

  return ingredients;
}

function buildImagePrompt(recipe) {
  if (!recipe || !recipe.title) {
    throw new Error('recipe with title required');
  }

  const concepts = detectConcepts(recipe);
  const keyIngredients = extractKeyIngredients(recipe);

  // Build critical components list
  const criticalParts = [];
  for (const concept of concepts) {
    const rule = CONCEPT_IMAGE_RULES[concept];
    if (rule) {
      criticalParts.push(rule.critical_components[0]);
    }
  }

  // Format ingredient list
  const ingredientList = keyIngredients.length > 0 
    ? keyIngredients.join(', ')
    : 'freshly prepared ingredients';

  // Build the deterministic prompt
  const prompt = [
    `A high-quality professional food photograph of ${recipe.title},`,
    criticalParts.length > 0
      ? `clearly showing ${criticalParts.join(' and ')},`
      : `beautifully plated,`,

    `top-down and 45-degree angle combined composition,`,
    `natural soft lighting with subtle shadows, high detail textures,`,

    `visible key ingredients include: ${ingredientList},`,

    `food styling: realistic plating on ceramic or modern plate, no blur, no abstraction, no artistic distortion,`,
    `sharp focus throughout, 4k professional food photography, restaurant-quality presentation,`,

    criticalParts.length > 0
      ? `CRITICAL: the image must clearly and unmistakably show ${criticalParts.join(' and ')},`
      : `CRITICAL: no missing ingredients, accurate representation of the complete recipe,`,

    `no substitutions, no ingredient omissions, every element of the recipe visible and identifiable,`,
    `warm color grading, vibrant but natural colors, editorial food magazine style.`,
  ].join(' ');

  return {
    prompt,
    concepts,
    critical_components: criticalParts,
    key_ingredients: keyIngredients,
  };
}

Deno.serve(async (req) => {
  try {
    const { recipe } = await req.json();

    if (!recipe) {
      return Response.json({ error: 'recipe required' }, { status: 400 });
    }

    const result = buildImagePrompt(recipe);

    return Response.json(result);

  } catch (error) {
    console.error('[buildImagePrompt] error:', error.message);
    return Response.json({ error: error.message }, { status: 500 });
  }
});

/**
 * STRUCTURAL IMAGE PROMPT BUILDER
 * 
 * Builds image prompts from validated recipe structure, not vague summaries.
 * Ensures all required visual concepts are explicit in the prompt.
 */

import { createClientFromRequest } from 'npm:@base44/sdk@0.8.23';

/**
 * Build image prompt from validated recipe and requirements
 * 
 * Returns strict prompt that includes:
 * - dish type
 * - required structural elements
 * - required visible components
 * - critical visibility rules
 */
function buildImagePrompt(recipe, validation, requiredConcepts) {
  if (!validation.valid) {
    throw new Error(
      `Cannot build image prompt: Recipe validation failed. ` +
      `Missing: ${validation.missing_concepts.join(', ')}`
    );
  }

  const dishName = recipe.title || 'dish';

  // Build required structural elements description
  const structuralElements = [];

  if (requiredConcepts.required_proteins.length > 0) {
    for (const protein of requiredConcepts.required_proteins) {
      if (protein === 'patty') structuralElements.push('visible burger patties');
      if (protein === 'shawarma_filling') structuralElements.push('visible shawarma filling or sliced shawarma meat');
      if (protein === 'sliced_meat') structuralElements.push('visible sliced meat layers');
    }
  }

  if (requiredConcepts.required_structural.length > 0) {
    for (const structural of requiredConcepts.required_structural) {
      if (structural === 'bun') structuralElements.push('visible burger bun/bread');
      if (structural === 'bread') structuralElements.push('visible bread base');
      if (structural === 'wrap_shell') structuralElements.push('visible wrap');
    }
  }

  // Build visible ingredients
  const visibleIngredients = [];

  if (requiredConcepts.required_toppings.length > 0) {
    for (const topping of requiredConcepts.required_toppings) {
      if (topping === 'cheese') visibleIngredients.push('melted or layered cheese');
      if (topping === 'lettuce') visibleIngredients.push('fresh lettuce');
      if (topping === 'tomato') visibleIngredients.push('tomato slices');
      if (topping === 'onion') visibleIngredients.push('onion');
    }
  }

  // Build critical omission rules
  const omissionRules = [];
  if (requiredConcepts.forbidden_omissions.length > 0) {
    for (const forbidden of requiredConcepts.forbidden_omissions) {
      if (forbidden === 'patty') {
        omissionRules.push('Do not omit burger patties');
      }
      if (forbidden === 'shawarma_filling') {
        omissionRules.push('Do not omit shawarma filling or shawarma meat — it must be visibly present');
      }
      if (forbidden === 'bun') {
        omissionRules.push('Do not omit the burger bun');
      }
    }
  }

  // Build the prompt
  const prompt = `
A high-quality realistic professional food photograph of ${dishName}.

REQUIRED STRUCTURAL ELEMENTS:
${structuralElements.map(e => `- ${e}`).join('\n')}

VISIBLE INGREDIENTS:
${visibleIngredients.length > 0 ? visibleIngredients.map(i => `- ${i}`).join('\n') : '- All fresh, quality ingredients'}

CRITICAL VISIBILITY RULES:
${omissionRules.length > 0 ? omissionRules.map(r => `- ${r}`).join('\n') : '- All requested components must be visible'}

SHOT AS:
Restaurant-quality food photography
Realistic plating and composition
Natural, appetizing lighting
Sharp, detailed focus
Clean, professional presentation
No abstraction, no substitutions, no missing ingredients

This must accurately represent a ${requiredConcepts.primary_dishes.join(' and ')} with ${requiredConcepts.all_required.join(', ')}.
`.trim();

  return {
    prompt,
    structural_elements: structuralElements,
    visible_ingredients: visibleIngredients,
    omission_rules: omissionRules,
  };
}

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const { recipe, validation, required_concepts } = await req.json();

    if (!recipe || !validation || !required_concepts) {
