// Oil density correction: 1ml oil ≈ 0.911g (not 1g)
// Applied when ingredient is oil AND unit is volumetric
const OIL_DENSITY = 0.911;
const OIL_KEYWORDS = ['oil', 'ghee'];
const VOLUME_UNITS = new Set(['ml', 'l', 'tsp', 'tbsp', 'tablespoon', 'teaspoon', 'cup', 'cups']);

function isOilIngredient(name) {
  const lower = (name || '').toLowerCase();
  return OIL_KEYWORDS.some(kw => lower.includes(kw));
}

function parseAmount(amount) {
  if (!amount) return { qty: 100, unit: "g" };
  const s = amount.toString().trim();
  const match = s.match(/^([\d.]+(?:\/[\d.]+)?)\s*(.*)$/);
  if (!match) return { qty: 100, unit: "g" };
  let qty;
  if (match[1].includes("/")) {
    const [n, d] = match[1].split("/");
    qty = parseFloat(n) / parseFloat(d);
  } else {
    qty = parseFloat(match[1]) || 100;
  }
  return { qty, unit: (match[2] || "g").trim() || "g" };
}

function localNutrition(name) {
  const lower = name.toLowerCase().trim();
  if (FOODS[lower]) return FOODS[lower];

  // Spice/seasoning detection — always zero before partial matching
  // Prevents "pepper" from matching "bell pepper" data
  const SPICE_KEYWORDS = ['pepper', 'salt', 'paprika', 'cumin', 'cinnamon', 'oregano', 'basil', 'thyme', 'rosemary', 'turmeric', 'cayenne', 'chili powder', 'garlic powder', 'onion powder', 'herb', 'seasoning', 'spice'];
  for (const spice of SPICE_KEYWORDS) {
    if (lower === spice || lower.startsWith(spice + ' ') || lower.endsWith(' ' + spice)) {
      return { cal: 0, p: 0, c: 0, f: 0 };
    }
  }

  // Partial match: longest key that name contains (prefer specificity)
  let best = null;
  let bestLen = 0;
  for (const [key, v] of Object.entries(FOODS)) {
    if (key.length > 3 && lower.includes(key) && key.length > bestLen) {
      best = v;
      bestLen = key.length;
    }
  }
  if (best) return best;

  // Generic estimate for unknown ingredients
  return { cal: 80, p: 3, c: 12, f: 2 };
}

Deno.serve(async (req) => {
  const base44 = createClientFromRequest(req);

  let body;
  try { body = await req.json(); } catch { return Response.json({ error: "Invalid JSON" }, { status: 400 }); }

  /**
   * NEW CONTRACT: Frontend must send canonical grams only.
   * 
   * Expected payload:
   * {
   *   ingredients: [
   *     { name: "chicken breast", grams: 150 },
   *     { name: "quinoa", grams: 120 }
   *   ],
   *   servings: 2,
   *   recipe_default_servings: 1  (optional, for validation)
   * }
   */
  const { ingredients = [], servings = 1, recipe_default_servings = 1 } = body;

  // Auth check
  const user = await base44.auth.me();
  if (!user) return Response.json({ error: "Unauthorized" }, { status: 401 });

  if (!ingredients.length) {
    const zero = { calories: 0, protein: 0, carbs: 0, fat: 0 };
    return Response.json({ 
      total: zero, 
      perServing: zero, 
      servings: Math.max(1, servings),
      confidence_level: "empty",
      ingredients: [] 
    });
  }

  // Validate and process ingredients
  let hasConfidenceIssues = false;
  const results = [];

  for (const item of ingredients) {
    if (!item.name) continue;
    if (item.optional) continue;

    // STRICT: Validate grams is present and valid
    try {
      validateGramsInput(item.grams, item.name);
    } catch (err) {
      return Response.json({ error: err.message }, { status: 400 });
    }

    const v = localNutrition(item.name);
    // Use raw grams from payload — frontend NutritionEngine already applied oil density
    // but backend receives pre-normalized grams, so no second density correction here.
    const gramsUsed = item.grams;

    // Accumulate full-precision floats — NO rounding before aggregation
    results.push({
      name: item.name,
      grams: gramsUsed,
      grams_confidence: item.grams_confidence || "user-provided",
      // Store unrounded for accurate summation
      calories: (v.cal / 100) * gramsUsed,
      protein:  (v.p   / 100) * gramsUsed,
      carbs:    (v.c   / 100) * gramsUsed,
      fat:      (v.f   / 100) * gramsUsed,
    });

    // Track confidence issues for metadata
    if (item.grams_confidence === 'estimated-fallback-unsafe') {
      hasConfidenceIssues = true;
    }
  }

  if (!results.length) {
    const zero = { calories: 0, protein: 0, carbs: 0, fat: 0 };
    return Response.json({ 
      total: zero, 
      perServing: zero, 
      servings: Math.max(1, servings),
      confidence_level: "empty",
      ingredients: [] 
    });
  }

  // Sum all ingredients — full precision, no intermediate rounding
  const totalRaw = results.reduce((acc, r) => ({
    calories: acc.calories + r.calories,
    protein:  acc.protein  + r.protein,
    carbs:    acc.carbs    + r.carbs,
    fat:      acc.fat      + r.fat,
  }), { calories: 0, protein: 0, carbs: 0, fat: 0 });

  // Sanity check: fat > total ingredient weight * 0.95 is physically impossible
  const totalGrams = results.reduce((s, r) => s + r.grams, 0);
  if (totalRaw.fat > totalGrams * 0.95) {
    console.error(`[calcNutrition] SANITY FAIL: fat=${totalRaw.fat.toFixed(1)}g > 95% of totalGrams=${totalGrams.toFixed(1)}g`);
    return Response.json({ error: "SANITY_FAT_EXCEEDS_WEIGHT", detail: "Likely unit parsing error in ingredient grams" }, { status: 422 });
  }

  // Sanity check: calories should roughly match macros (within ±5%)
  // Formula: cal ≈ protein*4 + carbs*4 + fat*9
  const macroCalories = totalRaw.protein * 4 + totalRaw.carbs * 4 + totalRaw.fat * 9;
  if (totalRaw.calories > 0 && Math.abs(totalRaw.calories - macroCalories) / totalRaw.calories > 0.25) {
    // Log mismatch but don't fail — FOODS table uses direct cal values so slight deviation is ok
    console.warn(`[calcNutrition] Calorie/macro mismatch: computed=${totalRaw.calories.toFixed(0)} vs macro-derived=${macroCalories.toFixed(0)}`);
  }

  // Round ONLY at final output layer
  const sv = Math.max(1, servings);
  const round1 = (v) => Math.round(v * 10) / 10;

  const total = {
    calories: round1(totalRaw.calories),
    protein:  round1(totalRaw.protein),
    carbs:    round1(totalRaw.carbs),
    fat:      round1(totalRaw.fat),
  };

  const perServing = {
    calories: round1(totalRaw.calories / sv),
    protein:  round1(totalRaw.protein  / sv),
    carbs:    round1(totalRaw.carbs    / sv),
    fat:      round1(totalRaw.fat      / sv),
  };

  return Response.json({
    total,
    perServing,
    servings: sv,
    confidence_level: hasConfidenceIssues ? "partial" : "authoritative",
    ingredients: results.map(r => ({ ...r, calories: round1(r.calories), protein: round1(r.protein), carbs: round1(r.carbs), fat: round1(r.fat) })),
    _metadata: {
      backend_policy: "Round only at output. No yield factor. Oil density corrected at frontend (0.911g/ml).",
      canonical_grams: true,
      double_scaling_prevented: true,
    }
  });
});

/**
 * calculateStageMetrics — Staged Content Distribution Engine
 *
 * Called by scheduler (every 30 min) OR manually for a specific post_id.
 * Processes all active Stage 1-8 posts and advances/decays them based on performance.
 *
 * STAGE LADDER:
 *   Stage 1: test batch  (target 50 impressions)   → advance if score ≥ 0.10
 *   Stage 2: local reach (target 150 impressions)  → advance if score ≥ 0.12
 *   Stage 3: broad       (target 400 impressions)  → advance if score ≥ 0.15
 *   Stage 4: viral       (target 1,000)            → advance if score ≥ 0.18
 *   Stage 5: mega        (target 2,500)            → advance if score ≥ 0.20
 *   Stage 6: trending    (target 6,000)            → advance if score ≥ 0.22
 *   Stage 7: featured    (target 15,000)           → advance if score ≥ 0.25
 *   Stage 8: top         (target 40,000)           → max stage
 *
 * SCORE FORMULA:
 *   score = CTR×0.15 + ER×0.20 + Dwell×0.15 + Rating×0.15 + SaveRate×0.25 + Integrity×0.10
 *
 * DECAY:
 *   - score < threshold/2  → status='limited' (soft decay)
 *   - score < threshold/4  → status='limited' (harder decay, remains in stage)
 *   - integrity_score < 0.4 → status='limited' immediately
 *   - Decay never removes post instantly — it reduces distribution weight in feed
 *
 * FAIRNESS GUARDRAILS:
 *   - New posts (stage=1, impressions<10) are NEVER decayed — guaranteed initial test window
 *   - Posts younger than 2 hours always advance if not actively failing
 */
import { createClientFromRequest } from 'npm:@base44/sdk@0.8.23';

// Impression target per stage before evaluation
const STAGE_TARGETS = [0, 50, 150, 400, 1000, 2500, 6000, 15000, 40000];

// Minimum score to advance to next stage
const ADVANCE_THRESHOLDS = {
  1: 0.10,
  2: 0.12,
  3: 0.15,
  4: 0.18,
  5: 0.20,
  6: 0.22,
  7: 0.25,
  8: 0.28,
};

// Score below (threshold * DECAY_RATIO) triggers soft decay
const DECAY_RATIO = 0.5;
const MAX_STAGE = 8;

function computeRankScore(post) {
  const impressions = Math.max(1, post.stage_impressions || 1);
  const opens = post.opens || 0;
  const likes = post.like_count || 0;
  const comments = post.comment_count || 0;
  const saves = post.save_count || 0;

  // CTR: click-through rate, normalized (10% CTR = perfect score)
  const ctr = opens / impressions;
  const ctrScore = Math.min(1.0, ctr / 0.10);

  // ER: engagement rate, normalized (5% ER = perfect score)
  const engagements = likes + (comments * 2) + (saves * 3);
  const er = engagements / impressions;
  const erScore = Math.min(1.0, er / 0.05);

  // Dwell: 30s = perfect, 0s = zero
  const dwellScore = Math.min(1.0, (post.dwell_rolling || 0) / 30.0);

  // Rating: Bayesian weighted /5
  const ratingScore = (post.rating_bayes || 0) / 5.0;

  // Save rate: strongest intent signal (5% save rate = perfect)
  const saveRate = saves / impressions;
  const saveScore = Math.min(1.0, saveRate / 0.05);

  // Integrity: 1.0 = clean, 0.0 = flagged
  const integrityScore = Math.max(0, Math.min(1.0, post.integrity_score ?? 1.0));

  const score =
    (ctrScore    * 0.15) +
    (erScore     * 0.20) +
    (dwellScore  * 0.15) +
    (ratingScore * 0.15) +
    (saveScore   * 0.25) +
    (integrityScore * 0.10);

  return {
    score: +score.toFixed(4),
    breakdown: {
      ctrScore: +ctrScore.toFixed(3),
      erScore: +erScore.toFixed(3),
      dwellScore: +dwellScore.toFixed(3),
      ratingScore: +ratingScore.toFixed(3),
      saveScore: +saveScore.toFixed(3),
      integrityScore: +integrityScore.toFixed(3),
      ctr: +ctr.toFixed(4),
      er: +er.toFixed(4),
      saveRate: +saveRate.toFixed(4),
    },
  };
}

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user || user.role !== 'admin') {
      return Response.json({ error: 'Admin only' }, { status: 403 });
    }

    const body = await req.json().catch(() => ({}));
    const { post_id, dry_run = false } = body;
    const now = Date.now();
    const runId = `stage_${Date.now()}`;

    let posts = [];

    if (post_id) {
      // Single post mode
      const rows = await base44.asServiceRole.entities.Post.filter({ id: post_id }).catch(() => []);
      posts = rows;
    } else {
      // Batch mode: process all active community posts in stages 1-7
      const batch = await base44.asServiceRole.entities.Post.filter(
        { type: 'community', status: 'active' },
        '-created_date',
        500
      ).catch(() => []);
      // Also grab 'limited' posts — they can recover if metrics improve
      const limited = await base44.asServiceRole.entities.Post.filter(
        { type: 'community', status: 'limited' },
        '-created_date',
        200
      ).catch(() => []);
      posts = [...batch, ...limited].filter(p => (p.stage || 0) >= 1 && (p.stage || 0) <= MAX_STAGE);
    }

    console.log(`[STAGE_ENGINE:${runId}] processing ${posts.length} posts dry_run=${dry_run}`);

    const results = [];
    let advanced = 0, decayed = 0, recovered = 0, held = 0, newProtected = 0;

    for (const post of posts) {
      const stage = post.stage || 1;
      const impressions = post.stage_impressions || 0;
      const stageTarget = STAGE_TARGETS[stage] || 50;
      const advanceThreshold = ADVANCE_THRESHOLDS[stage] || 0.10;
      const decayThreshold = advanceThreshold * DECAY_RATIO;
      const ageHours = (now - new Date(post.created_date || now).getTime()) / 3600000;

      const { score, breakdown } = computeRankScore(post);

      // ── FAIRNESS: New post protection window ─────────────────────────────
      // Posts in Stage 1 with < 10 impressions OR < 2 hours old are NEVER decayed.
      // They need their initial test window before any judgment.
      const isNew = stage === 1 && (impressions < 10 || ageHours < 2);
      if (isNew) {
        newProtected++;
        results.push({
          post_id: post.id, stage, impressions, score,
          decision: 'new_protected', reason: `age=${ageHours.toFixed(1)}h impressions=${impressions}`,
        });
        continue;
      }

      // ── Not enough impressions yet — hold and wait ────────────────────────
      if (impressions < stageTarget) {
        held++;
        results.push({
          post_id: post.id, stage, impressions, score,
          decision: 'hold', reason: `need ${stageTarget - impressions} more impressions`,
        });
        continue;
      }

      // ── Integrity failure — force limit regardless of score ───────────────
      if ((post.integrity_score ?? 1.0) < 0.4) {
        if (!dry_run) {
          await base44.asServiceRole.entities.Post.update(post.id, {
            status: 'limited',
            last_metrics_update: new Date().toISOString(),
          }).catch(() => {});
        }
        decayed++;
        results.push({
          post_id: post.id, stage, impressions, score,
          decision: 'integrity_decay', reason: `integrity=${post.integrity_score}`,
          breakdown,
        });
        continue;
      }

      // ── Decision: Advance, Hold, Decay, or Recover ───────────────────────
      const patch = { last_metrics_update: new Date().toISOString() };
      let decision, reason;

      if (score >= advanceThreshold && stage < MAX_STAGE) {
        // ADVANCE
        patch.stage = stage + 1;
        patch.stage_passed_at = new Date().toISOString();
        patch.status = 'active'; // recover from limited if it was
        decision = 'advance';
        reason = `score ${score} ≥ threshold ${advanceThreshold} → stage ${stage + 1}`;
        advanced++;

      } else if (score >= decayThreshold) {
        // HOLD at current stage — performing adequately but not ready to advance
        if (post.status === 'limited') {
          // Recovery: was limited but score improved
          patch.status = 'active';
          decision = 'recover';
          reason = `score ${score} ≥ decay threshold ${decayThreshold} → recovered`;
          recovered++;
        } else {
          decision = 'hold';
          reason = `score ${score} between decay(${decayThreshold}) and advance(${advanceThreshold}) thresholds`;
          held++;
        }

      } else {
        // DECAY — score below decay threshold
        patch.status = 'limited';
        decision = 'decay';
        reason = `score ${score} < decay threshold ${decayThreshold}`;
        decayed++;
      }

      if (!dry_run) {
        await base44.asServiceRole.entities.Post.update(post.id, patch).catch(e =>
          console.warn(`[STAGE_ENGINE] post ${post.id} update failed:`, e.message)
        );
      }

      results.push({
        post_id: post.id,
        title: (post.title || '').slice(0, 40),
        stage,
        new_stage: patch.stage || stage,
        impressions,
        score,
        decision,
        reason,
        breakdown,
      });

      // Analytics event for admin auditing
      if (!dry_run && (decision === 'advance' || decision === 'decay')) {
        base44.asServiceRole.entities.AdminAnalyticsEvent.create({
          event_type: `stage_${decision}`,
          event_category: 'engagement',
          feature_area: 'distribution_engine',
          user_id: post.author_id || '',
          metadata_json: JSON.stringify({
            post_id: post.id,
            from_stage: stage,
            to_stage: patch.stage || stage,
            score,
            impressions,
            breakdown,
            run_id: runId,
          }),
          status: 'success',
        }).catch(() => {});
      }
    }

    const summary = {
      run_id: runId,
      dry_run,
      total: posts.length,
      advanced,
      decayed,
      recovered,
      held,
      new_protected: newProtected,
    };

    console.log(`[STAGE_ENGINE:${runId}] done:`, JSON.stringify(summary));

    return Response.json({ summary, results });
  } catch (error) {
    console.error('[STAGE_ENGINE] error:', error.message);
    return Response.json({ error: error.message }, { status: 500 });
  }
});

/**
 * cascadeProfileUpdate — Full identity propagation across all denormalized entities.
 *
 * When a user changes display_name or avatar_url this updates ALL cached
 * identity snapshots in the database so every surface reflects the new identity.
 *
 * Entities covered:
 *  - Recipe            → author_name, author_avatar
 *  - GroupPost         → author_name, author_avatar
 *  - ChatMessage       → sender_name, sender_avatar_url
 *  - PostComment       → author_name, author_avatar
 *  - GroupPostComment  → author_name, author_avatar
 *  - RecipeReview      → author_name, author_avatar
 *  - Message (DM)      → sender_name/avatar  (where sender_id = me)
 *                        recipient_name/avatar (where recipient_id = me)
 *  - UserFollow        → follower_name, follower_avatar
 *  - FollowRequest     → requester_name, requester_avatar
 *  - BlockedUser       → blocked_name, blocked_avatar (where blocked_id = me)
 *  - Notification      → from_user_name, from_user_avatar
 *  - DirectConversation → participant_a/b_name, participant_a/b_avatar
 */
import { createClientFromRequest } from 'npm:@base44/sdk@0.8.21';

async function batchUpdate(entity, records, fields) {
  if (!records || records.length === 0) return 0;
  await Promise.all(records.map(r => entity.update(r.id, fields).catch(() => {})));
  return records.length;
}

