      batchUpdate(sr.Message,            dmReceived,      { recipient_name: display_name, recipient_avatar: avatar_url }),
      batchUpdate(sr.UserFollow,         follows,         { follower_name: display_name, follower_avatar: avatar_url }),
      batchUpdate(sr.FollowRequest,      followReqs,      { requester_name: display_name, requester_avatar: avatar_url }),
      batchUpdate(sr.BlockedUser,        blockedAsTarget, { blocked_name: display_name, blocked_avatar: avatar_url }),
      batchUpdate(sr.Notification,       notifications,   { from_user_name: display_name, from_user_avatar: avatar_url }),
      batchUpdate(sr.DirectConversation, dcAsA,           { participant_a_name: display_name, participant_a_avatar: avatar_url }),
      batchUpdate(sr.DirectConversation, dcAsB,           { participant_b_name: display_name, participant_b_avatar: avatar_url }),
    ]);

    const breakdown = {
      recipes:         counts[0],
      groupPosts:      counts[1],
