      groupComments:   counts[4],
      dmSent:          counts[5],
      dmReceived:      counts[6],
      follows:         counts[7],
      followReqs:      counts[8],
      blocked:         counts[9],
      notifications:   counts[10],
      directConvAsA:   counts[11],
      directConvAsB:   counts[12],
    };
    const total = Object.values(breakdown).reduce((s, c) => s + c, 0);

    console.log(`[cascadeProfileUpdate] done — total=${total}`, breakdown);
    return Response.json({ ok: true, updated: total, breakdown });

  } catch (err) {
    console.error('[cascadeProfileUpdate]', err.message);
    return Response.json({ error: err.message }, { status: 500 });
  }
});

/**
 * changeUsername — Backend-authoritative username change with 24h cooldown enforcement.
 *
 * This is the ONLY place a username change is committed.
 * Frontend cannot bypass this by calling base44.auth.updateMe directly for username.
 *
 * Flow:
 *   1. Auth check
 *   2. Format validation
 *   3. Availability check (uniqueness)
 *   4. Cooldown check (24h since username_last_changed_at)
 *   5. Save username
 *   6. Set username_last_changed_at = now (AFTER successful save only)
 */
import { createClientFromRequest } from 'npm:@base44/sdk@0.8.21';

const COOLDOWN_MS = 24 * 60 * 60 * 1000; // 24 hours in milliseconds

function validateUsernameFormat(username) {
  if (!username || typeof username !== 'string') return 'Username is required';
  const trimmed = username.trim().toLowerCase();
  if (trimmed.length < 2) return 'Must be at least 2 characters';
  if (trimmed.length > 14) return 'Must be 14 characters or fewer';
  if (!/^[a-z0-9_.]+$/.test(trimmed)) return 'Only letters, numbers, underscores, and dots allowed';
  return null;
}

function computeRemainingTime(lastChangedAt) {
  const last = new Date(lastChangedAt).getTime();
  const now = Date.now();
  const elapsed = now - last;
  const remaining = COOLDOWN_MS - elapsed;
  if (remaining <= 0) return null; // cooldown expired

  const totalMinutes = Math.ceil(remaining / 60000);
  const hours = Math.floor(totalMinutes / 60);
  const minutes = totalMinutes % 60;
  return { remaining_ms: remaining, hours, minutes };
}

Deno.serve(async (req) => {
  if (req.method !== 'POST') {
    return Response.json({ error: 'Method not allowed' }, { status: 405 });
  }

  try {
    const base44 = createClientFromRequest(req);

    // 1. Auth check
    const user = await base44.auth.me();
    if (!user) return Response.json({ error: 'Unauthorized' }, { status: 401 });

    const body = await req.json().catch(() => ({}));
    const newUsername = (body.username || '').trim().toLowerCase();

    // 2. Format validation
    const formatErr = validateUsernameFormat(newUsername);
    if (formatErr) {
      return Response.json({ error: 'INVALID_FORMAT', message: formatErr }, { status: 400 });
    }

    // 3. No-op if username is unchanged
    const currentUsername = (user.username || '').toLowerCase();
    if (newUsername === currentUsername) {
      return Response.json({ ok: true, changed: false, message: 'Username unchanged' });
    }

    // 4. Cooldown check — backend is sole authority, never trust frontend timestamp
    if (user.username_last_changed_at) {
      const remaining = computeRemainingTime(user.username_last_changed_at);
      if (remaining !== null) {
        const msg = remaining.hours > 0
          ? `You can change your username again in ${remaining.hours}h ${remaining.minutes}m`
          : `You can change your username again in ${remaining.minutes}m`;
        return Response.json({
          error: 'USERNAME_COOLDOWN',
          message: msg,
          remaining_hours: remaining.hours,
          remaining_minutes: remaining.minutes,
          remaining_ms: remaining.remaining_ms,
        }, { status: 429 });
      }
    }

    // 5. Availability check — ensure no other user has this username
    const existing = await base44.asServiceRole.entities.User.filter({ username: newUsername });
    const takenByOther = existing.filter(u => u.id !== user.id);
    if (takenByOther.length > 0) {
      return Response.json({ error: 'USERNAME_TAKEN', message: 'Username is already taken' }, { status: 409 });
    }

    // 6. Save username — timestamp is set ONLY after this succeeds
    await base44.auth.updateMe({ username: newUsername });

    // 7. Set cooldown timestamp NOW (after successful save)
    await base44.auth.updateMe({ username_last_changed_at: new Date().toISOString() });

    console.log(`[changeUsername] user=${user.id} changed username from "${currentUsername}" to "${newUsername}"`);

    return Response.json({ ok: true, changed: true, username: newUsername });

  } catch (err) {
    console.error('[changeUsername] Error:', err.message);
    return Response.json({ error: err.message }, { status: 500 });
  }
});

