      .filter(e => e.credit_state === 'earned' && (e.credits_remaining || 0) > 0)
      .reduce((sum, e) => sum + (e.credits_remaining || 0), 0);
    const totalAvailable = weeklyRemaining + bankedCredits;
    const allowed = totalAvailable > 0;

    const nextWeekStart = new Date(weekStart);
    nextWeekStart.setDate(nextWeekStart.getDate() + 7);
    const resetDate = nextWeekStart.toISOString().split('T')[0];

    console.log(`[CHECK_GEN_LIMIT] user=${user.id} weeklyUsed=${used} weeklyRemaining=${weeklyRemaining} banked=${bankedCredits} total=${totalAvailable} allowed=${allowed}`);

    if (!allowed) {
      return Response.json({
