        message: "You've used all your generations. Invite friends to earn more!",
        allowed: false,
        used,
        limit,
        remaining: 0,
        banked_referral_credits: 0,
        total_available: 0,
        resetDate,
        show_referral_plus_button: true,
      }, { status: 429 });
    }

    return Response.json({
      allowed: true,
      used,
      limit,
      remaining: weeklyRemaining,
      banked_referral_credits: bankedCredits,
      total_available: totalAvailable,
      resetDate,
      show_referral_plus_button: weeklyRemaining === 0,
    });
  } catch (error) {
    console.error('checkGenerationLimitAdvanced error:', error);
    return Response.json({ error: error.message }, { status: 500 });
  }
});

function getWeekStartDate(date) {
  const d = new Date(date);
  const day = d.getDay() || 7; // 0 (Sun) -> 7
  d.setDate(d.getDate() - (day - 1)); // Go to Monday
  d.setHours(0, 0, 0, 0);
  return d;
}

