/**
 * checkProGenerationLimit
 *
 * Backend-authoritative PRO generation gate.
 * Called BEFORE any generation starts.
 *
 * Rules:
 *   - PRO daily limit: 25 generations per calendar day (user's timezone)
 *   - Cooldown: after the 10th generation, require 3 minutes between accepted starts
 *   - generation_in_progress flag: prevents parallel/double-tap slots
 *
 * Atomic: reads + writes in one request to minimize race conditions.
 * Returns structured response for frontend rendering.
 *
 * Response shape (allowed):
 *   { allowed: true, daily_count, remaining_today, cooldown_active: false }
 *
 * Response shape (blocked):
 *   { allowed: false, reason, remaining_seconds?, remaining_today?, daily_count }
 *
 * Reasons:
 *   pro_daily_limit_reached     — 25/day cap hit
 *   pro_cooldown_active         — 3-min cooldown between gens 11-25
 *   generation_already_in_progress — another generation is running
 */
import { createClientFromRequest } from 'npm:@base44/sdk@0.8.23';

const PRO_DAILY_LIMIT = 25;
const COOLDOWN_AFTER_N = 10;       // cooldown kicks in after this many gens
const COOLDOWN_SECONDS = 180;      // 3 minutes

// Compute local day key (YYYY-MM-DD) in a given timezone
function getDayKey(date, timezone) {
  try {
    const formatter = new Intl.DateTimeFormat('en-CA', {
      timeZone: timezone,
      year: 'numeric',
      month: '2-digit',
      day: '2-digit',
    });
    return formatter.format(date); // en-CA gives YYYY-MM-DD
  } catch {
    // fallback to UTC
    return date.toISOString().slice(0, 10);
  }
}

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user) return Response.json({ error: 'Unauthorized' }, { status: 401 });

    const sr = base44.asServiceRole;
    const now = new Date();
    const userTz = user.timezone || 'UTC';
    const todayKey = getDayKey(now, userTz);

    // Fetch (or create) today's ProGenerationQuota record
    let quotas = await sr.entities.ProGenerationQuota.filter({
      user_id: user.id,
      day_key: todayKey,
    }).catch(() => []);

    let quota = quotas[0] || null;

    if (!quota) {
      // First generation attempt today — create fresh record
      try {
        quota = await sr.entities.ProGenerationQuota.create({
          user_id: user.id,
          day_key: todayKey,
          daily_count: 0,
          last_generation_started_at: null,
          generation_in_progress: false,
          timezone: userTz,
          updated_at: now.toISOString(),
        });
      } catch (createErr) {
        // Race: another request already created it — re-fetch
        quotas = await sr.entities.ProGenerationQuota.filter({
          user_id: user.id,
          day_key: todayKey,
        }).catch(() => []);
        quota = quotas[0];
        if (!quota) throw createErr;
      }
    }

    const dailyCount = quota.daily_count || 0;
    const remainingToday = Math.max(0, PRO_DAILY_LIMIT - dailyCount);

    // --- CHECK 1: Daily cap ---
    if (dailyCount >= PRO_DAILY_LIMIT) {
      return Response.json({
        allowed: false,
        reason: 'daily_limit_reached',
        daily_count: dailyCount,
        remaining_today: 0,
        message: "You've reached today's 25-generation Pro limit. Come back tomorrow!",
      }, { status: 429 });
    }

    // --- CHECK 2: Generation already in progress ---
    if (quota.generation_in_progress) {
      // Safety: if in_progress has been set for >5 minutes, auto-clear it (stuck flag recovery)
      const stuckThresholdMs = 5 * 60 * 1000;
      const updatedAt = quota.updated_at ? new Date(quota.updated_at).getTime() : 0;
      if (now.getTime() - updatedAt < stuckThresholdMs) {
        return Response.json({
          allowed: false,
          reason: 'generation_already_in_progress',
          daily_count: dailyCount,
          remaining_today: remainingToday,
          message: 'A generation is already in progress. Please wait for it to complete.',
        }, { status: 429 });
      }
      // Stale flag — fall through and clear it below
      console.warn(`[checkProGenerationLimit] Clearing stale generation_in_progress for user=${user.id}`);
    }

    // --- CHECK 3: Cooldown (applies only after COOLDOWN_AFTER_N gens) ---
    if (dailyCount >= COOLDOWN_AFTER_N && quota.last_generation_started_at) {
      const lastMs = new Date(quota.last_generation_started_at).getTime();
      const elapsedSeconds = (now.getTime() - lastMs) / 1000;
      const remainingSeconds = Math.ceil(COOLDOWN_SECONDS - elapsedSeconds);

      if (remainingSeconds > 0) {
        return Response.json({
          allowed: false,
          reason: 'pro_cooldown_active',
          daily_count: dailyCount,
          remaining_today: remainingToday,
          remaining_seconds: remainingSeconds,
          message: `You can generate again in ${formatCountdown(remainingSeconds)}.`,
        }, { status: 429 });
      }
    }

    // --- ALL CHECKS PASSED: Reserve the slot atomically ---
    const newCount = dailyCount + 1;
    await sr.entities.ProGenerationQuota.update(quota.id, {
      daily_count: newCount,
      last_generation_started_at: now.toISOString(),
      generation_in_progress: true,
      updated_at: now.toISOString(),
    });

    const remainingAfter = Math.max(0, PRO_DAILY_LIMIT - newCount);
    const cooldownWillApply = newCount >= COOLDOWN_AFTER_N;

    console.log(`[checkProGenerationLimit] ALLOWED user=${user.id} count=${newCount}/25 cooldownActive=${cooldownWillApply}`);

    return Response.json({
      allowed: true,
      quota_id: quota.id,
      daily_count: newCount,
      remaining_today: remainingAfter,
      cooldown_will_apply: cooldownWillApply,
      cooldown_after_n: COOLDOWN_AFTER_N,
      cooldown_seconds: COOLDOWN_SECONDS,
    });

  } catch (error) {
    console.error('[checkProGenerationLimit]', error.message);
    return Response.json({ error: error.message }, { status: 500 });
  }
});

function formatCountdown(seconds) {
  const m = Math.floor(seconds / 60);
  const s = seconds % 60;
  if (m > 0) return `${m}m ${s}s`;
  return `${s}s`;
}

