// ─── Moderation (mirrors frontend exactly) ────────────────────────────────────
function normalizeLeet(s) {
  return s
    .replace(/0/g, 'o').replace(/1/g, 'i').replace(/3/g, 'e')
    .replace(/4/g, 'a').replace(/5/g, 's').replace(/7/g, 't')
    .replace(/8/g, 'b').replace(/\$/g, 's').replace(/!/g, 'i')
    .replace(/@/g, 'a');
}

const INNOCENT_EXACT = new Set([
  'essex','sussex','middlesex','wessex','sextet','sextant',
  'bass','bass1','bass2','classic','class','grassfed',
]);

const BLOCKED_SUBSTRINGS = [
  'fuck','shit','cunt','cock','dick','pussy','porn',
  'slut','whore','horny','dildo','blowjob','handjob',
  'cumshot','creampie','masturbat','piss','wank',
  'nude','naked','nsfw',
  'nigger','nigga','faggot','chink','spic','kike',
  'xxx','boob','bitch','sex',
];

const BLOCKED_SEGMENTS_EXACT = new Set(['ass','tit','tits','cum','ho']);

function containsExplicitContent(rawInput) {
  const lower = rawInput.toLowerCase();
  const stripped = normalizeLeet(lower.replace(/[_.\-\s]/g, ''));

  if (INNOCENT_EXACT.has(stripped)) return false;

  for (const term of BLOCKED_SUBSTRINGS) {
    if (stripped.includes(term)) return true;
  }

  if (stripped.startsWith('ass')) return true;
  const segments = lower.split(/[_.\-\s]+/).filter(Boolean);
  for (const seg of segments) {
    const ns = normalizeLeet(seg);
    if (ns.startsWith('ass')) return true;
    if (BLOCKED_SEGMENTS_EXACT.has(ns)) return true;
  }

  return false;
}

// ─── Handler ──────────────────────────────────────────────────────────────────
Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user) return Response.json({ error: 'Unauthorized' }, { status: 401 });

    const body = await req.json();
    const raw = (body.username || '').trim().toLowerCase();

    // Length check: 2–14
    if (raw.length < 2 || raw.length > 14) {
      return Response.json({ available: false, error: 'Username must be between 2 and 14 characters' });
    }

    // Format check
    if (!/^[a-z0-9_.]+$/.test(raw)) {
      return Response.json({ available: false, error: 'Only letters, numbers, underscores, and dots allowed' });
    }

    // Moderation — runs BEFORE availability check
    if (containsExplicitContent(raw)) {
      return Response.json({ available: false, error: "This username isn't allowed. Please choose a different one." });
    }

    // Uniqueness — only after moderation passes
    const users = await base44.asServiceRole.entities.User.list();
    const taken = users.some(u =>
      u.id !== user.id &&
      (u.username || '').trim().toLowerCase() === raw
    );

    if (taken) {
      return Response.json({ available: false, error: 'Username is already taken' });
    }

    return Response.json({ available: true, username: raw });
  } catch (error) {
    return Response.json({ error: error.message }, { status: 500 });
  }
});

