/**
 * cleanupBlockedFollows — Admin utility.
 * Scans all BlockedUser records and removes any Follow rows that survived between
 * the two parties. This repairs corrupted data from before the block fix was applied.
 *
 * Also removes stale UserFollow and FollowRequest rows for the same pairs.
 *
 * Admin-only endpoint.
 */
Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user) return Response.json({ error: 'Unauthorized' }, { status: 401 });
    if (user.role !== 'admin') return Response.json({ error: 'Forbidden: Admin access required' }, { status: 403 });

    const sr = base44.asServiceRole;

    // Load all block records
    const allBlocks = await sr.entities.BlockedUser.list(null, 5000).catch(() => []);
    console.log(`[cleanupBlockedFollows] Scanning ${allBlocks.length} block records...`);

    let removedFollow = 0;
    let removedUserFollow = 0;
    let removedFollowRequest = 0;

    for (const block of allBlocks) {
      const { blocker_id, blocked_id } = block;
      if (!blocker_id || !blocked_id) continue;

      // Check Follow entity both directions
      const [f1, f2, f3, f4] = await Promise.all([
        sr.entities.Follow.filter({ follower_id: blocker_id, followed_id: blocked_id }).catch(() => []),
        sr.entities.Follow.filter({ follower_id: blocked_id, followed_id: blocker_id }).catch(() => []),
        sr.entities.Follow.filter({ followed_id: blocker_id, follower_id: blocked_id }).catch(() => []),
        sr.entities.Follow.filter({ followed_id: blocked_id, follower_id: blocker_id }).catch(() => []),
      ]);
      const allFollowRows = [...f1, ...f2, ...f3, ...f4];
      const uniqueFollowIds = [...new Set(allFollowRows.map(r => r.id))];
      if (uniqueFollowIds.length > 0) {
        console.log(`[cleanupBlockedFollows] Removing ${uniqueFollowIds.length} Follow rows for block ${blocker_id}<->${blocked_id}`);
        await Promise.all(uniqueFollowIds.map(id => sr.entities.Follow.delete(id).catch(() => {})));
        removedFollow += uniqueFollowIds.length;
      }

      // Check UserFollow entity
      const [uf1, uf2] = await Promise.all([
        sr.entities.UserFollow.filter({ follower_id: blocker_id, following_id: blocked_id }).catch(() => []),
        sr.entities.UserFollow.filter({ follower_id: blocked_id, following_id: blocker_id }).catch(() => []),
      ]);
      const allUF = [...uf1, ...uf2];
      const uniqueUFIds = [...new Set(allUF.map(r => r.id))];
      if (uniqueUFIds.length > 0) {
        await Promise.all(uniqueUFIds.map(id => sr.entities.UserFollow.delete(id).catch(() => {})));
        removedUserFollow += uniqueUFIds.length;
      }

      // Check FollowRequest entity
      const [fr1, fr2] = await Promise.all([
        sr.entities.FollowRequest.filter({ requester_id: blocker_id, target_id: blocked_id }).catch(() => []),
        sr.entities.FollowRequest.filter({ requester_id: blocked_id, target_id: blocker_id }).catch(() => []),
      ]);
      const allFR = [...fr1, ...fr2];
      const uniqueFRIds = [...new Set(allFR.map(r => r.id))];
      if (uniqueFRIds.length > 0) {
        await Promise.all(uniqueFRIds.map(id => sr.entities.FollowRequest.delete(id).catch(() => {})));
        removedFollowRequest += uniqueFRIds.length;
      }
    }

    const summary = {
      blocksScanned: allBlocks.length,
      removedFollow,
      removedUserFollow,
      removedFollowRequest,
      totalRemoved: removedFollow + removedUserFollow + removedFollowRequest,
    };

    console.log('[cleanupBlockedFollows] Done:', summary);
    return Response.json({ ok: true, ...summary });
  } catch (error) {
    console.error('[cleanupBlockedFollows] error:', error.message);
    return Response.json({ error: error.message }, { status: 500 });
  }
});

/**
 * cleanupRecipeLikes — Admin-only one-time cleanup.
 * Deletes all RecipeLike records that have no user_id (created by old broken system)
 * and resets likes_count on all affected recipes to 0 (since we have no way to know
 * who actually liked them). New likes will be tracked correctly going forward.
