import { createClientFromRequest } from 'npm:@base44/sdk@0.8.20';

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user || user.role !== 'admin') {
      return Response.json({ error: 'Admin only' }, { status: 403 });
    }

    const sr = base44.asServiceRole;

    // Fetch all RecipeLike records in batches
    let deleted = 0;
    const affectedRecipeIds = new Set();

    // Fetch up to 500 records at a time
    let page = 0;
    const PAGE = 200;
    while (true) {
      const batch = await sr.entities.RecipeLike.list(null, PAGE, page * PAGE);
      if (!batch || batch.length === 0) break;

      for (const like of batch) {
        if (!like.user_id) {
          // This record has no user_id — it's orphaned garbage from the old system
          affectedRecipeIds.add(like.recipe_id);
          await sr.entities.RecipeLike.delete(like.id).catch(() => {});
          deleted++;
        }
      }

      if (batch.length < PAGE) break;
      page++;
    }

    // Reset likes_count to 0 for all affected recipes (their real likes are unknown)
    let recipesReset = 0;
    for (const recipeId of affectedRecipeIds) {
      // Count remaining valid likes for this recipe
      const remaining = await sr.entities.RecipeLike.filter({ recipe_id: recipeId });
      const count = new Set(remaining.map(l => l.user_id).filter(Boolean)).size;
      await sr.entities.Recipe.update(recipeId, { likes_count: count }).catch(() => {});
      recipesReset++;
    }

    return Response.json({
      success: true,
      deleted_likes: deleted,
      recipes_reset: recipesReset,
      message: `Cleaned up ${deleted} orphaned RecipeLike records across ${recipesReset} recipes.`
    });

  } catch (error) {
    console.error('[cleanupRecipeLikes] error:', error.message);
    return Response.json({ error: error.message }, { status: 500 });
  }
});

/**
 * clearDeletedUserTombstone — Called when a previously-deleted user signs in again via OAuth.
 *
 * This function:
 * 1. Deletes ALL tombstone records for this user
 * 2. Resets the User profile to absolute clean defaults
 * 3. Cleans up any leftover data that survived the original deletion
 *    (safety net — completeDeleteAccount should have caught everything,
 *     but this ensures a truly fresh start)
 *
 * After this runs, the user goes through onboarding from scratch.
 * account_status is set to 'active' so the app treats them as a new user.
 */
import { createClientFromRequest } from 'npm:@base44/sdk@0.8.25';

async function sha256hex(str) {
  const buf = await crypto.subtle.digest('SHA-256', new TextEncoder().encode(str));
  return Array.from(new Uint8Array(buf)).map(b => b.toString(16).padStart(2, '0')).join('');
}

async function safeFilter(sr, entity, filter, limit = 200) {
  try { return await sr[entity].filter(filter, '-created_date', limit); }
  catch { return []; }
}

async function deleteAll(sr, entity, records) {
  let n = 0;
  for (const r of records) { try { await sr[entity].delete(r.id); n++; } catch {} }
  return n;
}

function dedup(arrays) {
  const merged = arrays.flat();
  const seen = new Set();
  return merged.filter(r => { if (seen.has(r.id)) return false; seen.add(r.id); return true; });
}

