 * Instead we strip it clean so re-login gets a blank slate.
 */
import { createClientFromRequest } from 'npm:@base44/sdk@0.8.25';

async function sha256hex(str) {
  const buf = await crypto.subtle.digest('SHA-256', new TextEncoder().encode(str));
  return Array.from(new Uint8Array(buf)).map(b => b.toString(16).padStart(2, '0')).join('');
}

async function safeFilter(sr, entityName, filter, limit = 500) {
  try {
    return await sr[entityName].filter(filter, '-created_date', limit);
  } catch (err) {
    console.warn(`[DELETE] Filter failed for ${entityName}:`, err.message);
    return [];
  }
}

async function deleteAll(sr, entityName, records) {
  if (!records?.length) return 0;
  let count = 0;
  for (const r of records) {
    try { await sr[entityName].delete(r.id); count++; } catch {}
  }
  return count;
}

function dedup(arrays) {
  const merged = arrays.flat();
  const seen = new Set();
  return merged.filter(r => { if (seen.has(r.id)) return false; seen.add(r.id); return true; });
}

