    const processedGroupIds = new Set();
    for (const gm of groupMembers) {
      if (processedGroupIds.has(gm.group_id)) continue;
      processedGroupIds.add(gm.group_id);
      try {
        const group = await sr.Group.get(gm.group_id).catch(() => null);
        if (!group) continue;

        // Get actual remaining members (after the user's memberships were deleted above)
        const remaining = await sr.GroupMember.filter({ group_id: gm.group_id, status: 'active' });
        const actualCount = remaining.length;

        if (actualCount === 0) {
          // Last member — delete group + its messages
          const msgs = await sr.GroupMessage.filter({ group_id: gm.group_id }).catch(() => []);
          for (const msg of msgs) { await sr.GroupMessage.delete(msg.id).catch(() => {}); }
          await sr.Group.delete(gm.group_id).catch(() => {});
          console.log(`[DELETE] Group ${gm.group_id} deleted (no members left)`);
          continue;
        }

        const wasOwner = group.owner_id === uid || gm.role === 'owner';
        if (wasOwner) {
          // Transfer ownership: admins first (by join date), then regular members
          const admins = remaining.filter(m => m.role === 'admin').sort((a, b) =>
            new Date(a.joined_at || a.created_date) - new Date(b.joined_at || b.created_date)
          );
          const regulars = remaining.filter(m => m.role === 'member').sort((a, b) =>
            new Date(a.joined_at || a.created_date) - new Date(b.joined_at || b.created_date)
          );
          const successor = admins[0] || regulars[0];
          if (successor) {
            await sr.GroupMember.update(successor.id, { role: 'owner' });
            await sr.Group.update(gm.group_id, { owner_id: successor.user_id, member_count: actualCount });
            console.log(`[DELETE] Ownership of group ${gm.group_id} transferred to ${successor.user_id}`);
            // Send ownership transfer notification
            try {
              await base44.asServiceRole.functions.invoke('sendBasicNotification', {
                type: 'ownership_transferred',
                recipientId: successor.user_id,
                actorName: 'System',
                data: { groupId: gm.group_id, groupName: group.name || 'a group' },
              });
            } catch (ne) { console.warn(`[DELETE] Ownership notif failed:`, ne.message); }
          } else {
            await sr.Group.update(gm.group_id, { member_count: actualCount });
          }
        } else {
          // Not owner — just update the count to actual
          await sr.Group.update(gm.group_id, { member_count: actualCount });
        }
      } catch (e) { console.warn(`[DELETE] group update failed:`, e.message); }
    }

    // ── PHASE 2c: Decrement recipe likes_count/review_count for affected recipes ──
    // Recipe likes (from Like entity with target_type=recipe)
    const recipeIdsLiked = new Set(
      likesUnified.filter(l => l.target_type === 'recipe' && l.target_id).map(l => l.target_id)
    );
    const recipeIdsFromOldLikes = new Set(recipeLikes.filter(l => l.recipe_id).map(l => l.recipe_id));
    const allLikedRecipeIds = new Set([...recipeIdsLiked, ...recipeIdsFromOldLikes]);

    for (const rid of allLikedRecipeIds) {
      try {
        const recs = await sr.Recipe.filter({ id: rid }, '-created_date', 1);
        if (recs?.[0]) {
          await sr.Recipe.update(recs[0].id, {
            likes_count: Math.max(0, (recs[0].likes_count || 1) - 1),
          });
        }
      } catch {}
    }

    // Recipe reviews — decrement review_count and recalculate avg_rating
    const reviewsByRecipe = {};
    for (const rv of recipeReviews) {
      if (rv.recipe_id) {
        if (!reviewsByRecipe[rv.recipe_id]) reviewsByRecipe[rv.recipe_id] = [];
        reviewsByRecipe[rv.recipe_id].push(rv);
      }
    }
    for (const [rid, userReviews] of Object.entries(reviewsByRecipe)) {
      try {
        const recs = await sr.Recipe.filter({ id: rid }, '-created_date', 1);
        if (recs?.[0]) {
          const oldCount = recs[0].review_count || 0;
          const oldAvg = recs[0].avg_rating || 0;
          const removedCount = userReviews.length;
          const newCount = Math.max(0, oldCount - removedCount);
          let newAvg = 0;
          if (newCount > 0 && oldCount > 0) {
            const totalRating = oldAvg * oldCount;
            const removedRating = userReviews.reduce((s, r) => s + (r.rating || 0), 0);
            newAvg = Math.max(0, (totalRating - removedRating) / newCount);
          }
          await sr.Recipe.update(recs[0].id, {
            review_count: newCount,
            avg_rating: Math.round(newAvg * 10) / 10,
          });
        }
      } catch {}
    }

    // Post likes — decrement likes_count on each post (from PostLike + unified Like entities)
    const postIdsFromPostLikes = postLikes.filter(l => l.post_id).map(l => l.post_id);
    const postIdsFromUnifiedLikes = likesUnified.filter(l => l.target_type === 'post' && l.target_id).map(l => l.target_id);
    const postIdsLiked = new Set([...postIdsFromPostLikes, ...postIdsFromUnifiedLikes]);
    for (const pid of postIdsLiked) {
      try {
        const ps = await sr.Post.filter({ id: pid }, '-created_date', 1);
        if (ps?.[0]) {
          await sr.Post.update(ps[0].id, {
            likes_count: Math.max(0, (ps[0].likes_count || 1) - 1),
          });
        }
      } catch {}
    }

    console.log(`[DELETE_ACCOUNT] Counters decremented`);

    // ── PHASE 3: Strip User profile clean ──
    // We do NOT delete the User entity (platform manages auth binding).
    // We reset ALL fields to defaults so re-login gets a totally fresh slate.
    try {
      await sr.User.update(uid, {
        display_name: null,
        username: null,
        bio: null,
        avatar_url: null,
        dietary_preferences: [],
        goals: [],
        skill_level: null,
        equipment: [],
        allergies: [],
        onboarding_complete: false,
        is_pro: false,
        is_public: true,
        is_private_account: false,
        has_shop: false,
        has_reviewed: false,
        account_status: 'deleted',
        paused_until: null,
        pause_started_at: null,
        banned_until: null,
        timeout_until: null,
        timeout_reason: null,
        timeout_acknowledged_for: null,
        suspended_at: null,
        suspended_reason: null,
        deletion_initiated_at: null,
        last_seen_at: null,
        last_seen_likes_at: null,
        last_seen_followers_at: null,
        last_seen_reviews_at: null,
        locale_preferences: null,
      });
      console.log(`[DELETE_ACCOUNT] User profile stripped clean`);
    } catch (err) {
      console.warn(`[DELETE_ACCOUNT] Profile reset error (non-fatal):`, err.message);
    }

    // ── PHASE 4: Delete any existing tombstones for this user, then write a fresh one ──
    // The unique constraint on user_id means we must clear old tombstones first.
    const emailHash = await sha256hex(email);
    try {
      const existingTombstones = dedup([
        await f('DeletedUser', { user_id: uid }, 10),
        await f('DeletedUser', { email_hash: emailHash }, 10),
      ]);
      await d('DeletedUser', existingTombstones);
    } catch {}

    try {
      await sr.DeletedUser.create({
        user_id: uid,
        email_hash: emailHash,
        deleted_at: new Date().toISOString(),
      });
      console.log(`[DELETE_ACCOUNT] Tombstone written`);
    } catch (err) {
      console.warn(`[DELETE_ACCOUNT] Tombstone write error (non-fatal):`, err.message);
    }

    console.log(`[DELETE_ACCOUNT] ✓ COMPLETE for user=${uid}`);

    return Response.json({
      ok: true,
      success: true,
      finalStage: 'deleted',
      errorCode: null,
      errorMessage: null,
      deleted_at: new Date().toISOString(),
    });

  } catch (error) {
    console.error('[DELETE_ACCOUNT_ERROR]', error.message);
    return Response.json({
      ok: false,
      success: false,
      finalStage: 'delete_failed',
      errorCode: 'DELETE_FAILED',
      errorMessage: 'Failed to delete account. Please try again or contact support.',
    }, { status: 500 });
  }
});

