import { createClientFromRequest } from 'npm:@base44/sdk@0.8.6';

/**
 * Mark recipe as cooked/completed by user.
 * Idempotent per day (same user same recipe same day = no duplicate).
 * Updates RecipeAggregate with unique count.
 */
Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user) return Response.json({ error: 'Unauthorized' }, { status: 401 });

    const { recipe_id, cook_time_minutes } = await req.json();
    if (!recipe_id) return Response.json({ error: 'recipe_id required' }, { status: 400 });

    // Verify recipe exists
    const recipe = await base44.asServiceRole.entities.Recipe.filter({
      id: recipe_id,
    }).catch(() => []);

    if (recipe.length === 0) {
      return Response.json({ error: 'Recipe not found' }, { status: 404 });
    }

    // Get today's date (ISO format)
    const today = new Date().toISOString().split('T')[0];

    // Check if already completed today (idempotent)
    const existing = await base44.asServiceRole.entities.RecipeCompletion.filter({
      recipe_id,
      completion_date: today,
    }).catch(() => []);

    let completion;
    if (existing.length > 0) {
      // Already completed today, just update cook time if provided
      if (cook_time_minutes) {
        completion = await base44.asServiceRole.entities.RecipeCompletion.update(
          existing[0].id,
          { cook_time_minutes }
        );
      } else {
        completion = existing[0];
      }
      console.log(`[COMPLETE_RECIPE] user=${user.id} recipe=${recipe_id} already_today`);
    } else {
      // New completion for today
      completion = await base44.asServiceRole.entities.RecipeCompletion.create({
        recipe_id,
        completion_date: today,
        cook_time_minutes: cook_time_minutes || null,
      });
      console.log(`[COMPLETE_RECIPE] user=${user.id} recipe=${recipe_id} new`);

      // Recompute aggregates for this recipe
      await updateRecipeAggregates(base44, recipe_id);
    }

    return Response.json({
      success: true,
      completion,
    });
  } catch (error) {
    console.error('completeRecipe error:', error);
    return Response.json({ error: error.message }, { status: 500 });
  }
});

/**
 * Compute aggregates for a recipe (unique cooked count, total cooked count).
 */
async function updateRecipeAggregates(base44, recipeId) {
  try {
    // Count unique users who completed this recipe
    const completions = await base44.asServiceRole.entities.RecipeCompletion.filter({
      recipe_id: recipeId,
    });

    const uniqueUsers = new Set(completions.map(c => c.created_by)).size;
    const totalCount = completions.length;

    // Update or create aggregate
    const existing = await base44.asServiceRole.entities.RecipeAggregate.filter({
      recipe_id: recipeId,
    });

    if (existing.length > 0) {
      await base44.asServiceRole.entities.RecipeAggregate.update(existing[0].id, {
        cooked_count_unique_users: uniqueUsers,
        cooked_count_total: totalCount,
        last_updated: new Date().toISOString(),
      });
    } else {
      await base44.asServiceRole.entities.RecipeAggregate.create({
        recipe_id: recipeId,
        cooked_count_unique_users: uniqueUsers,
        cooked_count_total: totalCount,
        last_updated: new Date().toISOString(),
      });
    }

    console.log(`[AGGREGATE_UPDATE] recipe=${recipeId} unique=${uniqueUsers} total=${totalCount}`);
  } catch (err) {
    console.error('[AGGREGATE_ERROR]', err);
  }
}

