const UNIT_TO_GRAMS = {g:1,gram:1,grams:1,kg:1000,kilogram:1000,kilograms:1000,oz:28.35,ounce:28.35,ounces:28.35,lb:453.6,lbs:453.6,pound:453.6,pounds:453.6,cup:240,cups:240,tbsp:15,tablespoon:15,tablespoons:15,tsp:5,teaspoon:5,teaspoons:5,ml:1,l:1000,liter:1000,liters:1000};
const OIL_KEYWORDS = ['oil','ghee'];
const VOLUME_UNITS = new Set(['ml','l','liter','liters','tsp','teaspoon','teaspoons','tbsp','tablespoon','tablespoons','cup','cups']);
const PIECE_WEIGHTS = {'chicken breast':175,'chicken thigh':120,'egg':55,'large egg':65,'potato':170,'sweet potato':200,'tomato':150,'onion':150,'garlic clove':4,clove:4,'avocado':200,'banana':120,'apple':182,'orange':180,'lemon':85,'lime':67,'carrot':80,'bell pepper':120,slice:30,rasher:35,strip:35,can:400,'pizza dough':250};

function lookupNutr(name) {
  if (!name) return null;
  const lower = name.toLowerCase().trim();
  if (FOODS[lower]) return FOODS[lower];
  const SPICE_KW = ['pepper','salt','paprika','cumin','cinnamon','oregano','basil','thyme','rosemary','turmeric','cayenne','chili powder','garlic powder','onion powder','herb','seasoning','spice'];
  for (const sp of SPICE_KW) {
    if (lower === sp || lower.startsWith(sp+' ') || lower.endsWith(' '+sp) || lower.includes(' '+sp+' ')) return {cal:0,p:0,c:0,f:0};
  }
  let best = null, bestLen = 0;
  for (const [key, val] of Object.entries(FOODS)) {
    if (key.length > 3 && lower.includes(key) && key.length > bestLen) { best = val; bestLen = key.length; }
  }
  return best;
}

function evalFrac(s) {
  if (String(s).includes('/')) { const [n,d] = String(s).split('/'); return parseFloat(n)/parseFloat(d); }
  return parseFloat(s);
}

function resolveGrams(ing) {
  let amtStr = String(ing.amount || '').trim();
  if (amtStr && ing.unit && /^[\d./]+$/.test(amtStr)) amtStr = `${amtStr} ${String(ing.unit).trim()}`;
  if (!amtStr) return ing.base_grams > 0 ? ing.base_grams : 100;
  const nameLower = (ing.name || '').toLowerCase().trim();
  const justG = amtStr.match(/^([\d.]+)\s*g$/i);
  if (justG) return parseFloat(justG[1]);
  const nu = amtStr.match(/^([\d.\/]+)\s*(ml|l|tsp|tbsp|tablespoon|teaspoon|cup|cups|oz|lb|lbs|kg|g)\b/i);
  if (nu) {
    const q = evalFrac(nu[1]); const u = nu[2].toLowerCase();
    const ug = UNIT_TO_GRAMS[u] ?? UNIT_TO_GRAMS[u.replace(/s$/,'')];
    if (ug) { const isOil = OIL_KEYWORDS.some(kw => nameLower.includes(kw)); return q * ug * (VOLUME_UNITS.has(u) && isOil ? 0.911 : 1); }
  }
  const nu2 = amtStr.match(/^([\d.\/]+)\s+([a-z]+[a-z\s]*)$/i);
  if (nu2) {
    const q = evalFrac(nu2[1]); const u = nu2[2].trim().toLowerCase();
    const ug = UNIT_TO_GRAMS[u] ?? UNIT_TO_GRAMS[u.replace(/s$/,'')];
    if (ug) { const isOil = OIL_KEYWORDS.some(kw => nameLower.includes(kw)); return q * ug * (VOLUME_UNITS.has(u) && isOil ? 0.911 : 1); }
    const uBase = u.replace(/s$/,'');
    if (uBase === 'piece' || uBase === 'pc') {
      if (PIECE_WEIGHTS[nameLower]) return q * PIECE_WEIGHTS[nameLower];
      for (const [k,w] of Object.entries(PIECE_WEIGHTS)) { if (nameLower.includes(k)) return q * w; }
      return q * 100;
    }
  }
  const jn = amtStr.match(/^([\d.]+)$/); if (jn) return parseFloat(jn[1]);
  const q = evalFrac(amtStr.split(/\s/)[0]) || 1;
  if (PIECE_WEIGHTS[nameLower]) return q * PIECE_WEIGHTS[nameLower];
  for (const [k,w] of Object.entries(PIECE_WEIGHTS)) { if (nameLower.includes(k)) return q * w; }
  return q * 100;
}

function computeNutrition(ingredientGroups, servings) {
  const s = Math.max(1, servings || 1);
  let cal = 0, prot = 0, carbs = 0, fat = 0;
  for (const group of (ingredientGroups || [])) {
    for (const item of (group.items || [])) {
      if (!item.name || item.optional || item.missing) continue;
      const g = resolveGrams(item);
      const n = lookupNutr(item.name) || {cal:80,p:3,c:12,f:2};
      cal  += g * (n.cal / 100);
      prot += g * (n.p   / 100);
      carbs+= g * (n.c   / 100);
      fat  += g * (n.f   / 100);
    }
  }
  if (cal <= 0) return null;
  return {
    total:       { calories: Math.round(cal),     protein: Math.round(prot),     carbs: Math.round(carbs),     fat: Math.round(fat) },
    per_serving: { calories: Math.round(cal/s),   protein: Math.round(prot/s),   carbs: Math.round(carbs/s),   fat: Math.round(fat/s) },
  };
}

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user) return Response.json({ error: 'Unauthorized' }, { status: 401 });

    const { recipe_id } = await req.json();
    if (!recipe_id) return Response.json({ error: 'recipe_id required' }, { status: 400 });

    const recipes = await base44.asServiceRole.entities.Recipe.filter({ id: recipe_id });
    if (!recipes.length) return Response.json({ error: 'Recipe not found' }, { status: 404 });
    const recipe = recipes[0];

    // Only owner or admin can trigger this
    if (recipe.created_by !== user.email && user.role !== 'admin') {
      return Response.json({ error: 'Forbidden' }, { status: 403 });
    }

    const computed = computeNutrition(recipe.ingredients, recipe.servings || 1);
    if (!computed) {
      return Response.json({ success: false, reason: 'No computable ingredients' });
    }

    await base44.asServiceRole.entities.Recipe.update(recipe_id, {
      nutrition_total_for_recipe: computed.total,
      nutrition_per_serving: computed.per_serving,
    });

    console.log(`[computeAndStoreNutrition] recipe=${recipe_id} cal=${computed.total.calories} prot=${computed.total.protein}`);
    return Response.json({ success: true, total: computed.total, per_serving: computed.per_serving });
  } catch (error) {
    console.error('[computeAndStoreNutrition]', error.message);
    return Response.json({ error: error.message }, { status: 500 });
  }
});

/**
 * computeNotificationPerformance — Aggregates notification performance by strategy.
 * Runs periodically (scheduled) or on-demand from admin.
 * Computes open rate, click rate, effectiveness score per strategy.
 * Feeds the strategy optimizer to boost/deprioritize strategies.
 */
import { createClientFromRequest } from 'npm:@base44/sdk@0.8.25';

const STRATEGIES = [
  'daily_reminder', 'streak_reminder', 'streak_continued', 'streak_lost',
  'likes', 'follow', 'comment', 'cook_mode_return', 'missing_ingredients',
  'limit_reached', 'reset', 'motivation_chef', 'motivation_save_money',
  'motivation_start_cooking', 'breakup_style_comeback', 'low_cost_meal_upgrade',
  'takeout_temptation_blocker', 'zero_waste_rescue', 'lazy_energy_saver',
];

const MIN_SAMPLE_SIZE = 20;

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user || user.role !== 'admin') {
      return Response.json({ error: 'Admin only' }, { status: 403 });
    }

    const sr = base44.asServiceRole;
    const now = new Date();
    const periodStart = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000); // 7-day window
    const periodKey = periodStart.toISOString().split('T')[0];
    const results = [];

    for (const strategy of STRATEGIES) {
      // Fetch history for this strategy in the 7-day window
      const history = await sr.entities.NotificationHistory.filter(
        { notification_type: strategy },
        '-sent_at', 500
      ).catch(() => []);

      const inWindow = history.filter(h => new Date(h.sent_at) >= periodStart);
      const sentCount = inWindow.length;
      const openedCount = inWindow.filter(h => h.was_opened).length;

      // Click = opened + action_taken is not null
      const clickedCount = inWindow.filter(h => h.was_opened && h.action_taken).length;

      // Converted = meaningful action (viewed_recipe, started_cook, saved_recipe)
      const convertedCount = inWindow.filter(h => 
        h.action_taken && ['viewed_recipe', 'started_cook', 'saved_recipe', 'logged_meal'].includes(h.action_taken)
      ).length;

      // Dismissed = delivered but never opened
      const dismissedCount = inWindow.filter(h => 
        h.delivery_status === 'delivered' && !h.was_opened
      ).length;

      const openRate = sentCount > 0 ? Math.round((openedCount / sentCount) * 100) : 0;
      const clickRate = sentCount > 0 ? Math.round((clickedCount / sentCount) * 100) : 0;

      // Effectiveness score: weighted combination
      // Open rate (40%), click rate (35%), conversion (25%)
      const convRate = sentCount > 0 ? (convertedCount / sentCount) * 100 : 0;
      const rawScore = (openRate * 0.4) + (clickRate * 0.35) + (convRate * 0.25);
      const effectivenessScore = Math.min(100, Math.max(0, Math.round(rawScore)));
      const sufficient = sentCount >= MIN_SAMPLE_SIZE;

      // Upsert performance record
      const existing = await sr.entities.NotificationPerformance.filter(
        { strategy, period_start: periodKey }, null, 1
      ).catch(() => []);

      const perf = {
        strategy,
        period_start: periodKey,
        sent_count: sentCount,
        opened_count: openedCount,
        clicked_count: clickedCount,
        converted_count: convertedCount,
        dismissed_count: dismissedCount,
        open_rate: openRate,
        click_rate: clickRate,
        effectiveness_score: effectivenessScore,
        sample_size_sufficient: sufficient,
      };

      if (existing[0]) {
        await sr.entities.NotificationPerformance.update(existing[0].id, perf);
      } else {
        await sr.entities.NotificationPerformance.create(perf);
      }

      results.push(perf);
    }

    console.log(`[NotifPerf] Computed performance for ${results.length} strategies`);
    return Response.json({ success: true, strategies: results });
  } catch (err) {
    console.error('[computeNotificationPerformance]', err.message);
    return Response.json({ error: err.message }, { status: 500 });
  }
});

