function findPrice(ingredientName) {
  if (!ingredientName) return null;
  const lower = ingredientName.toLowerCase().trim();
  if (INGREDIENT_PRICES[lower]) return INGREDIENT_PRICES[lower];

  let bestPrice = null;
  let bestLen = 0;
  for (const [key, price] of Object.entries(INGREDIENT_PRICES)) {
    if (key.length > 3 && lower.includes(key) && key.length > bestLen) {
      bestPrice = price;
      bestLen = key.length;
    }
  }
  return bestPrice;
}

Deno.serve(async (req) => {
  try {
    const { ingredientGroups, servings } = await req.json();

    const defSrv = Math.max(1, servings || 1);
    let totalCost = 0;
    let hasUnknown = false;

    for (const group of (ingredientGroups || [])) {
      for (const item of (group.items || [])) {
        if (item.optional) continue;

        const baseGrams = item.base_grams || 100;
        const pricePerHundred = findPrice(item.name);
        const costPerGram = pricePerHundred ? pricePerHundred / 100 : null;
        const ingredientCost = costPerGram ? baseGrams * costPerGram : null;

        if (ingredientCost) {
          totalCost += ingredientCost;
        } else {
          hasUnknown = true;
        }
      }
    }

    const perServingCost = totalCost > 0 ? totalCost / defSrv : 0;

    return Response.json({
      totalCost: totalCost > 0 ? totalCost : 0,
      perServingCost: perServingCost > 0 ? perServingCost : 0,
      hasUnknown,
    });
  } catch (error) {
    return Response.json({ error: error.message }, { status: 500 });
  }
});

