const MEASUREMENT_TYPE_DETECTION = {
  // Liquids
  liquid: ['water', 'milk', 'oil', 'vinegar', 'sauce', 'juice', 'wine', 'cream', 'broth', 'stock'],
  // Pieces
  piece_based: ['egg', 'clove', 'onion', 'lemon', 'lime', 'lime', 'garlic', 'potato', 'apple', 'can', 'package'],
  // Solids (default)
