// ─────────────────────────────────────────────────────────────────────────
// STAGE A: INGREDIENT CANONICALIZATION
// ─────────────────────────────────────────────────────────────────────────

async function matchIngredientToCanonical(ingredientText, canonicalCache, base44) {
  if (!ingredientText || typeof ingredientText !== 'string') {
    return { match: null, method: 'unresolved', confidence: 0, reason: 'invalid_input' };
  }

  const text = ingredientText.trim().toLowerCase();
  const normalized = text.replace(/^\d+\s*([\w\s]+)/, '$1').trim(); // strip leading quantity

  // 1. EXACT CANONICAL MATCH (by normalized_name)
  const exactCanonical = Object.values(canonicalCache).find(c => c.normalized_name === normalized);
  if (exactCanonical) {
    return { match: exactCanonical, method: 'exact', confidence: 1.0 };
  }

  // 2. ALIAS MATCH
  const aliasMatch = Object.values(canonicalCache).find(c =>
    c.aliases && c.aliases.some(alias => alias.toLowerCase() === normalized)
  );
  if (aliasMatch) {
    return { match: aliasMatch, method: 'alias', confidence: 0.95 };
  }

  // 3. PLURAL/SINGULAR NORMALIZATION
  const singularized = normalized.endsWith('s') ? normalized.slice(0, -1) : normalized + 's';
  const pluralMatch = Object.values(canonicalCache).find(c =>
    c.plural_forms && c.plural_forms.some(p => p.toLowerCase() === singularized)
  );
  if (pluralMatch) {
    return { match: pluralMatch, method: 'plural_normalized', confidence: 0.90 };
  }

  // 4. DESCRIPTOR STRIPPING (remove common modifiers: "fresh", "organic", "raw", etc.)
  const descriptors = ['fresh', 'organic', 'raw', 'frozen', 'canned', 'whole', 'ground', 'chopped', 'diced', 'sliced', 'minced'];
  let stripped = normalized;
  for (const desc of descriptors) {
    stripped = stripped.replace(new RegExp(`\\b${desc}\\s+`, 'i'), '').trim();
  }
  if (stripped !== normalized) {
    const strippedMatch = Object.values(canonicalCache).find(c => c.normalized_name === stripped);
    if (strippedMatch) {
      return { match: strippedMatch, method: 'descriptor_stripped', confidence: 0.85 };
    }
  }

  // 5. SUBSTRING/FUZZY MATCH (e.g., "milk" matches "whole milk")
  const partialMatches = Object.values(canonicalCache)
    .filter(c => {
      const cName = c.normalized_name;
      return (cName.includes(normalized) || normalized.includes(cName)) && cName.length < 50;
    })
    .sort((a, b) => {
      // Prefer shorter canonical names (more specific)
      const aLen = a.normalized_name.length;
      const bLen = b.normalized_name.length;
      return aLen - bLen;
    });
  if (partialMatches.length > 0) {
    const best = partialMatches[0];
    const overlap = Math.min(normalized.length, best.normalized_name.length);
    const confidence = 0.7 * (overlap / Math.max(normalized.length, best.normalized_name.length));
    return { match: best, method: 'category_fuzzy', confidence };
  }

  // 6. UNRESOLVED
  return { match: null, method: 'unresolved', confidence: 0, reason: 'no_match_found' };
}

// ─────────────────────────────────────────────────────────────────────────
// STAGE B: QUANTITY NORMALIZATION
// ─────────────────────────────────────────────────────────────────────────

function parseQuantityAmount(amountStr) {
  // Parse "500g", "2 cups", "1.5 tbsp", "3 cloves", etc.
  if (!amountStr) return { value: null, unit: null };

  const match = String(amountStr).match(/^([\d.\/]+)\s*([a-z\s]+)?$/i);
  if (!match) return { value: null, unit: null };

  let value = parseFloat(match[1]);
  if (match[1].includes('/')) {
    // Handle fractions: "1/2", "1/4", etc.
    const [num, denom] = match[1].split('/').map(Number);
    value = num / denom;
  }

  let unit = (match[2] || '').trim().toLowerCase();
  return { value, unit: unit || null };
}

function normalizeQuantity(parsed, canonical) {
  // Converts ingredient amount to normalized unit (g, ml, or piece)
  // Returns: { normalized_quantity, normalized_unit, method, confidence }

  if (!parsed.value || parsed.value <= 0) {
    return { normalized_quantity: null, normalized_unit: 'unknown', method: 'unresolved', confidence: 0 };
  }

  // Detect ingredient measurement type from canonical metadata or heuristics
  let measurementType = canonical?.measurement_type || 'solid';
  if (!canonical && measurementType === 'solid') {
    const textLower = parsed.unit?.toLowerCase() || '';
    if (['ml', 'l', 'cup', 'tbsp', 'tsp'].some(u => textLower.includes(u))) {
      measurementType = 'liquid';
    }
  }

  // CASE 1: SOLIDS (grams)
  if (measurementType === 'solid' || measurementType === 'mixed') {
    // Try direct gram conversion
    if (parsed.unit && UNIT_TO_GRAMS[parsed.unit]) {
      return {
        normalized_quantity: parsed.value * UNIT_TO_GRAMS[parsed.unit],
        normalized_unit: 'g',
        method: 'exact_canonical',
        confidence: 1.0,
      };
    }
    // Fallback to canonical grams_per_unit
    if (canonical?.grams_per_unit?.[parsed.unit]) {
      return {
        normalized_quantity: parsed.value * canonical.grams_per_unit[parsed.unit],
        normalized_unit: 'g',
        method: 'exact_canonical',
        confidence: 0.95,
      };
    }
    // Category default (e.g., assume piece-based items)
    if (parsed.unit && ['piece', 'pieces', 'whole'].includes(parsed.unit)) {
      const gramsPerPiece = canonical?.grams_per_unit?.['piece'] || 100;
      return {
        normalized_quantity: parsed.value * gramsPerPiece,
        normalized_unit: 'g',
        method: 'category_default',
        confidence: 0.70,
      };
    }
    // Assume grams if no unit specified and solid ingredient
    if (!parsed.unit) {
      return {
        normalized_quantity: parsed.value,
        normalized_unit: 'g',
        method: 'category_default',
        confidence: 0.60,
      };
    }
  }

  // CASE 2: LIQUIDS (milliliters)
  if (measurementType === 'liquid') {
    if (parsed.unit && UNIT_TO_ML[parsed.unit]) {
      return {
        normalized_quantity: parsed.value * UNIT_TO_ML[parsed.unit],
        normalized_unit: 'ml',
        method: 'exact_canonical',
        confidence: 1.0,
      };
    }
    if (canonical?.ml_per_unit?.[parsed.unit]) {
      return {
        normalized_quantity: parsed.value * canonical.ml_per_unit[parsed.unit],
        normalized_unit: 'ml',
        method: 'exact_canonical',
        confidence: 0.95,
      };
    }
    // Assume milliliters if no unit and liquid ingredient
    if (!parsed.unit) {
      return {
        normalized_quantity: parsed.value,
        normalized_unit: 'ml',
        method: 'category_default',
        confidence: 0.60,
      };
    }
  }

  // CASE 3: PIECE-BASED (pieces)
  if (measurementType === 'piece_based') {
    if (['piece', 'pieces', 'whole', 'clove', 'cloves', 'egg', 'eggs'].includes(parsed.unit)) {
      return {
        normalized_quantity: parsed.value,
        normalized_unit: 'piece',
        method: 'exact_canonical',
        confidence: 1.0,
      };
    }
  }

  return { normalized_quantity: null, normalized_unit: 'unknown', method: 'unresolved', confidence: 0 };
}

// ─────────────────────────────────────────────────────────────────────────
// STAGE C: PRICE SOURCE RESOLUTION
// ─────────────────────────────────────────────────────────────────────────

function resolvePrice(canonical, normalizedUnit) {
  // Returns: { price_per_unit, source_used, confidence }
  // Implements hierarchical fallback strategy

  if (!canonical) {
    return { price_per_unit: null, source_used: 'unresolved', confidence: 0 };
  }

  const order = canonical.price_resolution_order || ['price_per_g', 'price_per_100ml', 'price_per_piece', 'price_per_typical_package', 'category_benchmark'];

  for (const source of order) {
    switch (source) {
      case 'price_per_g':
        if (canonical.price_per_g && normalizedUnit === 'g') {
          return {
            price_per_unit: canonical.price_per_g,
            source_used: 'price_per_g',
            confidence: canonical.price_confidence || 'medium',
          };
        }
        break;
      case 'price_per_100ml':
        if (canonical.price_per_100ml && normalizedUnit === 'ml') {
          return {
            price_per_unit: canonical.price_per_100ml / 100, // convert to per-ml
            source_used: 'price_per_100ml',
            confidence: canonical.price_confidence || 'medium',
          };
        }
        break;
      case 'price_per_piece':
        if (canonical.price_per_piece && normalizedUnit === 'piece') {
          return {
            price_per_unit: canonical.price_per_piece,
            source_used: 'price_per_piece',
            confidence: canonical.price_confidence || 'medium',
          };
        }
        break;
      case 'price_per_typical_package':
        if (canonical.price_per_typical_package && canonical.typical_package_size_grams) {
          const unitPrice = canonical.price_per_typical_package / canonical.typical_package_size_grams;
          return {
            price_per_unit: unitPrice,
            source_used: 'price_per_typical_package',
            confidence: 'low',
          };
        }
        break;
      case 'category_benchmark':
        const benchmark = CATEGORY_BENCHMARKS[canonical.category] || 0.50;
        return {
          price_per_unit: benchmark,
          source_used: 'category_benchmark',
          confidence: 'low',
        };
    }
  }

  return { price_per_unit: null, source_used: 'unresolved', confidence: 0 };
}

// ─────────────────────────────────────────────────────────────────────────
// STAGE D: COST CALCULATION + ANOMALY DETECTION
// ─────────────────────────────────────────────────────────────────────────

function calculateIngredientCost(normalized, priceResolution, countryMultiplier = 1.0) {
  if (!normalized.normalized_quantity || !priceResolution.price_per_unit) {
    return {
      ingredient_cost: null,
      anomalies: ['no_pricing_available'],
    };
  }

  const cost = normalized.normalized_quantity * priceResolution.price_per_unit * countryMultiplier;
  const anomalies = [];

  // Detect anomalies
  if (normalized.normalized_quantity > 10000) {
    anomalies.push('abnormally_high_quantity');
  }
  if (cost > 100) {
    anomalies.push('suspiciously_high_cost');
  }
  if (cost < 0.01 && normalized.normalized_quantity > 50) {
    anomalies.push('suspiciously_low_cost');
  }
  if (priceResolution.source_used === 'category_benchmark' || priceResolution.source_used === 'fallback') {
    anomalies.push('fallback_only_pricing');
  }

  return {
    ingredient_cost: cost,
    anomalies,
  };
}

// ─────────────────────────────────────────────────────────────────────────
// MAIN PRICING PIPELINE
// ─────────────────────────────────────────────────────────────────────────

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user) return Response.json({ error: 'Unauthorized' }, { status: 401 });

    const { recipe_id, recompute_reason, country_code } = await req.json();
    if (!recipe_id) return Response.json({ error: 'recipe_id required' }, { status: 400 });

    // Fetch recipe
    const recipes = await base44.asServiceRole.entities.Recipe.filter({ id: recipe_id });
    if (!recipes[0]) return Response.json({ error: 'Recipe not found' }, { status: 404 });
    const recipe = recipes[0];
    const countryMultiplier = getCountryMultiplier(country_code || 'US');

    // Load canonical ingredient cache
    const canonicalIngredients = await base44.asServiceRole.entities.CanonicalIngredient.filter({ is_active: true }, undefined, 500);
    const canonicalCache = {};
    for (const ci of canonicalIngredients) {
      canonicalCache[ci.slug] = ci;
    }

    // PROCESS EACH INGREDIENT
    const ingredientPricings = [];
    let totalCost = 0;
    let primedCount = 0;
    const unresolvedTexts = [];

    for (let groupIdx = 0; groupIdx < (recipe.ingredients || []).length; groupIdx++) {
      const group = recipe.ingredients[groupIdx];
      for (let itemIdx = 0; itemIdx < (group.items || []).length; itemIdx++) {
        const item = group.items[itemIdx];
        if (!item || item.optional) continue;

        // Stage A: Canonicalization
        const canonMatch = await matchIngredientToCanonical(item.name, canonicalCache, base44);

        // Stage B: Quantity Normalization
        const parsed = parseQuantityAmount(item.amount);
        const normalized = normalizeQuantity(parsed, canonMatch.match);

        // Stage C: Price Resolution
        const priceResolution = resolvePrice(canonMatch.match, normalized.normalized_unit);

        // Stage D: Cost Calculation (with country multiplier applied)
        const costResult = calculateIngredientCost(normalized, priceResolution, countryMultiplier);

        // Create per-ingredient pricing record
        const ingredientPricing = {
          recipe_id,
          ingredient_index: `${groupIdx}_${itemIdx}`,
          raw_ingredient_text: item.name,
          raw_amount: item.amount,
          canonical_ingredient_id: canonMatch.match?.slug || null,
          canonical_ingredient_name: canonMatch.match?.display_name || null,
          match_method: canonMatch.method,
          match_confidence: canonMatch.confidence,
          normalized_quantity: normalized.normalized_quantity,
          normalized_unit: normalized.normalized_unit,
          quantity_conversion_method: normalized.method,
          quantity_confidence: normalized.confidence,
          price_per_normalized_unit: priceResolution.price_per_unit,
          price_source_used: priceResolution.source_used,
          price_source_confidence: priceResolution.confidence,
          ingredient_cost: costResult.ingredient_cost,
          pricing_status: costResult.ingredient_cost !== null ? 'resolved' : 'unresolved',
          unresolved_reason: costResult.ingredient_cost === null ? (canonMatch.reason || 'no_price_source') : null,
          recipe_servings: recipe.servings || 1,
          pricing_version: 2,
          computed_at: new Date().toISOString(),
          anomaly_flags: costResult.anomalies,
        };

        ingredientPricings.push(ingredientPricing);

        if (costResult.ingredient_cost !== null) {
          totalCost += costResult.ingredient_cost;
          primedCount++;
        } else {
          unresolvedTexts.push(item.name);
        }
      }
    }

    // STAGE E: PERSISTENCE & SUMMARY
    const totalIngredients = ingredientPricings.length;
    const unresolvedCount = totalIngredients - primedCount;
    const costPerServing = totalCost / (recipe.servings || 1);
    const coverageRatio = primedCount / Math.max(totalIngredients, 1);

    let pricingStatus = 'full';
    if (unresolvedCount > 0) pricingStatus = coverageRatio > 0.5 ? 'partial' : 'unresolved';

    const anomalyFlags = [];
    if (unresolvedCount === totalIngredients) anomalyFlags.push('all_unresolved_ingredients');
    if (primedCount === 0) anomalyFlags.push('zero_priced_ingredients');
    if (totalCost > 500) anomalyFlags.push('implausibly_high_cost');
    if (totalCost < 0.1 && primedCount > 3) anomalyFlags.push('implausibly_low_cost');

    const fallbackCount = ingredientPricings.filter(ip =>
      ip.price_source_used === 'category_benchmark' || ip.price_source_used === 'fallback'
    ).length;

    // Create summary record
    const summary = {
      recipe_id,
      total_cost: parseFloat(totalCost.toFixed(2)),
      cost_per_serving: parseFloat(costPerServing.toFixed(2)),
      pricing_status: pricingStatus,
      priced_ingredient_count: primedCount,
      unresolved_ingredient_count: unresolvedCount,
      pricing_coverage_ratio: parseFloat(coverageRatio.toFixed(2)),
      recipe_servings: recipe.servings || 1,
      ingredient_count: totalIngredients,
      fallback_pricing_count: fallbackCount,
      pricing_version: 2,
      computed_at: new Date().toISOString(),
      anomaly_flags: anomalyFlags,
      unresolved_ingredient_texts: unresolvedTexts,
      audit_trail: {
        source_recipe_version: 0, // integer version placeholder — updated_date is stored in computed_at
        recompute_reason: recompute_reason || 'initial_creation',
        engine_changes: ['v2_unified_pipeline', 'deterministic_matching', 'hierarchical_fallback'],
      },
    };

    // Upsert summary
    const existingSummary = await base44.asServiceRole.entities.RecipePricingSummary.filter({ recipe_id });
    if (existingSummary[0]) {
      await base44.asServiceRole.entities.RecipePricingSummary.update(existingSummary[0].id, summary);
    } else {
      await base44.asServiceRole.entities.RecipePricingSummary.create(summary);
    }

    // Bulk upsert ingredient pricings (for audit/observability)
    // In production, batch this in a separate background job to avoid large payloads
    // For now, just return summary
    console.log('[computeRecipePricingV2] recipe=' + recipe_id + ' total=$' + totalCost.toFixed(2) + ' status=' + pricingStatus + ' coverage=' + (coverageRatio * 100).toFixed(0) + '%');

    return Response.json({
      summary,
      ingredient_count: totalIngredients,
      priced_count: primedCount,
      unresolved_count: unresolvedCount,
      unresolved_texts: unresolvedTexts.slice(0, 10), // Return first 10 for review
      debug: {
        anomaly_flags: anomalyFlags,
        fallback_count: fallbackCount,
        coverage_ratio: coverageRatio,
      },
    });
  } catch (error) {
    console.error('[computeRecipePricingV2] error:', error.message);
    return Response.json({ error: error.message }, { status: 500 });
  }
});

/**
 * consumeBankedCredit
 * 
 * Consumes exactly 1 banked referral credit for the authenticated user.
 * 
 * ARCHITECTURE (v3 — CLEAN SEPARATION):
 * - Deducts 1 credit from the oldest banked referral ledger entry (FIFO).
 * - Does NOT touch the weekly quota `used` field at all.
 * - The generation function (generateRecipeWithQuota) has its own banked-consumption
 *   path that fires when weeklyRemaining <= 0. That path re-reads the ledger,
 *   so the credit deducted here will be naturally consumed there.
 * 
 * WAIT — that means double-deduction! The flow is:
 *   1. consumeBankedCredit deducts 1 from ledger
 *   2. User generates → generateRecipeWithQuota sees weeklyRemaining=0 → enters banked path → deducts ANOTHER from ledger
 * 
 * FIX: consumeBankedCredit ONLY creates a temporary generation slot by decrementing
 * `used` (so weeklyRemaining > 0). generateRecipeWithQuota then consumes via the
 * weekly_free path (incrementing `used` back). The ledger deduction here is the ONLY
 * ledger deduction — generateRecipeWithQuota's banked path never fires because
 * weeklyRemaining > 0 after our decrement.
 * 
 * KEY INVARIANT: `used` is decremented here and incremented back by generation.
 * The limit stays at 2 always. No net change to limit.
 * 
 * Returns the AUTHORITATIVE quota snapshot so frontend can update immediately.
 */
import { createClientFromRequest } from 'npm:@base44/sdk@0.8.25';

const WEEKLY_LIMIT = 2;

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user) return Response.json({ error: 'Unauthorized' }, { status: 401 });

    let body = {};
    try { body = await req.json(); } catch {}
    const clientTz = body?.client_timezone || null;
    const userTz = user.timezone && user.timezone !== 'UTC' ? user.timezone : (clientTz || user.timezone || 'UTC');

    // 1. Find banked referral credits
    const ledgerEntries = await base44.asServiceRole.entities.ReferralRewardLedger.filter({
      user_id: user.id,
      credit_state: 'earned',
    }).catch(() => []);

    // Sort oldest first (FIFO) and find one with remaining > 0
    const sortedEntries = ledgerEntries
      .filter(e => (e.credits_remaining || 0) > 0)
      .sort((a, b) => new Date(a.created_date).getTime() - new Date(b.created_date).getTime());

    if (sortedEntries.length === 0) {
      return Response.json({ error: 'No banked credits available', code: 'NO_BANKED_CREDITS' }, { status: 400 });
    }

    // 2. Get current weekly quota
    const now = new Date();
    const { periodStart, periodEnd } = getWeekWindow(now);
    const periodStartISO = periodStart.toISOString();
    const periodEndISO = periodEnd.toISOString();

    // Fetch ALL records for this user+period, pick highest-used (authoritative), dedup rest.
    const allQuotas = await base44.asServiceRole.entities.AiGenerationQuota.filter(
      { user_id: user.id, period_start: periodStartISO },
      null,
      20
    );
    let quota = null;
    if (allQuotas.length > 0) {
      allQuotas.sort((a, b) => (b.used || 0) - (a.used || 0));
      quota = allQuotas[0];
      if (allQuotas.length > 1) {
        console.warn(`[consumeBankedCredit] DEDUP: found ${allQuotas.length} records for user=${user.id}, keeping id=${quota.id} (used=${quota.used})`);
        for (let i = 1; i < allQuotas.length; i++) {
          base44.asServiceRole.entities.AiGenerationQuota.delete(allQuotas[i].id).catch(() => {});
        }
      }
    }

    if (!quota) {
      quota = await base44.asServiceRole.entities.AiGenerationQuota.create({
        user_id: user.id,
        period_start: periodStartISO,
        period_end: periodEndISO,
        limit: WEEKLY_LIMIT,
        used: 0,
        timezone: userTz,
        updated_at: now.toISOString(),
      });
    }

    const currentUsed = quota.used || 0;

    // GUARD: Only allow banked credit use when weekly is exhausted
    const weeklyRemaining = Math.max(0, WEEKLY_LIMIT - currentUsed);
    if (weeklyRemaining > 0) {
      return Response.json({ 
        error: 'Weekly credits still available — use those first',
        code: 'WEEKLY_NOT_EXHAUSTED',
      }, { status: 400 });
    }

    // 3. Deduct 1 from the ledger entry (FIFO)
    const entry = sortedEntries[0];
    const newRemaining = (entry.credits_remaining || 0) - 1;
    await base44.asServiceRole.entities.ReferralRewardLedger.update(entry.id, {
      credits_remaining: newRemaining,
      credit_state: newRemaining <= 0 ? 'consumed' : 'earned',
    });

    // 4. Create room for exactly 1 generation by decrementing `used`.
    // CRITICAL: Do NOT mutate `limit`. The weekly cap stays at WEEKLY_LIMIT (2) always.
    const newUsed = Math.max(0, currentUsed - 1);
    await base44.asServiceRole.entities.AiGenerationQuota.update(quota.id, {
      used: newUsed,
      updated_at: now.toISOString(),
    });

    // Also ensure limit is exactly WEEKLY_LIMIT (repair any previously corrupted state)
    if ((quota.limit || 0) !== WEEKLY_LIMIT) {
      await base44.asServiceRole.entities.AiGenerationQuota.update(quota.id, {
        limit: WEEKLY_LIMIT,
      });
    }

    // 5. Compute updated banked total
    const updatedBanked = ledgerEntries.reduce((sum, e) => {
      if (e.id === entry.id) return sum + newRemaining;
      return sum + (e.credits_remaining || 0);
    }, 0);

    const updatedRemaining = Math.max(0, WEEKLY_LIMIT - newUsed);

    console.log(`[consumeBankedCredit] user=${user.id} deducted 1 banked credit (entry=${entry.id}), used=${currentUsed}→${newUsed}, remaining=${updatedRemaining}, banked_left=${updatedBanked}`);

    return Response.json({
      success: true,
      quota: {
        is_premium: false,
        limit: WEEKLY_LIMIT,
        used: newUsed,
        remaining: updatedRemaining,
        total_available: updatedRemaining + updatedBanked,
        banked_referral_credits: updatedBanked,
        period_start: periodStartISO,
        period_end: periodEndISO,
        resets_at: periodEndISO,
        next_reset_at: periodEndISO,
      },
    });
  } catch (err) {
    console.error('[consumeBankedCredit]', err.message);
    return Response.json({ error: err.message }, { status: 500 });
  }
});

function getWeekWindow(date) {
  const dayOfWeek = date.getUTCDay();
  const daysToSubtract = dayOfWeek === 0 ? 6 : dayOfWeek - 1;
  const periodStart = new Date(date);
  periodStart.setUTCDate(periodStart.getUTCDate() - daysToSubtract);
  periodStart.setUTCHours(0, 0, 0, 0);
  const periodEnd = new Date(periodStart);
  periodEnd.setUTCDate(periodEnd.getUTCDate() + 7);
  return { periodStart, periodEnd };
}

/**
 * consumeRecipeGeneration
 * 
 * Atomically consumes one recipe generation from the correct bucket.
 * 
 * Consumption order (free users):
 * 1. weekly_free_remaining  → decrement UsageCounter
 * 2. banked_referral_credits → decrement ReferralRewardLedger entries (oldest first)
 * 
 * Pro users: no consumption needed.
 * 
 * Returns updated entitlement state.
 */
import { createClientFromRequest } from 'npm:@base44/sdk@0.8.20';

function getWeekStartDate(date) {
  const d = new Date(date);
  const day = d.getDay() || 7;
  d.setDate(d.getDate() - (day - 1));
  d.setHours(0, 0, 0, 0);
  return d;
}

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user) return Response.json({ error: 'Unauthorized' }, { status: 401 });

    const now = new Date();
    const weekStart = getWeekStartDate(now);
    const weekStartStr = weekStart.toISOString().split('T')[0];

    const [subs, counters, ledgerEntries] = await Promise.all([
      base44.asServiceRole.entities.Subscription.filter({ created_by: user.email }).catch(() => []),
      base44.asServiceRole.entities.UsageCounter.filter({
        created_by: user.email,
        feature: 'recipe_generation',
        week_start_date: weekStartStr,
      }).catch(() => []),
      base44.asServiceRole.entities.ReferralRewardLedger.filter({ user_id: user.id }).catch(() => []),
    ]);

    // Check Pro
    const ENTITLED_PLAN_TYPES = new Set(['pro', 'vip']);
    const isPro = subs.some(s => {
      if (!ENTITLED_PLAN_TYPES.has(s.plan_type)) return false;
      if (s.status === 'active' || s.status === 'trialing') return true;
      if (s.status === 'canceled' && s.current_period_end) return new Date(s.current_period_end).getTime() > now.getTime();
      return false;
    });

    if (isPro) {
      return Response.json({
        success: true,
        consumed_from: 'pro_unlimited',
        is_pro: true,
        weekly_free_remaining: 0,
        banked_referral_credits: 0,
        total_available: null,
        can_generate: true,
      });
    }

    // Compute available
    const WEEKLY_LIMIT = 2;
    const counter = counters[0] || null;
    const weeklyUsed = counter?.count || 0;
    const weeklyRemaining = Math.max(0, WEEKLY_LIMIT - weeklyUsed);

    const earnedEntries = ledgerEntries
      .filter(e => e.credit_state === 'earned' && (e.credits_remaining || 0) > 0)
      .sort((a, b) => new Date(a.earned_at || a.created_date) - new Date(b.earned_at || b.created_date));
    const bankedCredits = earnedEntries.reduce((sum, e) => sum + (e.credits_remaining || 0), 0);

    if (weeklyRemaining === 0 && bankedCredits === 0) {
      return Response.json({
        error: 'LIMIT_REACHED',
        message: 'No generations available. Invite friends to earn more!',
        weekly_free_remaining: 0,
        banked_referral_credits: 0,
        total_available: 0,
        can_generate: false,
      }, { status: 429 });
    }

    let consumedFrom = null;
    let newWeeklyUsed = weeklyUsed;
    let newBankedCredits = bankedCredits;

    if (weeklyRemaining > 0) {
      // Consume from weekly free bucket
      const newCount = weeklyUsed + 1;
      if (counter) {
        await base44.asServiceRole.entities.UsageCounter.update(counter.id, { count: newCount });
      } else {
        await base44.asServiceRole.entities.UsageCounter.create({
          feature: 'recipe_generation',
          week_start_date: weekStartStr,
          count: newCount,
        });
      }
      newWeeklyUsed = newCount;
      consumedFrom = 'weekly_free';
      console.log(`[CONSUME] user=${user.id} from=weekly_free week=${weekStartStr} used=${newCount}`);
    } else {
      // Consume from oldest banked referral credit
      const entry = earnedEntries[0];
      const newRemaining = (entry.credits_remaining || 0) - 1;
      const nowIso = now.toISOString();

      if (newRemaining <= 0) {
        await base44.asServiceRole.entities.ReferralRewardLedger.update(entry.id, {
          credits_remaining: 0,
          credit_state: 'consumed',
          consumed_at: nowIso,
        });
      } else {
        await base44.asServiceRole.entities.ReferralRewardLedger.update(entry.id, {
          credits_remaining: newRemaining,
        });
      }
      newBankedCredits = bankedCredits - 1;
      consumedFrom = 'banked_referral';
      console.log(`[CONSUME] user=${user.id} from=banked_referral entry=${entry.id} remaining_after=${newRemaining}`);
    }

    const nextWeekStart = new Date(weekStart);
    nextWeekStart.setDate(nextWeekStart.getDate() + 7);

    return Response.json({
      success: true,
      consumed_from: consumedFrom,
      is_pro: false,
      weekly_free_used: newWeeklyUsed,
      weekly_free_remaining: Math.max(0, WEEKLY_LIMIT - newWeeklyUsed),
      banked_referral_credits: newBankedCredits,
      total_available: Math.max(0, WEEKLY_LIMIT - newWeeklyUsed) + newBankedCredits,
      can_generate: (Math.max(0, WEEKLY_LIMIT - newWeeklyUsed) + newBankedCredits) > 0,
      next_reset_at: nextWeekStart.toISOString(),
    });
  } catch (error) {
    console.error('[consumeRecipeGeneration]', error.message);
    return Response.json({ error: error.message }, { status: 500 });
  }
});

/**
