 *   if (!check.data.allowed) return Response.json({ error: 'Blocked by cost policy' }, { status: 403 });
 */
import { createClientFromRequest } from 'npm:@base44/sdk@0.8.25';

// ══════════════════════════════════════════════════════════════════════════════
// ALLOWLIST — Every explicitly approved cost-producing scope
