    } = body;

    if (!source || !endpoint_name || !provider_name) {
      return Response.json({ error: 'source, endpoint_name, provider_name required' }, { status: 400 });
    }

    const scopeKey = `${source}:${endpoint_name}:${provider_name}`;
    const isAllowlisted = ALLOWLIST.has(scopeKey);

    // ── Read enforcement mode from AppConfig ────────────────────────────────
    let mode = 'audit'; // safe default
    try {
      const configs = await base44.asServiceRole.entities.AppConfig.filter(
        { config_key: 'cost_enforcement' }, null, 1
      ).catch(() => []);
      if (configs.length > 0 && configs[0].config_value) {
        const parsed = typeof configs[0].config_value === 'string'
          ? JSON.parse(configs[0].config_value)
          : configs[0].config_value;
        if (parsed.mode === 'enforce') mode = 'enforce';
      }
    } catch {
      // AppConfig read failed — safe default to audit
    }

    // ── DECISION ────────────────────────────────────────────────────────────
    if (isAllowlisted) {
      return Response.json({
        allowed: true,
        mode,
        scope_key: scopeKey,
        reason: 'allowlisted',
      });
    }

    // Not in allowlist — depends on mode
    const allowed = mode === 'audit'; // audit = allow but log, enforce = block

    // ── LOG VIOLATION to SystemEventLog ──────────────────────────────────────
    base44.asServiceRole.functions.invoke('logSystemEvent', {
      event_type: event_type || 'violation',
      source,
      endpoint_name,
      origin: 'backend',
      allowed_scope: mode === 'enforce' ? 'should_block' : 'review_needed',
      provider_name,
      model_name,
      user_id,
      credits_used: 0,
      raw_cost_source: 'COST_DATA_UNAVAILABLE',
      success: false,
      error_code: mode === 'enforce' ? 'BLOCKED_BY_POLICY' : 'AUDIT_VIOLATION',
      raw_usage_metadata: {
        scope_key: scopeKey,
        enforcement_mode: mode,
        action_taken: allowed ? 'audit_logged' : 'blocked',
      },
    }).catch(e => console.warn('[costEnforcementPolicy] log failed:', e.message));

    const reason = mode === 'enforce'
      ? `Blocked: scope "${scopeKey}" is not in the cost allowlist`
      : `Audit: scope "${scopeKey}" not allowlisted — would be blocked in enforce mode`;

    console.warn(`[COST_ENFORCEMENT] mode=${mode} allowed=${allowed} scope=${scopeKey} user=${user_id}`);

    return Response.json({
      allowed,
      mode,
      scope_key: scopeKey,
      reason,
    });

  } catch (err) {
    console.error('[costEnforcementPolicy] error:', err.message);
    // Fail-open on infrastructure error — never break the app due to policy check failure
    return Response.json({
      allowed: true,
      mode: 'error_fallback',
      scope_key: 'unknown',
      reason: `Policy check error: ${err.message} — failing open`,
    });
  }
});

/**
 * costPolicyGuard — Central enforcement layer for cost-producing actions.
 *
 * ARCHITECTURE:
 *   Every cost-producing code path calls this BEFORE executing the expensive operation.
 *   Returns { allowed: true } or { allowed: false, reason, violation_id }.
 *
 * MODE (stored in AppConfig entity, key "cost_policy_mode"):
 *   - "audit"   → log violations but allow all calls (default, safe rollout)
 *   - "enforce" → block unauthorized calls and log violation
 *
 * ALLOWLIST:
 *   Hard-coded in this file. Admin changes mode via getCostPolicyConfig.
 *   Scopes are keyed by: { event_type, source, endpoint_name }
 *
 * IMPORTANT: This function is designed to be FAST (<50ms).
 *   It does NOT call external APIs. It reads one AppConfig row (cached per cold start).
 */
import { createClientFromRequest } from 'npm:@base44/sdk@0.8.25';

// ══════════════════════════════════════════════════════════════════════════════
// ALLOWLIST — Explicitly approved cost-producing scopes
// Format: { event_type, source, endpoint_name }
// Anything not listed here is DENIED by default.
// ══════════════════════════════════════════════════════════════════════════════

const ALLOWLIST = [
  // ── RECIPE GENERATION (core product, always allowed) ────────────────────
  { event_type: 'llm_call',          source: 'ai_recipe',       endpoint_name: 'generateRecipeWithQuota' },
  { event_type: 'llm_call',          source: 'ai_recipe',       endpoint_name: 'aiGenerateWithConstraints' },
  { event_type: 'llm_call',          source: 'ai_recipe',       endpoint_name: 'autoRepairRecipeWithConcepts' },

  // ── RECIPE IMAGE GENERATION (Together AI — external, 0 Base44 credits) ──
  { event_type: 'image_generation',  source: 'image_gen',       endpoint_name: 'generateRecipeImageOnDemand' },

  // ── ALLERGEN SUBSTITUTION — NOW DETERMINISTIC (zero LLM) ─────────────────
  // LLM calls from allergen_sub are NO LONGER ALLOWED.
  // substituteAllergenIngredients uses a deterministic engine.

  // ── FILE UPLOADS — Cloudflare R2 (zero Base44 credits) ───────────────────
  // Legacy Base44 Core.UploadFile entries removed — all uploads now go through R2.
  { event_type: 'file_upload',       source: 'upload',          endpoint_name: 'r2Upload' },
  { event_type: 'file_upload',       source: 'image_gen',       endpoint_name: 'r2UploadFromUrl' },

  // ── CONTENT MODERATION (safety-critical, cannot be disabled) ────────────
  { event_type: 'llm_call',          source: 'moderation',      endpoint_name: 'moderateImage' },

  // ── POST VALIDATION (community safety) ──────────────────────────────────
  { event_type: 'llm_call',          source: 'post_validation', endpoint_name: 'validatePostContent' },
];

// Build a fast lookup Set: "event_type|source|endpoint_name"
const ALLOWLIST_SET = new Set(
  ALLOWLIST.map(a => `${a.event_type}|${a.source}|${a.endpoint_name}`)
);

// ── MODE: always read fresh from DB (no cache) ──────────────────────────────
// Admin mode changes must propagate immediately. A single AppConfig.filter()
// call adds ~15-30ms — acceptable for a guard that gates expensive LLM calls.
async function getMode(sr) {
  try {
    const configs = await sr.entities.AppConfig.filter({ config_key: 'cost_policy_mode' }, null, 1);
    return configs[0]?.config_value || 'audit';
  } catch {
    return 'audit'; // fail-safe: default to audit
  }
}

// ══════════════════════════════════════════════════════════════════════════════
// HANDLER
// ══════════════════════════════════════════════════════════════════════════════

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const payload = await req.json();

    const { event_type, source, endpoint_name, user_id, provider_name, model_name } = payload;

    if (!event_type || !source || !endpoint_name) {
      return Response.json({ error: 'Missing: event_type, source, endpoint_name' }, { status: 400 });
    }

    const sr = base44.asServiceRole;
    const mode = await getMode(sr);

    // ── CHECK ALLOWLIST ──────────────────────────────────────────────────────
    const key = `${event_type}|${source}|${endpoint_name}`;
    const isAllowed = ALLOWLIST_SET.has(key);

    if (isAllowed) {
      return Response.json({ allowed: true, mode, scope: 'allowed' });
    }

    // ── NOT ALLOWED — determine action based on mode ─────────────────────────
    const violationData = {
      event_type: event_type === 'llm_call' ? 'violation' : event_type,
      source,
      endpoint_name,
      origin: 'backend',
      allowed_scope: 'should_block',
      provider_name: provider_name || 'unknown',
      model_name: model_name || null,
      credits_used: 0,
      raw_cost_source: 'COST_DATA_UNAVAILABLE',
      user_id: user_id || null,
      success: false,
      error_code: mode === 'enforce' ? 'BLOCKED_BY_COST_POLICY' : 'AUDIT_VIOLATION',
      raw_usage_metadata: {
        policy_mode: mode,
        attempted_scope: key,
        action_taken: mode === 'enforce' ? 'blocked' : 'audit_logged',
      },
    };

    // Log violation to SystemEventLog (always, in both modes)
    sr.functions.invoke('logSystemEvent', violationData).catch(e =>
      console.warn('[costPolicyGuard] violation log failed:', e.message)
    );

    if (mode === 'enforce') {
      // BLOCK: prevent the cost-producing action
      console.warn(`[COST_POLICY] BLOCKED: ${key} user=${user_id}`);
      return Response.json({
        allowed: false,
        mode,
        scope: 'should_block',
        reason: `Cost policy: ${endpoint_name} (${source}/${event_type}) is not in the allowlist`,
      });
    }

    // AUDIT: allow but flag
    console.warn(`[COST_POLICY] AUDIT VIOLATION: ${key} user=${user_id} — allowed in audit mode`);
    return Response.json({
      allowed: true,
      mode,
      scope: 'review_needed',
      reason: `Audit-only: ${endpoint_name} not allowlisted but permitted in audit mode`,
    });

  } catch (err) {
    console.error('[costPolicyGuard] error:', err.message);
    // Fail-open: if the guard itself fails, allow the call (don't break the app)
    return Response.json({ allowed: true, mode: 'error_fallback', scope: 'allowed', error: err.message });
  }
});

