const LEET_MAP = {
  '0':'o','1':'i','2':'z','3':'e','4':'a','5':'s','6':'g',
  '7':'t','8':'b','9':'g','@':'a','$':'s','!':'i','|':'l','+':'t','(':'c',')':'o',
};

function stripInvisible(text) {
  return text.replace(/[\u200B-\u200F\u2028-\u202F\u2060-\u206F\uFEFF\u00AD]/g, '');
}

function normalizeMod(input) {
  if (!input) return { lower: '', stripped: '', collapsed: '', collapsedPartial: '', joined: '' };
  let lower = stripInvisible(input).toLowerCase().trim();
  try { lower = lower.normalize('NFC'); } catch {}
  let leetReplaced = '';
  for (const ch of lower) leetReplaced += LEET_MAP[ch] || ch;
  const stripped = leetReplaced.replace(/[^a-z\u0590-\u05FF\u0600-\u06FF]/g, '');
  const collapsedPartial = stripped.replace(/(.)\1{2,}/g, '$1$1');
  const collapsed = stripped.replace(/(.)\1+/g, '$1');
  const joined = leetReplaced.replace(/[\s._\-=~|/\\,;:!?'"()\[\]{}]/g, '');
  return { lower, stripped, collapsed, collapsedPartial, joined };
}

