  if (terms.length === 0) {
    const jl = (v.joined || '').toLowerCase();
    for (const phrase of ADULT_LOWER) {
      if (v.lower.includes(phrase) || jl.includes(phrase.replace(/\s/g, ''))) {
        terms.push(phrase); break;
      }
