  if (terms.length === 0) {
    const jl = (v.joined || '').toLowerCase();
    for (const [a, b] of SUGGESTIVE_COMBOS) {
      if ((v.lower.includes(a) && v.lower.includes(b)) || (jl.includes(a) && jl.includes(b))) {
