/**
 * createGroupFromDM — Creates a FRIENDS GROUP CHAT.
 * 
 * STRICT RULES:
 * - member_ids must have at least 2 users (excluding the creator) → minimum 3 people total
 * - group_type = 'friends_chat'
 * - privacy = 'private', join_mode = 'invite_only'
 * - Owner role assigned to creator
 * - All invited members must be followers of the creator (backend enforced)
 */
import { createClientFromRequest } from 'npm:@base44/sdk@0.8.25';

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user) return Response.json({ error: 'Unauthorized' }, { status: 401 });

    const { name, member_ids } = await req.json();

    if (!name || name.trim().length < 2 || name.trim().length > 60) {
      return Response.json({ error: 'Group name must be 2–60 characters' }, { status: 400 });
    }

    const uniqueIds = [...new Set((member_ids || []).filter(id => id && id !== user.id))];

    if (uniqueIds.length < 2) {
      return Response.json({ 
        error: 'At least 2 members are required (minimum 3 people total including you)',
        error_code: 'MIN_MEMBERS'
      }, { status: 400 });
    }

    const sr = base44.asServiceRole;

    // BACKEND ENFORCEMENT: verify all invited users are followers of the creator
    const myFollowers = await sr.entities.Follow.filter({ followed_id: user.id, status: 'accepted' }, '', 500).catch(() => []);
    const followerIdSet = new Set(myFollowers.map(f => f.follower_id));
    const invalidIds = uniqueIds.filter(id => !followerIdSet.has(id));
    if (invalidIds.length > 0) {
      return Response.json({ 
        error: 'Some users are not your followers and cannot be invited',
        error_code: 'NOT_FOLLOWERS',
        invalid_ids: invalidIds,
      }, { status: 400 });
    }

    // Create the group
    const group = await sr.entities.Group.create({
      owner_id: user.id,
      name: name.trim(),
      group_type: 'friends_chat',
      privacy: 'private',
      join_mode: 'invite_only',
      description: '',
      cover_emoji: '💬',
      cover_color: '#8b5cf6',
      member_count: 1,
      allow_icon_change: true,
      allow_member_invite: true,
      allow_member_remove: false,
      allow_accept_requests: false,
    });

    // Add owner as member
    await sr.entities.GroupMember.create({
      group_id: group.id,
      user_id: user.id,
      user_name: user.display_name || user.full_name || user.email,
      user_avatar: user.avatar_url || null,
      role: 'owner',
      status: 'active',
      joined_at: new Date().toISOString(),
    });

    // Add invited members
    let addedCount = 0;
    for (const memberId of uniqueIds) {
      try {
        const users = await sr.entities.User.filter({ id: memberId });
        const memberUser = users[0];
        if (!memberUser) continue;

        const existing = await sr.entities.GroupMember.filter({ group_id: group.id, user_id: memberId });
        if (existing.length > 0) continue;

        await sr.entities.GroupMember.create({
          group_id: group.id,
          user_id: memberId,
          user_name: memberUser.display_name || memberUser.full_name || memberUser.email,
          user_avatar: memberUser.avatar_url || null,
          role: 'member',
          status: 'active',
          joined_at: new Date().toISOString(),
        });
        addedCount++;
      } catch (err) {
        console.warn(`[createGroupFromDM] Failed to add member ${memberId}:`, err.message);
      }
    }

    const finalCount = 1 + addedCount;
    await sr.entities.Group.update(group.id, { member_count: finalCount });

    return Response.json({ 
      success: true,
      group_id: group.id, 
      group,
      group_type: 'friends_chat',
      members_added: addedCount,
      member_count: finalCount,
    });
  } catch (error) {
    console.error('[createGroupFromDM] error:', error.message);
    return Response.json({ error: error.message }, { status: 500 });
  }
});

/**
