    const user = await base44.auth.me();

    if (!user) {
      return Response.json({ error: 'Unauthorized' }, { status: 401 });
    }

    // Hard Pro check — mirrors getEntitlements logic (includes canceled-but-active)
    const subs = await base44.asServiceRole.entities.Subscription.filter(
      { created_by: user.email }
    ).catch(() => []);
    const now = Date.now();
    const activeSub = subs.find(s => {
      if (s.plan_type !== 'pro') return false;
      if (s.status === 'active' || s.status === 'trialing') return true;
      if (s.status === 'canceled' && s.current_period_end) return new Date(s.current_period_end).getTime() > now;
      if (s.status === 'canceled' && s.expires_at) return new Date(s.expires_at).getTime() > now;
      return false;
    });
    const isPro = !!activeSub;

    if (!isPro) {
      console.log(`[CREATE_GROUP_POST] PRO_REQUIRED user=${user.id}`);
      return Response.json({ error_code: 'PRO_REQUIRED', error: 'Posting requires Pro' }, { status: 403 });
    }

    // Paused users cannot post
    if (user.account_status === 'paused') {
      return Response.json({ error_code: 'ACCOUNT_PAUSED', error: 'Cannot post while paused' }, { status: 403 });
    }

    const body = await req.json();
    const { group_id, content, recipe_id, media_url } = body;

    if (!group_id || !content) {
      return Response.json({ error: 'group_id and content required' }, { status: 400 });
    }

    // Verify user is member
    const membership = await base44.asServiceRole.entities.GroupMember.filter(
      { group_id, user_id: user.id }, '-created_date', 1
    ).catch(() => []);

    if (!membership.length) {
      return Response.json({ error: 'Not a group member' }, { status: 403 });
    }

    const post = await base44.asServiceRole.entities.GroupPost.create({
      group_id,
      author_id: user.id,
      author_name: user.display_name || user.username || 'User',
      author_avatar: user.avatar_url || null,
      content,
      media_url: media_url || null,
      recipe_id: recipe_id || null,
      like_count: 0,
      comment_count: 0,
      created_at: new Date().toISOString(),
    });

    console.log(`[CREATE_GROUP_POST] SUCCESS group=${group_id} post=${post.id} user=${user.id}`);
    return Response.json({ ok: true, post_id: post.id });

  } catch (error) {
    console.error('[CREATE_GROUP_POST_ERROR]', error.message);
    return Response.json({ error: error.message }, { status: 500 });
  }
});

/**
 * createPost — creates a community or shop post.
 *
 * SHOP POST RULES:
 * - type=shop: community_visible=true, personal_profile_visible=false, shop_visible=true
 * - must have either category_id (shop_location_type=category) OR shop_location_type=general
 * - shop_id required and must be owned by caller
 *
 * COMMUNITY POST RULES:
 * - type=community: community_visible=true, personal_profile_visible=true, shop_visible=false
 */
import { createClientFromRequest } from 'npm:@base44/sdk@0.8.21';

Deno.serve(async (req) => {
  const reqId = crypto.randomUUID().slice(0, 8);
  console.log(`[CREATE_POST:${reqId}] request start`);
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user) return Response.json({ error: 'Unauthorized' }, { status: 401 });

    // Hard Pro check
    const subs = await base44.asServiceRole.entities.Subscription.filter(
      { created_by: user.email }
    ).catch(() => []);
    const now = Date.now();
    const activeSub = subs.find(s => {
      // Accept any paid plan: pro, vip, or trial
      if (!['pro', 'vip', 'trial'].includes(s.plan_type)) return false;
      if (s.status === 'active' || s.status === 'trialing') return true;
      if (s.status === 'canceled' && s.current_period_end) return new Date(s.current_period_end).getTime() > now;
      if (s.status === 'canceled' && s.expires_at) return new Date(s.expires_at).getTime() > now;
      // Trial within dates
      if (s.plan_type === 'trial' && s.trial_end) return new Date(s.trial_end).getTime() > now;
      return false;
    });
    const isPro = !!activeSub;

    if (!isPro) {
      return Response.json({ ok: false, code: 'PRO_REQUIRED', message: 'Posting to the community requires a Pro subscription.' }, { status: 403 });
    }

    if (user.account_status === 'paused') {
      return Response.json({ ok: false, code: 'ACCOUNT_PAUSED', message: 'Cannot post while account is paused.' }, { status: 403 });
    }

    // PRIVATE ACCOUNT RULE: If account is private, cannot post to community/public
    if (user.is_private) {
      return Response.json({
        ok: false,
        code: 'PRIVATE_ACCOUNT_CANNOT_POST_PUBLICLY',
        message: 'Your account is private. Public community posting is unavailable while your account is private. Make your account public to share content with the community.',
      }, { status: 403 });
    }

    const body = await req.json();
    const { type = 'community', title, post_body, media_url, recipe_id, tags, shop_id, category_id, shop_location_type } = body;

    if (!title || !post_body) {
      return Response.json({ ok: false, code: 'MISSING_FIELDS', message: 'Title and description are required.' }, { status: 400 });
    }

    // ── IMAGE MODERATION GATE ─────────────────────────────────────────────────
    // Run before ANY entity creation. Block explicit/adult content.
    if (media_url && !media_url.includes('unsplash.com')) {
      try {
        const moderationRes = await base44.asServiceRole.functions.invoke('moderateImage', {
          image_url: media_url,
          post_type: type,
        });
        const modResult = moderationRes;
        if (modResult && modResult.safe === false) {
          console.warn(`[CREATE_POST:${reqId}] IMAGE_REJECTED user=${user.id} violations=${JSON.stringify(modResult.violations)} confidence=${modResult.confidence}`);
          return Response.json({
            ok: false,
            code: 'IMAGE_POLICY_VIOLATION',
            message: 'This image violates our policy. Please upload a different image that follows our community guidelines.',
            violations: modResult.violations || [],
          }, { status: 400 });
        }
      } catch (modErr) {
        // Moderation check failure: fail open, log warning, allow post
        console.warn(`[CREATE_POST:${reqId}] image moderation check failed (fail open):`, modErr.message);
      }
    }

    // Validate recipe if provided: must be user-authored and owned by caller
    if (recipe_id) {
      const recipeRows = await base44.asServiceRole.entities.Recipe.filter({ id: recipe_id }).catch(() => []);
      const recipe = recipeRows?.[0];
      if (!recipe) {
        return Response.json({ ok: false, code: 'RECIPE_NOT_FOUND', message: 'Recipe not found.' }, { status: 404 });
      }
      if (recipe.source === 'generated') {
        console.warn(`[CREATE_POST:${reqId}] AI_RECIPE_BLOCKED recipeId=${recipe_id} userId=${user.id}`);
        return Response.json({ ok: false, code: 'AI_RECIPE_NOT_ALLOWED', message: 'AI-generated recipes cannot be shared as posts.' }, { status: 400 });
      }
      if (recipe.author_id && recipe.author_id !== user.id) {
        console.warn(`[CREATE_POST:${reqId}] NOT_RECIPE_OWNER recipeId=${recipe_id} userId=${user.id}`);
        return Response.json({ ok: false, code: 'NOT_RECIPE_OWNER', message: 'You can only share your own recipes.' }, { status: 403 });
      }
    }

    let postData = {
      author_id: user.id,
      type,
      title,
      body: post_body,
      media_url: media_url || null,
      recipe_id: recipe_id || null,
      tags: tags || [],
      like_count: 0,
      comment_count: 0,
      status: 'active',
    };

    if (type === 'shop') {
      // Validate shop ownership
      if (!shop_id) return Response.json({ ok: false, error: 'shop_id required for shop posts' }, { status: 400 });
      const shops = await base44.asServiceRole.entities.Shop.filter({ id: shop_id, owner_id: user.id });
      if (!shops.length) return Response.json({ ok: false, error: 'Forbidden: not shop owner' }, { status: 403 });

      // Determine placement
      const hasCategory = !!category_id;
      const resolvedLocationType = hasCategory ? 'category' : (shop_location_type === 'general' ? 'general' : null);
      if (!resolvedLocationType) {
        return Response.json({ ok: false, error: 'Shop posts must have a category or be placed in General. Provide category_id or shop_location_type=general.' }, { status: 400 });
      }

      postData = {
        ...postData,
        shop_id,
        category_id: hasCategory ? category_id : null,
        shop_location_type: resolvedLocationType,
        community_visible: true,       // always distributed to community/discovery
        personal_profile_visible: false, // never appears on author profile grid
        shop_visible: true,
      };

      // Also register in ShopAvailableRecipe if recipe_id provided
      if (recipe_id) {
        const existing = await base44.asServiceRole.entities.ShopAvailableRecipe.filter({ shop_id, recipe_id }).catch(() => []);
        if (!existing.length) {
          await base44.asServiceRole.entities.ShopAvailableRecipe.create({
            shop_id,
            recipe_id,
            distribution_state: 'active',
          }).catch(e => console.warn(`[CREATE_POST:${reqId}] ShopAvailableRecipe upsert warn: ${e.message}`));
        }
        // Also register in ShopCategoryRecipe if category set
        if (hasCategory) {
          const existingCatRecipe = await base44.asServiceRole.entities.ShopCategoryRecipe.filter({ category_id, recipe_id }).catch(() => []);
          if (!existingCatRecipe.length) {
            await base44.asServiceRole.entities.ShopCategoryRecipe.create({
              category_id,
              shop_id,
              recipe_id,
              sort_order: 0,
            }).catch(e => console.warn(`[CREATE_POST:${reqId}] ShopCategoryRecipe upsert warn: ${e.message}`));
          }
        }
      }

    } else {
      // Community post
      postData = {
        ...postData,
        shop_id: null,
        category_id: null,
        shop_location_type: 'none',
        community_visible: true,
        personal_profile_visible: true,
        shop_visible: false,
      };
    }

    // ── STAGE 1 INITIALIZATION ────────────────────────────────────────────────
    // Every new post enters Stage 1 with a controlled initial impression budget.
    // Stage 0 = not yet initialized. Stage 1 = initial test batch (target 50 impressions).
    // This is set here so the distribution engine can detect new posts immediately.
    postData.stage = 1;
    postData.stage_impressions = 0;
    postData.stage_passed_at = null;
    postData.ctr_rolling = 0;
    postData.er_rolling = 0;
    postData.dwell_rolling = 0;
    postData.integrity_score = 1.0;
    postData.status = 'active';

    const post = await base44.asServiceRole.entities.Post.create(postData);

    // CACHE INVALIDATION: Delete the user's UserFeedCache so next feed fetch re-computes
    // without this, newly published posts won't appear in community for up to 30 minutes
    base44.asServiceRole.entities.UserFeedCache.filter({ user_id: user.id, feed_type: 'for_you' })
      .then(caches => {
        if (caches?.length > 0) {
          return base44.asServiceRole.entities.UserFeedCache.delete(caches[0].id);
        }
      })
      .catch(e => console.warn(`[CREATE_POST:${reqId}] Cache invalidation warn: ${e.message}`));

    // Fire-and-forget: generate deterministic Hebrew translations (zero credits)
    base44.asServiceRole.functions.invoke('generateHebrewContentForPost', {
      post_id: post.id,
      post_data: { title, body: post_body },
    }).catch(e => console.warn(`[CREATE_POST:${reqId}] Hebrew gen warn: ${e.message}`));

    console.log(`[CREATE_POST:${reqId}] SUCCESS postId=${post.id} type=${type} user=${user.id} stage=1 recipeId=${recipe_id || 'none'}`);
    return Response.json({ ok: true, post_id: post.id, post }, { status: 201 });
  } catch (error) {
    console.error(`[CREATE_POST:${reqId}] error: ${error.message}`);
    return Response.json({ ok: false, code: 'INTERNAL_ERROR', message: 'Failed to publish your recipe. Please try again.' }, { status: 500 });
  }
});

