    }

    const { post_id, body, parent_comment_id } = await req.json();
    if (!post_id || !body?.trim()) {
      return Response.json({ error: 'post_id and body required' }, { status: 400 });
    }

    // Backend moderation
    if (!_moderateComment(body)) {
      return Response.json({ error: 'Please remove inappropriate language and try again.' }, { status: 400 });
    }

    const sr = base44.asServiceRole.entities;

    // Verify post exists
    const posts = await sr.Post.filter({ id: post_id });
    if (!posts.length) {
      return Response.json({ error: 'Post not found' }, { status: 404 });
    }
    const post = posts[0];

    // Create the comment
    const commentData = {
      post_id,
      author_id: user.id,
      author_name: user.display_name || user.full_name || user.email?.split('@')[0] || 'User',
      author_avatar: user.avatar_url || '',
      body: body.trim(),
    };
    if (parent_comment_id) {
      commentData.parent_comment_id = parent_comment_id;
    }

    const comment = await sr.PostComment.create(commentData);

    // Update comment count
    const allComments = await sr.PostComment.filter({ post_id });
    await sr.Post.update(post_id, { comment_count: allComments.length }).catch(() => {});

    const actorName = user.display_name || user.full_name || user.email?.split('@')[0] || 'Someone';
    const actorAvatar = user.avatar_url || '';

    // ── REPLY DETECTION ───────────────────────────────────────────────────
    // If parent_comment_id is set, this is a reply → notify parent comment author
    // If not, this is a top-level comment → notify post/recipe author
    // Edge case: if reply author is ALSO different from post author, notify BOTH
    //            (parent comment author gets "comment_reply", post author gets "recipe_commented")

    const notifiedIds = new Set(); // prevent duplicate notifications

    if (parent_comment_id) {
      // REPLY: look up parent comment to find its author
      const parentComments = await sr.PostComment.filter({ id: parent_comment_id });
      const parentComment = parentComments[0];

      if (parentComment && parentComment.author_id && parentComment.author_id !== user.id) {
        notifiedIds.add(parentComment.author_id);
        base44.asServiceRole.functions.invoke('sendBasicNotification', {
          type: 'comment_reply',
          recipientId: parentComment.author_id,
          actorId: user.id,
          actorName,
          actorAvatar,
          data: {
            recipeId: post.recipe_id || null,
            recipeTitle: post.title || '',
          },
        }).catch(err => console.warn('[createPostComment] reply push failed:', err.message));
      }

      // ALSO notify post author with "recipe_commented" if they're a different person
      if (post.author_id && post.author_id !== user.id && !notifiedIds.has(post.author_id)) {
        notifiedIds.add(post.author_id);
        base44.asServiceRole.functions.invoke('sendBasicNotification', {
          type: 'recipe_commented',
          recipientId: post.author_id,
          actorId: user.id,
          actorName,
          actorAvatar,
          data: {
            recipeId: post.recipe_id || null,
            recipeTitle: post.title || '',
          },
        }).catch(err => console.warn('[createPostComment] post author push failed:', err.message));
      }
    } else {
      // TOP-LEVEL COMMENT: notify post/recipe author
      if (post.author_id && post.author_id !== user.id) {
        base44.asServiceRole.functions.invoke('sendBasicNotification', {
          type: 'recipe_commented',
          recipientId: post.author_id,
          actorId: user.id,
          actorName,
          actorAvatar,
          data: {
            recipeId: post.recipe_id || null,
            recipeTitle: post.title || '',
          },
        }).catch(err => console.warn('[createPostComment] push failed:', err.message));
      }
    }

    return Response.json({ comment });
  } catch (error) {
    console.error('[createPostComment] error:', error.message);
    return Response.json({ error: error.message }, { status: 500 });
  }
});

/**
 * createPostWithProGate — Post creation with backend Pro enforcement
 * Used by: PublishRecipe, Community posts, Group posts
 * Backend is single source of truth
 */
import { createClientFromRequest } from 'npm:@base44/sdk@0.8.20';

Deno.serve(async (req) => {
  if (req.method !== 'POST') {
    return Response.json({ error: 'Method not allowed' }, { status: 405 });
  }

  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user) {
      return Response.json({ error: 'Unauthorized' }, { status: 401 });
    }

    // Check Pro status (backend entitlements only)
    const entRes = await base44.functions.invoke('getEntitlements', { user_id: user.id });
    if (!entRes.data?.is_pro) {
      return Response.json({ error: 'PRO_REQUIRED', message: 'Only Pro users can post' }, { status: 403 });
    }

    // Check account status
    if (user.account_status === 'paused') {
      return Response.json({ error: 'ACCOUNT_PAUSED', message: 'Cannot post while account is paused' }, { status: 403 });
    }

    const { title, body, media_url, type, shop_id, category_id, tags } = await req.json();

    // Validate
    if (!title || !body) {
      return Response.json({ error: 'Missing title or body' }, { status: 400 });
    }

    // If shop post, verify ownership
    if (type === 'shop' && shop_id) {
      const shop = await base44.asServiceRole.entities.Shop.read(shop_id);
      if (!shop || shop.owner_id !== user.id) {
        return Response.json({ error: 'Shop ownership required' }, { status: 403 });
      }
    }

    // Create post
    const post = await base44.asServiceRole.entities.Post.create({
      author_id: user.id,
      type: type || 'community',
      shop_id: shop_id || null,
      category_id: category_id || null,
      title,
      body,
      media_url: media_url || null,
      tags: Array.isArray(tags) ? tags : [],
      stage: 0,
      stage_impressions: 0,
      like_count: 0,
      comment_count: 0,
      save_count: 0,
      rating_count: 0,
      rating_bayes: 0,
      ctr_rolling: 0,
      er_rolling: 0,
      dwell_rolling: 0,
      integrity_score: 1.0,
      status: 'active',
      last_metrics_update: new Date().toISOString(),
    });

    console.log(`[CREATE_POST] user=${user.id} post=${post.id} type=${type}`);
    return Response.json({ ok: true, post_id: post.id });

  } catch (error) {
    console.error('[CREATE_POST_ERROR]', error.message);
    if (error.message.includes('PRO_REQUIRED')) {
      return Response.json({ error: 'PRO_REQUIRED' }, { status: 403 });
    }
    return Response.json({ error: 'Failed to create post' }, { status: 500 });
  }
});

/**
 * createReport — Submit a user-generated moderation report
 *
 * Architecture:
 *   1. Authenticate reporter
 *   2. Validate input
 *   3. Save Report entity to DB (source of truth — MUST succeed)
 *   4. Fire-and-forget email notification via sendReportEmail (failure is logged, never bubbles)
 *   5. Return success as long as DB write succeeded
 */
import { createClientFromRequest } from 'npm:@base44/sdk@0.8.20';

Deno.serve(async (req) => {
  if (req.method !== 'POST') {
    return Response.json({ error: 'Method not allowed' }, { status: 405 });
  }

  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user) {
      return Response.json({ error: 'Unauthorized' }, { status: 401 });
    }

    const { target_type, target_id, reason, details } = await req.json();
    if (!target_type || !target_id || !reason) {
      return Response.json({ error: 'Missing required fields: target_type, target_id, reason' }, { status: 400 });
    }

    // ── Step 1: Save report to DB (primary, must succeed) ────────────────────
    const report = await base44.asServiceRole.entities.Report.create({
      reporter_user_id: user.id,
      target_type,
      target_id,
      reason,
      details: details || '',
      status: 'open',
      email_status: 'pending',
    });

    console.log(`[CREATE_REPORT] saved report=${report.id} type=${target_type} reporter=${user.id}`);

    // ── Step 2: Fire-and-forget HTML email notification via Resend ───────────
    // Email failure NEVER fails the report submission.
    const emailPayload = {
      report_id:      report.id,
      reporter_email: user.email || null,
      reporter_id:    user.id || null,
      target_type,
      target_id,
      reason,
      details:        details || '',
      created_at:     report.created_date || new Date().toISOString(),
      app_url:        Deno.env.get('APP_PUBLIC_URL') || '',
    };

    // Invoke asynchronously — do not await, do not let it fail the response
    base44.asServiceRole.functions.invoke('sendReportEmail', emailPayload)
      .then(res => {
        const d = res?.data;
        if (d?.ok) {
          console.log(`[CREATE_REPORT] email sent report=${report.id} resend_id=${d.resend_id || 'ok'}`);
          // Best-effort: update email_status to 'sent'
          base44.asServiceRole.entities.Report.update(report.id, { email_status: 'sent' }).catch(() => {});
        } else {
          console.warn(`[CREATE_REPORT] email failed report=${report.id} error=${d?.error || 'unknown'}`);
          base44.asServiceRole.entities.Report.update(report.id, { email_status: 'failed' }).catch(() => {});
        }
      })
      .catch(err => {
        console.error(`[CREATE_REPORT] sendReportEmail invocation error report=${report.id}:`, err.message);
        base44.asServiceRole.entities.Report.update(report.id, { email_status: 'failed' }).catch(() => {});
      });

    // Return success immediately — email is non-blocking
    return Response.json({ ok: true, report_id: report.id });

  } catch (error) {
    console.error('[CREATE_REPORT_ERROR]', error.message);
    return Response.json({ error: error.message }, { status: 500 });
  }
});

import { createClientFromRequest } from 'npm:@base44/sdk@0.8.23';

/**
 * createUniqueNotification — Creates a notification only if it doesn't already
 * exist for this recipient+actor+type combo in the last 24 hours.
 *
 * Key guarantees:
 *  - NEVER creates a self-notification (recipientId === fromUserId → skip)
 *  - Deduplicates follow/like/etc. within a 24h window
 *  - Works correctly when recipe_id is null (follow notifications)
 */
Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const { recipientId, type, fromUserId, recipeId, message, title, fromUserName, fromUserAvatar } = await req.json();

    if (!recipientId || !type || !fromUserId) {
      return Response.json({ error: 'Missing required fields: recipientId, type, fromUserId' }, { status: 400 });
    }

    // ── Hard guard: never create a self-notification ─────────────────────────
    if (recipientId === fromUserId) {
      console.log(`[createUniqueNotification] Skipped — self-notification prevented type=${type} user=${fromUserId}`);
      return Response.json({ success: false, reason: 'Self-notification prevented', created: false });
    }

    // ── Dedup logic by notification type ─────────────────────────────────────
    // For interaction types (like/follow/save/rating): ALL-TIME dedup — never
    // re-create if a notification already exists from the same actor. This prevents
    // spam from repeated like→unlike→like cycles.
    // For follow_request: delete all existing pending requests from this actor first,
    // then create a fresh one (only the latest request is ever visible).
    // For all other types (comment, mention, etc.): keep 24h dedup window.
    const INTERACTION_TYPES = new Set(['like', 'recipe_like', 'follow', 'save', 'rating', 'recipe_rating', 'recipe_save']);

    const filterQuery = {
      recipient_id: recipientId,
      type,
      from_user_id: fromUserId,
    };
    if (recipeId) filterQuery.recipe_id = recipeId;

    const existingNotifs = await base44.asServiceRole.entities.Notification.filter(filterQuery);

    if (INTERACTION_TYPES.has(type)) {
      // All-time dedup: if any notification of this type already exists from this actor, skip
      if (existingNotifs.length > 0) {
        console.log(`[createUniqueNotification] Skipped — all-time duplicate ${type} from=${fromUserId} to=${recipientId}`);
        return Response.json({ success: false, reason: 'Duplicate notification', created: false });
      }
    } else if (type === 'follow_request') {
      // Follow requests: remove all previous pending requests from this actor, then create fresh
      const toDelete = existingNotifs.filter(n => !n.is_read);
      await Promise.allSettled(
        toDelete.map(n => base44.asServiceRole.entities.Notification.delete(n.id))
      );
      if (toDelete.length > 0) {
        console.log(`[createUniqueNotification] Cleared ${toDelete.length} old follow_request notifs from=${fromUserId}`);
      }
    } else {
      // Default: 24h dedup for comments, mentions, etc.
      const oneDayAgo = new Date(Date.now() - 24 * 60 * 60 * 1000);
      const recentDupes = existingNotifs.filter(n => new Date(n.created_date) > oneDayAgo);
      if (recentDupes.length > 0) {
        console.log(`[createUniqueNotification] Skipped — 24h duplicate ${type} from=${fromUserId} to=${recipientId}`);
        return Response.json({ success: false, reason: 'Duplicate notification', created: false });
      }
    }

    // ── Re-fetch actor identity from DB (canonical avatar + name, never stale) ──
    // This ensures default Reciply character avatars and recently-updated profiles
    // always show correctly, regardless of what the caller passed.
    let canonicalAvatar = fromUserAvatar || '';
    let canonicalName   = fromUserName   || '';
    try {
      const actorUsers = await base44.asServiceRole.entities.User.filter({ id: fromUserId });
      if (actorUsers[0]) {
        canonicalAvatar = actorUsers[0].avatar_url   || canonicalAvatar;
        canonicalName   = actorUsers[0].display_name || actorUsers[0].full_name || canonicalName;
      }
    } catch (_e) {
      // Non-fatal — fall back to caller-supplied values
      console.warn(`[createUniqueNotification] Could not re-fetch actor ${fromUserId}: ${_e.message}`);
    }

    // ── Create the notification ───────────────────────────────────────────────
    const notification = await base44.asServiceRole.entities.Notification.create({
      recipient_id: recipientId,
      type,
      title: title || 'New notification',
      message: message || '',
      from_user_id: fromUserId,
      from_user_name: canonicalName,
      from_user_avatar: canonicalAvatar,
      recipe_id: recipeId || null,
      is_read: false,
    });

    return Response.json({ success: true, created: true, notification });

  } catch (error) {
    console.error('[createUniqueNotification]', error.message);
    return Response.json({ error: error.message }, { status: 500 });
  }
});

/**
 * createUserRecipe — Backend-authoritative recipe creation for user-uploaded recipes.
 *
 * Enforces:
 *  1. Ownership / auth
 *  2. Ingredient amount limits — category-aware MIN + MAX (centralized policy)
 *  3. Servings limit (max 150)
 *  4. Creates Recipe entity and returns the created record
 */
import { createClientFromRequest } from 'npm:@base44/sdk@0.8.23';

// ── Centralized unit MIN + MAX policy (mirrored from lib/ingredientAmountPolicy.js) ──
const UNIT_MAX = {
  g: 25000, gram: 25000, grams: 25000,
  kg: 25, kilogram: 25, kilograms: 25,
  ml: 20000,
  l: 20, liter: 20, liters: 20, litre: 20, litres: 20,
  tsp: 300, teaspoon: 300, teaspoons: 300,
  tbsp: 150, tablespoon: 150, tablespoons: 150,
  cup: 100, cups: 100,
  piece: 500, pieces: 500, pc: 500, pcs: 500, unit: 500, units: 500,
  clove: 200, cloves: 200, slice: 300, slices: 300,
  egg: 200, eggs: 200,
  can: 50, cans: 50, tin: 50, tins: 50,
  packet: 50, packets: 50, pack: 50, packs: 50, sachet: 50, sachets: 50,
  bunch: 30, bunches: 30, pinch: 50, pinches: 50, dash: 50, dashes: 50,
  oz: 500, ounce: 500, ounces: 500,
  lb: 50, lbs: 50, pound: 50, pounds: 50,
  handful: 50, handfuls: 50, sprig: 50, sprigs: 50,
  leaf: 200, leaves: 200, drop: 100, drops: 100,
  strip: 100, strips: 100, rasher: 100, rashers: 100,
  stalk: 50, stalks: 50, head: 20, heads: 20,
  fillet: 150, fillets: 150, ball: 50, balls: 50,
  block: 50, blocks: 50, loaf: 20, loaves: 20,
  sheet: 50, sheets: 50, wrap: 100, wraps: 100,
  tortilla: 100, tortillas: 100,
};

const UNIT_FAMILY = {
  g: 'weight', gram: 'weight', grams: 'weight',
  kg: 'weight_kg', kilogram: 'weight_kg', kilograms: 'weight_kg',
  oz: 'weight_oz', ounce: 'weight_oz', ounces: 'weight_oz',
  lb: 'weight_lb', lbs: 'weight_lb', pound: 'weight_lb', pounds: 'weight_lb',
  ml: 'volume_ml',
  l: 'volume_l', liter: 'volume_l', liters: 'volume_l', litre: 'volume_l', litres: 'volume_l',
  tsp: 'spoon', teaspoon: 'spoon', teaspoons: 'spoon',
  tbsp: 'spoon', tablespoon: 'spoon', tablespoons: 'spoon',
  cup: 'cup', cups: 'cup',
  pinch: 'tiny', pinches: 'tiny', dash: 'tiny', dashes: 'tiny', drop: 'tiny', drops: 'tiny',
};

const PROTEIN_KEYWORDS = [
  'chicken', 'beef', 'pork', 'lamb', 'turkey', 'duck', 'veal', 'venison', 'bison',
  'salmon', 'tuna', 'cod', 'halibut', 'tilapia', 'shrimp', 'prawn', 'lobster', 'crab',
  'tofu', 'tempeh', 'seitan', 'quorn',
  'steak', 'mince', 'ground beef', 'ground turkey', 'ground pork',
  'breast', 'thigh', 'wing', 'drumstick', 'fillet', 'tenderloin', 'loin', 'sirloin',
  'sausage', 'bacon', 'ham', 'prosciutto',
];
const SPICE_KEYWORDS = [
  'salt', 'pepper', 'paprika', 'cumin', 'oregano', 'thyme', 'rosemary', 'basil',
  'cinnamon', 'turmeric', 'coriander', 'cardamom', 'nutmeg', 'allspice',
  'chili', 'cayenne', 'chilli', 'flakes', 'powder', 'seasoning', 'spice', 'herb',
  'garlic powder', 'onion powder', 'mustard powder', 'curry', 'garam masala',
  'bay leaf', 'sage', 'marjoram', 'dill', 'fennel', 'anise', 'saffron', 'sumac',
];
const LIQUID_KEYWORDS = [
  'oil', 'milk', 'cream', 'broth', 'stock', 'water', 'juice', 'wine', 'vinegar',
  'sauce', 'soy sauce', 'fish sauce', 'oyster sauce', 'worcestershire', 'hot sauce',
  'sriracha', 'ketchup', 'mustard', 'mayonnaise', 'tahini', 'pesto', 'salsa',
  'coconut milk', 'almond milk', 'buttermilk', 'yogurt', 'sour cream',
  'honey', 'maple syrup', 'molasses', 'syrup', 'extract', 'vanilla',
  'butter', 'ghee', 'lard', 'shortening', 'margarine',
];

function detectCategory(name) {
  const n = (name || '').toLowerCase().trim();
  if (PROTEIN_KEYWORDS.some(k => n.includes(k))) return 'protein';
  if (SPICE_KEYWORDS.some(k => n.includes(k))) return 'spice';
  if (LIQUID_KEYWORDS.some(k => n.includes(k))) return 'liquid';
  return 'general';
}

function getMinForUnitAndCategory(unitFamily, category) {
  if (['spoon', 'tiny'].includes(unitFamily)) return 0.1;
  if (['count', 'cup'].includes(unitFamily)) return 0.1; // count units handled by family lookup
  if (unitFamily === 'volume_ml') return 1;
  if (unitFamily === 'volume_l') return 0.01;
  if (unitFamily === 'weight') {
    if (category === 'protein') return 20;
    if (category === 'spice')   return 0.1;
    if (category === 'liquid')  return 1;
    return 5;
  }
  if (unitFamily === 'weight_kg') {
    if (category === 'protein') return 0.02;
    if (category === 'spice')   return 0.0001;
    return 0.005;
  }
  if (unitFamily === 'weight_oz') {
    if (category === 'protein') return 0.7;
    if (category === 'spice')   return 0.01;
    return 0.2;
  }
  if (unitFamily === 'weight_lb') {
    if (category === 'protein') return 0.04;
    if (category === 'spice')   return 0.001;
    return 0.01;
  }
  return 0;
}

function parseAmountAndUnit(item) {
  let amount = item.amount;
  let unit = item.unit || '';
  if (typeof amount === 'string') {
    const match = amount.trim().match(/^([\d.]+)\s*([a-zA-Z].*)$/);
    if (match) {
      amount = match[1];
      if (!unit) unit = match[2].trim();
    }
  }
  return { amount, unit };
}

function validateIngredients(ingredientGroups) {
  const errors = [];
  let globalIndex = 0;
  for (const group of (ingredientGroups || [])) {
    for (const item of (group.items || [])) {
      if (!item || item.optional || item.missing) { globalIndex++; continue; }
      const { amount, unit } = parseAmountAndUnit(item);
      if (!amount && amount !== 0) { globalIndex++; continue; }
      const parsedAmount = parseFloat(amount);
      const name = item.name || 'ingredient';
      const normalizedUnit = String(unit || '').trim().toLowerCase();
      const category = detectCategory(name);
      const unitFamily = UNIT_FAMILY[normalizedUnit] || 'unknown';

      if (isNaN(parsedAmount)) {
        errors.push({ index: globalIndex, name, entered_amount: amount, entered_unit: unit, error_code: 'NOT_NUMERIC', message: `Amount for "${name}" must be a number.` });
        globalIndex++; continue;
      }
      if (parsedAmount <= 0) {
        errors.push({ index: globalIndex, name, entered_amount: parsedAmount, entered_unit: unit, error_code: 'NOT_POSITIVE', message: `Amount for "${name}" must be greater than 0.` });
        globalIndex++; continue;
      }

      // ── MIN check ──────────────────────────────────────────────────────────
      const min = getMinForUnitAndCategory(unitFamily, category);
      if (min > 0 && parsedAmount < min) {
        const categoryLabel = category === 'protein' ? 'proteins/meat' : category;
        errors.push({
          index: globalIndex, name, entered_amount: parsedAmount,
          entered_unit: unit, normalized_unit: normalizedUnit,
          min_allowed: min, ingredient_category: category,
          error_code: 'BELOW_MIN',
          message: `Amount for "${name}" is too small. Minimum for ${categoryLabel} in ${normalizedUnit || 'this unit'} is ${min} ${normalizedUnit || 'units'}.`,
        });
        globalIndex++; continue;
      }

      // ── MAX check ──────────────────────────────────────────────────────────
      const max = UNIT_MAX[normalizedUnit] ?? 1000;
      if (parsedAmount > max) {
        errors.push({
          index: globalIndex, name, entered_amount: parsedAmount,
          entered_unit: unit, normalized_unit: normalizedUnit,
          max_allowed: max, error_code: 'EXCEEDS_MAX',
          message: `Amount for "${name}" is too large. Maximum for "${normalizedUnit || 'this unit'}" is ${max.toLocaleString()}.`,
        });
      }
      globalIndex++;
    }
  }
  return { valid: errors.length === 0, errors };
}

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user) return Response.json({ error: 'Unauthorized' }, { status: 401 });

    const body = await req.json();
    const {
      title, description, cuisine, meal_type, cook_time, prep_time,
      difficulty, servings, tags, ingredients, steps, hero_image_url,
      is_public, visibility, followers_only, is_community_content,
      community_visible, source,
    } = body;

    // ── Servings limit ───────────────────────────────────────────────────────
    const parsedServings = parseInt(servings) || 2;
    if (parsedServings > 150) {
      return Response.json({ ok: false, code: 'SERVINGS_EXCEEDED', message: 'Servings cannot exceed 150.' }, { status: 400 });
    }

    // ── Instructions validation — reject whitespace-only steps ────────────
    if (steps && Array.isArray(steps)) {
      const realSteps = steps.filter(s => s?.instruction && s.instruction.replace(/[\s\n\r\t]+/g, '').length > 0);
      if (realSteps.length < 2) {
        return Response.json({ ok: false, code: 'INSTRUCTIONS_EMPTY', message: 'At least 2 instruction steps with real text are required.' }, { status: 400 });
      }
    }

    // ── Ingredient amount validation (MIN + MAX) ─────────────────────────────
    if (ingredients && Array.isArray(ingredients)) {
      const validation = validateIngredients(ingredients);
      if (!validation.valid) {
        return Response.json({
          ok: false,
          code: 'INGREDIENT_AMOUNT_INVALID',
          message: validation.errors[0]?.message || 'One or more ingredient amounts are invalid.',
          errors: validation.errors,
        }, { status: 400 });
      }
    }

    // ── Create Recipe ────────────────────────────────────────────────────────
    const recipeData = {
      title, description, cuisine, meal_type,
      cook_time: parseInt(cook_time) || 0,
      prep_time: parseInt(prep_time) || 0,
      difficulty,
      servings: parsedServings,
      tags: tags || [],
      ingredients: ingredients || [],
      steps: steps || [],
      hero_image_url: hero_image_url || null,
      is_public: is_public !== false,
