/**
 * debugSendTestEmail — Admin-only Resend email test endpoint
 * Sends a simple test email and returns full debug payload
 * 
 * Security: Requires X-ADMIN-DEBUG-KEY header matching ADMIN_DEBUG_KEY env var
 */

import { createClientFromRequest } from 'npm:@base44/sdk@0.8.20';

function maskEmail(email) {
  if (!email || !email.includes('@')) return 'invalid';
  const [localPart, domain] = email.split('@');
  if (localPart.length <= 2) return `${localPart}***@${domain}`;
  return `${localPart.substring(0, 2)}***@${domain}`;
}

Deno.serve(async (req) => {
  const correlationId = crypto.randomUUID().slice(0, 8);

  if (req.method !== 'POST') {
    return Response.json({ error: 'Method not allowed' }, { status: 405 });
  }

  try {
    console.log(`[DEBUG_EMAIL:${correlationId}] Test email request initiated`);

    // Check admin authorization
    const adminDebugKey = Deno.env.get('ADMIN_DEBUG_KEY');
    const providedKey = req.headers.get('X-ADMIN-DEBUG-KEY');

    if (!adminDebugKey) {
      console.warn(`[DEBUG_EMAIL:${correlationId}] ADMIN_DEBUG_KEY not set`);
      return Response.json(
        { error: 'Admin debug mode not enabled' },
        { status: 403 }
      );
    }

    if (providedKey !== adminDebugKey) {
      console.warn(`[DEBUG_EMAIL:${correlationId}] Invalid admin key`);
      return Response.json(
        { error: 'Unauthorized' },
        { status: 403 }
      );
    }

    // Parse request body
    const { to } = await req.json();

    if (!to || !to.includes('@')) {
      return Response.json(
        { error: 'Invalid recipient email' },
        { status: 400 }
      );
    }

    console.log(`[DEBUG_EMAIL:${correlationId}] Sending test email to: ${maskEmail(to)}`);

    // Get Resend config
    const resendApiKey = Deno.env.get('RESEND_API_KEY');
    if (!resendApiKey) {
      return Response.json(
        {
          ok: false,
          error: 'RESEND_API_KEY not configured',
          http_status: 0,
          to: maskEmail(to),
        },
        { status: 500 }
      );
    }

    // Hardcoded verified Resend sender
    const mailFrom = 'support@reciplyai.app';
    const mailFromName = 'Reciply';
    const fromHeader = `${mailFromName} <${mailFrom}>`;

    console.log(`[DEBUG_EMAIL:${correlationId}] Using sender: ${fromHeader}`);

    // Build Resend payload
    const payload = {
      from: fromHeader,
      to: [to],
      subject: '[Reciply] Test Email',
      html: `<div style="font-family: sans-serif; padding: 20px;"><h2>✓ Reciply Test Email</h2><p>This is a test email from Reciply to verify Resend integration is working.</p><p>Time: ${new Date().toISOString()}</p></div>`,
      text: `Reciply Test Email\n\nThis is a test email from Reciply to verify Resend integration is working.\n\nTime: ${new Date().toISOString()}`,
    };

    console.log(`[DEBUG_EMAIL:${correlationId}] Calling Resend API...`);

    const resendResponse = await fetch('https://api.resend.com/emails', {
      method: 'POST',
      headers: {
        'Authorization': `Bearer ${resendApiKey}`,
        'Content-Type': 'application/json',
      },
      body: JSON.stringify(payload),
    });

    const httpStatus = resendResponse.status;
    const responseBody = await resendResponse.json().catch(() => ({}));

    console.log(`[DEBUG_EMAIL:${correlationId}] Resend Status: ${httpStatus}`);
    console.log(`[DEBUG_EMAIL:${correlationId}] Resend Response:`, responseBody);

    if (!resendResponse.ok) {
      return Response.json({
        ok: false,
        provider: 'resend',
        http_status: httpStatus,
        to: maskEmail(to),
        from: fromHeader,
        error: responseBody.message || responseBody.error || 'Unknown error',
        response_body: responseBody,
      });
    }

    return Response.json({
      ok: true,
      provider: 'resend',
      http_status: httpStatus,
      resend_id: responseBody.id || 'resend-ok',
      to: maskEmail(to),
      from: fromHeader,
      message: 'Test email sent successfully',
      response_body: responseBody,
    });
  } catch (error) {
    console.error(`[DEBUG_EMAIL:${correlationId}] Uncaught error: ${error.message}`);
    return Response.json(
      {
        ok: false,
        error: error.message,
        http_status: 0,
      },
      { status: 500 }
    );
  }
});

/**
 * debugStreakSimulate — PROOF-ONLY backend endpoint.
 * Simulates a streak action as if the user's last action was N days ago.
 * Admin-only. Never call in production flow.
 *
 * Payload:
 *   action_type: 'generate' | 'log_meal' | 'cook_complete'
 *   days_since_last_action: number (1 = yesterday, 2 = 2 days ago, etc.)
 *
 * Returns: the same response shape as updateStreakAction, plus debug info.
 */
import { createClientFromRequest } from 'npm:@base44/sdk@0.8.23';

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();

    if (!user?.id) return Response.json({ error: 'Unauthorized' }, { status: 401 });
    if (user.role !== 'admin') return Response.json({ error: 'Admin only' }, { status: 403 });

    const body = await req.json();
    const { action_type = 'generate', days_since_last_action = 1, set_only = false } = body;

    const sr = base44.asServiceRole;
    const now = new Date();
    const userTz = user.timezone || 'Asia/Jerusalem';
    const todayStr = now.toLocaleDateString('en-CA', { timeZone: userTz });

    // Compute the simulated "last action date" = today minus N days
    const simulatedLastDate = new Date(now);
    simulatedLastDate.setDate(simulatedLastDate.getDate() - days_since_last_action);
    const simulatedLastDateStr = simulatedLastDate.toLocaleDateString('en-CA', { timeZone: userTz });

    // Fetch existing streak state
    const existing = await sr.entities.StreakState.filter({ user_id: user.id });
    let streak = existing[0];

    if (!streak) {
      // Create a fresh one starting from the simulated last date
      streak = await sr.entities.StreakState.create({
        user_id: user.id,
        current_streak_days: 3,
        longest_streak_days: 3,
        streak_status: 'active',
        user_timezone: userTz,
        pending_break_popup: false,
        last_streak_action_date_local: simulatedLastDateStr,
        last_streak_action_at: simulatedLastDate.toISOString(),
      });
    } else {
      // Patch the last action date to simulate N days ago
      await sr.entities.StreakState.update(streak.id, {
        last_streak_action_date_local: simulatedLastDateStr,
        last_streak_action_at: simulatedLastDate.toISOString(),
        streak_status: days_since_last_action > 1 ? 'broken' : 'active',
        pending_break_popup: days_since_last_action > 1,
        updated_at: now.toISOString(),
      });
      streak.last_streak_action_date_local = simulatedLastDateStr;
      streak.streak_status = days_since_last_action > 1 ? 'broken' : 'active';
      streak.pending_break_popup = days_since_last_action > 1;
    }

    const debugBefore = {
      current_streak_days: streak.current_streak_days,
      last_streak_action_date_local: simulatedLastDateStr,
      streak_status: streak.streak_status,
      pending_break_popup: streak.pending_break_popup,
    };

    console.log(`[debugStreakSimulate] BEFORE: user=${user.id} simulated_last_action=${simulatedLastDateStr} today=${todayStr} days_gap=${days_since_last_action} set_only=${set_only}`);
    console.log(`[debugStreakSimulate] BEFORE state:`, JSON.stringify(debugBefore));

    // set_only = true: ONLY patch the date, don't compute a new streak value.
    // Use this to "prime" the state so the browser's triggerProof() does the real increment.
    if (set_only) {
      return Response.json({
        ok: true,
        mode: 'set_only',
        primed: {
          last_streak_action_date_local: simulatedLastDateStr,
          current_streak_days: streak.current_streak_days,
          streak_status: streak.streak_status,
        },
        message: `State primed. last_action_date set to ${simulatedLastDateStr} (${days_since_last_action} day(s) ago). Call window.__streakManager.triggerProof() on Home page to fire the real increment.`,
      });
    }

    // Now recompute exactly as updateStreakAction does
    const lastDate = new Date(simulatedLastDateStr);
    const today = new Date(todayStr);
    const daysDiff = Math.floor((today.getTime() - lastDate.getTime()) / (1000 * 60 * 60 * 24));

    let newStreakDays = streak.current_streak_days || 1;
    let newStatus = streak.streak_status || 'active';
    let newPendingBreak = false;
    let isNewDayIncrement = false;
    let decision = '';

    if (daysDiff === 0) {
      decision = 'SAME_DAY_NO_INCREMENT';
    } else if (daysDiff === 1) {
      newStreakDays = (streak.current_streak_days || 0) + 1;
      newStatus = 'active';
      newPendingBreak = false;
      isNewDayIncrement = true;
      decision = 'NEXT_DAY_INCREMENT';
    } else if (daysDiff > 1) {
      newStreakDays = 1;
      newStatus = 'restored';
      newPendingBreak = false;
      isNewDayIncrement = true;
      decision = `STREAK_BROKEN_RESET (gap=${daysDiff} days)`;
    }

    // Save result
    await sr.entities.StreakState.update(streak.id, {
      current_streak_days: newStreakDays,
      longest_streak_days: Math.max(newStreakDays, streak.longest_streak_days || 0),
      last_streak_action_at: now.toISOString(),
      last_streak_action_date_local: todayStr,
      streak_status: newStatus,
      pending_break_popup: newPendingBreak,
      updated_at: now.toISOString(),
    });

    const debugAfter = {
      current_streak_days: newStreakDays,
      last_streak_action_date_local: todayStr,
      streak_status: newStatus,
      pending_break_popup: newPendingBreak,
      is_new_day_increment: isNewDayIncrement,
    };

    console.log(`[debugStreakSimulate] AFTER: decision=${decision}`, JSON.stringify(debugAfter));

    return Response.json({
      ok: true,
      proof: {
        user_id: user.id,
        user_timezone: userTz,
        today_local: todayStr,
        simulated_last_action_local: simulatedLastDateStr,
        days_gap: daysDiff,
        decision,
        before: debugBefore,
        after: debugAfter,
      },
      streak: debugAfter,
    });

  } catch (error) {
    console.error('[debugStreakSimulate]', error);
    return Response.json({ error: error.message }, { status: 500 });
  }
});

import { createClientFromRequest } from 'npm:@base44/sdk@0.8.20';

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user || user.role !== 'admin') {
      return Response.json({ error: 'Admin only' }, { status: 403 });
    }

    // Get all group members
    let all_members = [];
    try {
      all_members = await base44.entities.GroupMember.list();
    } catch {
      all_members = [];
    }

    if (!all_members || all_members.length === 0) {
      return Response.json({ message: 'No members to dedupe', cleaned: 0 });
    }

    // Group by (group_id, user_id) and find duplicates
    const groups_by_key = {};
    for (const m of all_members) {
      const key = `${m.group_id}:${m.user_id}`;
      if (!groups_by_key[key]) {
        groups_by_key[key] = [];
      }
      groups_by_key[key].push(m);
    }

    // Find and delete duplicates (keep earliest joined_at)
    let deleted_count = 0;
    for (const key in groups_by_key) {
      const dups = groups_by_key[key];
      if (dups.length > 1) {
        // Sort by joined_at ascending to keep the earliest
        dups.sort((a, b) => {
          const aTime = a.joined_at ? new Date(a.joined_at).getTime() : 0;
          const bTime = b.joined_at ? new Date(b.joined_at).getTime() : 0;
          return aTime - bTime;
        });

        // Delete all except the first (earliest)
        for (let i = 1; i < dups.length; i++) {
          try {
            await base44.entities.GroupMember.delete(dups[i].id);
            deleted_count++;
            console.log('[dedupeGroupMembers] deleted duplicate', {
              group_id: dups[i].group_id,
              user_id: dups[i].user_id,
              id: dups[i].id,
            });
          } catch (err) {
            console.warn('[dedupeGroupMembers] failed to delete', dups[i].id, err.message);
          }
        }
      }
    }

    return Response.json({
      success: true,
      message: `Dedupe complete. Deleted ${deleted_count} duplicate members.`,
      deleted: deleted_count,
    });
  } catch (error) {
    console.error('[dedupeGroupMembers]', error.message);
    return Response.json({ error: error.message }, { status: 500 });
  }
});

/**
 * deduplicateFollows — Admin utility to remove duplicate Follow rows
 * that may have been created due to race conditions or bugs.
 * Keeps the most recent row for each (follower_id, followed_id) pair.
 * Admin-only.
 */
import { createClientFromRequest } from 'npm:@base44/sdk@0.8.20';

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user || user.role !== 'admin') {
      return Response.json({ error: 'Admin access required' }, { status: 403 });
    }

    const sr = base44.asServiceRole;
    const allFollows = await sr.entities.Follow.list('-created_date', 5000);

    // Group by canonical pair key
    const pairMap = new Map();
    for (const f of allFollows) {
      const key = `${f.follower_id}::${f.followed_id}`;
      if (!pairMap.has(key)) {
        pairMap.set(key, []);
      }
      pairMap.get(key).push(f);
    }

    let deleted = 0;
    for (const [, rows] of pairMap) {
      if (rows.length > 1) {
        // Sort by created_date desc — keep first (newest), delete the rest
        rows.sort((a, b) => new Date(b.created_date) - new Date(a.created_date));
        const toDelete = rows.slice(1);
        await Promise.all(toDelete.map(f => sr.entities.Follow.delete(f.id).catch(() => {})));
        deleted += toDelete.length;
      }
    }

    console.log(`[deduplicateFollows] Scanned ${allFollows.length} rows, removed ${deleted} duplicates`);
    return Response.json({ success: true, scanned: allFollows.length, deleted });
  } catch (error) {
    console.error('[deduplicateFollows]', error.message);
    return Response.json({ error: error.message }, { status: 500 });
  }
});

/**
 * deduplicateGroupMembers — one-time admin cleanup job.
 * Removes duplicate GroupMember rows and reconciles Group.member_count.
 * ADMIN ONLY.
 */
import { createClientFromRequest } from 'npm:@base44/sdk@0.8.20';

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();

    if (!user || user.role !== 'admin') {
      return Response.json({ error: 'Admin access required' }, { status: 403 });
    }

    const sr = base44.asServiceRole.entities;

    // Fetch all GroupMembers
    const allMembers = await sr.GroupMember.list('-created_date', 10000);

    if (!allMembers || allMembers.length === 0) {
      return Response.json({ success: true, message: 'No members found', duplicates_found: 0, deleted_count: 0 });
    }

    console.log('[deduplicateGroupMembers] Scanning', allMembers.length, 'records');

    // Group by (group_id, user_id)
    const rolePriority = { owner: 3, admin: 2, member: 1 };
    const grouped = {};
    for (const m of allMembers) {
      if (!m.group_id || !m.user_id) continue;
      const key = `${m.group_id}:${m.user_id}`;
      if (!grouped[key]) grouped[key] = [];
      grouped[key].push(m);
    }

    let deletedCount = 0;
    const affectedKeys = [];
    const affectedGroupIds = new Set();

    for (const [key, records] of Object.entries(grouped)) {
      if (records.length <= 1) continue;

      affectedKeys.push(key);
      const groupId = records[0].group_id;
      affectedGroupIds.add(groupId);

      // Sort: highest role first, then earliest created_date as tiebreak
      records.sort((a, b) => {
        const aPriority = rolePriority[a.role] || 1;
        const bPriority = rolePriority[b.role] || 1;
        if (bPriority !== aPriority) return bPriority - aPriority;
        return new Date(a.created_date || 0) - new Date(b.created_date || 0);
      });

      // Keep first, delete rest
      const toDelete = records.slice(1);
      for (const m of toDelete) {
        try {
          await sr.GroupMember.delete(m.id);
          deletedCount++;
          console.log('[deduplicateGroupMembers] Deleted', m.id, 'for key', key);
        } catch (err) {
          console.error('[deduplicateGroupMembers] Failed to delete', m.id, err.message);
        }
      }
    }

    // Reconcile Group.member_count for all affected groups
    const reconciled = [];
    for (const groupId of affectedGroupIds) {
      try {
        const realMembers = await sr.GroupMember.filter({ group_id: groupId }, null, 2000);
        const realCount = realMembers.length;
        await sr.Group.update(groupId, { member_count: realCount });
        reconciled.push({ groupId, member_count: realCount });
        console.log('[deduplicateGroupMembers] Reconciled group', groupId, 'count=', realCount);
      } catch (err) {
        console.error('[deduplicateGroupMembers] Failed to reconcile group', groupId, err.message);
      }
    }

    return Response.json({
      success: true,
      message: 'Deduplication complete',
      total_records: allMembers.length,
      duplicates_found: affectedKeys.length,
      deleted_count: deletedCount,
      affected_keys: affectedKeys,
      reconciled_groups: reconciled,
    });
  } catch (error) {
    console.error('[deduplicateGroupMembers]', error.message);
    return Response.json({ error: error.message }, { status: 500 });
  }
});

/**
 * deduplicatePostLikes — Admin-only one-time cleanup.
 * Finds and removes duplicate PostLike and GroupPostLike records (same user, same post),
 * then recomputes like_count for every affected Post and GroupPost from unique truth.
 *
 * SAFE: only removes extras — one valid like per user/post is preserved.
 * Run once from dashboard -> code -> functions -> deduplicatePostLikes.
 */
import { createClientFromRequest } from 'npm:@base44/sdk@0.8.20';

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (user?.role !== 'admin') {
      return Response.json({ error: 'Forbidden: Admin only' }, { status: 403 });
    }

    const sr = base44.asServiceRole.entities;
    const report = { postLikes: {}, groupPostLikes: {} };

    // ── 1. Deduplicate PostLike ──────────────────────────────────────────────
    const allPostLikes = await sr.PostLike.list('-created_date', 2000);

    // Group by (post_id, user_id)
    const postLikeMap = new Map();
    for (const like of allPostLikes) {
      const key = `${like.post_id}::${like.user_id}`;
      if (!postLikeMap.has(key)) postLikeMap.set(key, []);
      postLikeMap.get(key).push(like);
    }

    let postDupsDeleted = 0;
    const affectedPostIds = new Set();
    for (const [, records] of postLikeMap) {
      if (records.length > 1) {
        // Keep oldest (smallest created_date), delete the rest
        records.sort((a, b) => new Date(a.created_date) - new Date(b.created_date));
        const toDelete = records.slice(1);
        for (const dup of toDelete) {
          await sr.PostLike.delete(dup.id);
          postDupsDeleted++;
        }
        affectedPostIds.add(records[0].post_id);
      }
    }

    // Recount all affected Posts from unique truth
    let postCountsFixed = 0;
    for (const postId of affectedPostIds) {
      const likes = await sr.PostLike.filter({ post_id: postId });
      const uniqueCount = new Set(likes.map(l => l.user_id)).size;
      await sr.Post.update(postId, { like_count: uniqueCount });
      postCountsFixed++;
    }

    report.postLikes = { duplicatesDeleted: postDupsDeleted, countsRecomputed: postCountsFixed };

    // ── 2. Deduplicate GroupPostLike ────────────────────────────────────────
    const allGroupLikes = await sr.GroupPostLike.list('-created_date', 2000);

    const groupLikeMap = new Map();
    for (const like of allGroupLikes) {
      const key = `${like.group_post_id}::${like.user_id}`;
      if (!groupLikeMap.has(key)) groupLikeMap.set(key, []);
      groupLikeMap.get(key).push(like);
    }

    let groupDupsDeleted = 0;
    const affectedGroupPostIds = new Set();
    for (const [, records] of groupLikeMap) {
      if (records.length > 1) {
        records.sort((a, b) => new Date(a.created_date) - new Date(b.created_date));
        const toDelete = records.slice(1);
        for (const dup of toDelete) {
          await sr.GroupPostLike.delete(dup.id);
          groupDupsDeleted++;
        }
        affectedGroupPostIds.add(records[0].group_post_id);
      }
    }

    // Recount all affected GroupPosts from unique truth
    let groupCountsFixed = 0;
    for (const postId of affectedGroupPostIds) {
      const likes = await sr.GroupPostLike.filter({ group_post_id: postId });
      const uniqueCount = new Set(likes.map(l => l.user_id)).size;
      await sr.GroupPost.update(postId, { like_count: uniqueCount });
      groupCountsFixed++;
    }

