    return Response.json({ error: error.message }, { status: 500 });
  }
});

/**
 * deduplicateReviews — admin-only one-time cleanup.
 * For each (recipe_id + created_by) combo that has more than 1 review,
 * keeps the OLDEST one and deletes all newer duplicates.
 * Also recomputes recipe aggregates after cleanup.
 */
import { createClientFromRequest } from 'npm:@base44/sdk@0.8.23';

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (user?.role !== 'admin') {
      return Response.json({ error: 'Admin only' }, { status: 403 });
    }

    const sr = base44.asServiceRole;

    // Fetch all reviews
    const allReviews = await sr.entities.RecipeReview.list('-created_date', 500);

    // Group by recipe_id + created_by
    const grouped = {};
    for (const r of allReviews) {
      const key = `${r.recipe_id}::${r.created_by}`;
      if (!grouped[key]) grouped[key] = [];
      grouped[key].push(r);
    }

    const deleted = [];
    const affectedRecipes = new Set();

    for (const [key, reviews] of Object.entries(grouped)) {
      if (reviews.length <= 1) continue;

      // Sort oldest first — keep index 0, delete the rest
      reviews.sort((a, b) => new Date(a.created_date) - new Date(b.created_date));
      const toDelete = reviews.slice(1);

      for (const r of toDelete) {
        await sr.entities.RecipeReview.delete(r.id);
        deleted.push({ id: r.id, recipe_id: r.recipe_id, created_by: r.created_by });
        affectedRecipes.add(r.recipe_id);
      }
    }

    // Recompute aggregates for affected recipes
    const recomputed = [];
    for (const recipeId of affectedRecipes) {
      const remaining = await sr.entities.RecipeReview.filter({ recipe_id: recipeId });
      const count = remaining.length;
      const avg = count > 0
        ? remaining.reduce((sum, r) => sum + (r.rating || 0), 0) / count
        : 0;
      await sr.entities.Recipe.update(recipeId, {
        review_count: count,
        avg_rating: Math.round(avg * 10) / 10,
      });
      recomputed.push(recipeId);
    }

    return Response.json({
      ok: true,
      deleted_count: deleted.length,
      deleted,
      recomputed_recipes: recomputed,
    });

  } catch (err) {
    return Response.json({ error: err.message }, { status: 500 });
  }
});

/**
 * deleteAccount — HARD-DELETE ALL USER DATA + SHOPS
 *
 * This is the authoritative deletion endpoint. It:
 * 1. Validates the user is authenticated (server-side only, never trust client)
 * 2. Deletes ALL user-owned entities (recipes, posts, shops, groups, messages, etc)
 * 3. Removes user from all group memberships
 * 4. Anonymizes any references (comments, reports) where needed
 * 5. Resets the User profile to default state (but keeps auth record)
 * 6. Creates a DeletedUser tombstone to prevent resurrection
 * 7. Returns { ok: true } ONLY if everything succeeded
 *
 * CRITICAL: Shops are deleted, not archived. If a shop comes back, it's a bug.
 */
import { createClientFromRequest } from 'npm:@base44/sdk@0.8.25';

async function sha256hex(str) {
  const buf = await crypto.subtle.digest('SHA-256', new TextEncoder().encode(str));
  return Array.from(new Uint8Array(buf)).map(b => b.toString(16).padStart(2, '0')).join('');
}

async function deleteAll(entityApi, records) {
  if (!records?.length) return 0;
  let deleted = 0;
  for (const r of records) {
    try {
      await entityApi.delete(r.id);
      deleted++;
    } catch (err) {
      console.warn(`[DELETE_ACCOUNT] Failed to delete ${entityApi.constructor.name} ${r.id}:`, err.message);
    }
  }
  return deleted;
}

async function safeFilter(entityApi, filter, limit = 500) {
  try {
    return await entityApi.filter(filter, '-created_date', limit);
  } catch (err) {
    console.warn(`[DELETE_ACCOUNT] Filter failed for ${entityApi.constructor.name}:`, err.message);
    return [];
  }
}

async function audit(entityApi, filter, entityName) {
  try {
    const remaining = await entityApi.filter(filter, '-created_date', 1);
    if (remaining.length > 0) {
      console.error(`[DELETE_ACCOUNT] AUDIT FAILED: ${entityName} still has records`);
      return false;
    }
    return true;
  } catch (err) {
    console.warn(`[DELETE_ACCOUNT] Audit check failed for ${entityName}`);
    return true; // Non-fatal
  }
}

