/**
 * deleteDirectMessage — delete a DM.
 * mode: 'for_me' hides it from your side only. 'for_all' hard-deletes (sender only).
 */
import { createClientFromRequest } from 'npm:@base44/sdk@0.8.20';

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user?.id) return Response.json({ error: 'Unauthorized' }, { status: 401 });

    const { message_id, mode = 'for_me' } = await req.json().catch(() => ({}));
    if (!message_id) return Response.json({ error: 'message_id required' }, { status: 400 });

    const sr = base44.asServiceRole.entities;
    const messages = await sr.Message.filter({ id: message_id });
    const msg = messages[0];
    if (!msg) return Response.json({ error: 'Not found' }, { status: 404 });

    const isSender = msg.sender_id === user.id;
    const isRecipient = msg.recipient_id === user.id;
    if (!isSender && !isRecipient) return Response.json({ error: 'Forbidden' }, { status: 403 });

    if (mode === 'for_all') {
      if (!isSender) return Response.json({ error: 'Only sender can delete for everyone' }, { status: 403 });
      await sr.Message.delete(message_id);
    } else {
      // Delete for me only
      if (isSender) await sr.Message.update(message_id, { deleted_for_sender: true });
      else await sr.Message.update(message_id, { deleted_for_recipient: true });
    }

    return Response.json({ ok: true });
  } catch (err) {
    console.error('[deleteDirectMessage]', err.message);
    return Response.json({ error: err.message }, { status: 500 });
  }
});

