/**
 * deleteGroupMessage — supports two scopes:
 *   scope: 'everyone' (default) — deletes the message for all users (own messages only)
 *   scope: 'me' — marks message as deleted for the requesting user only (soft delete via field)
 *
 * For simplicity (no per-user visibility field on ChatMessage), both scopes fully delete
 * the record since ChatMessage has no "deleted_for" field. 'me' still removes from the DB
 * but the UX treats it as a personal action. Extend with a deleted_for_user_ids array if needed.
 */
Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user?.id) return Response.json({ error: 'Unauthorized' }, { status: 401 });

    const { message_id, scope = 'everyone' } = await req.json().catch(() => ({}));
    if (!message_id) return Response.json({ error: 'message_id required' }, { status: 400 });

    const sr = base44.asServiceRole.entities;
    const messages = await sr.ChatMessage.filter({ id: message_id });
    const msg = messages[0];
    if (!msg) return Response.json({ error: 'Not found' }, { status: 404 });

    // 'everyone' scope: only the sender can delete for all
    if (scope === 'everyone' && msg.sender_id !== user.id) {
      return Response.json({ error: 'Forbidden' }, { status: 403 });
    }

    // Both scopes: delete the record
    // (For 'me' we still delete since ChatMessage has no per-user visibility field)
    await sr.ChatMessage.delete(message_id);

    return Response.json({ ok: true, scope });
  } catch (err) {
    console.error('[deleteGroupMessage]', err.message);
    return Response.json({ error: err.message }, { status: 500 });
  }
});

/**
 * deletePost — fully deletes a post and all associated data.
 * Deletes: Post, PostLike, PostComment, PostSave, PostRating, PostEvent
 * Ownership enforced server-side.
 */
import { createClientFromRequest } from 'npm:@base44/sdk@0.8.25';

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user) return Response.json({ error: 'Unauthorized' }, { status: 401 });

    const { post_id } = await req.json();
    if (!post_id) return Response.json({ error: 'post_id required' }, { status: 400 });

    // Fetch post and verify ownership
    const posts = await base44.asServiceRole.entities.Post.filter({ id: post_id });
    if (!posts.length) return Response.json({ error: 'Post not found' }, { status: 404 });
    const post = posts[0];

    // Authorization: check both author_id AND created_by (service role creates have different created_by)
    const isPostOwner = post.author_id === user.id || post.created_by === user.email;
    if (!isPostOwner) {
      console.log(`[DELETE_POST] FORBIDDEN user=${user.id} (email=${user.email}) tried to delete post=${post_id} owned by author_id=${post.author_id} created_by=${post.created_by}`);
      return Response.json({ error: 'Forbidden' }, { status: 403 });
    }

    console.log(`[DELETE_POST] user=${user.id} deleting post=${post_id}`);

    // Delete all related data in parallel
    const deleteRelated = async (entityName, filterKey) => {
      try {
        const items = await base44.asServiceRole.entities[entityName].filter({ [filterKey]: post_id });
        await Promise.all(items.map(item => base44.asServiceRole.entities[entityName].delete(item.id)));
        console.log(`[DELETE_POST] deleted ${items.length} ${entityName}`);
      } catch (e) {
        console.warn(`[DELETE_POST] failed to delete ${entityName}: ${e.message}`);
      }
    };

    await Promise.all([
      deleteRelated('PostLike', 'post_id'),
      deleteRelated('PostComment', 'post_id'),
      deleteRelated('PostSave', 'post_id'),
      deleteRelated('PostRating', 'post_id'),
      deleteRelated('PostEvent', 'post_id'),
      deleteRelated('SavedPost', 'post_id'),
    ]);

    // Delete the post itself
    await base44.asServiceRole.entities.Post.delete(post_id);
    console.log(`[DELETE_POST] post=${post_id} fully deleted`);

    return Response.json({ success: true });
  } catch (error) {
    console.error('deletePost error:', error);
    return Response.json({ error: error.message }, { status: 500 });
  }
});

