    if (!post_id) return Response.json({ error: 'post_id required' }, { status: 400 });

    const sr = base44.asServiceRole;

    // Fetch the post to verify ownership
    const posts = await sr.entities.Post.filter({ id: post_id });
    if (!posts[0]) return Response.json({ error: 'Post not found' }, { status: 404 });
    const post = posts[0];

    // Only owner can delete
    if (post.author_id !== user.id) {
      return Response.json({ error: 'Only post owner can delete' }, { status: 403 });
    }

    // Delete the post (soft-delete via moderation_status if applicable, or hard-delete)
    // For now, hard-delete to clean up the system completely
    await sr.entities.Post.delete(post_id);

    // Also delete linked Recipe if it exists and is owned by this user
    if (post.recipe_id) {
      try {
        const recipes = await sr.entities.Recipe.filter({ id: post.recipe_id });
        if (recipes[0] && recipes[0].author_id === user.id) {
          await sr.entities.Recipe.delete(post.recipe_id);
        }
      } catch (e) {
        console.warn('[deletePostWithAppeal] recipe delete failed:', e.message);
      }
    }

    // Cleanup: remove any ModerationLog entries for this post
    try {
      const logs = await sr.entities.ModerationLog.filter({ target_id: post_id, target_type: 'post' }, null, 100);
      for (const log of logs) {
        await sr.entities.ModerationLog.delete(log.id).catch(() => {});
      }
    } catch (e) {
      console.warn('[deletePostWithAppeal] log cleanup failed:', e.message);
    }

    console.log('[deletePostWithAppeal] SUCCESS postId=' + post_id + ' userId=' + user.id);
    return Response.json({ ok: true, post_id });
  } catch (error) {
    console.error('[deletePostWithAppeal] error:', error);
    return Response.json({ error: error.message }, { status: 500 });
  }
});

import { createClientFromRequest } from 'npm:@base44/sdk@0.8.25';

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user) return Response.json({ error: 'Unauthorized' }, { status: 401 });

    const { recipeId } = await req.json();
    if (!recipeId) return Response.json({ error: 'recipeId required' }, { status: 400 });

    // Fetch recipe to verify ownership
    let recipe;
    try {
      const recipes = await base44.asServiceRole.entities.Recipe.filter({ id: recipeId });
      if (!recipes.length) return Response.json({ error: 'Recipe not found' }, { status: 404 });
      recipe = recipes[0];
    } catch (fetchErr) {
      console.error('[RECIPE_DELETE] Failed to fetch recipe:', fetchErr.message);
      return Response.json({ error: 'Recipe not found or invalid ID' }, { status: 404 });
    }

    // Authorization: only owner can delete (check both created_by email AND author_id)
    const isOwner = recipe.created_by === user.email || recipe.author_id === user.id;
    if (!isOwner) {
      console.warn(`[RECIPE_DELETE] FORBIDDEN: user=${user.email} (id=${user.id}) tried to delete recipe=${recipeId} owned by ${recipe.created_by} (author_id=${recipe.author_id})`);
      return Response.json({ error: 'Forbidden: only owner can delete' }, { status: 403 });
    }

    // Cascade cleanup — delete all linked entities in parallel (non-fatal)
    const cleanup = async (entityName, filterObj, label) => {
      try {
        const items = await base44.asServiceRole.entities[entityName].filter(filterObj);
        for (const item of items) {
          await base44.asServiceRole.entities[entityName].delete(item.id);
        }
        if (items.length > 0) console.log(`[RECIPE_DELETE] cleaned ${items.length} ${label}`);
      } catch (err) {
        console.warn(`[RECIPE_DELETE] ${label} cleanup failed (non-fatal): ${err.message}`);
      }
    };

    // Delete linked Post entities first so feeds don't show orphan cards
    let deletedPostIds = [];
    try {
      const posts = await base44.asServiceRole.entities.Post.filter({ recipe_id: recipeId });
      for (const post of posts) {
        // Also clean up post engagement data
        const postCleanup = async (entityName, key) => {
          try {
            const items = await base44.asServiceRole.entities[entityName].filter({ [key]: post.id });
            for (const item of items) await base44.asServiceRole.entities[entityName].delete(item.id);
          } catch {}
        };
        await Promise.all([
          postCleanup('PostLike', 'post_id'),
          postCleanup('PostComment', 'post_id'),
          postCleanup('PostSave', 'post_id'),
          postCleanup('PostRating', 'post_id'),
          postCleanup('PostEvent', 'post_id'),
          postCleanup('SavedPost', 'post_id'),
        ]);
        await base44.asServiceRole.entities.Post.delete(post.id);
        deletedPostIds.push(post.id);
      }
      if (posts.length > 0) console.log(`[RECIPE_DELETE] cleaned ${posts.length} Post(s) + engagement data`);
    } catch (err) {
      console.warn(`[RECIPE_DELETE] Post cleanup failed (non-fatal): ${err.message}`);
    }

    // Delete linked engagement entities
    await Promise.all([
      cleanup('Like', { target_id: recipeId, target_type: 'recipe' }, 'Like'),
      cleanup('RecipeLike', { recipe_id: recipeId }, 'RecipeLike'),
      cleanup('RecipeSave', { recipe_id: recipeId }, 'RecipeSave'),
      cleanup('RecipeReview', { recipe_id: recipeId }, 'RecipeReview'),
      cleanup('PostComment', { post_id: recipeId }, 'PostComment'),
      cleanup('ShopAvailableRecipe', { recipe_id: recipeId }, 'ShopAvailableRecipe'),
      cleanup('ShopCategoryRecipe', { recipe_id: recipeId }, 'ShopCategoryRecipe'),
      cleanup('ShoppingList', { recipe_id: recipeId }, 'ShoppingList'),
    ]);

    // Delete recipe (source of truth)
    await base44.asServiceRole.entities.Recipe.delete(recipeId);
    console.log(`[DELETE_WRITE_TRACE] entityType=Recipe entityId=${recipeId} backendRemovedState=hard_deleted`);
    console.log(`[RECIPE_DELETE] user=${user.email} recipe=${recipeId} title="${recipe.title}"`);

    return Response.json({ success: true, deleted_recipe_id: recipeId, deleted_post_ids: deletedPostIds, message: 'Recipe deleted' });
  } catch (error) {
    console.error('deleteRecipe error:', error);
    return Response.json({ error: error.message }, { status: 500 });
  }
});

/**
 * deleteShopsOnAccountDelete — Delete all shops when account is deleted.
 * Runs within deleteAccount function via service role.
 * Ensures no orphaned shops remain.
 */
import { createClientFromRequest } from 'npm:@base44/sdk@0.8.20';

export async function deleteUserShops(base44, user_id) {
  try {
    // Find all shops owned by user
    const shops = await base44.asServiceRole.entities.Shop.filter({ owner_id: user_id });

    for (const shop of shops) {
      // Delete assets
      const assets = await base44.asServiceRole.entities.ShopAsset.filter({ owner_id: user_id });
      await Promise.all(assets.map(a => 
        base44.asServiceRole.entities.ShopAsset.delete(a.id).catch(() => {})
      ));

      // Delete analytics
      const analytics = await base44.asServiceRole.entities.ShopAnalyticsDaily.filter({ shop_id: shop.id });
      await Promise.all(analytics.map(a => 
        base44.asServiceRole.entities.ShopAnalyticsDaily.delete(a.id).catch(() => {})
      ));

      // Delete shop
      await base44.asServiceRole.entities.Shop.delete(shop.id);
    }

    console.log(`[DELETE_SHOPS] Deleted ${shops.length} shops for user=${user_id}`);
    return shops.length;
  } catch (error) {
    console.error('[DELETE_SHOPS_ERROR]', error.message);
    throw error;
  }
}

