import { createClientFromRequest } from 'npm:@base44/sdk@0.8.20';
import nodemailer from 'npm:nodemailer@6.9.7';

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const { reportId, recipeId, recipeName, reporterId, reporterName, reporterEmail, ownerId, reason, details } = await req.json();

    const reasonLabels = {
      spam_scam: 'Spam / Scam',
      nudity_sexual: 'Nudity / Sexual content',
      hate_harassment: 'Hate / Harassment',
      dangerous_illegal: 'Dangerous / Illegal',
      copyright_stolen: 'Copyright / Stolen content',
      misinformation: 'Misinformation',
      other: 'Other',
    };

    const SMTP_HOST = Deno.env.get('SMTP_HOST');
    const SMTP_PORT = parseInt(Deno.env.get('SMTP_PORT') || '587', 10);
    const SMTP_USER = Deno.env.get('SMTP_USER');
    const SMTP_PASS = Deno.env.get('SMTP_PASS');
    const SMTP_FROM = Deno.env.get('SMTP_FROM') || 'Reciply Support <support@reciplyai.app>';
    const SUPPORT_EMAIL_TO = Deno.env.get('SUPPORT_EMAIL_TO') || 'support@reciplyai.app';

    if (!SMTP_HOST || !SMTP_USER || !SMTP_PASS) {
      console.error('SMTP configuration incomplete');
      return Response.json({ error: 'Email service not configured' }, { status: 503 });
    }

    const transporter = nodemailer.createTransport({
      host: SMTP_HOST,
      port: SMTP_PORT,
      secure: false,
      auth: {
        user: SMTP_USER,
        pass: SMTP_PASS,
      },
    });

    const emailBody = `
Recipe Report Submitted

Recipe: ${recipeName}
Report Reason: ${reasonLabels[reason] || reason}
Reporter: ${reporterName} (${reporterEmail})
Details: ${details || '(no additional details)'}

Report ID: ${reportId}
Status: Open - Review and take action
    `;

    const htmlBody = `
      <h2>Recipe Report Submitted</h2>
      <p><strong>Recipe:</strong> ${recipeName}</p>
      <p><strong>Report Reason:</strong> ${reasonLabels[reason] || reason}</p>
      <p><strong>Reporter:</strong> ${reporterName} (${reporterEmail})</p>
      <p><strong>Details:</strong></p>
      <p>${details || '(no additional details)'}</p>
      <p><strong>Report ID:</strong> ${reportId}</p>
      <p><em>Status: Open - Review and take action</em></p>
    `;

    try {
      await transporter.sendMail({
        from: SMTP_FROM,
        to: SUPPORT_EMAIL_TO,
        replyTo: reporterEmail,
        subject: `Reciply Support: Recipe Report - ${recipeName}`,
        text: emailBody,
        html: htmlBody,
        headers: {
          'X-Report-ID': reportId,
          'X-Recipe-ID': recipeId,
          'X-Reporter-ID': reporterId,
        },
      });

      await base44.asServiceRole.entities.RecipeReport.update(reportId, {
        delivery_status: 'sent',
        delivery_method: 'email',
      });

      console.log('Report email sent:', reportId);
      return Response.json({ success: true, method: 'email' });
    } catch (emailError) {
      console.error('Email delivery failed:', emailError.message);
      throw emailError;
    }
  } catch (error) {
    console.error('deliverReport error:', error);
    return Response.json({ error: error.message }, { status: 500 });
  }
});

