/**
 * downgradeExpiredSubscription
 *
 * Called when a subscription fully expires (trial ended, payment failed, cancelled past period).
 * Privates all community posts and shop content. Does NOT delete anything.
 * Caps free-tier generation quota per spec:
 *   - if remaining >= 2 → set to 2
 *   - if remaining == 1 → keep 1
 *   - if remaining == 0 → keep 0
 *
 * Idempotent — safe to call multiple times.
 * Logs every action for audit trail.
 *
 * Groups created by user are NOT deleted — they remain accessible.
 */
import { createClientFromRequest } from 'npm:@base44/sdk@0.8.25';

const FREE_WEEKLY_LIMIT = 2;

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user) return Response.json({ error: 'Unauthorized' }, { status: 401 });

    const sr = base44.asServiceRole;
    const now = new Date();

    // ── 1. Verify subscription is truly expired ─────────────────────────────
    const subs = await sr.entities.Subscription.filter({ created_by: user.email }).catch(() => []);
    const ENTITLED_PLAN_TYPES = new Set(['pro', 'vip', 'trial']);
    const ENTITLED_STATUSES = new Set(['active', 'active_paid', 'trialing', 'grace_period']);

    const activeSub = subs.find(s => {
      if (!ENTITLED_PLAN_TYPES.has(s.plan_type)) return false;
      if (ENTITLED_STATUSES.has(s.status)) return true;
      // Still within billing period even if cancelled
      if (s.status === 'canceled' || s.status === 'canceled_pending_expiry') {
        const cpEnd = s.current_period_end ? new Date(s.current_period_end).getTime() : 0;
        if (cpEnd > now.getTime()) return true;
      }
      return false;
    });

    if (activeSub) {
      // User still has valid entitlement — do nothing
      return Response.json({
        skipped: true,
        reason: 'subscription_still_active',
        plan: activeSub.plan_type,
        status: activeSub.status,
      });
    }

    // ── 2. Private all community posts (but not delete) ─────────────────────
    const userPosts = await sr.entities.Post.filter(
      { author_id: user.id, community_visible: true },
      null,
      500
    ).catch(() => []);

    let postsPrivated = 0;
    for (const post of userPosts) {
      await sr.entities.Post.update(post.id, {
        community_visible: false,
        personal_profile_visible: false,
      }).catch(() => {});
      postsPrivated++;
    }

    // ── 3. Private the shop ─────────────────────────────────────────────────
    const shops = await sr.entities.Shop.filter({ owner_id: user.id }).catch(() => []);
    let shopPrivated = false;
    for (const shop of shops) {
      if (shop.is_public !== false) {
        await sr.entities.Shop.update(shop.id, { is_public: false }).catch(() => {});
        shopPrivated = true;
      }
    }

    // ── 4. Private all shop posts ───────────────────────────────────────────
    const shopPosts = await sr.entities.Post.filter(
      { author_id: user.id, type: 'shop' },
      null,
      500
    ).catch(() => []);
    for (const post of shopPosts) {
      await sr.entities.Post.update(post.id, {
        community_visible: false,
        shop_visible: false,
      }).catch(() => {});
    }

    // ── 5. Private public recipes ───────────────────────────────────────────
    const publicRecipes = await sr.entities.Recipe.filter(
      { author_id: user.id, is_public: true },
      null,
      500
    ).catch(() => []);
    for (const recipe of publicRecipes) {
      await sr.entities.Recipe.update(recipe.id, {
        is_public: false,
        community_visible: false,
      }).catch(() => {});
    }

    // ── 6. Cap generation quota for free tier ───────────────────────────────
    // Find current week's AiGenerationQuota
    const dayOfWeek = now.getUTCDay();
    const daysToSubtract = dayOfWeek === 0 ? 6 : dayOfWeek - 1;
    const periodStart = new Date(now);
    periodStart.setUTCDate(periodStart.getUTCDate() - daysToSubtract);
    periodStart.setUTCHours(0, 0, 0, 0);
    const periodStartISO = periodStart.toISOString();

    let quotaCapped = false;
    let quotaDetails = {};
    const quotas = await sr.entities.AiGenerationQuota.filter(
      { user_id: user.id, period_start: periodStartISO },
      null, 1
    ).catch(() => []);

    if (quotas.length > 0) {
      const q = quotas[0];
      const currentUsed = q.used || 0;
      const currentRemaining = Math.max(0, (q.limit || FREE_WEEKLY_LIMIT) - currentUsed);

      // Cap: if remaining >= 2 → set used so remaining = 2
      // if remaining == 1 → keep
      // if remaining == 0 → keep
      let newUsed = currentUsed;
      if (currentRemaining > FREE_WEEKLY_LIMIT) {
        // Pro had unlimited — now cap to 2 remaining
        newUsed = Math.max(0, FREE_WEEKLY_LIMIT - FREE_WEEKLY_LIMIT); // = 0, remaining = 2
      }

      await sr.entities.AiGenerationQuota.update(q.id, {
        limit: FREE_WEEKLY_LIMIT,
        used: newUsed,
        updated_at: now.toISOString(),
      }).catch(() => {});

      quotaCapped = true;
      quotaDetails = { previous_used: currentUsed, new_used: newUsed, new_limit: FREE_WEEKLY_LIMIT, remaining: Math.max(0, FREE_WEEKLY_LIMIT - newUsed) };
    }

    // ── 7. Clear is_pro on user record ──────────────────────────────────────
    await sr.entities.User.update(user.id, { is_pro: false }).catch(() => {});

    // ── 8. Mark all expired subscription records ────────────────────────────
    for (const sub of subs) {
      if (sub.status !== 'expired' && sub.status !== 'free') {
        await sr.entities.Subscription.update(sub.id, { status: 'expired' }).catch(() => {});
      }
    }

    console.log(`[downgradeExpiredSubscription] user=${user.id} postsPrivated=${postsPrivated} shopPrivated=${shopPrivated} recipesPrivated=${publicRecipes.length} quotaCapped=${quotaCapped} timestamp=${now.toISOString()}`);

    return Response.json({
      success: true,
      user_id: user.id,
      entitlement_old: 'pro',
      entitlement_new: 'free',
      posts_privated_count: postsPrivated,
      shop_posts_privated_count: shopPosts.length,
      recipes_privated_count: publicRecipes.length,
      shop_privated: shopPrivated,
      quota_capped: quotaCapped,
      quota_details: quotaDetails,
      timestamp: now.toISOString(),
    });

  } catch (error) {
    console.error('[downgradeExpiredSubscription] error:', error.message);
    return Response.json({ error: error.message }, { status: 500 });
  }
});

