import { createClientFromRequest } from "npm:@base44/sdk@0.8.6";

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();

    if (!user) {
      return Response.json({ error: "Unauthorized" }, { status: 401 });
    }

    const resendKey = Deno.env.get("RESEND_API_KEY");
    const hasResendKey = !!resendKey;

    if (!hasResendKey) {
      return Response.json({
        provider_configured: false,
        provider_working: false,
        missing_secrets: ["RESEND_API_KEY"],
        last_error: "RESEND_API_KEY not found in environment",
      });
    }

    // Test the key with a minimal call (list emails endpoint - read-only check)
    let provider_working = false;
    let lastError = null;

    try {
      const res = await fetch("https://api.resend.com/emails", {
        method: "GET",
        headers: {
          Authorization: `Bearer ${resendKey}`,
        },
      });
      // 200 = works, 405 = method not allowed but key is valid
      if (res.status === 200 || res.status === 405 || res.status === 404) {
        provider_working = true;
      } else if (res.status === 401) {
        lastError = "Invalid API key (401 Unauthorized)";
      } else {
        const body = await res.text();
        lastError = `Status ${res.status}: ${body.slice(0, 100)}`;
      }
    } catch (err) {
      lastError = err.message;
    }

    return Response.json({
      provider_configured: hasResendKey,
      provider_working,
      missing_secrets: [],
      last_error: lastError,
    });
  } catch (error) {
    return Response.json({ error: error.message }, { status: 500 });
  }
});

