 * @param {{ code: string, action: string }} opts
 *   action can be a template key (VERIFY_DELETE) or a purpose string (delete_account)
 * @returns {{ subject, html, text, templateKey }}
 */
export function buildEmail({ code, action }) {
  // Resolve alias
  const templateKey = TEMPLATES[action] ? action : PURPOSE_MAP[action];
  if (!templateKey) throw new Error(`Unknown email action: ${action}`);

  const tpl = TEMPLATES[templateKey];
  return {
    subject: tpl.subject,
    html: buildHtml({ title: tpl.title, description: tpl.description, code, footerNote: tpl.footerNote, templateKey }),
    text: buildText({ title: tpl.title, description: tpl.description, code, footerNote: tpl.footerNote, templateKey }),
    templateKey,
  };
}

