/**
 * Enrich a batch of ingredients with real nutrition data from APIs.
 * Called in background to populate IngredientCache.
 * USDA → Spoonacular fallback per ingredient.
 */
import { createClientFromRequest } from "npm:@base44/sdk@0.8.6";

const USDA_API_KEY = Deno.env.get("USDA_API_KEY");
const SPOONACULAR_API_KEY = Deno.env.get("SPOONACULAR_API_KEY");

async function fetchUSDA(name) {
  if (!USDA_API_KEY) return null;
  try {
    const res = await fetch(
      `https://api.nal.usda.gov/fdc/v1/foods/search?query=${encodeURIComponent(name)}&pageSize=1&dataType=Foundation,SR%20Legacy&api_key=${USDA_API_KEY}`
    );
    if (!res.ok) return null;
    const data = await res.json();
    if (!data.foods?.length) return null;
    const food = data.foods[0];
    const n = food.foodNutrients || [];
    const get = (id) => n.find(x => x.nutrientId === id)?.value || 0;
    const cal = get(1008);
    if (!cal) return null;
    return { calories: cal, protein: get(1003), carbs: get(1005), fat: get(1004) };
  } catch { return null; }
}

async function fetchSpoonacular(name) {
  if (!SPOONACULAR_API_KEY) return null;
  try {
    const sRes = await fetch(
      `https://api.spoonacular.com/food/ingredients/search?query=${encodeURIComponent(name)}&number=1&apiKey=${SPOONACULAR_API_KEY}`
    );
    if (!sRes.ok) return null;
    const sData = await sRes.json();
    if (!sData.results?.length) return null;
    const iRes = await fetch(
      `https://api.spoonacular.com/food/ingredients/${sData.results[0].id}/information?amount=100&unit=g&apiKey=${SPOONACULAR_API_KEY}`
    );
    if (!iRes.ok) return null;
    const info = await iRes.json();
    const getN = (label) => info.nutrition?.nutrients?.find(n => n.name === label)?.amount || 0;
    const cal = getN("Calories");
    if (!cal) return null;
    return { calories: cal, protein: getN("Protein"), carbs: getN("Carbohydrates"), fat: getN("Fat") };
  } catch { return null; }
}

const iconMap = {
  vegetables: "🥦", fruits: "🍎", proteins: "🍗", dairy: "🥛",
  grains: "🌾", spices: "🌶️", oils_sauces: "🫒", other: "🍲",
};

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user) return Response.json({ error: "Unauthorized" }, { status: 401 });

    const body = await req.json();
    const { ingredients = [] } = body;
    if (!ingredients.length) return Response.json([]);

    const results = await Promise.all(
      ingredients.map(async (ing) => {
        let nutrition = await fetchUSDA(ing.name);
        if (!nutrition) nutrition = await fetchSpoonacular(ing.name);
        if (!nutrition) nutrition = { calories: 0, protein: 0, carbs: 0, fat: 0 };

        return {
          name: ing.name,
          normalizedName: (ing.name || "").toLowerCase().trim(),
          category: ing.category || "other",
          icon: iconMap[ing.category] || "🍲",
          nutrition,
          source: nutrition.calories > 0 ? "USDA" : "local",
        };
      })
    );

    return Response.json(results);
  } catch (error) {
    console.error("Enrichment error:", error.message);
    return Response.json({ error: error.message }, { status: 500 });
  }
});

/**
 * entitlementGuard — SINGLE authoritative backend access check.
 * 
 * ALL premium-gated actions MUST call this before proceeding.
 * Returns: { allowed, reason, is_pro, entitlement_source }
 * 
 * Actions: generate_recipe, premium_post, create_group, open_shop, view_analytics
 * 
 * NO BYPASSES. NO STALE CACHE. Backend decides.
 */
import { createClientFromRequest } from 'npm:@base44/sdk@0.8.25';

const OWNER_EMAIL = 'xenodekuu@gmail.com';

const FREE_ALLOWED_ACTIONS = new Set([
  'generate_recipe', // Has its own quota logic
]);

const PRO_ONLY_ACTIONS = new Set([
  'premium_post', 'create_group', 'open_shop', 'view_analytics',
  'pro_feature_access',
]);

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user) return Response.json({ error: 'Unauthorized' }, { status: 401 });

    const body = await req.json();
    const { action } = body;
    if (!action) return Response.json({ error: 'action required' }, { status: 400 });

    const isOwner = user.email === OWNER_EMAIL;

    // Owner always allowed
    if (isOwner) {
      return Response.json({
        allowed: true,
        reason: 'owner_override',
        is_pro: true,
        entitlement_source: 'owner',
        action,
      });
    }

    // Check subscription status (single source of truth)
    const subs = await base44.asServiceRole.entities.Subscription.filter(
      { created_by: user.email }, null, 10
    ).catch(() => []);

    const nowMs = Date.now();
    const ENTITLED_PLAN_TYPES = new Set(['pro', 'vip', 'trial']);
    const ENTITLED_STATUSES = new Set(['active', 'active_paid', 'trialing', 'grace_period']);

    const activeSub = subs.find(s => {
      if (!ENTITLED_PLAN_TYPES.has(s.plan_type)) return false;
      if (ENTITLED_STATUSES.has(s.status)) return true;
      if (s.status === 'canceled' || s.status === 'canceled_pending_expiry') {
        if (s.current_period_end && new Date(s.current_period_end).getTime() > nowMs) return true;
      }
      return false;
    });

    const isPro = !!activeSub;

    // Pro-only actions: block free users
    if (PRO_ONLY_ACTIONS.has(action) && !isPro) {
      return Response.json({
        allowed: false,
        reason: 'pro_required',
        is_pro: false,
        entitlement_source: 'none',
        action,
        upgrade_hint: 'This feature requires a Pro subscription.',
      }, { status: 403 });
    }

    // Free-allowed actions with limits (generate_recipe uses unifiedGenerationQuotaGate separately)
    if (FREE_ALLOWED_ACTIONS.has(action) && !isPro) {
      return Response.json({
        allowed: true,
        reason: 'free_with_limits',
        is_pro: false,
        entitlement_source: 'free_tier',
        action,
      });
    }

    // Pro user — all actions allowed
    if (isPro) {
      return Response.json({
        allowed: true,
        reason: 'pro_subscription',
        is_pro: true,
        entitlement_source: activeSub.payment_provider || 'subscription',
        action,
        plan_type: activeSub.plan_type,
        billing_period: activeSub.billing_period,
      });
    }

    // Unknown action for free user — default deny
    return Response.json({
      allowed: false,
      reason: 'not_entitled',
      is_pro: false,
      entitlement_source: 'none',
      action,
    }, { status: 403 });
  } catch (err) {
    console.error('[entitlementGuard]', err.message);
    return Response.json({ error: err.message }, { status: 500 });
  }
});

/**
 * MANDATORY CONCEPT EXTRACTION FROM USER PROMPT
 * 
 * Extracts required dish structure, proteins, and critical components.
 * Output drives all downstream validation and regeneration.
 */

import { createClientFromRequest } from 'npm:@base44/sdk@0.8.23';

// CONCEPT RULES — what each dish type requires
const CONCEPT_RULES = {
  'burger': {
    requires: ['patty', 'bun'],
    forbidden_omissions: ['patty'],
    description: 'Must have visible burger patty and bun'
  },
  'shawarma': {
    requires: ['shawarma_filling', 'sliced_meat'],
    forbidden_omissions: ['shawarma_filling'],
    description: 'Must have visible shawarma filling or sliced shawarma meat'
  },
  'sandwich': {
    requires: ['bread'],
    forbidden_omissions: ['bread'],
    description: 'Must have bread base'
  },
  'wrap': {
    requires: ['wrap_shell', 'filling'],
    forbidden_omissions: ['wrap_shell'],
    description: 'Must have wrap and filling'
  }
};

// KEYWORD MAPPINGS — user intent → required concepts
const KEYWORD_CONCEPT_MAP = {
  // Proteins/fillings
  'burger': 'burger',
  'hamburger': 'burger',
  'beef burger': 'burger',
  'chicken burger': 'burger',
  'patty': 'patty',

  'shawarma': 'shawarma',
  'doner': 'shawarma',
  'kebab': 'shawarma',
  'sliced meat': 'shawarma_filling',

  // Toppings
  'cheese': 'cheese',
  'melted cheese': 'cheese',
  'cheddar': 'cheese',
  'lettuce': 'lettuce',
  'tomato': 'tomato',
  'onion': 'onion',

  // Structural
  'bread': 'bread',
  'bun': 'bun',
  'pita': 'bread',
  'wrap': 'wrap_shell',
};

function normalizeString(s) {
  return s.toLowerCase().replace(/[^a-z0-9 ]/g, ' ').trim();
}

/**
 * Extract required concepts from user prompt
 * Returns: {
 *   primary_dishes: ['burger', 'shawarma'],
 *   required_proteins: ['patty', 'shawarma_filling'],
 *   required_toppings: ['cheese', 'lettuce'],
 *   required_structural: ['bun'],
 *   forbidden_omissions: ['patty', 'shawarma_filling'],
 *   all_required: [...],
 *   image_requirements: "description of what must be visible"
 * }
 */
function extractConcepts(userPrompt) {
  const normalized = normalizeString(userPrompt);

  const detected = {
    primary_dishes: [],
    required_proteins: [],
    required_toppings: [],
    required_structural: [],
    forbidden_omissions: [],
  };

  // Map keywords to concepts
  for (const [keyword, concept] of Object.entries(KEYWORD_CONCEPT_MAP)) {
    if (normalized.includes(normalizeString(keyword))) {
      // Categorize the concept
      if (['patty', 'shawarma_filling', 'sliced_meat'].includes(concept)) {
        if (!detected.required_proteins.includes(concept)) {
          detected.required_proteins.push(concept);
        }
      } else if (['cheese', 'lettuce', 'tomato', 'onion'].includes(concept)) {
        if (!detected.required_toppings.includes(concept)) {
          detected.required_toppings.push(concept);
        }
      } else if (['bread', 'bun', 'wrap_shell'].includes(concept)) {
        if (!detected.required_structural.includes(concept)) {
          detected.required_structural.push(concept);
        }
      }

      // Check if it's a primary dish type
      if (Object.keys(CONCEPT_RULES).includes(concept)) {
        if (!detected.primary_dishes.includes(concept)) {
          detected.primary_dishes.push(concept);
        }
      }
    }
  }

  // HYBRID RULE: burger + shawarma together = shawarma burger
  // Required: bun + patty + shawarma_filling (+ cheese if requested)
  // The standalone shawarma "no bun" constraint does NOT apply here.
  const isBurger   = detected.primary_dishes.includes('burger');
  const isShawarma = detected.primary_dishes.includes('shawarma');

  if (isBurger && isShawarma) {
    // Override: hybrid dish requires all three structural elements
    detected.required_structural = [...new Set([...detected.required_structural, 'bun'])];
    detected.required_proteins   = [...new Set([...detected.required_proteins, 'patty', 'shawarma_filling'])];
    detected.forbidden_omissions = [...new Set([...detected.forbidden_omissions, 'patty', 'shawarma_filling', 'bun'])];
  } else {
    // Add rule-based requirements for each standalone primary dish
    for (const dish of detected.primary_dishes) {
      const rule = CONCEPT_RULES[dish];
      if (rule) {
        for (const req of rule.requires) {
          if (!detected.required_proteins.includes(req) &&
              !detected.required_structural.includes(req)) {
            detected.required_proteins.push(req);
          }
        }
        for (const forbidden of rule.forbidden_omissions) {
          if (!detected.forbidden_omissions.includes(forbidden)) {
            detected.forbidden_omissions.push(forbidden);
          }
        }
      }
    }
  }

  // Build image requirements description
  const imageReqs = [];
  if (detected.required_proteins.length > 0) {
    imageReqs.push(`visible ${detected.required_proteins.join(' and ')}`);
  }
  if (detected.required_structural.length > 0) {
    imageReqs.push(`visible ${detected.required_structural.join(' and ')}`);
  }
  if (detected.required_toppings.length > 0) {
    imageReqs.push(`visible ${detected.required_toppings.join(', ')}`);
  }

  return {
    primary_dishes: detected.primary_dishes,
    required_proteins: detected.required_proteins,
    required_toppings: detected.required_toppings,
    required_structural: detected.required_structural,
    forbidden_omissions: detected.forbidden_omissions,
    all_required: [
      ...detected.required_proteins,
      ...detected.required_toppings,
      ...detected.required_structural
    ],
    image_requirements: imageReqs.join(', and '),
  };
}

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const { user_prompt } = await req.json();

    if (!user_prompt) {
      return Response.json({ error: 'user_prompt required' }, { status: 400 });
    }

    const concepts = extractConcepts(user_prompt);

    return Response.json({
      success: true,
      concepts,
      debug: {
        prompt_normalized: normalizeString(user_prompt),
      }
    });

  } catch (error) {
    console.error('[extractRequiredConcepts] error:', error.message);
    return Response.json({ error: error.message }, { status: 500 });
  }
});

import { createClientFromRequest } from 'npm:@base44/sdk@0.8.6';

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();

    if (!user) {
      return Response.json({ error: 'Unauthorized' }, { status: 401 });
    }

    const { action, token, device_type, device_name } = await req.json();

    if (action === 'register') {
      if (!token || !device_type) {
        return Response.json({ error: 'Missing token or device_type' }, { status: 400 });
      }

      // Check if token already exists for this user
      const existing = await base44.entities.DeviceToken.filter({
        user_email: user.email,
        token: token,
      });

      if (existing.length > 0) {
        // Update last_used_at
        await base44.entities.DeviceToken.update(existing[0].id, {
          is_active: true,
          last_used_at: new Date().toISOString(),
        });
        return Response.json({ success: true, message: 'Token updated' });
      }

      // Create new device token
      await base44.entities.DeviceToken.create({
        user_email: user.email,
        token: token,
        device_type: device_type,
        device_name: device_name || `${device_type} device`,
        is_active: true,
        last_used_at: new Date().toISOString(),
      });

      return Response.json({ success: true, message: 'Token registered' });
    }

    if (action === 'unregister') {
      if (!token) {
        return Response.json({ error: 'Missing token' }, { status: 400 });
      }

      const existing = await base44.entities.DeviceToken.filter({
        user_email: user.email,
        token: token,
      });

      if (existing.length > 0) {
        await base44.entities.DeviceToken.update(existing[0].id, {
          is_active: false,
        });
      }

      return Response.json({ success: true, message: 'Token unregistered' });
    }

    if (action === 'list') {
      const tokens = await base44.entities.DeviceToken.filter({
        user_email: user.email,
        is_active: true,
      });
      return Response.json({ tokens });
    }

    return Response.json({ error: 'Invalid action' }, { status: 400 });
  } catch (error) {
    console.error('FCM Token Manager Error:', error);
    return Response.json({ error: error.message }, { status: 500 });
  }
});

/**
 * fetchIngredientNutrition - Get nutrition from USDA (primary) or OpenFoodFacts (fallback)
 * NO SPOONACULAR
 */
import { createClientFromRequest } from 'npm:@base44/sdk@0.8.21';

const USDA_API_KEY = Deno.env.get("USDA_API_KEY");
const USDA_BASE = "https://api.nal.usda.gov/fdc/v1";
const OFF_BASE = Deno.env.get("OPENFOODFACTS_BASE_URL") || "https://world.openfoodfacts.org";

function extractUSDANutrition(nutrients) {
  const get = (ids) => {
    for (const nutrient of nutrients) {
      const nid = String(nutrient.nutrientId || nutrient.nutrientNumber || "");
      if (ids.some(id => String(id) === nid)) {
        return Math.round((nutrient.value || nutrient.amount || 0) * 10) / 10;
      }
    }
    return 0;
  };
  return {
    calories: get(["1008", "208"]),
    protein: get(["1003", "203"]),
    carbs: get(["1005", "205"]),
    fat: get(["1004", "204"]),
    fiber: get(["1079", "291"]),
    sugar: get(["2000", "269"]),
    sodium: get(["1093", "307"])
  };
}

async function getFromUSDA(fdcId) {
  if (!USDA_API_KEY || !fdcId) return null;
  try {
    const res = await fetch(`${USDA_BASE}/food/${fdcId}?api_key=${USDA_API_KEY}`);
    if (!res.ok) return null;
    const data = await res.json();
    return {
      nutrition: extractUSDANutrition(data.foodNutrients || []),
      source: "usda",
      confidence: "high",
      fdc_id: String(fdcId)
    };
  } catch (e) {
    console.error("[fetchNutrition] USDA fetch error:", e.message);
    return null;
  }
}

async function searchUSDAByName(name) {
  if (!USDA_API_KEY) return null;
  try {
    const url = `${USDA_BASE}/foods/search?query=${encodeURIComponent(name)}&dataType=Foundation,SR%20Legacy&pageSize=3&api_key=${USDA_API_KEY}`;
    const res = await fetch(url);
    if (!res.ok) return null;
    const data = await res.json();
    const food = data.foods?.[0];
    if (!food) return null;
    return {
      nutrition: extractUSDANutrition(food.foodNutrients || []),
      source: "usda",
      confidence: "high",
      fdc_id: String(food.fdcId)
    };
  } catch (e) {
    console.error("[fetchNutrition] USDA search error:", e.message);
    return null;
  }
}

async function getFromOpenFoodFacts(name) {
  try {
    const url = `${OFF_BASE}/cgi/search.pl?search_terms=${encodeURIComponent(name)}&json=1&page_size=3&fields=product_name,nutriments`;
    const res = await fetch(url, { signal: AbortSignal.timeout(4000) });
    if (!res.ok) return null;
    const data = await res.json();
    const product = data.products?.[0];
    if (!product?.nutriments) return null;
    const n = product.nutriments;
    return {
      nutrition: {
        calories: n["energy-kcal_100g"] || n["energy_100g"] / 4.184 || 0,
        protein: n["proteins_100g"] || 0,
        carbs: n["carbohydrates_100g"] || 0,
        fat: n["fat_100g"] || 0,
        fiber: n["fiber_100g"] || 0,
        sugar: n["sugars_100g"] || 0,
        sodium: (n["sodium_100g"] || 0) * 1000
      },
      source: "openfoodfacts",
      confidence: "medium"
    };
  } catch (e) {
    console.error("[fetchNutrition] OpenFoodFacts error:", e.message);
    return null;
  }
}

Deno.serve(async (req) => {
  if (req.method === "OPTIONS") {
    return new Response(null, { status: 204 });
  }

  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user) return Response.json({ error: "Unauthorized" }, { status: 401 });

    const { ingredient_name, fdc_id, canonical_id } = await req.json();

    // 1. Check if we have a canonical record with nutrition already
    if (canonical_id) {
      const canonical = await base44.asServiceRole.entities.CanonicalIngredient.filter(
        { id: canonical_id }, null, 1
      );
      const c = canonical[0];
      if (c?.nutrition_per_100g?.calories > 0 && c.confidence_level === "high") {
        return Response.json({
          nutrition: c.nutrition_per_100g,
          source: c.nutrition_source,
          confidence: c.confidence_level,
          cached: true
        });
      }
    }

    // 2. Try USDA by fdc_id first (most accurate)
    let result = null;
    if (fdc_id) {
      result = await getFromUSDA(fdc_id);
    }

    // 3. Search USDA by name
    if (!result && ingredient_name) {
      result = await searchUSDAByName(ingredient_name);
    }

    // 4. Fallback to OpenFoodFacts (lower confidence, only for packaged)
    if (!result && ingredient_name) {
      result = await getFromOpenFoodFacts(ingredient_name);
    }

    // 5. If still nothing, return estimated flag
    if (!result) {
      return Response.json({
        nutrition: null,
        source: "unavailable",
        confidence: "estimated",
        message: "No nutrition data found. Estimates will be used."
      });
    }

    // Update canonical record if we have one
    if (canonical_id && result.nutrition) {
      await base44.asServiceRole.entities.CanonicalIngredient.update(canonical_id, {
        nutrition_per_100g: result.nutrition,
        nutrition_source: result.source,
        confidence_level: result.confidence,
        fdc_id: result.fdc_id || undefined
      });
    }

    return Response.json(result);

  } catch (error) {
    console.error("[fetchIngredientNutrition] Error:", error.message);
    return Response.json({ error: error.message }, { status: 500 });
  }
});

