  'flax': '🌾', 'chia': '🌾',
};

const DEFAULT_EMOJI = '🍳'; // Fallback emoji

function suggestEmojiForIngredient(name) {
  if (!name) return DEFAULT_EMOJI;

  const lower = name.toLowerCase();

  // Exact match first
  if (EMOJI_SUGGESTIONS[lower]) return EMOJI_SUGGESTIONS[lower];

  // Partial match (check if ingredient name contains any key)
  for (const [key, emoji] of Object.entries(EMOJI_SUGGESTIONS)) {
    if (lower.includes(key) || key.includes(lower.split(' ')[0])) {
      return emoji;
    }
  }

  return DEFAULT_EMOJI;
}

export default Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();

    // Admin check
    if (!user || user.role !== 'admin') {
      return Response.json({ error: 'Admin access required' }, { status: 403 });
    }

    // Fetch ALL CanonicalIngredient records (1000+) with pagination
    let allIngredients = [];
    let offset = 0;
    const pageSize = 500;
    let hasMore = true;

    try {
      while (hasMore) {
        const batch = await base44.entities.CanonicalIngredient.list('display_name', pageSize, offset);
        if (!batch || batch.length === 0) {
          hasMore = false;
        } else {
          allIngredients.push(...batch);
          offset += pageSize;
        }
      }
    } catch (e) {
      console.warn('CanonicalIngredient fetch failed:', e.message);
    }

    if (!allIngredients || allIngredients.length === 0) {
      return Response.json({ 
        error: 'No CanonicalIngredient records found. Ensure CanonicalIngredient entity exists and is populated.',
        status: 'no_data'
      }, { status: 404 });
    }

    // Assign emojis to ALL canonical ingredients (process in chunks)
    let successful = 0;
    let failed = 0;
    const BATCH_SIZE = 50;

    for (let i = 0; i < allIngredients.length; i += BATCH_SIZE) {
      const batch = allIngredients.slice(i, i + BATCH_SIZE);
      const updates = batch.map(ingredient => {
        const suggestedEmoji = suggestEmojiForIngredient(ingredient.display_name || ingredient.name);
        return base44.entities.CanonicalIngredient.update(ingredient.id, {
          emoji: suggestedEmoji,
        });
      });

      const results = await Promise.allSettled(updates);
      successful += results.filter(r => r.status === 'fulfilled').length;
      failed += results.filter(r => r.status === 'rejected').length;

      console.log(`Processed batch ${Math.ceil((i + BATCH_SIZE) / BATCH_SIZE)}, successful: ${successful}, failed: ${failed}`);
    }

    console.log(`Updated ${successful} ingredients, ${failed} failed`);

    return Response.json({
      success: true,
      total_scanned: allIngredients.length,
      missing_icons_found: 0,
      successfully_updated: successful,
      failed: failed,
      details: {
        sample_updates: [],
      },
    });
  } catch (error) {
    console.error('Error:', error);
    return Response.json({ 
      error: error.message,
      stack: error.stack,
    }, { status: 500 });
  }
});

import { createClientFromRequest } from 'npm:@base44/sdk@0.8.6';

const RATE_LIMIT_WINDOW_MS = 30000;
const RATE_LIMIT_MAX = 10;
const followHistory = new Map();

function checkRateLimit(userId) {
  const now = Date.now();
  if (!followHistory.has(userId)) followHistory.set(userId, []);
  const history = followHistory.get(userId);
  const recent = history.filter(t => now - t < RATE_LIMIT_WINDOW_MS);
  if (recent.length >= RATE_LIMIT_MAX) return false;
  recent.push(now);
  followHistory.set(userId, recent);
  return true;
}

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user) return Response.json({ error: 'Unauthorized' }, { status: 401 });

    if (!checkRateLimit(user.id)) {
      return Response.json({ error: 'Too many follow actions. Please slow down.' }, { status: 429 });
    }

    const { targetUserId, action } = await req.json();
    // action: 'follow' | 'unfollow' | 'cancel_request' | 'accept' | 'decline'

    if (!targetUserId || !action) {
      return Response.json({ error: 'Invalid request' }, { status: 400 });
    }

    if (targetUserId === user.id) {
      return Response.json({ error: 'Cannot follow yourself' }, { status: 400 });
    }

    // Load target user
    const targets = await base44.asServiceRole.entities.User.filter({ id: targetUserId });
    if (!targets.length) return Response.json({ error: 'User not found' }, { status: 404 });
    const target = targets[0];

    // Look up existing follow
    const existingFollows = await base44.asServiceRole.entities.UserFollow.filter({
      follower_id: user.id,
      following_id: targetUserId,
    });
    const existingFollow = existingFollows[0];

    if (action === 'follow') {
      if (existingFollow && existingFollow.status === 'accepted') {
        return Response.json({ status: 'following' });
      }
      if (existingFollow && existingFollow.status === 'requested') {
        return Response.json({ status: 'requested' });
      }

      const isPrivate = target.is_private === true;
      const followStatus = isPrivate ? 'requested' : 'accepted';

      if (!existingFollow) {
        await base44.asServiceRole.entities.UserFollow.create({
          follower_id: user.id,
          following_id: targetUserId,
          follower_name: user.display_name || user.full_name || '',
          follower_avatar: user.avatar_url || '',
          status: followStatus,
        });
      } else {
        await base44.asServiceRole.entities.UserFollow.update(existingFollow.id, { status: followStatus });
      }

      // Fetch canonical actor identity (auth.me() avatar can be stale)
      const actorUsers = await base44.asServiceRole.entities.User.filter({ id: user.id }).catch(() => []);
      const actor = actorUsers[0] || user;
      const actorName   = actor.display_name || actor.full_name || 'Someone';
      const actorAvatar = actor.avatar_url || '';

      const notifType  = isPrivate ? 'follow_request' : 'follow';
      const notifTitle = isPrivate ? 'New Follow Request' : 'New Follower!';
      const notifMsg   = isPrivate
        ? `${actorName} wants to follow you`
        : `${actorName} started following you`;

      // Guard: only notify the target, never the actor themselves
      if (user.id !== targetUserId) {
        await base44.asServiceRole.functions.invoke('sendBasicNotification', {
          type: isPrivate ? 'follow_request' : 'new_follower',
          recipientId: targetUserId,
          actorId: user.id,
          actorName: actorName,
          actorAvatar: actorAvatar,
          data: {},
        });
      }

      return Response.json({ status: followStatus });

    } else if (action === 'unfollow') {
      if (existingFollow) {
        await base44.asServiceRole.entities.UserFollow.delete(existingFollow.id);
      }
      return Response.json({ status: 'none' });

    } else if (action === 'cancel_request') {
      if (existingFollow && existingFollow.status === 'requested') {
        await base44.asServiceRole.entities.UserFollow.delete(existingFollow.id);
      }
      return Response.json({ status: 'none' });

    } else if (action === 'accept') {
      // Only the TARGET can accept — targetUserId must be the caller in this context
      // In this endpoint: "accept" means: I am accepting a follow request where someone wants to follow ME
      // So follower_id = targetUserId (the requester), following_id = user.id (me)
      const incomingFollows = await base44.asServiceRole.entities.UserFollow.filter({
        follower_id: targetUserId,
        following_id: user.id,
      });
      const incoming = incomingFollows[0];
      if (!incoming) return Response.json({ error: 'Follow request not found' }, { status: 404 });

      await base44.asServiceRole.entities.UserFollow.update(incoming.id, { status: 'accepted' });

      // Fetch canonical identity for the acceptor
      const acceptorUsers = await base44.asServiceRole.entities.User.filter({ id: user.id }).catch(() => []);
      const acceptor = acceptorUsers[0] || user;
      const acceptorName   = acceptor.display_name || acceptor.full_name || 'Someone';
      const acceptorAvatar = acceptor.avatar_url || '';

      // Notify the requester (targetUserId) — they get told their request was accepted
      if (user.id !== targetUserId) {
        await base44.asServiceRole.functions.invoke('sendBasicNotification', {
          type: 'follow_accepted',
          recipientId: targetUserId,
          actorId: user.id,
          actorName: acceptorName,
          actorAvatar: acceptorAvatar,
          data: {},
        });
      }

      return Response.json({ status: 'accepted' });

    } else if (action === 'decline') {
      // Similar to accept but just delete
      const incomingFollows = await base44.asServiceRole.entities.UserFollow.filter({
        follower_id: targetUserId,
        following_id: user.id,
      });
      const incoming = incomingFollows[0];
      if (incoming) {
        await base44.asServiceRole.entities.UserFollow.delete(incoming.id);
      }
      return Response.json({ status: 'declined' });
    }

    return Response.json({ error: 'Unknown action' }, { status: 400 });

  } catch (error) {
    console.error('followUser error:', error);
    return Response.json({ error: error.message }, { status: 500 });
  }
});

/**
 * Global shared cost formatter for production use.
 * Single source of truth for cost display formatting.
 * 
 * Rule:
 *   >= $1.00: show as dollars (e.g., $1.08)
 *   > 0 and < $1: show as cents (e.g., 54¢)
 *   <= 0: return null
 */

export function formatCostForDisplay(amount) {
  if (amount == null || amount <= 0) {
    return null;
  }

  if (amount < 1) {
    const cents = Math.round(amount * 100);
    return cents > 0 ? `${cents}¢` : null;
  }

  return `$${amount.toFixed(2)}`;
}

export default formatCostForDisplay;

/**
 * friendsGroupAdmin — Admin actions for friends_chat groups.
 *
 * Actions: remove_member, delete_group, update_settings, promote_admin, demote_admin, transfer_ownership
 * 
 * Permission model:
 * - owner: ALL actions
 * - admin: remove_member (if allow_member_remove), promote cannot exceed own role
 * - member: none (unless specific group toggles allow)
 *
 * Backend-enforced — frontend is display-only.
 */
import { createClientFromRequest } from 'npm:@base44/sdk@0.8.25';

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user) return Response.json({ error: 'Unauthorized' }, { status: 401 });

    const { action, group_id, target_user_id, settings } = await req.json();
    if (!group_id || !action) {
      return Response.json({ error: 'Missing group_id or action' }, { status: 400 });
    }

    const sr = base44.asServiceRole;

    // Verify group exists and is friends_chat
    const groups = await sr.entities.Group.filter({ id: group_id });
    const group = groups[0];
    if (!group || group.group_type !== 'friends_chat') {
      return Response.json({ error: 'Group not found', error_code: 'NOT_FOUND' }, { status: 404 });
    }

    // Get caller's membership
    const callerMemberships = await sr.entities.GroupMember.filter({ group_id, user_id: user.id, status: 'active' });
    const callerMember = callerMemberships[0];
    if (!callerMember) {
      return Response.json({ error: 'Not a member of this group' }, { status: 403 });
    }

    const isOwner = group.owner_id === user.id || callerMember.role === 'owner';
    const isAdmin = callerMember.role === 'admin' || isOwner;

    // ────────────────────────────────────────────────────
    // ACTION: remove_member (kick)
    // ────────────────────────────────────────────────────
    if (action === 'remove_member') {
      if (!target_user_id || target_user_id === user.id) {
        return Response.json({ error: 'Invalid target user' }, { status: 400 });
      }

      // Permission check: owner always can, admin only if allow_member_remove is on
      if (!isOwner && !(isAdmin && group.allow_member_remove)) {
        return Response.json({ error: 'No permission to remove members', error_code: 'FORBIDDEN' }, { status: 403 });
      }

      // Get target membership
      const targetMemberships = await sr.entities.GroupMember.filter({ group_id, user_id: target_user_id });
      const targetMember = targetMemberships[0];
      if (!targetMember) {
        return Response.json({ error: 'Target is not a member' }, { status: 400 });
      }

      // Admin cannot kick owner or other admins (only owner can kick admins)
      if (!isOwner && (targetMember.role === 'owner' || targetMember.role === 'admin')) {
        return Response.json({ error: 'Cannot remove someone with equal or higher role' }, { status: 403 });
      }

      // Owner cannot be kicked
      if (targetMember.role === 'owner') {
        return Response.json({ error: 'Cannot remove the group owner' }, { status: 403 });
      }

      await sr.entities.GroupMember.delete(targetMember.id);
      const remaining = await sr.entities.GroupMember.filter({ group_id, status: 'active' });
      await sr.entities.Group.update(group_id, { member_count: remaining.length });

      return Response.json({ success: true, action: 'remove_member' });
    }

    // ────────────────────────────────────────────────────
    // ACTION: promote_admin
    // ────────────────────────────────────────────────────
    if (action === 'promote_admin') {
      if (!isOwner) {
        return Response.json({ error: 'Only the owner can promote admins' }, { status: 403 });
      }
      if (!target_user_id || target_user_id === user.id) {
        return Response.json({ error: 'Invalid target user' }, { status: 400 });
      }

      const targetMemberships = await sr.entities.GroupMember.filter({ group_id, user_id: target_user_id, status: 'active' });
      const targetMember = targetMemberships[0];
      if (!targetMember) {
        return Response.json({ error: 'Target is not an active member' }, { status: 400 });
      }
      if (targetMember.role === 'owner') {
        return Response.json({ error: 'Cannot change owner role' }, { status: 400 });
      }

      await sr.entities.GroupMember.update(targetMember.id, { role: 'admin' });
      return Response.json({ success: true, action: 'promote_admin' });
    }

    // ────────────────────────────────────────────────────
    // ACTION: demote_admin
    // ────────────────────────────────────────────────────
    if (action === 'demote_admin') {
      if (!isOwner) {
        return Response.json({ error: 'Only the owner can demote admins' }, { status: 403 });
      }
      if (!target_user_id || target_user_id === user.id) {
        return Response.json({ error: 'Invalid target user' }, { status: 400 });
      }

