      function nsfwNorm(t) { if (!t) return ''; let r = ''; for (const c of t.toLowerCase()) r += LEET[c] || c; return r.replace(/[^a-z\u0590-\u05FF]/g, ''); }
      const NORM_TERMS = BLOCKED_TERMS.map(t => nsfwNorm(t)).filter(t => t.length >= 2);
      function hasNSFW(text) { if (!text) return false; const n = nsfwNorm(text); return NORM_TERMS.some(t => n.includes(t)); }

      // Name and appearance — admin or owner
      if (settings?.name && settings.name.trim().length >= 2 && settings.name.trim().length <= 60) {
        if (hasNSFW(settings.name)) {
