/**
 * Fuzzy matching algorithm for ingredient search
 * Returns score 0-1, higher = better match
 */
export function fuzzyScore(query, text) {
  const q = query.toLowerCase();
  const t = text.toLowerCase();

  // Exact match
  if (t === q) return 1;
  if (t.includes(q)) return 0.95;
  if (q.includes(t)) return 0.85;

  // Prefix match
  if (t.startsWith(q)) return 0.9;

  // Levenshtein distance (simple version)
  let score = 0;
  let matched = 0;

  for (let i = 0; i < q.length; i++) {
    if (t.includes(q[i])) matched++;
  }

  score = matched / q.length;

  // Prefer earlier matches
  const firstMatchIndex = t.indexOf(q[0]);
  if (firstMatchIndex >= 0) {
    score *= Math.max(0.5, 1 - firstMatchIndex / 20);
  }

  return Math.min(score, 0.8);
}

/**
 * Search ingredients with fuzzy matching
 */
export function searchIngredients(query, ingredients, maxResults = 15) {
  if (!query || query.length < 2) return [];

  const q = query.toLowerCase();

  // Score all ingredients
  const scored = ingredients
    .map((ing) => ({
      ...ing,
      _score: fuzzyScore(q, ing.normalizedName) + fuzzyScore(q, ing.name) * 0.5,
    }))
    .filter((ing) => ing._score > 0.3) // Min score threshold
    .sort((a, b) => b._score - a._score)
    .slice(0, maxResults);

  return scored;
}

