// Build a detailed, realistic food photography prompt for each ingredient
function buildIconPrompt(displayName, category, subcategory) {
  const style = "professional food photography, overhead shot, isolated on pure white background, soft natural lighting, ultra-sharp focus, realistic colors, clean minimal composition, no text, no watermarks, no shadows, high resolution";

  const categoryHints = {
