    herbs_spices: `${displayName}, scattered or in small pile, vivid close-up`,
    grains_cereals: `${displayName}, natural grain texture close-up`,
    legumes_beans: `${displayName}, dried or cooked beans scattered naturally`,
    nuts_seeds: `${displayName}, naturally scattered pile, golden warm tones`,
    dairy_eggs: `${displayName}, fresh dairy product`,
    meat_poultry: `raw ${displayName}, fresh cut, visible marbling or texture`,
    seafood: `fresh ${displayName}, glistening`,
    oils_fats: `${displayName} in small clear glass dish or drizzle`,
    sauces_condiments: `${displayName} in small ceramic bowl or spoon`,
    sweeteners: `${displayName} with natural texture`,
    baking: `${displayName}, baking ingredient close-up`,
    beverages: `${displayName} in clear glass`,
    canned_jarred: `${displayName}`,
    bread_wraps: `fresh baked ${displayName}`,
    pasta_noodles: `${displayName}, dried pasta`,
    frozen: `${displayName}`,
    packaged: `${displayName}`,
    other: `${displayName}`,
  };

  const hint = categoryHints[category] || displayName;
  return `${hint}, ${style}`;
}

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();

    if (!user || user.role !== 'admin') {
      return Response.json({ error: 'Admin access required' }, { status: 403 });
    }

    const body = await req.json().catch(() => ({}));
    const {
      offset = 0,
      batch_size = 5,           // small batch per call to avoid timeouts
      skip_existing = true,     // skip if already has a URL icon
      force_category = null,    // optionally only process a specific category
      dry_run = false,
    } = body;

    // Fetch the batch of ingredients to process
    const allIngredients = await base44.asServiceRole.entities.CanonicalIngredient.list('display_name', 2000, 0);

    let toProcess = allIngredients;

    if (force_category) {
      toProcess = toProcess.filter(i => i.category === force_category);
    }

    if (skip_existing) {
      toProcess = toProcess.filter(i => {
        const icon = i.emoji || '';
        // Skip if already has a URL (previously generated image)
        return !icon.startsWith('http');
      });
    }

    const batch = toProcess.slice(offset, offset + batch_size);
    const total_remaining = toProcess.length;

    if (batch.length === 0) {
      return Response.json({
        success: true,
        processed: 0,
        total_remaining: 0,
        message: 'All ingredients already have custom icons!',
      });
    }

    if (dry_run) {
      return Response.json({
        dry_run: true,
        would_process: batch.map(i => ({ id: i.id, name: i.display_name, category: i.category })),
        total_remaining,
        next_offset: offset + batch_size,
      });
    }

    const results = [];

    for (const ingredient of batch) {
      const prompt = buildIconPrompt(
        ingredient.display_name,
        ingredient.category,
        ingredient.subcategory
      );

      console.log(`[IconGen] Generating for: ${ingredient.display_name} (${ingredient.category})`);
      console.log(`[IconGen] Prompt: ${prompt}`);

      let imageUrl = null;
      let error = null;

      try {
        const imgRes = await base44.asServiceRole.integrations.Core.GenerateImage({ prompt });
        imageUrl = imgRes?.url || null;
      } catch (err) {
        error = err.message;
        console.error(`[IconGen] Failed for ${ingredient.display_name}:`, err.message);
      }

      if (imageUrl) {
        try {
          await base44.asServiceRole.entities.CanonicalIngredient.update(ingredient.id, {
            emoji: imageUrl,
          });
          results.push({ name: ingredient.display_name, status: 'success', url: imageUrl });
          console.log(`[IconGen] ✓ ${ingredient.display_name} -> ${imageUrl}`);
        } catch (updateErr) {
          results.push({ name: ingredient.display_name, status: 'update_failed', error: updateErr.message });
        }
      } else {
        results.push({ name: ingredient.display_name, status: 'image_failed', error });
      }
    }

    return Response.json({
      success: true,
      processed: batch.length,
      total_remaining: total_remaining - batch.length,
      next_offset: offset + batch_size,
      results,
      message: `Generated ${results.filter(r => r.status === 'success').length}/${batch.length} icons. Call again with offset=${offset + batch_size} to continue.`,
    });

  } catch (error) {
    console.error('[generateIngredientIcons] Error:', error.message);
    return Response.json({ error: error.message }, { status: 500 });
  }
});

/**
 * generateIngredientSvgIcon
 * 
 * Generates a global SVG icon for a canonical ingredient.
 * 1. Checks if CanonicalIngredient.ai_generated_icon_svg already exists (global check)
 * 2. If not, generates via LLM and saves to CanonicalIngredient for all users
 * 3. Returns the SVG string immediately
 * 
 * Callable by any authenticated user.
 */

import { createClientFromRequest } from 'npm:@base44/sdk@0.8.21';

async function generateSvgViaLLM(canonicalName, category) {
  const base44 = createClientFromRequest(globalThis._currentRequest);

  const prompt = `Generate a simple, clean SVG icon for the ingredient "${canonicalName}".

Requirements:
- Output ONLY valid SVG code, no markdown or explanation
- Must be readable at 24x24px and 32x32px sizes
- Clean, modern, minimalist style (premium cooking app aesthetic)
- No photorealism, no noisy details
- No emoji, no illustrations
- Single color or subtle two-color gradient
- Fit the ingredient visually (shape, color tone, essence)
- Use viewBox="0 0 24 24"
- Use fill and stroke appropriately
- Should feel like a native app icon, not a placeholder

Example good styles:
- Simple geometric shapes (circles, pentagons, lines)
- Stylized outlines
- Subtle gradients
- Monochromatic with accent color
- Clean sans-serif details if text is needed

Start with: <svg viewBox="0 0 24 24" ...>`;

  try {
    const result = await base44.integrations.Core.InvokeLLM({
      prompt,
      model: "gemini_3_flash",
    });

    const svgString = (result.data || result).trim();

    // Validate it's actually SVG with content
    if (!svgString.includes("<svg")) {
      console.warn(`Invalid SVG for "${canonicalName}":`, svgString.slice(0, 100));
      return null;
    }

    // Validate SVG has drawable content (not just empty tags)
    const hasContent = /(<path|<circle|<rect|<ellipse|<line|<polyline|<polygon|<text|<use|<image|<g[^>]*>)/i.test(svgString);
    if (!hasContent) {
      console.warn(`SVG for "${canonicalName}" has no drawable content`);
      return null;
    }

    // Validate minimum size (50+ bytes suggests real icon)
    if (svgString.length < 50) {
      console.warn(`SVG for "${canonicalName}" too small (${svgString.length} bytes)`);
      return null;
    }

    // Convert to data URL for storage
    const dataUrl = `data:image/svg+xml;base64,${btoa(svgString)}`;
    return dataUrl;
  } catch (err) {
    console.error(`Failed to generate SVG for "${canonicalName}":`, err.message);
    return null;
  }
}

