      return Response.json({
        success: true,
        canonical_name,
        svg_data_url: ingredient.ai_generated_icon_svg,
        source: 'cached_global',
      });
    }

    // CREDIT GUARD: Normal users NEVER trigger LLM generation.
    // Icon generation is admin-only. Non-admin users receive a zero-credit fallback.
    if (user.role !== 'admin') {
      console.log(`[IconGen] No cached icon for "${canonical_name}", returning zero-credit fallback for non-admin user`);
      return Response.json({
        success: true,
        canonical_name,
        svg_data_url: null,
        source: 'fallback_no_icon',
      });
    }

    // 2. AI GENERATION: Admin-only — generate and persist globally
    console.log(`[IconGen] Admin generating new SVG icon for "${canonical_name}"`);
    const svgDataUrl = await generateSvgViaLLM(canonical_name, category);

    if (!svgDataUrl) {
      return Response.json(
        { error: 'Failed to generate SVG icon' },
        { status: 500 }
      );
    }

    // 3. GLOBAL PERSISTENCE: Save to CanonicalIngredient so all users benefit
    if (ingredient?.id) {
      try {
        await base44.asServiceRole.entities.CanonicalIngredient.update(ingredient.id, {
          ai_generated_icon_svg: svgDataUrl,
        });
        console.log(`[IconGen] ✓ Saved global SVG icon for "${canonical_name}"`);
      } catch (updateErr) {
        console.error(`Failed to save icon for "${canonical_name}":`, updateErr.message);
      }
    }

    return Response.json({
      success: true,
      canonical_name,
      svg_data_url: svgDataUrl,
      source: 'newly_generated',
    });
  } catch (error) {
    console.error('[generateIngredientSvgIcon] Error:', error.message);
    return Response.json({ error: error.message }, { status: 500 });
  }
});

/**
 * GENERATE RECIPE IMAGE ON DEMAND
 *
 * SINGLE PROVIDER: TogetherAI ONLY
 * MODEL: black-forest-labs/FLUX.1-schnell
 *
 * No fallback to Base44.
 * No mixed provider logic.
 * No threshold switching.
 * If TogetherAI fails → return failure honestly.
 */

import { createClientFromRequest } from 'npm:@base44/sdk@0.8.25';

const TOGETHER_API_URL = 'https://api.together.xyz/v1/images/generations';
const TOGETHER_API_KEY = Deno.env.get('TOGETHER_AI_API_KEY');
const TOGETHER_MODEL = 'black-forest-labs/FLUX.1.1-pro';

const FALLBACK_MODEL = 'black-forest-labs/FLUX.1-schnell';

// ── TogetherAI image generation with automatic model fallback ─────────────────
async function callTogetherAI(prompt) {
  if (!TOGETHER_API_KEY) throw new Error('TOGETHER_AI_API_KEY not configured');

  // Try primary model first, fall back to schnell on failure
  const models = [
    { model: TOGETHER_MODEL, steps: 28, width: 1024, height: 768 },
    { model: FALLBACK_MODEL, steps: 20, width: 1024, height: 1024 },
  ];

  let lastErr = null;
  for (const cfg of models) {
    try {
      const res = await fetch(TOGETHER_API_URL, {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${TOGETHER_API_KEY}`,
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          model: cfg.model,
          prompt,
          steps: cfg.steps,
          width: cfg.width,
          height: cfg.height,
          n: 1,
        }),
      });
      if (!res.ok) {
        const errText = await res.text();
        lastErr = new Error(`TogetherAI ${cfg.model}: ${res.status} — ${errText.substring(0, 200)}`);
        console.warn(`[IMAGE_GEN] ${cfg.model} failed (${res.status}), trying next model...`);
        continue;
      }
      const data = await res.json();
      const url = data?.data?.[0]?.url || null;
      if (!url) {
        lastErr = new Error(`TogetherAI ${cfg.model} returned no URL`);
        continue;
      }
      console.log(`[IMAGE_GEN] Success with model: ${cfg.model}`);
      return url;
    } catch (err) {
      lastErr = err;
      console.warn(`[IMAGE_GEN] ${cfg.model} exception: ${err.message}`);
    }
  }
  throw lastErr || new Error('All TogetherAI models failed');
}

// ── MAIN HANDLER ─────────────────────────────────────────────────────────────
Deno.serve(async (req) => {
  const startTime = Date.now();

  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user) return Response.json({ error: 'Unauthorized' }, { status: 401 });

    const body = await req.json();
    const { recipe_id, image_prompt } = body;

    if (!image_prompt) {
      return Response.json({ error: 'image_prompt required' }, { status: 400 });
    }

    console.log('[IMAGE_GEN] Starting TogetherAI generation', {
      model: TOGETHER_MODEL,
      recipe_id,
      user_id: user.id,
    });

    // ── RESOLVE PROMPT ────────────────────────────────────────────────────────
    let strictPrompt = image_prompt;
    if (recipe_id && recipe_id !== '_preview') {
      try {
        const sr = base44.asServiceRole;
        const recipe = await sr.entities.Recipe.filter({ id: recipe_id }).then(r => r[0]);
        if (recipe) {
          const promptResult = await sr.functions.invoke('buildImagePrompt', { recipe });
          if (promptResult?.data?.prompt) strictPrompt = promptResult.data.prompt;
        }
      } catch (promptErr) {
        console.warn('[IMAGE_GEN] Could not build from recipe, using provided prompt:', promptErr.message);
      }
    }

    // ── EXECUTE: TogetherAI ONLY ──────────────────────────────────────────────
    let imageUrl = null;
    try {
      const tempUrl = await callTogetherAI(strictPrompt);
      const togetherDuration = Date.now() - startTime;
      console.log('[IMAGE_GEN] TogetherAI SUCCESS (temp URL)', {
        model: TOGETHER_MODEL,
        duration_ms: togetherDuration,
      });

      // LOG: Together AI image generation
      base44.asServiceRole.functions.invoke('logSystemEvent', {
        event_type: 'image_generation',
        source: 'image_gen',
        endpoint_name: 'generateRecipeImageOnDemand',
        origin: 'backend',
        allowed_scope: 'allowed',
        provider_name: 'Together AI',
        model_name: TOGETHER_MODEL,
        request_type: 'image_gen',
        credits_used: 0,
        raw_cost_source: 'COST_DATA_UNAVAILABLE',
        user_id: user.id,
        success: true,
        duration_ms: togetherDuration,
        raw_usage_metadata: { recipe_id, fallback_used: false },
      }).catch(e => console.warn('[IMAGE_GEN] log failed:', e.message));

      // ── PERSIST to Cloudflare R2 (zero Base44 credits) ──────────────────────
      // Together AI short URLs expire after a few hours/days.
      // We persist the image to R2 so it's always accessible.
      try {
        const r2Result = await base44.asServiceRole.functions.invoke('r2UploadFromUrl', {
          source_url: tempUrl,
          purpose: 'recipe_image',
          context_id: recipe_id || 'preview',
        });
        if (r2Result?.data?.file_url) {
          imageUrl = r2Result.data.file_url;
          console.log('[IMAGE_GEN] Permanently uploaded to R2:', imageUrl);
        } else {
          console.warn('[IMAGE_GEN] R2 upload returned no file_url, using temp URL');
          imageUrl = tempUrl;
        }
      } catch (uploadErr) {
        console.warn('[IMAGE_GEN] R2 re-upload failed, using temp URL:', uploadErr.message);
        imageUrl = tempUrl;
      }
    } catch (togetherErr) {
      const failDuration = Date.now() - startTime;
      // LOG: failed Together AI call
      base44.asServiceRole.functions.invoke('logSystemEvent', {
        event_type: 'image_generation',
        source: 'image_gen',
        endpoint_name: 'generateRecipeImageOnDemand',
        origin: 'backend',
        allowed_scope: 'allowed',
        provider_name: 'Together AI',
        model_name: TOGETHER_MODEL,
        request_type: 'image_gen',
        credits_used: 0,
        raw_cost_source: 'COST_DATA_UNAVAILABLE',
        user_id: user.id,
        success: false,
        error_code: togetherErr.message?.substring(0, 200),
        duration_ms: failDuration,
      }).catch(() => {});
      // TogetherAI failed — return failure honestly, NO Base44 fallback
      console.error('[IMAGE_GEN] TogetherAI FAILED:', togetherErr.message);
      return Response.json({
        success: false,
        hero_image_url: null,
        requested_provider: 'togetherai',
        actual_provider_used: 'togetherai',
        model_used: TOGETHER_MODEL,
        error: togetherErr.message,
        duration_ms: failDuration,
      }, { status: 500 });
    }

    // ── UPDATE RECIPE ─────────────────────────────────────────────────────────
    if (recipe_id && recipe_id !== '_preview') {
      const sr = base44.asServiceRole;
      await sr.entities.Recipe.update(recipe_id, { hero_image_url: imageUrl })
        .catch(err => console.warn('[IMAGE_GEN] Recipe update failed:', err.message));
    }

    return Response.json({
      success: true,
      hero_image_url: imageUrl,
      requested_provider: 'togetherai',
      actual_provider_used: 'togetherai',
      model_used: TOGETHER_MODEL,
      fallback_used: false,
      duration_ms: Date.now() - startTime,
      // Legacy compat fields
      provider: 'togetherai',
      isTogetherAI: true,
    });

  } catch (err) {
    console.error('[IMAGE_GEN] Unexpected error:', err.message);
    return Response.json({
      success: false,
      hero_image_url: null,
      error: err.message,
      requested_provider: 'togetherai',
      actual_provider_used: 'togetherai',
      model_used: TOGETHER_MODEL,
    }, { status: 500 });
  }
});

/**
 * RECIPE IMAGE GENERATION PIPELINE
 * 
 * Fully integrated image generation with:
 * - Provider selection and auth validation
 * - Request payload construction from validated recipe
 * - Timeout / retry handling
 * - Response parsing and asset saving
 * - Structured debug logging
 * 
 * Only generates images for recipes that pass integrity validation.
 */

import { createClientFromRequest } from 'npm:@base44/sdk@0.8.23';

// Supported image generation providers
const PROVIDERS = {
  TOGETHER: 'together',
  OPENAI: 'openai',
  FALLBACK: 'fallback'
};

/**
 * Build image prompt from validated recipe
 */
function buildImagePrompt(recipe) {
  if (!recipe || !recipe.title) {
    return null;
  }

  // Use title as base
  let prompt = recipe.title;

  // Add key description details if available
  if (recipe.description) {
    prompt += `. ${recipe.description.substring(0, 100)}`;
  }

  // Add key ingredients
  const keyIngredients = [];
  if (recipe.ingredients && Array.isArray(recipe.ingredients)) {
    for (const group of recipe.ingredients) {
      if (!group.items) continue;
      for (const item of group.items.slice(0, 5)) {
        keyIngredients.push(item.name);
      }
    }
  }

  if (keyIngredients.length > 0) {
    prompt += `. Made with ${keyIngredients.join(', ')}`;
  }

  // Professional photography directive
  prompt += `. Professional food photography, appetizing, high-quality, clean background`;

  return prompt;
}

/**
 * Generate image via Together.ai
 */
async function generateWithTogether(prompt, apiKey) {
  const url = 'https://api.together.xyz/v1/images/generations';

  const payload = {
    model: 'black-forest-labs/FLUX.1-dev',
    prompt,
    width: 768,
    height: 512,
    steps: 20,
    n: 1
  };

  const response = await fetch(url, {
    method: 'POST',
    headers: {
      'Authorization': `Bearer ${apiKey}`,
      'Content-Type': 'application/json'
    },
    body: JSON.stringify(payload),
    signal: AbortSignal.timeout(60000) // 60s timeout
  });

  if (!response.ok) {
    const error = await response.text();
    throw new Error(`Together API error: ${response.status} ${error}`);
  }

  const data = await response.json();

  if (!data.data || !data.data[0] || !data.data[0].b64_json) {
    throw new Error('Invalid Together response format');
  }

  return {
    format: 'base64',
    data: data.data[0].b64_json,
    provider: PROVIDERS.TOGETHER
  };
}

/**
 * Save generated image as asset
 */
async function saveImageAsset(imageData, recipeId, base44) {
  if (!imageData || !imageData.data) {
    return null;
  }

  try {
    // Convert base64 to blob
    const binaryString = atob(imageData.data);
    const bytes = new Uint8Array(binaryString.length);
    for (let i = 0; i < binaryString.length; i++) {
      bytes[i] = binaryString.charCodeAt(i);
    }
    const blob = new Blob([bytes], { type: 'image/jpeg' });

    // Upload to storage
    const uploadResult = await base44.integrations.Core.UploadFile({
      file: blob
    });

    return uploadResult.file_url;
  } catch (err) {
    console.warn('[saveImageAsset] Failed to save:', err.message);
    return null;
  }
}

/**
 * Main image generation pipeline
 */
export async function generateRecipeImage(recipe, recipeId, options = {}) {
  const result = {
    success: false,
    image_url: null,
    provider_used: null,
    debug: {
      recipe_id: recipeId,
      prompt_built: false,
      provider_selected: null,
      request_sent: false,
      response_parsed: false,
      asset_saved: false,
      error: null
    }
  };

  try {
    // Validate recipe
    if (!recipe || !recipe.title) {
      throw new Error('Invalid recipe for image generation');
    }

    // Build prompt from validated recipe structure
    const prompt = buildImagePrompt(recipe);
    if (!prompt) {
      throw new Error('Could not build image prompt from recipe');
    }
    result.debug.prompt_built = true;

    // Get API keys from environment
    const togetherKey = Deno.env.get('TOGETHER_AI_API_KEY');

    if (!togetherKey) {
      throw new Error('No image generation provider configured');
    }

    result.debug.provider_selected = PROVIDERS.TOGETHER;
    result.debug.request_sent = true;

    // Generate image
    const imageData = await generateWithTogether(prompt, togetherKey);
    result.debug.response_parsed = true;
    result.provider_used = imageData.provider;

    // Only proceed to save if we're actually in a database context
    if (options.base44 && options.saveToRecipe) {
      const imageUrl = await saveImageAsset(imageData, recipeId, options.base44);
      if (imageUrl) {
        result.image_url = imageUrl;
        result.debug.asset_saved = true;
      }
    } else {
      // For testing/preview, return the base64 directly
      result.image_url = `data:image/jpeg;base64,${imageData.data}`;
      result.debug.asset_saved = true;
    }

    result.success = true;

  } catch (error) {
    console.error('[generateRecipeImage]', error.message);
    result.debug.error = error.message;
  }

  return result;
}

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user) return Response.json({ error: 'Unauthorized' }, { status: 401 });

    const { recipe, recipeId, saveToRecipe } = await req.json();
    if (!recipe) return Response.json({ error: 'recipe required' }, { status: 400 });

    const result = await generateRecipeImage(recipe, recipeId || 'preview', {
      base44,
      saveToRecipe: saveToRecipe || false
    });

    return Response.json(result);
  } catch (error) {
    console.error('[generateRecipeImagePipeline]', error.message);
    return Response.json({ error: error.message }, { status: 500 });
  }
});

/**
 * generateRecipeWithQuota — AUTHORITATIVE GENERATION ENDPOINT
 *
 * ARCHITECTURE (fail-closed, credit-first, self-healing):
 * 1. Authenticate user
 * 2. Content moderation on USER text
 * 3. Idempotency check — same client_request_id returns cached recipe + FRESH quota
 * 4. Determine Pro/Free entitlement
 * 5. Consume credit ATOMICALLY (record credit_source on event)
 * 6. Run LLM generation (single call)
 * 7. On ANY failure → refund credit + clear Pro cooldown anchor + mark event refunded
 * 8. Return { recipe, quota (authoritative), event_id, credit_source }
 *
 * GUARANTEE: Failed generations never consume quota, never trigger cooldown.
 */
import { createClientFromRequest } from 'npm:@base44/sdk@0.8.25';

const OWNER_EMAIL = 'xenodekuu@gmail.com';
const WEEKLY_LIMIT = 2;
const PRO_DAILY_LIMIT = 25;
const COOLDOWN_AFTER_N = 10;
const COOLDOWN_SECONDS = 180;

function getWeekWindow(date) {
  const dayOfWeek = date.getUTCDay();
  const daysToSubtract = dayOfWeek === 0 ? 6 : dayOfWeek - 1;
  const periodStart = new Date(date);
  periodStart.setUTCDate(periodStart.getUTCDate() - daysToSubtract);
  periodStart.setUTCHours(0, 0, 0, 0);
  const periodEnd = new Date(periodStart);
  periodEnd.setUTCDate(periodEnd.getUTCDate() + 7);
  return { periodStart, periodEnd };
}

function getDayKey(date, timezone) {
  try {
    return new Intl.DateTimeFormat('en-CA', { timeZone: timezone, year: 'numeric', month: '2-digit', day: '2-digit' }).format(date);
  } catch { return date.toISOString().slice(0, 10); }
}

// Build a fresh authoritative quota snapshot for the user.
// Called in idempotency hits AND after successful consumption so response shape is consistent.
async function buildQuotaSnapshot(base44, user, userTz, isPro) {
  const now = new Date();
  if (isPro) {
    const todayKey = getDayKey(now, userTz);
    const proQuota = (await base44.asServiceRole.entities.ProGenerationQuota.filter(
      { user_id: user.id, day_key: todayKey }
    ).catch(() => []))[0] || null;
    const daily = proQuota?.daily_count || 0;
    let cooldownActive = false, cooldownRem = 0;
    if (daily >= COOLDOWN_AFTER_N && proQuota?.last_generation_started_at) {
      const elapsed = (now.getTime() - new Date(proQuota.last_generation_started_at).getTime()) / 1000;
      const rem = Math.ceil(COOLDOWN_SECONDS - elapsed);
      if (rem > 0) { cooldownActive = true; cooldownRem = rem; }
    }
    const proLedger = await base44.asServiceRole.entities.ReferralRewardLedger.filter({
      user_id: user.id, credit_state: 'earned',
    }).catch(() => []);
    const banked = proLedger.reduce((s, e) => s + (e.credits_remaining || 0), 0);
    let nextReset = null;
    try {
      const fmt = new Intl.DateTimeFormat('en-US', { timeZone: userTz, hour: 'numeric', minute: 'numeric', second: 'numeric', hour12: false });
      const parts = fmt.formatToParts(now);
      const h = parseInt(parts.find(p => p.type === 'hour')?.value || '0');
      const m = parseInt(parts.find(p => p.type === 'minute')?.value || '0');
      const s = parseInt(parts.find(p => p.type === 'second')?.value || '0');
      const secsUntilMidnight = ((23 - h) * 3600) + ((59 - m) * 60) + (60 - s);
      nextReset = new Date(now.getTime() + secsUntilMidnight * 1000).toISOString();
    } catch {}
    return {
      is_premium: true,
      pro_daily_limit: PRO_DAILY_LIMIT,
      pro_daily_count: daily,
      pro_remaining_today: Math.max(0, PRO_DAILY_LIMIT - daily),
      pro_cooldown_active: cooldownActive,
      pro_cooldown_remaining_seconds: cooldownRem,
      pro_cooldown_after_n: COOLDOWN_AFTER_N,
      banked_referral_credits: banked,
      next_reset_at: nextReset,
      remaining: null, used: null, limit: null,
    };
  }
  const { periodStart, periodEnd } = getWeekWindow(now);
  const records = await base44.asServiceRole.entities.AiGenerationQuota.filter(
    { user_id: user.id, period_start: periodStart.toISOString() }, null, 20
  ).catch(() => []);
  let q = null;
  if (records.length > 0) {
    records.sort((a, b) => (b.used || 0) - (a.used || 0));
    q = records[0];
  }
  const used = q?.used || 0;
  const remaining = Math.max(0, WEEKLY_LIMIT - used);
  const ledger = await base44.asServiceRole.entities.ReferralRewardLedger.filter({
    user_id: user.id, credit_state: 'earned',
  }).catch(() => []);
  const banked = ledger.reduce((s, e) => s + (e.credits_remaining || 0), 0);
  return {
    is_premium: false,
    remaining, used, limit: WEEKLY_LIMIT,
    banked_referral_credits: banked,
    total_available: remaining + banked,
    period_start: periodStart.toISOString(),
    period_end: periodEnd.toISOString(),
    next_reset_at: periodEnd.toISOString(),
    resets_at: periodEnd.toISOString(),
  };
}

// Clear Pro cooldown anchor + in-progress flag. Called on every failure path.
async function clearProCooldown(base44, userId, userTz) {
  try {
    const todayKey = getDayKey(new Date(), userTz);
    const records = await base44.asServiceRole.entities.ProGenerationQuota.filter(
      { user_id: userId, day_key: todayKey }
    ).catch(() => []);
    if (records[0]?.id) {
      await base44.asServiceRole.entities.ProGenerationQuota.update(records[0].id, {
        last_generation_started_at: null,
        generation_in_progress: false,
        updated_at: new Date().toISOString(),
      });
    }
  } catch (e) {
    console.warn('[clearProCooldown] failed:', e.message);
  }
}

// Refund a credit based on credit_source. Idempotent-safe (caller guards status).
async function refundCredit(base44, userId, userTz, creditSource) {
  try {
    if (creditSource === 'pro_daily') {
      const todayKey = getDayKey(new Date(), userTz);
      const records = await base44.asServiceRole.entities.ProGenerationQuota.filter(
        { user_id: userId, day_key: todayKey }
      ).catch(() => []);
      const pq = records[0];
      if (pq?.id && (pq.daily_count || 0) > 0) {
        await base44.asServiceRole.entities.ProGenerationQuota.update(pq.id, {
          daily_count: Math.max(0, (pq.daily_count || 0) - 1),
          last_generation_started_at: null,
          generation_in_progress: false,
          updated_at: new Date().toISOString(),
        });
      }
    } else if (creditSource === 'weekly_free') {
      const { periodStart } = getWeekWindow(new Date());
      const records = await base44.asServiceRole.entities.AiGenerationQuota.filter(
        { user_id: userId, period_start: periodStart.toISOString() }, null, 5
      ).catch(() => []);
      if (records.length > 0) {
        records.sort((a, b) => (b.used || 0) - (a.used || 0));
        const r = records[0];
        if ((r.used || 0) > 0) {
          await base44.asServiceRole.entities.AiGenerationQuota.update(r.id, {
            used: Math.max(0, (r.used || 0) - 1),
            updated_at: new Date().toISOString(),
          });
        }
      }
    } else if (creditSource === 'banked_referral' || creditSource === 'pro_banked') {
      const ledgerEntries = await base44.asServiceRole.entities.ReferralRewardLedger.filter({
        user_id: userId,
      }).catch(() => []);
      const recentConsumed = ledgerEntries
        .filter(e => e.credit_state === 'consumed' || (e.credits_remaining || 0) === 0)
        .sort((a, b) => new Date(b.updated_date || b.created_date) - new Date(a.updated_date || a.created_date));
      if (recentConsumed.length > 0) {
        const entry = recentConsumed[0];
        await base44.asServiceRole.entities.ReferralRewardLedger.update(entry.id, {
          credits_remaining: 1, credit_state: 'earned', consumed_at: null,
        });
      }
    }
  } catch (e) {
    console.error('[refundCredit] failed:', e.message);
  }
}

Deno.serve(async (req) => {
  const generationId = crypto.randomUUID();
  const startTime = Date.now();

  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user) return Response.json({ error: 'Unauthorized' }, { status: 401 });

    const body = await req.json();
    const { prompt, response_json_schema, client_request_id, client_timezone } = body;

    if (!prompt) return Response.json({ error: 'prompt required' }, { status: 400 });
    if (!client_request_id) return Response.json({ error: 'client_request_id required for idempotency' }, { status: 400 });

    const now = new Date();
    // CRITICAL: must use the SAME tz resolution as getAiQuotaAdvanced and refundFailedGeneration
    // so day_key writes/reads agree. If user.timezone is missing/UTC, fall back to client tz.
    // A mismatch here causes the Pro quota to look reset (writes go to UTC's day_key while
    // the read uses the local tz day_key) — the exact bug we're fixing.
    const userTz = (user.timezone && user.timezone !== 'UTC')
      ? user.timezone
      : (client_timezone || user.timezone || 'UTC');
    const isOwner = user.email === OWNER_EMAIL;

