    // STEP 0: CONTENT MODERATION — user text only
    // ══════════════════════════════════════════════════════════════════════════
    {
      let userText = '';
      const optionalPromptMatch = prompt.match(/Optional prompt:\s*(.+?)(?:\n|$)/i);
      const freeStyleMatch = prompt.match(/User request:\s*(.+?)(?:\n|$)/i);
      if (optionalPromptMatch) userText = optionalPromptMatch[1];
      else if (freeStyleMatch) userText = freeStyleMatch[1];
      const titleMatch = prompt.match(/Recipe title suggestion:\s*(.+?)(?:\n|$)/i);
      if (titleMatch) userText += ' ' + titleMatch[1];
      if (!userText.trim()) userText = prompt.slice(-500);

      const promptLower = userText.toLowerCase();
      const stripped = promptLower.replace(/[\u200B-\u200F\u2028-\u202F\u2060-\u206F\uFEFF\u00AD]/g, '');
      const LEET = {'0':'o','1':'i','3':'e','4':'a','5':'s','7':'t','@':'a','$':'s','!':'i'};
