      const FOOD_EXCEPTIONS = ['naked cake','breast','chicken breast','turkey breast','duck breast'];
      let scanText = promptLower, scanLeet = leetNorm, scanJoined = joined;
      for (const exc of FOOD_EXCEPTIONS) {
        scanText = scanText.replaceAll(exc, '');
        scanLeet = scanLeet.replaceAll(exc, '');
        scanJoined = scanJoined.replaceAll(exc.replace(/\s/g, ''), '');
      }
      const SHORT_AMBIGUOUS = new Set(['tits','cum','sex','anal','cunt','slut','dick','cock','nude']);
      let blocked = false;
