      let cachedRecipe = null;
      try { cachedRecipe = existing.recipe_payload ? JSON.parse(existing.recipe_payload) : null; } catch {}
      // CRITICAL: always return a FRESH quota snapshot on idempotent hit
      const freshQuota = await buildQuotaSnapshot(base44, user, userTz, isPro);
      return Response.json({
        success: true,
        idempotent_hit: true,
        recipe: cachedRecipe,
        event_id: existing.id,
        generation_id: generationId,
