        quota: freshQuota,
      });
    }

    // ══════════════════════════════════════════════════════════════════════════
    // STEP 3: CONSUME CREDIT ATOMICALLY
    // ══════════════════════════════════════════════════════════════════════════
    let creditSource = 'none';
    let quotaAfter = null;

