    let recipe = null;
    try {
      const schema = response_json_schema || {
        type: "object",
        properties: {
          title: { type: "string" }, description: { type: "string" },
          cuisine: { type: "string" }, meal_type: { type: "string" },
          cook_time: { type: "number" }, prep_time: { type: "number" },
