      try {
        await base44.asServiceRole.entities.IntegrationCostLog.create({
          timestamp: now.toISOString(), user_id: user.id,
          function_name: 'generateRecipeWithQuota', action_type: 'ai_generation',
          cost_category: 'llm', integration_name: 'Core.InvokeLLM',
