          metadata_json: JSON.stringify({ recipe_title: recipe?.title || 'unknown', generation_id: generationId }),
        });
      } catch (logErr) {
        console.error('[generateRecipeWithQuota] CREDIT LOG FAILED:', logErr.message);
      }

      base44.asServiceRole.functions.invoke('logSystemEvent', {
        event_type: 'llm_call', source: 'ai_recipe',
        endpoint_name: 'generateRecipeWithQuota', origin: 'backend',
        allowed_scope: 'allowed', provider_name: 'Core.InvokeLLM',
        model_name: 'automatic', request_type: 'json_schema',
        credits_used: 1, raw_cost_source: 'inferred_from_usage',
        user_id: user.id, quota_event_id: event?.id, success: true,
        duration_ms: Date.now() - startTime,
        raw_usage_metadata: { recipe_title: recipe?.title, generation_id: generationId, credit_source: creditSource },
      }).catch(() => {});

      try {
        const monthKey = new Date().toISOString().slice(0, 7);
        const records = await base44.asServiceRole.entities.MonthlyIntegrationUsageState.filter({ month_key: monthKey }, null, 1).catch(() => []);
        const record = records[0];
        if (record) {
          await base44.asServiceRole.entities.MonthlyIntegrationUsageState.update(record.id, {
            tracked_base44_credits_used: (record.tracked_base44_credits_used || 0) + 1,
            last_updated: new Date().toISOString(),
          });
        } else {
          await base44.asServiceRole.entities.MonthlyIntegrationUsageState.create({
            month_key: monthKey, monthly_max_credits: 50000,
            threshold_percent: 33, threshold_credits_computed: 16500,
            tracked_base44_credits_used: 1, current_mode: 'base44',
            auto_mode_enabled: true, last_updated: new Date().toISOString(),
          });
        }
      } catch {}

      const normTime = (v) => {
        if (v == null) return 0;
        const n = typeof v === 'string' ? parseFloat(v) : v;
        if (isNaN(n) || n < 0) return 0;
        if (n > 0 && n <= 12 && !Number.isInteger(n)) return Math.round(n * 60);
        return Math.round(n);
      };
      if (recipe) {
        recipe.cook_time = normTime(recipe.cook_time);
        recipe.prep_time = normTime(recipe.prep_time);
      }

      if (event?.id && recipe?.title) {
        base44.asServiceRole.entities.AiGenerationEvent.update(event.id, {
          recipe_title: recipe.title,
          status: 'generated',
          recipe_payload: JSON.stringify(recipe),
        }).catch(() => {});
      }

      // Release Pro in-progress flag on success (cooldown anchor stays set — that's intended for Pro)
      if (isPro && creditSource === 'pro_daily') {
        const todayKey = getDayKey(now, userTz);
        const pq = (await base44.asServiceRole.entities.ProGenerationQuota.filter(
          { user_id: user.id, day_key: todayKey }
        ).catch(() => []))[0];
        if (pq?.id) {
          base44.asServiceRole.entities.ProGenerationQuota.update(pq.id, {
            generation_in_progress: false, updated_at: new Date().toISOString(),
          }).catch(() => {});
        }
      }

    } catch (llmErr) {
      console.error(`[GENERATION_FAILED] generation_id=${generationId} error=${llmErr.message} — REFUNDING`);
      if (event?.id) {
        base44.asServiceRole.entities.AiGenerationEvent.update(event.id, { status: 'refunded' }).catch(() => {});
      }
      await refundCredit(base44, user.id, userTz, creditSource);
      if (isPro) await clearProCooldown(base44, user.id, userTz);
      return Response.json({
        error: 'Recipe generation failed — credit was refunded',
        code: 'LLM_FAILED',
        generation_id: generationId, event_id: event?.id,
        quota: await buildQuotaSnapshot(base44, user, userTz, isPro),
      }, { status: 500 });
    }

    if (!recipe || !recipe.title) {
      if (event?.id) {
        base44.asServiceRole.entities.AiGenerationEvent.update(event.id, { status: 'refunded' }).catch(() => {});
      }
      await refundCredit(base44, user.id, userTz, creditSource);
      if (isPro) await clearProCooldown(base44, user.id, userTz);
      return Response.json({
        error: 'LLM returned invalid recipe — credit was refunded',
        code: 'LLM_INVALID',
        generation_id: generationId, event_id: event?.id,
        quota: await buildQuotaSnapshot(base44, user, userTz, isPro),
      }, { status: 500 });
    }

    const totalDuration = Date.now() - startTime;
    console.log(`[GENERATION_COMPLETE] generation_id=${generationId} title="${recipe.title}" source=${creditSource} duration=${totalDuration}ms`);

    return Response.json({
      success: true,
      recipe,
      event_id: event?.id,
      generation_id: generationId,
      credit_source: creditSource,
      quota: await buildQuotaSnapshot(base44, user, userTz, isPro),
    });

  } catch (err) {
    console.error(`[generateRecipeWithQuota] FATAL generation_id=${generationId}:`, err.message);
    return Response.json({ error: err.message }, { status: 500 });
  }
});

import { createClientFromRequest } from 'npm:@base44/sdk@0.8.23';

/**
 * generateUsername — Centralized identity generation for Reciply.
 *
 * Modes:
 *   generate  → given full_name + email, returns { username, display_name }
 *   backfill  → scans ALL users, fills any missing username / display_name
 *
 * Rules:
 *   username   : lowercase, 2–14 chars, [a-z0-9_] only, globally unique
 *   display_name: human-readable, ≤14 chars, not forced to be unique
 */

const USERNAME_MAX  = 14;
const USERNAME_BASE_MAX = 11; // leave 3 chars for suffix (up to 999)
const DISPLAY_MAX   = 14;

// ── Helpers ──────────────────────────────────────────────────────────────────

/**
 * Derive a clean display_name from full_name or email.
 * Priority: full_name → email local part → "Chef"
 */
function deriveDisplayName(full_name, email) {
  if (full_name && full_name.trim().length >= 2) {
    // Title-case and trim to DISPLAY_MAX
    return full_name.trim().replace(/\s+/g, ' ').slice(0, DISPLAY_MAX).trim();
  }
  if (email) {
    const local = email.split('@')[0] || '';
    // Replace separators with spaces, remove trailing digits
    // Capitalise each word segment (Chef Kelly24 not Chef kelly24)
    const cleaned = local
      .replace(/[._\-+]/g, ' ')
      .replace(/\s+/g, ' ')
      .trim()
      .split(' ')
      .map(w => w.charAt(0).toUpperCase() + w.slice(1))
      .join(' ');
    const capped = cleaned;
    const result = capped.slice(0, DISPLAY_MAX).trim();
    if (result.length >= 2) return result;
    return local.slice(0, DISPLAY_MAX) || 'Chef';
  }
  return 'Chef';
}

/**
 * Build a raw username base from full_name or email.
 * Returns lowercase, [a-z0-9_] only, max USERNAME_BASE_MAX chars.
 */
function buildUsernameBase(full_name, email) {
  let raw = '';
  if (full_name && full_name.trim()) {
    raw = full_name.trim().toLowerCase().replace(/\s+/g, '').replace(/[^a-z0-9_]/g, '');
  }
  if (raw.length < 2 && email) {
    raw = email.split('@')[0].toLowerCase().replace(/[^a-z0-9_]/g, '');
  }
  // Ensure minimum
  if (raw.length < 2) raw = 'chef' + raw;
  return raw.slice(0, USERNAME_BASE_MAX);
}

/**
 * Find a unique username — returns null if exhausted (very unlikely).
 */
async function findUniqueUsername(base, serviceRole) {
  let username = base;
  let suffix   = 0;

  while (suffix < 1000) {
    const existing = await serviceRole.entities.User.filter(
      { username },
      '-created_date',
      1
    ).catch(() => []);

    if (existing.length === 0) return username;

    suffix++;
    const sfx = suffix.toString();
    const truncated = base.slice(0, Math.max(2, USERNAME_MAX - sfx.length));
    username = truncated + sfx;
  }
  return null; // could not find unique
}

// ── Handler ──────────────────────────────────────────────────────────────────

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const body   = await req.json().catch(() => ({}));
    const { mode = 'generate', full_name = '', email = '' } = body;

    // ── MODE: generate ──────────────────────────────────────────────
    if (mode === 'generate') {
      // Resolve the calling user — required so we know who to update
      const caller = await base44.auth.me().catch(() => null);
      if (!caller) {
        return Response.json({ ok: false, error: 'Not authenticated' }, { status: 401 });
      }

      // Use provided args OR fall back to caller's own profile data
      const resolvedFullName = full_name || caller.full_name || '';
      const resolvedEmail    = email    || caller.email    || '';

      const display_name = deriveDisplayName(resolvedFullName, resolvedEmail);
      const base         = buildUsernameBase(resolvedFullName, resolvedEmail);
      const username     = await findUniqueUsername(base, base44.asServiceRole);

      if (!username) {
        return Response.json({ ok: false, error: 'Could not generate unique username' }, { status: 500 });
      }

      // Persist directly — only set fields that are still missing so we never
      // overwrite a username the user already chose manually.
      const updates = {};
      const needsUsername    = !caller.username    || caller.username.trim().length < 2;
      const needsDisplayName = !caller.display_name || caller.display_name.trim().length < 2;
      if (needsUsername)    updates.username     = username;
      if (needsDisplayName) updates.display_name = display_name;

      if (Object.keys(updates).length > 0) {
        await base44.asServiceRole.entities.User.update(caller.id, updates);
      }

      return Response.json({ ok: true, username, display_name });
    }

    // ── MODE: backfill ──────────────────────────────────────────────
    if (mode === 'backfill') {
      // Admin-only guard
      const caller = await base44.auth.me().catch(() => null);
      if (!caller || caller.role !== 'admin') {
        return Response.json({ error: 'Forbidden' }, { status: 403 });
      }

      // Fetch all users — paginate in batches of 200
      let allUsers = [];
      let skip = 0;
      while (true) {
        const batch = await base44.asServiceRole.entities.User.list('-created_date', 200, skip).catch(() => []);
        if (!batch.length) break;
        allUsers = allUsers.concat(batch);
        if (batch.length < 200) break;
        skip += 200;
      }

      let backfilledUsername    = 0;
      let backfilledDisplayName = 0;
      let errors = 0;

      for (const user of allUsers) {
        try {
          const updates = {};

          // Check display_name
          const hasDisplayName = user.display_name && user.display_name.trim().length >= 2;
          if (!hasDisplayName) {
            updates.display_name = deriveDisplayName(user.full_name || '', user.email || '');
            backfilledDisplayName++;
          }

          // Check username
          const hasUsername = user.username && user.username.trim().length >= 2;
          if (!hasUsername) {
            const base    = buildUsernameBase(user.full_name || '', user.email || '');
            const uname   = await findUniqueUsername(base, base44.asServiceRole);
            if (uname) {
              updates.username = uname;
              backfilledUsername++;
            }
          }

          if (Object.keys(updates).length > 0) {
            await base44.asServiceRole.entities.User.update(user.id, updates);
          }
        } catch (err) {
          console.warn(`[generateUsername/backfill] failed for user ${user.id}:`, err.message);
          errors++;
        }
      }

      return Response.json({
        ok: true,
        total: allUsers.length,
        backfilledUsername,
        backfilledDisplayName,
        errors,
      });
    }

    return Response.json({ ok: false, error: 'Invalid mode' }, { status: 400 });

  } catch (error) {
    console.error('[generateUsername] error:', error);
    return Response.json({ ok: false, error: error.message }, { status: 500 });
  }
});

import { createClientFromRequest } from 'npm:@base44/sdk@0.8.25';

const ADMIN_EMAIL = 'xenodekuu@gmail.com';
const OWNER_EMAIL = 'xenodekuu@gmail.com';

// Delay helper to spread calls and avoid rate limits
const delay = (ms) => new Promise(r => setTimeout(r, ms));

// Retry wrapper: retries on 429 with exponential backoff
async function withRetry(fn, retries = 3, baseDelay = 600) {
  for (let i = 0; i <= retries; i++) {
    try {
      return await fn();
    } catch (err) {
      const status = err?.response?.status || err?.status;
      if (status === 429 && i < retries) {
        await delay(baseDelay * Math.pow(2, i));
        continue;
      }
      throw err;
    }
  }
}

// Safe fetch: returns fallback on any error (never throws)
async function safeFetch(fn, fallback = []) {
  try {
    return await withRetry(fn);
  } catch {
    return fallback;
  }
}

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
