    const now = new Date();
    const ISRAEL_OFFSET_MS = 3 * 60 * 60 * 1000;
    const nowIsrael = new Date(now.getTime() + ISRAEL_OFFSET_MS);
    const todayStart = new Date(Date.UTC(nowIsrael.getUTCFullYear(), nowIsrael.getUTCMonth(), nowIsrael.getUTCDate(), 0, 0, 0, 0) - ISRAEL_OFFSET_MS);
    const weekStart = new Date(now); weekStart.setDate(now.getDate() - 7);
    const todayStr = todayStart.toISOString();
    const weekStr = weekStart.toISOString();

    // ── OVERVIEW ────────────────────────────────────────────────────────────
    if (section === 'overview') {
      // Sequential with small delays to avoid rate limits
      const users = await safeFetch(() => base44.asServiceRole.entities.User.list('-created_date', 2000));
      await delay(200);
      const allGens = await safeFetch(() => base44.asServiceRole.entities.AiGenerationEvent.list('-created_date', 500));
      await delay(200);
      const costLogs = await safeFetch(() => base44.asServiceRole.entities.IntegrationCostLog.list('-timestamp', 300));
      await delay(200);
      const proUsers = await safeFetch(() => base44.asServiceRole.entities.Subscription.filter({ status: 'active' }, '-created_date', 500));

      const todayGens = allGens.filter(g => g.created_date && g.created_date >= todayStr);
      const todayCostLogs = costLogs.filter(l => (l.timestamp || l.created_date) >= todayStr);
      const signupsToday = users.filter(u => u.created_date && u.created_date >= todayStr);
      const activeUserIds = new Set(todayGens.map(g => g.user_id));
      const weekGenUserIds = new Set(allGens.filter(g => g.created_date && g.created_date >= weekStr).map(g => g.user_id));
      const recentSignups = users.filter(u => u.created_date && u.created_date >= weekStr);

      const totalCostToday = todayCostLogs.reduce((sum, log) => {
        const cats = { llm: 0.004, image_generation: 0.02, file_upload: 0.001, email: 0.001 };
        return sum + (cats[log.cost_category] || 0.002) * (log.estimated_cost_units || 1);
      }, 0);

      return Response.json({
        summary: {
          total_users: users.length,
          active_today: activeUserIds.size,
          new_signups_today: signupsToday.length,
          new_signups_week: recentSignups.length,
          pro_users: proUsers.length,
          free_users: users.length - proUsers.length,
          total_generations_today: todayGens.length,
          integrations_consumed_today: todayCostLogs.length,
          estimated_cost_today_usd: Math.round(totalCostToday * 100) / 100,
          failed_generations_today: todayGens.filter(g => g.status === 'failed').length,
          conversion_rate: users.length > 0 ? Math.round((proUsers.length / users.length) * 100) : 0,
          active_week: weekGenUserIds.size,
        },
        live_feed: [],
      });
    }

    // ── SIGNUPS ─────────────────────────────────────────────────────────────
    if (section === 'signups') {
      const users = await safeFetch(() => base44.asServiceRole.entities.User.list('-created_date', 2000));
      await delay(300);
      const subs = await safeFetch(() => base44.asServiceRole.entities.Subscription.list('-created_date', 500));
      const subMap = {};
      subs.forEach(s => { subMap[s.created_by] = s; });

      const enriched = users.map(u => {
        const isOwnerUser = u.email === OWNER_EMAIL;
        const sub = subMap[u.email];
        let plan = 'free';
        if (isOwnerUser) plan = 'pro';
        else if (sub?.status === 'active') plan = 'pro';
        else if (sub?.status === 'trialing') plan = 'trial';
        else if (sub?.status === 'grace_period') plan = 'pro';
        return {
          id: u.id, email: u.email,
          display_name: u.display_name || u.full_name || u.username || 'Unknown',
          full_name: u.full_name, username: u.username, avatar_url: u.avatar_url,
          created_date: u.created_date, onboarding_complete: !!u.onboarding_complete,
          plan, owner_override: isOwnerUser,
          last_active: u.last_seen_at || u.updated_date,
          referral_code: u.referral_code_used || null,
        };
      });
      return Response.json({ signups: enriched, total: enriched.length });
    }

    // ── USERS ───────────────────────────────────────────────────────────────
    if (section === 'users') {
      const allUsers = await safeFetch(() => base44.asServiceRole.entities.User.list('-created_date', 300));
      await delay(300);
      const subs_v = await safeFetch(() => base44.asServiceRole.entities.Subscription.list('-created_date', 500));
      await delay(300);
      const gens_all_v = await safeFetch(() => base44.asServiceRole.entities.AiGenerationEvent.list('-created_date', 5000));
      await delay(300);
      const posts_v = await safeFetch(() => base44.asServiceRole.entities.Post.list('-created_date', 500));
      await delay(200);
      const saved_v = await safeFetch(() => base44.asServiceRole.entities.RecipeSave.list('-created_date', 2000));
      await delay(200);
      const ledger_v = await safeFetch(() => base44.asServiceRole.entities.ReferralRewardLedger.list('-created_date', 2000));
      await delay(200);

      const todayKeyIsrael = `${nowIsrael.getUTCFullYear()}-${String(nowIsrael.getUTCMonth()+1).padStart(2,'0')}-${String(nowIsrael.getUTCDate()).padStart(2,'0')}`;
      const proQuota_v = await safeFetch(() => base44.asServiceRole.entities.ProGenerationQuota.list('-updated_at', 500));
      await delay(200);
      const freeQuota_v = await safeFetch(() => base44.asServiceRole.entities.AiGenerationQuota.list('-updated_at', 500));

      const subMap = {}; subs_v.forEach(s => { subMap[s.created_by] = s; });

      const bankedByUser = {};
      ledger_v.filter(e => e.credit_state === 'earned').forEach(e => {
        bankedByUser[e.user_id] = (bankedByUser[e.user_id] || 0) + parseInt(e.credits_remaining || 0, 10);
      });

      const proQuotaByUser = {};
      proQuota_v.filter(q => q.day_key === todayKeyIsrael).forEach(q => { proQuotaByUser[q.user_id] = parseInt(q.daily_count || 0, 10); });

      const freeQuotaByUser = {};
      freeQuota_v.forEach(q => {
        if (!freeQuotaByUser[q.user_id] || new Date(q.period_start) > new Date(freeQuotaByUser[q.user_id].period_start)) {
          freeQuotaByUser[q.user_id] = q;
        }
      });

      const genByUser = {};
      gens_all_v.forEach(g => {
        if (!g.user_id) return;
        if (!genByUser[g.user_id]) genByUser[g.user_id] = { total: 0, today: 0, week: 0 };
        genByUser[g.user_id].total++;
        if (g.created_date && g.created_date >= weekStr) genByUser[g.user_id].week++;
        if (g.created_date && g.created_date >= todayStr) genByUser[g.user_id].today++;
      });

      freeQuota_v.forEach(q => {
        if (!q.user_id || !q.used) return;
        const uid = q.user_id;
        if (!genByUser[uid]) genByUser[uid] = { total: 0, today: 0, week: 0 };
        if (q.period_end && new Date(q.period_end) > now && genByUser[uid].week === 0) genByUser[uid].week = parseInt(q.used || 0, 10);
        if (genByUser[uid].total === 0 && q.used > 0) genByUser[uid].total = parseInt(q.used || 0, 10);
      });
      proQuota_v.forEach(q => {
        if (!q.user_id) return;
        const uid = q.user_id;
        if (!genByUser[uid]) genByUser[uid] = { total: 0, today: 0, week: 0 };
        const dailyUsed = parseInt(q.daily_count || 0, 10);
        genByUser[uid].today = Math.max(genByUser[uid].today, dailyUsed);
        genByUser[uid].week = Math.max(genByUser[uid].week, dailyUsed);
      });

      const postsByUser = {};
      posts_v.forEach(p => { postsByUser[p.author_id] = (postsByUser[p.author_id] || 0) + 1; });
      const savedByUser = {};
      saved_v.forEach(r => { if (r.created_by) savedByUser[r.created_by] = (savedByUser[r.created_by] || 0) + 1; });

      const PRO_DAILY_LIMIT = 25;
      const FREE_WEEKLY_LIMIT = 2;

      function getSubInfo(sub) {
        if (!sub) return { plan: 'free', billing_cycle: null, sub_end_at: null, trial_end_at: null, auto_renew: false, is_trial: false };
        const status = sub.status;
        const sub_end_at = sub.current_period_end || sub.grace_period_end || null;
        const trial_end_at = sub.trial_end || null;
        const auto_renew = sub.auto_renew !== false;
        let plan = 'free';
        if (status === 'active' || status === 'grace_period') plan = 'pro';
        else if (status === 'trialing') plan = 'trial';
        else if (status === 'canceled' && sub_end_at && new Date(sub_end_at) > now) plan = 'pro';
        return { plan, billing_cycle: sub.plan_type || 'pro', sub_end_at, trial_end_at, auto_renew, is_trial: status === 'trialing', raw_status: status };
      }

      const profiles = allUsers.slice(offset, offset + limit).map(u => {
        const isOwnerUser = u.email === OWNER_EMAIL;
        const sub = subMap[u.email];
        const subInfo = isOwnerUser
          ? { plan: 'pro', billing_cycle: 'owner_override', sub_end_at: null, trial_end_at: null, auto_renew: true, is_trial: false, raw_status: 'owner_override' }
          : getSubInfo(sub);
        const { plan, sub_end_at, trial_end_at, auto_renew, is_trial, raw_status } = subInfo;

        const gens = genByUser[u.id] || { total: 0, today: 0, week: 0 };
        const lastActive = new Date(u.last_seen_at || u.updated_date || u.created_date);
        const daysSinceActive = Math.floor((now - lastActive) / (1000 * 60 * 60 * 24));

        let normal_credits = 0;
        if (isOwnerUser) { normal_credits = 999; }
        else if (plan === 'pro') { normal_credits = Math.max(0, PRO_DAILY_LIMIT - (proQuotaByUser[u.id] || 0)); }
        else {
          const fq = freeQuotaByUser[u.id];
          if (fq && fq.period_end && new Date(fq.period_end) > now) {
            normal_credits = Math.max(0, parseInt(fq.limit || FREE_WEEKLY_LIMIT, 10) - parseInt(fq.used || 0, 10));
          } else { normal_credits = FREE_WEEKLY_LIMIT; }
        }

        const banked_credits = isOwnerUser ? 0 : (bankedByUser[u.id] || 0);

        let churn_risk = 'low';
        if (daysSinceActive > 14) churn_risk = 'high';
        else if (daysSinceActive > 7 && gens.week === 0) churn_risk = 'medium';

        let engagement = 'inactive';
        if (gens.week >= 10 || (postsByUser[u.id] || 0) >= 3) engagement = 'power';
        else if (gens.week >= 3 || daysSinceActive <= 3) engagement = 'active';
        else if (gens.week >= 1 || daysSinceActive <= 7) engagement = 'casual';

        return {
          id: u.id, email: u.email,
          display_name: u.display_name || u.username || 'Unknown',
          full_name: u.full_name, avatar_url: u.avatar_url,
          plan, owner_override: isOwnerUser,
          billing_cycle: subInfo.billing_cycle,
          subscription_status: raw_status || 'free',
          sub_end_at, trial_end_at, auto_renew, is_trial,
          signup_date: u.created_date,
          last_active: u.last_seen_at,
          days_since_active: daysSinceActive,
          onboarding_complete: !!u.onboarding_complete,
          total_generations: gens.total,
          generations_today: gens.today,
          generations_week: gens.week,
          saved_recipes: savedByUser[u.email] || 0,
          posted_recipes: postsByUser[u.id] || 0,
          churn_risk, engagement,
          normal_credits, banked_credits,
          total_credits: normal_credits + banked_credits,
        };
