      const cats = { llm: 0.004, image_generation: 0.02, file_upload: 0.001, email: 0.001, other: 0.002 };
      const enriched = paged.map(log => ({
        ...log,
        user_display: userMap[log.user_id]?.display_name || userMap[log.user_id]?.email || log.user_id || 'system',
        user_email: userMap[log.user_id]?.email,
        estimated_cost_usd: Math.round(((cats[log.cost_category] || 0.002) * (log.estimated_cost_units || 1)) * 10000) / 10000,
      }));

      const totalCost = enriched.reduce((s, l) => s + l.estimated_cost_usd, 0);
