      const users_v = await safeFetch(() => base44.asServiceRole.entities.User.list('-created_date', 500));
      await delay(300);
      const subs_v = await safeFetch(() => base44.asServiceRole.entities.Subscription.list('-created_date', 500));
      await delay(300);
      const gens_v = await safeFetch(() => base44.asServiceRole.entities.AiGenerationEvent.list('-created_date', 2000));
      await delay(200);
      const posts_v = await safeFetch(() => base44.asServiceRole.entities.Post.list('-created_date', 200));
      await delay(200);
      const costs_v = await safeFetch(() => base44.asServiceRole.entities.IntegrationCostLog.list('-timestamp', 500));

      // Filter gens to month in JS
      const monthGens = gens_v.filter(g => g.created_date && g.created_date >= monthStart.toISOString());
      // Filter costs to week in JS
      const weekCosts = costs_v.filter(l => (l.timestamp || l.created_date) >= weekStr);

      const subMap = {}; subs_v.forEach(s => { subMap[s.created_by] = s; });
      const genByUser = {}; monthGens.forEach(g => { genByUser[g.user_id] = (genByUser[g.user_id] || 0) + 1; });
      const postByUser = {}; posts_v.forEach(p => { postByUser[p.author_id] = (postByUser[p.author_id] || 0) + 1; });
      const cats = { llm: 0.004, image_generation: 0.02, file_upload: 0.001, email: 0.001, other: 0.002 };
      const costByUser = {};
      weekCosts.forEach(l => {
        const cost = (cats[l.cost_category] || 0.002) * (l.estimated_cost_units || 1);
        costByUser[l.user_id] = (costByUser[l.user_id] || 0) + cost;
      });

      const churnRisk = users_v.filter(u => {
        if (!u.onboarding_complete) return false;
        const last = new Date(u.last_seen_at || u.created_date);
        const daysSinceSeen = Math.floor((now - last) / 86400000);
        const signupAge = Math.floor((now - new Date(u.created_date)) / 86400000);
        return signupAge >= 14 && daysSinceSeen >= 14 && (genByUser[u.id] || 0) >= 1;
      }).map(u => ({
        id: u.id, email: u.email, name: u.display_name || u.email,
        last_active: u.last_seen_at, gens: genByUser[u.id] || 0,
        days_inactive: Math.floor((now - new Date(u.last_seen_at || u.created_date)) / 86400000),
      })).sort((a, b) => b.days_inactive - a.days_inactive);

      const neverActivated = users_v.filter(u => {
        return Math.floor((now - new Date(u.created_date)) / 86400000) >= 3 && (genByUser[u.id] || 0) === 0;
      }).map(u => ({
        id: u.id, email: u.email, name: u.display_name || u.email,
        signup: u.created_date, onboarding: !!u.onboarding_complete,
        days_since_signup: Math.floor((now - new Date(u.created_date)) / 86400000),
      })).sort((a, b) => b.days_since_signup - a.days_since_signup);

      const conversionOpportunity = users_v.filter(u => {
        const isPaying = subMap[u.email]?.status === 'active';
        return !isPaying && (genByUser[u.id] || 0) >= 10;
      }).map(u => ({ id: u.id, email: u.email, name: u.display_name || u.email, gens: genByUser[u.id] || 0 })).sort((a, b) => b.gens - a.gens);

      const topSpenders = Object.entries(costByUser).sort(([,a],[,b]) => b-a).slice(0,10).map(([uid, cost]) => {
        const u = users_v.find(x => x.id === uid);
        return { user_id: uid, name: u?.display_name || u?.email || uid, email: u?.email, cost_usd: Math.round(cost * 1000) / 1000 };
      });

      const signupTrend = [];
      for (let i = 6; i >= 0; i--) {
        const d = new Date(now); d.setDate(d.getDate() - i); d.setHours(0,0,0,0);
        const end = new Date(d); end.setDate(end.getDate() + 1);
        signupTrend.push({ date: d.toISOString().split('T')[0], count: users_v.filter(u => new Date(u.created_date) >= d && new Date(u.created_date) < end).length });
      }

      return Response.json({
        churn_risk: churnRisk.slice(0, 20), never_activated: neverActivated.slice(0, 20),
        conversion_opportunity: conversionOpportunity.slice(0, 20), top_spenders: topSpenders,
        signup_trend: signupTrend, total_churn_risk: churnRisk.length,
        total_never_activated: neverActivated.length, total_conversion_opportunity: conversionOpportunity.length,
        total_users_analyzed: users_v.length,
        thresholds: { churn_risk: 'onboarded + ≥1 gen ever + inactive 14+ days', never_activated: 'signed up 3+ days ago + zero gens', conversion_opportunity: 'free/trial + 10+ gens/30d' },
      });
    }

    // ── LIVE EVENTS (polling summary patch) ─────────────────────────────────
    if (section === 'live_events') {
      const allUsers = await safeFetch(() => base44.asServiceRole.entities.User.list('-created_date', 1000));
      await delay(200);
      const allGens = await safeFetch(() => base44.asServiceRole.entities.AiGenerationEvent.list('-created_date', 500));
      await delay(200);
      const proUsers = await safeFetch(() => base44.asServiceRole.entities.Subscription.filter({ status: 'active' }, '-created_date', 500));

      const todayGens = allGens.filter(g => g.created_date && g.created_date >= todayStr);
      const signupsToday = allUsers.filter(u => u.created_date && u.created_date >= todayStr);
      const activeUserIds = new Set(todayGens.map(g => g.user_id));

      return Response.json({
        events: [],
        summary_patch: {
          new_signups_today: signupsToday.length,
          active_today: activeUserIds.size,
          total_generations_today: todayGens.length,
          pro_users: proUsers.length,
          total_users: allUsers.length,
          free_users: allUsers.length - proUsers.length,
          conversion_rate: allUsers.length > 0 ? Math.round((proUsers.length / allUsers.length) * 100) : 0,
        },
        recent_signups: signupsToday.slice(0, 20).map(u => ({
          id: u.id, email: u.email,
          display_name: u.display_name || u.full_name || u.username || 'Unknown',
          full_name: u.full_name, username: u.username, avatar_url: u.avatar_url,
          created_date: u.created_date, onboarding_complete: !!u.onboarding_complete,
          plan: 'free', last_active: u.last_seen_at || u.updated_date,
        })),
