    const periodStartISO = periodStart.toISOString();
    const periodEndISO = periodEnd.toISOString();

    // Fetch ALL quota records for this user+period (there may be duplicates from race conditions).
    // Pick the one with the HIGHEST `used` value — that is the authoritative one.
    // Clean up duplicates in the background to prevent future confusion.
    const allQuotas = await base44.asServiceRole.entities.AiGenerationQuota.filter(
      { user_id: user.id, period_start: periodStartISO },
      null,
      20
    );

    let quota = null;
    if (allQuotas.length > 0) {
      // AUTHORITATIVE: pick the record with the highest `used` count.
      // This is the one that was actually incremented by generateRecipeWithQuota.
      allQuotas.sort((a, b) => (b.used || 0) - (a.used || 0));
      quota = allQuotas[0];

      // DEDUP: delete all other records for this user+period to prevent future mismatch
      if (allQuotas.length > 1) {
        console.warn(`[getAiQuotaAdvanced] DEDUP: found ${allQuotas.length} records for user=${user.id} period=${periodStartISO}, keeping id=${quota.id} (used=${quota.used})`);
        for (let i = 1; i < allQuotas.length; i++) {
          base44.asServiceRole.entities.AiGenerationQuota.delete(allQuotas[i].id).catch(() => {});
        }
      }
    }

    if (!quota) {
      // No record for this period — try to create. If creation fails (race condition /
      // duplicate key because generateRecipeWithQuota created one concurrently),
      // RE-FETCH from DB instead of falling back to a hardcoded used:0 default.
      // The old code had: .catch(() => null) || { used: 0 } — which silently
      // returned remaining=2 even when the real record had used>0.
      try {
        quota = await base44.asServiceRole.entities.AiGenerationQuota.create({
          user_id: user.id,
          period_start: periodStartISO,
          period_end: periodEndISO,
          limit: WEEKLY_LIMIT,
          used: 0,
          timezone: userTz,
          updated_at: serverNowISO,
        });
      } catch (createErr) {
        // Create failed (likely duplicate key) — re-fetch the record that must exist
        console.warn(`[getAiQuotaAdvanced] Create failed (race): ${createErr.message} — re-fetching`);
        const retryRecords = await base44.asServiceRole.entities.AiGenerationQuota.filter(
          { user_id: user.id, period_start: periodStartISO }, null, 5
        ).catch(() => []);
        if (retryRecords.length > 0) {
          retryRecords.sort((a, b) => (b.used || 0) - (a.used || 0));
          quota = retryRecords[0];
        }
      }
      // LAST RESORT: if still null after create + re-fetch, use safe default
      // but this should never happen in practice
      if (!quota) {
        console.error('[getAiQuotaAdvanced] CRITICAL: could not create or fetch quota record');
        quota = { limit: WEEKLY_LIMIT, used: 0, period_start: periodStartISO, period_end: periodEndISO };
      }
    }
    // CRITICAL: Never reset an existing record here.
    // The record's used count is ONLY modified by generateRecipeWithQuota when credits are consumed.
    // getAiQuotaAdvanced is READ-ONLY for the used field.

    const used = quota.used || 0;
    // STRICT: Always report WEEKLY_LIMIT as the cap, never a mutated limit.
    const limit = WEEKLY_LIMIT;
    const remaining = Math.max(0, limit - used);
    const totalAvailable = remaining + bankedCredits;

    console.log(`[getAiQuotaAdvanced] free user=${user.id} used=${used}/${limit} banked=${bankedCredits} period_start=${periodStart.toISOString()}`);

    return Response.json({
      is_premium: false,
      owner_override: false,
      billing_source: 'none',
      limit,
      used,
      remaining,
      total_available: totalAvailable,
      banked_referral_credits: bankedCredits,
      period_start: periodStartISO,
      period_end: periodEndISO,
      resets_at: periodEndISO,
      next_reset_at: periodEndISO,
      timezone: userTz,
      server_time: serverNowISO,
    });
  } catch (err) {
    console.error('[getAiQuotaAdvanced]', err.message);
    return Response.json({ error: err.message }, { status: 500 });
  }
});

function getWeekWindow(date) {
  // ALWAYS use UTC midnight for period_start — this is the canonical key stored in DB.
  // Never apply timezone offsets here: doing so creates mismatched keys between functions
  // (e.g. Jerusalem users get '2026-03-29T22:00:00Z' instead of '2026-03-30T00:00:00Z',
  //  the filter finds no record, creates a fresh used=0 record → displays wrong state).
  const dayOfWeek = date.getUTCDay(); // 0=Sun, 1=Mon, ..., 6=Sat
  // Week starts Monday: subtract days to reach Monday
  const daysToSubtract = dayOfWeek === 0 ? 6 : dayOfWeek - 1;

  const periodStart = new Date(date);
  periodStart.setUTCDate(periodStart.getUTCDate() - daysToSubtract);
  periodStart.setUTCHours(0, 0, 0, 0);

  const periodEnd = new Date(periodStart);
  periodEnd.setUTCDate(periodEnd.getUTCDate() + 7);

  return { periodStart, periodEnd };
}

