/**
 * getCommunityFeedReliable v2 — USER-SCOPED RELIABLE FEED
 *
 * UPGRADE from v1:
 *   v1 had a global in-process cache that shared feed ordering across users.
 *   v2 removes that shared cache entirely. All caching is user-scoped.
 *
 * FALLBACK CHAIN (all user-aware):
 *   1. Primary: getForYouFeedCached (personalized, user-scoped cache)
 *   2. Fallback: Direct entity query with viewer-safe filtering
 *   3. Never returns a shared/global cached ordering
 *   4. Recovery: empty array only after authoritative exhaustion
 */
import { createClientFromRequest } from 'npm:@base44/sdk@0.8.25';

const CONFIG = {
  FETCH_TIMEOUT: 8000,
  MAX_POSTS: 50,
};

function sanitizePostArray(posts) {
  if (!Array.isArray(posts)) return [];
  return posts
    .filter(p => {
      if (!p || !p.id) return false;
      if (!p.title) p.title = 'Untitled Recipe';
      if (!p.likes_count) p.likes_count = 0;
      if (!p.created_date) p.created_date = new Date().toISOString();
      return true;
    })
    .slice(0, CONFIG.MAX_POSTS);
}

async function withTimeout(promise, ms, name) {
  return Promise.race([
    promise,
    new Promise((_, reject) => setTimeout(() => reject(new Error(`${name} timed out after ${ms}ms`)), ms)),
  ]);
}

async function fetchFromPrimaryAlgorithm(base44, userId) {
  try {
    console.log(`[PRIMARY] Invoking getForYouFeedCached for user=${userId}`);
    const res = await withTimeout(
      base44.asServiceRole.functions.invoke('getForYouFeedCached', { limit: CONFIG.MAX_POSTS }),
      CONFIG.FETCH_TIMEOUT,
      'PRIMARY'
    );
    const posts = res?.data?.posts;
    if (!Array.isArray(posts) || posts.length === 0) {
      console.warn(`[PRIMARY] No posts returned`);
      return null;
    }
    console.log(`[PRIMARY] ✓ ${posts.length} posts`);
    return sanitizePostArray(posts);
  } catch (err) {
    console.error(`[PRIMARY] ✗ Failed:`, err.message);
    return null;
  }
}

async function fetchFromDirectEntity(base44, userId) {
  try {
    console.log(`[ENTITY] Fetching posts directly from Recipe entity`);
    // Try with moderation_status filter first, fall back to just is_public
    let posts;
    try {
      posts = await withTimeout(
        base44.asServiceRole.entities.Recipe.filter(
          { is_public: true, moderation_status: 'active' },
          '-created_date',
          200
        ),
        CONFIG.FETCH_TIMEOUT,
        'ENTITY_ACTIVE'
      );
    } catch {
      // Fallback: query without moderation_status (older recipes may not have it)
      posts = await withTimeout(
        base44.asServiceRole.entities.Recipe.filter(
          { is_public: true },
          '-created_date',
          200
        ),
        CONFIG.FETCH_TIMEOUT,
        'ENTITY_FALLBACK'
      );
    }
    if (!Array.isArray(posts) || posts.length === 0) {
      console.warn(`[ENTITY] No posts found`);
      return null;
    }

    // Viewer-specific filtering: blocked users
    let blockedIds = new Set();
    if (userId) {
      const [blockedByMe, blockedByOthers] = await Promise.all([
        base44.asServiceRole.entities.BlockedUser.filter({ blocker_id: userId }).catch(() => []),
        base44.asServiceRole.entities.BlockedUser.filter({ blocked_id: userId }).catch(() => []),
      ]);
      blockedIds = new Set([
        ...blockedByMe.map(b => b.blocked_id),
        ...blockedByOthers.map(b => b.blocker_id),
      ]);
    }

    const eligible = posts.filter(p =>
      p.moderation_status !== 'removed_by_moderation' &&
      p.community_visible !== false &&
      p.author_account_status !== 'suspended' &&
      p.author_account_status !== 'deleted' &&
      (!p.author_id || !blockedIds.has(p.author_id))
    );

    const ranked = eligible
      .map(p => ({ ...p, _score: (p.likes_count || 0) * 2 + (p.saves_count || 0) * 3 + (p.comment_count || 0) * 1.5 }))
      .sort((a, b) => b._score - a._score);

    // FEED ORDER: pin the top 2 highest-scoring posts, then shuffle the rest
    // so the community feed never feels strictly "popular top to bottom".
    const top2 = ranked.slice(0, 2);
    const tail = ranked.slice(2);
    for (let i = tail.length - 1; i > 0; i--) {
      const j = Math.floor(Math.random() * (i + 1));
      [tail[i], tail[j]] = [tail[j], tail[i]];
    }
    const finalOrder = [...top2, ...tail];

    // RATE LIMIT FIX: Skip viewer_has_liked enrichment — frontend resolves it
    // via useLikeUnified (cached, single query). Saves 2+ entity queries per call.
    console.log(`[ENTITY] ✓ ${finalOrder.length} posts (${posts.length} raw, top2 pinned + shuffled tail)`);
    return sanitizePostArray(finalOrder);
  } catch (err) {
    console.error(`[ENTITY] ✗ Failed:`, err.message);
    return null;
  }
}

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();

    if (!user?.id) {
      return Response.json({ ok: false, error: 'Unauthorized' }, { status: 401 });
    }

    console.log(`[FEED:START] userId=${user.id}`);
    const startTime = Date.now();

    // Layer 1: Primary personalized algorithm (user-scoped cache inside)
    // RATE LIMIT FIX: Do NOT enrich viewer_has_liked here — frontend cards resolve
    // like state via useLikeUnified which is more efficient (single query, cached).
    // This removes 2-3 extra entity queries per feed load.
    const primary = await fetchFromPrimaryAlgorithm(base44, user.id);
    if (primary?.length > 0) {
      console.log(`[FEED:SUCCESS] ${primary.length} posts in ${Date.now() - startTime}ms (primary)`);
      return Response.json({ ok: true, posts: primary, source: 'primary', latency: Date.now() - startTime });
    }

    // Layer 2: Direct entity fallback (viewer-safe)
    const entity = await fetchFromDirectEntity(base44, user.id);
    if (entity?.length > 0) {
      console.log(`[FEED:SUCCESS] ${entity.length} posts in ${Date.now() - startTime}ms (entity_fallback)`);
      return Response.json({ ok: true, posts: entity, source: 'entity_fallback', latency: Date.now() - startTime });
    }

    // Layer 3: Ultra-simple last-resort — just get the 30 newest public recipes, no ranking
    try {
      console.log('[LAST-RESORT] Attempting bare-minimum entity query');
      const lastResort = await base44.asServiceRole.entities.Recipe.filter(
        { is_public: true, moderation_status: 'active' },
        '-created_date',
        30
      );
      if (Array.isArray(lastResort) && lastResort.length > 0) {
