        ));
        if (safe.length > 0) {
          console.log(`[LAST-RESORT] ✓ ${safe.length} posts recovered`);
          return Response.json({ ok: true, posts: safe, source: 'last_resort', latency: Date.now() - startTime });
        }
      }
    } catch (lrErr) {
      console.error('[LAST-RESORT] ✗ Failed:', lrErr.message);
    }

    // Layer 4: Authoritative empty — log reason for observability
    console.error(`[FEED:FINAL] All 3 sources exhausted, returning empty`);
    try {
      await base44.asServiceRole.functions.invoke('logBackendError', {
        function_name: 'getCommunityFeedReliable',
        error_category: 'feed_failure',
        error_message: 'All 3 feed layers (primary + entity + last-resort) returned 0 posts',
        page_surface: 'Community',
        severity: 'critical',
        normalized_reason: 'All feed layers exhausted — possible rate limit cascade or truly empty DB',
        fallback_used: true,
        fallback_succeeded: false,
      });
    } catch {}
    return Response.json({ ok: true, posts: [], source: 'empty_fallback', latency: Date.now() - startTime });

  } catch (err) {
    console.error(`[FEED:ERROR] Unhandled exception:`, err.message);
    // Log to observability
    try {
      await base44.asServiceRole.functions.invoke('logBackendError', {
        function_name: 'getCommunityFeedReliable',
        error_category: err?.status === 429 ? 'rate_limit' : 'feed_failure',
        error_message: err?.message || 'Unknown error',
        page_surface: 'Community',
        severity: 'critical',
        normalized_reason: 'Both primary + entity fallback exhausted',
        fallback_used: true,
        fallback_succeeded: false,
      });
    } catch {}
    return Response.json({ ok: true, posts: [], source: 'error_fallback', error: err.message });
  }
});

/**
 * Task D: Get community stats for user in a date range
 * Backend source of truth for likes, followers, ratings
 * Used by Home Stats modal
 */
import { createClientFromRequest } from 'npm:@base44/sdk@0.8.20';

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user) return Response.json({ error: 'Unauthorized' }, { status: 401 });

    const body = await req.json().catch(() => ({}));
    const userId = body.userId || user.id;
    const fromDate = body.from ? new Date(body.from) : new Date(Date.now() - 30 * 24 * 60 * 60 * 1000);
    const toDate = body.to ? new Date(body.to) : new Date();

    // Validate date range (max 90 days)
    const daysDiff = (toDate - fromDate) / (1000 * 60 * 60 * 24);
    if (daysDiff > 90) {
      return Response.json({ error: 'Date range cannot exceed 90 days' }, { status: 400 });
    }

    // Fetch the user whose stats we're viewing
    const viewedUser = await base44.asServiceRole.entities.User.filter({ id: userId }).then(u => u[0]);
    if (!viewedUser) {
      return Response.json({ error: 'User not found' }, { status: 404 });
    }

    // Get all recipes created by this user
    const userRecipes = await base44.asServiceRole.entities.Recipe.filter(
      { created_by: viewedUser.email },
      null,
      1000
    );

    // Total followers (current, not time-limited unless we store follower events)
    const followerRecords = await base44.asServiceRole.entities.UserFollow.filter(
      { following_id: userId, status: 'accepted' }
    );
    const followersTotal = followerRecords.length;

    // Likes in range
    const likesInRange = userRecipes.reduce((sum, r) => {
      if (r.created_date) {
        const recipeDate = new Date(r.created_date);
        if (recipeDate >= fromDate && recipeDate <= toDate) {
          return sum + (r.likes_count || 0);
        }
      }
      return sum;
    }, 0);

    // Ratings in range
    let ratingsCountInRange = 0;
    let ratingsAvgInRange = 0;
    const ratedRecipesInRange = userRecipes.filter(r => {
      if (r.created_date) {
        const recipeDate = new Date(r.created_date);
        return recipeDate >= fromDate && recipeDate <= toDate;
      }
      return false;
    });

    const ratingsInRange = ratedRecipesInRange.filter(r => r.review_count > 0);
    if (ratingsInRange.length > 0) {
      ratingsCountInRange = ratingsInRange.reduce((sum, r) => sum + (r.review_count || 0), 0);
      ratingsAvgInRange = ratingsInRange.reduce((sum, r) => sum + (r.avg_rating || 0), 0) / ratingsInRange.length;
    }

    // Timeseries (daily buckets)
    const timeseries = [];
    for (let d = new Date(fromDate); d <= toDate; d.setDate(d.getDate() + 1)) {
      const dateKey = d.toISOString().split('T')[0];
      const dayLikes = userRecipes.reduce((sum, r) => {
        if (r.created_date) {
          const recipeDate = new Date(r.created_date).toISOString().split('T')[0];
          if (recipeDate === dateKey) {
            return sum + (r.likes_count || 0);
          }
        }
        return sum;
      }, 0);

      const dayRatings = userRecipes.reduce((sum, r) => {
        if (r.created_date) {
          const recipeDate = new Date(r.created_date).toISOString().split('T')[0];
          if (recipeDate === dateKey) {
            return sum + (r.review_count || 0);
          }
        }
        return sum;
      }, 0);

      timeseries.push({
        date: dateKey,
        likes: dayLikes,
        ratings_count: dayRatings,
        followers_delta: null, // Would need separate event tracking
      });
    }

    return Response.json({
      followers_total: followersTotal,
      likes_total_in_range: likesInRange,
      ratings_count_in_range: ratingsCountInRange,
      ratings_avg_in_range: Number(ratingsAvgInRange.toFixed(2)),
      timeseries,
    });
  } catch (error) {
    console.error('[getCommunityStats] error:', error);
    return Response.json({ error: error.message }, { status: 500 });
  }
});

/**
 * getCostMonitorData — Admin-only backend for the Cost Monitor page.
 *
 * Returns:
 *   - recent: last N SystemEventLog entries (default 100)
 *   - summary: aggregate counts/credits by event_type, provider, endpoint
 *   - violations: entries with allowed_scope !== 'allowed'
 *
 * Accepts filters: { minutes, event_type, provider_name, endpoint_name,
 *                    user_id, origin, unknown_cost_only, limit }
 */
import { createClientFromRequest } from 'npm:@base44/sdk@0.8.25';

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user || user.role !== 'admin') {
      return Response.json({ error: 'Forbidden: Admin access required' }, { status: 403 });
    }

    const body = await req.json().catch(() => ({}));
    const {
      minutes = 30,
      event_type,
      provider_name,
      endpoint_name,
      model_name,
      user_id: filterUserId,
      origin,
      unknown_cost_only = false,
      limit = 100,
    } = body;

    const sr = base44.asServiceRole;

    // Build filter — SystemEventLog.filter only supports exact field match
    const filter = {};
    if (event_type) filter.event_type = event_type;
    if (provider_name) filter.provider_name = provider_name;
    if (endpoint_name) filter.endpoint_name = endpoint_name;
    if (model_name) filter.model_name = model_name;
    if (filterUserId) filter.user_id = filterUserId;
    if (origin) filter.origin = origin;
    if (unknown_cost_only) filter.raw_cost_source = 'COST_DATA_UNAVAILABLE';

    // Fetch recent entries sorted by newest first
    const allEntries = await sr.entities.SystemEventLog.filter(
      filter, '-created_date', Math.min(limit, 500)
    ).catch(() => []);

    // Time-window filter (client-side since DB filter doesn't support date ranges)
    const cutoff = new Date(Date.now() - minutes * 60 * 1000);
    const recent = allEntries.filter(e => new Date(e.created_date) >= cutoff);

    // ── SUMMARY AGGREGATION ──────────────────────────────────────────────────
    const byEventType = {};
    const byProvider = {};
    const byEndpoint = {};
    let totalCredits = 0;
    let totalEvents = recent.length;
    let unknownCostCount = 0;
    let failedCount = 0;

    for (const e of recent) {
      // By event_type
      const et = e.event_type || 'unknown';
      if (!byEventType[et]) byEventType[et] = { count: 0, credits: 0 };
      byEventType[et].count++;
      byEventType[et].credits += e.credits_used || 0;

      // By provider
      const pn = e.provider_name || 'unknown';
      if (!byProvider[pn]) byProvider[pn] = { count: 0, credits: 0 };
      byProvider[pn].count++;
      byProvider[pn].credits += e.credits_used || 0;

      // By endpoint
      const en = e.endpoint_name || 'unknown';
      if (!byEndpoint[en]) byEndpoint[en] = { count: 0, credits: 0 };
      byEndpoint[en].count++;
      byEndpoint[en].credits += e.credits_used || 0;

      totalCredits += e.credits_used || 0;
      if (e.raw_cost_source === 'COST_DATA_UNAVAILABLE') unknownCostCount++;
      if (!e.success) failedCount++;
    }

    // ── VIOLATIONS ───────────────────────────────────────────────────────────
    const violations = recent.filter(e => e.allowed_scope && e.allowed_scope !== 'allowed');

    return Response.json({
      recent: recent.slice(0, limit),
      summary: {
        total_events: totalEvents,
        total_credits: totalCredits,
        unknown_cost_count: unknownCostCount,
        failed_count: failedCount,
        by_event_type: byEventType,
        by_provider: byProvider,
        by_endpoint: byEndpoint,
      },
      violations,
      window_minutes: minutes,
    });
  } catch (err) {
    console.error('[getCostMonitorData] error:', err.message);
    return Response.json({ error: err.message }, { status: 500 });
  }
});

