import { createClientFromRequest } from 'npm:@base44/sdk@0.8.23';

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user) return Response.json({ error: 'Unauthorized' }, { status: 401 });

    // ── PRO GATING (backend authoritative — mirrors getEntitlements logic exactly) ──
    const subs = await base44.asServiceRole.entities.Subscription.filter({ created_by: user.email }).catch(() => []);
    const nowMs = Date.now();
    const ENTITLED_PLAN_TYPES = new Set(['pro', 'vip', 'trial']);
    const activeSub = subs.find(s => {
      if (!ENTITLED_PLAN_TYPES.has(s.plan_type)) return false;
      if (s.status === 'active' || s.status === 'trialing') return true;
      if (s.status === 'canceled' && s.current_period_end) return new Date(s.current_period_end).getTime() > nowMs;
      if (s.status === 'canceled' && s.expires_at) return new Date(s.expires_at).getTime() > nowMs;
      return false;
    });
    const isPro = !!activeSub;
    if (!isPro) return Response.json({ error: 'Pro required', code: 'NOT_PRO' }, { status: 403 });

    const body = await req.json().catch(() => ({}));
    const range = body.range || '30d';

    // Compute range start boundary
    const now = new Date();
    let rangeStart = null;
    if (range === '7d') { rangeStart = new Date(now); rangeStart.setDate(rangeStart.getDate() - 7); }
    else if (range === '30d') { rangeStart = new Date(now); rangeStart.setDate(rangeStart.getDate() - 30); }

    const inRange = (dateStr) => {
      if (!rangeStart || !dateStr) return true;
      return new Date(dateStr) >= rangeStart;
    };

    // ── STEP 1: Fetch all creator's public recipes ─────────────────────────────
    const allRecipes = await base44.asServiceRole.entities.Recipe.filter(
      { author_id: user.id, is_public: true }, '-created_date', 200
    ).catch(() => []);

    const recipeIds = allRecipes.map(r => r.id);

    if (recipeIds.length === 0) {
      // No recipes — still fetch followers and shop
      const [allFollowers, shopArr] = await Promise.all([
        base44.asServiceRole.entities.Follow.filter({ followed_id: user.id, status: 'accepted' }).catch(() => []),
        base44.asServiceRole.entities.Shop.filter({ owner_id: user.id }).catch(() => []),
      ]);
      return Response.json({
        overview: {
          totalLikes: 0, totalSaves: 0, totalFollowers: allFollowers.length,
          totalPosts: 0, totalRatings: 0, avgRating: 0,
          rangeNewPosts: 0, rangeNewLikes: 0, rangeNewSaves: 0,
          rangeNewFollowers: allFollowers.filter(f => inRange(f.created_date)).length,
          rangeNewReviews: 0,
        },
        contentPerformance: [],
        topPerformers: { mostLiked: null, mostSaved: null, highestRated: null, mostRecent: null },
        dailyTrend: buildDailyTrend(range, now, [], [], []),
        shopAnalytics: null,
        range,
      });
    }

    // ── STEP 2: Fetch all engagement data — chunked to avoid rate limits ─────
    // Chunk array into groups and fetch sequentially between groups
    const chunk = (arr, size) => {
      const out = [];
      for (let i = 0; i < arr.length; i += size) out.push(arr.slice(i, i + size));
      return out;
    };

    const batchFetch = async (entityFn, idField, ids, chunkSize = 5) => {
      const chunks = chunk(ids, chunkSize);
      const results = [];
      for (const ch of chunks) {
        const chunkResults = await Promise.all(
          ch.map(id => entityFn({ [idField]: id }).catch(() => []))
        );
        results.push(...chunkResults.flat());
        // Small pause between chunks to avoid rate limiting
        if (chunks.length > 1) await new Promise(r => setTimeout(r, 100));
      }
      return results;
    };

    const [allFollowers, allLikes, allSaves, allReviews, shopArr] = await Promise.all([
      base44.asServiceRole.entities.Follow.filter({ followed_id: user.id, status: 'accepted' }).catch(() => []),
      batchFetch(base44.asServiceRole.entities.RecipeLike.filter.bind(base44.asServiceRole.entities.RecipeLike), 'recipe_id', recipeIds),
      batchFetch(base44.asServiceRole.entities.RecipeSave.filter.bind(base44.asServiceRole.entities.RecipeSave), 'recipe_id', recipeIds),
      batchFetch(base44.asServiceRole.entities.RecipeReview.filter.bind(base44.asServiceRole.entities.RecipeReview), 'recipe_id', recipeIds),
      base44.asServiceRole.entities.Shop.filter({ owner_id: user.id }).catch(() => []),
    ]);

    const shop = shopArr[0] || null;

    // ── STEP 3: Build per-recipe index ─────────────────────────────────────────
    const likesByRecipe = {};
    allLikes.forEach(l => { likesByRecipe[l.recipe_id] = (likesByRecipe[l.recipe_id] || 0) + 1; });

    const savesByRecipe = {};
    allSaves.forEach(s => { savesByRecipe[s.recipe_id] = (savesByRecipe[s.recipe_id] || 0) + 1; });

    const reviewsByRecipe = {};
    allReviews.forEach(r => {
      if (!reviewsByRecipe[r.recipe_id]) reviewsByRecipe[r.recipe_id] = { count: 0, ratingSum: 0 };
      reviewsByRecipe[r.recipe_id].count++;
      reviewsByRecipe[r.recipe_id].ratingSum += (r.rating || 0);
    });

    // ── STEP 4: Content performance list ──────────────────────────────────────
    // Engagement Score = likes×3 + saves×3 + reviewCount×2
    const contentPerformance = allRecipes.map(r => {
      const likes = likesByRecipe[r.id] || 0;
      const saves = savesByRecipe[r.id] || 0;
      const rv = reviewsByRecipe[r.id] || { count: 0, ratingSum: 0 };
      const avgRating = rv.count > 0 ? Math.round((rv.ratingSum / rv.count) * 10) / 10 : 0;
      const engagementScore = likes * 3 + saves * 3 + rv.count * 2;
      return {
        id: r.id,
        title: r.title,
        heroImage: r.hero_image_url || null,
        createdDate: r.created_date,
        likes,
        saves,
        ratingCount: rv.count,
        avgRating,
        engagementScore,
      };
    }).sort((a, b) => b.engagementScore - a.engagementScore);

    // ── STEP 5: Overview totals (all-time, authoritative) ─────────────────────
    const totalLikes = allLikes.length;
    const totalSaves = allSaves.length;
    const totalFollowers = allFollowers.length;
    const totalPosts = allRecipes.length;
    const totalRatings = allReviews.length;
    const avgRatingAll = totalRatings > 0
      ? Math.round((allReviews.reduce((s, r) => s + (r.rating || 0), 0) / totalRatings) * 10) / 10
      : 0;

    // Range-scoped deltas
    const rangeNewPosts = allRecipes.filter(r => inRange(r.created_date)).length;
    const rangeNewLikes = allLikes.filter(l => inRange(l.created_date)).length;
    const rangeNewSaves = allSaves.filter(s => inRange(s.created_date)).length;
    const rangeNewFollowers = allFollowers.filter(f => inRange(f.created_date)).length;
    const rangeNewReviews = allReviews.filter(r => inRange(r.created_date)).length;

    // ── STEP 6: Top performers ─────────────────────────────────────────────────
    const sortedByLikes = [...contentPerformance].sort((a, b) => b.likes - a.likes);
    const sortedBySaves = [...contentPerformance].sort((a, b) => b.saves - a.saves);
    const sortedByRating = [...contentPerformance].filter(r => r.ratingCount > 0).sort((a, b) => b.avgRating - a.avgRating);
    const sortedByRecent = [...contentPerformance].sort((a, b) => new Date(b.createdDate) - new Date(a.createdDate));

    const topPerformers = {
      mostLiked: sortedByLikes[0] || null,
      mostSaved: sortedBySaves[0] || null,
      highestRated: sortedByRating[0] || null,
      mostRecent: sortedByRecent[0] || null,
    };

    // ── STEP 7: Daily trend data ───────────────────────────────────────────────
    const dailyTrend = buildDailyTrend(range, now, allLikes, allSaves, allFollowers);

    // ── STEP 8: Shop analytics ─────────────────────────────────────────────────
    let shopAnalytics = null;
    if (shop) {
      const shopFollowers = await base44.asServiceRole.entities.ShopFollow.filter({ shop_id: shop.id }).catch(() => []);
      const shopRecipeIds = allRecipes.filter(r => r.shop_id === shop.id).map(r => r.id);
      const shopLikes = allLikes.filter(l => shopRecipeIds.includes(l.recipe_id)).length;
      const shopSaves = allSaves.filter(s => shopRecipeIds.includes(s.recipe_id)).length;
      const shopReviews = allReviews.filter(r => shopRecipeIds.includes(r.recipe_id));
      const shopAvgRating = shopReviews.length > 0
        ? Math.round((shopReviews.reduce((s, r) => s + (r.rating || 0), 0) / shopReviews.length) * 10) / 10
        : 0;
      shopAnalytics = {
        shopName: shop.shop_name,
        followers: shopFollowers.length,
        totalRecipes: shopRecipeIds.length,
        totalLikes: shopLikes,
        totalSaves: shopSaves,
        avgRating: shopAvgRating,
        totalRatings: shopReviews.length,
      };
    }

    return Response.json({
      overview: {
        totalLikes, totalSaves, totalFollowers, totalPosts, totalRatings, avgRating: avgRatingAll,
        rangeNewPosts, rangeNewLikes, rangeNewSaves, rangeNewFollowers, rangeNewReviews,
      },
      contentPerformance: contentPerformance.slice(0, 20),
      topPerformers,
      dailyTrend,
      shopAnalytics,
      range,
    });
  } catch (error) {
    console.error('[getCreatorAnalytics]', error?.message);
    return Response.json({ error: error.message }, { status: 500 });
  }
});

function buildDailyTrend(range, now, allLikes, allSaves, allFollowers) {
  const trendDays = range === '7d' ? 7 : 30;
  const result = [];
  for (let i = trendDays - 1; i >= 0; i--) {
    const day = new Date(now);
    day.setDate(day.getDate() - i);
    const dayStr = day.toISOString().slice(0, 10);
    result.push({
      date: day.toLocaleDateString('en-US', { month: 'short', day: 'numeric' }),
      likes: allLikes.filter(l => l.created_date?.slice(0, 10) === dayStr).length,
      saves: allSaves.filter(s => s.created_date?.slice(0, 10) === dayStr).length,
      followers: allFollowers.filter(f => f.created_date?.slice(0, 10) === dayStr).length,
    });
  }
  return result;
}

/**
 * getDirectConversations — Returns all DirectConversation records for current user.
 *
 * GET /getDirectConversations
 *
 * Returns conversations where current user is participant_a OR participant_b,
 * sorted by last_message_at descending.
 * Resolves the other participant's current profile for display.
 */
import { createClientFromRequest } from 'npm:@base44/sdk@0.8.20';

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user) return Response.json({ error: 'Unauthorized' }, { status: 401 });

    const sr = base44.asServiceRole;

    // Fetch both sides in parallel
    const [asA, asB] = await Promise.all([
      sr.entities.DirectConversation.filter({ participant_a_id: user.id }, '-last_message_at', 100),
      sr.entities.DirectConversation.filter({ participant_b_id: user.id }, '-last_message_at', 100),
    ]);

    // Merge, deduplicate by conversation_key (the actual canonical field)
    const seen = new Set();
    const all = [];
    for (const c of [...asA, ...asB]) {
      const key = c.conversation_key || c.id;
      if (!seen.has(key)) {
        seen.add(key);
        all.push(c);
      }
    }

    if (all.length === 0) {
      return Response.json({ conversations: [] });
    }

    // Fetch block list so we can filter blocked conversations
    const [blockedByMe, blockedByThem] = await Promise.all([
      sr.entities.BlockedUser.filter({ blocker_id: user.id }),
      sr.entities.BlockedUser.filter({ blocked_id: user.id }),
    ]);
    const blockedIds = new Set([
      ...blockedByMe.map(b => b.blocked_id),
      ...blockedByThem.map(b => b.blocker_id),
    ]);

    // Build output — use denormalized name/avatar from conversation record
    // (these are refreshed on every message send)
    const isUserA = (c) => c.participant_a_id === user.id;

    // is_request and request_recipient_id are the actual schema fields
    const isRequestForMe = (c) => c.is_request === true && c.request_recipient_id === user.id;

    const conversations = all
      .filter(c => {
        const otherId = isUserA(c) ? c.participant_b_id : c.participant_a_id;
        return !blockedIds.has(otherId);
      })
      .map(c => {
        const otherId = isUserA(c) ? c.participant_b_id : c.participant_a_id;
        const otherName = isUserA(c) ? c.participant_b_name : c.participant_a_name;
        const otherAvatar = isUserA(c) ? c.participant_b_avatar : c.participant_a_avatar;
        const convKey = c.conversation_key || c.id;
        return {
          id: c.id,
          conversation_key: convKey,
          other_user_id: otherId,
          other_user_name: otherName || 'User',
          other_user_avatar: otherAvatar || '',
          last_message_text: c.last_message_text || '',
          last_message_at: c.last_message_at || c.created_date,
          last_message_sender_id: c.last_message_sender_id || '',
          is_request: isRequestForMe(c),
        };
      })
      .sort((a, b) => new Date(b.last_message_at) - new Date(a.last_message_at));

    return Response.json({ conversations });

  } catch (err) {
    console.error('[getDirectConversations]', err.message);
    return Response.json({ error: err.message }, { status: 500 });
  }
});

/**
 * getEnforcementConfig — Admin-only: read current enforcement mode + allowlist.
 */
import { createClientFromRequest } from 'npm:@base44/sdk@0.8.25';

// Mirror of the allowlist in costEnforcementPolicy (source of truth is there)
const ALLOWLIST = [
  'ai_recipe:generateRecipeWithQuota:Core.InvokeLLM',
