/**
 * getEntitlements — Server-authoritative entitlement endpoint.
 * 
 * OWNER OVERRIDE: xenodekuu@gmail.com is always Pro (owner_override).
 * This is the ONLY place where owner override is applied — all other
 * entitlement checks in all other functions also call this pattern.
 */

const OWNER_EMAIL = 'xenodekuu@gmail.com';

async function withRetry(fn, maxAttempts = 3) {
  for (let attempt = 1; attempt <= maxAttempts; attempt++) {
    try {
      return await fn();
    } catch (err) {
      const isRateLimit = err?.message?.includes('429') || err?.message?.includes('Rate limit') || err?.status === 429;
      if (isRateLimit && attempt < maxAttempts) {
        const delay = attempt * 600;
        console.warn(`[getEntitlements] Rate limit hit (attempt ${attempt}/${maxAttempts}), retrying in ${delay}ms`);
        await new Promise(r => setTimeout(r, delay));
        continue;
      }
      throw err;
    }
  }
}

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();

    if (!user) {
      return Response.json({ error: 'Unauthorized' }, { status: 401 });
    }

    const now = Date.now();

    // ── OWNER OVERRIDE: xenodekuu@gmail.com is always Pro ──────────────────
    const isOwner = user.email === OWNER_EMAIL;

    let isPro = isOwner; // Owner is always Pro
    let activeSub = null;
    let billingSource = isOwner ? 'owner_override' : 'none';

    if (!isOwner) {
      // ─── Fetch subscriptions with retry to handle rate limits ──────────────
      const subs = await withRetry(() =>
        base44.asServiceRole.entities.Subscription.filter({ created_by: user.email })
      ).catch(() => []);

      const ENTITLED_PLAN_TYPES = new Set(['pro', 'vip', 'trial']);
      const ENTITLED_STATUSES = new Set(['active', 'active_paid', 'trialing', 'grace_period']);
      activeSub = subs.find(s => {
        if (!ENTITLED_PLAN_TYPES.has(s.plan_type)) return false;
        if (ENTITLED_STATUSES.has(s.status)) return true;
        if (s.status === 'canceled' || s.status === 'canceled_pending_expiry') {
          if (s.current_period_end && new Date(s.current_period_end).getTime() > now) return true;
          if (s.expires_at && new Date(s.expires_at).getTime() > now) return true;
        }
        return false;
      });

      isPro = !!activeSub;
      if (activeSub) {
        billingSource = activeSub.payment_provider || 'subscription';
      }
    }

    console.log(`[getEntitlements] user=${user.id} email=${user.email} isPro=${isPro} isOwner=${isOwner} billingSource=${billingSource}`);

    // ─── Fetch aggregates with retry ──────────────────────────────────────
    const aggs = await withRetry(() =>
      base44.asServiceRole.entities.UserAggregates.filter({ user_id: user.id })
    ).catch(() => []);
    const userAgg = aggs[0] || null;

    // Rating badge tier
    const getRatingBadgeTier = () => {
      const ratingsCount = userAgg?.total_ratings_received || 0;
      const tiers = [
        { threshold: 0,     tier_key: 'starter_chef',       tier_name: 'Starter Chef' },
        { threshold: 50,    tier_key: 'rising_chef',         tier_name: 'Rising Chef' },
        { threshold: 100,   tier_key: 'trusted_cook',        tier_name: 'Trusted Cook' },
        { threshold: 500,   tier_key: 'community_favorite',  tier_name: 'Community Favorite' },
        { threshold: 1000,  tier_key: 'pro_creator',         tier_name: 'Pro Creator' },
        { threshold: 5000,  tier_key: 'elite_chef',          tier_name: 'Elite Chef' },
        { threshold: 10000, tier_key: 'legend',              tier_name: 'Legend' },
        { threshold: 50000, tier_key: 'mythic',              tier_name: 'Mythic Chef' },
      ];
      for (let i = tiers.length - 1; i >= 0; i--) {
        if (ratingsCount >= tiers[i].threshold) {
          const nextTier = i < tiers.length - 1 ? tiers[i + 1] : null;
          return {
            ...tiers[i],
            next_threshold: nextTier?.threshold || null,
            progress_to_next: nextTier ? Math.min(100, Math.round((ratingsCount / nextTier.threshold) * 100)) : 100,
          };
        }
      }
      return tiers[0];
    };

    // ─── Generation limit ──────────────────────────────────────────────────
    let generationLimit;
    if (isPro) {
      generationLimit = { mode: 'daily_limit', daily_limit: 25, banked_referral_credits: 0 };
    } else {
      const weekStart = new Date();
      const dayOfWeek = weekStart.getDay() || 7;
      weekStart.setDate(weekStart.getDate() - (dayOfWeek - 1));
      weekStart.setHours(0, 0, 0, 0);
      const weekStartISO = weekStart.toISOString().split('T')[0];

      const counters = await withRetry(() =>
        base44.asServiceRole.entities.UsageCounter.filter({
          created_by: user.email,
          feature: 'recipe_generation',
          week_start_date: weekStartISO,
        })
      ).catch(() => []);

      const count = counters[0]?.count || 0;
      const limit = 2;
      const weeklyRemaining = Math.max(0, limit - count);

      generationLimit = {
        mode: 'weekly_limit',
        remaining: weeklyRemaining,
        total: limit,
        used: count,
        banked_referral_credits: 0,
        total_available: weeklyRemaining,
        show_referral_plus_button: weeklyRemaining === 0,
      };
    }

    // ─── Determine subscription category for richer entitlement info ──────
    const subBillingPeriod = activeSub?.billing_period || 'none';
    const isTrialing = activeSub?.status === 'trialing';
    const hasUsedYearlyTrial = activeSub?.has_used_yearly_trial || false;
    const isCanceled = !!(activeSub?.canceled_at || activeSub?.status === 'canceled' || activeSub?.status === 'canceled_pending_expiry');
    let userCategory = 'free';
    if (isOwner) {
      userCategory = 'owner';
    } else if (isTrialing) {
      userCategory = 'yearly_trial';
    } else if (isPro && isCanceled) {
      userCategory = 'canceled_still_active'; // Pro access but canceled — will expire
    } else if (isPro && subBillingPeriod === 'yearly') {
      userCategory = 'yearly_paid';
    } else if (isPro && subBillingPeriod === 'monthly') {
      userCategory = 'monthly_paid';
    } else if (isPro) {
      userCategory = 'active_paid';
    }

    return Response.json({
      user_id: user.id,
      email: user.email,
      full_name: user.full_name,
      is_pro: isPro,
      is_pro_active: isPro,
      is_owner: isOwner,
      owner_override: isOwner,
      billing_source: billingSource,
      plan: isPro ? 'pro' : 'free',
      plan_type: isOwner ? 'pro' : (activeSub?.plan_type || 'free'),
      entitlement_status: isPro ? (isOwner ? 'owner_override' : 'active') : 'free',
      // ── New trial-ready fields ──────────────────────────────────────────
      user_category: userCategory,
      billing_period: subBillingPeriod,
      is_trialing: isTrialing,
      trial_end: activeSub?.trial_end || null,
      trial_source: activeSub?.trial_source || null,
      has_used_yearly_trial: hasUsedYearlyTrial,
      subscription_plan_id: activeSub?.subscription_plan_id || null,
      current_period_end: activeSub?.current_period_end || null,
      canceled_at: activeSub?.canceled_at || null,
      is_canceled: isCanceled,
      auto_renew: activeSub?.auto_renew ?? null,
      // ── Existing fields ────────────────────────────────────────────────
      generation_limit: generationLimit,
      can_post: isPro,
      can_create_group: isPro,
      can_view_top100: true,
      can_open_shop: isPro,
      rating_badge: getRatingBadgeTier(),
      total_ratings_received: userAgg?.total_ratings_received || 0,
      pro_visuals_enabled: isPro,
      pro_daily_limit: 25,
    });
  } catch (error) {
    console.error('[getEntitlements] error:', error);
    return Response.json({ error: error.message }, { status: 500 });
  }
});

/**
 * GET ENTITLEMENTS WITH REFRESH
 * 
 * Returns user entitlements with fresh quota data.
 * Called after generation completes to refresh UI.
 * 
 * Returns quota_data, banked_credits, etc.
 */

import { createClientFromRequest } from 'npm:@base44/sdk@0.8.23';

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user) return Response.json({ error: 'Unauthorized' }, { status: 401 });

    // Check subscription
    const subs = await base44.asServiceRole.entities.Subscription.filter(
      { created_by: user.email },
      null,
      10
    );
    const nowMs = Date.now();
    const ENTITLED_PLAN_TYPES = new Set(['pro', 'vip', 'trial']);
    const ENTITLED_STATUSES = new Set(['active', 'trialing', 'grace_period']);
    const activeSub = subs.find(s => {
      if (!ENTITLED_PLAN_TYPES.has(s.plan_type)) return false;
      if (ENTITLED_STATUSES.has(s.status)) return true;
      if (s.status === 'canceled') {
        if (s.current_period_end && new Date(s.current_period_end).getTime() > nowMs) return true;
        if (s.expires_at && new Date(s.expires_at).getTime() > nowMs) return true;
      }
      return false;
    });
    const is_pro = !!activeSub;

    // Banked credits
    const ledgerEntries = await base44.asServiceRole.entities.ReferralRewardLedger.filter({
      user_id: user.id,
      credit_state: 'earned',
    }).catch(() => []);
    const banked_credits = ledgerEntries.reduce((sum, e) => sum + (e.credits_remaining || 0), 0);

    if (!is_pro) {
      // FREE: get weekly quota
      const userTz = user.timezone || 'UTC';
      const now = new Date();
      const { periodStart } = getWeekWindow(now, userTz);

      const quota = (
        await base44.asServiceRole.entities.AiGenerationQuota.filter(
          { user_id: user.id, period_start: periodStart.toISOString() },
          null,
          1
        )
      )[0];

      const remaining = quota ? Math.max(0, quota.limit - quota.used) : 2;

      return Response.json({
        is_pro: false,
        remaining_weekly: remaining,
        used_weekly: quota?.used || 0,
        limit_weekly: 2,
        banked_credits,
        total_available: remaining + banked_credits,
      });
    }

    // PRO: get daily quota
    const proCheck = await base44.asServiceRole.functions.invoke('checkProGenerationLimit', {});
    const proQuota = proCheck?.data || {};

    return Response.json({
      is_pro: true,
      remaining_today: proQuota.remaining_today ?? 30,
      used_today: proQuota.daily_count ?? 0,
      limit_today: 30,
      cooldown_will_apply: proQuota.cooldown_will_apply ?? false,
      remaining_seconds: proQuota.remaining_seconds || null,
      banked_credits,
    });
  } catch (err) {
    console.error('[GetEntitlementsWithRefresh]', err.message);
    return Response.json({ error: err.message }, { status: 500 });
  }
});

function getWeekWindow(date, timezone) {
  const formatter = new Intl.DateTimeFormat('en-US', {
    timeZone: timezone,
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
    weekday: 'long',
  });

  const parts = formatter.formatToParts(date);
  const weekday = parts.find(p => p.type === 'weekday')?.value;
  const dayOfWeekNum = weekday === 'Monday' ? 1 : weekday === 'Tuesday' ? 2 : weekday === 'Wednesday' ? 3 : weekday === 'Thursday' ? 4 : weekday === 'Friday' ? 5 : weekday === 'Saturday' ? 6 : 0;
  const daysToSubtract = dayOfWeekNum === 0 ? 6 : dayOfWeekNum - 1;
  const periodStart = new Date(date);
  periodStart.setDate(periodStart.getDate() - daysToSubtract);
  periodStart.setUTCHours(0, 0, 0, 0);
  const offset = getTimezoneOffset(timezone);
  periodStart.setUTCHours(offset, 0, 0, 0);
  return { periodStart };
}

function getTimezoneOffset(timezone) {
  const formatter = new Intl.DateTimeFormat('en-US', {
    timeZone: timezone,
    hour: '2-digit',
    hour12: false,
  });
  const testDate = new Date('2000-01-01T00:00:00Z');
  const parts = formatter.formatToParts(testDate);
  return -parseInt(parts.find(p => p.type === 'hour')?.value || '0', 10);
}

