/**
 * Get active follower goal for current period
 * Auto-creates goal if doesn't exist
 */
Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user) return Response.json({ error: 'Unauthorized' }, { status: 401 });

    // Get current followers count — use Follow entity (UserFollow is legacy)
    let followerCount = 0;
    try {
      const followers = await base44.entities.Follow.filter({
        followed_id: user.id,
        status: 'accepted'
      });
      followerCount = followers.length;
    } catch (e) {
      // Fallback: try UserFollow (legacy) if Follow fails
      try {
        const followers = await base44.entities.UserFollow.filter({
          following_id: user.id,
          status: 'accepted'
        });
        followerCount = followers.length;
      } catch {
        console.warn('[getFollowerGoal] Both Follow and UserFollow queries failed');
        followerCount = 0;
      }
    }

    // Get week start (Monday)
    const now = new Date();
    const dayOfWeek = now.getDay();
    const daysToMonday = dayOfWeek === 0 ? 6 : dayOfWeek - 1;
    const weekStart = new Date(now);
    weekStart.setDate(weekStart.getDate() - daysToMonday);
    weekStart.setHours(0, 0, 0, 0);

    const weekEnd = new Date(weekStart);
    weekEnd.setDate(weekEnd.getDate() + 6);
    weekEnd.setHours(23, 59, 59, 999);

    const weekStartStr = weekStart.toISOString().split('T')[0];
    const weekEndStr = weekEnd.toISOString().split('T')[0];

    // Check for existing goal this week
    let goal = null;
    try {
      const existing = await base44.asServiceRole.entities.FollowerGoal.filter({
        user_id: user.id,
        period_start: weekStartStr
      });
      if (existing.length > 0) {
        goal = existing[0];
      }
    } catch {}

    // If no goal exists, create one
    if (!goal) {
      // Get last week's goal to determine base
      let lastGoal = null;
      try {
        const previousGoals = await base44.asServiceRole.entities.FollowerGoal.filter({
          user_id: user.id
        }, '-period_start', 1);
        if (previousGoals.length > 0) {
          lastGoal = previousGoals[0];
        }
      } catch {}

      // If achieved last goal, continue from there; otherwise use formula
      let initialGoal;
      if (lastGoal?.achieved_at && lastGoal?.next_goal) {
        // Continue from stretch goal
        initialGoal = lastGoal.next_goal;
      } else if (followerCount > 0) {
        // Formula: 5 followers or 20% more than current, whichever is higher
        initialGoal = Math.max(5, Math.ceil(followerCount * 1.2));
      } else {
        initialGoal = 5;
      }

      goal = await base44.asServiceRole.entities.FollowerGoal.create({
        user_id: user.id,
        period_start: weekStartStr,
        period_end: weekEndStr,
        current_goal: initialGoal,
        updated_at: new Date().toISOString()
      });
      console.log(`[FOLLOWER_GOAL] created goal=${initialGoal} for week=${weekStartStr}`);
    }

    // Check if goal achieved and not yet marked
    const isAchieved = followerCount >= goal.current_goal && !goal.achieved_at;

    if (isAchieved) {
      // Mark achieved and create stretch goal
      const stretchGoal = Math.ceil(goal.current_goal * 1.3) + 5;
      await base44.asServiceRole.entities.FollowerGoal.update(goal.id, {
        achieved_at: new Date().toISOString(),
        next_goal: stretchGoal,
        updated_at: new Date().toISOString()
      });
      goal.achieved_at = new Date().toISOString();
      goal.next_goal = stretchGoal;

      console.log(`[FOLLOWER_GOAL] achieved! stretch=${stretchGoal}`);
    }

    return Response.json({
      user_id: user.id,
      followers_count: followerCount,
      follower_goal: {
        period_start: goal.period_start,
        period_end: goal.period_end,
        current_goal: goal.current_goal,
        achieved: !!goal.achieved_at,
        progress: Math.min(1, followerCount / goal.current_goal),
        next_goal: goal.next_goal || null
      }
    });
  } catch (error) {
    console.error('[getFollowerGoal] error:', error);
    // Log to observability system (fire and forget)
    try {
      await base44.asServiceRole.functions.invoke('logBackendError', {
        function_name: 'getFollowerGoal',
        error_category: error?.status === 429 ? 'rate_limit' : 'unknown',
        error_message: error?.message || 'Unknown error',
        page_surface: 'Home',
        severity: 'error',
        stack_trace: error?.stack?.substring?.(0, 1500) || null,
      });
    } catch {}
    return Response.json({ error: error.message }, { status: 500 });
  }
});

