const UNIT_TO_GRAMS = {'g':1,'gram':1,'grams':1,'kg':1000,'kilogram':1000,'kilograms':1000,'oz':28.35,'ounce':28.35,'ounces':28.35,'lb':453.6,'lbs':453.6,'pound':453.6,'pounds':453.6,'cup':240,'cups':240,'tbsp':15,'tablespoon':15,'tablespoons':15,'tsp':5,'teaspoon':5,'teaspoons':5,'ml':1,'l':1000,'liter':1000,'liters':1000};
const OIL_DENSITY = 0.911;
const OIL_KEYWORDS = ['oil','ghee'];
const VOLUME_UNITS = new Set(['ml','l','liter','liters','tsp','teaspoon','teaspoons','tbsp','tablespoon','tablespoons','cup','cups']);
const PIECE_WEIGHTS = {'chicken breast':175,'chicken thigh':120,'chicken leg':150,'egg':55,'large egg':65,'small egg':40,'potato':170,'large potato':250,'small potato':100,'sweet potato':200,'tomato':150,'cherry tomato':17,'onion':150,'large onion':200,'small onion':80,'red onion':150,'garlic clove':4,'clove':4,'avocado':200,'banana':120,'apple':182,'orange':180,'lemon':85,'lime':67,'carrot':80,'bell pepper':120,'slice':30,'rasher':35,'strip':35,'can':400,'bunch':100,'pizza dough':250,'dough ball':250};
const GENERIC_FALLBACK = {calories:80,protein_g:3,carbs_g:12,fat_g:2};

function lookupNutr(name) {
  if (!name) return null;
  const lower = name.toLowerCase().trim();
  if (FOODS_PER_100G[lower]) return FOODS_PER_100G[lower];
  const SPICE_ZERO = {calories:0,protein_g:0,carbs_g:0,fat_g:0};
  const SPICE_KW = ['pepper','salt','paprika','cumin','cinnamon','oregano','basil','thyme','rosemary','turmeric','cayenne','chili powder','garlic powder','onion powder','herb','seasoning','spice'];
  for (const sp of SPICE_KW) {
    if (lower === sp || lower.startsWith(sp+' ') || lower.endsWith(' '+sp) || lower.includes(' '+sp+' ')) return SPICE_ZERO;
  }
  let best = null, bestLen = 0;
  for (const [key, val] of Object.entries(FOODS_PER_100G)) {
    if (key.length > 3 && lower.includes(key) && key.length > bestLen) { best = val; bestLen = key.length; }
  }
  return best;
}

function evalFrac(s) {
  if (String(s).includes('/')) { const [n,d] = String(s).split('/'); return parseFloat(n)/parseFloat(d); }
  return parseFloat(s);
}

function resolveGrams(ing) {
  let amtStr = String(ing.amount || '').trim();
  if (amtStr && ing.unit && /^[\d./]+$/.test(amtStr)) amtStr = `${amtStr} ${String(ing.unit).trim()}`;
  if (!amtStr) return ing.base_grams > 0 ? ing.base_grams : 100;
  const nameLower = (ing.name || '').toLowerCase().trim();
  const justG = amtStr.match(/^([\d.]+)\s*g$/i);
  if (justG) return parseFloat(justG[1]);
  const nu = amtStr.match(/^([\d.\/]+)\s*(ml|l|tsp|tbsp|tablespoon|teaspoon|cup|cups|oz|lb|lbs|kg|g)\b/i);
  if (nu) {
    const q = evalFrac(nu[1]); const u = nu[2].toLowerCase();
    const ug = UNIT_TO_GRAMS[u] ?? UNIT_TO_GRAMS[u.replace(/s$/,'')];
    if (ug) { const isOil = OIL_KEYWORDS.some(kw => nameLower.includes(kw)); return q * ug * (VOLUME_UNITS.has(u) && isOil ? OIL_DENSITY : 1); }
  }
  const nu2 = amtStr.match(/^([\d.\/]+)\s+([a-z]+[a-z\s]*)$/i);
  if (nu2) {
    const q = evalFrac(nu2[1]); const u = nu2[2].trim().toLowerCase();
    const ug = UNIT_TO_GRAMS[u] ?? UNIT_TO_GRAMS[u.replace(/s$/,'')];
    if (ug) { const isOil = OIL_KEYWORDS.some(kw => nameLower.includes(kw)); return q * ug * (VOLUME_UNITS.has(u) && isOil ? OIL_DENSITY : 1); }
    const uBase = u.replace(/s$/,'');
    if (uBase === 'piece' || uBase === 'pc') {
      if (PIECE_WEIGHTS[nameLower]) return q * PIECE_WEIGHTS[nameLower];
      for (const [k,w] of Object.entries(PIECE_WEIGHTS)) { if (nameLower.includes(k)) return q * w; }
      return q * 100;
    }
  }
  const jn = amtStr.match(/^([\d.]+)$/); if (jn) return parseFloat(jn[1]);
  const q = evalFrac(amtStr.split(/\s/)[0]) || 1;
  if (PIECE_WEIGHTS[nameLower]) return q * PIECE_WEIGHTS[nameLower];
  for (const [k,w] of Object.entries(PIECE_WEIGHTS)) { if (nameLower.includes(k)) return q * w; }
  return q * 100;
}

function computeNutrFromIngredients(recipe) {
  const groups = recipe.ingredients || [];
  const servings = Math.max(1, recipe.servings || 1);
  let cal = 0, prot = 0, carbs = 0, fat = 0;
  for (const group of groups) {
    for (const item of (group.items || [])) {
      if (!item.name || item.optional || item.missing) continue;
      const g = resolveGrams(item);
      const n = lookupNutr(item.name) || GENERIC_FALLBACK;
      cal += g*(n.calories/100); prot += g*(n.protein_g/100); carbs += g*(n.carbs_g/100); fat += g*(n.fat_g/100);
    }
  }
  if (cal <= 0) return null;
  return {
    total:       {calories:Math.round(cal),       protein:Math.round(prot),       carbs:Math.round(carbs),       fat:Math.round(fat)},
    per_serving: {calories:Math.round(cal/servings), protein:Math.round(prot/servings), carbs:Math.round(carbs/servings), fat:Math.round(fat/servings)},
  };
}

function injectTotalNutrition(recipe) {
  if (recipe.nutrition_total_for_recipe?.calories > 0 && recipe.nutrition_per_serving?.calories > 0) return recipe;
  const s = Math.max(1, recipe.servings || 1);
  const ps = recipe.nutrition_per_serving;
  const leg = recipe.nutrition;
  const src = (ps?.calories > 0) ? ps : (leg?.calories > 0 ? leg : null);
  if (src) {
    const total = {calories:Math.round((src.calories||0)*s), protein:Math.round(((src.protein??src.protein_g??0))*s), carbs:Math.round(((src.carbs??src.carbs_g??0))*s), fat:Math.round(((src.fat??src.fat_g??0))*s)};
    return { ...recipe, nutrition_total_for_recipe: recipe.nutrition_total_for_recipe?.calories > 0 ? recipe.nutrition_total_for_recipe : total, nutrition_per_serving: ps?.calories > 0 ? ps : {calories:src.calories||0, protein:src.protein??src.protein_g??0, carbs:src.carbs??src.carbs_g??0, fat:src.fat??src.fat_g??0} };
  }
  const computed = computeNutrFromIngredients(recipe);
  if (!computed) return recipe;
  return { ...recipe, nutrition_total_for_recipe: computed.total, nutrition_per_serving: computed.per_serving };
}

/**
 * FOLLOWING FEED — Recipes from creators the user follows.
 * Filters out blocked users (both directions).
 */
Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user?.id) return Response.json({ error: 'Unauthorized' }, { status: 401 });

    const body = await req.json().catch(() => ({}));
    const limit = Math.min(body.limit || 20, 100);

    const sr = base44.asServiceRole;

    const [follows, followedBackMe, blockedByMe, blockedByOthers] = await Promise.all([
      sr.entities.Follow.filter({ follower_id: user.id }).catch(() => []),
      sr.entities.Follow.filter({ followed_id: user.id, status: 'accepted' }).catch(() => []),
      sr.entities.BlockedUser.filter({ blocker_id: user.id }).catch(() => []),
      sr.entities.BlockedUser.filter({ blocked_id: user.id }).catch(() => []),
    ]);

    const blockedIds = new Set([
      ...blockedByMe.map(b => b.blocked_id),
      ...blockedByOthers.map(b => b.blocker_id),
    ]);

    // People I follow (accepted)
    const followedUserIds = new Set(
      follows
        .filter(f => f.status === 'accepted')
        .map(f => f.followed_id)
        .filter(id => id && !blockedIds.has(id))
    );

    // People who follow ME back (for "followers only" posts visibility)
    const myFollowerIds = new Set(
      followedBackMe.map(f => f.follower_id).filter(id => id && !blockedIds.has(id))
    );

    if (followedUserIds.size === 0) {
      return Response.json({ posts: [], total: 0, source: 'following_empty' });
    }

    // CRITICAL FIX: Query Post entities to respect Post.community_visible (the canonical visibility source)
    // This includes both user-created and AI-generated recipes that have been published to community
    const allPosts = await sr.entities.Post.filter(
      {
        type: 'community',
        community_visible: true,
        moderation_status: 'active',
        author_account_status: 'active',
      },
      '-created_date',
      500
    ).catch(() => []);

    let blockedCount = 0;
    const filtered = allPosts.filter(p => {
      if (!p.author_id) return false;
      // Must be following this author
      if (!followedUserIds.has(p.author_id)) return false;
      if (blockedIds.has(p.author_id)) {
        blockedCount++;
        return false;
      }
      // Never show your own posts to yourself in following feed
      if (p.author_id === user.id) return false;
      // PRIVACY: For "followers only" posts — only show if author also follows ME back (mutual follow)
      // The Post entity doesn't have a "followers_only" field, so we enforce this by checking:
      // if the recipe linked is NOT is_public, it's private and only mutual followers should see it
      // Already filtered at DB level: community_visible === true, moderation_status === 'active'
      return true;
    });

    if (blockedCount > 0 && process.env.DEBUG_BLOCKS === 'true') {
      console.log(`[FOLLOWING] Filtered ${blockedCount}/${allRecipes.length} recipes due to blocking`);
    }

    // Fetch Recipe data for each Post to enrich
    const recipeMap = {};
    const recipeIds = filtered.map(p => p.recipe_id).filter(Boolean);
    if (recipeIds.length > 0) {
      const recipes = await Promise.all(
        recipeIds.map(id => sr.entities.Recipe.filter({ id }).then(r => r[0]).catch(() => null))
      ).then(r => r.filter(Boolean));
      for (const recipe of recipes) {
        recipeMap[recipe.id] = recipe;
      }
    }

    const ranked = filtered
      .filter(p => {
        if (!recipeMap[p.recipe_id]) return false;
        const recipe = recipeMap[p.recipe_id];
        // PRIVACY: Only show public recipes in the shared following feed
        // If a recipe is private (is_public=false), only the owner can see it
        if (recipe.is_public !== true) return false;
        return true;
      })
      .map(p => {
        const recipe = recipeMap[p.recipe_id];
        return {
          ...(recipe || {}),
          post_id: p.id,
          id: recipe.id,
          recipe_id: p.recipe_id,
          author_id: p.author_id,
          title: p.title || recipe?.title || '',
          description: p.body || recipe?.description || '',
          hero_image_url: p.media_url || recipe?.hero_image_url || null,
          media_url: p.media_url || recipe?.hero_image_url || null,
          author_name: p.author_name || recipe?.author_name || '',
          author_avatar: p.author_avatar || recipe?.author_avatar || '',
          like_count: recipe?.likes_count || p.like_count || 0,
          likes_count: recipe?.likes_count || p.like_count || 0,
          save_count: recipe?.saves_count || p.save_count || 0,
          saves_count: recipe?.saves_count || p.save_count || 0,
          moderation_status: p.moderation_status,
          community_visible: p.community_visible,
          is_public: recipe?.is_public ?? p.community_visible,
          source: recipe?.source || 'user',
          _score: ((p.like_count || 0) * 2 + (p.save_count || 0) * 3 + (p.comment_count || 0) * 1.5) || new Date(p.created_date || 0).getTime() / 1e9,
        };
      })
      .sort((a, b) => b._score !== a._score ? b._score - a._score : new Date(b.created_date || 0) - new Date(a.created_date || 0))
      .slice(0, limit)
      .map(p => { const { _score, ...rest } = p; return rest; });

    // CRITICAL: Query Like entity (unified system), NOT RecipeLike (old system).
    const followingLikedByUser = await sr.entities.Like.filter(
      { target_type: 'recipe', user_id: user.id }
    ).catch(() => []);
    const followingLikedIds = new Set(followingLikedByUser.map(l => l.target_id));

    const enrichedRanked = ranked.map(p => ({
      ...p,
      isLiked: followingLikedIds.has(p.id || p.recipe_id),
      viewer_has_liked: followingLikedIds.has(p.id || p.recipe_id),
    }));

    return Response.json({ posts: enrichedRanked.map(injectTotalNutrition), total: filtered.length, source: 'following' });
  } catch (error) {
    console.error(`[FOLLOWING_FEED] error: ${error.message}`);
    return Response.json({ error: error.message, posts: [], total: 0 }, { status: 500 });
  }
});

import { createClientFromRequest } from 'npm:@base44/sdk@0.8.6';

/**
 * STRICT Following Feed Endpoint
 * - ONLY posts from accepted follows
 * - NEVER includes viewer's own posts
 * - NEVER fallback to For You
 * - NEVER leak posts from non-followed users
 */
Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user) return Response.json({ error: 'Unauthorized' }, { status: 401 });

    const url = new URL(req.url);
    const limit = Math.min(parseInt(url.searchParams.get('limit') || '30'), 100);
    const cursor = url.searchParams.get('cursor');

    // Get accepted follows only
    const follows = await base44.asServiceRole.entities.UserFollow.filter({
      follower_id: user.id,
      status: 'accepted',
    });

    if (follows.length === 0) {
      console.log(`[FEED_FOLLOWING] user=${user.id} no_follows`);
      return Response.json({ posts: [], total: 0, cursor: null });
    }

    const followedIds = follows.map(f => f.following_id);

    // Query posts from followed users only (exclude viewer's posts)
    // In real implementation, use SQL directly for performance:
    // SELECT * FROM posts
    // WHERE owner_id IN (followedIds)
    // AND owner_id != viewer_id
    // AND is_public = true
    // AND deleted_at IS NULL
    // ORDER BY created_at DESC, id DESC
    // LIMIT limit + 1

    // Using SDK with filtering (slower but works):
    const allPosts = await base44.asServiceRole.entities.Post.filter({
      author_id: { $in: followedIds },
    }, '-created_at', limit + 1);

    // Filter: exclude viewer, deleted, private
    const posts = allPosts.filter(p => 
      p.author_id !== user.id && 
      p.status !== 'removed'
    );

    // Determine next cursor
    let nextCursor = null;
    if (posts.length > limit) {
      const lastPost = posts[limit - 1];
      nextCursor = `${lastPost.created_date}:${lastPost.id}`;
    }

    // Enrich each post with viewer engagement + cooked count
    const enrichedPosts = await Promise.all(posts.slice(0, limit).map(async (post) => {
      const likeRecord = await base44.asServiceRole.entities.PostLike.filter({
        post_id: post.id,
        user_id: user.id,
      }).catch(() => []);

      const saveRecord = await base44.asServiceRole.entities.PostSave.filter({
        post_id: post.id,
        user_id: user.id,
      }).catch(() => []);

      const agg = await base44.asServiceRole.entities.RecipeAggregate.filter({
        recipe_id: post.recipe_id,
      }).catch(() => []);

      return {
        ...post,
        viewer_has_liked: likeRecord.length > 0,
        viewer_has_saved: saveRecord.length > 0,
        cooked_count_unique_users: agg[0]?.cooked_count_unique_users || 0,
      };
    }));

    console.log(`[FEED_FOLLOWING] user=${user.id} posts=${enrichedPosts.length} followers=${followedIds.length}`);

    return Response.json({
      posts: enrichedPosts,
      total: posts.length,
      cursor: nextCursor,
    });
  } catch (error) {
    console.error('getFollowingFeedStrict error:', error);
    return Response.json({ error: error.message }, { status: 500 });
  }
});

import { createClientFromRequest } from 'npm:@base44/sdk@0.8.23';

/**
 * getFollowList — returns followers OR following list for a given user.
 * Includes viewer's follow status for each user (embedded, no N+1 calls).
 * Uses batch User fetch to avoid rate limits.
 *
 * Params: { user_id, list_type: 'followers' | 'following' }
 * Returns: { users: [{ id, display_name, avatar_url, username, viewer_follow_status }] }
 */
Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const viewer = await base44.auth.me();
    if (!viewer) return Response.json({ error: 'Unauthorized' }, { status: 401 });

    const { user_id, list_type } = await req.json();
    if (!user_id || !['followers', 'following'].includes(list_type)) {
      return Response.json({ error: 'user_id and list_type required' }, { status: 400 });
    }

    const sr = base44.asServiceRole;

    // For followers: find all Follow records where followed_id = user_id (people who follow user_id)
    // For following: find all Follow records where follower_id = user_id (people user_id follows)
    const filterKey = list_type === 'followers' ? 'followed_id' : 'follower_id';
    const idKey     = list_type === 'followers' ? 'follower_id' : 'followed_id';

    // Fetch follow records + viewer's own follows + block lists — all in parallel
    // BOTH tabs only show 'accepted' follows — matches profile page counts exactly.
    // Pending requests are handled separately by the FollowRequests feature.
    const [followRecords, viewerFollowsAll, blockedByViewer, blockedByOthers] = await Promise.all([
      sr.entities.Follow.filter({ [filterKey]: user_id, status: 'accepted' }, '', 200),
      // Viewer's own follow records so we can embed viewer_follow_status without extra calls
      sr.entities.Follow.filter({ follower_id: viewer.id }, '', 500).catch(() => []),
      sr.entities.BlockedUser.filter({ blocker_id: viewer.id }).catch(() => []),
      sr.entities.BlockedUser.filter({ blocked_id: viewer.id }).catch(() => []),
    ]);

    const blockedIds = new Set([
      ...blockedByViewer.map(b => b.blocked_id),
      ...blockedByOthers.map(b => b.blocker_id),
    ]);

    // Build viewer follow status map: target_id → 'following' | 'requested' | 'none'
    // CRITICAL: always map 'accepted' → 'following' to match profile vocabulary
    const viewerFollowMap = {};
    for (const f of viewerFollowsAll) {
      viewerFollowMap[f.followed_id] = f.status === 'accepted' ? 'following' : (f.status || 'requested');
    }

    // Filter out blocked users
    const visibleRecords = followRecords.filter(f => !blockedIds.has(f[idKey]));

    if (visibleRecords.length === 0) return Response.json({ users: [] });

    // Batch-fetch all user profiles in ONE call using list with filter
    // Use Promise.all but limit concurrency to avoid rate limits
    // Batch into groups of 10
    const userIds = [...new Set(visibleRecords.map(f => f[idKey]))];

    // Fetch users in batches of 10
    const BATCH_SIZE = 10;
    const userMap = {};
    for (let i = 0; i < userIds.length; i += BATCH_SIZE) {
      const batch = userIds.slice(i, i + BATCH_SIZE);
      const fetched = await Promise.all(
        batch.map(uid =>
          sr.entities.User.filter({ id: uid }, '', 1)
            .then(arr => arr[0] || null)
            .catch(() => null)
        )
      );
      for (const u of fetched) {
        if (u) userMap[u.id] = u;
      }
    }

    const users = visibleRecords
      .map(f => {
        const uid = f[idKey];
        const u = userMap[uid];
        if (!u) return null;

        const display_name = (u.display_name || u.full_name || u.username || u.email?.split('@')[0] || '').trim();
        // SYSTEM 3: Skip rows with no resolvable real name — never produce fake "User" fallbacks
        if (!display_name) return null;

        // Viewer's follow status toward this user
        const viewer_follow_status = uid === viewer.id ? 'self' : (viewerFollowMap[uid] || 'none');

        // account_status gate: only show fully active users in follow lists.
        // 'active' = normal. 'trialing' = active trial. null/undefined = legacy record, treat as active.
        // NOTE: 'paused' users who were reactivated will have account_status='active' again.
        // We fetch live from DB here via service role (no cache), so restored users appear immediately.
        // BLOCKER 3 FIX: null/undefined = legacy record → treat as active.
        // Only exclude explicitly terminated accounts. 'paused' is on-hold but NOT excluded —
        // restored accounts return to 'active'. Never filter 'paused' since that state is transient.
        const status = u.account_status || 'active';
        if (['suspended', 'pending_deletion', 'deleted'].includes(status)) return null;

        return {
          id: uid,
          follow_record_id: f.id,
          display_name,
          avatar_url: u.avatar_url || null,
          username: u.username || null,
          account_status: status,
          viewer_follow_status,
          // For followers list, also expose their follow request status if pending
          follow_status: f.status || 'accepted',
        };
      })
      .filter(Boolean);

    return Response.json({ users });
  } catch (error) {
    console.error('getFollowList error:', error);
    return Response.json({ error: error.message }, { status: 500 });
  }
});

