const UNIT_TO_GRAMS = {'g':1,'gram':1,'grams':1,'kg':1000,'kilogram':1000,'kilograms':1000,'oz':28.35,'ounce':28.35,'ounces':28.35,'lb':453.6,'lbs':453.6,'pound':453.6,'pounds':453.6,'cup':240,'cups':240,'tbsp':15,'tablespoon':15,'tablespoons':15,'tsp':5,'teaspoon':5,'teaspoons':5,'ml':1,'l':1000,'liter':1000,'liters':1000};
const OIL_DENSITY = 0.911;
const OIL_KEYWORDS = ['oil','ghee'];
const VOLUME_UNITS = new Set(['ml','l','liter','liters','tsp','teaspoon','teaspoons','tbsp','tablespoon','tablespoons','cup','cups']);
const PIECE_WEIGHTS = {'chicken breast':175,'chicken thigh':120,'chicken leg':150,'egg':55,'large egg':65,'small egg':40,'potato':170,'large potato':250,'small potato':100,'sweet potato':200,'tomato':150,'cherry tomato':17,'onion':150,'large onion':200,'small onion':80,'red onion':150,'garlic clove':4,'clove':4,'avocado':200,'banana':120,'apple':182,'orange':180,'lemon':85,'lime':67,'carrot':80,'bell pepper':120,'slice':30,'rasher':35,'strip':35,'can':400,'bunch':100,'pizza dough':250,'dough ball':250};
const GENERIC_FALLBACK = {calories:80,protein_g:3,carbs_g:12,fat_g:2};

function lookupNutr(name) {
  if (!name) return null;
  const lower = name.toLowerCase().trim();
  if (FOODS_PER_100G[lower]) return FOODS_PER_100G[lower];
  const SPICE_ZERO = {calories:0,protein_g:0,carbs_g:0,fat_g:0};
  const SPICE_KW = ['pepper','salt','paprika','cumin','cinnamon','oregano','basil','thyme','rosemary','turmeric','cayenne','chili powder','garlic powder','onion powder','herb','seasoning','spice'];
  for (const sp of SPICE_KW) {
    if (lower === sp || lower.startsWith(sp+' ') || lower.endsWith(' '+sp) || lower.includes(' '+sp+' ')) return SPICE_ZERO;
  }
  let best = null, bestLen = 0;
  for (const [key, val] of Object.entries(FOODS_PER_100G)) {
    if (key.length > 3 && lower.includes(key) && key.length > bestLen) { best = val; bestLen = key.length; }
  }
  return best;
}

function evalFrac(s) {
  if (String(s).includes('/')) { const [n,d] = String(s).split('/'); return parseFloat(n)/parseFloat(d); }
  return parseFloat(s);
}

function resolveGrams(ing) {
  let amtStr = String(ing.amount || '').trim();
  if (amtStr && ing.unit && /^[\d./]+$/.test(amtStr)) amtStr = `${amtStr} ${String(ing.unit).trim()}`;
  if (!amtStr) return ing.base_grams > 0 ? ing.base_grams : 100;
  const nameLower = (ing.name || '').toLowerCase().trim();
  const justG = amtStr.match(/^([\d.]+)\s*g$/i);
  if (justG) return parseFloat(justG[1]);
  const nu = amtStr.match(/^([\d.\/]+)\s*(ml|l|tsp|tbsp|tablespoon|teaspoon|cup|cups|oz|lb|lbs|kg|g)\b/i);
  if (nu) {
    const q = evalFrac(nu[1]); const u = nu[2].toLowerCase();
    const ug = UNIT_TO_GRAMS[u] ?? UNIT_TO_GRAMS[u.replace(/s$/,'')];
    if (ug) { const isOil = OIL_KEYWORDS.some(kw => nameLower.includes(kw)); return q * ug * (VOLUME_UNITS.has(u) && isOil ? OIL_DENSITY : 1); }
  }
  const nu2 = amtStr.match(/^([\d.\/]+)\s+([a-z]+[a-z\s]*)$/i);
  if (nu2) {
    const q = evalFrac(nu2[1]); const u = nu2[2].trim().toLowerCase();
    const ug = UNIT_TO_GRAMS[u] ?? UNIT_TO_GRAMS[u.replace(/s$/,'')];
    if (ug) { const isOil = OIL_KEYWORDS.some(kw => nameLower.includes(kw)); return q * ug * (VOLUME_UNITS.has(u) && isOil ? OIL_DENSITY : 1); }
    const uBase = u.replace(/s$/,'');
    if (uBase === 'piece' || uBase === 'pc') {
      if (PIECE_WEIGHTS[nameLower]) return q * PIECE_WEIGHTS[nameLower];
      for (const [k,w] of Object.entries(PIECE_WEIGHTS)) { if (nameLower.includes(k)) return q * w; }
      return q * 100;
    }
  }
  const jn = amtStr.match(/^([\d.]+)$/); if (jn) return parseFloat(jn[1]);
  const q = evalFrac(amtStr.split(/\s/)[0]) || 1;
  if (PIECE_WEIGHTS[nameLower]) return q * PIECE_WEIGHTS[nameLower];
  for (const [k,w] of Object.entries(PIECE_WEIGHTS)) { if (nameLower.includes(k)) return q * w; }
  return q * 100;
}

function computeNutrFromIngredients(recipe) {
  const groups = recipe.ingredients || [];
  const servings = Math.max(1, recipe.servings || 1);
  let cal = 0, prot = 0, carbs = 0, fat = 0;
  for (const group of groups) {
    for (const item of (group.items || [])) {
      if (!item.name || item.optional || item.missing) continue;
      const g = resolveGrams(item);
      const n = lookupNutr(item.name) || GENERIC_FALLBACK;
      cal += g*(n.calories/100); prot += g*(n.protein_g/100); carbs += g*(n.carbs_g/100); fat += g*(n.fat_g/100);
    }
  }
  if (cal <= 0) return null;
  return {
    total:       {calories:Math.round(cal),       protein:Math.round(prot),       carbs:Math.round(carbs),       fat:Math.round(fat)},
    per_serving: {calories:Math.round(cal/servings), protein:Math.round(prot/servings), carbs:Math.round(carbs/servings), fat:Math.round(fat/servings)},
  };
}

function injectTotalNutrition(recipe) {
  if (recipe.nutrition_total_for_recipe?.calories > 0 && recipe.nutrition_per_serving?.calories > 0) return recipe;
  const s = Math.max(1, recipe.servings || 1);
  const ps = recipe.nutrition_per_serving;
  const leg = recipe.nutrition;
  const src = (ps?.calories > 0) ? ps : (leg?.calories > 0 ? leg : null);
  if (src) {
    const total = {calories:Math.round((src.calories||0)*s), protein:Math.round(((src.protein??src.protein_g??0))*s), carbs:Math.round(((src.carbs??src.carbs_g??0))*s), fat:Math.round(((src.fat??src.fat_g??0))*s)};
    return { ...recipe, nutrition_total_for_recipe: recipe.nutrition_total_for_recipe?.calories > 0 ? recipe.nutrition_total_for_recipe : total, nutrition_per_serving: ps?.calories > 0 ? ps : {calories:src.calories||0, protein:src.protein??src.protein_g??0, carbs:src.carbs??src.carbs_g??0, fat:src.fat??src.fat_g??0} };
  }
  const computed = computeNutrFromIngredients(recipe);
  if (!computed) return recipe;
  return { ...recipe, nutrition_total_for_recipe: computed.total, nutrition_per_serving: computed.per_serving };
}

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user) return Response.json({ error: 'Unauthorized' }, { status: 401 });

    const body = await req.json().catch(() => ({}));
    const limit = Math.min(body.limit || 20, 100);

    const sr = base44.asServiceRole;

    const [notInterested, blockedByMe, blockedByOthers] = await Promise.all([
      sr.entities.FeedPreference.filter({
        created_by: user.email,
        preference_type: 'not_interested',
      }).catch(() => []),
      sr.entities.BlockedUser.filter({ blocker_id: user.id }).catch(() => []),
      sr.entities.BlockedUser.filter({ blocked_id: user.id }).catch(() => []),
    ]);

    const notInterestedIds = new Set(notInterested.map(f => f.recipe_id));
    const blockedIds = new Set([
      ...blockedByMe.map(b => b.blocked_id),
      ...blockedByOthers.map(b => b.blocker_id),
    ]);

    function applyBaseFilters(recipes) {
      let blocked = 0;
      const result = recipes.filter(r => {
        // Block filter — check by author_id (user ID). Skip own content check.
        const authorId = r.author_id;
        if (authorId && blockedIds.has(authorId)) {
          blocked++;
          return false;
        }
        // Also skip viewer's own non-community content
        if (r.created_by === user.email) {
          if (!r.is_community_content && !r.is_shop_content) return false;
        }
        if (notInterestedIds.has(r.id)) return false;
        if (r.community_visible === false) return false;
        if (r.author_account_status && r.author_account_status !== 'active') return false;
        // MODERATION: exclude removed_by_moderation posts from all public feeds
        if (r.moderation_status === 'removed_by_moderation' || r.moderation_status === 'appealed') return false;
        return true;
      });
      if (blocked > 0 && process.env.DEBUG_BLOCKS === 'true') {
        console.log(`[FOR_YOU] Filtered ${blocked}/${recipes.length} recipes due to blocking`);
      }
      return result;
    }

    function rankByEngagement(recipes) {
      return recipes
        .map(r => {
          const isOwn = r.created_by === user.email;
          const baseScore = ((r.likes_count || 0) * 2 + (r.saves_count || 0) * 3 + (r.review_count || 0)) || new Date(r.created_date || 0).getTime() / 1e9;
          return { ...r, _score: isOwn ? baseScore * 0.35 : baseScore };
        })
        .sort((a, b) => {
          if (b._score !== a._score) return b._score - a._score;
          return new Date(b.created_date || 0) - new Date(a.created_date || 0);
        })
        .map(r => { const { _score, ...rest } = r; return rest; });
    }

    // PERF FIX: Single query for community recipes (most common case) — avoid fetching 1100 records.
    // Fetch community + shop in one deduped call; fall back to broader query only if needed.
    const communityRecipes = await sr.entities.Recipe.filter(
      { is_public: true, is_community_content: true },
      '-created_date',
      200
    ).catch(() => []);

    let combined = communityRecipes;

    // Only fetch shop recipes if we don't have enough community ones
    if (combined.length < limit * 2) {
      const shopRecipes = await sr.entities.Recipe.filter(
        { is_public: true, is_shop_content: true },
        '-created_date',
        100
      ).catch(() => []);
      const seen = new Set(combined.map(r => r.id));
      for (const r of shopRecipes) {
        if (!seen.has(r.id)) { seen.add(r.id); combined.push(r); }
      }
    }

    const filtered = applyBaseFilters(combined);
    if (filtered.length === 0) {
      // Last resort: any public recipe
      const lastResort = await sr.entities.Recipe.filter({ is_public: true }, '-created_date', 100).catch(() => []);
      const fallback = lastResort.filter(r => !notInterestedIds.has(r.id) && r.community_visible !== false);
      return Response.json({ posts: rankByEngagement(fallback).slice(0, limit).map(injectTotalNutrition), total: fallback.length, source: 'fallback' });
    }

    return Response.json({ posts: rankByEngagement(filtered).slice(0, limit).map(injectTotalNutrition), total: filtered.length, source: 'community' });
  } catch (error) {
    console.error(`[FOR_YOU_FEED] error: ${error.message}`);
    return Response.json({ error: error.message, posts: [], total: 0 }, { status: 500 });
  }
});

import { createClientFromRequest } from 'npm:@base44/sdk@0.8.20';

/**
 * FOR YOU ALGORITHM (ADVANCED)
 * 
 * RankScore =
 * (3*SaveRate + 2*CTR + 1.5*CommentRate + 1*LikeRate + 2*CookIntent + 1*RatingQuality)
 * * FreshnessBoost
 * * PersonalizationFactor
 * * StageBoost
 * - Penalties
 */
Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user) return Response.json({ error: 'Unauthorized' }, { status: 401 });

    const url = new URL(req.url);
    const limit = Math.min(parseInt(url.searchParams.get('limit') || '30'), 100);
    const isDev = url.searchParams.get('debug') === 'true' && (Deno.env.get('DEBUG_MODE') === 'true' || user.id === 'dev');

    // Get user preferences
    const userPrefs = await base44.asServiceRole.entities.UserPreference.filter({
      owner_id: user.id,
    }).catch(() => []);

    const prefs = userPrefs[0] || { allergens_enabled: false, allergens_list: [] };

    // Get "not interested" recipes + block list
    const [notInterested, blockedByMe, blockedByOthers] = await Promise.all([
      base44.asServiceRole.entities.FeedPreference.filter({
        created_by: user.id,
        preference_type: 'not_interested',
      }).catch(() => []),
      base44.asServiceRole.entities.BlockedUser.filter({ blocker_id: user.id }).catch(() => []),
      base44.asServiceRole.entities.BlockedUser.filter({ blocked_id: user.id }).catch(() => []),
    ]);

    const notInterestedIds = new Set(notInterested.map(n => n.recipe_id));
    const blockedIds = new Set([
      ...blockedByMe.map(b => b.blocked_id),
      ...blockedByOthers.map(b => b.blocker_id),
    ]);

    // Get user's likes, saves, follow list for personalization
    const userLikes = await base44.asServiceRole.entities.RecipeLike.filter({
      created_by: user.email,
    }).catch(() => []);

    const userSaves = await base44.asServiceRole.entities.RecipeSave.filter({
      created_by: user.email,
    }).catch(() => []);

    const follows = await base44.asServiceRole.entities.UserFollow.filter({
      follower_id: user.id,
      status: 'accepted',
    }).catch(() => []);

    const followedIds = new Set(follows.map(f => f.following_id));
    const likedIds = new Set(userLikes.map(l => l.recipe_id));
    const savedIds = new Set(userSaves.map(s => s.recipe_id));

    // Candidate pool: public user-created recipes (source='user') not liked/saved/not-interested and not own
    const allRecipes = await base44.asServiceRole.entities.Recipe.filter({
      is_public: true,
      source: 'user',
    }, '-created_date', 200);

    const candidates = allRecipes.filter(r => 
      r.created_by !== user.email &&
      !notInterestedIds.has(r.id) &&
      !likedIds.has(r.id) &&
      !savedIds.has(r.id) &&
      r.community_visible !== false &&
      (!r.author_account_status || r.author_account_status === 'active') &&
      // CRITICAL: Block filter — exclude blocked authors bidirectionally
      !blockedIds.has(r.author_id)
    );

    // Score each candidate
    const scoredRecipes = await Promise.all(candidates.map(async (recipe) => {
      // Engagement metrics
      const likes = recipe.likes_count || 0;
      const saves = recipe.saves_count || 0;
      const reviews = recipe.review_count || 0;
      const rating = recipe.avg_rating || 0;

      // Get completions
      const completions = await base44.asServiceRole.entities.RecipeCompletion.filter({
        recipe_id: recipe.id,
      }).catch(() => []);

      const cookIntent = completions.length; // Higher if many people cooked it

      // Freshness boost (more recent = higher)
      const ageMs = Date.now() - new Date(recipe.created_date).getTime();
      const ageDays = ageMs / (1000 * 60 * 60 * 24);
      const freshnessBoost = Math.exp(-ageDays / 7); // decay over 7 days

      // Engagement score
      const engagementScore = 
        (3 * (saves / Math.max(likes, 1))) + // SaveRate (high save rate = good)
        (2 * (likes / Math.max(likes + 100, 1))) + // CTR proxy
        (1.5 * (reviews / Math.max(likes, 1))) + // CommentRate
        (1 * (likes / Math.max(likes + 1, 1))) + // LikeRate
        (2 * (cookIntent / Math.max(likes, 1))) + // CookIntent (people actually making it)
        (1 * (rating / 5)); // RatingQuality

      // Personalization factor
      let personalizationFactor = 1.0;

      // Boost if tags match user interests
      if (recipe.tags && recipe.tags.length > 0) {
        const tagMatches = recipe.tags.filter(t => 
          ['vegan', 'vegetarian', 'gluten-free', 'dairy-free', 'keto', 'high-protein'].includes(t)
        ).length;
        personalizationFactor = 1.0 + (tagMatches * 0.1);
      }

      // Budget / low-cost preference boost
      if (user.prefers_low_cost && recipe.cost_per_serving && recipe.cost_per_serving < 5) {
        personalizationFactor *= 1.3;
      }

      // Follow penalty (low weight for followed creators)
      const followPenalty = followedIds.has(recipe.created_by) ? 0.8 : 1.0;

      // Final rank score
      const rankScore = engagementScore * freshnessBoost * personalizationFactor * followPenalty;

      if (isDev) {
        return {
          recipe,
          rankScore,
          debug: {
            engagementScore: engagementScore.toFixed(2),
            freshnessBoost: freshnessBoost.toFixed(3),
            personalizationFactor: personalizationFactor.toFixed(2),
            cookIntent,
            likes,
            saves,
            reviews,
          },
        };
      }

      return { recipe, rankScore };
    }));

    // Sort by rank score
    scoredRecipes.sort((a, b) => b.rankScore - a.rankScore);

    // Apply diversity constraints: max 2 per creator, mix of categories
    const creatorCounts = {};
    const diverseRecipes = [];
    const categories = {};

    for (const scored of scoredRecipes) {
      const recipe = scored.recipe;
      const creator = recipe.created_by;

      // Max 2 per creator
      if ((creatorCounts[creator] || 0) >= 2) continue;
      creatorCounts[creator] = (creatorCounts[creator] || 0) + 1;

      // Track category balance
      const category = recipe.cuisine || 'other';
      categories[category] = (categories[category] || 0) + 1;

      diverseRecipes.push(scored);

      if (diverseRecipes.length >= limit) break;
    }

    // Add 20% exploration (random from lower-ranked)
    const explorationCount = Math.ceil(limit * 0.2);
    const exploration = scoredRecipes
      .slice(limit)
      .sort(() => Math.random() - 0.5)
      .slice(0, explorationCount);

    const finalRecipes = [...diverseRecipes, ...exploration]
      .slice(0, limit)
      .map(scored => ({
        ...scored.recipe,
        ...(isDev ? { _debug: scored.debug } : {}),
      }));

    // Enrich with viewer state
    const enrichedPosts = await Promise.all(finalRecipes.map(async (recipe) => {
      const agg = await base44.asServiceRole.entities.RecipeAggregate.filter({
        recipe_id: recipe.id,
      }).catch(() => []);

      return {
        ...recipe,
        viewer_has_liked: likedIds.has(recipe.id),
        viewer_has_saved: savedIds.has(recipe.id),
        cooked_count_unique_users: agg[0]?.cooked_count_unique_users || 0,
      };
    }));

    console.log(`[FEED_FOR_YOU] user=${user.id} posts=${enrichedPosts.length} candidates=${candidates.length}`);

    return Response.json({
      posts: enrichedPosts,
      total: enrichedPosts.length,
      algorithm: isDev ? 'advanced-ranking' : undefined,
    });
  } catch (error) {
    console.error('getForYouFeedAdvanced error:', error);
    return Response.json({ error: error.message }, { status: 500 });
  }
});

/**
 * getForYouFeedCached — PERSONALIZED "For You" Feed v2
 *
 * UPGRADE from v1:
 *   v1 was quality × recency × stage — identical ordering for all users.
 *   v2 adds TRUE per-user personalization:
 *     - cuisine affinity (from likes/saves/generations)
 *     - tag affinity (from behavior + declared preferences)
 *     - followed-author boost
 *     - goal matching (high-protein, low-calorie)
 *     - already-engaged dampening
 *     - not-interested exclusion
 *     - author-fatigue penalty (max exposure per author)
 *     - exploration injection for unseen quality content
 *     - comments now count in engagement scoring
 *
 * CACHE: 30-min per-user UserFeedCache, keyed by user_id. NEVER shared across users.
 *
 * FORMULA:
 *   finalScore = qualityScore × freshnessBoost × personalizationFactor
 *                × explorationFactor × reinsertionMod × antiFatigueFactor
 *
 * Where:
 *   qualityScore = (rating×4) + (saves×2.5) + (reviews×2) + (likes×0.8) + (comments×1.2) + 0.1
 *   freshnessBoost = ageDays ≤ 1 ? 1.0 : exp(-ageDays / 14)
 *   personalizationFactor = 1.0 + cuisine_affinity + tag_match + followed_author + goal_match
 *   explorationFactor = unseen quality content gets 1.06× boost
 *   reinsertionMod = warmup phase dampening
 *   antiFatigueFactor = repeat author dampening
 */
import { createClientFromRequest } from 'npm:@base44/sdk@0.8.25';

const STAGE_WEIGHT = {
  0: 0.20,
  1: 0.30,
  2: 0.50,
  3: 0.70,
  4: 0.85,
  5: 1.00,
  6: 1.00,
  7: 1.00,
  8: 1.00,
};
const LIMITED_WEIGHT = 0.10;
const MIN_NEW_SLOTS = 2;
const TTL_MINUTES = 30;

// ── Build user preference profile from behavior ──────────────────────────────
async function buildUserProfile(sr, user) {
  const [
    userPrefsArr,
    notInterestedArr,
    userLikesArr,
    userSavesArr,
    blockedByMe,
    blockedByOthers,
    userFollows,
    postEvents,
    recentGenerations,
  ] = await Promise.all([
    sr.entities.UserPreference.filter({ owner_id: user.id }).catch(() => []),
    sr.entities.FeedPreference.filter({ created_by: user.email, preference_type: 'not_interested' }).catch(() => []),
    sr.entities.Like.filter({ target_type: 'recipe', user_id: user.id }).catch(() => []),
    sr.entities.RecipeSave.filter({ created_by: user.email }).catch(() => []),
    sr.entities.BlockedUser.filter({ blocker_id: user.id }).catch(() => []),
    sr.entities.BlockedUser.filter({ blocked_id: user.id }).catch(() => []),
    sr.entities.UserFollow.filter({ follower_id: user.id, status: 'accepted' }).catch(() => []),
    sr.entities.PostEvent.filter({ created_by: user.email }).catch(() => []),
    sr.entities.AiGenerationEvent.filter({ created_by: user.email }).catch(() => []),
  ]);

  const prefs = userPrefsArr[0] || {};
  const notInterestedIds = new Set(notInterestedArr.map(n => n.recipe_id));
  const likedRecipeIds = new Set(userLikesArr.map(l => l.target_id));
  const savedRecipeIds = new Set(userSavesArr.map(s => s.recipe_id));
  const followedAuthorIds = new Set(userFollows.map(f => f.following_id));
  const blockedIds = new Set([
    ...blockedByMe.map(b => b.blocked_id),
    ...blockedByOthers.map(b => b.blocker_id),
  ]);
  const engagedIds = new Set([...likedRecipeIds, ...savedRecipeIds]);
  const clickedRecipeIds = new Set(
    postEvents.filter(e => e.event_type === 'click' || e.event_type === 'view').map(e => e.recipe_id).filter(Boolean)
  );

  // User goals
  const userGoals = Array.isArray(user.goals) ? user.goals : [];
  const preferHighProtein = userGoals.some(g => ['high_protein', 'muscle_gain', 'bulking'].includes(g)) || !!prefs.prefer_high_protein;
  const preferLowCalorie = userGoals.some(g => ['weight_loss', 'low_calorie', 'cutting'].includes(g)) || !!prefs.prefer_low_calorie;

  // Build cuisine + tag affinity from behavior
  const cuisineVotes = {};
  const tagVotes = {};

  for (const gen of recentGenerations.slice(0, 50)) {
    const cuisine = gen.cuisine || (() => { try { return JSON.parse(gen.metadata_json || '{}')?.cuisine; } catch { return null; } })();
    if (cuisine) cuisineVotes[cuisine] = (cuisineVotes[cuisine] || 0) + 1;
    for (const t of (gen.tags || [])) tagVotes[t] = (tagVotes[t] || 0) + 1;
  }

  for (const e of postEvents.slice(0, 100)) {
    if (e.cuisine) cuisineVotes[e.cuisine] = (cuisineVotes[e.cuisine] || 0) + 1;
  }

  // Declared diet tags
  const declaredDietTags = new Set(prefs.preferred_tags || prefs.diet_tags || []);
  const cuisineAffinities = new Set(Object.entries(cuisineVotes).filter(([, v]) => v >= 1).map(([k]) => k));
  const tagAffinities = new Set(Object.entries(tagVotes).filter(([, v]) => v >= 1).map(([k]) => k));
  for (const t of declaredDietTags) tagAffinities.add(t);

  return {
    notInterestedIds,
    likedRecipeIds,
    savedRecipeIds,
    followedAuthorIds,
    blockedIds,
    engagedIds,
    clickedRecipeIds,
    cuisineAffinities,
    tagAffinities,
    preferHighProtein,
    preferLowCalorie,
  };
}

function computePersonalizedScore(recipe, now, profile) {
  const stage = recipe.stage || 0;
  const isLimited = recipe.status === 'limited';
  const stageWeight = isLimited ? LIMITED_WEIGHT : (STAGE_WEIGHT[stage] ?? 1.00);

  const likes = recipe.likes_count || 0;
  const saves = recipe.saves_count || 0;
  const reviews = recipe.review_count || 0;
  const rating = recipe.avg_rating || 0;
  const comments = recipe.comment_count || 0;
  const tags = recipe.tags || [];

  // ── QUALITY SCORE — now includes comments ─────────────────────────────────
  const qualityScore = (rating * 4) + (saves * 2.5) + (reviews * 2) + (likes * 0.8) + (comments * 1.2) + 0.1;

  // ── FRESHNESS — 14-day half-life ──────────────────────────────────────────
  const ageDays = (now - new Date(recipe.created_date || now).getTime()) / 86400000;
  const freshnessBoost = ageDays <= 1 ? 1.0 : Math.exp(-ageDays / 14);

  // ── PERSONALIZATION FACTOR ────────────────────────────────────────────────
  let personalizationFactor = 1.0;

  // Cuisine affinity
  if (recipe.cuisine && profile.cuisineAffinities.has(recipe.cuisine)) {
    personalizationFactor += 0.35;
  }

  // Tag affinity
  const matchingTags = tags.filter(t => profile.tagAffinities.has(t));
  if (matchingTags.length > 0) {
    personalizationFactor += Math.min(matchingTags.length * 0.3, 0.9);
  }

  // Followed author
  if (recipe.author_id && profile.followedAuthorIds.has(recipe.author_id)) {
    personalizationFactor += 0.35;
  }

  // Goal matching
  if (profile.preferHighProtein) {
    const tagMatch = tags.some(t => ['high-protein', 'protein', 'muscle'].includes(t));
    if (tagMatch) personalizationFactor += 0.5;
  }
  if (profile.preferLowCalorie) {
    const tagMatch = tags.some(t => ['low-calorie', 'light', 'diet', 'weight-loss'].includes(t));
    if (tagMatch) personalizationFactor += 0.4;
  }

  // Already-engaged dampening — gentler than Recommended (0.5× vs 0.25×)
  if (profile.engagedIds.has(recipe.id)) {
    personalizationFactor *= 0.5;
  }

  // ── EXPLORATION FACTOR ────────────────────────────────────────────────────
  const isUnseen = !profile.clickedRecipeIds.has(recipe.id) && !profile.engagedIds.has(recipe.id);
  const explorationFactor = (isUnseen && qualityScore > 5) ? 1.06 : 1.0;

  // ── REINSERTION ───────────────────────────────────────────────────────────
  let reinsertionMod = 1.0;
  if (recipe.reinsertion_phase === 'warmup' && recipe.reinsertion_weight != null) {
    reinsertionMod = Math.max(0.35, recipe.reinsertion_weight);
  }

  // ── STAGE-1 BONUS ─────────────────────────────────────────────────────────
  const newBonus = (stage === 1 && !isLimited) ? 1.3 : 1.0;

  return {
    score: qualityScore * stageWeight * freshnessBoost * personalizationFactor * explorationFactor * reinsertionMod * newBonus,
    stage,
    isNew: (stage === 1) && !isLimited,
    isUnseen,
  };
}

function enrichRecipe(recipe, authorMap, likedIds = new Set()) {
  const author = authorMap[recipe.author_id];
  return {
    ...recipe,
    recipe_id: recipe.id,
    post_id: recipe.id,
    title: recipe.title || '',
    description: recipe.description || '',
    hero_image_url: recipe.hero_image_url || null,
    media_url: recipe.hero_image_url || null,
    author_name: author?.display_name || author?.full_name || recipe.author_name || '',
    author_avatar: author?.avatar_url || recipe.author_avatar || '',
    likes_count: recipe.likes_count || 0,
    like_count: recipe.likes_count || 0,
    saves_count: recipe.saves_count || 0,
    save_count: recipe.saves_count || 0,
    avg_rating: recipe.avg_rating || 0,
    source: recipe.source || 'user',
    _feed_stage: recipe.stage || 0,
    _feed_status: recipe.status || 'active',
    isLiked: likedIds.has(recipe.id),
    viewer_has_liked: likedIds.has(recipe.id),
  };
}

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user?.id) return Response.json({ error: 'Unauthorized' }, { status: 401 });

    const sr = base44.asServiceRole;
    const body = await req.json().catch(() => ({}));
    const limit = Math.min(body.limit || 30, 50);
    const forceRefresh = !!body.refresh;
    const now = Date.now();

    // ── STEP 1: Build user preference profile (always needed for personalization) ──
    const profile = await buildUserProfile(sr, user);

    // ── STEP 2: Check per-user cache ─────────────────────────────────────────
    let cache = null;
    if (!forceRefresh) {
      try {
        const caches = await base44.entities.UserFeedCache.filter(
          { user_id: user.id, feed_type: 'for_you' }, '-cached_at', 1
        );
        cache = caches[0] || null;
      } catch (_) {}
    }

    const cacheAge = cache ? (now - new Date(cache.cached_at).getTime()) / 60000 : Infinity;
    const isFresh = cache && cacheAge < TTL_MINUTES && (cache.post_ids?.length || 0) > 0;

    if (isFresh) {
      const recipeIds = cache.post_ids.slice(0, limit);
      const recipes = await Promise.all(
        recipeIds.map(id =>
          sr.entities.Recipe.filter({ id }).then(r => r[0] || null).catch(() => null)
        )
      );

      const valid = recipes.filter(r =>
        r &&
        r.is_public === true &&
        r.moderation_status !== 'removed_by_moderation' &&
        r.community_visible !== false &&
        r.author_account_status !== 'suspended' &&
        r.author_account_status !== 'deleted' &&
        !profile.blockedIds.has(r.author_id) &&
        !profile.notInterestedIds.has(r.id)
      );

      if (valid.length > 0) {
        const authorIds = [...new Set(valid.map(r => r.author_id).filter(Boolean))];
        const authorMap = {};
        if (authorIds.length > 0) {
          const users = await sr.entities.User.filter({ id: { $in: authorIds } }).catch(() => []);
          users.forEach(u => { authorMap[u.id] = u; });
        }

        const posts = valid.map(r => enrichRecipe(r, authorMap, profile.likedRecipeIds));
        return Response.json({ posts, cached: true, cacheAge: Math.round(cacheAge) });
      }
    }

    // ── STEP 3: Cache miss — build personalized feed ─────────────────────────
    console.log('[getForYouFeedCached:v2] Cache stale/missing — recomputing for user', user.id);

    const allRecipes = await sr.entities.Recipe.filter(
      { is_public: true },
      '-created_date',
      300
    ).catch(() => []);

    // Base eligibility filter
    const visible = allRecipes.filter(r =>
      r.is_public === true &&
      r.moderation_status !== 'removed_by_moderation' &&
      r.moderation_status !== 'deleted_by_owner' &&
      r.community_visible !== false &&
      r.author_account_status !== 'suspended' &&
      r.author_account_status !== 'deleted'
    );

    // Viewer-specific filters: blocked + not interested
    const eligible = visible.filter(r =>
      (!r.author_id || !profile.blockedIds.has(r.author_id)) &&
      !profile.notInterestedIds.has(r.id)
    );

    console.log(`[getForYouFeedCached:v2] Eligibility: ${allRecipes.length} total → ${eligible.length} eligible`);

    // ── PERSONALIZED RANKING ─────────────────────────────────────────────────
    const scored = eligible.map(r => {
      const result = computePersonalizedScore(r, now, profile);
      return { recipe: r, ...result };
    });

    scored.sort((a, b) => b.score - a.score);

    // ── FEED COMPOSITION ─────────────────────────────────────────────────────
    // 1. Reserve MIN_NEW_SLOTS for Stage-1 posts
    const newPosts = scored.filter(s => s.isNew).slice(0, MIN_NEW_SLOTS);
    const newPostIds = new Set(newPosts.map(s => s.recipe.id));

    // 2. Fill remaining from high-score
    const remaining = scored.filter(s => !newPostIds.has(s.recipe.id));

    // 3. Interleave new posts at natural positions
    const combined = [...remaining];
    if (newPosts.length > 0) combined.splice(Math.min(2, combined.length), 0, newPosts[0]);
    if (newPosts.length > 1) combined.splice(Math.min(7, combined.length), 0, newPosts[1]);

    // 4. Author-fatigue diversity: max 3 per author (relaxed if ≤1 unique author)
    const uniqueAuthors = new Set(combined.map(s => s.recipe.author_id).filter(Boolean));
    const perAuthorCap = uniqueAuthors.size <= 1 ? Infinity : 3;
    const authorCount = {};
    const diversified = combined.filter(s => {
      const ac = authorCount[s.recipe.author_id] || 0;
      if (ac >= perAuthorCap) return false;
      authorCount[s.recipe.author_id] = ac + 1;
      return true;
    });

    const finalList = diversified.slice(0, Math.max(limit, 20));

    // ── CACHE SAVE (user-scoped) ─────────────────────────────────────────────
    const recipeIds = finalList.map(s => s.recipe.id);
    try {
      if (cache) {
        await base44.entities.UserFeedCache.update(cache.id, {
          post_ids: recipeIds,
          cached_at: new Date().toISOString(),
          total_posts: recipeIds.length,
        });
      } else {
        await base44.entities.UserFeedCache.create({
          user_id: user.id,
          feed_type: 'for_you',
          post_ids: recipeIds,
          cached_at: new Date().toISOString(),
          cache_ttl_minutes: TTL_MINUTES,
          total_posts: recipeIds.length,
        });
      }
    } catch (e) {
      console.warn('[getForYouFeedCached:v2] Cache save failed:', e.message);
    }

    // ── ENRICH + RETURN ──────────────────────────────────────────────────────
    const authorIds = [...new Set(finalList.map(s => s.recipe.author_id).filter(Boolean))];
    const authorMap = {};
    if (authorIds.length > 0) {
      const users = await sr.entities.User.filter({ id: { $in: authorIds } }).catch(() => []);
      users.forEach(u => { authorMap[u.id] = u; });
    }

    const posts = finalList.slice(0, limit).map(s => enrichRecipe(s.recipe, authorMap, profile.likedRecipeIds));

    const stageDist = {};
    finalList.forEach(s => { stageDist[s.stage] = (stageDist[s.stage] || 0) + 1; });
    console.log(`[getForYouFeedCached:v2] Returning ${posts.length} posts. Stage: ${JSON.stringify(stageDist)}`);

    return Response.json({ posts, cached: false, stage_distribution: stageDist });

  } catch (error) {
    console.error('[getForYouFeedCached:v2] Error:', error.message);
    return Response.json({ error: error.message, posts: [], ok: false }, { status: 500 });
  }
});

/**
 * getFullIntegrationState — Return COMPLETE backend truth for cost audit dashboard refresh
 * 
 * This is the single source of truth for UI refresh.
 * Called on every refresh to ensure zero stale state.
 */
import { createClientFromRequest } from 'npm:@base44/sdk@0.8.23';

function getMonthKey() {
  const now = new Date();
  return `${now.getUTCFullYear()}-${String(now.getUTCMonth() + 1).padStart(2, '0')}`;
}

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user || user.role !== 'admin') {
      return Response.json({ error: 'Admin only' }, { status: 403 });
    }

    const monthKey = getMonthKey();
    const sr = base44.asServiceRole;

    // Fetch monthly state
    const monthlyRecords = await sr.entities.MonthlyIntegrationUsageState.filter(
      { month_key: monthKey }, null, 1
    ).catch(() => []);
    const monthlyState = monthlyRecords[0] || {
      monthly_max_credits: 50000,
      threshold_percent: 33,
      threshold_credits_computed: 16500,
      tracked_base44_credits_used: 0,
      auto_mode_enabled: true,
    };

    // Fetch all raw logs to recompute raw totals
    const allLogs = await sr.entities.IntegrationCostLog.list('-created_date', 5000).catch(() => []);

    const now = new Date();
    const monthStart = new Date(Date.UTC(now.getUTCFullYear(), now.getUTCMonth(), 1));
    const monthEnd = new Date(Date.UTC(now.getUTCFullYear(), now.getUTCMonth() + 1, 1));

    const monthLogs = allLogs.filter(log => {
      const ts = new Date(log.created_date || log.timestamp || 0);
      return ts >= monthStart && ts < monthEnd;
    });

    // Recompute raw billable totals using unified accounting
    let rawBillableTotal = 0;
    let base44ImageCount = 0;
    let togetherImageCount = 0;
    let llmCount = 0;

    monthLogs.forEach(log => {
      const isTogether = log.integration_name?.toLowerCase().includes('together');
      const isBase44Image = log.cost_category === 'image_generation' && !isTogether;

      if (isBase44Image) {
        base44ImageCount++;
        rawBillableTotal += 7;
      } else if (log.cost_category === 'image_generation') {
        togetherImageCount++;
        // Together = 0 credits, not added to total
      } else if (log.cost_category === 'llm') {
        llmCount++;
        rawBillableTotal += (log.estimated_cost_units || 1);
      }
    });

    // Resolve current provider/model
    const used = monthlyState.tracked_base44_credits_used || 0;
    const threshold = monthlyState.threshold_credits_computed || 16500;
    const hasOverride = !!monthlyState.testing_override && !!monthlyState.testing_image_provider;
    const autoMode = used >= threshold ? 'togetherai' : 'base44';
    const resolvedProvider = hasOverride ? monthlyState.testing_image_provider : autoMode;
    const resolvedModel = monthlyState.current_text_model || 'automatic';

    return Response.json({
      month_key: monthKey,
      timestamp: new Date().toISOString(),

      // Backend truth: all settings
      monthly_max_credits: monthlyState.monthly_max_credits || 50000,
      threshold_percent: monthlyState.threshold_percent || 33,
      threshold_credits_computed: monthlyState.threshold_credits_computed || 16500,

      // Usage totals
      raw_logs_count: monthLogs.length,
      raw_billable_total: rawBillableTotal,
      tracked_base44_credits_used: used,
      actual_billed_credits: monthlyState.actual_billed_credits || null,

      // Reconciliation
      raw_vs_tracked_delta: Math.abs(rawBillableTotal - used),
      tracked_vs_billed_delta: monthlyState.actual_billed_credits ? Math.abs(monthlyState.actual_billed_credits - used) : null,

      // Provider/model resolution
      resolved_provider: resolvedProvider,
      resolved_text_model: resolvedModel,
      auto_mode_enabled: monthlyState.auto_mode_enabled !== false,
      override_active: hasOverride,
      testing_override: monthlyState.testing_override || null,
      testing_image_provider: monthlyState.testing_image_provider || null,

      // Override history
      switched_at: monthlyState.switched_at || null,
      switched_by: monthlyState.switched_by || null,
      updated_by: monthlyState.updated_by || null,

      // Event breakdown
      base44_image_events: base44ImageCount,
      together_image_events: togetherImageCount,
      llm_events: llmCount,
    });
  } catch (err) {
    console.error('[getFullIntegrationState]', err.message);
    return Response.json({ error: err.message }, { status: 500 });
  }
});

import { createClientFromRequest } from 'npm:@base44/sdk@0.8.25';

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user) return Response.json({ error: 'Unauthorized' }, { status: 401 });

    const body = await req.json().catch(() => ({}));
    const limit = body.limit || 50;
    const resolveEventId = body.resolve_recipe_id || null;

    console.log(`[getGeneratedHistory] START user=${user.id} limit=${limit} resolve=${resolveEventId || 'none'}`);

    // If called with resolve_recipe_id, look up the saved_recipe_id for that specific event
    if (resolveEventId) {
      const events = await base44.asServiceRole.entities.AiGenerationEvent.filter(
        { user_id: user.id, id: resolveEventId },
