      if (ev.saved_recipe_id) return Response.json({ saved_recipe_id: ev.saved_recipe_id });
      try {
        const payload = ev.recipe_payload ? (typeof ev.recipe_payload === 'string' ? JSON.parse(ev.recipe_payload) : ev.recipe_payload) : null;
        if (payload?.id) return Response.json({ saved_recipe_id: payload.id });
      } catch (_) {}
      return Response.json({ saved_recipe_id: null });
    }

    // Normal list — fetch events
    const events = await base44.asServiceRole.entities.AiGenerationEvent.filter(
      { user_id: user.id },
      '-created_date',
      limit
    );

    console.log(`[getGeneratedHistory] FETCHED ${events.length} events for user=${user.id}`);

    // Filter out non-displayable events (credit_consumed, failed, blocked)
    const displayable = events.filter(e => 
      e.status === 'generated' || e.status === 'saved' || e.status === 'logged' || e.status === 'discarded'
    );

    // Enrich: ensure recipe_image_url is present
    const enriched = displayable.map(e => {
      // If recipe_image_url is already on the event record, use it directly
      if (e.recipe_image_url) {
        // Strip heavy recipe_payload but keep the image
        const { recipe_payload, ...rest } = e;
        return rest;
      }

      // Fallback: extract from recipe_payload if image was stored inside it
      let extractedImage = null;
      if (e.recipe_payload) {
        try {
          const payload = typeof e.recipe_payload === 'string' ? JSON.parse(e.recipe_payload) : e.recipe_payload;
          extractedImage = payload?.hero_image_url || payload?.image_url || null;
        } catch (_) {}
      }

      const { recipe_payload, ...rest } = e;
      if (extractedImage) {
        return { ...rest, recipe_image_url: extractedImage };
      }

      // If event has a saved_recipe_id, we'll resolve the image on the client side
      // from the Recipe entity when the user clicks the card
      return rest;
    });

    console.log(`[getGeneratedHistory] SUCCESS returning ${enriched.length} events (${displayable.length} displayable of ${events.length} total)`);

    return Response.json({ events: enriched, total: enriched.length });
  } catch (error) {
    console.error('[getGeneratedHistory] FAILED:', error.message);
    return Response.json({ error: error.message }, { status: 500 });
  }
});

/**
 * getGroupDetail v4 — fast parallel fetch: group + membership in one shot.
 * No sleep-based retries (client handles retries). Fails fast on real errors.
 */
import { createClientFromRequest } from 'npm:@base44/sdk@0.8.25';

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();

    let group_id;
    try {
      const body = await req.json();
      group_id = body.group_id;
    } catch {
      const url = new URL(req.url);
      group_id = url.searchParams.get('group_id');
    }

    if (!group_id) {
      return Response.json({ ok: false, error: 'group_id required', code: 'NO_GROUP_ID' }, { status: 400 });
    }

    // Run group fetch + membership check IN PARALLEL for speed
    const [groupResult, membershipResult] = await Promise.allSettled([
      base44.asServiceRole.entities.Group.get(group_id),
      user?.id
        ? base44.asServiceRole.entities.GroupMember.filter({ group_id, user_id: user.id })
        : Promise.resolve([]),
    ]);

    // Handle group fetch result
    const group = groupResult.status === 'fulfilled' ? groupResult.value : null;

    if (!group) {
      const err = groupResult.status === 'rejected' ? groupResult.reason : null;
      console.warn(`[GET_GROUP:${group_id}] group not found or fetch failed: ${err?.message}`);
      return Response.json({ ok: false, error: 'Group not found', code: 'NOT_FOUND' }, { status: 404 });
    }

    if (!user && group.privacy === 'private') {
      return Response.json({ ok: false, error: 'Authentication required', code: 'FORBIDDEN' }, { status: 403 });
    }

    // Handle membership result — on error, default to non-member (don't block the load)
    let viewerIsMember = false;
    let viewerRole = 'none';
    let viewerIsBanned = false;

    if (membershipResult.status === 'fulfilled') {
      const membership = membershipResult.value || [];
      if (membership.length > 0) {
        const activeMembership = membership.find(m => !m.status || m.status !== 'banned');
        const bannedMembership = membership.find(m => m.status === 'banned');
        if (activeMembership) {
          viewerIsMember = true;
          viewerRole = activeMembership.role || 'member';
        } else if (bannedMembership) {
          viewerIsBanned = true;
        }
      }
    } else {
      // Membership check failed — log but don't block. Default to non-member.
      console.warn(`[GET_GROUP:${group_id}] membership check failed: ${membershipResult.reason?.message} — defaulting to non-member`);
    }

    // For friends_chat groups, never block on membership failure — the user was invited.
    // Only block public community groups that are truly private.
    if (group.privacy === 'private' && !viewerIsMember && group.group_type !== 'friends_chat') {
      return Response.json({ ok: false, error: 'This group is private', code: 'FORBIDDEN' }, { status: 403 });
    }

    const isOwner = user?.id === group.owner_id;
    const effectiveRole = isOwner ? 'owner' : viewerRole;

    return Response.json({
      ok: true,
      success: true,
      group,
      viewer_is_member: viewerIsMember,
      viewer_role: effectiveRole,
      viewer_is_banned: viewerIsBanned,
    });
  } catch (error) {
    console.error('[getGroupDetail] uncaught:', error.message);
    return Response.json({ ok: false, error: error.message, code: 'INTERNAL_SERVER_ERROR' }, { status: 500 });
  }
});

