/**
 * getGroupEligibleUsers — Returns ONLY users who follow the current user.
 *
 * STRICT RULE: The ONLY eligible source is FOLLOWERS of the current user.
 * - NOT people I follow
 * - NOT DM contacts
 * - NOT global search
 * - NOT random users
 *
 * Params: { search?: string }
 */
Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const me = await base44.auth.me();
    if (!me) return Response.json({ error: 'Unauthorized' }, { status: 401 });

    const body = await req.json().catch(() => ({}));
    const searchQuery = (body.search || '').trim().toLowerCase();

    const sr = base44.asServiceRole;

    // Fetch: people who follow me + blocked users
    const [followMe, blockedByMe, blockedMe] = await Promise.all([
      sr.entities.Follow.filter({ followed_id: me.id, status: 'accepted' }, '', 500).catch(() => []),
      sr.entities.BlockedUser.filter({ blocker_id: me.id }).catch(() => []),
      sr.entities.BlockedUser.filter({ blocked_id: me.id }).catch(() => []),
    ]);

    const blockedIds = new Set([
      ...blockedByMe.map(b => b.blocked_id),
      ...blockedMe.map(b => b.blocker_id),
    ]);

    // STRICT: Only people who follow me, minus blocked, minus self
    const followerIds = [...new Set(
      followMe.map(f => f.follower_id).filter(id => id !== me.id && !blockedIds.has(id))
    )];

    if (followerIds.length === 0) {
      return Response.json({ users: [] });
    }

    // Batch fetch user profiles
    const users = [];
    for (let i = 0; i < followerIds.length; i += 15) {
      const chunk = followerIds.slice(i, i + 15);
      const fetched = await Promise.all(
        chunk.map(id => sr.entities.User.filter({ id }).then(r => r[0] || null).catch(() => null))
      );
      for (const u of fetched) {
        if (!u) continue;
        const status = u.account_status || 'active';
        if (['suspended', 'pending_deletion', 'deleted'].includes(status)) continue;
        const displayName = (u.display_name || u.full_name || '').trim();
        if (!displayName) continue;

        // If searching, filter by name/username
        if (searchQuery) {
          const dn = displayName.toLowerCase();
          const fn = (u.full_name || '').toLowerCase();
          const un = (u.username || '').toLowerCase();
          if (!dn.includes(searchQuery) && !fn.includes(searchQuery) && !un.includes(searchQuery)) continue;
        }

        users.push({
          id: u.id,
          display_name: displayName,
          full_name: u.full_name || null,
          avatar_url: u.avatar_url || null,
          username: u.username || null,
        });
      }
    }

    // Sort alphabetically
    users.sort((a, b) => (a.display_name || '').localeCompare(b.display_name || ''));

    return Response.json({ users });
  } catch (error) {
    console.error('[getGroupEligibleUsers] error:', error);
    return Response.json({ error: error.message }, { status: 500 });
  }
});

