/**
 * getGroupMembers v3 — fetch group members enriched with presence/online data.
 * PERF FIX: Only fetches User records for actual group members (not all 2000 users).
 * Returns deduplicated member list with is_online, last_seen_at, etc.
 */
import { createClientFromRequest } from 'npm:@base44/sdk@0.8.23';

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user) {
      return Response.json({ error: 'Unauthorized' }, { status: 401 });
    }

    const body = await req.json().catch(() => ({}));
    const { group_id } = body;

    if (!group_id) {
      return Response.json({ error: 'group_id required' }, { status: 400 });
    }

    const sr = base44.asServiceRole.entities;

    // Get all GroupMember records for this group
    const groupMembers = await sr.GroupMember.filter({ group_id }, '-created_date', 500).catch(() => []);

    if (!groupMembers.length) {
      return Response.json({ members: [], total_unique: 0, online_count: 0, offline_count: 0 });
    }

    // Deduplicate by user_id — keep highest-priority role
    const rolePriority = { owner: 3, admin: 2, member: 1 };
    const byUser = {};
    for (const m of groupMembers) {
      if (!m.user_id) continue;
      const existing = byUser[m.user_id];
      if (!existing) {
        byUser[m.user_id] = m;
      } else {
        const existingPriority = rolePriority[existing.role] || 1;
        const newPriority = rolePriority[m.role] || 1;
        if (newPriority > existingPriority) byUser[m.user_id] = m;
      }
    }
    const deduped = Object.values(byUser);

    // PERF FIX: Fetch up to 500 recently-seen users in ONE query, then intersect with members.
    // This is O(1) queries instead of O(N) per member — critical for groups with many members.
    const memberUserIds = deduped.map(m => m.user_id).filter(Boolean);
    const userMap = {};

    // Fetch all users seen in the last 24h in a single query (covers online + recently offline)
    const recentCutoff = new Date(Date.now() - 24 * 60 * 60 * 1000).toISOString();
    const recentUsers = await sr.User.filter(
      { last_seen_at: { $gte: recentCutoff } },
      '-last_seen_at',
      500
    ).catch(() => []);

    for (const u of recentUsers) {
      if (u?.id && memberUserIds.includes(u.id)) {
        userMap[u.id] = u;
      }
    }

    // For any members NOT in the recent window, fetch individually (usually very few)
    const missingIds = memberUserIds.filter(uid => !userMap[uid]);
    if (missingIds.length > 0) {
      const missingResults = await Promise.all(
        missingIds.map(uid => sr.User.filter({ id: uid }, '-created_date', 1).catch(() => []))
      );
      for (const arr of missingResults) {
        if (arr[0]) userMap[arr[0].id] = arr[0];
      }
    }

    const now = Date.now();
    const GRACE_PERIOD_MS = 5 * 60 * 1000; // 5 minutes — online if seen within 5 min

    const memberData = deduped.map(gm => {
      const u = userMap[gm.user_id];

      let isOnline = false;
      let lastSeenAt = null;
      let lastActiveMinutesAgo = null;
      let onlineForMinutes = null;

      if (u?.last_seen_at) {
        const lastSeen = new Date(u.last_seen_at).getTime();
        const timeSinceLastSeen = now - lastSeen;
        isOnline = timeSinceLastSeen <= GRACE_PERIOD_MS;
        lastSeenAt = u.last_seen_at;
        if (isOnline) {
          // How long have they been online (approx — based on last seen within grace window)
          onlineForMinutes = Math.floor(timeSinceLastSeen / (1000 * 60));
        } else {
          lastActiveMinutesAgo = Math.floor(timeSinceLastSeen / (1000 * 60));
        }
      }

      return {
        user_id: gm.user_id,
        display_name: u?.display_name || u?.full_name || u?.username || null,
        username: u?.display_name || u?.full_name || u?.username || null,
        avatar_url: u?.avatar_url || null,
        avatar_version: u?.avatar_version || 0,
        role: gm.role || 'member',
        joined_at: gm.joined_at || null,
        is_online: isOnline,
        online_for_minutes: onlineForMinutes,
        last_seen_at: lastSeenAt,
        last_active_minutes_ago: lastActiveMinutesAgo,
        is_paused: u?.account_status === 'paused',
      };
    }).filter(m => m.user_id);

    // Sort: online first, then by last_seen descending
    memberData.sort((a, b) => {
      if (a.is_online !== b.is_online) return b.is_online ? 1 : -1;
      const aTime = new Date(a.last_seen_at || 0).getTime();
      const bTime = new Date(b.last_seen_at || 0).getTime();
      return bTime - aTime;
    });

    const onlineCount = memberData.filter(m => m.is_online).length;

    return Response.json({
      members: memberData,
      total_unique: memberData.length,
      online_count: onlineCount,
      offline_count: memberData.length - onlineCount,
    });

  } catch (error) {
    console.error('[getGroupMembers]', error.message);
    return Response.json({ error: error.message }, { status: 500 });
  }
});

import { createClientFromRequest } from 'npm:@base44/sdk@0.8.20';

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user) {
      return Response.json({ error: 'Unauthorized' }, { status: 401 });
    }

    const { group_id } = await req.json();
    if (!group_id) {
      return Response.json({ error: 'Missing group_id' }, { status: 400 });
    }

    // Verify user can view group
    const viewer_membership = await base44.entities.GroupMember.filter({
      group_id,
      user_id: user.id,
    });
    if (!viewer_membership || viewer_membership.length === 0) {
      return Response.json({ error: 'Not authorized to view group members' }, { status: 403 });
    }

    // Get all members (deduped by user_id)
    const all_memberships = await base44.entities.GroupMember.filter({
      group_id,
    });

    if (!all_memberships) {
      return Response.json({
        members: [],
        total_unique: 0,
        online_count: 0,
        offline_count: 0,
      });
    }

    // Dedupe by user_id (keep first occurrence)
    const seen = new Set();
    const unique_memberships = [];
    for (const m of all_memberships) {
      if (!seen.has(m.user_id)) {
        seen.add(m.user_id);
        unique_memberships.push(m);
      }
    }

    // Fetch user profiles + presence data
    const member_ids = unique_memberships.map(m => m.user_id);
    let all_users = [];
    try {
      all_users = await base44.entities.User.list();
    } catch {
      all_users = [];
    }

    const user_map = {};
    for (const u of all_users) {
      user_map[u.id] = u;
    }

    // Fetch presence data
    let all_presence = [];
    try {
      all_presence = await base44.entities.Presence.filter({ group_id });
    } catch {
      all_presence = [];
    }

    const presence_map = {};
    for (const p of all_presence) {
      presence_map[p.user_id] = p;
    }

    // Determine online status (within 45 seconds)
    const now = new Date();
    const ONLINE_THRESHOLD_MS = 45 * 1000;

    const members = unique_memberships.map(m => {
      const profile = user_map[m.user_id] || {};
      const presence = presence_map[m.user_id];
      const last_seen_at = presence?.last_seen_at ? new Date(presence.last_seen_at) : null;
      const is_online = last_seen_at && (now - last_seen_at) <= ONLINE_THRESHOLD_MS;

      return {
        user_id: m.user_id,
        username: profile.full_name || 'Unknown',
        avatar_url: profile.avatar_url || null,
        is_online: !!is_online,
        last_seen_at: presence?.last_seen_at || null,
        is_private: profile.privacy_last_seen_enabled === false,
      };
    });

    // Sort by last_seen_at descending (most recent first)
    members.sort((a, b) => {
      const aTime = a.last_seen_at ? new Date(a.last_seen_at).getTime() : 0;
      const bTime = b.last_seen_at ? new Date(b.last_seen_at).getTime() : 0;
      return bTime - aTime;
    });

    // Split online/offline
    const online = members.filter(m => m.is_online);
    const offline = members.filter(m => !m.is_online);

    return Response.json({
      members: [...online, ...offline], // Online first
      total_unique: members.length,
      online_count: online.length,
      offline_count: offline.length,
    });
  } catch (error) {
    console.error('[getGroupMembersWithPresence]', error.message);
    return Response.json({ error: error.message }, { status: 500 });
  }
});

/**
 * getGroupMessageReactions — Returns all reactions for a group's recent messages.
 * Keyed by message_id: { [emoji]: { count, user_ids } }
 * user_ids includes the real userId. '__me__' sentinel added for backward compat.
 *
 * FIXES:
 * - Deduplicates reactions per user+emoji (cleans DB silently)
 * - Parallel batch fetch (no sequential waterfall)
 * - Returns FULL authoritative state (client should REPLACE, not merge)
 */
import { createClientFromRequest } from 'npm:@base44/sdk@0.8.25';

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user?.id) return Response.json({ error: 'Unauthorized' }, { status: 401 });

    const { group_id } = await req.json().catch(() => ({}));
    if (!group_id) return Response.json({ error: 'group_id required' }, { status: 400 });

    const sr = base44.asServiceRole.entities;

    // Get recent messages for this group
    let messages = [];
    try {
      messages = await sr.ChatMessage.filter({ group_id }, '-created_at', 100);
    } catch {
      messages = [];
    }

    if (!messages.length) return Response.json({ reactions: {} });

    // Parallel fetch all reactions for all messages
    const reactionArrays = await Promise.all(
      messages.map(m => sr.MessageReaction.filter({ message_id: m.id }).catch(() => []))
    );

    // Build reactions map with deduplication
    const reactions = {};
    messages.forEach((msg, i) => {
      const msgReactions = reactionArrays[i] || [];
      if (msgReactions.length === 0) return;

      const grouped = {};
      const seenKeys = new Set();

      for (const r of msgReactions) {
        const key = `${r.user_id}:${r.emoji}`;
        if (seenKeys.has(key)) {
          // Duplicate — silently clean up
          sr.MessageReaction.delete(r.id).catch(() => {});
          continue;
        }
        seenKeys.add(key);

        if (!grouped[r.emoji]) grouped[r.emoji] = { count: 0, user_ids: [] };
        grouped[r.emoji].count++;
        grouped[r.emoji].user_ids.push(r.user_id);

        // Add __me__ sentinel for backward compat
        if (r.user_id === user.id && !grouped[r.emoji].user_ids.includes('__me__')) {
          grouped[r.emoji].user_ids.push('__me__');
        }
      }

      if (Object.keys(grouped).length > 0) {
        reactions[msg.id] = grouped;
      }
    });

    return Response.json({ reactions });
  } catch (err) {
    console.error('[getGroupMessageReactions]', err.message);
    return Response.json({ error: err.message }, { status: 500 });
  }
});

