      ? { status: membership.status, role: membership.role }
      : null;

    const isActiveMember = viewerMembership?.status === 'active';
    const isPublic = group.privacy === 'public' || !group.privacy;
    const canViewContent = isPublic || isActiveMember;

    // JOIN action
    if (action === 'join') {
      if (isActiveMember) {
        return Response.json({ viewer_membership: viewerMembership, already_member: true });
      }
      if (membership?.status === 'pending' || membership?.status === 'requested') {
        return Response.json({ viewer_membership: viewerMembership, already_requested: true });
      }

      const joinMode = group.join_mode || 'open';
      const newStatus = joinMode === 'request' ? 'requested' : 'active';

      if (membership) {
        // Update existing
        await base44.asServiceRole.entities.GroupMember.update(membership.id, { status: newStatus });
      } else {
        await base44.asServiceRole.entities.GroupMember.create({
          group_id,
          user_id: user.id,
          user_name: user.full_name,
          user_avatar: user.avatar_url || '',
          role: 'member',
          status: newStatus,
        });
        if (newStatus === 'active') {
          await base44.asServiceRole.entities.Group.update(group_id, {
            member_count: (group.member_count || 0) + 1,
          });
        }
      }

      return Response.json({
        viewer_membership: { status: newStatus, role: 'member' },
        joined: newStatus === 'active',
        requested: newStatus === 'requested',
      });
    }

    // Default: return group view
    return Response.json({
      group,
      viewer_membership: viewerMembership,
      can_view_content: canViewContent,
    });
  } catch (error) {
    return Response.json({ error: error.message }, { status: 500 });
  }
});

/**
 * getImageProvider — Returns REAL execution provider based on backend truth
 * 
 * Priority:
 * 1. Explicit owner override (testing_override + testing_image_provider)
 * 2. Auto-threshold mode: compare tracked_used vs threshold_computed
 * 3. Default: base44
 * 
 * Response includes:
 * - provider: actual execution provider (base44 or togetherai)
 * - current_mode: resolved mode from MonthlyIntegrationUsageState
 * - threshold details: budget, percent, computed threshold
 * - usage: tracked_base44_credits_used
 * - override status
 */
import { createClientFromRequest } from 'npm:@base44/sdk@0.8.23';

function getMonthKey() {
  const now = new Date();
  const y = now.getUTCFullYear();
  const m = String(now.getUTCMonth() + 1).padStart(2, '0');
  return `${y}-${m}`;
}

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const monthKey = getMonthKey();
    const sr = base44.asServiceRole;

    const records = await sr.entities.MonthlyIntegrationUsageState.filter(
      { month_key: monthKey }, null, 1
    ).catch(() => []);

    const record = records[0];

    if (!record) {
      // Fresh month: no usage yet, base44 by default
      return Response.json({
        provider: 'base44',
        over_threshold: false,
        tracked_credits: 0,
        threshold: 16500,
        threshold_pct: 33,
        budget: 50000,
        current_mode: 'base44',
        auto_mode_enabled: true,
        month_key: monthKey,
        override_active: false,
        testing_override: null,
        current_text_model: 'automatic',
        switched_at: null,
        switched_by: null,
      });
    }

    const used = record.tracked_base44_credits_used || 0;
    const budget = record.monthly_max_credits || 50000;
    const thresholdPct = record.threshold_percent || 33;
    const threshold = record.threshold_credits_computed || Math.round(budget * thresholdPct / 100);
    const autoOverThreshold = used >= threshold;
    const autoProvider = autoOverThreshold ? 'togetherai' : 'base44';

    // Priority 1: Explicit override
    const hasOverride = !!record.testing_override && !!record.testing_image_provider;
    const provider = hasOverride ? record.testing_image_provider : autoProvider;
    const overThreshold = hasOverride ? (provider === 'togetherai') : autoOverThreshold;

    return Response.json({
      provider,
      over_threshold: overThreshold,
      tracked_credits: used,
      threshold,
      threshold_pct: thresholdPct,
      budget,
      current_mode: provider,
      auto_mode_enabled: !hasOverride,
      month_key: monthKey,
      usage_pct: Math.round((used / budget) * 100),
      override_active: hasOverride,
      testing_override: record.testing_override || null,
      testing_image_provider: record.testing_image_provider || null,
      current_text_model: record.current_text_model || 'automatic',
      switched_at: record.switched_at || null,
      switched_by: record.switched_by || null,
    });
  } catch (err) {
    console.error('[getImageProvider]', err.message);
    return Response.json({ provider: 'togetherai', over_threshold: false, error: err.message });
  }
});

/**
 * getIngredientIconReport — Generate report of ingredients missing icons
 */
import { createClientFromRequest } from 'npm:@base44/sdk@0.8.21';

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();

    if (!user || user.role !== 'admin') {
      return Response.json({ error: 'Admin access required' }, { status: 403 });
    }

    // Fetch ALL canonical ingredients with pagination
    let allIngredients = [];
    let offset = 0;
    const pageSize = 500;
    let hasMore = true;

    while (hasMore) {
      const batch = await base44.entities.CanonicalIngredient.list('display_name', pageSize, offset);
      if (!batch || batch.length === 0) {
        hasMore = false;
      } else {
        allIngredients.push(...batch);
        offset += pageSize;
      }
    }

    if (!allIngredients || allIngredients.length === 0) {
      return Response.json({ total: 0, missing: [], missing_count: 0 });
    }

    // Find only ingredients with empty/missing/placeholder emoji
    const missingEmoji = allIngredients.filter(ing => {
      const emoji = ing.emoji || '';
      return (
        !emoji ||
        emoji.trim() === '' ||
        emoji === 'undefined' ||
        emoji === '🍳' // placeholder
      );
    });

    return Response.json({
      total: allIngredients.length,
      missing_count: missingEmoji.length,
      missing: missingEmoji.map(ing => ({
        id: ing.id,
        name: ing.display_name || ing.name,
        category: ing.category,
        current_icon: ing.emoji || '(none)',
      })),
    });
  } catch (error) {
    console.error('Report error:', error);
    return Response.json({ error: error.message }, { status: 500 });
  }
});

