function toGrams(quantity, unit) {
  const map = {
    g: 1, kg: 1000, oz: 28.35, lb: 453.6, lbs: 453.6,
    cup: 240, cups: 240, tbsp: 15, tsp: 5, ml: 1, l: 1000,
    pieces: 100, piece: 100, cloves: 4, clove: 4,
    slices: 30, slice: 30, cans: 400, can: 400, bunch: 150,
  };
  return Math.max(1, (quantity || 100) * (map[(unit || "g").toLowerCase().trim()] || 100));
}

