function mk(name, grams, v, source) {
  return {
    name, grams,
    calories: Math.round((v.cal / 100) * grams * 10) / 10,
    protein: Math.round((v.p / 100) * grams * 10) / 10,
    carbs: Math.round((v.c / 100) * grams * 10) / 10,
    fat: Math.round((v.f / 100) * grams * 10) / 10,
    per100g: { calories: v.cal, protein: v.p, carbs: v.c, fat: v.f },
    source,
  };
}

function localLookup(name, grams) {
  const lower = name.toLowerCase().trim();
  if (LOCAL_DB[lower]) return mk(name, grams, LOCAL_DB[lower], "LocalDB");
  for (const [key, v] of Object.entries(LOCAL_DB)) {
    if (lower.includes(key)) return mk(name, grams, v, "LocalDB");
  }
  return mk(name, grams, { cal: 100, p: 5, c: 15, f: 3 }, "Estimate");
}

Deno.serve(async (req) => {
  const base44 = createClientFromRequest(req);

  let body;
  try { body = await req.json(); } catch { return Response.json({ error: "Invalid JSON" }, { status: 400 }); }

  const { ingredientName, quantity = 100, unit = "g" } = body;
  if (!ingredientName) return Response.json({ error: "ingredientName required" }, { status: 400 });

  const grams = toGrams(quantity, unit);

  const authPromise = base44.auth.me();
  const localResult = localLookup(ingredientName, grams);

  // Try canonical registry lookup + USDA in parallel with auth
  const canonicalPromise = (async () => {
    try {
      const records = await base44.asServiceRole.entities.CanonicalIngredient.filter(
        { normalized_name: ingredientName.toLowerCase().trim() }, null, 1
      );
      if (records.length && records[0].nutrition_per_100g?.calories) {
        const n = records[0].nutrition_per_100g;
        return {
          name: records[0].display_name || ingredientName, grams,
          calories: Math.round((n.calories / 100) * grams * 10) / 10,
          protein: Math.round(((n.protein || 0) / 100) * grams * 10) / 10,
          carbs: Math.round(((n.carbs || 0) / 100) * grams * 10) / 10,
          fat: Math.round(((n.fat || 0) / 100) * grams * 10) / 10,
          per100g: { calories: n.calories, protein: n.protein || 0, carbs: n.carbs || 0, fat: n.fat || 0 },
          source: "CanonicalDB",
        };
      }
    } catch (_) { /* fall through */ }
    return null;
  })();

  let usdaPromise = Promise.resolve(null);
  if (USDA_KEY) {
    usdaPromise = (async () => {
      try {
        const controller = new AbortController();
        const tid = setTimeout(() => controller.abort(), 4000);
        const res = await fetch(
          `https://api.nal.usda.gov/fdc/v1/foods/search?query=${encodeURIComponent(ingredientName)}&pageSize=1&dataType=Foundation,SR%20Legacy&api_key=${USDA_KEY}`,
          { signal: controller.signal }
        );
        clearTimeout(tid);
        if (!res.ok) return null;
        const data = await res.json();
        if (!data.foods?.length) return null;
        const food = data.foods[0];
        const n = food.foodNutrients || [];
        const get = (id) => n.find(x => x.nutrientId === id || x.nutrient?.id === id)?.value || 0;
        const cal = get(1008);
        if (!cal) return null;
        const per100g = { calories: cal, protein: get(1003), carbs: get(1005), fat: get(1004) };
        return {
          name: food.description || ingredientName, grams,
          calories: Math.round((per100g.calories / 100) * grams * 10) / 10,
          protein: Math.round((per100g.protein / 100) * grams * 10) / 10,
          carbs: Math.round((per100g.carbs / 100) * grams * 10) / 10,
          fat: Math.round((per100g.fat / 100) * grams * 10) / 10,
          per100g, source: "USDA",
        };
      } catch { return null; }
    })();
  }

  const [user, canonicalResult, usdaResult] = await Promise.all([authPromise, canonicalPromise, usdaPromise]);
  if (!user) return Response.json({ error: "Unauthorized" }, { status: 401 });

  // Priority: CanonicalDB > USDA > LocalDB/Estimate
  return Response.json(canonicalResult || usdaResult || localResult);
});

/**
 * getLiveEvents — Admin-only endpoint for live event dashboard.
 * Supports filtering by event_type, event_category, and time window.
 */
import { createClientFromRequest } from 'npm:@base44/sdk@0.8.25';

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user || user.role !== 'admin') {
      return Response.json({ error: 'Admin only' }, { status: 403 });
    }

    const body = await req.json().catch(() => ({}));
    const { filter_type, filter_category, minutes_window = 30, limit = 100 } = body;

    const sr = base44.asServiceRole;
    let events;

    if (filter_type) {
      events = await sr.entities.LiveEvent.filter(
        { event_type: filter_type },
        '-timestamp',
        Math.min(limit, 200)
      ).catch(() => []);
    } else if (filter_category) {
      events = await sr.entities.LiveEvent.filter(
        { event_category: filter_category },
        '-timestamp',
        Math.min(limit, 200)
      ).catch(() => []);
    } else {
      events = await sr.entities.LiveEvent.list(
        '-timestamp',
        Math.min(limit, 200)
      ).catch(() => []);
    }

    // Filter to time window
    const cutoff = new Date(Date.now() - minutes_window * 60 * 1000);
    const inWindow = events.filter(e => new Date(e.timestamp || e.created_date) >= cutoff);

    // Compute summary counts
    const counts = {};
    for (const e of inWindow) {
      counts[e.event_type] = (counts[e.event_type] || 0) + 1;
    }

    return Response.json({
      events: inWindow.slice(0, limit),
      total: inWindow.length,
      counts,
      window_minutes: minutes_window,
      filter: filter_type || filter_category || 'all',
    });
  } catch (err) {
    console.error('[getLiveEvents]', err.message);
    return Response.json({ error: err.message }, { status: 500 });
  }
});

