/**
 * getMentionPings — returns unread @mention pings for the current user,
 * grouped by context_id (group_id or conversation_id).
 * Returns: { pings: { [context_id]: { count, notifications: [...] } }, total }
 */
import { createClientFromRequest } from 'npm:@base44/sdk@0.8.23';

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user?.id) return Response.json({ error: 'Unauthorized' }, { status: 401 });

    const sr = base44.asServiceRole;

    // Get all unread mention notifications for this user
    const notifs = await sr.entities.Notification.filter({
      recipient_id: user.id,
      is_read: false,
    }, '-created_date', 200);

    // Filter to only mention notifications
    const mentionNotifs = notifs.filter(n => {
      try {
        const p = JSON.parse(n.payload_json || '{}');
        return p.mention === true;
      } catch {
        return false;
      }
    });

    // Group by context_id
    const pings = {};
    for (const notif of mentionNotifs) {
      try {
        const p = JSON.parse(notif.payload_json || '{}');
        const ctxId = p.context_id || 'unknown';
        if (!pings[ctxId]) pings[ctxId] = { count: 0, notifications: [] };
        pings[ctxId].count++;
        pings[ctxId].notifications.push({
          id: notif.id,
          context_type: p.context_type,
          context_id: ctxId,
          from_user_name: notif.from_user_name,
          message: notif.message,
          created_at: notif.created_date,
        });
      } catch {}
    }

    const total = mentionNotifs.length;

    return Response.json({ ok: true, pings, total });
  } catch (error) {
    console.error('[getMentionPings] error:', error.message);
    return Response.json({ error: error.message }, { status: 500 });
  }
});

