      sr.entities.BlockedUser.filter({ blocker_id: user.id }).catch(() => []),
      sr.entities.BlockedUser.filter({ blocked_id: user.id }).catch(() => []),
    ]);

    // Build bidirectional blocked IDs set
    const blockedIds = new Set([
      ...blockedByMe.map(b => b.blocked_id),
      ...blockedByOthers.map(b => b.blocker_id),
    ]);

    // Filter out comments authored by blocked users
    const filtered = blockedIds.size > 0
      ? comments.filter(c => !c.author_id || !blockedIds.has(c.author_id))
      : comments;

    return Response.json({ comments: filtered });
  } catch (error) {
    console.error('[getPostComments] error:', error.message);
    return Response.json({ error: error.message }, { status: 500 });
  }
});

/**
 * getPricingObservability — PART 10: ANOMALY DETECTION & OBSERVABILITY
 * 
 * Provides production observability for the pricing system:
 * - Top unresolved ingredients (for catalog expansion)
 * - Anomaly rates (fallback-only, suspicious costs, coverage)
 * - Pricing health metrics
 * - Per-recipe pricing diagnostics
 */

import { createClientFromRequest } from 'npm:@base44/sdk@0.8.23';

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user || user.role !== 'admin') {
      return Response.json({ error: 'Admin access required' }, { status: 403 });
    }

    const { lookback_days, limit } = await req.json() || {};
    const days = lookback_days || 7;
    const limit_val = limit || 100;

    const cutoffDate = new Date();
    cutoffDate.setDate(cutoffDate.getDate() - days);

    // Fetch all pricing summaries from last N days
    const summaries = await base44.asServiceRole.entities.RecipePricingSummary.filter(
      { computed_at: { $gte: cutoffDate.toISOString() } },
      '-computed_at',
      10000
    );

    // Aggregated metrics
    const totalRecipes = summaries.length;
    let fullCoverageCount = 0;
    let partialCoverageCount = 0;
    let unresolvedCount = 0;
    let totalUnresolvedIngredients = 0;
    const unresolvedTexts = {};
    const anomalyCounts = {};
    let totalFallbackCount = 0;

    for (const summary of summaries) {
      if (summary.pricing_status === 'full') fullCoverageCount++;
      else if (summary.pricing_status === 'partial') partialCoverageCount++;
      else unresolvedCount++;

      totalUnresolvedIngredients += summary.unresolved_ingredient_count || 0;
      totalFallbackCount += summary.fallback_pricing_count || 0;

      // Track unresolved ingredient texts
      for (const text of (summary.unresolved_ingredient_texts || [])) {
        unresolvedTexts[text] = (unresolvedTexts[text] || 0) + 1;
      }

      // Track anomalies
      for (const flag of (summary.anomaly_flags || [])) {
        anomalyCounts[flag] = (anomalyCounts[flag] || 0) + 1;
      }
    }

    // Sort unresolved by frequency
    const topUnresolved = Object.entries(unresolvedTexts)
      .sort(([, a], [, b]) => b - a)
      .slice(0, limit_val)
      .map(([text, count]) => ({ text, count }));

    // Coverage metrics
    const fullCoverageRatio = totalRecipes > 0 ? (fullCoverageCount / totalRecipes) : 0;
    const fallbackRatio = totalRecipes > 0 ? (totalFallbackCount / (totalRecipes * 5)) : 0; // Rough estimate: ~5 ingredients per recipe

    const healthMetrics = {
      total_recipes_priced: totalRecipes,
      full_coverage_count: fullCoverageCount,
      full_coverage_ratio: (fullCoverageRatio * 100).toFixed(1) + '%',
      partial_coverage_count: partialCoverageCount,
      partial_coverage_ratio: ((partialCoverageCount / totalRecipes) * 100).toFixed(1) + '%',
      unresolved_count: unresolvedCount,
      unresolved_ratio: ((unresolvedCount / totalRecipes) * 100).toFixed(1) + '%',
      total_unresolved_ingredients: totalUnresolvedIngredients,
      fallback_pricing_count: totalFallbackCount,
      fallback_ratio: (fallbackRatio * 100).toFixed(1) + '%',
    };

    return Response.json({
      lookback_days: days,
      generated_at: new Date().toISOString(),
      health: healthMetrics,
      top_unresolved_ingredients: topUnresolved,
      anomaly_distribution: anomalyCounts,
      action_items: generateActionItems(healthMetrics, topUnresolved, anomalyCounts),
    });
  } catch (error) {
    console.error('[getPricingObservability] error:', error.message);
    return Response.json({ error: error.message }, { status: 500 });
  }
});

function generateActionItems(health, topUnresolved, anomalies) {
  const items = [];

  // Check coverage health
  const fullCoverageNum = parseFloat(health.full_coverage_ratio);
  if (fullCoverageNum < 50) {
    items.push({
      severity: 'high',
      issue: 'Low pricing coverage',
      message: `Only ${fullCoverageNum}% of recipes have full pricing coverage`,
      action: 'Review and expand canonical ingredient database',
    });
  }

  // Check unresolved ingredients
  if (topUnresolved.length > 0) {
    items.push({
      severity: 'medium',
      issue: 'Top unresolved ingredients found',
      message: `${topUnresolved[0].text} appears ${topUnresolved[0].count} times`,
      action: 'Add these ingredients to CanonicalIngredient catalog',
      examples: topUnresolved.slice(0, 5).map(u => u.text),
    });
  }

  // Check fallback usage
  const fallbackNum = parseFloat(health.fallback_ratio);
  if (fallbackNum > 30) {
    items.push({
      severity: 'medium',
      issue: 'High fallback pricing usage',
      message: `${fallbackNum}% of pricing uses category benchmarks`,
      action: 'Add more ingredient-specific prices to CanonicalIngredient',
    });
  }

  // Check anomalies
  if (anomalies.all_unresolved_ingredients || anomalies.zero_priced_ingredients) {
    items.push({
      severity: 'high',
      issue: 'Zero-priced recipes detected',
      message: `${anomalies.zero_priced_ingredients || 0} recipes have no pricing`,
      action: 'Investigate and fix ingredient matching',
    });
  }

  return items;
}

import { createClientFromRequest } from 'npm:@base44/sdk@0.8.23';

/**
 * getProfileWithFollowStatus — single source of truth for profile page.
 * Reads from Follow entity (same as toggleFollowState writes to).
 *
 * Returns does_target_follow_viewer so UserProfile can show "Follow Back"
 * when the target follows the viewer but the viewer doesn't follow back.
 *
 * account_state values:
 *   'active' | 'paused' | 'suspended' | 'pending_deletion' | 'deleted' | 'not_found'
 *   'blocked_by_viewer' — viewer has blocked this user (viewer can unblock)
 *   'blocked_by_target' — this user has blocked the viewer (shows "unavailable")
 */
Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const viewer = await base44.auth.me();

    const body = await req.json().catch(() => ({}));
    const { target_user_id } = body;

    if (!target_user_id) {
      return Response.json({ error: 'target_user_id required' }, { status: 400 });
    }

    const sr = base44.asServiceRole;

    // Fetch target user
    let targetUsers = [];
    try {
      targetUsers = await sr.entities.User.filter({ id: target_user_id });
    } catch (_) {
      return Response.json({ account_state: 'not_found', error: 'User not found', target_user_id });
    }
    const targetUser = targetUsers[0];

    if (!targetUser) {
      return Response.json({ account_state: 'not_found', error: 'User not found', target_user_id });
    }

    const isOwnProfile = viewer && viewer.id === target_user_id;
    const targetStatus = targetUser.account_status || 'active';

    // Block check (skip for own profile)
    if (!isOwnProfile && viewer) {
      const [viewerBlockedTarget, targetBlockedViewer] = await Promise.all([
        sr.entities.BlockedUser.filter({ blocker_id: viewer.id, blocked_id: target_user_id }).catch(() => []),
        sr.entities.BlockedUser.filter({ blocker_id: target_user_id, blocked_id: viewer.id }).catch(() => []),
      ]);

      if (viewerBlockedTarget.length > 0) {
        return Response.json({
          account_state: 'blocked_by_viewer',
          user: {
            id: targetUser.id,
            display_name: targetUser.display_name || targetUser.full_name,
            avatar_url: targetUser.avatar_url,
          },
        });
      }

      if (targetBlockedViewer.length > 0) {
        return Response.json({
          account_state: 'blocked_by_target',
          user: {
            id: targetUser.id,
            display_name: targetUser.display_name || targetUser.full_name,
            avatar_url: null,
          },
        });
      }
    }

    // Non-active accounts — always return HTTP 200 so React Query treats as data (not error)
    // This ensures the frontend staleTime:0 / refetchOnMount:'always' can properly invalidate stale state
    // pending_deletion: self-heal if no deletion_initiated_at or it's been < 7 days
    // (admin accounts / test accounts often get stuck in pending_deletion without completing)
    // Fall through to active rendering in self-heal cases.
    if (!isOwnProfile && targetStatus === 'pending_deletion') {
      const initiatedAt = targetUser.deletion_initiated_at ? new Date(targetUser.deletion_initiated_at) : null;
      const daysSinceInitiated = initiatedAt ? (Date.now() - initiatedAt.getTime()) / (1000 * 60 * 60 * 24) : null;
      // Self-heal: no initiation date, or initiated recently without completion (stuck state)
      const isStuckDeletion = !initiatedAt || daysSinceInitiated < 30;
      if (isStuckDeletion) {
        console.log(`[getProfileWithFollowStatus] self-heal pending_deletion: initiated=${targetUser.deletion_initiated_at} days=${daysSinceInitiated} — serving active profile`);
        sr.entities.User.update(targetUser.id, {
          account_status: 'active',
          deletion_initiated_at: null,
          account_paused: false,
          account_paused_until: null,
        }).catch(e => console.warn('[getProfileWithFollowStatus] pending_deletion self-heal write failed:', e.message));
        // fall through to active profile rendering below
      } else {
        // Genuinely pending deletion for 30+ days — show as unavailable
        return Response.json({
          account_state: 'pending_deletion',
          user: { id: targetUser.id, display_name: targetUser.display_name || targetUser.full_name, avatar_url: null },
        });
      }
    }

    const HARD_BLOCKED_STATES = ['suspended', 'deleted'];
    if (!isOwnProfile && HARD_BLOCKED_STATES.includes(targetStatus)) {
      return Response.json({
        account_state: targetStatus,
        user: {
          id: targetUser.id,
          display_name: targetUser.display_name || targetUser.full_name,
          avatar_url: null,
        },
      });
    }

    // Paused: self-heal under ALL these conditions:
    //   1. paused_until has already passed (expired pause)
    //   2. no paused_until set at all (resume partially ran — cleared expiry but not status)
    //   3. paused_until is in the future BUT the expiry is within 5 minutes (grace window)
    // In ALL self-heal cases: write correction to DB asynchronously, then IMMEDIATELY
    // fall through to active profile rendering. Do NOT return 'paused' and then re-heal —
    // that causes a stale "Account On Hold" screen on the first load after resume.
    if (!isOwnProfile && targetStatus === 'paused') {
      const pausedUntil = targetUser.paused_until ? new Date(targetUser.paused_until) : null;
      const now = new Date();
      const pauseExpired = pausedUntil && pausedUntil < now;
      const noExpiry = !pausedUntil; // paused with no expiry = resume partially ran
      const nearExpiry = pausedUntil && (pausedUntil - now) < 5 * 60 * 1000; // within 5 min

      if (pauseExpired || noExpiry || nearExpiry) {
        // Self-heal: write correction to DB async — do NOT block rendering on it
        console.log(`[getProfileWithFollowStatus] self-heal: paused_until=${targetUser.paused_until} pauseExpired=${pauseExpired} noExpiry=${noExpiry} nearExpiry=${nearExpiry} — writing active to DB, serving active profile immediately`);
        sr.entities.User.update(targetUser.id, {
          account_status: 'active',
          paused_until: null,
          pause_started_at: null,
        }).catch(e => console.warn('[getProfileWithFollowStatus] self-heal write failed:', e.message));
        // fall through immediately to active profile rendering below
      } else {
        // Genuinely paused with future expiry
        return Response.json({
          account_state: 'paused',
          user: {
            id: targetUser.id,
            display_name: targetUser.display_name || targetUser.full_name,
            avatar_url: null,
          },
        });
      }
    }

    // Fetch all data in parallel (including viewer's follow records for normalization)
    const [settings, followersAll, followingAll, publicRecipes, shops] = await Promise.all([
      sr.entities.UserSettings.filter({ user_id: target_user_id }).catch(() => []),
      sr.entities.Follow.filter({ followed_id: target_user_id }).catch(() => []),
      sr.entities.Follow.filter({ follower_id: target_user_id }).catch(() => []),
      sr.entities.Recipe.filter({ author_id: target_user_id, is_public: true }).catch(() => []),
      sr.entities.Shop.filter({ owner_id: target_user_id }).catch(() => []),
    ]);

    const isPrivate = settings.length > 0 ? (settings[0].is_private_account === true) : false;

    const acceptedFollowers = followersAll.filter(f => f.status === 'accepted');
    const acceptedFollowing = followingAll.filter(f => f.status === 'accepted');

    // viewer_follow_status: what the VIEWER's relationship is toward the TARGET
    let viewerFollowStatus = 'none';
    // does_target_follow_viewer: whether the TARGET follows the VIEWER (for "Follow Back" button)
    let doesTargetFollowViewer = false;

    if (isOwnProfile) {
      viewerFollowStatus = 'self';
    } else if (viewer) {
      // Viewer → Target relationship — find ALL viewer's follow records toward target
      const viewerRecords = followersAll.filter(f => f.follower_id === viewer.id);

      // SELF-HEAL: if multiple duplicate rows exist, keep the best one and delete the rest
      if (viewerRecords.length > 1) {
        const best = viewerRecords.find(f => f.status === 'accepted') || viewerRecords[0];
        const toDelete = viewerRecords.filter(f => f.id !== best.id);
        toDelete.forEach(f => sr.entities.Follow.delete(f.id).catch(() => {}));
        viewerFollowStatus = best.status === 'accepted' ? 'following' : (best.status || 'requested');
      } else if (viewerRecords.length === 1) {
        const viewerRecord = viewerRecords[0];
        viewerFollowStatus = viewerRecord.status === 'accepted' ? 'following' : viewerRecord.status;
      }

      // Target → Viewer relationship (to determine "Follow Back")
      // followingAll = target's following list (who target follows)
      const targetFollowsViewer = followingAll.find(f => f.followed_id === viewer.id && f.status === 'accepted');
      doesTargetFollowViewer = !!targetFollowsViewer;
    }

    const totalLikesReceived = publicRecipes.reduce((sum, r) => sum + (r.likes_count || 0), 0);
    const hasShop = shops.length > 0;

    const isViewerAccepted = !isPrivate || viewerFollowStatus === 'following' || viewerFollowStatus === 'self';

    return Response.json({
      account_state: 'active',
      user: {
        id: targetUser.id,
        full_name: targetUser.full_name,
        display_name: targetUser.display_name || targetUser.full_name,
        avatar_url: targetUser.avatar_url,
        bio: targetUser.bio,
        is_private_account: isPrivate,
        has_shop: hasShop,
      },
      follower_count: acceptedFollowers.length,
      following_count: acceptedFollowing.length,
      recipe_count: publicRecipes.length,
      total_likes_received: totalLikesReceived,
      viewer_follow_status: viewerFollowStatus,
      does_target_follow_viewer: doesTargetFollowViewer,
      is_viewer_accepted: isViewerAccepted,
    });
  } catch (error) {
    console.error('getProfileWithFollowStatus error:', error);
    return Response.json({ error: error.message }, { status: 500 });
  }
});

