/**
 * getRecipeGenerationEntitlement
 *
 * SINGLE SOURCE OF TRUTH for recipe generation access.
 *
 * FREE users: weekly 2-generation limit via AiGenerationQuota (same entity aiGenerateAdvanced writes to).
 * PRO users: 25/day cap + 3-min cooldown after 10th gen via ProGenerationQuota.
 *
 * CRITICAL: reads from AiGenerationQuota (not UsageCounter) to stay in sync with spend writes.
 */
import { createClientFromRequest } from 'npm:@base44/sdk@0.8.25';

const PRO_DAILY_LIMIT = 25;
const COOLDOWN_AFTER_N = 10;
const COOLDOWN_SECONDS = 180;

/**
 * Compute next midnight in user's local timezone.
 * Uses Intl to get current local time components, then calculates offset to midnight.
 */
function computeNextLocalMidnight(now, tz) {
  try {
    const fmt = new Intl.DateTimeFormat('en-US', { timeZone: tz, hour: 'numeric', minute: 'numeric', second: 'numeric', hour12: false });
    const parts = fmt.formatToParts(now);
    const h = parseInt(parts.find(p => p.type === 'hour')?.value || '0');
    const m = parseInt(parts.find(p => p.type === 'minute')?.value || '0');
    const s = parseInt(parts.find(p => p.type === 'second')?.value || '0');
    const secsUntilMidnight = ((23 - h) * 3600) + ((59 - m) * 60) + (60 - s);
    return new Date(now.getTime() + secsUntilMidnight * 1000);
  } catch {
    // Fallback: add 24h
    return new Date(now.getTime() + 86400000);
  }
}

function getDayKey(date, timezone) {
  try {
    return new Intl.DateTimeFormat('en-CA', { timeZone: timezone, year: 'numeric', month: '2-digit', day: '2-digit' }).format(date);
  } catch { return date.toISOString().slice(0, 10); }
}

function getWeekWindow(date) {
  const dayOfWeek = date.getUTCDay();
  const daysToSubtract = dayOfWeek === 0 ? 6 : dayOfWeek - 1;

  const periodStart = new Date(date);
  periodStart.setUTCDate(periodStart.getUTCDate() - daysToSubtract);
  periodStart.setUTCHours(0, 0, 0, 0);

  const periodEnd = new Date(periodStart);
  periodEnd.setUTCDate(periodEnd.getUTCDate() + 7);
  return { periodStart, periodEnd };
}

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user) return Response.json({ error: 'Unauthorized' }, { status: 401 });

    const now = new Date();
    // Prefer user's stored timezone; accept client_timezone param as fallback for users who never set it.
    let body = {};
    try { body = await req.json(); } catch {}
    const clientTz = body?.client_timezone || null;
    const userTz = user.timezone && user.timezone !== 'UTC' ? user.timezone : (clientTz || user.timezone || 'UTC');

    // Owner override — read REAL quota data so credits decrement correctly
    if (user.email === 'xenodekuu@gmail.com') {
      const ownerTodayKey = getDayKey(now, userTz);
      const ownerProQuota = (await base44.asServiceRole.entities.ProGenerationQuota.filter({
        user_id: user.id, day_key: ownerTodayKey,
      }).catch(() => []))[0] || null;
      const ownerDailyCount = ownerProQuota?.daily_count || 0;
      const ownerRemaining = Math.max(0, PRO_DAILY_LIMIT - ownerDailyCount);
      let ownerCooldownActive = false, ownerCooldownSeconds = 0;
      if (ownerDailyCount >= COOLDOWN_AFTER_N && ownerProQuota?.last_generation_started_at) {
        const elapsed = (now.getTime() - new Date(ownerProQuota.last_generation_started_at).getTime()) / 1000;
        const rem = Math.ceil(COOLDOWN_SECONDS - elapsed);
        if (rem > 0) { ownerCooldownActive = true; ownerCooldownSeconds = rem; }
      }
      // Compute next midnight in user's LOCAL timezone accurately
      const ownerTomorrow = computeNextLocalMidnight(now, userTz);
      return Response.json({
        user_id: user.id, is_pro: true,
        pro_daily_limit: PRO_DAILY_LIMIT,
        pro_daily_count: ownerDailyCount,
        pro_remaining_today: ownerRemaining,
        pro_cooldown_active: ownerCooldownActive,
        pro_cooldown_remaining_seconds: ownerCooldownSeconds,
        can_generate: ownerRemaining > 0 && !ownerCooldownActive,
        generation_source: ownerRemaining > 0 ? 'pro_daily' : 'none',
        banked_referral_credits: 0, owner_override: true,
        next_reset_at: ownerTomorrow.toISOString(),
        server_time: now.toISOString(),
      });
    }

    const [subs, ledgerEntries] = await Promise.all([
      base44.asServiceRole.entities.Subscription.filter({ created_by: user.email }).catch(() => []),
      base44.asServiceRole.entities.ReferralRewardLedger.filter({ user_id: user.id }).catch(() => []),
    ]);

    // Determine Pro status
    const ENTITLED_PLAN_TYPES = new Set(['pro', 'vip', 'trial']);
    const activeSub = subs.find(s => {
      if (!ENTITLED_PLAN_TYPES.has(s.plan_type)) return false;
      if (s.status === 'active' || s.status === 'active_paid' || s.status === 'trialing' || s.status === 'grace_period') return true;
      if ((s.status === 'canceled' || s.status === 'canceled_pending_expiry') && s.current_period_end && new Date(s.current_period_end).getTime() > now.getTime()) return true;
      return false;
    });
    const isPro = !!activeSub;

    const earnedEntries = ledgerEntries.filter(e => e.credit_state === 'earned' && (e.credits_remaining || 0) > 0);
    const bankedReferralCredits = earnedEntries.reduce((sum, e) => sum + (e.credits_remaining || 0), 0);

    if (isPro) {
      const todayKey = getDayKey(now, userTz);
      const proQuota = (await base44.asServiceRole.entities.ProGenerationQuota.filter({
        user_id: user.id, day_key: todayKey,
      }).catch(() => []))[0] || null;

      const dailyCount = proQuota?.daily_count || 0;
      const remainingToday = Math.max(0, PRO_DAILY_LIMIT - dailyCount);
      let cooldownActive = false, cooldownRemainingSeconds = 0;
      if (dailyCount >= COOLDOWN_AFTER_N && proQuota?.last_generation_started_at) {
        const elapsed = (now.getTime() - new Date(proQuota.last_generation_started_at).getTime()) / 1000;
        const rem = Math.ceil(COOLDOWN_SECONDS - elapsed);
        if (rem > 0) { cooldownActive = true; cooldownRemainingSeconds = rem; }
      }

      // Compute next midnight in user's LOCAL timezone accurately.
      // We calculate seconds until midnight and add to now — avoids timezone parsing bugs.
      const nextResetPro = computeNextLocalMidnight(now, userTz);

      return Response.json({
        user_id: user.id, is_pro: true,
        pro_daily_limit: PRO_DAILY_LIMIT,
        pro_daily_count: dailyCount,
        pro_remaining_today: remainingToday,
        pro_cooldown_active: cooldownActive,
        pro_cooldown_remaining_seconds: cooldownRemainingSeconds,
        pro_cooldown_after_n: COOLDOWN_AFTER_N,
        can_generate: (remainingToday > 0 || bankedReferralCredits > 0) && !cooldownActive,
        generation_source: remainingToday > 0 ? 'pro_daily' : (bankedReferralCredits > 0 ? 'pro_banked' : 'none'),
        banked_referral_credits: bankedReferralCredits,
        next_reset_at: nextResetPro.toISOString(),
        show_referral_upsell: false, show_upgrade_paywall: false, show_referral_plus_button: false,
      });
    }

    // ── FREE USER ──
    const WEEKLY_LIMIT = 2;
    const { periodStart, periodEnd } = getWeekWindow(now);
    const periodStartISO = periodStart.toISOString();
    const periodEndISO = periodEnd.toISOString();

    // Find quota matching CURRENT period — exact match only
    let quota = (await base44.asServiceRole.entities.AiGenerationQuota.filter(
      { user_id: user.id, period_start: periodStartISO }, null, 1
    ).catch(() => []))[0] || null;

    if (!quota) {
      // No record for this period — create fresh (READ path only creates, never resets)
      quota = await base44.asServiceRole.entities.AiGenerationQuota.create({
        user_id: user.id,
        period_start: periodStartISO,
        period_end: periodEndISO,
        limit: WEEKLY_LIMIT,
        used: 0,
        timezone: userTz,
        updated_at: now.toISOString(),
      }).catch(() => null);
    }
    // CRITICAL: Never reset used count here. Only aiGenerateAdvanced modifies used.

    const used = quota?.used || 0;
    const weeklyRemaining = Math.max(0, WEEKLY_LIMIT - used);
    const totalAvailable = weeklyRemaining + bankedReferralCredits;

    console.log(`[getRecipeGenerationEntitlement] free user=${user.id} used=${used}/${WEEKLY_LIMIT} banked=${bankedReferralCredits} period_start=${periodStart.toISOString()}`);

    return Response.json({
      user_id: user.id, is_pro: false,
      weekly_free_limit: WEEKLY_LIMIT,
      weekly_free_used: used,
      weekly_free_remaining: weeklyRemaining,
      banked_referral_credits: bankedReferralCredits,
      total_available: totalAvailable,
      can_generate: totalAvailable > 0,
      generation_source: weeklyRemaining > 0 ? 'weekly_free' : 'banked_referral',
      next_reset_at: periodEndISO,
      resets_at: periodEndISO,
      remaining: weeklyRemaining,
      used,
      limit: WEEKLY_LIMIT,
      server_time: now.toISOString(),
      show_referral_upsell: totalAvailable === 0,
      show_upgrade_paywall: totalAvailable === 0,
