});

/**
 * getRecipePricing
 *
 * Returns deterministic pricing for a recipe based on ingredient costs.
 * Called on mount + servings change for both generated and saved recipes.
 *
 * Input (JSON body): { recipe_id, servings }
 *
 * Returns:
 * {
 *   pricing_status: "known|partial|unknown",
 *   total_cost: number|null,
 *   cost_per_serving: number|null,
 *   line_items: [{name, grams, cost}],
 *   unpriced: [{name, is_optional}]
 * }
 */
import { createClientFromRequest } from 'npm:@base44/sdk@0.8.20';

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user) return Response.json({ error: 'Unauthorized' }, { status: 401 });

    const body = await req.json().catch(() => ({}));
    const recipeId = body.recipe_id;
    const servings = parseFloat(body.servings) || 1;

    if (!recipeId) return Response.json({ error: 'recipe_id required' }, { status: 400 });

    // Fetch recipe
    const recipes = await base44.asServiceRole.entities.Recipe.filter({ id: recipeId }, null, 1);
    if (!recipes[0]) return Response.json({ error: 'recipe not found' }, { status: 404 });
    const recipe = recipes[0];

    const lineItems = [];
    const unpriced = [];
    let totalKnownCost = 0;
    let hasAnyPriced = false;
    let allRequiredPriced = true;

    const baseSrvs = recipe.servings || 1;
    const scale = servings / baseSrvs;

    for (const group of recipe.ingredients || []) {
      for (const item of group.items || []) {
        const name = item.name || '';
        const cost = item.ingredient_cost || 0;
        const grams = item.base_grams || 0;

        if (cost > 0) {
          hasAnyPriced = true;
          lineItems.push({
            name,
            grams: Math.round(grams * scale),
            cost: parseFloat((cost * scale).toFixed(2)),
          });
          totalKnownCost += cost * scale;
        } else {
          if (!item.optional) {
            allRequiredPriced = false;
          }
          unpriced.push({ name, is_optional: item.optional || false });
        }
      }
    }

    let status = 'unknown';
    if (hasAnyPriced) {
      status = allRequiredPriced ? 'known' : 'partial';
    }

    // Always return the total of known costs (even for partial)
    const displayTotal = hasAnyPriced ? parseFloat(totalKnownCost.toFixed(2)) : null;
    const displayPerServing = hasAnyPriced && servings > 0
      ? parseFloat((totalKnownCost / servings).toFixed(2))
      : null;

    // Also include per-ingredient costs scaled by servings in line_items
    return Response.json({
      pricing_status: status,
      total_cost: displayTotal,
      cost_per_serving: displayPerServing,
      line_items: lineItems,
      unpriced,
      servings_used: servings,
    });
  } catch (err) {
    console.error('[getRecipePricing]', err.message);
    return Response.json({ error: err.message }, { status: 500 });
  }
});

/**
 * Safe pricing read function that uses cached pricing summaries.
 * Does NOT recompute pricing on every RecipeDetail load.
 * Only computes if summary missing or explicitly requested.
 */

import { createClientFromRequest } from 'npm:@base44/sdk@0.8.25';

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const payload = await req.json();
    const { recipe_id, force_recompute = false } = payload;

    if (!recipe_id) {
      return Response.json({ error: 'recipe_id required' }, { status: 400 });
    }

    // STEP 1: Check Recipe entity directly — repricingAdapter writes pricing here.
    // This is the CHEAPEST path: 1 DB read, 0 function invocations.
    const recipes = await base44.entities.Recipe.filter({ id: recipe_id }).catch(() => []);
    const recipe = recipes[0];

    if (!recipe) {
      return Response.json({ error: 'Recipe not found' }, { status: 404 });
    }

    // If pricing is already on the entity, return it immediately — no further calls.
    if (recipe.total_cost > 0 && !force_recompute) {
      return Response.json({
        total_cost: recipe.total_cost,
        cost_per_serving: recipe.cost_per_serving || 0,
        pricing_status: recipe.has_unknown_pricing ? 'partial' : 'complete',
        cached: true,
        source: 'recipe_entity',
      });
    }

    // STEP 2: Pricing missing — invoke repricingAdapter directly (deterministic, no LLM).
    // This writes pricing to the Recipe entity so future reads are free.
    console.log(`[getRecipePricingSafe] Pricing missing for ${recipe_id}, invoking repricingAdapter`);
    const pricingRes = await base44.asServiceRole.functions.invoke('repricingAdapter', {
      recipe_id,
    }).catch(err => {
      console.error('[getRecipePricingSafe] repricingAdapter failed:', err.message);
      return null;
    });

    return Response.json({
      total_cost: pricingRes?.data?.total_cost || 0,
      cost_per_serving: pricingRes?.data?.cost_per_serving || 0,
      pricing_status: pricingRes?.data?.ok ? 'complete' : 'unresolved',
      cached: false,
      source: 'computed_on_demand',
    });
  } catch (error) {
    console.error('[getRecipePricingSafe] Error:', error);
    return Response.json({ error: error.message }, { status: 500 });
  }
});

import { createClientFromRequest } from 'npm:@base44/sdk@0.8.25';

/**
 * RECOMMENDED FEED v6 — RESILIENT MULTI-SIGNAL RECOMMENDATIONS
 *
 * SEPARATE from Trending / Top100 / Community.
 *
 * RESILIENCE GUARANTEE:
 *   - NEVER returns empty unless the entire DB has zero eligible public recipes.
 *   - Multi-tier fallback: scored personalized → quality fallback → newest fallback.
 *   - Always returns at least 1 item if any public recipe exists.
 *
 * SCORING SIGNALS:
 *   userMatch (0..3):     liked/saved/followed authors, cuisine affinity, tag affinity,
 *                         dietary prefs, allergens, difficulty affinity, time preference.
 *   engagementQuality:    saves * 3 + reviews * 2.5 + likes * 0.8 + comments * 1.5
 *   qualityScore:         rating + completeness (image, ingredients, steps, nutrition)
 *   freshness:            1.0 fresh → exp(-ageDays/30) decay
 *   exploration:          unseen content boost
 *   creatorBalance:       per-author cap to prevent monopoly
 *
 * REFRESH ROTATION:
 *   - Caller passes session_seed; deterministic shuffle within similarly-scored buckets.
 *   - Different seed → different visible order, but same quality bar.
 */

// ─── Seeded RNG ─────────────────────────────────────────────────────────────
function mulberry32(seed) {
  let a = seed >>> 0;
  return function () {
    a = (a + 0x6D2B79F5) >>> 0;
    let t = a;
    t = Math.imul(t ^ (t >>> 15), t | 1);
    t ^= t + Math.imul(t ^ (t >>> 7), t | 61);
    return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
  };
}
function seedFromString(str) {
  let h = 2166136261 >>> 0;
  for (let i = 0; i < str.length; i++) {
    h ^= str.charCodeAt(i);
    h = Math.imul(h, 16777619);
  }
  return h >>> 0;
}
function shuffle(arr, rng) {
  const a = [...arr];
  for (let i = a.length - 1; i > 0; i--) {
    const j = Math.floor(rng() * (i + 1));
    [a[i], a[j]] = [a[j], a[i]];
  }
  return a;
}

// ─── Completeness scoring ──────────────────────────────────────────────────
function getCompleteness(recipe) {
  let score = 0;
  if (recipe.hero_image_url) score += 0.4;
  if (recipe.ingredients?.length >= 3) score += 0.2;
  if (recipe.steps?.length >= 3) score += 0.2;
  if (recipe.nutrition_per_serving?.calories > 0) score += 0.1;
  if (recipe.description) score += 0.05;
  if (recipe.cook_time > 0 || recipe.prep_time > 0) score += 0.05;
  return score; // 0..1
}

// ─── Main handler ──────────────────────────────────────────────────────────
Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user) return Response.json({ error: 'Unauthorized' }, { status: 401 });

    const body = await req.json().catch(() => ({}));
    const limit = Math.min(body.limit || 12, 30);
    const offset = Math.max(0, body.offset || 0);
    // For paginated calls (offset > 0), keep the SAME seed across pages so the ranking stays stable.
    // The frontend passes session_seed for "load more" so page 1 and page 2 are slices of the same ranked list.
    const sessionSeed = body.session_seed || `${user.id}_${Math.floor(Date.now() / (5 * 60 * 1000))}`; // 5-min stability bucket
    const rng = mulberry32(seedFromString(String(sessionSeed)));
    const requestId = `rec_${user.id.slice(-6)}_${Date.now().toString(36)}`;

    console.log(`[RECOMMENDED_V6:${requestId}] start user=${user.id} seed=${sessionSeed} limit=${limit}`);

    // ── STEP 1: Gather user signals (parallel, fault-tolerant) ──
    const [
      userPrefsArr,
      userLikesArr,
      blockedByMe,
      blockedByOthers,
    ] = await Promise.all([
      base44.asServiceRole.entities.UserPreference.filter({ owner_id: user.id }).catch(() => []),
      base44.asServiceRole.entities.Like.filter({ target_type: 'recipe', user_id: user.id }).catch(() => []),
      base44.asServiceRole.entities.BlockedUser.filter({ blocker_id: user.id }).catch(() => []),
      base44.asServiceRole.entities.BlockedUser.filter({ blocked_id: user.id }).catch(() => []),
    ]);

    const [
      notInterestedArr,
      userSavesArr,
      userFollows,
    ] = await Promise.all([
      base44.asServiceRole.entities.FeedPreference.filter({ created_by: user.email, preference_type: 'not_interested' }).catch(() => []),
      base44.asServiceRole.entities.RecipeSave.filter({ created_by: user.email }).catch(() => []),
      base44.asServiceRole.entities.UserFollow.filter({ follower_id: user.id, status: 'accepted' }).catch(() => []),
    ]);

    const prefs = userPrefsArr[0] || {};
    const notInterestedIds = new Set(notInterestedArr.map(n => n.recipe_id));
    const likedRecipeIds = new Set(userLikesArr.map(l => l.target_id));
    const savedRecipeIds = new Set(userSavesArr.map(s => s.recipe_id));
    const followedAuthorIds = new Set(userFollows.map(f => f.following_id));
    const userAllergens = prefs.allergens_enabled ? (prefs.allergens_list || []) : [];
    const blockedAuthorIds = new Set([
      ...blockedByMe.map(b => b.blocked_id),
      ...blockedByOthers.map(b => b.blocker_id),
    ]);

    // Declared diet tags from prefs
    const declaredTags = new Set([
      ...(prefs.preferred_tags || []),
      ...(prefs.diet_tags || []),
    ]);

    // User goal-based prefs
    const userGoals = Array.isArray(user.goals) ? user.goals : [];
    const preferHighProtein = userGoals.some(g => ['high_protein', 'muscle_gain', 'bulking'].includes(g));
    const preferLowCalorie = userGoals.some(g => ['weight_loss', 'low_calorie', 'cutting'].includes(g));
    const preferLowCost = !!prefs.prefer_low_cost;

    // Skill / time preferences
    const cookingSkill = (user.cooking_skill || prefs.cooking_skill || 'beginner').toLowerCase();
    const skillToDifficulty = { beginner: 'easy', intermediate: 'medium', advanced: 'hard' };
    const preferredDifficulty = skillToDifficulty[cookingSkill] || null;

    // ── STEP 2: Fetch candidate pool ──
    const publicRecipes = await base44.asServiceRole.entities.Recipe.filter(
      { is_public: true },
      '-created_date',
      150
    ).catch(() => []);

    // Behavioral cuisine/tag affinity from liked/saved
    const cuisineVotes = {};
    const tagVotes = {};
    const behaviorIds = new Set([
      ...userLikesArr.slice(0, 20).map(l => l.target_id),
      ...userSavesArr.slice(0, 20).map(s => s.recipe_id),
    ]);
    for (const r of publicRecipes) {
      if (behaviorIds.has(r.id)) {
        if (r.cuisine) cuisineVotes[r.cuisine] = (cuisineVotes[r.cuisine] || 0) + 2;
        for (const t of (r.tags || [])) tagVotes[t] = (tagVotes[t] || 0) + 1.5;
      }
    }
    const cuisineAffinities = new Set(Object.keys(cuisineVotes));
    const tagAffinities = new Set([...Object.keys(tagVotes), ...declaredTags]);
    const isWarmStart = behaviorIds.size > 0 || cuisineAffinities.size > 0 || tagAffinities.size > 0;

    // ── STEP 3: Eligibility filter ──
    const eligible = publicRecipes.filter(r => {
      if (r.is_public !== true) return false;
      if (r.source === 'generated' && !r.is_community_content && !r.is_shop_content) return false;
      if (notInterestedIds.has(r.id)) return false;
      if (r.author_account_status && r.author_account_status !== 'active') return false;
      if (r.author_id && blockedAuthorIds.has(r.author_id)) return false;
      if (userAllergens.length > 0 && r.allergens?.some(a => userAllergens.includes(a))) return false;
      if (['removed_by_moderation', 'deleted_by_owner'].includes(r.moderation_status)) return false;
      return true;
    });

    console.log(`[RECOMMENDED_V6:${requestId}] pool: public=${publicRecipes.length} eligible=${eligible.length} warmStart=${isWarmStart}`);

    // ── HARD FALLBACK: zero eligible — return absolute newest public posts so feed never empty ──
    if (eligible.length === 0) {
      const allFallback = publicRecipes
        .filter(r => r.author_account_status !== 'deleted' && r.moderation_status !== 'removed_by_moderation');
      const fallback = allFallback
        .slice(offset, offset + limit)
        .map(r => ({ ...r, _recommended_source: 'hard_fallback' }));
      console.log(`[RECOMMENDED_V6:${requestId}] HARD FALLBACK: returning ${fallback.length} newest public (offset=${offset})`);
      return Response.json({
        posts: fallback,
        total: fallback.length,
        total_available: allFallback.length,
        has_more: offset + limit < allFallback.length,
        session_seed: sessionSeed,
        source: 'recommended_v6_hard_fallback',
      });
    }

    // ── STEP 4: Score every eligible recipe ──
    const now = Date.now();
    const scored = eligible.map(recipe => {
      const tags = recipe.tags || [];
      const likes = recipe.likes_count || 0;
      const saves = recipe.saves_count || 0;
      const reviews = recipe.review_count || 0;
      const comments = recipe.comment_count || 0;
      const rating = recipe.avg_rating || 0;
      const ageDays = (now - new Date(recipe.created_date || now).getTime()) / 86400000;

      // ── userMatch (0..3+) ──
      let userMatch = 0;
      const matchReasons = [];

      const matchingTags = tags.filter(t => tagAffinities.has(t));
      if (matchingTags.length > 0) {
        userMatch += Math.min(matchingTags.length * 0.4, 1.2);
        matchReasons.push(`tags:${matchingTags.length}`);
      }

      if (recipe.cuisine && cuisineAffinities.has(recipe.cuisine)) {
        userMatch += 0.5;
        matchReasons.push('cuisine');
      }

      if (recipe.author_id && followedAuthorIds.has(recipe.author_id)) {
        userMatch += 0.6;
        matchReasons.push('followed');
      }

      if (preferredDifficulty && recipe.difficulty === preferredDifficulty) {
        userMatch += 0.3;
        matchReasons.push('difficulty');
      }

      if (preferHighProtein) {
        const protein = recipe.nutrition_per_serving?.protein ?? 0;
        const hasProteinTag = tags.some(t => ['high-protein', 'protein', 'muscle'].includes(t));
        if (protein >= 25 || hasProteinTag) {
          userMatch += 0.5;
          matchReasons.push('protein');
        }
      }
      if (preferLowCalorie) {
        const cal = recipe.nutrition_per_serving?.calories ?? 0;
        if ((cal > 0 && cal <= 450) || tags.some(t => ['low-calorie', 'light', 'diet'].includes(t))) {
          userMatch += 0.4;
          matchReasons.push('low_cal');
        }
      }
      if (preferLowCost && recipe.cost_per_serving != null && recipe.cost_per_serving < 6) {
        userMatch += 0.3;
        matchReasons.push('low_cost');
      }

      // ── engagementQuality ──
      const engagementQuality = (saves * 3) + (reviews * 2.5) + (likes * 0.8) + (comments * 1.5);

      // ── qualityScore (rating + completeness) ──
      const qualityScore = (rating * 5) + (getCompleteness(recipe) * 6) + 1;

      // ── freshness ──
      const freshness = ageDays <= 2 ? 1.0 : Math.exp(-ageDays / 30);

      // ── exploration bonus: unseen, decent quality ──
      const isUnseen = !likedRecipeIds.has(recipe.id) && !savedRecipeIds.has(recipe.id);
      const explorationBonus = isUnseen && qualityScore > 5 ? 1.08 : 1.0;

      // ── deprioritize already-engaged ──
      const isEngaged = likedRecipeIds.has(recipe.id) || savedRecipeIds.has(recipe.id);
      const engagedDamper = isEngaged ? 0.35 : 1.0;

      // ── final score ──
      // Cold-start: emphasize quality + engagement; warm: emphasize userMatch.
      const userMatchWeight = isWarmStart ? 1.4 : 0.5;
      const finalScore =
        (1 + userMatch * userMatchWeight) *
        (1 + Math.log(1 + engagementQuality) * 0.4) *
        qualityScore *
        freshness *
        explorationBonus *
        engagedDamper;

      return {
        recipe,
        finalScore,
        userMatch,
        qualityScore,
        engagementQuality,
        isUnseen,
        isEngaged,
        matchReasons,
      };
    });

    // ── STEP 5: Sort by score ──
    scored.sort((a, b) => b.finalScore - a.finalScore);

    // ── STEP 6: Bucketed shuffle for refresh rotation ──
    // Split into top/mid quartiles, lightly shuffle within each. With a stable session_seed,
    // the same user gets the same ordering across paginated calls — so offset slicing works.
    const splitPoint = Math.max(limit, Math.floor(scored.length / 2));
    const topBucket = scored.slice(0, splitPoint);
    const restBucket = scored.slice(splitPoint);
    const topShuffled = shuffle(topBucket, rng);
    const restShuffled = shuffle(restBucket, rng);
    const allOrdered = [...topShuffled, ...restShuffled];

    // ── STEP 7: Diversity pass — produce a FULL ordered list, then slice by offset/limit. ──
    // Per-author cap: max 2 from same author; prevent same cuisine 3-in-a-row.
    // Build the full diversified list first so pagination across calls is consistent.
    const authorCount = {};
    const fullDiversified = [];
    let lastCuisine = null;
    let sameCuisineRun = 0;

    for (const item of allOrdered) {
      const r = item.recipe;
      const ac = authorCount[r.author_id] || 0;
      if (ac >= 2) continue;

      if (r.cuisine && r.cuisine === lastCuisine) {
        sameCuisineRun++;
        if (sameCuisineRun >= 2) continue;
      } else {
        sameCuisineRun = 0;
      }
      lastCuisine = r.cuisine || null;

      authorCount[r.author_id] = ac + 1;
      fullDiversified.push(item);
    }

    // Top up with anything diversity culled (so total available is maximized for "load more")
    if (fullDiversified.length < allOrdered.length) {
      const inList = new Set(fullDiversified.map(s => s.recipe.id));
      for (const item of allOrdered) {
        if (!inList.has(item.recipe.id)) {
          fullDiversified.push(item);
          inList.add(item.recipe.id);
        }
      }
    }

    // ── STEP 8: Slice by offset + limit ──
    const totalAvailable = fullDiversified.length;
    const result = fullDiversified.slice(offset, offset + limit);
    const hasMore = offset + result.length < totalAvailable;

    // ── STEP 9: Build output ──
    const posts = result.map(s => ({
      ...s.recipe,
      viewer_has_liked: likedRecipeIds.has(s.recipe.id),
      viewer_has_saved: savedRecipeIds.has(s.recipe.id),
      _recommended_score: +s.finalScore.toFixed(3),
      _recommended_source: s.matchReasons.length > 0 ? 'personalized' : 'quality',
      _recommended_reasons: s.matchReasons,
    }));

    console.log(`[RECOMMENDED_V6:${requestId}] done results=${posts.length} offset=${offset} totalAvailable=${totalAvailable} hasMore=${hasMore}`);

    return Response.json({
      posts,
      total: posts.length,
      total_available: totalAvailable,
      has_more: hasMore,
      offset,
      source: 'recommended_v6',
      warm_start: isWarmStart,
      session_seed: sessionSeed,
    });
  } catch (error) {
    console.error('[RECOMMENDED_V6] error:', error.message, error.stack);
    return Response.json({ error: error.message }, { status: 500 });
  }
});

/**
 * getReferralProfile
 * Returns the authenticated user's full referral profile:
 * - referral code / link
 * - successful referrals count
 * - banked generation credits available
 * - list of referrals
 * - weekly allowance snapshot
 */
import { createClientFromRequest } from 'npm:@base44/sdk@0.8.21';

function generateCode(userId) {
  // Deterministic but unguessable code from userId + salt
  const chars = 'ABCDEFGHJKLMNPQRSTUVWXYZ23456789';
  let hash = 0;
  const str = userId + 'reciply_salt_v1';
  for (let i = 0; i < str.length; i++) {
    hash = ((hash << 5) - hash) + str.charCodeAt(i);
    hash |= 0;
  }
  let code = 'CHEF-';
  let h = Math.abs(hash);
  for (let i = 0; i < 6; i++) {
    code += chars[h % chars.length];
    h = Math.floor(h / chars.length) + (hash * (i + 1));
    h = Math.abs(h);
  }
  return code;
}

function getWeekStartDate(date, timezone = 'UTC') {
  // Parse date in user's timezone to get the local Monday
  const formatter = new Intl.DateTimeFormat('en-US', {
    timeZone: timezone,
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
    weekday: 'long',
  });

  const parts = formatter.formatToParts(date);
  const weekday = parts.find(p => p.type === 'weekday')?.value;
  const dayOfWeekNum =
    weekday === 'Monday' ? 1 :
    weekday === 'Tuesday' ? 2 :
    weekday === 'Wednesday' ? 3 :
    weekday === 'Thursday' ? 4 :
    weekday === 'Friday' ? 5 :
    weekday === 'Saturday' ? 6 : 0;

  const daysToSubtract = dayOfWeekNum === 0 ? 6 : dayOfWeekNum - 1;
  const periodStart = new Date(date);
  periodStart.setDate(periodStart.getDate() - daysToSubtract);
  periodStart.setUTCHours(0, 0, 0, 0);

  const offset = getTimezoneOffset(timezone);
  periodStart.setUTCHours(offset, 0, 0, 0);

  return periodStart;
}

function getTimezoneOffset(timezone) {
  const formatter = new Intl.DateTimeFormat('en-US', {
    timeZone: timezone,
    hour: '2-digit',
    hour12: false,
  });
  const testDate = new Date('2000-01-01T00:00:00Z');
  const parts = formatter.formatToParts(testDate);
  const hour = parseInt(parts.find(p => p.type === 'hour')?.value || '0', 10);
  return -hour;
}

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user) return Response.json({ error: 'Unauthorized' }, { status: 401 });

    // Ensure referral profile exists
    let [referralProfiles, attributions, ledgerEntries] = await Promise.all([
      base44.asServiceRole.entities.UserReferralProfile.filter({ user_id: user.id }),
      base44.asServiceRole.entities.ReferralAttribution.filter({ inviter_user_id: user.id }),
      base44.asServiceRole.entities.ReferralRewardLedger.filter({ user_id: user.id }),
    ]);

    let profile = referralProfiles[0];
    const code = generateCode(user.id);

    if (!profile) {
      profile = await base44.asServiceRole.entities.UserReferralProfile.create({
        user_id: user.id,
        referral_code: code,
        invites_sent_count: 0,
        successful_referrals_count: 0,
        total_credits_earned: 0,
        total_credits_consumed: 0,
      });
    }

    // Compute banked referral credits (sum of all 'earned' ledger entries with remaining > 0)
    const earnedEntries = ledgerEntries.filter(e => e.credit_state === 'earned' && (e.credits_remaining || 0) > 0);
    const bankedCredits = earnedEntries.reduce((sum, e) => sum + (e.credits_remaining || 0), 0);

    // Weekly allowance snapshot
    const now = new Date();
    const userTz = user.timezone || 'UTC';
    const weekStart = getWeekStartDate(now, userTz);
    const weekEnd = new Date(weekStart);
    weekEnd.setDate(weekEnd.getDate() + 7);

    const [subs, quotas] = await Promise.all([
      base44.asServiceRole.entities.Subscription.filter({ created_by: user.email }).catch(() => []),
      base44.asServiceRole.entities.AiGenerationQuota.filter({
        user_id: user.id,
        period_start: weekStart.toISOString(),
      }).catch(() => []),
    ]);

    const ENTITLED_PLAN_TYPES = new Set(['pro', 'vip']);
    const isPro = subs.some(s => {
      if (!ENTITLED_PLAN_TYPES.has(s.plan_type)) return false;
      if (s.status === 'active' || s.status === 'trialing') return true;
      if (s.status === 'canceled' && s.current_period_end) return new Date(s.current_period_end).getTime() > Date.now();
      return false;
    });

    const quota = quotas[0];
    const WEEKLY_LIMIT = 2;
    const weeklyUsed = quota?.used || 0;
    const weeklyRemaining = Math.max(0, WEEKLY_LIMIT - weeklyUsed);

    // Build referral list with display data — fetch invited user profiles
    const completedReferrals = attributions.filter(a => a.status === 'completed');

    // Fetch User profiles for invited users to get display names + avatars
    const invitedUserIds = attributions
      .filter(a => a.invited_user_id)
      .map(a => a.invited_user_id);

    let userProfiles = {};
    if (invitedUserIds.length > 0) {
      const users = await base44.asServiceRole.entities.User.list().catch(() => []);
      for (const u of users) {
        if (invitedUserIds.includes(u.id)) {
          userProfiles[u.id] = {
            full_name: u.full_name || u.display_name || null,
            avatar_url: u.avatar_url || null,
          };
        }
      }
    }

    const appUrl = Deno.env.get('APP_PUBLIC_URL') || 'https://reciply.app';
    const referralLink = `${appUrl}/invite/${profile.referral_code}`;

    return Response.json({
      referral_code: profile.referral_code,
      referral_link: referralLink,
      successful_referrals_count: completedReferrals.length,
      banked_referral_credits: bankedCredits,
      referral_list: attributions.map(a => {
        const up = a.invited_user_id ? userProfiles[a.invited_user_id] : null;
        return {
          id: a.id,
          status: a.status,
          source: a.source,
          invited_user_id: a.invited_user_id || null,
          invited_user_email: a.invited_user_email ? maskEmail(a.invited_user_email) : null,
          invited_user_name: up?.full_name || null,
          invited_user_avatar: up?.avatar_url || null,
          completed_at: a.completed_at,
          created_at: a.created_date,
          reward_earned: a.status === 'completed',
        };
      }),
      weekly_snapshot: {
        is_pro: isPro,
        weekly_limit: WEEKLY_LIMIT,
        weekly_used: weeklyUsed,
        weekly_remaining: weeklyRemaining,
        banked_referral_credits: bankedCredits,
        total_available: isPro ? null : (weeklyRemaining + bankedCredits),
        next_reset_at: weekEnd.toISOString(),
      },
    });
  } catch (error) {
    console.error('[getReferralProfile]', error.message);
    return Response.json({ error: error.message }, { status: 500 });
  }
});

function maskEmail(email) {
  const [local, domain] = email.split('@');
  if (!domain) return email;
  const visible = local.length > 2 ? local.slice(0, 2) : local[0];
  return `${visible}***@${domain}`;
}

