/**
 * getStreakState — Fetch current user's streak state
 * Called on app open, home page load
 * Returns streak data + pending UI flags
 *
 * CRITICAL FIX: Also checks if streak is broken (missed a day) on every fetch.
 * If the user missed a day since their last action, we update pending_break_popup = true.
 * This ensures the break popup shows even if the user doesn't perform an action.
 */
import { createClientFromRequest } from 'npm:@base44/sdk@0.8.23';

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();

    if (!user?.id) {
      return Response.json({ error: 'Unauthorized' }, { status: 401 });
    }

    const sr = base44.asServiceRole;
    const existing = await sr.entities.StreakState.filter({
      user_id: user.id,
    });

    if (!existing[0]) {
      // No streak yet — initialize fresh
      const streak = {
        user_id: user.id,
        current_streak_days: 0,
        longest_streak_days: 0,
        streak_status: 'active',
        user_timezone: user.timezone || 'UTC',
        pending_break_popup: false,
      };
      const created = await sr.entities.StreakState.create(streak);
      return Response.json({ ok: true, streak: { ...streak, ...created } });
    }

    const streak = existing[0];
    // TIMEZONE RESOLUTION: Same priority as updateStreakAction and adminStreakManage.
    // StreakState.user_timezone is authoritative (admin writes it, previous actions sync it).
    // Only fall back to User.timezone if stored is missing/UTC.
    const storedTz = streak.user_timezone;
    const userTz = (storedTz && storedTz !== 'UTC' ? storedTz : null)
                || user.timezone
                || 'UTC';
    const now = new Date();
    const localDateStr = now.toLocaleDateString('en-CA', { timeZone: userTz }); // YYYY-MM-DD

    // Sync timezone if it's missing or outdated
    if (streak.user_timezone !== userTz) {
      await sr.entities.StreakState.update(streak.id, { user_timezone: userTz });
      streak.user_timezone = userTz;
    }

    // ── ADMIN PROTECTION: Skip break-detection for 24h after admin set ──────
    // If an admin recently modified this streak, do NOT auto-detect breaks.
    // This prevents getStreakState from overwriting admin-set values on next app open.
    const adminSetAt = streak.admin_set_at ? new Date(streak.admin_set_at) : null;
    const adminProtectionActive = adminSetAt && (now.getTime() - adminSetAt.getTime()) < 24 * 60 * 60 * 1000;
    if (adminProtectionActive) {
      console.log(`[getStreakState] Admin protection active (set ${Math.round((now - adminSetAt) / 60000)}m ago) — skipping break detection`);
    }

    // Check if streak is now broken (user missed a day or more)
    // Only flag if streak was active/restored and current_streak_days > 0
    // SKIP if admin recently set the streak (24h protection window)
    if (
      !adminProtectionActive &&
      streak.last_streak_action_date_local &&
      streak.current_streak_days > 0 &&
      streak.streak_status !== 'broken'
    ) {
      // CRITICAL FIX: Parse dates as UTC noon to avoid DST/timezone shift artifacts.
      // new Date("2026-04-14") parses as midnight UTC which can shift to previous day
      // in timezones behind UTC. Adding T12:00:00Z ensures stable date math.
      const lastDate = new Date(streak.last_streak_action_date_local + 'T12:00:00Z');
      const today = new Date(localDateStr + 'T12:00:00Z');
      const daysDiff = Math.round((today.getTime() - lastDate.getTime()) / (1000 * 60 * 60 * 24));

      if (daysDiff > 1) {
        // Save previous streak count before marking broken (used by break popup to show "your N-day streak")
        const prevDays = streak.current_streak_days || 0;
        await sr.entities.StreakState.update(streak.id, {
          streak_status: 'broken',
          pending_break_popup: true,
          previous_streak_days: prevDays,
          current_streak_days: 0,
          updated_at: now.toISOString(),
        });
        streak.streak_status = 'broken';
        streak.pending_break_popup = true;
        streak.previous_streak_days = prevDays;
        streak.current_streak_days = 0;
      }
    }

    return Response.json({ ok: true, streak });

  } catch (error) {
    console.error('[getStreakState]', error);
    // Log to observability system (fire and forget)
    try {
      await base44.asServiceRole.functions.invoke('logBackendError', {
        function_name: 'getStreakState',
        error_category: error?.status === 429 ? 'rate_limit' : 'unknown',
        error_message: error?.message || 'Unknown error',
        page_surface: 'Home',
        severity: 'error',
        stack_trace: error?.stack?.substring?.(0, 1500) || null,
      });
    } catch {}
    return Response.json({ error: error.message }, { status: 500 });
  }
});

