import { createClientFromRequest } from 'npm:@base44/sdk@0.8.23';

/**
 * TRENDING FEED — Global popular posts (sorted by engagement).
 * 
 * ROBUSTNESS:
 * - Graceful degradation at each phase
 * - Fallback to unranked posts if ranking fails
 * - Return empty array instead of throwing errors
 * - Safe defaults for all fields
 */
Deno.serve(async (req) => {
  const startTime = Date.now();

  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me().catch(() => null);

    if (!user) {
      return Response.json({ error: 'Unauthorized' }, { status: 401 });
    }

    let payload = { limit: 20, cursor: undefined };
    try {
      payload = await req.json().catch(() => ({ limit: 20 }));
    } catch {
      // Ignore parse errors, use defaults
    }

    const limit = Math.min(Math.max(parseInt(payload.limit || '20', 10), 1), 100);
    const cursor = payload.cursor ? parseInt(payload.cursor, 10) : 0;

    // ── PHASE 1: Fetch candidates ────────────────────────────────
    let allPosts = [];
    try {
      allPosts = await base44.asServiceRole.entities.Post.filter(
        { status: 'active', is_public: true, moderation_status: 'active' },
        '-created_date',
        1000
      ).catch(() => []);
    } catch (err) {
      console.warn('[getTrendingFeed] fetch posts failed:', err?.message);
    }

    // Safety: handle empty candidate pool
    if (!allPosts || allPosts.length === 0) {
      console.warn('[getTrendingFeed] No posts available');
      return Response.json({
        posts: [],
        cursor: null,
        total: 0,
        fallback: true,
      });
    }

    // ── PHASE 2: Filter ──────────────────────────────────────────
    let filtered = [];
    try {
      filtered = allPosts.filter(p => {
        // Exclude own posts
        if (p.author_id === user.id) return false;

        // AUTHOR STATUS: suppress content from non-active authors
        if (p.author_account_status && p.author_account_status !== 'active') return false;

        // Skip removed/suppressed content
        if (p.moderation_status === 'removed_by_moderation') return false;

        return true;
      });
    } catch (err) {
      console.warn('[getTrendingFeed] filter failed:', err?.message);
      // Fallback: use unfiltered but at least non-removed posts
      filtered = allPosts.filter(p => p.moderation_status !== 'removed_by_moderation');
    }

    // ── PHASE 3: Rank by engagement ──────────────────────────────
    let ranked = [];
    try {
      ranked = filtered
        .map(p => {
          const score = (Math.max(0, p.like_count || 0)) + 
                       (Math.max(0, p.save_count || 0)) * 2 + 
                       (Math.max(0, p.comment_count || 0));
          return { ...p, _score: score };
        })
        .sort((a, b) => (b._score || 0) - (a._score || 0));
    } catch (err) {
      console.warn('[getTrendingFeed] ranking failed:', err?.message);
      // Fallback: use unranked filtered posts
      ranked = filtered;
    }

    // Safety: if ranking/filtering produced nothing, use raw posts
    if (!ranked || ranked.length === 0) {
      console.warn('[getTrendingFeed] No filtered posts, using raw fallback');
      ranked = allPosts.slice(0, limit * 2);
    }

    // ── PHASE 4: Paginate ────────────────────────────────────────
    const start = Math.max(0, cursor || 0);
    const page = ranked
      .slice(start, start + limit)
      .filter(p => p && p.id); // Extra safety: skip null/empty posts

    const nextCursor = page.length === limit ? start + limit : null;

    const elapsed = Date.now() - startTime;
    console.log(`[getTrendingFeed] SUCCESS: user=${user.id} results=${page.length}/${ranked.length} (${elapsed}ms)`);

    return Response.json({
      posts: page,
      cursor: nextCursor,
      total: ranked.length,
    });
  } catch (error) {
    const elapsed = Date.now() - startTime;
    console.error(`[getTrendingFeed] CRITICAL FAILURE (${elapsed}ms):`, error?.message);

    // Return safe empty response instead of 500
    return Response.json({
      posts: [],
      cursor: null,
      total: 0,
      error: error?.message || 'Unknown error',
      fallback_critical: true,
    });
  }
});

/**
 * getTrendingFeedCached v2 — REBALANCED TRENDING
 *
 * UPGRADES from v1:
 *   - Comments now count in engagement (×2 weight)
 *   - Ultra-young low-engagement posts get confidence dampening
 *   - Slightly gentler base decay (8-day instead of 7-day)
 *   - Blocked-user filtering now enforced server-side
 *   - Saves rebalanced (×4 instead of ×5)
 *   - Minimum engagement confidence: posts < 6h old with < 3 total engagement
 *     get a √(eng/3) damper so 2 likes in 1 hour doesn't beat 20 likes in 5 days
 *
 * FORMULA:
 *   rawEngagement = (likes×3) + (saves×4) + (reviews×3) + (comments×2)
 *   velocity = rawEngagement / ageDays
 *   freshnessDecay = exp(-ageDays / DECAY_DAYS)
 *   confidenceDamper = (ageDays < 0.25 && rawEngagement < 9) ? sqrt(rawEngagement/9) : 1.0
 *   trendScore = (rawEngagement > 0) ? velocity × freshnessDecay × confidenceDamper × 10
 *                                    : freshnessDecay × 0.3
 */
import { createClientFromRequest } from 'npm:@base44/sdk@0.8.25';

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user?.id) return Response.json({ error: 'Unauthorized' }, { status: 401 });

    const body = await req.json().catch(() => ({}));
    const limit = Math.min(body.limit || 12, 100);
    const now = Date.now();
    const TTL_MINUTES = 30;

    // ── Blocked users (server-side enforcement) ─────────────────────────────
    const [blockedByMe, blockedByOthers] = await Promise.all([
      base44.asServiceRole.entities.BlockedUser.filter({ blocker_id: user.id }).catch(() => []),
      base44.asServiceRole.entities.BlockedUser.filter({ blocked_id: user.id }).catch(() => []),
    ]);
    const blockedIds = new Set([
      ...blockedByMe.map(b => b.blocked_id),
      ...blockedByOthers.map(b => b.blocker_id),
    ]);

    // ── Check cache ─────────────────────────────────────────────────────────
    let cache = null;
    try {
      const caches = await base44.asServiceRole.entities.TrendingFeedCache.filter(
        { cache_key: 'trending_global' }, '-cached_at', 1
      );
      cache = caches[0] || null;
    } catch (_) {}

    const cacheAge = cache ? (now - new Date(cache.cached_at).getTime()) / 60000 : Infinity;
    const isFresh = cache && cacheAge < TTL_MINUTES && (cache.post_ids?.length || 0) > 0;

    if (isFresh) {
      const recipeIds = cache.post_ids.slice(0, limit);
      const recipes = await Promise.all(
        recipeIds.map(id =>
          base44.asServiceRole.entities.Recipe.filter({ id }).then(r => r[0] || null).catch(() => null)
        )
      );
      const valid = recipes.filter(r =>
        r &&
        r.is_public === true &&
        r.moderation_status !== 'removed_by_moderation' &&
        r.moderation_status !== 'appealed' &&
        r.community_visible !== false &&
        (!r.author_id || !blockedIds.has(r.author_id))
      );

      // Only query real ObjectIds (24-char hex). Seed/demo posts use slugs like
      // "seed_author_sofiaeats" which would crash the User.filter $in query.
      const authorIds = [...new Set(valid.map(r => r.author_id).filter(Boolean))]
        .filter(id => /^[a-f0-9]{24}$/i.test(id));
      const authorMap = {};
      if (authorIds.length > 0) {
        const users = await base44.asServiceRole.entities.User.filter({ id: { $in: authorIds } }).catch(() => []);
        users.forEach(u => { authorMap[u.id] = u; });
      }

      const likedByUser = await base44.asServiceRole.entities.Like.filter(
        { target_type: 'recipe', user_id: user.id }
      ).catch(() => []);
      const likedIds = new Set(likedByUser.map(l => l.target_id));

      const posts = valid.map((r, idx) => enrichRecipe(r, idx + 1, authorMap, likedIds));
      return Response.json({ posts, cached: true, cacheAge: Math.round(cacheAge) });
    }

    // ── Compute trending from scratch ───────────────────────────────────────
    console.log('[getTrendingFeedCached:v2] Cache stale/missing — recomputing');

    const publicRecipes = await base44.asServiceRole.entities.Recipe.filter(
      { is_public: true },
      '-created_date',
      500
    ).catch(() => []);

    const visible = publicRecipes.filter(r =>
      r.is_public === true &&
      r.moderation_status !== 'removed_by_moderation' &&
      r.moderation_status !== 'appealed' &&
      r.community_visible !== false &&
      r.author_account_status !== 'suspended' &&
      r.author_account_status !== 'deleted' &&
      (!r.author_id || !blockedIds.has(r.author_id))
    );

    if (visible.length === 0) {
      console.warn('[getTrendingFeedCached:v2] No visible recipes found');
      return Response.json({ posts: [], cached: false });
    }

    const nowTs = Date.now();
    // Gentler 8-day base decay (was 7). Small pool extends to 14.
    const DECAY_DAYS = visible.length < 12 ? 14 : 8;

    const ranked = [...visible].sort((a, b) => {
      const ageA = Math.max((nowTs - new Date(a.created_date || Date.now()).getTime()) / 86400000, 0.01);
      const ageB = Math.max((nowTs - new Date(b.created_date || Date.now()).getTime()) / 86400000, 0.01);
      const decayA = Math.exp(-ageA / DECAY_DAYS);
      const decayB = Math.exp(-ageB / DECAY_DAYS);

      // Rebalanced weights: saves 4 (was 5), comments 2 (was 0), reviews 3 (was 2)
      const engA = ((a.likes_count || 0) * 3 + (a.saves_count || 0) * 4 + (a.review_count || 0) * 3 + (a.comment_count || 0) * 2);
      const engB = ((b.likes_count || 0) * 3 + (b.saves_count || 0) * 4 + (b.review_count || 0) * 3 + (b.comment_count || 0) * 2);

      // Confidence dampening: ultra-young + low engagement gets sqrt penalty
      const confA = (ageA < 0.25 && engA < 9) ? Math.max(0.2, Math.sqrt(engA / 9)) : 1.0;
      const confB = (ageB < 0.25 && engB < 9) ? Math.max(0.2, Math.sqrt(engB / 9)) : 1.0;

      const scoreA = engA > 0 ? ((engA + 1) / ageA) * decayA * confA : decayA * 0.3;
      const scoreB = engB > 0 ? ((engB + 1) / ageB) * decayB * confB : decayB * 0.3;

      if (Math.abs(scoreB - scoreA) > 0.001) return scoreB - scoreA;
      return new Date(b.created_date || 0) - new Date(a.created_date || 0);
    }).slice(0, 100);

    // Save cache
    const recipeIds = ranked.map(r => r.id);
    try {
      if (cache) {
        await base44.asServiceRole.entities.TrendingFeedCache.update(cache.id, {
          post_ids: recipeIds,
          cached_at: new Date().toISOString(),
        });
      } else {
        await base44.asServiceRole.entities.TrendingFeedCache.create({
          cache_key: 'trending_global',
          post_ids: recipeIds,
          cached_at: new Date().toISOString(),
          cache_ttl_minutes: TTL_MINUTES,
          computation_time_ms: Date.now() - now,
        });
      }
    } catch (e) {
      console.warn('[getTrendingFeedCached:v2] Cache save failed:', e.message);
    }

    // Enrich — only query real ObjectIds (24-char hex). Seed posts use slugs.
    const authorIds = [...new Set(ranked.map(r => r.author_id).filter(Boolean))]
      .filter(id => /^[a-f0-9]{24}$/i.test(id));
    const authorMap = {};
    if (authorIds.length > 0) {
      const users = await base44.asServiceRole.entities.User.filter({ id: { $in: authorIds } }).catch(() => []);
      users.forEach(u => { authorMap[u.id] = u; });
    }

    const likedByUser = await base44.asServiceRole.entities.Like.filter(
      { target_type: 'recipe', user_id: user.id }
    ).catch(() => []);
    const likedIds = new Set(likedByUser.map(l => l.target_id));

    const posts = ranked.slice(0, limit).map((r, idx) => enrichRecipe(r, idx + 1, authorMap, likedIds));
    console.log(`[getTrendingFeedCached:v2] Returning ${posts.length} posts`);
    return Response.json({ posts, cached: false });

  } catch (error) {
    console.error('[getTrendingFeedCached:v2] Error:', error.message);
    return Response.json({ error: error.message, posts: [] }, { status: 500 });
  }
});

function enrichRecipe(recipe, rank, authorMap, likedIds = new Set()) {
  const author = authorMap[recipe.author_id];
  const authorName = author?.display_name || author?.full_name || recipe.author_name || (recipe.source === 'generated' ? 'Reciply AI' : null);
  return {
    ...recipe,
    rank,
    id: recipe.id,
    recipe_id: recipe.id,
    post_id: recipe.id,
    title: recipe.title || '',
    description: recipe.description || '',
    hero_image_url: recipe.hero_image_url || null,
    media_url: recipe.hero_image_url || null,
    author_name: authorName,
    author_avatar: author?.avatar_url || recipe.author_avatar || null,
    likes_count: recipe.likes_count || 0,
    like_count: recipe.likes_count || 0,
    saves_count: recipe.saves_count || 0,
    save_count: recipe.saves_count || 0,
    avg_rating: recipe.avg_rating || 0,
    source: recipe.source || 'user',
    isLiked: likedIds.has(recipe.id),
    viewer_has_liked: likedIds.has(recipe.id),
  };
}

import { createClientFromRequest } from 'npm:@base44/sdk@0.8.23';

Deno.serve(async (req) => {
  const startTime = Date.now();

  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me().catch(() => null);

    const params = new URL(req.url).searchParams;
    const limit = Math.min(parseInt(params.get('limit') || '100', 10), 200);

    // ── PHASE 1: Fetch candidates (with fallback) ──────────────────
    let allPublicPosts = [];
    let allPublicRecipes = [];
    try {
      [allPublicPosts, allPublicRecipes] = await Promise.all([
        base44.asServiceRole.entities.Post.filter(
          { is_public: true, moderation_status: 'active' },
          '-created_date',
          500
        ).catch(() => []),
        base44.asServiceRole.entities.Recipe.filter(
          { is_public: true, moderation_status: 'active' },
          '-created_date',
          300
        ).catch(() => []),
      ]);
    } catch {
      console.warn('[getTrendingTop100] fetch posts/recipes failed, using empty fallback');
    }

    // Convert recipes to post-like objects for consistent ranking
    const recipeAsPosts = (allPublicRecipes || []).map(r => ({
      ...r,
      id: r.id,
      title: r.title,
      media_url: r.hero_image_url,
      cook_time: r.cook_time,
      difficulty: r.difficulty,
      tags: r.tags || [],
      like_count: r.likes_count || 0,
      save_count: r.saves_count || 0,
      comment_count: 0,
      avg_rating: r.avg_rating || 0,
      ratings_count: r.review_count || 0,
      author_name: r.author_name || 'Reciply AI',
      author_avatar: r.author_avatar,
      created_date: r.created_date,
      _type: 'recipe',
    }));

    allPublicPosts = [...(allPublicPosts || []), ...recipeAsPosts];

    // Safety: ensure we have posts to rank, otherwise return cached minimal data
    if (!allPublicPosts || allPublicPosts.length === 0) {
      console.warn('[getTrendingTop100] No posts available, returning empty trending');
      return Response.json({
        posts: [],
        viewer_is_vip: false,
        total: 0,
        error_fallback: true,
      });
    }

    // ── PHASE 2: Filter and rank ──────────────────────────────────
    const now = new Date();
    let ranked = [];

    try {
      ranked = allPublicPosts
        .filter(p => {
          // Skip removed/suspended content
          if (p.status === 'removed' || p.moderation_status === 'removed_by_moderation') return false;
          // Skip content from inactive authors
          if (p.author_account_status && p.author_account_status !== 'active') return false;
          return true;
        })
        .map(post => {
          try {
            const created = new Date(post.created_date || 0);
            const hoursSinceCreation = Math.max(0, (now - created) / (1000 * 60 * 60));

            // Freshness decay: new posts get boost, old posts decay but don't disappear
            const freshness_boost = Math.exp(-Math.max(0, hoursSinceCreation) / 168) * 5;

            const score =
              (Math.max(0, post.like_count || 0)) * 3 +
              (Math.max(0, post.save_count || 0)) * 3 +
              (Math.max(0, post.cooked_count_unique_users || 0)) * 2 +
              (Math.max(0, post.comment_count || 0)) * 1 +
              freshness_boost;

            return { ...post, _score: Math.max(0, score) };
          } catch (err) {
            console.warn('[getTrendingTop100] scoring error:', err?.message);
            return { ...post, _score: 0 };
          }
        })
        .sort((a, b) => (b._score || 0) - (a._score || 0))
        .slice(0, Math.max(limit, 1));
    } catch (err) {
      console.error('[getTrendingTop100] ranking failed:', err?.message);
      // Fallback: use unsorted posts (still better than nothing)
      ranked = allPublicPosts
        .filter(p => p.status !== 'removed' && (!p.author_account_status || p.author_account_status === 'active'))
        .slice(0, limit);
    }

    // Safety: if ranking produced nothing, return at least something
    if (!ranked || ranked.length === 0) {
      console.warn('[getTrendingTop100] ranking produced 0 results, using unranked fallback');
      ranked = allPublicPosts
        .slice(0, limit)
        .map(p => ({ ...p, _score: 0 }));
    }

    // ── PHASE 3: Determine VIP status ─────────────────────────────
    let viewer_is_vip = false;
    if (user) {
      try {
        const subs = await base44.asServiceRole.entities.Subscription.filter(
          { created_by: user.email },
        ).catch(() => []);
        viewer_is_vip = subs && subs.length > 0 && subs[0].status === 'active';
      } catch (err) {
        console.warn('[getTrendingTop100] vip check failed:', err?.message);
      }
    }

    // ── PHASE 4: Fetch engagement state ───────────────────────────
    let viewerLikes = new Set();
    let viewerSaves = new Set();
    if (user) {
      try {
        const [likes, saves] = await Promise.all([
          base44.entities.RecipeLike.filter({ created_by: user.email }).catch(() => []),
          base44.entities.RecipeSave.filter({ created_by: user.email }).catch(() => []),
        ]);
        viewerLikes = new Set((likes || []).map(l => l.recipe_id));
        viewerSaves = new Set((saves || []).map(s => s.recipe_id));
      } catch (err) {
        console.warn('[getTrendingTop100] engagement fetch failed:', err?.message);
      }
    }

    // ── PHASE 5: Build response ───────────────────────────────────
    const response = ranked.map((post, idx) => {
      const rank = idx + 1;
      const isLocked = !viewer_is_vip && rank > 7;

      if (isLocked) {
        return { rank, locked: true };
      }

      return {
        rank,
        locked: false,
        id: post.id || '',
        type: 'POST',
        title: post.title || '(No title)',
        cover_image_url: post.media_url || null,
        time_minutes: post.cook_time || 0,
        difficulty: post.difficulty || 'medium',
        tags: (post.tags || post.diet_tags || []).filter(t => t),
        cooked_count_unique_users: post.cooked_count_unique_users || 0,
        like_count: post.like_count || 0,
        save_count: post.save_count || 0,
        avg_rating: post.avg_rating || 0,
        ratings_count: post.ratings_count || 0,
        comment_count: post.comment_count || 0,
        viewer_has_liked: viewerLikes.has(post.id),
        viewer_has_saved: viewerSaves.has(post.id),
        author_id: post.author_id || '',
        author_name: post.author_name || 'Unknown',
        author_avatar: post.author_avatar || null,
        created_date: post.created_date || new Date().toISOString(),
      };
    });

    const elapsed = Date.now() - startTime;
    console.log(`[getTrendingTop100] SUCCESS: ${response.length} posts, ${elapsed}ms`);

    return Response.json({
      posts: response,
      viewer_is_vip,
      total: response.length,
      cached: false,
    });
  } catch (error) {
    const elapsed = Date.now() - startTime;
    console.error(`[getTrendingTop100] CRITICAL FAILURE (${elapsed}ms):`, error?.message);

    // ABSOLUTE LAST-RESORT FALLBACK: return empty but valid response
    return Response.json({
      posts: [],
      viewer_is_vip: false,
      total: 0,
      error: error?.message || 'Unknown error',
      fallback_empty: true,
    });
  }
});

