import { createClientFromRequest } from 'npm:@base44/sdk@0.8.23';

/**
 * Fetches unseen activity counts for the current user.
 * SOURCE OF TRUTH: Notification entity only.
 * - Only active (is_active=true) notifications
 * - Only unread (is_read=false) notifications
 * - No separate Follow/Like entity queries that can diverge
 */
Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();

    if (!user?.id) {
      return Response.json({ error: 'Unauthorized' }, { status: 401 });
    }

    const sr = base44.asServiceRole;

    // Single source of truth: unread + active notifications for this user
    const allUnread = await sr.entities.Notification.filter({
      recipient_id: user.id,
      is_read: false,
      is_active: true,
    });

    // Count by type
    let likesCount = 0;
    let followersCount = 0;
    let reviewsCount = 0;
    let mentionsCount = 0;

    for (const n of allUnread) {
      // Skip self-notifications
      if (n.from_user_id === user.id) continue;
      // Skip moderation notifications (handled separately)
      if (n.type === 'moderation') continue;

      if (n.type === 'like' || n.type === 'save') {
        likesCount++;
      } else if (n.type === 'follow' || n.type === 'follow_request' || n.type === 'follow_accepted') {
        followersCount++;
      } else if (n.type === 'rating') {
        reviewsCount++;
      } else if (n.type === 'app') {
        // Only count mention-type app notifications
        try {
          const p = n.payload_json ? JSON.parse(n.payload_json) : {};
          if (p.mention) mentionsCount++;
        } catch { /* skip */ }
      }
    }

    const hasUnseenActivity = likesCount > 0 || followersCount > 0 || reviewsCount > 0 || mentionsCount > 0;

    return Response.json({
      hasUnseenActivity,
      likesCount,
      followersCount,
      reviewsCount,
      mentionsCount,
    });
  } catch (error) {
    console.error('[getUnseenActivityCounts] Error:', error);
    return Response.json({ error: error.message }, { status: 500 });
  }
});

import { createClientFromRequest } from 'npm:@base44/sdk@0.8.21';

/**
 * getUserProfile — Fetch a user's profile with follow status.
 *
 * ACCOUNT STATUS CODES returned to frontend:
 *   account_state: 'active'           — normal profile, show everything per privacy rules
 *   account_state: 'paused'           — user-initiated freeze; show "Account On Hold" UI
 *   account_state: 'suspended'        — admin action; show "Account Suspended" UI
 *   account_state: 'pending_deletion' — deletion in progress; show "Account On Hold" UI
 *   account_state: 'deleted'          — tombstoned; show "User Not Found" UI
 *   account_state: 'not_found'        — no record; show "User Not Found" UI
 *
 * Frontend Sub-prompt B must handle all 6 states in UserProfile.jsx.
 */
Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const viewer = await base44.auth.me();

    if (!viewer) {
      return Response.json({ error: 'Unauthorized' }, { status: 401 });
    }

    const { targetUserId, username } = await req.json().catch(() => ({}));

    // SYSTEM 4: Support username lookup for mention click-throughs
    // If only username is provided (from MentionText), resolve it to a userId
    if (!targetUserId && username) {
      try {
        const byUsername = await base44.asServiceRole.entities.User.filter({ username: username.trim() });
        if (byUsername[0]) {
          return Response.json({ user: { id: byUsername[0].id } });
        }
      } catch {}
      return Response.json({ error: 'User not found' }, { status: 404 });
    }

    if (!targetUserId) return Response.json({ error: 'targetUserId required' }, { status: 400 });

    // Fetch target user
    let target = null;
    try {
      const users = await base44.asServiceRole.entities.User.filter({ id: targetUserId });
      target = users[0] || null;
    } catch (_e) {
      return Response.json({
        account_state: 'not_found',
        error: 'User not found',
      }, { status: 404 });
    }

    if (!target) {
      return Response.json({
        account_state: 'not_found',
        error: 'User not found',
      }, { status: 404 });
    }

    const isOwnProfile = viewer.id === targetUserId;
    const targetStatus = target.account_status || 'active';

    // Non-active accounts: return state code so frontend can show correct UI.
    // Own profile always gets full data regardless of status.
    if (!isOwnProfile && targetStatus !== 'active') {
      return Response.json({
        account_state: targetStatus, // 'paused' | 'suspended' | 'pending_deletion' | 'deleted'
        user: {
          id: target.id,
          display_name: target.display_name || target.full_name,
          avatar_url: null, // do not expose avatar of non-active accounts to other users
        },
      });
    }

    // Fetch follow relationship (viewer -> target)
    const viewerFollowsTarget = await base44.asServiceRole.entities.UserFollow.filter({
      follower_id: viewer.id,
      following_id: targetUserId,
    });
    const followRecord = viewerFollowsTarget[0];
    const followStatus = followRecord
      ? (followRecord.status === 'accepted' ? 'following' : 'requested')
      : 'none';

    // Target -> viewer (mutual check)
    const targetFollowsViewer = await base44.asServiceRole.entities.UserFollow.filter({
      follower_id: targetUserId,
      following_id: viewer.id,
    });
    const isMutual = targetFollowsViewer.length > 0 && targetFollowsViewer[0].status === 'accepted';

    // Follower / following counts
    const [followers, following] = await Promise.all([
      base44.asServiceRole.entities.UserFollow.filter({ following_id: targetUserId, status: 'accepted' }),
      base44.asServiceRole.entities.UserFollow.filter({ follower_id: targetUserId, status: 'accepted' }),
    ]);

    // Total likes on public recipes
    const recipes = await base44.asServiceRole.entities.Recipe.filter({
      created_by: target.email,
      is_public: true,
    });
    const totalLikes = recipes.reduce((sum, r) => sum + (r.likes_count || 0), 0);

    // Privacy check
    const isPrivate = target.is_private === true;
    const canViewContent = !isPrivate || isOwnProfile || followStatus === 'following';

    return Response.json({
      account_state: 'active',
      user: {
        id: target.id,
        display_name: target.display_name || target.full_name,
        full_name: target.full_name,
        avatar_url: target.avatar_url,
        bio: target.bio,
        is_private: isPrivate,
        messaging_mode: target.messaging_mode || 'requests_only',
      },
      relationship: {
        follow_status: followStatus,
        is_mutual: isMutual,
        viewer_follows_target: followStatus === 'following',
        target_follows_viewer: isMutual,
        can_view_content: canViewContent,
      },
      counters: {
        follower_count: followers.length,
        following_count: following.length,
        total_likes: totalLikes,
        recipe_count: canViewContent ? recipes.length : 0,
      },
    });
  } catch (error) {
    console.error('getUserProfile error:', error);
    return Response.json({ error: error.message }, { status: 500 });
  }
});

