/**
 * groupJoin — idempotent group join with retry on rate-limit.
 * Creates GroupMember + increments Group.member_count.
 * Returns immediately if already a member.
 */
import { createClientFromRequest } from 'npm:@base44/sdk@0.8.23';

async function withRetry(fn, maxRetries = 3) {
  for (let i = 0; i <= maxRetries; i++) {
    try {
      return await fn();
    } catch (err) {
      const status = err?.status || err?.response?.status;
      if (status === 429 && i < maxRetries) {
        const delay = 1000 * (i + 1); // 1s, 2s, 3s
        console.log(`[groupJoin] Rate limited, retrying in ${delay}ms (attempt ${i + 1}/${maxRetries})`);
        await new Promise(r => setTimeout(r, delay));
        continue;
      }
