/**
 * groupLeave — remove current user from a group and decrement member_count.
 * 
 * OWNERSHIP TRANSFER: If the leaving user is the owner:
 * 1. Transfer ownership to the longest-serving admin
 * 2. If no admins, transfer to the longest-serving member
 * 3. If no other members, delete the group entirely
 *
 * Returns the exact group_id and transfer info for frontend cache targeting.
 */
import { createClientFromRequest } from 'npm:@base44/sdk@0.8.25';

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user) {
      return Response.json({ error: 'Unauthorized' }, { status: 401 });
    }

    const body = await req.json();
    const { group_id } = body;

    if (!group_id) {
      return Response.json({ error: 'group_id required' }, { status: 400 });
    }

    const sr = base44.asServiceRole.entities;

    // Fetch group
    let group = null;
    try {
      group = await sr.Group.get(group_id);
    } catch {
      group = null;
    }
    if (!group) {
      return Response.json({ error: 'Group not found' }, { status: 404 });
    }

    // Find all memberships for this user
    const existing = await sr.GroupMember.filter({ group_id, user_id: user.id });

    if (existing.length === 0) {
      return Response.json({ success: true, group_id, viewer_is_member: false, member_count: group.member_count || 0 });
    }

    const isOwner = group.owner_id === user.id || existing.some(m => m.role === 'owner');

    // Delete ALL memberships for this user
    for (const m of existing) {
      await sr.GroupMember.delete(m.id).catch(err => {
        console.warn('[groupLeave] delete failed for', m.id, err.message);
      });
    }

    // Get remaining members
    const remaining = await sr.GroupMember.filter({ group_id, status: 'active' });

    if (remaining.length === 0) {
      // No one left — delete group entirely
      console.log('[groupLeave] Last member left — deleting group', group_id);
      const messages = await sr.GroupMessage.filter({ group_id }).catch(() => []);
      for (const msg of messages) {
        await sr.GroupMessage.delete(msg.id).catch(() => {});
      }
      await sr.Group.delete(group_id);
      return Response.json({ success: true, group_id, viewer_is_member: false, group_deleted: true, member_count: 0 });
    }

    // If owner is leaving, transfer ownership
    let newOwnerId = null;
    if (isOwner) {
      // Priority: admins by join date (oldest first), then members by join date
      const admins = remaining.filter(m => m.role === 'admin').sort((a, b) => {
        const da = a.joined_at ? new Date(a.joined_at).getTime() : new Date(a.created_date).getTime();
        const db = b.joined_at ? new Date(b.joined_at).getTime() : new Date(b.created_date).getTime();
        return da - db;
      });
      const regularMembers = remaining.filter(m => m.role === 'member').sort((a, b) => {
        const da = a.joined_at ? new Date(a.joined_at).getTime() : new Date(a.created_date).getTime();
        const db = b.joined_at ? new Date(b.joined_at).getTime() : new Date(b.created_date).getTime();
        return da - db;
      });

      const successor = admins[0] || regularMembers[0];
      if (successor) {
        newOwnerId = successor.user_id;
        await sr.GroupMember.update(successor.id, { role: 'owner' });
        await sr.Group.update(group_id, { owner_id: newOwnerId, member_count: remaining.length });
        console.log('[groupLeave] Ownership transferred to', newOwnerId, 'for group', group_id);
        // Send ownership transfer notification to the new owner
        try {
          await base44.asServiceRole.functions.invoke('sendBasicNotification', {
            type: 'ownership_transferred',
            recipientId: newOwnerId,
            actorId: user.id,
            actorName: user.display_name || user.full_name || 'Someone',
            actorAvatar: user.avatar_url || '',
            data: { groupId: group_id, groupName: group.name || 'a group' },
          });
        } catch (ne) { console.warn('[groupLeave] Ownership notif failed:', ne.message); }
      }
    } else {
      await sr.Group.update(group_id, { member_count: remaining.length });
    }

    console.log('[groupLeave] LEFT', { userId: user.id, groupId: group_id, newCount: remaining.length, newOwnerId });

    return Response.json({
      success: true,
      group_id,
      viewer_is_member: false,
      member_count: remaining.length,
      ownership_transferred: !!newOwnerId,
      new_owner_id: newOwnerId,
    });
  } catch (error) {
    console.error('[groupLeave]', error.message);
    return Response.json({ error: error.message }, { status: 500 });
  }
});

