        if (target_user_id === group.owner_id) {
          return Response.json({ error: 'Cannot ban the group owner' }, { status: 400 });
        }
        const memberships = await base44.asServiceRole.entities.GroupMember.filter({ group_id, user_id: target_user_id });
        if (memberships.length > 0) {
          // Update existing record to banned
          await base44.asServiceRole.entities.GroupMember.update(memberships[0].id, { status: 'banned' });
