function checkProfanity(normalized) {
  if (!normalized) return { blocked: false };
  const tokens = normalized.split(/\s+/).filter(Boolean);
  for (const profanity of PROFANITY_DICTIONARY) {
    if (new RegExp(`\\b${profanity}\\b`).test(normalized)) {
      return { blocked: true };
    }
    for (const token of tokens) {
      if (token.includes(profanity) && token !== profanity) {
        const beforeIndex = token.indexOf(profanity);
        const afterIndex = beforeIndex + profanity.length;
        const before = token.substring(0, beforeIndex);
        const after = token.substring(afterIndex);
        if ((before && before.length < 4) || (after && after.length < 4)) {
          return { blocked: true };
        }
      }
    }
  }
  return { blocked: false };
}

function isSafeException(text) {
  if (!text) return false;
  const lower = text.toLowerCase();
  return CULINARY_SAFE_WORDS.some(word => lower.includes(word));
}

function containsProfanity(text) {
  if (!text || typeof text !== 'string') return false;
  const trimmed = text.trim();
  if (!trimmed) return false;
  if (isSafeException(trimmed)) return false;
  const normalized = normalizeText(trimmed);
  return checkProfanity(normalized).blocked;
}

Deno.serve(async (req) => {
