});

import { createClientFromRequest } from 'npm:@base44/sdk@0.8.20';

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user) return Response.json({ error: 'Unauthorized' }, { status: 401 });

    const { comment_id } = await req.json();
    if (!comment_id) return Response.json({ error: 'Missing comment_id' }, { status: 400 });

    const comment = await base44.asServiceRole.entities.GroupPostComment.get(comment_id);
    if (!comment) return Response.json({ error: 'Comment not found' }, { status: 404 });

    const existing = await base44.asServiceRole.entities.GroupPostCommentLike.filter({
      comment_id,
      user_id: user.id,
    });

    const userLiked = existing.length > 0;

    if (userLiked) {
      for (const like of existing) {
        await base44.asServiceRole.entities.GroupPostCommentLike.delete(like.id);
      }
    } else {
      try {
        await base44.asServiceRole.entities.GroupPostCommentLike.create({ comment_id, user_id: user.id });
      } catch (e) {
        const msg = e.message?.toLowerCase() || '';
        if (!msg.includes('unique') && e.code !== 'UNIQUE_CONSTRAINT_VIOLATION') throw e;
      }
    }

    // Recount authoritatively
    const allLikes = await base44.asServiceRole.entities.GroupPostCommentLike.filter({ comment_id });
    const uniqueUsers = new Set(allLikes.map(l => l.user_id));
    if (userLiked) uniqueUsers.delete(user.id);
    else uniqueUsers.add(user.id);

    const newCount = uniqueUsers.size;
    const finalLiked = uniqueUsers.has(user.id);

    await base44.asServiceRole.entities.GroupPostComment.update(comment_id, { like_count: newCount });
    return Response.json({ liked: finalLiked, count: newCount });
  } catch (error) {
    return Response.json({ error: error.message }, { status: 500 });
  }
});

