/**
 * groupPostCreate — create a post in a group.
 * - Pro-gating: only Pro users can post
 * - 1 hour cooldown per user per group (server-enforced)
 * - Bad-word moderation on caption
 * - Structured logging
 */
import { createClientFromRequest } from 'npm:@base44/sdk@0.8.20';

const BLOCKED_TERMS = [
  /\bfuck\b/i, /\bshit\b/i, /\bcunt\b/i, /\bn[i1]gg[ae]r/i,
  /\basshole\b/i, /\bbitc+h\b/i, /\bdick\b/i, /\bcoc+k\b/i,
  /\bpussy\b/i, /\bwhore\b/i, /\bslut\b/i,
];

function moderateText(text) {
  if (!text) return { ok: true };
  for (const pattern of BLOCKED_TERMS) {
    if (pattern.test(text)) return { ok: false, code: 'CONTENT_NOT_ALLOWED' };
  }
  return { ok: true };
}

Deno.serve(async (req) => {
  const reqId = crypto.randomUUID().slice(0, 8);
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user) return Response.json({ error: 'Unauthorized' }, { status: 401 });

    const body = await req.json();
    const { group_id, content, media_url, recipe_id } = body;

    console.log(`[GROUP_POST:${reqId}] groupId=${group_id} userId=${user.id} isPro=${!!user.is_pro}`);

    if (!group_id) {
      return Response.json({ ok: false, error: 'group_id required' }, { status: 400 });
    }

    // Pro gate
    if (!user.is_pro) {
      console.warn(`[GROUP_POST:${reqId}] NOT_PRO userId=${user.id}`);
      return Response.json({ ok: false, error_code: 'NOT_PRO', error: 'Pro subscription required to post in groups.' }, { status: 403 });
    }

    // Membership check
    const members = await base44.asServiceRole.entities.GroupMember.filter({ group_id, user_id: user.id });
    if (members.length === 0) {
      return Response.json({ ok: false, error: 'Not a group member' }, { status: 403 });
    }

    // 1 hour cooldown
    const oneHourAgo = new Date(Date.now() - 60 * 60 * 1000).toISOString();
    const recentPosts = await base44.asServiceRole.entities.GroupPost.filter({
      group_id,
      author_id: user.id,
    }, '-created_at', 1);

    if (recentPosts.length > 0) {
      const lastPostTime = new Date(recentPosts[0].created_at || recentPosts[0].created_date);
      const remainingMs = (lastPostTime.getTime() + 60 * 60 * 1000) - Date.now();
      if (remainingMs > 0) {
        const remaining_seconds = Math.ceil(remainingMs / 1000);
        console.warn(`[GROUP_POST:${reqId}] COOLDOWN userId=${user.id} remainingSecs=${remaining_seconds}`);
        return Response.json({
          ok: false,
          error_code: 'COOLDOWN',
          error: `Wait ${Math.ceil(remaining_seconds / 60)} minutes before posting again.`,
          remaining_seconds,
        }, { status: 429 });
      }
    }

    // Content moderation
    if (content) {
      const mod = moderateText(content);
      if (!mod.ok) {
        console.warn(`[GROUP_POST:${reqId}] CONTENT_BLOCKED userId=${user.id}`);
        return Response.json({ ok: false, error_code: mod.code, error: 'Please edit your message.' }, { status: 400 });
      }
    }

    if (!recipe_id) {
      return Response.json({ ok: false, error: 'A linked recipe is required to share a post.', error_code: 'RECIPE_REQUIRED' }, { status: 400 });
    }

    // Validate recipe: must exist, be owned by caller, and NOT be AI-generated
    const recipeRows = await base44.asServiceRole.entities.Recipe.filter({ id: recipe_id }).catch(() => []);
    const recipe = recipeRows?.[0];
    if (!recipe) {
      return Response.json({ ok: false, error: 'Recipe not found.', error_code: 'RECIPE_NOT_FOUND' }, { status: 404 });
    }
    if (recipe.source === 'generated') {
      console.warn(`[GROUP_POST:${reqId}] AI_RECIPE_BLOCKED recipeId=${recipe_id} userId=${user.id}`);
      return Response.json({ ok: false, error: 'AI-generated recipes cannot be shared as group posts.', error_code: 'AI_RECIPE_NOT_ALLOWED' }, { status: 400 });
    }
    if (recipe.author_id && recipe.author_id !== user.id) {
      console.warn(`[GROUP_POST:${reqId}] NOT_RECIPE_OWNER recipeId=${recipe_id} userId=${user.id}`);
      return Response.json({ ok: false, error: 'You can only share your own recipes.', error_code: 'NOT_RECIPE_OWNER' }, { status: 403 });
    }

    const post = await base44.asServiceRole.entities.GroupPost.create({
      group_id,
      author_id: user.id,
      author_name: user.full_name || user.display_name || 'User',
      author_avatar: user.avatar_url || '',
      content: content || '',
      media_url: media_url || null,
      recipe_id: recipe_id || null,
      like_count: 0,
      comment_count: 0,
      created_at: new Date().toISOString(),
    });

    console.log(`[GROUP_POST:${reqId}] SUCCESS postId=${post.id} groupId=${group_id}`);
    return Response.json({ ok: true, success: true, post_id: post.id }, { status: 201 });
  } catch (error) {
    console.error(`[GROUP_POST:${reqId}] UNCAUGHT: ${error.message}`);
    return Response.json({ ok: false, error: error.message }, { status: 500 });
  }
});

import { createClientFromRequest } from 'npm:@base44/sdk@0.8.20';

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user) return Response.json({ error: 'Unauthorized' }, { status: 401 });

    const { post_id } = await req.json();
    if (!post_id) return Response.json({ error: 'Missing post_id' }, { status: 400 });

    const sr = base44.asServiceRole.entities;

    const post = await sr.GroupPost.get(post_id);
    if (!post) return Response.json({ error: 'Post not found' }, { status: 404 });

    // Get ALL like records for this user/post (handles any pre-existing duplicates safely)
    const existing = await sr.GroupPostLike.filter({ group_post_id: post_id, user_id: user.id });
    const userCurrentlyLiked = existing.length > 0;

    if (userCurrentlyLiked) {
      // Delete ALL records for this user/post — cleans up any pre-existing duplicates too
      for (const like of existing) {
        await sr.GroupPostLike.delete(like.id);
      }
      console.log('[groupPostLikeToggle] Unliked', { userId: user.id, postId: post_id, deletedCount: existing.length });
    } else {
      try {
        await sr.GroupPostLike.create({ group_post_id: post_id, user_id: user.id });
        console.log('[groupPostLikeToggle] Liked', { userId: user.id, postId: post_id });
      } catch (createErr) {
        // Unique constraint hit (race condition) — treat as already liked, idempotent
        const msg = createErr.message?.toLowerCase() || '';
        if (!msg.includes('unique') && createErr.code !== 'UNIQUE_CONSTRAINT_VIOLATION') {
          throw createErr;
        }
        console.log('[groupPostLikeToggle] Duplicate absorbed (race)', { userId: user.id, postId: post_id });
      }
    }

    // Recount from authoritative source — deduplicate by user_id
    const allLikes = await sr.GroupPostLike.filter({ group_post_id: post_id });
    const uniqueUserIds = new Set(allLikes.map(l => l.user_id));

    // Force-apply the KNOWN operation result to eliminate DB write-propagation timing issues.
    // A re-query after delete can still see the old row if the commit hasn't fully propagated —
    // this causes the unlike-rebound bug. We know the exact intended final state:
    if (userCurrentlyLiked) {
      uniqueUserIds.delete(user.id); // we just deleted all this user's like rows
    } else {
      uniqueUserIds.add(user.id);   // we just created this user's like row
    }

    const newCount = uniqueUserIds.size;
    const finalLiked = uniqueUserIds.has(user.id); // deterministic, no timing dependency

    await sr.GroupPost.update(post_id, { like_count: newCount });

    return Response.json({ liked: finalLiked, count: newCount });
  } catch (error) {
    console.error('[groupPostLikeToggle]', error);
    return Response.json({ error: error.message }, { status: 500 });
  }
});

