/**
 * guardCreateGroup — server-authoritative gate for group creation.
 * 
 * Checks:
 * 1. Pro entitlement (subscription + canceled-but-in-period)
 * 2. Anti-spam: max 5 groups per rolling 7-day window
 */

const MAX_GROUPS_PER_WEEK = 5;

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user) return Response.json({ error: 'Unauthorized' }, { status: 401 });

    // Admin/owner always allowed (no rate limit)
    if (user.role === 'admin') {
      return Response.json({ allowed: true });
    }

    const now = Date.now();
    const sr = base44.asServiceRole;
    const subs = await sr.entities.Subscription.filter({ created_by: user.email }).catch(() => []);

    const ENTITLED_PLANS = new Set(['pro', 'vip', 'trial']);
    const ENTITLED_STATUSES = new Set(['active', 'active_paid', 'trialing', 'grace_period']);

    const activeSub = subs.find(s => {
      if (!ENTITLED_PLANS.has(s.plan_type)) return false;
      if (ENTITLED_STATUSES.has(s.status)) return true;
      if (s.status === 'canceled' || s.status === 'canceled_pending_expiry') {
        if (s.current_period_end && new Date(s.current_period_end).getTime() > now) return true;
      }
      return false;
    });

    if (!activeSub) {
      console.log(`[guardCreateGroup] user=${user.id} → BLOCKED (no active sub)`);
      return Response.json({
        allowed: false,
        reason: 'PAYWALL_CREATE',
        message: 'Creating groups requires a Pro subscription',
      }, { status: 402 });
    }

    // ── Anti-spam: 5 groups per rolling 7 days ──────────────────────────────
    const sevenDaysAgo = new Date(now - 7 * 24 * 60 * 60 * 1000).toISOString();
    const recentGroups = await sr.entities.Group.filter(
      { owner_id: user.id },
      '-created_date',
      MAX_GROUPS_PER_WEEK + 1
    ).catch(() => []);

    const groupsInWindow = recentGroups.filter(g => 
      g.created_date && new Date(g.created_date).toISOString() >= sevenDaysAgo
    );

    if (groupsInWindow.length >= MAX_GROUPS_PER_WEEK) {
      console.log(`[guardCreateGroup] user=${user.id} → BLOCKED (anti-spam: ${groupsInWindow.length} groups in 7 days)`);
      return Response.json({
        allowed: false,
        reason: 'RATE_LIMITED',
        message: `You can create up to ${MAX_GROUPS_PER_WEEK} groups per week. Please wait before creating another.`,
        groups_created_this_week: groupsInWindow.length,
        limit: MAX_GROUPS_PER_WEEK,
      }, { status: 429 });
    }

    console.log(`[guardCreateGroup] user=${user.id} → ALLOWED (${activeSub.plan_type}/${activeSub.status}, groups_this_week=${groupsInWindow.length})`);
    return Response.json({ 
      allowed: true,
      groups_created_this_week: groupsInWindow.length,
      group_limit_per_week: MAX_GROUPS_PER_WEEK,
    });
  } catch (error) {
    console.error('guardCreateGroup error:', error);
    return Response.json({ error: error.message }, { status: 500 });
  }
});

