/**
 * handleReferralProUpgrade
 *
 * Called after a user successfully upgrades to Pro.
 * Awards +10 bonus credits to the inviter (ONE TIME only).
 *
 * Anti-abuse:
 * - Only fires if the upgrading user was referred
 * - pro_reward_given flag prevents duplicate payouts
 * - Idempotent: safe to call multiple times
 */
import { createClientFromRequest } from 'npm:@base44/sdk@0.8.23';

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user) return Response.json({ error: 'Unauthorized' }, { status: 401 });

    const userId = user.id;

    // Find the completed attribution where this user was the INVITED user
    const attributions = await base44.asServiceRole.entities.ReferralAttribution.filter({
      invited_user_id: userId,
      status: 'completed',
    });

    if (!attributions.length) {
      return Response.json({ success: true, skipped: true, reason: 'not_referred' });
    }

    const attribution = attributions[0];

    // Check if pro_reward_given is already true (idempotency)
    if (attribution.pro_reward_given === true) {
      return Response.json({ success: true, skipped: true, reason: 'already_rewarded' });
    }

    const inviterId = attribution.inviter_user_id;
    if (!inviterId) {
      return Response.json({ success: true, skipped: true, reason: 'no_inviter' });
    }

    // Mark pro_reward_given FIRST to prevent race-condition duplicates
    await base44.asServiceRole.entities.ReferralAttribution.update(attribution.id, {
      pro_reward_given: true,
      pro_reward_given_at: new Date().toISOString(),
    });

    // Award +10 credits to the inviter via ledger
    const now = new Date().toISOString();
    await base44.asServiceRole.entities.ReferralRewardLedger.create({
      user_id: inviterId,
      source_referral_attribution_id: attribution.id,
      reward_type: 'recipe_generation_credit',
      credit_amount: 10,
      credit_state: 'earned',
      credits_remaining: 10,
      earned_at: now,
    });

    // Update inviter's aggregate counters
    const inviterProfiles = await base44.asServiceRole.entities.UserReferralProfile.filter({ user_id: inviterId });
    if (inviterProfiles.length > 0) {
      const profile = inviterProfiles[0];
      await base44.asServiceRole.entities.UserReferralProfile.update(profile.id, {
        total_credits_earned: (profile.total_credits_earned || 0) + 10,
      });
    }

    // Create a reward popup event for the inviter
    await base44.asServiceRole.entities.UserRewardEvent.create({
      recipient_user_id: inviterId,
      reward_type: 'referral_reward',
      credit_amount: 10,
      custom_message: 'A friend you invited just upgraded to Pro! You earned +10 bonus credits 🚀',
      is_seen: false,
    }).catch(() => {});

    console.log(`[REFERRAL PRO BONUS] inviter=${inviterId} invited=${userId} → +10 credits awarded`);

    return Response.json({
      success: true,
      rewarded: true,
      inviter_id: inviterId,
      credits_awarded: 10,
    });
  } catch (error) {
    console.error('[handleReferralProUpgrade]', error.message);
    return Response.json({ error: error.message }, { status: 500 });
  }
});

/**
 * PRODUCTION HEALTH CHECK — validates recipe visibility & community eligibility
 * Run on demand to diagnose why recipes aren't loading
 */
import { createClientFromRequest } from 'npm:@base44/sdk@0.8.20';

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user?.id || user.role !== 'admin') {
      return Response.json({ error: 'Admin only' }, { status: 403 });
    }

    // Get sample of public recipes
    const publicRecipes = await base44.asServiceRole.entities.Recipe.filter(
      { is_public: true },
      '-created_date',
      50
    );

    console.log(`[HEALTH_CHECK] found ${publicRecipes.length} public recipes`);

    const stats = {
      total_public: publicRecipes.length,
      by_source: {},
      by_visibility: {
        community_visible_true: 0,
        community_visible_false: 0,
        community_visible_missing: 0,
      },
      missing_fields: {
        no_author_id: 0,
        no_created_date: 0,
        no_title: 0,
      },
      samples: publicRecipes.slice(0, 5).map(r => ({
        id: r.id,
        title: r.title,
        author_id: r.author_id,
        created_by: r.created_by,
        is_public: r.is_public,
        source: r.source,
        community_visible: r.community_visible,
        created_date: r.created_date,
      })),
    };

    // Analyze
    publicRecipes.forEach(r => {
      stats.by_source[r.source || 'null'] = (stats.by_source[r.source || 'null'] || 0) + 1;

      if (r.community_visible === true) stats.by_visibility.community_visible_true++;
      else if (r.community_visible === false) stats.by_visibility.community_visible_false++;
      else stats.by_visibility.community_visible_missing++;

      if (!r.author_id) stats.missing_fields.no_author_id++;
      if (!r.created_date) stats.missing_fields.no_created_date++;
      if (!r.title) stats.missing_fields.no_title++;
    });

    console.log(`[HEALTH_CHECK] stats:`, JSON.stringify(stats, null, 2));

    return Response.json({ ok: true, stats });
