/**
 * HOME / PROFILE: MY RECIPES
 * Returns ALL of the current user's own recipes (both public AND private).
 * source='user' ensures generated recipes never appear here.
 * Filters by created_by (owner) — user always sees their own recipes regardless of privacy setting.
 */
Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user) return Response.json({ error: 'Unauthorized' }, { status: 401 });

    const body = await req.json().catch(() => ({}));
    const limit = body.limit || 8;

    // Fetch all user's recipes — source='user' excludes generated
    // Fetch by BOTH author_id AND created_by to handle recipes created via different paths
    // Also fetch any missing-source recipes to catch edge cases
    const fetchLimit = Math.max(limit * 3, 30);
    const [byAuthorId, byCreatedBy, byAuthorIdAll] = await Promise.all([
      base44.asServiceRole.entities.Recipe.filter(
        { author_id: user.id, source: 'user' },
        '-created_date',
        fetchLimit
      ).catch(() => []),
      base44.asServiceRole.entities.Recipe.filter(
        { created_by: user.email, source: 'user' },
        '-created_date',
        fetchLimit
      ).catch(() => []),
      // Safety net: fetch ALL recipes by this author in case source field is missing/wrong
      base44.asServiceRole.entities.Recipe.filter(
        { author_id: user.id },
        '-created_date',
        fetchLimit
      ).catch(() => []),
    ]);

    // Merge and deduplicate by id
    // CRITICAL: Exclude ALL source='generated' recipes — they belong in the Generated tab only.
    // Generated recipes must NEVER appear in the "My Recipes" / public posts tab,
    // even if is_saved=true. The only exception is if explicitly published to community
    // (is_community_content=true), which is a separate intentional action.
    const seenIds = new Set();
    const recipes = [];
    for (const r of [...byAuthorId, ...byCreatedBy, ...byAuthorIdAll]) {
      if (seenIds.has(r.id)) continue;
      seenIds.add(r.id);
      // Exclude generated recipes unless explicitly published to community
      if (r.source === 'generated' && !r.is_community_content) continue;
      // Exclude shop-only recipes — they belong in the Shop tab, not personal profile
      if (r.is_shop_content && !r.is_community_content) continue;
      recipes.push(r);
    }
    // Re-sort by created_date descending after merge
    recipes.sort((a, b) => new Date(b.created_date) - new Date(a.created_date));

    // Show all except actively moderation-removed — null moderation_status is ALLOWED (treated as active)
    const visible = recipes
      .filter(r =>
        r.moderation_status !== 'removed_by_moderation' &&
        r.moderation_status !== 'appealed'
      )
      .slice(0, limit);

    console.log(`[homeMyRecipes] user=${user.id} found=${recipes.length} visible=${visible.length}`);

    // Enrich each recipe with live avg_rating and review_count from RecipeAggregate if available
    // This ensures the profile page always shows up-to-date rating stats
    const enriched = await Promise.all(
      visible.map(async (r) => {
        // avg_rating and review_count already live on Recipe entity — return as-is
        // They are updated by the review/rating system directly on the Recipe record
        return {
          ...r,
          avg_rating: r.avg_rating ?? 0,
          review_count: r.review_count ?? 0,
          likes_count: r.likes_count ?? 0,
        };
      })
    );

    return Response.json({ posts: enriched, total: enriched.length });
  } catch (error) {
    console.error('[homeMyRecipes] error:', error);
    return Response.json({ error: error.message }, { status: 500 });
  }
});

