alories:0,protein_g:0,carbs_g:0,fat_g:0},"pepper":{calories:0,protein_g:0,carbs_g:0,fat_g:0}};
const UNIT_TO_GRAMS = {'g':1,'gram':1,'grams':1,'kg':1000,'oz':28.35,'ounce':28.35,'ounces':28.35,'lb':453.6,'lbs':453.6,'cup':240,'cups':240,'tbsp':15,'tablespoon':15,'tablespoons':15,'tsp':5,'teaspoon':5,'teaspoons':5,'ml':1,'l':1000};
const OIL_DENSITY = 0.911;
