function lookupNutr(name) { if (!name) return null; const l = name.toLowerCase().trim(); if (FOODS_PER_100G[l]) return FOODS_PER_100G[l]; for (const [k,v] of Object.entries(FOODS_PER_100G)) { if (k.length > 3 && l.includes(k)) return v; } return null; }
function evalFrac(s) { if (String(s).includes('/')) { const [n,d] = String(s).split('/'); return parseFloat(n)/parseFloat(d); } return parseFloat(s); }
function resolveGrams(ing) { let a = String(ing.amount||'').trim(); if (a && ing.unit && /^[\d./]+$/.test(a)) a=`${a} ${ing.unit}`; if (!a) return ing.base_grams>0?ing.base_grams:100; const jg=a.match(/^([\d.]+)\s*g$/i); if(jg) return parseFloat(jg[1]); const nu=a.match(/^([\d.\/]+)\s*(ml|l|tsp|tbsp|tablespoon|teaspoon|cup|cups|oz|lb|lbs|kg|g)\b/i); if(nu){const q=evalFrac(nu[1]),u=nu[2].toLowerCase(),ug=UNIT_TO_GRAMS[u]??UNIT_TO_GRAMS[u.replace(/s$/,'')]; if(ug) return q*ug*(VOLUME_UNITS.has(u)&&OIL_KEYWORDS.some(k=>(ing.name||'').toLowerCase().includes(k))?OIL_DENSITY:1);} const q2=evalFrac(a.split(/\s/)[0])||1; const nl=(ing.name||'').toLowerCase(); if(PIECE_WEIGHTS[nl]) return q2*PIECE_WEIGHTS[nl]; return q2*100; }

function injectTotalNutrition(recipe) {
  if (recipe.nutrition_total_for_recipe?.calories > 0 && recipe.nutrition_per_serving?.calories > 0) return recipe;
  const s = Math.max(1, recipe.servings || 1);
  const ps = recipe.nutrition_per_serving; const leg = recipe.nutrition;
  const src = (ps?.calories > 0) ? ps : (leg?.calories > 0 ? leg : null);
  if (src) { return { ...recipe, nutrition_total_for_recipe: { calories:Math.round((src.calories||0)*s), protein:Math.round(((src.protein??src.protein_g??0))*s), carbs:Math.round(((src.carbs??src.carbs_g??0))*s), fat:Math.round(((src.fat??src.fat_g??0))*s) }, nutrition_per_serving: ps?.calories>0?ps:{ calories:src.calories||0, protein:src.protein??src.protein_g??0, carbs:src.carbs??src.carbs_g??0, fat:src.fat??src.fat_g??0 } }; }
