}

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user?.id) return Response.json({ error: 'Unauthorized' }, { status: 401 });

    const body = await req.json().catch(() => ({}));
    const limit = Math.min(body.limit || 100, 100);

    console.log(`[TRENDING_V4:${user.id}] fetching limit=${limit}`);

    // ── Blocked users (server-side enforcement) ─────────────────────────────
    const [blockedByMe, blockedByOthers] = await Promise.all([
      base44.asServiceRole.entities.BlockedUser.filter({ blocker_id: user.id }).catch(() => []),
      base44.asServiceRole.entities.BlockedUser.filter({ blocked_id: user.id }).catch(() => []),
    ]);
    const blockedIds = new Set([
      ...blockedByMe.map(b => b.blocked_id),
      ...blockedByOthers.map(b => b.blocker_id),
    ]);

    const allRecipes = await base44.asServiceRole.entities.Recipe.filter(
      { is_public: true }, '-created_date', 500
    ).catch(() => []);

    if (allRecipes.length === 0) {
      return Response.json({ posts: [], total: 0, source: 'empty' });
    }

    const now = Date.now();
    const TRENDING_WINDOW_DAYS = 8; // Gentler (was 7)

    const visibleRecipes = allRecipes.filter(r =>
      r.moderation_status !== 'removed_by_moderation' &&
      r.moderation_status !== 'appealed' &&
      r.moderation_status !== 'deleted_by_owner' &&
      // Allow shop recipes even if community_visible is not explicitly set
      (r.community_visible !== false || r.is_shop_content === true) &&
      (!r.author_id || !blockedIds.has(r.author_id))
    );

    const ranked = visibleRecipes
      .map(recipe => {
        const ageDays = Math.max((now - new Date(recipe.created_date || Date.now()).getTime()) / 86400000, 0.1);
        const likes = recipe.likes_count || 0;
        const saves = recipe.saves_count || 0;
        const reviews = recipe.review_count || 0;
        const comments = recipe.comment_count || 0;

        // Rebalanced: saves ×4 (was ×5), comments ×2 (was 0), reviews ×3 (was ×4)
        const rawEngagement = (likes * 3) + (saves * 4) + (reviews * 3) + (comments * 2);
        const velocity = rawEngagement / ageDays;
        const freshnessDecay = Math.exp(-ageDays / TRENDING_WINDOW_DAYS);

        // Confidence dampening: ultra-young + low engagement
        const confidenceDamper = (ageDays < 0.25 && rawEngagement < 9)
          ? Math.max(0.2, Math.sqrt(rawEngagement / 9))
          : 1.0;

        let trendScore = rawEngagement > 0
          ? velocity * freshnessDecay * confidenceDamper * 10
          : freshnessDecay * 0.3;

        // Reinsertion penalty
        if (recipe.reinsertion_phase === 'warmup' && recipe.reinsertion_weight != null) {
          trendScore *= recipe.reinsertion_weight * 0.5;
        }

        return { recipe, trendScore, _debug: { ageDays: +ageDays.toFixed(1), velocity: +velocity.toFixed(3), freshnessDecay: +freshnessDecay.toFixed(3), confidenceDamper: +confidenceDamper.toFixed(3), rawEngagement, likes, saves, reviews, comments } };
      })
      .sort((a, b) => b.trendScore - a.trendScore)
      .slice(0, limit)
      .map((item, idx) => ({ ...item.recipe, rank: idx + 1, _trend_score: +item.trendScore.toFixed(4) }));

    console.log(`[TRENDING_V4:${user.id}] ranked=${ranked.length}`);

    // Enrich
    const authorIds = [...new Set(ranked.map(r => r.author_id).filter(Boolean))];
    const authorMap = {};
    if (authorIds.length > 0) {
      const users = await base44.asServiceRole.entities.User.filter({ id: { $in: authorIds } }).catch(() => []);
      users.forEach(u => { authorMap[u.id] = { full_name: u.full_name, avatar_url: u.avatar_url }; });
    }

    const trendingLikedByUser = await base44.asServiceRole.entities.Like.filter(
      { target_type: 'recipe', user_id: user.id }
    ).catch(() => []);
    const trendingLikedIds = new Set(trendingLikedByUser.map(l => l.target_id));

    const enriched = ranked.map(r => {
      if (r.author_id && authorMap[r.author_id]) {
        const u = authorMap[r.author_id];
        r = { ...r, author_name: u.full_name || r.author_name, author_avatar: u.avatar_url || r.author_avatar };
      }
      return { ...injectTotalNutrition(r), isLiked: trendingLikedIds.has(r.id), viewer_has_liked: trendingLikedIds.has(r.id) };
    });

    return Response.json({ posts: enriched, total: enriched.length, source: 'trending_v4' });
  } catch (error) {
    console.error(`[TRENDING_V4] fatal error: ${error.message}`);
    return Response.json({ error: error.message, posts: [], total: 0 }, { status: 500 });
  }
});

import { createClientFromRequest } from 'npm:@base44/sdk@0.8.6';

/**
 * Atomically increment generation usage for free users.
 * Called AFTER validation passes, just before generation starts.
 * Idempotent: same generation_id only increments once.
 */
Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user) return Response.json({ error: 'Unauthorized' }, { status: 401 });

    const { generation_id } = await req.json();
    if (!generation_id) return Response.json({ error: 'generation_id required' }, { status: 400 });

    // Check subscription first
    const subs = await base44.asServiceRole.entities.Subscription.filter({
      created_by: user.email,
    });

    const sub = subs[0];
    if (sub && (sub.status === 'active' || sub.status === 'trialing')) {
      // Premium user, no increment
      console.log(`[USAGE_INCREMENT] user=${user.id} premium_skip`);
      return Response.json({ success: true, incremented: false });
    }

    // Get week start
    const weekStart = getWeekStartDate(new Date());
    const weekStartStr = weekStart.toISOString().split('T')[0];

    // Get or create counter
    const existing = await base44.asServiceRole.entities.UsageCounter.filter({
      created_by: user.email,
      feature: 'recipe_generation',
      week_start_date: weekStartStr,
    });

    let counter;
    if (existing.length > 0) {
      counter = existing[0];
      // Increment
      const newCount = counter.count + 1;
      await base44.asServiceRole.entities.UsageCounter.update(counter.id, {
        count: newCount,
      });
      counter.count = newCount;
    } else {
      // Create with count=1
      counter = await base44.asServiceRole.entities.UsageCounter.create({
        feature: 'recipe_generation',
        week_start_date: weekStartStr,
        count: 1,
      });
    }

    console.log(`[USAGE_INCREMENT] user=${user.id} count=${counter.count} week=${weekStartStr}`);

    return Response.json({
      success: true,
      incremented: true,
      count: counter.count,
      limit: 2,
      remaining: Math.max(0, 2 - counter.count),
    });
  } catch (error) {
    console.error('incrementGenerationUsage error:', error);
    return Response.json({ error: error.message }, { status: 500 });
  }
});

function getWeekStartDate(date) {
  const d = new Date(date);
  const day = d.getDay() || 7;
  d.setDate(d.getDate() - (day - 1));
  d.setHours(0, 0, 0, 0);
  return d;
}

