 * 3-step strict pipeline:
 *   Step 1 — Fetch full nutrition + metadata from USDA FoodData Central (with OpenFoodFacts fallback)
 *   Step 2 — Generate a hyper-realistic custom icon via AI image generation
 *   Step 3 — Return enriched ingredient + icon URL ready to save to pantry
 */
import { createClientFromRequest } from 'npm:@base44/sdk@0.8.21';

const USDA_KEY = Deno.env.get("USDA_API_KEY");
const OPFF_BASE = Deno.env.get("OPENFOODFACTS_BASE_URL") || "https://world.openfoodfacts.org";

// ── STEP 1: Fetch nutrition from USDA ─────────────────────────────────────────
async function fetchUSDANutrition(ingredientName) {
  try {
    const searchUrl = `https://api.nal.usda.gov/fdc/v1/foods/search?query=${encodeURIComponent(ingredientName)}&dataType=Foundation,SR%20Legacy&pageSize=1&api_key=${USDA_KEY}`;
    const res = await fetch(searchUrl);
    if (!res.ok) throw new Error(`USDA HTTP ${res.status}`);
    const data = await res.json();
    const food = data.foods?.[0];
    if (!food) return null;

    const getNutrient = (id) => food.foodNutrients?.find(n => n.nutrientId === id)?.value ?? 0;

    return {
      source: "usda",
      fdc_id: String(food.fdcId),
      description: food.description,
      nutrition_per_100g: {
        calories: getNutrient(1008),
        protein: getNutrient(1003),
        carbs: getNutrient(1005),
        fat: getNutrient(1004),
        fiber: getNutrient(1079),
        sugar: getNutrient(2000),
        sodium: getNutrient(1093),
      }
    };
  } catch (e) {
    console.warn(`[USDA] Failed for "${ingredientName}":`, e.message);
    return null;
  }
}

// ── STEP 1b: Fallback to OpenFoodFacts ────────────────────────────────────────
async function fetchOpenFoodFacts(ingredientName) {
  try {
    const url = `${OPFF_BASE}/cgi/search.pl?search_terms=${encodeURIComponent(ingredientName)}&search_simple=1&action=process&json=1&page_size=1`;
    const res = await fetch(url);
    if (!res.ok) throw new Error(`OFF HTTP ${res.status}`);
    const data = await res.json();
    const product = data.products?.[0];
    if (!product) return null;
    const n = product.nutriments || {};
    return {
      source: "openfoodfacts",
      fdc_id: null,
      description: product.product_name || ingredientName,
      nutrition_per_100g: {
        calories: n["energy-kcal_100g"] ?? n["energy_100g"] ?? 0,
        protein: n["proteins_100g"] ?? 0,
        carbs: n["carbohydrates_100g"] ?? 0,
        fat: n["fat_100g"] ?? 0,
        fiber: n["fiber_100g"] ?? 0,
        sugar: n["sugars_100g"] ?? 0,
        sodium: n["sodium_100g"] ? n["sodium_100g"] * 1000 : 0,
      }
    };
  } catch (e) {
    console.warn(`[OpenFoodFacts] Failed for "${ingredientName}":`, e.message);
    return null;
  }
}

// ── STEP 2: Generate ultra-realistic custom icon ──────────────────────────────
async function generateIngredientIcon(base44, ingredientName, category) {
  const categoryContext = {
    proteins: "raw fresh protein food ingredient on white background",
    vegetables: "fresh whole vegetable on white background",
    fruits: "fresh whole fruit on white background",
    dairy: "dairy product on white background",
    grains: "grain or bread product on white background",
    spices: "spice or herb on white background",
    oils_sauces: "sauce or oil bottle/jar on white background",
    canned_goods: "canned or jarred food product on white background",
    frozen: "frozen food ingredient on white background",
    baking: "baking ingredient on white background",
    beverages: "beverage on white background",
    other: "food ingredient on white background",
  }[category] || "food ingredient on white background";

  const prompt = `A single ${ingredientName} ingredient icon in a clean, modern emoji art style. The icon should look like a high-quality food emoji — vibrant colors, soft rounded shapes, slightly stylized but clearly recognizable as the real ingredient. Pure white background, centered, no shadows, no text, no labels, no abstract shapes or circles, no decorative elements. The food item fills most of the frame. Style: between realistic and emoji, similar to Apple/Google food emojis but slightly more detailed. 512x512.`;

  try {
