// ── MAIN HANDLER ──────────────────────────────────────────────────────────────
Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user) return Response.json({ error: 'Unauthorized' }, { status: 401 });

    const body = await req.json();
    const { ingredient_name, category = "other" } = body;

    if (!ingredient_name?.trim()) {
      return Response.json({ error: 'ingredient_name is required' }, { status: 400 });
    }

    const name = ingredient_name.trim();
    console.log(`[3-Step] Starting pipeline for: "${name}" (${category})`);

    // ── STEP 1: Fetch nutrition ───────────────────────────────────────────────
    console.log(`[Step 1] Fetching nutrition for "${name}"...`);
    let nutrition = await fetchUSDANutrition(name);
    if (!nutrition) {
      console.log(`[Step 1] USDA miss — trying OpenFoodFacts...`);
      nutrition = await fetchOpenFoodFacts(name);
    }
    const nutritionData = nutrition || {
      source: "estimated",
      fdc_id: null,
      description: name,
      nutrition_per_100g: { calories: 0, protein: 0, carbs: 0, fat: 0, fiber: 0, sugar: 0, sodium: 0 }
