    console.log(`[Step 2] ✓ Icon generated: ${iconUrl.slice(0, 60)}...`);

    // ── STEP 3: Return enriched ingredient ready to save ─────────────────────
    console.log(`[Step 3] ✓ Returning enriched ingredient for "${name}"`);
    return Response.json({
      ok: true,
