    return Response.json({ error: error.message }, { status: 500 });
  }
});

/**
 * invalidateRecipePricingOnUpdate
 * 
 * Triggered by entity automation when a Recipe is updated.
 * Deletes the cached RecipePricingSummary so next load recomputes fresh pricing.
 * Only runs when ingredients or servings fields change.
 */
import { createClientFromRequest } from 'npm:@base44/sdk@0.8.25';

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const payload = await req.json();

    const recipeId = payload?.event?.entity_id;
    const changedFields = payload?.changed_fields || [];

    if (!recipeId) {
      return Response.json({ skipped: true, reason: 'no entity_id' });
    }

    // SURGICAL INVALIDATION: Only invalidate if fields that ACTUALLY affect pricing changed.
    // title, description, steps, tags, image, likes, saves, reviews, moderation = NEVER invalidate.
    const PRICING_RELEVANT_FIELDS = new Set(['ingredients', 'servings', 'pricing_currency']);
    const hasPricingChange = changedFields.some(f => PRICING_RELEVANT_FIELDS.has(f));

    if (!hasPricingChange) {
      // COST SAVING: Skip entirely — no DB reads, no deletes
      return Response.json({ skipped: true, reason: 'no pricing-relevant fields changed', changedFields });
    }

    // Find and delete the cached pricing summary for this recipe
    const summaries = await base44.asServiceRole.entities.RecipePricingSummary.filter({
      recipe_id: recipeId,
    }).catch(() => []);

    if (summaries.length === 0) {
      return Response.json({ skipped: true, reason: 'no cached summary found' });
    }

    await Promise.all(
      summaries.map(s => base44.asServiceRole.entities.RecipePricingSummary.delete(s.id).catch(() => {}))
    );

    console.log(`[invalidateRecipePricingOnUpdate] Deleted ${summaries.length} pricing summary(s) for recipe ${recipeId}`);

    return Response.json({ invalidated: true, recipe_id: recipeId, deleted_count: summaries.length });
  } catch (error) {
    console.error('[invalidateRecipePricingOnUpdate] Error:', error);
    return Response.json({ error: error.message }, { status: 500 });
  }
});

