/**
 * logBackendError — Captures backend failures to BackendErrorLog entity.
 * Called from other backend functions when they catch errors.
 * Also callable from frontend for client-side error capture.
 *
 * Payload: { function_name, error_category, error_message, page_surface?, severity?,
 *            normalized_reason?, stack_trace?, request_context?, fallback_used?,
 *            fallback_succeeded?, retry_count?, retry_succeeded? }
 */
import { createClientFromRequest } from 'npm:@base44/sdk@0.8.23';

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const payload = await req.json();

    if (!payload.function_name || !payload.error_message) {
      return Response.json({ error: 'Missing function_name or error_message' }, { status: 400 });
    }

    // Classify error category if not provided
    let category = payload.error_category || 'unknown';
    const msg = (payload.error_message || '').toLowerCase();
    if (category === 'unknown') {
      if (msg.includes('rate limit')) category = 'rate_limit';
      else if (msg.includes('unauthorized') || msg.includes('401')) category = 'auth_failure';
      else if (msg.includes('timeout') || msg.includes('timed out')) category = 'query_timeout';
      else if (msg.includes('network') || msg.includes('fetch failed')) category = 'network_error';
      else if (msg.includes('null') || msg.includes('undefined')) category = 'null_reference';
      else if (msg.includes('permission') || msg.includes('forbidden') || msg.includes('403')) category = 'permission_mismatch';
    }

    // Try to get user context (non-blocking)
    let userId = payload.user_id || null;
    if (!userId) {
      try {
        const user = await base44.auth.me();
        userId = user?.id || null;
      } catch { /* anonymous ok */ }
    }

    // Truncate stack trace for safety (max 2000 chars)
    const stackTrace = payload.stack_trace ? payload.stack_trace.substring(0, 2000) : null;

    // Truncate request context (max 1000 chars)
    const requestContext = payload.request_context
      ? (typeof payload.request_context === 'string' 
          ? payload.request_context.substring(0, 1000) 
          : JSON.stringify(payload.request_context).substring(0, 1000))
      : null;

    const record = await base44.asServiceRole.entities.BackendErrorLog.create({
      timestamp: new Date().toISOString(),
      user_id: userId,
      page_surface: payload.page_surface || null,
      function_name: payload.function_name,
      error_category: category,
      severity: payload.severity || 'error',
      error_message: payload.error_message.substring(0, 500),
      normalized_reason: payload.normalized_reason || null,
      stack_trace: stackTrace,
      request_context: requestContext,
      fallback_used: payload.fallback_used || false,
      fallback_succeeded: payload.fallback_succeeded || false,
      retry_count: payload.retry_count || 0,
      retry_succeeded: payload.retry_succeeded || false,
      resolved: false,
    });

    return Response.json({ success: true, id: record.id });
  } catch (err) {
    // Last resort — never fail the error logger itself
    console.error('[logBackendError] SELF-ERROR:', err.message);
    return Response.json({ error: err.message }, { status: 500 });
  }
});

