/**
 * logMealAndUpdateInventory
 *
 * OPTIMIZED for speed:
 * 1. Creates MealLog quickly (priority)
 * 2. Deducts pantry items best-effort (non-blocking)
 * 3. Returns success immediately even if deductions fail
 */
import { createClientFromRequest } from 'npm:@base44/sdk@0.8.21';

function parseAmount(amountStr) {
  if (!amountStr) return null;
  const s = String(amountStr).trim();
  const fracMatch = s.match(/^(\d+)\s*\/\s*(\d+)$/);
  if (fracMatch) return parseInt(fracMatch[1]) / parseInt(fracMatch[2]);
  const mixedMatch = s.match(/^(\d+)\s+(\d+)\s*\/\s*(\d+)$/);
  if (mixedMatch) return parseInt(mixedMatch[1]) + parseInt(mixedMatch[2]) / parseInt(mixedMatch[3]);
  const numUnitMatch = s.match(/^([\d.]+)\s*([a-zA-Z]*)/);
  if (numUnitMatch) return parseFloat(numUnitMatch[1]) || null;
  return null;
}

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user) return Response.json({ error: 'Unauthorized' }, { status: 401 });

    const body = await req.json();
    const {
      meal_log_data,
      ingredient_deductions = [],
      pantry_item_ids_to_skip = [],
    } = body;

    if (!meal_log_data) return Response.json({ error: 'meal_log_data is required' }, { status: 400 });

    // PRIORITY: Create MealLog immediately
    const mealLog = await base44.entities.MealLog.create({
      ...meal_log_data,
      user_id: user.id,
    });

    // ASYNC: Deduct pantry items in background (fire and forget)
    // Don't await — return success to user immediately
    const skipSet = new Set(pantry_item_ids_to_skip || []);

    (async () => {
      try {
        for (const deduction of ingredient_deductions) {
          const { pantry_item_id, deduct_amount } = deduction;
          if (!pantry_item_id || !deduct_amount || deduct_amount <= 0) continue;
          if (skipSet.has(pantry_item_id)) continue;

          try {
            const items = await base44.entities.PantryItem.filter({
              id: pantry_item_id,
              created_by: user.email,
            });
            const item = items[0];
            if (!item) continue;

            const currentQty = parseFloat(item.quantity) || 0;
            const newQty = Math.max(0, currentQty - deduct_amount);
            await base44.entities.PantryItem.update(pantry_item_id, { quantity: newQty });
          } catch (err) {
            console.warn(`[logMeal] deduction failed for ${pantry_item_id}:`, err.message);
          }
        }
      } catch (err) {
        console.warn('[logMeal] background deduction error:', err.message);
      }
    })();

    return Response.json({
      ok: true,
      meal_log_id: mealLog.id,
    });

  } catch (error) {
    console.error('[logMealAndUpdateInventory] error:', error.message);
    return Response.json({ error: error.message }, { status: 500 });
  }
});

