            cook_time: generatedRecipe.cook_time || 0,
            prep_time: generatedRecipe.prep_time || 0,
            difficulty: generatedRecipe.difficulty,
            servings: generatedRecipe.servings || 2,
            ingredients: normalizedIngredients,
            steps: (generatedRecipe.steps || []).map((s, i) => ({
              step_number: i + 1,
              instruction: s.instruction,
              timer_minutes: s.timer_minutes || 0,
            })),
            hero_image_url: generatedRecipe.hero_image_url,
            is_public: false,
            source: 'generated',
            author_id: user.id,
            author_name: user.full_name || user.email,
