/**
 * logSystemEvent — Centralized cost/usage event logger.
 *
 * Every cost-producing code path MUST call this function.
 * Logs ALL available evidence. NEVER estimates monetary cost.
 *
 * If exact cost is unavailable, raw_cost_source = "COST_DATA_UNAVAILABLE"
 * but all other evidence fields (provider, model, tokens, etc.) are still recorded.
 *
 * Can be called fire-and-forget (non-blocking) or awaited.
 */
import { createClientFromRequest } from 'npm:@base44/sdk@0.8.25';

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const payload = await req.json();

    const {
      // Required
      event_type,
      source,
      endpoint_name,
      origin = 'backend',
      provider_name,
      success = true,
      // Optional evidence
      user_id = null,
      allowed_scope = 'allowed',
      model_name = null,
      request_type = null,
      token_input = null,
      token_output = null,
      provider_request_id = null,
      provider_response_id = null,
