/**
 * manageGroupRoles — CRUD for custom group roles + assign/unassign roles to members.
 *
 * Actions:
 *   create_role:  { group_id, name, emoji?, color?, permissions? }
 *   update_role:  { group_id, role_id, name?, emoji?, color?, permissions? }
 *   delete_role:  { group_id, role_id }
 *   assign_role:  { group_id, user_id, role_id }  (null role_id = unassign)
 *   list_roles:   { group_id }
 *
 * Only group owner can manage roles (system role = 'owner').
 * Owner always retains crown regardless of custom role assignment.
 */
import { createClientFromRequest } from 'npm:@base44/sdk@0.8.25';

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user) return Response.json({ error: 'Unauthorized' }, { status: 401 });

    const body = await req.json();
    const { action, group_id } = body;

    if (!group_id || !action) {
      return Response.json({ error: 'group_id and action required' }, { status: 400 });
    }

    const sr = base44.asServiceRole;

    // Verify caller is the group owner
    const members = await sr.entities.GroupMember.filter({ group_id, user_id: user.id });
    const callerMember = members[0];
    if (!callerMember || callerMember.role !== 'owner') {
      return Response.json({ error: 'Only the group owner can manage roles' }, { status: 403 });
    }

    // ── LIST ROLES ──────────────────────────────────────────────────────────────
    if (action === 'list_roles') {
      const roles = await sr.entities.GroupRole.filter({ group_id });
      return Response.json({ roles: roles.sort((a, b) => (a.sort_order || 0) - (b.sort_order || 0)) });
    }

    // ── CREATE ROLE ─────────────────────────────────────────────────────────────
    if (action === 'create_role') {
      const { name, emoji, color, permissions } = body;
      if (!name || name.trim().length < 1 || name.trim().length > 30) {
        return Response.json({ error: 'Role name must be 1-30 characters' }, { status: 400 });
      }

      // Max 10 custom roles per group
      const existing = await sr.entities.GroupRole.filter({ group_id });
      if (existing.length >= 10) {
        return Response.json({ error: 'Maximum 10 custom roles per group' }, { status: 400 });
      }

      const role = await sr.entities.GroupRole.create({
        group_id,
        name: name.trim(),
        emoji: emoji || null,
        color: color || '#6366f1',
        sort_order: existing.length,
        permissions: {
          can_manage_members: permissions?.can_manage_members || false,
          can_delete_messages: permissions?.can_delete_messages || false,
          can_post_announcements: permissions?.can_post_announcements || false,
          can_edit_group_info: permissions?.can_edit_group_info || false,
          can_manage_roles: permissions?.can_manage_roles || false,
        },
      });

      return Response.json({ success: true, role });
    }

    // ── UPDATE ROLE ─────────────────────────────────────────────────────────────
    if (action === 'update_role') {
      const { role_id, name, emoji, color, permissions } = body;
      if (!role_id) return Response.json({ error: 'role_id required' }, { status: 400 });

      const updates = {};
      if (name !== undefined) updates.name = name.trim();
      if (emoji !== undefined) updates.emoji = emoji;
      if (color !== undefined) updates.color = color;
      if (permissions !== undefined) updates.permissions = permissions;

      await sr.entities.GroupRole.update(role_id, updates);

      // Denormalize: update all members who have this role
      const membersWithRole = await sr.entities.GroupMember.filter({ group_id, custom_role_id: role_id });
      for (const m of membersWithRole) {
        const denorm = {};
        if (updates.name !== undefined) denorm.custom_role_name = updates.name;
        if (updates.emoji !== undefined) denorm.custom_role_emoji = updates.emoji;
        if (updates.color !== undefined) denorm.custom_role_color = updates.color;
        await sr.entities.GroupMember.update(m.id, denorm).catch(() => {});
      }

      return Response.json({ success: true });
    }

    // ── DELETE ROLE ──────────────────────────────────────────────────────────────
    if (action === 'delete_role') {
      const { role_id } = body;
      if (!role_id) return Response.json({ error: 'role_id required' }, { status: 400 });

      // Unassign from all members first
      const membersWithRole = await sr.entities.GroupMember.filter({ group_id, custom_role_id: role_id });
      for (const m of membersWithRole) {
        await sr.entities.GroupMember.update(m.id, {
          custom_role_id: null,
          custom_role_name: null,
          custom_role_emoji: null,
          custom_role_color: null,
        }).catch(() => {});
      }

      await sr.entities.GroupRole.delete(role_id);
      return Response.json({ success: true });
    }

    // ── REORDER ROLES ──────────────────────────────────────────────────────────
    if (action === 'reorder_roles') {
      const { ordered_role_ids } = body;
      if (!Array.isArray(ordered_role_ids)) {
        return Response.json({ error: 'ordered_role_ids array required' }, { status: 400 });
      }
      for (let i = 0; i < ordered_role_ids.length; i++) {
        await sr.entities.GroupRole.update(ordered_role_ids[i], { sort_order: i }).catch(() => {});
      }
      return Response.json({ success: true });
    }

    // ── ASSIGN ROLE ─────────────────────────────────────────────────────────────
    if (action === 'assign_role') {
      const { user_id: targetUserId, role_id } = body;
      if (!targetUserId) return Response.json({ error: 'user_id required' }, { status: 400 });

      const targetMembers = await sr.entities.GroupMember.filter({ group_id, user_id: targetUserId });
      const target = targetMembers[0];
      if (!target) return Response.json({ error: 'User is not a member' }, { status: 404 });

      if (role_id) {
        // Assign custom role
        const roles = await sr.entities.GroupRole.filter({ group_id });
        const customRole = roles.find(r => r.id === role_id);
        if (!customRole) return Response.json({ error: 'Role not found' }, { status: 404 });

        await sr.entities.GroupMember.update(target.id, {
          custom_role_id: role_id,
          custom_role_name: customRole.name,
          custom_role_emoji: customRole.emoji || null,
          custom_role_color: customRole.color || null,
        });
      } else {
        // Unassign
        await sr.entities.GroupMember.update(target.id, {
          custom_role_id: null,
          custom_role_name: null,
          custom_role_emoji: null,
          custom_role_color: null,
        });
      }

      return Response.json({ success: true });
    }

    return Response.json({ error: `Unknown action: ${action}` }, { status: 400 });
  } catch (error) {
    console.error('[manageGroupRoles]', error.message);
    return Response.json({ error: error.message }, { status: 500 });
  }
});

/**
 * manageReview — backend-authoritative review CRUD with moderation.
 * Actions: create | edit | delete
 * Rules:
 *  - 1 review per user per recipe (enforced on create)
 *  - Stars locked after creation (edit updates text only)
 *  - Only review owner can edit/delete
 *  - Self-review blocked
 *  - Moderation blocks explicit/sexual/18+ content before save
 *  - Sends notification to recipe owner on create
 *  - Updates recipe avg_rating + review_count aggregates atomically
 */
import { createClientFromRequest } from 'npm:@base44/sdk@0.8.23';

const _RPROF = ['fuck','fuk','fck','sex','porn','pussy','cock','dick','ass','asshole','bastard','bitch','blowjob','cumshot','dildo','masturbat','orgasm','anal','rape','horny','nigger','nigga','cunt','whore','slut','shit','piss','jerkoff','jerk off','incest','pedophil','bestiality'];
const _RSAFE = ['chicken breast','cock-a-leekie','cocktail','bloody mary','sex on the beach','slippery nipple','spotted dick','duck','asparagus','arugula','eggplant','shallot'];

function moderateText(text) {
  if (!text) return { allowed: true };
  const trimmed = text.trim();
  if (!trimmed) return { allowed: true };
  const lower = trimmed.toLowerCase();
  if (_RSAFE.some(s => lower.includes(s))) return { allowed: true };
  let n = lower.replace(/0/g,'o').replace(/1/g,'i').replace(/3/g,'e').replace(/4/g,'a')
               .replace(/5/g,'s').replace(/7/g,'t').replace(/8/g,'b').replace(/9/g,'g')
               .replace(/\*/g,'').replace(/@/g,'a').replace(/\$/g,'s').replace(/!/g,'i')
               .replace(/\|/g,'i').replace(/\./g,'').replace(/-/g,'').replace(/_/g,'')
               .replace(/\^/g,'a').replace(/~/g,'').replace(/\+/g,'').replace(/%/g,'');
  n = n.replace(/(.)\1{2,}/g,'$1').replace(/\d+/g,'');
  const flat = n.replace(/\s/g,'');
  for (const w of _RPROF) {
    const re = new RegExp(`\\b${w.replace(/[.*+?^${}()|[\]\\]/g,'\\$&')}`,'i');
    if (re.test(n) || flat.includes(w)) {
      return { allowed: false, reason_code: 'EXPLICIT_CONTENT', user_message: 'Your review contains inappropriate language and couldn\'t be posted.' };
    }
  }
  return { allowed: true };
}

/**
 * Recompute and persist avg_rating + review_count on the Recipe entity.
 * Also updates UserAggregates (total_ratings_received) for the recipe author.
 * Always called after create or delete.
 */
async function updateRecipeAggregates(sr, recipe_id) {
  try {
    const allReviews = await sr.entities.RecipeReview.filter({ recipe_id });
    const count = allReviews.length;
    const avg = count > 0
      ? allReviews.reduce((sum, r) => sum + (r.rating || 0), 0) / count
      : 0;
    const roundedAvg = Math.round(avg * 10) / 10;

    // SEEDED-DEMO PROTECTION: For demo recipes (is_seed_demo=true), the recipe
    // ships with a curated review_count + avg_rating that represents historical
    // engagement. Real review records added on top should NEVER lower these
    // numbers. We take the MAX of (current value, computed value) so seeded
    // counts are preserved while real review activity can still grow them.
    const recipeRows = await sr.entities.Recipe.filter({ id: recipe_id }).catch(() => []);
    const currentRecipe = recipeRows[0];
    const isSeedDemo = currentRecipe?.is_seed_demo === true;

    let finalCount = count;
    let finalAvg = roundedAvg;
    if (isSeedDemo) {
      const seededCount = currentRecipe.review_count || 0;
      const seededAvg = currentRecipe.avg_rating || 0;
      // Never go below the seeded baseline
      finalCount = Math.max(seededCount, count);
      finalAvg = count > seededCount ? roundedAvg : seededAvg;
    }

    await sr.entities.Recipe.update(recipe_id, {
      review_count: finalCount,
      avg_rating: finalAvg,
    });

    // Update UserAggregates for the recipe author
    const recipes = await sr.entities.Recipe.filter({ id: recipe_id }).catch(() => []);
    const recipe = recipes[0];
    if (!recipe?.author_id) return;

    // Sum ALL ratings received across ALL the author's recipes
    const authorRecipes = await sr.entities.Recipe.filter({ author_id: recipe.author_id }).catch(() => []);
    const totalRatings = authorRecipes.reduce((sum, r) => sum + (r.review_count || 0), 0);
    const allRatings = authorRecipes.map(r => ({ avg: r.avg_rating || 0, count: r.review_count || 0 }));
    const totalRatingSum = allRatings.reduce((sum, r) => sum + r.avg * r.count, 0);
    const overallAvg = totalRatings > 0 ? Math.round((totalRatingSum / totalRatings) * 10) / 10 : 0;

    const computeVipTier = (n) => {
      if (n >= 50000) return 'mythic';
      if (n >= 10000) return 'legend';
      if (n >= 5000) return 'elite_chef';
      if (n >= 1000) return 'pro_creator';
      if (n >= 500) return 'community_favorite';
      if (n >= 100) return 'trusted_cook';
      if (n >= 50) return 'rising_chef';
      return 'starter_chef';
    };

    const existing = await sr.entities.UserAggregates.filter({ user_id: recipe.author_id }).catch(() => []);
    const aggData = {
      user_id: recipe.author_id,
      total_ratings_received: totalRatings,
      avg_rating: overallAvg,
      vip_tier: computeVipTier(totalRatings),
      updated_at: new Date().toISOString(),
    };
    if (existing[0]) {
      await sr.entities.UserAggregates.update(existing[0].id, aggData).catch(() => {});
    } else {
      await sr.entities.UserAggregates.create(aggData).catch(() => {});
    }
  } catch (err) {
    console.error('[manageReview] updateRecipeAggregates failed:', err.message);
  }
}

/**
 * Send a notification to the recipe owner when someone reviews their recipe.
 */
async function sendReviewNotification(sr, { recipe, reviewer, rating, review_text }) {
  try {
    if (!recipe?.author_id || recipe.author_id === reviewer.id) return;
    const snippet = review_text?.trim().slice(0, 60) || '';
    const starLabel = rating ? `${rating}-star ` : '';
    await sr.entities.Notification.create({
      type: 'rating',
      title: `${reviewer.full_name || 'Someone'} left a ${starLabel}review`,
      message: snippet ? `"${snippet}${snippet.length >= 60 ? '…' : ''}"` : `on your recipe: ${recipe.title || ''}`,
      from_user_id: reviewer.id,
      from_user_name: reviewer.full_name || reviewer.email?.split('@')[0] || 'Someone',
      from_user_avatar: reviewer.avatar_url || '',
      recipe_id: recipe.id,
      recipient_id: recipe.author_id,
      is_read: false,
    });
  } catch (err) {
    console.error('[manageReview] sendReviewNotification failed:', err.message);
  }
}

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user?.id) return Response.json({ error: 'Unauthorized' }, { status: 401 });

    const body = await req.json();
    const { action, recipe_id, review_id, rating, review_text, image_url } = body;

    const sr = base44.asServiceRole;

    // ── CREATE ──────────────────────────────────────────────────────────────
    if (action === 'create') {
      if (!recipe_id) return Response.json({ error: 'recipe_id required' }, { status: 400 });
      if (!rating || rating < 1 || rating > 5) return Response.json({ error: 'rating 1-5 required' }, { status: 400 });
      if (!review_text?.trim() || review_text.trim().length < 5) {
        return Response.json({ error: 'Review text must be at least 5 characters' }, { status: 400 });
      }

      // NOTE: has_reviewed flag on User is advisory only — actual duplicate check
      // is done below via RecipeReview query per recipe. The flag may be stale after deletes.

      // Moderation before save
      const mod = moderateText(review_text);
      if (!mod.allowed) {
        return Response.json({ error: mod.user_message, code: mod.reason_code }, { status: 400 });
      }

      // Fetch recipe — needed for self-review check and notification
      const recipes = await sr.entities.Recipe.filter({ id: recipe_id });
      if (!recipes.length) return Response.json({ error: 'Recipe not found' }, { status: 404 });
      const recipe = recipes[0];

      // Block self-review
      if (recipe.author_id === user.id || recipe.created_by === user.email) {
        return Response.json({ error: "You can't review your own recipe.", code: 'SELF_REVIEW' }, { status: 403 });
      }

      // Enforce 1 review per user per recipe — author_id is the ONLY reliable field
      // (created_by is the service account email when written via asServiceRole, not the user's email)
      const existingByAuthor = await sr.entities.RecipeReview.filter({ recipe_id, author_id: user.id });
      if (existingByAuthor.length > 0) {
        return Response.json({
          error: 'You already gave a review on this recipe.',
          code: 'ALREADY_REVIEWED',
          existing_review_id: existingByAuthor[0].id,
        }, { status: 409 });
      }

      const review = await sr.entities.RecipeReview.create({
        recipe_id,
        rating,
        review_text: review_text.trim(),
        image_url: image_url || null,
        author_name: user.full_name || user.email?.split('@')[0] || 'Anonymous',
        author_avatar: user.avatar_url || '',
        author_id: user.id,
      });

      // Update recipe aggregates + send notification + mark user as reviewed (non-blocking)
      await Promise.all([
        updateRecipeAggregates(sr, recipe_id),
        sendReviewNotification(sr, { recipe, reviewer: user, rating, review_text }),
        sr.entities.User.update(user.id, { has_reviewed: true }).catch(err => {
          console.error('[manageReview] Failed to set has_reviewed on user:', err.message);
        }),
      ]);

      return Response.json({ ok: true, review });
    }

    // ── EDIT (text only — stars locked) ─────────────────────────────────────
    if (action === 'edit') {
      if (!review_id) return Response.json({ error: 'review_id required' }, { status: 400 });
      if (!review_text?.trim() || review_text.trim().length < 5) {
        return Response.json({ error: 'Review text must be at least 5 characters' }, { status: 400 });
      }

      const mod = moderateText(review_text);
      if (!mod.allowed) {
        return Response.json({ error: mod.user_message, code: mod.reason_code }, { status: 400 });
      }

      const reviews = await sr.entities.RecipeReview.filter({ id: review_id });
      if (!reviews.length) return Response.json({ error: 'Review not found' }, { status: 404 });
      const review = reviews[0];
      if (review.created_by !== user.email && review.author_id !== user.id) {
        return Response.json({ error: 'Not authorized to edit this review' }, { status: 403 });
      }

      const updated = await sr.entities.RecipeReview.update(review_id, {
        review_text: review_text.trim(),
      });

      return Response.json({ ok: true, review: updated });
    }

    // ── DELETE ───────────────────────────────────────────────────────────────
    if (action === 'delete') {
      if (!review_id) return Response.json({ error: 'review_id required' }, { status: 400 });

      const reviews = await sr.entities.RecipeReview.filter({ id: review_id });
      if (!reviews.length) return Response.json({ error: 'Review not found' }, { status: 404 });
      const review = reviews[0];
      if (review.created_by !== user.email && review.author_id !== user.id) {
        return Response.json({ error: 'Not authorized to delete this review' }, { status: 403 });
      }

      const recipeIdForAgg = review.recipe_id;
      await sr.entities.RecipeReview.delete(review_id);

      // Check if user has any remaining reviews — if not, clear has_reviewed flag
      const remainingReviews = await sr.entities.RecipeReview.filter({ author_id: user.id }).catch(() => []);
      if (remainingReviews.length === 0) {
        await sr.entities.User.update(user.id, { has_reviewed: false }).catch(err => {
          console.error('[manageReview] Failed to clear has_reviewed:', err.message);
        });
      }

      // Update aggregates after delete
      if (recipeIdForAgg) await updateRecipeAggregates(sr, recipeIdForAgg);

      return Response.json({ ok: true, deleted: true, has_remaining_reviews: remainingReviews.length > 0 });
    }

    return Response.json({ error: 'Invalid action' }, { status: 400 });

  } catch (error) {
    console.error('[manageReview] error:', error.message);
    return Response.json({ error: error.message }, { status: 500 });
  }
});

import { createClientFromRequest } from 'npm:@base44/sdk@0.8.23';

/**
 * Marks all unread activity notifications as read.
 * SOURCE OF TRUTH: Notification entity is_read flag.
 * Called when user dismisses the entry popup or opens the Notifications page.
 */
Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();

    if (!user?.id) {
      return Response.json({ error: 'Unauthorized' }, { status: 401 });
    }

    const body = await req.json().catch(() => ({}));
    const { markLikes = false, markFollowers = false, markReviews = false, markMentions = false, markAll = false } = body;

    const sr = base44.asServiceRole;

    // Fetch all unread active notifications for this user
    const unread = await sr.entities.Notification.filter({
      recipient_id: user.id,
      is_read: false,
      is_active: true,
    });

    const toMark = [];

    for (const n of unread) {
      if (n.from_user_id === user.id) continue;
      if (n.type === 'moderation') continue;

      let shouldMark = markAll;
      if (!shouldMark) {
        if (markLikes && (n.type === 'like' || n.type === 'save')) shouldMark = true;
        if (markFollowers && (n.type === 'follow' || n.type === 'follow_request' || n.type === 'follow_accepted')) shouldMark = true;
        if (markReviews && n.type === 'rating') shouldMark = true;
        if (markMentions && n.type === 'app') {
          try {
            const p = n.payload_json ? JSON.parse(n.payload_json) : {};
            if (p.mention) shouldMark = true;
          } catch { /* skip */ }
        }
      }
      if (shouldMark) toMark.push(n.id);
    }

    // Batch mark as read
    await Promise.all(toMark.map(id => sr.entities.Notification.update(id, { is_read: true })));

    return Response.json({
      success: true,
      markedCount: toMark.length,
