import { createClientFromRequest } from 'npm:@base44/sdk@0.8.25';

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user) return Response.json({ error: 'Unauthorized' }, { status: 401 });

    const { message_id } = await req.json();
    if (!message_id) return Response.json({ error: 'Missing message_id' }, { status: 400 });

    const sr = base44.asServiceRole.entities;

    const reactions = await sr.MessageReaction.filter(
      { message_id },
      'created_date',
      200
    );

    // Deduplicate: keep only the FIRST reaction per user+emoji combo
    const seenKeys = new Set();
    const deduped = [];
    for (const r of reactions) {
      const key = `${r.user_id}:${r.emoji}`;
      if (seenKeys.has(key)) {
        // Delete the duplicate silently
        sr.MessageReaction.delete(r.id).catch(() => {});
        continue;
      }
      seenKeys.add(key);
      deduped.push(r);
    }

    // Group by emoji
    const grouped = {};
    for (const reaction of deduped) {
      if (!grouped[reaction.emoji]) {
        grouped[reaction.emoji] = [];
      }
      grouped[reaction.emoji].push({
        user_id: reaction.user_id,
        created_at: reaction.created_date,
      });
    }

    // Batch-fetch user info (parallel, not sequential)
    // Use .get() instead of .filter({id}) — id is a built-in field, filter may not match it
    const userIds = [...new Set(deduped.map(r => r.user_id))];
    const userResults = await Promise.all(
      userIds.map(uid => sr.User.get(uid).catch(() => null))
    );

    const users = {};
    userResults.forEach((u, i) => {
      if (u) {
        users[userIds[i]] = {
          id: userIds[i],
          display_name: u.display_name || u.full_name || u.username || null,
          full_name: u.full_name || null,
          name: u.display_name || u.full_name || u.username || null,
          avatar_url: u.avatar_url || null,
          avatar: u.avatar_url || null,
        };
      }
    });

    return Response.json({ grouped, users });
  } catch (error) {
    console.error('[messageReactionsGet]', error);
    return Response.json({ error: error.message }, { status: 500 });
  }
});

