/**
 * midnightStreakCheck — Scheduled function that runs every 30 minutes.
 * 
 * For each user with an active streak, checks whether their LOCAL time has
 * crossed midnight into a new day where they have no action logged.
 * If the gap is >1 day, marks the streak as broken with pending_break_popup.
 *
 * This ensures streaks break at exactly 12:00 AM in each user's timezone,
 * not whenever they next open the app.
 *
 * Also respects admin_set_at protection (24h window).
 */
import { createClientFromRequest } from 'npm:@base44/sdk@0.8.23';

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (user?.role !== 'admin') {
      return Response.json({ error: 'Forbidden: Admin access required' }, { status: 403 });
    }

    const sr = base44.asServiceRole;
    const now = new Date();

    // Fetch all active/restored streaks with days > 0
    // These are the only ones that CAN break
    const activeStreaks = await sr.entities.StreakState.filter({
      streak_status: 'active',
    });
    const restoredStreaks = await sr.entities.StreakState.filter({
      streak_status: 'restored',
    });
    const allStreaks = [...activeStreaks, ...restoredStreaks].filter(
      s => s.current_streak_days > 0 && s.last_streak_action_date_local
    );

    let processed = 0;
    let broken = 0;
    let skippedAdmin = 0;
    let skippedOk = 0;

    for (const streak of allStreaks) {
      processed++;

      // Admin protection: skip if admin modified within last 24h
      const adminSetAt = streak.admin_set_at ? new Date(streak.admin_set_at) : null;
      if (adminSetAt && (now.getTime() - adminSetAt.getTime()) < 24 * 60 * 60 * 1000) {
        skippedAdmin++;
        continue;
      }

      // Resolve timezone
      const tz = streak.user_timezone || 'UTC';

      // Get today's date in user's local timezone
      const todayLocal = now.toLocaleDateString('en-CA', { timeZone: tz });

      // CRITICAL FIX: Parse dates as UTC noon to avoid DST/timezone shift artifacts
      const lastDate = new Date(streak.last_streak_action_date_local + 'T12:00:00Z');
      const today = new Date(todayLocal + 'T12:00:00Z');
      const daysDiff = Math.round((today.getTime() - lastDate.getTime()) / (1000 * 60 * 60 * 24));

      if (daysDiff > 1) {
        // Streak is broken — user missed at least 1 full day
        const prevDays = streak.current_streak_days || 0;
        await sr.entities.StreakState.update(streak.id, {
          streak_status: 'broken',
          pending_break_popup: true,
          previous_streak_days: prevDays,
          current_streak_days: 0,
          updated_at: now.toISOString(),
        });
        broken++;
        console.log(`[midnightStreakCheck] BROKEN: user=${streak.user_id} tz=${tz} lastAction=${streak.last_streak_action_date_local} today=${todayLocal} daysDiff=${daysDiff} prevDays=${prevDays}`);
      } else {
        skippedOk++;
      }
    }

    console.log(`[midnightStreakCheck] Done: processed=${processed} broken=${broken} skippedAdmin=${skippedAdmin} ok=${skippedOk}`);

    return Response.json({
      ok: true,
      processed,
      broken,
      skippedAdmin,
      skippedOk,
      timestamp: now.toISOString(),
    });
  } catch (error) {
    console.error('[midnightStreakCheck]', error);
    return Response.json({ error: error.message }, { status: 500 });
  }
});

/**
 * Migration function: steps_he → steps_translations.he
 * 
 * Handles backward compatibility for recipes with old steps_he field.
 * When recipes are fetched or updated, this ensures steps_he is migrated
 * into the new steps_translations structure.
 * 
 * Can be called manually for batch migration or integrated into entity lifecycle.
 */

import { createClientFromRequest } from 'npm:@base44/sdk@0.8.23';

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();

    if (!user?.email) {
      return Response.json({ error: 'Unauthorized' }, { status: 401 });
    }

    // Only admins can trigger migration
    if (user.role !== 'admin') {
      return Response.json({ error: 'Admin access required' }, { status: 403 });
    }

    const { batch_size = 100, dry_run = true } = await req.json();

    // Find all recipes with steps_he but no steps_translations.he
    const recipesWithStepsHe = await base44.asServiceRole.entities.Recipe.filter(
      { steps_he: { $exists: true, $ne: [] } },
      '-created_date',
      batch_size
    );

    const migratedCount = { success: 0, skipped: 0, failed: 0 };
    const details = [];

    for (const recipe of recipesWithStepsHe) {
      try {
        // Skip if steps_translations.he already exists (double-migration safety)
        if (recipe.steps_translations?.he?.length > 0) {
          migratedCount.skipped++;
          details.push({ id: recipe.id, status: 'skipped', reason: 'steps_translations.he already exists' });
          continue;
        }

        if (!dry_run) {
          // Migrate: move steps_he → steps_translations.he
          const updatedData = {
            ...recipe,
            steps_translations: {
              ...(recipe.steps_translations || {}),
              he: recipe.steps_he
            }
            // steps_he is kept for backward compatibility (not deleted)
          };

          await base44.asServiceRole.entities.Recipe.update(recipe.id, updatedData);
        }

        migratedCount.success++;
        details.push({ id: recipe.id, status: 'migrated' });
      } catch (error) {
        migratedCount.failed++;
        details.push({ id: recipe.id, status: 'failed', error: error.message });
      }
    }

    return Response.json({
      dry_run,
      summary: migratedCount,
      total_found: recipesWithStepsHe.length,
      details: details.slice(0, 10) // Show first 10 for clarity
    });
  } catch (error) {
    return Response.json({ error: error.message }, { status: 500 });
  }
});

