    if (!user) return Response.json({ error: 'Unauthorized' }, { status: 401 });

    const body = await req.json();
    const { image_url, post_type = 'community' } = body;

    if (!image_url) {
      return Response.json({ error: 'image_url required' }, { status: 400 });
    }

    // COST REDUCTION: Skip LLM for known-safe image sources
    const SAFE_DOMAINS = ['unsplash.com', 'images.unsplash.com', 'base44-public', 'together-ai', 'reciply'];
    const urlLower = image_url.toLowerCase();
    if (SAFE_DOMAINS.some(d => urlLower.includes(d))) {
      return Response.json({ safe: true, violations: [], confidence: 0, reason: 'trusted source — skipped' });
    }
    // Skip AI-generated recipe images (our own pipeline)
    if (urlLower.includes('generated') && urlLower.includes('recipe')) {
      return Response.json({ safe: true, violations: [], confidence: 0, reason: 'internal generated image — skipped' });
    }

    // COST POLICY GUARD
    const policyCheck = await base44.asServiceRole.functions.invoke('costPolicyGuard', {
      event_type: 'llm_call', source: 'moderation', endpoint_name: 'moderateImage',
      user_id: user.id, provider_name: 'Core.InvokeLLM', model_name: 'automatic',
    }).catch(() => ({ data: { allowed: true, mode: 'error_fallback' } }));
    if (policyCheck.data?.allowed === false) {
      // Moderation blocked → fail-open (don't block uploads due to policy)
      console.warn('[moderateImage] Blocked by cost policy — failing open');
      return Response.json({ safe: true, violations: [], confidence: 0, reason: 'cost policy block — allowed', policy_blocked: true });
    }

    let moderationResult;
    const llmStart = Date.now();
    try {
      moderationResult = await base44.integrations.Core.InvokeLLM({
        prompt: MODERATION_PROMPT,
        file_urls: [image_url],
        response_json_schema: {
          type: 'object',
          properties: {
            safe: { type: 'boolean' },
            violations: { type: 'array', items: { type: 'string' } },
            confidence: { type: 'number' },
            reason: { type: 'string' },
          },
          required: ['safe', 'violations', 'confidence', 'reason'],
        },
      });
      const llmDuration = Date.now() - llmStart;

      // LOG: cost event for image moderation LLM call
      base44.asServiceRole.functions.invoke('logSystemEvent', {
        event_type: 'llm_call',
        source: 'moderation',
        endpoint_name: 'moderateImage',
        origin: 'backend',
        allowed_scope: 'review_needed',
        provider_name: 'Core.InvokeLLM',
        model_name: 'automatic',
        request_type: 'vision',
        credits_used: 1,
        raw_cost_source: 'inferred_from_usage',
        user_id: user.id,
        success: true,
        duration_ms: llmDuration,
        raw_usage_metadata: { post_type, has_image: true },
      }).catch(e => console.warn('[moderateImage] log failed:', e.message));
    } catch (llmErr) {
      const llmDuration = Date.now() - llmStart;
      // LOG: failed moderation attempt
      base44.asServiceRole.functions.invoke('logSystemEvent', {
        event_type: 'llm_call',
        source: 'moderation',
        endpoint_name: 'moderateImage',
        origin: 'backend',
        allowed_scope: 'review_needed',
        provider_name: 'Core.InvokeLLM',
        model_name: 'automatic',
        request_type: 'vision',
        credits_used: 0,
        raw_cost_source: 'COST_DATA_UNAVAILABLE',
        user_id: user.id,
        success: false,
        error_code: llmErr.message?.substring(0, 200),
        duration_ms: llmDuration,
      }).catch(() => {});
      // If LLM call fails, log and allow (fail open — don't block all uploads on transient LLM errors)
      console.warn('[moderateImage] LLM call failed, failing open:', llmErr.message);
      return Response.json({
        safe: true,
        violations: [],
        confidence: 0,
        reason: 'moderation check unavailable — allowed',
        moderation_skipped: true,
      });
    }

    const result = moderationResult;
    const isActuallySafe = result.safe === true || result.confidence < 0.75;

    // Log for admin review
    console.log('[moderateImage]', JSON.stringify({
      user_id: user.id,
      post_type,
      image_url: image_url.slice(0, 80),
      safe: result.safe,
      violations: result.violations,
      confidence: result.confidence,
      final_decision: isActuallySafe ? 'ALLOW' : 'BLOCK',
      reason: result.reason,
      ts: new Date().toISOString(),
    }));

    return Response.json({
      safe: isActuallySafe,
      violations: isActuallySafe ? [] : (result.violations || []),
      confidence: result.confidence || 0,
      reason: result.reason || '',
    });
  } catch (err) {
    console.error('[moderateImage] error:', err.message);
    // Fail open on unexpected errors — don't block legitimate posts
    return Response.json({ safe: true, violations: [], confidence: 0, reason: 'error — allowed', error: err.message });
  }
});

/**
 * normalizeIngredient - AI-powered ingredient normalization
 * Maps user text like "2 cups shredded mozzarella" to canonical ingredient
 * NO SPOONACULAR
 */
import { createClientFromRequest } from 'npm:@base44/sdk@0.8.21';

function normalize(s) {
  return (s || "").toLowerCase().trim().replace(/[^a-z0-9\s]/g, "").replace(/\s+/g, " ");
}

Deno.serve(async (req) => {
  if (req.method === "OPTIONS") {
    return new Response(null, { status: 204 });
  }

  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user) return Response.json({ error: "Unauthorized" }, { status: 401 });

    const { text, ingredients } = await req.json();

    // If array of ingredient texts, normalize all
    const inputs = ingredients || (text ? [text] : []);
    if (!inputs.length) return Response.json({ results: [] });

    // Load canonical DB (cached per request)
    const canonicals = await base44.asServiceRole.entities.CanonicalIngredient.filter(
      { is_active: true }, "-popularity_score", 1000
    );

    // Build alias lookup map
    const aliasMap = new Map();
    for (const c of canonicals) {
      const terms = [
        normalize(c.display_name),
        normalize(c.normalized_name),
        ...(c.aliases || []).map(normalize),
        ...(c.plural_forms || []).map(normalize),
        ...(c.common_misspellings || []).map(normalize),
        // Also index slug (dashes replaced with spaces)
        normalize((c.slug || "").replace(/-/g, " ")),
      ];
      for (const term of terms) {
        if (term && !aliasMap.has(term)) {
          aliasMap.set(term, c);
        }
      }
    }

    const results = inputs.map(input => {
      const raw = String(input);
      // Strip quantities and prep words to isolate ingredient name
      const cleaned = raw
        .replace(/^\d+[\d\/\s\.]*/, "") // remove leading numbers
        .replace(/\b(cup|cups|tbsp|tsp|tablespoon|teaspoon|oz|ounce|lb|pound|g|gram|kg|ml|liter|litre|handful|pinch|dash|bunch|clove|cloves|slice|slices|can|cans|jar|jars|package|pkg|medium|large|small|fresh|dried|frozen|cooked|raw|drained|rinsed|chopped|minced|diced|sliced|grated|shredded|peeled|pitted|boneless|skinless|halved|quartered|whole|ground|crushed|packed|heaping|level|rounded)\b/gi, "")
        .replace(/\s+/g, " ")
        .trim();

      const normalizedInput = normalize(cleaned);

      // Exact/alias match
      let canonical = aliasMap.get(normalizedInput);

      // Token match fallback - use longest token first for best specificity
      if (!canonical) {
        const tokens = normalizedInput.split(" ").filter(t => t.length > 3);
        tokens.sort((a, b) => b.length - a.length);
        for (const token of tokens) {
          // Exact key match only (no substring contains — avoids "roma" → "romaine" → wrong)
          if (aliasMap.has(token)) {
            canonical = aliasMap.get(token);
            break;
          }
          // Only match if token is a standalone word in the term (word-boundary safe)
          for (const [term, c] of aliasMap) {
            const termWords = term.split(" ");
            if (termWords[0] === token && token.length >= 5) {
              canonical = c;
              break;
            }
          }
          if (canonical) break;
        }
      }

      // Extract quantity info
      const quantityMatch = raw.match(/^([\d\/\.\s]+)/);
      const quantity = quantityMatch ? quantityMatch[1].trim() : null;

      return {
        original: raw,
        cleaned,
        canonical_id: canonical?.id || null,
        canonical_name: canonical?.display_name || cleaned,
        canonical_slug: canonical?.slug || null,
        category: canonical?.category || "other",
        emoji: canonical?.emoji || "🥄",
        quantity,
        matched: !!canonical,
        confidence: canonical ? "matched" : "unmatched"
      };
    });

    return Response.json({ results });

  } catch (error) {
    console.error("[normalizeIngredient] Error:", error.message);
    return Response.json({ error: error.message }, { status: 500 });
  }
});

/**
 * canSendNotification — ELIGIBILITY ENGINE (MANDATORY)
 * 
 * Enforces ALL delivery rules:
 * - daily limit (max 4)
 * - 2h spacing rule
 * - suppression rules
 * - duplicate prevention
 * - recent-type filtering
 * - activity-based cancellation
 * 
 * Returns: { allowed: boolean, reason: string, priority: integer }
 */

import { createClientFromRequest } from 'npm:@base44/sdk@0.8.23';
import { v4 as uuidv4 } from 'npm:uuid@9.0.1';

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user) return Response.json({ error: 'Unauthorized' }, { status: 401 });

    const body = await req.json();
    const { user_id = user.id, notification_type, context = {} } = body;

    if (!notification_type) {
      return Response.json({ error: 'notification_type required' }, { status: 400 });
    }

    const sr = base44.asServiceRole;
    const now = new Date();
    const today = now.toISOString().split('T')[0]; // YYYY-MM-DD

    // ── PRIORITY MAPPING ──────────────────────────────────────────────────
    const PRIORITY_MAP = {
      'streak_reminder': 1,
      'streak_continued': 1,
      'streak_lost': 1,
      'comment': 2,
      'follow': 2,
      'likes': 2,
      'daily_reminder': 3,
      'cook_mode_return': 3,
      'missing_ingredients': 3,
      'limit_reached': 3,
      'reset': 3,
      'motivation_chef': 4,
      'motivation_save_money': 4,
      'motivation_start_cooking': 4,
    };

    const priority = PRIORITY_MAP[notification_type] || 4;

    // ── FETCH USER PREFS & HISTORY ────────────────────────────────────────
    const prefs = (await sr.entities.UserNotificationPrefs.filter(
      { user_id }, null, 1
    ).catch(() => []))[0] || { notifications_enabled: true, daily_limit: 4, min_spacing_hours: 2 };

    if (!prefs.notifications_enabled) {
      return Response.json({ allowed: false, reason: 'notifications_disabled', priority });
    }

    if (prefs.disabled_types?.includes(notification_type)) {
      return Response.json({ allowed: false, reason: 'type_disabled_by_user', priority });
    }

    // ── FETCH TODAY'S SENT NOTIFICATIONS ──────────────────────────────────
    // Only count SENT + non-cancelled from today (UTC bucket)
    const todayStart = new Date(`${today}T00:00:00Z`);
    const todayEnd = new Date(`${today}T23:59:59Z`);

    const todaysSent = (await sr.entities.NotificationQueue.filter({
      user_id,
      status: { $in: ['sent'] },
      created_date: { $gte: todayStart.toISOString(), $lte: todayEnd.toISOString() }
    }).catch(() => [])) || [];

    const dailyCount = todaysSent.length;

    if (dailyCount >= (prefs.daily_limit || 4)) {
      return Response.json({ allowed: false, reason: 'daily_limit_reached', priority, daily_count: dailyCount });
    }

    // ── CHECK 2H SPACING RULE ─────────────────────────────────────────────
    if (todaysSent.length > 0) {
      const lastSent = new Date(todaysSent[todaysSent.length - 1].sent_at || todaysSent[todaysSent.length - 1].created_date);
      const hoursSinceLastSent = (now.getTime() - lastSent.getTime()) / (1000 * 60 * 60);

      const minSpacing = prefs.min_spacing_hours || 2;
      if (hoursSinceLastSent < minSpacing) {
        return Response.json({
          allowed: false,
          reason: 'spacing_rule_violated',
          hours_until_eligible: Math.ceil(minSpacing - hoursSinceLastSent),
          priority
        });
      }
    }

    // ── CHECK DUPLICATE PREVENTION ────────────────────────────────────────
    // Same notification type can't be sent twice in same day
    const sameTypeToday = todaysSent.filter(n => {
      const nqueue = n; // from NotificationQueue
      return nqueue.notification_type === notification_type;
    });

    if (sameTypeToday.length > 0) {
      return Response.json({
        allowed: false,
        reason: 'same_type_already_sent_today',
        priority
      });
    }

    // ── CHECK QUIET HOURS ─────────────────────────────────────────────────
    // If user has quiet hours set, check current time
    if (prefs.quiet_hours_start && prefs.quiet_hours_end) {
      const userTz = prefs.timezone || 'UTC';
      const formatter = new Intl.DateTimeFormat('en-US', {
        timeZone: userTz,
        hour: '2-digit',
        minute: '2-digit',
        hour12: false,
      });
      const parts = formatter.formatToParts(now);
      const hourStr = parts.find(p => p.type === 'hour')?.value || '00';
      const minStr = parts.find(p => p.type === 'minute')?.value || '00';
      const currentTimeStr = `${hourStr}:${minStr}`;

      // Parse quiet hours
      const [qhStartHour, qhStartMin] = prefs.quiet_hours_start.split(':').map(Number);
      const [qhEndHour, qhEndMin] = prefs.quiet_hours_end.split(':').map(Number);
      const [currHour, currMin] = currentTimeStr.split(':').map(Number);

      const inQuietHours = (() => {
        const qhStart = qhStartHour * 60 + qhStartMin;
        const qhEnd = qhEndHour * 60 + qhEndMin;
        const curr = currHour * 60 + currMin;
        // Handle wrap (e.g., 22:00 to 08:00)
        return qhStart > qhEnd ? curr >= qhStart || curr < qhEnd : curr >= qhStart && curr < qhEnd;
      })();

      if (inQuietHours) {
        return Response.json({ allowed: false, reason: 'quiet_hours_active', priority });
      }
    }

    // ── FINAL CHECK: HIGHEST PRIORITY ONLY ────────────────────────────────
    // If multiple notifications eligible at same time, only highest priority sent
    // This is handled at scheduling time, not eligibility check

    return Response.json({
      allowed: true,
      reason: 'eligible',
      priority,
      daily_count: dailyCount,
      daily_limit: prefs.daily_limit || 4
    });
  } catch (err) {
    console.error('[CanSendNotification] Error:', err.message);
    return Response.json({ allowed: false, reason: 'error', error: err.message }, { status: 500 });
  }
});

/**
 * onLikeCreated — Backend-authoritative notification logic
 * 
 * Called by toggleLikeUnified when a like is created.
 * Resolves target owner from DB (never from client) and sends notification.
 */

import { createClientFromRequest } from 'npm:@base44/sdk@0.8.23';

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user) return Response.json({ error: 'Unauthorized' }, { status: 401 });

    const { user_id, target_type, target_id } = await req.json();

    if (!user_id || !target_type || !target_id) {
      return Response.json({ error: 'Missing parameters' }, { status: 400 });
    }

    const sr = base44.asServiceRole.entities;
    let target = null;
    let recipient_id = null;
    let title = '';
    let message = '';

    // Resolve target and recipient based on target_type
    if (target_type === 'recipe') {
      const recipes = await sr.Recipe.filter({ id: target_id });
      if (!recipes.length) return Response.json({ error: 'Recipe not found' }, { status: 404 });

      target = recipes[0];
      recipient_id = target.author_id;
      title = 'Someone liked your recipe!';
      message = `${user.full_name || user.display_name || 'Someone'} liked your recipe "${target.title}"`;

    } else if (target_type === 'post') {
      const posts = await sr.Post.filter({ id: target_id });
      if (!posts.length) return Response.json({ error: 'Post not found' }, { status: 404 });

      target = posts[0];
      recipient_id = target.author_id;
      title = 'Someone liked your post!';
      message = `${user.full_name || user.display_name || 'Someone'} liked your post`;

    } else if (target_type === 'comment') {
      const comments = await sr.PostComment.filter({ id: target_id }).catch(() => []);
      if (!comments.length) return Response.json({ error: 'Comment not found' }, { status: 404 });

      target = comments[0];
      recipient_id = target.user_id;
      title = 'Someone liked your comment!';
      message = `${user.full_name || user.display_name || 'Someone'} liked your comment`;
    }

    // Don't notify self
    if (!recipient_id || recipient_id === user_id) {
      return Response.json({ success: true, notified: false });
    }

    // Send push + in-app via sendBasicNotification (0-LLM pipeline)
    try {
      await base44.asServiceRole.functions.invoke('sendBasicNotification', {
        type: 'recipe_liked',
        recipientId: recipient_id,
        recipientEmail: null,
        actorId: user_id,
        actorName: user.full_name || user.display_name || '',
        actorAvatar: user.avatar_url || '',
        data: {
          recipeId: target_type === 'recipe' ? target_id : null,
          recipeTitle: target?.title || '',
        },
      });

      console.log('[onLikeCreated] sendBasicNotification sent', { 
        recipient_id, 
        user_id, 
        target_type, 
        target_id 
      });
      return Response.json({ success: true, notified: true });
    } catch (err) {
      console.warn('[onLikeCreated] Notification failed:', err.message);
      return Response.json({ success: true, notified: false });
    }

  } catch (error) {
    console.error('[onLikeCreated] error:', error.message);
    return Response.json({ error: error.message }, { status: 500 });
  }
});

