/**
 * pauseAccount — User-initiated pause (freeze) for 60 days.
 *
 * CASCADE:
 *   1. Sets User.account_status = 'paused', paused_until, pause_started_at
 *   2. Sets Post.author_account_status = 'paused' for all author's posts
 *      (community_visible is NOT changed — feeds filter on author_account_status)
 *   3. Sets Recipe.author_account_status = 'paused' for all author's public recipes
 *      (is_public is NOT changed — feeds filter on author_account_status)
 *   4. Sets Shop.owner_account_status = 'paused' + is_paused_owner = true (legacy compat)
 *
 * OTP verification MUST have occurred before calling this endpoint.
 */
import { createClientFromRequest } from 'npm:@base44/sdk@0.8.20';

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();

    if (!user) {
      return Response.json({ error: 'Unauthorized' }, { status: 401 });
    }

    if (user.account_status === 'suspended') {
      return Response.json({ error: 'Account is suspended. Contact support.' }, { status: 403 });
    }

    if (user.account_status === 'paused') {
      return Response.json({ already_paused: true, paused_until: user.paused_until });
    }

    const now = new Date();
    const pausedUntil = new Date(now.getTime() + 60 * 24 * 60 * 60 * 1000);
    const sr = base44.asServiceRole.entities;

    // 1. Update user record
    await sr.User.update(user.id, {
      account_status: 'paused',
      paused_until: pausedUntil.toISOString(),
      pause_started_at: now.toISOString(),
    });

    // 2. Cascade to Posts — update all posts by this author
    const userPosts = await sr.Post.filter({ author_id: user.id }, '-created_date', 1000).catch(() => []);
    await Promise.all(
      userPosts.map(p => sr.Post.update(p.id, { author_account_status: 'paused' }).catch(() => {}))
    );

    // 3. Cascade to Recipes — update all public recipes by this author
    const userRecipes = await sr.Recipe.filter({ author_id: user.id }, '-created_date', 1000).catch(() => []);
    await Promise.all(
      userRecipes.map(r => sr.Recipe.update(r.id, { author_account_status: 'paused' }).catch(() => {}))
    );

    // 4. Cascade to Shop — update owner_account_status + legacy flag
    const userShops = await sr.Shop.filter({ owner_id: user.id }).catch(() => []);
    await Promise.all(
      userShops.map(s => sr.Shop.update(s.id, {
        owner_account_status: 'paused',
        is_paused_owner: true,
      }).catch(() => {}))
    );

    console.log(`[PAUSE_ACCOUNT] user=${user.id} paused_until=${pausedUntil.toISOString()} posts=${userPosts.length} recipes=${userRecipes.length} shops=${userShops.length}`);
    return Response.json({ success: true, paused_until: pausedUntil.toISOString() });

  } catch (error) {
    console.error('[PAUSE_ACCOUNT_ERROR]', error.message);
    return Response.json({ error: 'Failed to pause account' }, { status: 500 });
  }
});

