import { createClientFromRequest } from 'npm:@base44/sdk@0.8.6';

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user) {
      return Response.json({ error: 'Unauthorized' }, { status: 401 });
    }

    const body = await req.json();
    const { type, shop_id, category_id, title, body: content, media_url, recipe_id, tags } = body;

    // Validate type
    if (!['community', 'shop'].includes(type)) {
      return Response.json({ error: 'Invalid type' }, { status: 400 });
    }

    // If shop post, verify user owns the shop
    if (type === 'shop') {
      if (!shop_id) {
        return Response.json({ error: 'Shop posts require shop_id' }, { status: 400 });
      }
      const shop = await base44.entities.Shop.read(shop_id);
      if (!shop || shop.owner_id !== user.id) {
        return Response.json({ error: 'You do not own this shop' }, { status: 403 });
      }
    }

    // Free users cannot post to shop
    const entitlements = await base44.functions.invoke('getEntitlements', {});
    if (type === 'shop' && !entitlements?.data?.is_pro) {
      return Response.json({ error: 'Shops require pro subscription' }, { status: 403 });
    }

    const postData = {
      author_id: user.id,
      type,
      shop_id: type === 'shop' ? shop_id : null,
      category_id: type === 'shop' ? category_id : null,
      title,
      body: content,
      media_url,
      recipe_id: type === 'community' ? recipe_id : null,
      tags: tags || [],
      stage: type === 'community' ? 0 : undefined,
      status: 'active',
    };

    const post = await base44.asServiceRole.entities.Post.create(postData);

    // Increment shop post count if applicable
    if (type === 'shop' && shop_id) {
      const shop = await base44.entities.Shop.read(shop_id);
      await base44.asServiceRole.entities.Shop.update(shop_id, {
        post_count: (shop.post_count || 0) + 1,
      });
    }

    return Response.json({ success: true, post_id: post.id }, { status: 201 });
  } catch (error) {
    console.error('[postCreate]', error);
    return Response.json({ error: error.message }, { status: 500 });
  }
});

