      return Response.json({ error: 'Missing group_id' }, { status: 400 });
    }

    // Verify user is a member of the group
    const membership = await base44.entities.GroupMember.filter({
      group_id,
      user_id: user.id,
    });
    if (!membership || membership.length === 0) {
      return Response.json({ error: 'Not a group member' }, { status: 403 });
