/**
 * PRICING SYSTEM UNIT TESTS — deterministic validation
 * Run these to verify correctness
 */

const INGREDIENT_PRICES = {
  "chicken breast": 3.50, "rice": 0.50, "tomato": 0.80, "fake unknown": 0
};

function findPrice(ingredientName) {
  if (!ingredientName) return null;
  const lower = ingredientName.toLowerCase().trim();
  return INGREDIENT_PRICES[lower] || null;
}

export function testPricingScaling() {
  console.log("TEST: Pricing Scaling");

  // Base: 100g chicken (3.50/100g = $0.035/g) = $3.50
  const baseGrams = 100;
  const pricePerHundred = 3.50;
  const costPerGram = pricePerHundred / 100;
  const baseCost = baseGrams * costPerGram;

  // Double servings: 200g = $7.00
  const scaledGrams = baseGrams * 2;
  const scaledCost = scaledGrams * costPerGram;

  console.assert(baseCost === 3.50, "Base cost should be $3.50");
  console.assert(scaledCost === 7.00, "Scaled cost should be $7.00");
  console.log("✓ Scaling test passed");
}

export function testUnknownIngredientHandling() {
  console.log("TEST: Unknown Ingredient Handling");

  // 2 known + 1 unknown
  const items = [
    { name: "chicken breast", base_grams: 100, amount: "100g" },
    { name: "rice", base_grams: 50, amount: "50g" },
    { name: "mystery ingredient", base_grams: 30, amount: "30g" }
  ];

  let totalCost = 0;
  let unknownCount = 0;

  items.forEach(item => {
    const price = findPrice(item.name);
    if (price) {
      totalCost += (item.base_grams / 100) * price;
    } else {
      unknownCount++;
    }
  });

  console.assert(totalCost === 3.50 + 0.25, "Known total should be $3.75");
  console.assert(unknownCount === 1, "Unknown count should be 1");
  console.log("✓ Unknown ingredient test passed");
}

export function testPerServingCalculation() {
  console.log("TEST: Per-Serving Calculation");

  const totalCost = 10.00;
  const servings = 4;
  const perServing = totalCost / servings;

  console.assert(perServing === 2.50, "Per-serving should be $2.50");

  // Scaled servings: 6 servings
  const scaledServings = 6;
  const scaleFactor = scaledServings / servings;
  const scaledTotal = totalCost * scaleFactor;
  const scaledPerServing = scaledTotal / scaledServings;

  console.assert(scaledTotal === 15.00, "Scaled total should be $15.00");
  console.assert(scaledPerServing === 2.50, "Per-serving should remain $2.50");
  console.log("✓ Per-serving test passed");
}

export function testIdempotency() {
  console.log("TEST: Idempotency");

  // Same input, run twice
  const ingredient = "chicken breast";
  const baseGrams = 100;

  const result1 = {
    price: findPrice(ingredient),
    grams: baseGrams,
    cost: (baseGrams / 100) * (findPrice(ingredient) / 100 || 0)
  };

  const result2 = {
    price: findPrice(ingredient),
