/**
 * progressReinsertionPhases — Scheduled background job.
 *
 * Advances restored posts through reinsertion phases automatically:
 *   warmup → reintegrated
 *
 * PHASE LOGIC (deterministic, time + engagement quality based):
 *
 *   warmup:
 *     - Starts at reinsertion_weight = 0.25
 *     - After 24h: advance weight toward 0.60
 *     - After 48h with decent engagement (er_rolling > 0.01 or any new likes): weight → 0.80
 *     - After 72h: weight → 1.0, phase → reintegrated
 *     - If post earns zero engagement after 72h: still reintegrated at 1.0
 *       (no permanent suppression — just no boost)
 *
 * ANTI-ABUSE:
 *   - reinsertion_weight NEVER exceeds 1.0
 *   - restored_at is NOT used as created_at
 *   - posts with multiple restore cycles advance weight slower (handled at restore time)
 *
 * Run this on a schedule every 6 hours.
 * Last redeployed: 2026-04-03
 */
import { createClientFromRequest } from 'npm:@base44/sdk@0.8.25';

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);

    // Allow scheduled (no user) or admin calls
    let isScheduled = false;
    try {
      const user = await base44.auth.me();
      if (user?.role !== 'admin') {
        return Response.json({ error: 'Admin or scheduler access required' }, { status: 403 });
      }
    } catch {
      // Scheduled call — no user context, proceed as service role
      isScheduled = true;
    }

    const sr = base44.asServiceRole;
    const now = Date.now();

    // Fetch all posts currently in warmup phase
    const warmupPosts = await sr.entities.Post.filter({
      reinsertion_phase: 'warmup',
    });

    if (warmupPosts.length === 0) {
      console.log('[progressReinsertion] No posts in warmup phase');
      return Response.json({ ok: true, processed: 0 });
    }

    console.log(`[progressReinsertion] Processing ${warmupPosts.length} warmup posts`);

    const updates = [];

    for (const post of warmupPosts) {
      if (!post.reinsertion_started_at) continue;

      const startedAt = new Date(post.reinsertion_started_at).getTime();
      const hoursElapsed = (now - startedAt) / 3600000;
      const currentWeight = post.reinsertion_weight || 0.25;
      const restoreCount = post.moderation_restore_count || 1;

      // Engagement quality signal — indicates organic re-engagement
      const hasEngagement = (post.er_rolling > 0.01) ||
                            (post.like_count > 0) ||
                            (post.comment_count > 0);

      let newWeight = currentWeight;
      let newPhase = 'warmup';

      // PHASE PROGRESSION MODEL
      // More restore cycles = slower weight gain (anti-abuse)
      const speedFactor = Math.max(0.5, 1.0 - (restoreCount - 1) * 0.15);

      if (hoursElapsed >= 72) {
        // 72h+ → full reintegration regardless of engagement
        newWeight = 1.0;
        newPhase = 'reintegrated';
      } else if (hoursElapsed >= 48) {
        // 48h → strong weight if has engagement, otherwise moderate
        newWeight = hasEngagement
          ? Math.min(1.0, 0.80 * speedFactor)
          : Math.min(1.0, 0.65 * speedFactor);
      } else if (hoursElapsed >= 24) {
        // 24h → moderate weight
        newWeight = Math.min(1.0, 0.50 * speedFactor);
      } else if (hoursElapsed >= 12) {
        // 12h → slight bump from starting 0.25
        newWeight = Math.min(1.0, 0.35 * speedFactor);
      }
      // else: < 12h, keep starting weight (no change)

      // Only update if something changed
      if (newWeight !== currentWeight || newPhase !== post.reinsertion_phase) {
        updates.push({
          id: post.id,
          reinsertion_weight: parseFloat(newWeight.toFixed(3)),
          reinsertion_phase: newPhase,
        });
      }
    }

    // Apply updates
    let updated = 0;
    for (const u of updates) {
      await sr.entities.Post.update(u.id, {
        reinsertion_weight: u.reinsertion_weight,
        reinsertion_phase: u.reinsertion_phase,
      }).catch(e => console.warn(`[progressReinsertion] update failed for ${u.id}:`, e.message));
      updated++;
      console.log(`[progressReinsertion] post=${u.id} phase=${u.reinsertion_phase} weight=${u.reinsertion_weight}`);
    }

    return Response.json({
      ok: true,
      processed: warmupPosts.length,
      updated,
      isScheduled,
    });

  } catch (error) {
    console.error('[progressReinsertionPhases] error:', error);
    return Response.json({ error: error.message }, { status: 500 });
  }
});

/**
 * r2Upload — Cloudflare R2 upload backend
 *
 * Handles all image uploads, replacing Base44 Core.UploadFile.
 * Uses @aws-sdk/client-s3 for reliable S3-compatible signing.
 * Zero Base44 integration credits.
 */
import { createClientFromRequest } from 'npm:@base44/sdk@0.8.25';
import { S3Client, PutObjectCommand } from 'npm:@aws-sdk/client-s3@3.620.0';

const R2_ACCOUNT_ID = Deno.env.get('R2_ACCOUNT_ID');
const R2_ACCESS_KEY_ID = Deno.env.get('R2_ACCESS_KEY_ID');
const R2_SECRET_ACCESS_KEY = Deno.env.get('R2_SECRET_ACCESS_KEY');
const R2_BUCKET_NAME = Deno.env.get('R2_BUCKET_NAME');
const R2_PUBLIC_BASE_URL = Deno.env.get('R2_PUBLIC_BASE_URL');

// Lazy-init S3 client (reused across cold starts)
let s3Client = null;
function getS3Client() {
  if (!s3Client) {
    s3Client = new S3Client({
      region: 'auto',
      endpoint: `https://${R2_ACCOUNT_ID}.r2.cloudflarestorage.com`,
      credentials: {
        accessKeyId: R2_ACCESS_KEY_ID,
        secretAccessKey: R2_SECRET_ACCESS_KEY,
      },
    });
  }
  return s3Client;
}

// Purpose-specific config
const PURPOSE_CONFIG = {
  avatar:         { maxBytes: 200_000, folder: 'avatars',  allowedTypes: ['image/jpeg','image/png','image/webp'] },
  chat_image:     { maxBytes: 500_000, folder: 'chat',     allowedTypes: ['image/jpeg','image/png','image/webp','image/gif'] },
  feedback_image: { maxBytes: 500_000, folder: 'feedback', allowedTypes: ['image/jpeg','image/png','image/webp'] },
  recipe_image:   { maxBytes: 600_000, folder: 'recipes',  allowedTypes: ['image/jpeg','image/png','image/webp'] },
  post_image:     { maxBytes: 600_000, folder: 'posts',    allowedTypes: ['image/jpeg','image/png','image/webp'] },
};

Deno.serve(async (req) => {
  try {
    if (!R2_ACCOUNT_ID || !R2_ACCESS_KEY_ID || !R2_SECRET_ACCESS_KEY || !R2_BUCKET_NAME || !R2_PUBLIC_BASE_URL) {
      return Response.json({ error: 'R2 storage not configured' }, { status: 500 });
    }

    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user) return Response.json({ error: 'Unauthorized' }, { status: 401 });

    const body = await req.json();
    const { file_data, purpose, content_type, context_id } = body;

    const config = PURPOSE_CONFIG[purpose];
    if (!config) {
      return Response.json({ error: `Invalid purpose: ${purpose}` }, { status: 400 });
    }
    if (!file_data) {
      return Response.json({ error: 'file_data required (base64)' }, { status: 400 });
    }

    // Decode base64
    const base64Match = file_data.match(/^data:([^;]+);base64,(.+)$/);
    let binaryData, detectedType;

    if (base64Match) {
      detectedType = base64Match[1];
      const raw = atob(base64Match[2]);
      binaryData = new Uint8Array(raw.length);
      for (let i = 0; i < raw.length; i++) binaryData[i] = raw.charCodeAt(i);
    } else {
      detectedType = content_type || 'image/jpeg';
      const raw = atob(file_data);
      binaryData = new Uint8Array(raw.length);
      for (let i = 0; i < raw.length; i++) binaryData[i] = raw.charCodeAt(i);
    }

    const fileType = detectedType || 'image/jpeg';
    if (!config.allowedTypes.includes(fileType)) {
      return Response.json({ error: `Type ${fileType} not allowed for ${purpose}` }, { status: 400 });
    }
    if (binaryData.length > config.maxBytes) {
      return Response.json({ error: `File too large: ${(binaryData.length/1024).toFixed(0)}KB > ${(config.maxBytes/1024).toFixed(0)}KB limit` }, { status: 400 });
    }

    // Build object key
    const ext = fileType.includes('webp') ? 'webp' : fileType.includes('png') ? 'png' : fileType.includes('gif') ? 'gif' : 'jpg';
    const ts = Date.now();
    const rand = crypto.randomUUID().slice(0, 8);
    const subFolder = purpose === 'chat_image' ? (context_id || 'unknown') : (purpose === 'recipe_image' ? (context_id || 'generated') : user.id);
    const objectKey = `${config.folder}/${subFolder}/${ts}_${rand}.${ext}`;

    // Upload via S3 SDK
    const uploadStart = Date.now();
    const client = getS3Client();
    await client.send(new PutObjectCommand({
      Bucket: R2_BUCKET_NAME,
      Key: objectKey,
      Body: binaryData,
      ContentType: fileType,
    }));
    const uploadDuration = Date.now() - uploadStart;

    const publicBase = R2_PUBLIC_BASE_URL.endsWith('/') ? R2_PUBLIC_BASE_URL.slice(0, -1) : R2_PUBLIC_BASE_URL;
    const fileUrl = `${publicBase}/${objectKey}`;

    // Log (0 credits)
    base44.asServiceRole.functions.invoke('logSystemEvent', {
      event_type: 'file_upload',
      source: 'upload',
      endpoint_name: 'r2Upload',
      origin: 'backend',
      allowed_scope: 'allowed',
      provider_name: 'Cloudflare R2',
      request_type: 'file_upload',
      credits_used: 0,
      raw_cost_source: 'COST_DATA_UNAVAILABLE',
      user_id: user.id,
      success: true,
      duration_ms: uploadDuration,
      raw_usage_metadata: { purpose, object_key: objectKey, file_size_bytes: binaryData.length, content_type: fileType },
    }).catch(e => console.warn('[r2Upload] log failed:', e.message));

    console.log(`[r2Upload] OK purpose=${purpose} user=${user.id} size=${binaryData.length} key=${objectKey} ${uploadDuration}ms`);

    return Response.json({
      success: true,
      file_url: fileUrl,
      object_key: objectKey,
      size_bytes: binaryData.length,
      content_type: fileType,
    });

  } catch (err) {
    console.error('[r2Upload] error:', err.message);
    return Response.json({ error: err.message }, { status: 500 });
  }
});

/**
 * r2UploadFromUrl — Fetches an image from a URL and persists to R2.
 *
 * Used for generated recipe images (Together AI temp URLs → permanent R2).
 * Uses @aws-sdk/client-s3 for reliable S3-compatible signing.
