      Key: objectKey,
      Body: imgBuffer,
      ContentType: contentType,
    }));
    const uploadDuration = Date.now() - uploadStart;

    const publicBase = R2_PUBLIC_BASE_URL.endsWith('/') ? R2_PUBLIC_BASE_URL.slice(0, -1) : R2_PUBLIC_BASE_URL;
    const fileUrl = `${publicBase}/${objectKey}`;

    // Log (0 credits)
    base44.asServiceRole.functions.invoke('logSystemEvent', {
      event_type: 'file_upload',
      source: 'image_gen',
      endpoint_name: 'r2UploadFromUrl',
      origin: 'backend',
      allowed_scope: 'allowed',
      provider_name: 'Cloudflare R2',
      request_type: 'file_upload',
      credits_used: 0,
      raw_cost_source: 'COST_DATA_UNAVAILABLE',
      user_id: user.id,
      success: true,
      duration_ms: fetchDuration + uploadDuration,
      raw_usage_metadata: { purpose, object_key: objectKey, file_size_bytes: imgBuffer.length },
    }).catch(e => console.warn('[r2UploadFromUrl] log failed:', e.message));

    console.log(`[r2UploadFromUrl] OK purpose=${purpose} size=${imgBuffer.length} fetch=${fetchDuration}ms upload=${uploadDuration}ms`);

    return Response.json({ success: true, file_url: fileUrl, object_key: objectKey });

  } catch (err) {
    console.error('[r2UploadFromUrl] error:', err.message);
    return Response.json({ error: err.message }, { status: 500 });
  }
});

/**
 * rebuildMonthlyCostAudit — Authoritative backfill/recompute for monthly credit totals.
 *
 * Fetches ALL IntegrationCostLog records, filters to the target month in-memory,
 * then recomputes tracked_base44_credits_used from ground truth.
 *
 * Also deduplicates MonthlyIntegrationUsageState records for the month (keeps highest).
 * Admin-only endpoint.
 */
import { createClientFromRequest } from 'npm:@base44/sdk@0.8.23';

const BUDGET = 50000;
const THRESHOLD_PCT = 33;
const BASE44_IMAGE_CREDITS = 7;

function getMonthKey(date) {
  const d = date || new Date();
  return `${d.getUTCFullYear()}-${String(d.getUTCMonth() + 1).padStart(2, '0')}`;
}

function getMonthBounds(monthKey) {
  const [year, month] = monthKey.split('-').map(Number);
  const start = new Date(Date.UTC(year, month - 1, 1));
  const end   = new Date(Date.UTC(year, month, 1)); // exclusive
  return { start, end };
}

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user || user.role !== 'admin') {
      return Response.json({ error: 'Admin only' }, { status: 403 });
    }

    const body = await req.json().catch(() => ({}));
    const targetMonth = body.month_key || getMonthKey();
    const { start, end } = getMonthBounds(targetMonth);
    const sr = base44.asServiceRole;

    console.log(`[RebuildAudit] month=${targetMonth} window=${start.toISOString()} → ${end.toISOString()}`);

    // ── Fetch ALL logs (SDK doesn't support range queries) ───────────────────
    // Fetch up to 5000 most recent; filter to month in-memory
    const allLogs = await sr.entities.IntegrationCostLog.list('-created_date', 5000).catch(() => []);
    const monthLogs = allLogs.filter(log => {
      const ts = new Date(log.created_date || log.timestamp || 0);
      return ts >= start && ts < end;
    });

    console.log(`[RebuildAudit] total=${allLogs.length} this_month=${monthLogs.length}`);

    // ── Compute credits ──────────────────────────────────────────────────────
    let totalBase44Credits = 0;
    let llmCredits = 0;
    let base44ImageCredits = 0;
    let togetherImageCredits = 0;
    let otherCredits = 0;
    const byFunction = {};
    const byCategory = {};

    for (const log of monthLogs) {
      const isTogether = log.integration_name?.toLowerCase().includes('together');
      const isBase44Image = log.cost_category === 'image_generation' && !isTogether;

      let realCredits = 0;
      if (isBase44Image) {
        realCredits = BASE44_IMAGE_CREDITS;
        base44ImageCredits += realCredits;
        totalBase44Credits += realCredits;
      } else if (log.cost_category === 'llm') {
        realCredits = log.estimated_cost_units || 1;
        llmCredits += realCredits;
        totalBase44Credits += realCredits;
      } else if (log.cost_category === 'image_generation') {
        togetherImageCredits += 1; // no Base44 credits
      } else {
        realCredits = log.estimated_cost_units || 0;
        otherCredits += realCredits;
        totalBase44Credits += realCredits;
      }

      const fn = log.function_name || 'unknown';
      if (!byFunction[fn]) byFunction[fn] = { credits: 0, count: 0 };
      byFunction[fn].credits += realCredits;
      byFunction[fn].count += 1;

      const cat = log.cost_category || 'other';
      if (!byCategory[cat]) byCategory[cat] = { credits: 0, count: 0 };
      byCategory[cat].credits += realCredits;
      byCategory[cat].count += 1;
    }

    const threshold = Math.round(BUDGET * THRESHOLD_PCT / 100);
    const computedMode = totalBase44Credits >= threshold ? 'togetherai' : 'base44';

    // ── Fetch ALL monthly records for this month, deduplicate ────────────────
    const allMonthRecords = await sr.entities.MonthlyIntegrationUsageState.filter(
      { month_key: targetMonth }, null, 50
    ).catch(() => []);

    console.log(`[RebuildAudit] Found ${allMonthRecords.length} monthly records for ${targetMonth}`);

    let primaryRecord = null;
    if (allMonthRecords.length > 0) {
      // Keep the record with the highest tracked credits (most accurate), or most recently updated
      primaryRecord = allMonthRecords.reduce((best, r) => {
        const bUsed = best.tracked_base44_credits_used || 0;
        const rUsed = r.tracked_base44_credits_used || 0;
        return rUsed > bUsed ? r : best;
      });

      const prevUsed = primaryRecord.tracked_base44_credits_used || 0;

      // Update primary record with recomputed total
      await sr.entities.MonthlyIntegrationUsageState.update(primaryRecord.id, {
        tracked_base44_credits_used: totalBase44Credits,
        current_mode: computedMode,
        threshold_percent: THRESHOLD_PCT,
        threshold_value: threshold,
        monthly_credit_budget: BUDGET,
        last_updated: new Date().toISOString(),
      });

      // Delete duplicate records
      const duplicates = allMonthRecords.filter(r => r.id !== primaryRecord.id);
      for (const dup of duplicates) {
        await sr.entities.MonthlyIntegrationUsageState.delete(dup.id).catch(() => {});
        console.log(`[RebuildAudit] Deleted duplicate record id=${dup.id} (had ${dup.tracked_base44_credits_used || 0} cr)`);
      }

      return Response.json({
        month_key: targetMonth,
        raw_events_scanned: monthLogs.length,
        total_logs_scanned: allLogs.length,
        recomputed_total_credits: totalBase44Credits,
        previous_stored_credits: prevUsed,
        delta: totalBase44Credits - prevUsed,
        duplicates_removed: duplicates.length,
        reconciliation_status: totalBase44Credits === prevUsed ? 'MATCH' : 'UPDATED',
        breakdown: { llm_credits: llmCredits, base44_image_credits: base44ImageCredits, together_image_calls: togetherImageCredits, other_credits: otherCredits },
        threshold, budget: BUDGET, over_threshold: totalBase44Credits >= threshold,
        computed_mode: computedMode, by_function: byFunction, by_category: byCategory,
      });
    } else {
      // Create fresh record
      await sr.entities.MonthlyIntegrationUsageState.create({
        month_key: targetMonth, monthly_credit_budget: BUDGET,
        threshold_percent: THRESHOLD_PCT, threshold_value: threshold,
        tracked_base44_credits_used: totalBase44Credits,
        current_mode: computedMode, last_updated: new Date().toISOString(),
      });
      return Response.json({
        month_key: targetMonth, raw_events_scanned: monthLogs.length,
        total_logs_scanned: allLogs.length, recomputed_total_credits: totalBase44Credits,
        previous_stored_credits: 0, delta: totalBase44Credits,
        duplicates_removed: 0, reconciliation_status: 'CREATED',
        breakdown: { llm_credits: llmCredits, base44_image_credits: base44ImageCredits, together_image_calls: togetherImageCredits, other_credits: otherCredits },
        threshold, budget: BUDGET, over_threshold: totalBase44Credits >= threshold,
        computed_mode: computedMode, by_function: byFunction, by_category: byCategory,
      });
    }
  } catch (err) {
    console.error('[RebuildAudit] Error:', err);
    return Response.json({ error: err.message }, { status: 500 });
  }
});

/**
 * RECIPE INTEGRITY VALIDATOR — STRICT CONCEPT + STRUCTURE VALIDATION
 * 
 * Ensures:
 * - Required concepts (burger patty, shawarma meat) are present in ingredients
 * - Instructions explicitly mention required actions
 * - No missing mandatory components
 * - Hard failure if any requirement violated
 */

import { createClientFromRequest } from 'npm:@base44/sdk@0.8.23';

// CONCEPT REQUIREMENTS — multi-language synonym mapping
const CONCEPT_REQUIREMENTS = {
  'burger': {
    requires: ['patty', 'meat_protein'],
    keywords: ['burger', 'hamburger', 'beef burger', 'chicken burger', 'patty'],
    action_keywords: ['form patty', 'cook patty', 'grill patty', 'fry patty', 'burger patty'],
    image_critical: 'burger with visible patties',
  },
  'shawarma': {
    requires: ['shawarma_meat', 'sliced_meat'],
    keywords: ['shawarma', 'doner', 'kebab meat', 'shawarma meat'],
    action_keywords: ['slice', 'shawarma', 'layer meat', 'cook meat', 'marinate meat'],
    image_critical: 'shawarma meat filling clearly visible',
  },
  'sandwich': {
    requires: ['bread'],
    keywords: ['sandwich'],
    action_keywords: ['assemble', 'sandwich'],
    image_critical: 'sandwich with bread visible',
  },
};

const INGREDIENT_SYNONYMS = {
  'patty': ['patty', 'beef patty', 'meat patty', 'chicken patty', 'ground meat patty', 'burger patty'],
  'shawarma_meat': ['shawarma meat', 'sliced meat', 'doner meat', 'kebab meat', 'shawarma'],
  'sliced_meat': ['sliced meat', 'sliced beef', 'sliced chicken', 'meat slices'],
  'meat_protein': ['beef', 'chicken', 'patty', 'ground meat', 'meat'],
  'bread': ['bread', 'bun', 'pita', 'flatbread', 'tortilla', 'baguette'],
};

function normalizeString(s) {
  return s.toLowerCase().replace(/[^a-z0-9 ]/g, ' ').trim();
}

function detectConcepts(prompt) {
  const normalized = normalizeString(prompt);
  const detected = [];

  for (const [concept, config] of Object.entries(CONCEPT_REQUIREMENTS)) {
    const keywordMatch = config.keywords.some(kw => normalized.includes(kw));
    if (keywordMatch) {
      detected.push(concept);
    }
  }

  return detected;
}

function findMissingIngredients(ingredients, requiredSynonyms) {
  const allIngredientNames = (ingredients || [])
    .flatMap(g => (g.items || []).map(i => normalizeString(i.name)));

  const foundAny = requiredSynonyms.some(synonym => {
    return allIngredientNames.some(ing => ing.includes(normalizeString(synonym)));
  });

  return !foundAny;
}

function findMissingInstructions(instructions, actionKeywords) {
  const allSteps = (instructions || [])
    .map(s => normalizeString(s.instruction || s))
    .join(' ');

  const foundAny = actionKeywords.some(action => allSteps.includes(normalizeString(action)));
  return !foundAny;
}

function validateRecipe(recipe, userPrompt) {
  const debug_log = [];
  const missing_concepts = [];
  const consistency_issues = [];

  // Detect required concepts from prompt
  const detectedConcepts = detectConcepts(userPrompt);
  debug_log.push(`[CONCEPTS_DETECTED] ${detectedConcepts.join(', ') || 'none'}`);

  // Validate each required concept
  for (const concept of detectedConcepts) {
    const config = CONCEPT_REQUIREMENTS[concept];
    if (!config) continue;

    debug_log.push(`[VALIDATING_CONCEPT] ${concept}`);

    // Check each requirement (e.g., patty, meat_protein)
    for (const requirement of config.requires) {
      const synonyms = INGREDIENT_SYNONYMS[requirement] || [];
      const missingIng = findMissingIngredients(recipe.ingredients, synonyms);

      if (missingIng) {
        missing_concepts.push(`${concept}_${requirement}`);
        consistency_issues.push({
          type: 'missing_ingredient',
          concept,
          requirement,
          message: `${concept} requires ${requirement}, but no ingredient found matching: ${synonyms.join(', ')}`,
        });
        debug_log.push(`[MISSING_INGREDIENT] ${concept} → ${requirement}`);
      } else {
        debug_log.push(`[FOUND_INGREDIENT] ${concept} → ${requirement}`);
      }
    }

    // Check instructions mention required actions
    const missingInst = findMissingInstructions(recipe.steps, config.action_keywords);
    if (missingInst) {
      missing_concepts.push(`${concept}_instruction`);
      consistency_issues.push({
        type: 'missing_instruction',
        concept,
        message: `${concept} recipe lacks instructions mentioning: ${config.action_keywords.join(', ')}`,
      });
      debug_log.push(`[MISSING_INSTRUCTION] ${concept}`);
    } else {
      debug_log.push(`[FOUND_INSTRUCTION] ${concept}`);
    }
  }

  const valid = missing_concepts.length === 0;

  return {
    valid,
    missing_concepts: [...new Set(missing_concepts)],
    consistency_issues,
    detected_concepts: detectedConcepts,
    repairs_applied: [],
    debug_log: debug_log.join('\n'),
  };
}

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const { recipe, userPrompt } = await req.json();

    if (!recipe || !userPrompt) {
      return Response.json({ error: 'recipe and userPrompt required' }, { status: 400 });
    }

    const result = validateRecipe(recipe, userPrompt);

    return Response.json({
      valid: result.valid,
      missing_concepts: result.missing_concepts,
      consistency_issues: result.consistency_issues,
      detected_concepts: result.detected_concepts,
      debug: {
        log: result.debug_log,
        repairs_applied: result.repairs_applied,
      },
    });

  } catch (error) {
    console.error('[recipeIntegrityValidator] error:', error.message);
    return Response.json({ error: error.message }, { status: 500 });
  }
});

// Helper functions for recipe servings, ingredient scaling, and nutrition calculations
// Used across Generate, RecipeDetail, CookMode, and MealLogging

/**
 * Filters ingredients to remove items not in userSelectedIds when allowMissing is false
 * @param {Array} ingredients - Array of ingredient groups
 * @param {Set} userSelectedIds - Set of user-selected pantry item IDs
 * @param {boolean} allowMissing - Whether to allow missing ingredients
 * @returns {Object} { filteredIngredients, removedItems }
 */
export function filterIngredientsForMissing(ingredients, userSelectedIds, allowMissing) {
  if (allowMissing || !ingredients) {
    return { filteredIngredients: ingredients, removedItems: [] };
  }

  const removedItems = [];
  const filtered = ingredients.map(group => ({
    ...group,
    items: group.items?.filter(item => {
      // Keep items that were explicitly selected OR are not marked as missing
      if (!item.missing) {
        return true; // Keep non-missing items
      }
      // This is a missing item and allowMissing is false - remove it
      removedItems.push(item.name);
      return false;
    }) || [],
  })).filter(group => group.items.length > 0);

  if (removedItems.length > 0) {
    console.log('[Recipe Generation] Removed inferred items (allow_missing=false):', removedItems);
  }

  return { filteredIngredients: filtered, removedItems };
}

/**
 * Scales ingredient quantities based on cook servings vs recipe servings
 * @param {Array} ingredients - Array of ingredient groups
 * @param {number} recipeServings - Original recipe servings
 * @param {number} cookServings - New servings to cook
 * @returns {Array} Scaled ingredients
 */
export function scaleIngredients(ingredients, recipeServings, cookServings) {
  if (!ingredients || recipeServings === cookServings) {
    return ingredients;
  }

  const scaleFactor = cookServings / recipeServings;

  return ingredients.map(group => ({
    ...group,
    items: group.items?.map(item => {
      // Try to parse and scale the amount
      const amount = parseFloat(item.amount);
      if (!isNaN(amount)) {
        const scaled = Math.round(amount * scaleFactor * 100) / 100;
        return {
          ...item,
          amount: String(scaled),
        };
      }
      // If amount is not a number (e.g., "1 cup"), try to extract number
      const match = item.amount.match(/^([\d.]+)/);
      if (match) {
        const num = parseFloat(match[1]);
        const unit = item.amount.substring(match[1].length).trim();
        const scaled = Math.round(num * scaleFactor * 100) / 100;
        return {
          ...item,
          amount: `${scaled} ${unit}`,
        };
      }
      return item; // Can't scale, return as-is
    }) || [],
  }));
}

/**
 * Calculates nutrition for a given number of servings
 * @param {Object} nutritionPerServing - Nutrition per serving
 * @param {number} servings - Number of servings
 * @returns {Object} Total nutrition
 */
export function calculateNutritionForServings(nutritionPerServing, servings) {
  if (!nutritionPerServing) return null;

  return {
    calories: Math.round(nutritionPerServing.calories * servings),
    protein: Math.round(nutritionPerServing.protein * servings * 10) / 10,
    carbs: Math.round(nutritionPerServing.carbs * servings * 10) / 10,
    fat: Math.round(nutritionPerServing.fat * servings * 10) / 10,
    fiber: nutritionPerServing.fiber ? Math.round(nutritionPerServing.fiber * servings * 10) / 10 : 0,
  };
}

/**
 * Formats nutrition for display
 * @param {Object} nutrition - Nutrition object
 * @param {boolean} showPerServing - Show per serving or total
 * @returns {Object} Formatted nutrition with units
 */
export function formatNutrition(nutrition) {
  if (!nutrition) return null;
  return {
    calories: Math.round(nutrition.calories),
    protein: Math.round(nutrition.protein * 10) / 10,
    carbs: Math.round(nutrition.carbs * 10) / 10,
    fat: Math.round(nutrition.fat * 10) / 10,
    fiber: Math.round((nutrition.fiber || 0) * 10) / 10,
  };
}

/**
 * recordStreakAction — Track streak-eligible user actions
 * 
 * Called when user:
 * - generates recipe
 * - logs recipe
 * - completes cook mode
 * 
 * Updates StreakState and sends STREAK_CONTINUED notification
 */

import { createClientFromRequest } from 'npm:@base44/sdk@0.8.23';

function getLocalDateBucket(date, timeZone) {
  const formatter = new Intl.DateTimeFormat('en-CA', { timeZone, year: 'numeric', month: '2-digit', day: '2-digit' });
  return formatter.format(date);
}

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user) return Response.json({ error: 'Unauthorized' }, { status: 401 });

    const body = await req.json();
    const { action_type } = body; // 'generate', 'log', 'complete_cook'

    if (!['generate', 'log', 'complete_cook'].includes(action_type)) {
      return Response.json({ error: 'Invalid action_type' }, { status: 400 });
    }

    const sr = base44.asServiceRole;
    const now = new Date();
    const userTz = user.timezone || 'UTC';
    const todayBucket = getLocalDateBucket(now, userTz);

    // ── GET OR CREATE STREAK STATE ────────────────────────────────────────
    let streakRecs = await sr.entities.StreakState.filter({ user_id: user.id }, null, 1).catch(() => []);
    let streak = streakRecs[0];

    if (!streak) {
      // First-time user: create new streak
      streak = await sr.entities.StreakState.create({
        user_id: user.id,
        current_streak_count: 1,
        streak_started_at: now.toISOString(),
        last_streak_action_at: now.toISOString(),
        last_action_date_bucket: todayBucket,
        is_active: true,
        timezone: userTz
      });

      console.log(`[RecordStreakAction] New streak started for user ${user.id}`);

      // Don't send notification for first action — just track it
      return Response.json({
        success: true,
        streak_count: 1,
        streak_continued: false,
        is_new_streak: true,
        message: 'Streak started!'
      });
    }

    // ── CHECK IF TODAY'S ACTION ALREADY LOGGED ────────────────────────────
    const lastActionBucket = streak.last_action_date_bucket || '';

    if (lastActionBucket === todayBucket) {
      // Already acted today — don't increment streak
      console.log(`[RecordStreakAction] User ${user.id} already acted today`);
      return Response.json({
        success: true,
        streak_count: streak.current_streak_count,
        streak_continued: false,
        is_duplicate: true,
        message: 'You already cooked today!'
      });
    }

    // ── CALCULATE STREAK IMPACT ───────────────────────────────────────────
    const lastActionDate = new Date(streak.last_streak_action_at);
    const daysSince = Math.floor((now.getTime() - lastActionDate.getTime()) / (1000 * 60 * 60 * 24));

    let newStreakCount = streak.current_streak_count;
    let streakContinued = false;

    if (daysSince === 1) {
      // Consecutive day — increment streak
      newStreakCount = streak.current_streak_count + 1;
      streakContinued = true;
      console.log(`[RecordStreakAction] Streak continued: ${streak.current_streak_count} → ${newStreakCount}`);
    } else if (daysSince > 1) {
      // Streak was lost but user is back — reset to 1
      console.log(`[RecordStreakAction] Streak reset: ${daysSince} days since last action`);
      newStreakCount = 1;
      streakContinued = false;
    } else {
      // Same day (shouldn't reach here)
      return Response.json({
        success: true,
        streak_count: streak.current_streak_count,
        streak_continued: false
      });
    }

    // ── UPDATE STREAK STATE ───────────────────────────────────────────────
    const updateData = {
      current_streak_count: newStreakCount,
      last_streak_action_at: now.toISOString(),
      last_action_date_bucket: todayBucket,
      is_active: true
    };

    // Track best streak
    if (newStreakCount > (streak.best_streak_count || 0)) {
      updateData.best_streak_count = newStreakCount;
    }

    // Reset streak start if needed
    if (newStreakCount === 1 && daysSince > 1) {
      updateData.streak_started_at = now.toISOString();
    }

    await sr.entities.StreakState.update(streak.id, updateData);

    // ── SEND STREAK_CONTINUED NOTIFICATION IF ELIGIBLE ────────────────────
    if (streakContinued) {
      await base44.functions.invoke('sendNotification', {
        user_id: user.id,
        notification_type: 'streak_continued',
        context: { streak_count: newStreakCount }
      }).catch(err => console.warn('[RecordStreakAction] Notification send failed:', err.message));
    }

    return Response.json({
      success: true,
      streak_count: newStreakCount,
      streak_continued: streakContinued,
      best_streak: Math.max(newStreakCount, streak.best_streak_count || 0),
      message: streakContinued ? `Streak continued! 🔥 ${newStreakCount} days` : `You're back on track! 🎉`
    });
  } catch (err) {
    console.error('[recordStreakAction]', err.message);
    return Response.json({ error: err.message }, { status: 500 });
  }
});

