/**
 * recountGroupMembers — Recounts actual active members for one or all groups
 * and updates the Group.member_count field to match reality.
 * 
 * Admin-only. Pass { group_id } for a single group, or {} for all groups.
 */
import { createClientFromRequest } from 'npm:@base44/sdk@0.8.25';

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user || user.role !== 'admin') {
      return Response.json({ error: 'Forbidden: Admin access required' }, { status: 403 });
    }

    const body = await req.json().catch(() => ({}));
    const sr = base44.asServiceRole.entities;

    if (body.group_id) {
      // Single group recount
      const members = await sr.GroupMember.filter({ group_id: body.group_id, status: 'active' });
      await sr.Group.update(body.group_id, { member_count: members.length });
      return Response.json({ success: true, group_id: body.group_id, actual_count: members.length });
    }

    // All groups recount
    const groups = await sr.Group.filter({}, '-created_date', 500);
    const results = [];
    for (const group of groups) {
      const members = await sr.GroupMember.filter({ group_id: group.id, status: 'active' });
      const actual = members.length;
      if (actual !== group.member_count) {
        await sr.Group.update(group.id, { member_count: actual });
        results.push({ id: group.id, name: group.name, was: group.member_count, now: actual });
      }
    }

    return Response.json({ success: true, fixed: results.length, details: results });
  } catch (error) {
    console.error('[recountGroupMembers]', error.message);
    return Response.json({ error: error.message }, { status: 500 });
  }
});

/**
 * refundFailedGeneration — REFUND credit for a failed recipe generation.
 *
 * Called ONLY by the frontend for failures that happen AFTER generateRecipeWithQuota
 * returned successfully (e.g. image generation failed, post-generation validation failed).
 *
 * For backend-native failures (LLM_FAILED, LLM_INVALID, COST_POLICY_BLOCKED),
 * generateRecipeWithQuota already refunds internally. Calling this function
 * for those is a no-op — idempotent via event.status.
 *
 * AUTHORITATIVE REFUND:
 * - Uses event.credit_source (stored at consumption time) for correct bucket targeting.
 * - Clears Pro cooldown anchor on refund (no cooldown for failed generations).
 * - Returns FRESH full quota snapshot so frontend stays synced.
 *
 * INPUT: { event_id: string, reason?: string }
 * OUTPUT: { success, refunded, quota }
 */
import { createClientFromRequest } from 'npm:@base44/sdk@0.8.25';

const OWNER_EMAIL = 'xenodekuu@gmail.com';
const WEEKLY_LIMIT = 2;
const PRO_DAILY_LIMIT = 25;
const COOLDOWN_AFTER_N = 10;
const COOLDOWN_SECONDS = 180;

function getWeekWindow(date) {
  const dayOfWeek = date.getUTCDay();
  const daysToSubtract = dayOfWeek === 0 ? 6 : dayOfWeek - 1;
  const periodStart = new Date(date);
  periodStart.setUTCDate(periodStart.getUTCDate() - daysToSubtract);
  periodStart.setUTCHours(0, 0, 0, 0);
  const periodEnd = new Date(periodStart);
  periodEnd.setUTCDate(periodEnd.getUTCDate() + 7);
  return { periodStart, periodEnd };
}

function getDayKey(date, timezone) {
  try {
    return new Intl.DateTimeFormat('en-CA', { timeZone: timezone, year: 'numeric', month: '2-digit', day: '2-digit' }).format(date);
  } catch { return date.toISOString().slice(0, 10); }
}

async function buildQuotaSnapshot(base44, user, userTz, isPro) {
  const now = new Date();
  if (isPro) {
    const todayKey = getDayKey(now, userTz);
    const proQuota = (await base44.asServiceRole.entities.ProGenerationQuota.filter(
      { user_id: user.id, day_key: todayKey }
    ).catch(() => []))[0] || null;
    const daily = proQuota?.daily_count || 0;
    let cooldownActive = false, cooldownRem = 0;
    if (daily >= COOLDOWN_AFTER_N && proQuota?.last_generation_started_at) {
      const elapsed = (now.getTime() - new Date(proQuota.last_generation_started_at).getTime()) / 1000;
      const rem = Math.ceil(COOLDOWN_SECONDS - elapsed);
      if (rem > 0) { cooldownActive = true; cooldownRem = rem; }
    }
    const proLedger = await base44.asServiceRole.entities.ReferralRewardLedger.filter({
      user_id: user.id, credit_state: 'earned',
    }).catch(() => []);
    const banked = proLedger.reduce((s, e) => s + (e.credits_remaining || 0), 0);
    let nextReset = null;
    try {
      const fmt = new Intl.DateTimeFormat('en-US', { timeZone: userTz, hour: 'numeric', minute: 'numeric', second: 'numeric', hour12: false });
      const parts = fmt.formatToParts(now);
      const h = parseInt(parts.find(p => p.type === 'hour')?.value || '0');
      const m = parseInt(parts.find(p => p.type === 'minute')?.value || '0');
      const s = parseInt(parts.find(p => p.type === 'second')?.value || '0');
      const secsUntilMidnight = ((23 - h) * 3600) + ((59 - m) * 60) + (60 - s);
      nextReset = new Date(now.getTime() + secsUntilMidnight * 1000).toISOString();
    } catch {}
    return {
      is_premium: true,
      pro_daily_limit: PRO_DAILY_LIMIT,
      pro_daily_count: daily,
      pro_remaining_today: Math.max(0, PRO_DAILY_LIMIT - daily),
      pro_cooldown_active: cooldownActive,
      pro_cooldown_remaining_seconds: cooldownRem,
      pro_cooldown_after_n: COOLDOWN_AFTER_N,
      banked_referral_credits: banked,
      next_reset_at: nextReset,
      remaining: null, used: null, limit: null,
    };
  }
  const { periodStart, periodEnd } = getWeekWindow(now);
  const records = await base44.asServiceRole.entities.AiGenerationQuota.filter(
    { user_id: user.id, period_start: periodStart.toISOString() }, null, 20
  ).catch(() => []);
  let q = null;
  if (records.length > 0) {
    records.sort((a, b) => (b.used || 0) - (a.used || 0));
    q = records[0];
  }
  const used = q?.used || 0;
  const remaining = Math.max(0, WEEKLY_LIMIT - used);
  const ledger = await base44.asServiceRole.entities.ReferralRewardLedger.filter({
    user_id: user.id, credit_state: 'earned',
  }).catch(() => []);
  const banked = ledger.reduce((s, e) => s + (e.credits_remaining || 0), 0);
  return {
    is_premium: false,
    remaining, used, limit: WEEKLY_LIMIT,
    banked_referral_credits: banked,
    total_available: remaining + banked,
    period_start: periodStart.toISOString(),
    period_end: periodEnd.toISOString(),
    next_reset_at: periodEnd.toISOString(),
    resets_at: periodEnd.toISOString(),
  };
}

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user) return Response.json({ error: 'Unauthorized' }, { status: 401 });

    const body = await req.json();
    const { event_id, reason, client_timezone } = body;
    if (!event_id) return Response.json({ error: 'event_id required' }, { status: 400 });

    const events = await base44.asServiceRole.entities.AiGenerationEvent.filter(
      { id: event_id }, null, 1
    ).catch(() => []);
    const event = events[0];
    if (!event) return Response.json({ error: 'Event not found' }, { status: 404 });
    if (event.user_id !== user.id) return Response.json({ error: 'Forbidden' }, { status: 403 });

    const now = new Date();
    // CRITICAL: same tz resolution as getAiQuotaAdvanced — must agree on day_key.
    const userTz = (user.timezone && user.timezone !== 'UTC')
      ? user.timezone
      : (client_timezone || user.timezone || 'UTC');
    const isOwner = user.email === OWNER_EMAIL;

    // Determine isPro — for quota snapshot shape
    let isPro = isOwner;
    if (!isOwner) {
      const subs = await base44.asServiceRole.entities.Subscription.filter(
        { created_by: user.email }, null, 10
      ).catch(() => []);
      const nowMs = now.getTime();
      const ENTITLED = new Set(['pro', 'vip', 'trial']);
      isPro = subs.some(s => {
        if (!ENTITLED.has(s.plan_type)) return false;
        if (s.status === 'active' || s.status === 'active_paid' || s.status === 'trialing') return true;
        if (s.status === 'grace_period' && s.grace_period_end) return new Date(s.grace_period_end).getTime() > nowMs;
        if ((s.status === 'canceled' || s.status === 'canceled_pending_expiry') && s.current_period_end) return new Date(s.current_period_end).getTime() > nowMs;
        return false;
      });
    }

    // Idempotency: already refunded / cancelled → return fresh quota (no-op on credits)
    if (event.status === 'refunded' || event.status === 'cancelled') {
      return Response.json({
        success: true, refunded: false, already_refunded: true,
        quota: await buildQuotaSnapshot(base44, user, userTz, isPro),
      });
    }
    if (event.status === 'saved' || event.status === 'meal_logged') {
      return Response.json({ error: 'Cannot refund a saved or logged recipe', code: 'ALREADY_COMMITTED' }, { status: 409 });
    }

    // AUTHORITATIVE REFUND via stored credit_source
    const creditSource = event.credit_source || (isPro ? 'pro_daily' : 'weekly_free');

    if (creditSource === 'pro_daily') {
      const todayKey = getDayKey(now, userTz);
      const proQuotas = await base44.asServiceRole.entities.ProGenerationQuota.filter(
        { user_id: user.id, day_key: todayKey }, null, 5
      ).catch(() => []);
      const proQuota = proQuotas[0];
      const currentCount = proQuota?.daily_count || 0;
      if (proQuota?.id && currentCount > 0) {
        await base44.asServiceRole.entities.ProGenerationQuota.update(proQuota.id, {
          daily_count: Math.max(0, currentCount - 1),
          last_generation_started_at: null,
          generation_in_progress: false,
          updated_at: now.toISOString(),
        });
        console.log(`[REFUND_PRO_DAILY] user=${user.id} event=${event_id} reason=${reason || '-'}`);
      } else if (proQuota?.id) {
        // Always clear cooldown anchor on refund path — even if count was 0
        await base44.asServiceRole.entities.ProGenerationQuota.update(proQuota.id, {
          last_generation_started_at: null,
          generation_in_progress: false,
          updated_at: now.toISOString(),
        });
      }
    } else if (creditSource === 'weekly_free') {
      const { periodStart } = getWeekWindow(now);
      const records = await base44.asServiceRole.entities.AiGenerationQuota.filter(
        { user_id: user.id, period_start: periodStart.toISOString() }, null, 10
      ).catch(() => []);
      if (records.length > 0) {
        records.sort((a, b) => (b.used || 0) - (a.used || 0));
        const qr = records[0];
        if ((qr.used || 0) > 0) {
          await base44.asServiceRole.entities.AiGenerationQuota.update(qr.id, {
            used: Math.max(0, (qr.used || 0) - 1),
            updated_at: now.toISOString(),
          });
          console.log(`[REFUND_FREE] user=${user.id} event=${event_id} reason=${reason || '-'}`);
        }
      }
    } else if (creditSource === 'banked_referral' || creditSource === 'pro_banked') {
      const ledgerEntries = await base44.asServiceRole.entities.ReferralRewardLedger.filter({
        user_id: user.id,
      }).catch(() => []);
      const recentConsumed = ledgerEntries
        .filter(e => e.credit_state === 'consumed' || (e.credits_remaining || 0) === 0)
        .sort((a, b) => new Date(b.updated_date || b.created_date) - new Date(a.updated_date || a.created_date));
      if (recentConsumed.length > 0) {
        const entry = recentConsumed[0];
        await base44.asServiceRole.entities.ReferralRewardLedger.update(entry.id, {
          credits_remaining: 1, credit_state: 'earned', consumed_at: null,
        });
        console.log(`[REFUND_BANKED] user=${user.id} event=${event_id} reason=${reason || '-'}`);
      }
      // Also clear Pro cooldown if this was a Pro user
      if (isPro) {
        const todayKey = getDayKey(now, userTz);
        const proQuotas = await base44.asServiceRole.entities.ProGenerationQuota.filter(
          { user_id: user.id, day_key: todayKey }, null, 5
        ).catch(() => []);
        if (proQuotas[0]?.id) {
          await base44.asServiceRole.entities.ProGenerationQuota.update(proQuotas[0].id, {
            last_generation_started_at: null,
            generation_in_progress: false,
            updated_at: now.toISOString(),
          });
        }
      }
    }

    // Mark event refunded (idempotency anchor)
    await base44.asServiceRole.entities.AiGenerationEvent.update(event_id, {
      status: 'refunded',
    }).catch(() => {});

    return Response.json({
      success: true,
      refunded: true,
      quota: await buildQuotaSnapshot(base44, user, userTz, isPro),
    });
  } catch (err) {
    console.error('[refundFailedGeneration] FATAL:', err.message);
    return Response.json({ error: err.message }, { status: 500 });
  }
});

/**
 * releaseProGenerationSlot
 *
 * Clears the generation_in_progress flag on the PRO quota record after a
 * generation completes or fails. Must be called from the frontend after
 * every generation attempt (success or error) to unlock the slot.
 *
 * If the generation failed (success=false), also decrements the count so
 * the failed attempt doesn't consume a slot.
 */
import { createClientFromRequest } from 'npm:@base44/sdk@0.8.23';

function getDayKey(date, timezone) {
  try {
    const formatter = new Intl.DateTimeFormat('en-CA', {
      timeZone: timezone,
      year: 'numeric',
      month: '2-digit',
      day: '2-digit',
    });
    return formatter.format(date);
  } catch {
    return date.toISOString().slice(0, 10);
  }
}

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user) return Response.json({ error: 'Unauthorized' }, { status: 401 });

    const body = await req.json().catch(() => ({}));
    // success=false → generation failed → don't count it
    const { success = true } = body;

    const sr = base44.asServiceRole;
    const now = new Date();
    const userTz = user.timezone || 'UTC';
    const todayKey = getDayKey(now, userTz);

    const quotas = await sr.entities.ProGenerationQuota.filter({
      user_id: user.id,
      day_key: todayKey,
    }).catch(() => []);

    const quota = quotas[0];
    if (!quota) {
      // No record found — nothing to release
      return Response.json({ ok: true, skipped: true });
    }

    const updates = {
      generation_in_progress: false,
      updated_at: now.toISOString(),
    };

    // If generation failed, roll back the count increment
    if (!success && quota.daily_count > 0) {
      updates.daily_count = quota.daily_count - 1;
      console.log(`[releaseProGenerationSlot] Rolling back count for user=${user.id} count=${quota.daily_count} → ${quota.daily_count - 1}`);
    }

    await sr.entities.ProGenerationQuota.update(quota.id, updates);

    return Response.json({ ok: true, success, daily_count: updates.daily_count ?? quota.daily_count });
  } catch (error) {
    console.error('[releaseProGenerationSlot]', error.message);
    return Response.json({ error: error.message }, { status: 500 });
  }
});

/**
 * ROLLBACK QUOTA SLOT
 * 
 * Called when generation FAILS or is CANCELLED.
 * Reverses the quota consumption from unifiedGenerationQuotaGate.
 */

import { createClientFromRequest } from 'npm:@base44/sdk@0.8.23';

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user) return Response.json({ error: 'Unauthorized' }, { status: 401 });

    const body = await req.json();
    const { reservation_id, credit_source } = body;

    if (!reservation_id || !credit_source) {
      return Response.json({ error: 'reservation_id and credit_source required' }, { status: 400 });
    }

    // Fetch the reservation
    const reservation = await base44.asServiceRole.entities.AiGenerationEvent.filter({
      id: reservation_id,
      status: 'reserved',
    }).catch(() => []);

    if (!reservation || reservation.length === 0) {
      console.warn(`[ReleaseQuota] Reservation ${reservation_id} not found or already consumed`);
      return Response.json({ success: true, already_released: true });
    }

    const res = reservation[0];

    if (credit_source === 'weekly') {
      // Rollback weekly quota
      const userTz = user.timezone || 'UTC';
      const now = new Date();
      const { periodStart } = getWeekWindow(now, userTz);

      const quota = (
        await base44.asServiceRole.entities.AiGenerationQuota.filter({
          user_id: user.id,
          period_start: periodStart.toISOString(),
        }, null, 1)
      )[0];

      if (quota && quota.used > 0) {
        await base44.asServiceRole.entities.AiGenerationQuota.update(quota.id, {
          used: quota.used - 1,
          updated_at: now.toISOString(),
        });
      }
    } else if (credit_source === 'banked') {
      // Rollback banked credit
      const ledgerEntries = await base44.asServiceRole.entities.ReferralRewardLedger.filter({
        user_id: user.id,
        credit_state: 'earned',
      }).catch(() => []);

      const sortedEntries = ledgerEntries
        .filter(e => (e.credits_remaining || 0) > 0)
        .sort((a, b) => new Date(a.created_date).getTime() - new Date(b.created_date).getTime());

      if (sortedEntries.length > 0) {
        const entry = sortedEntries[0];
        await base44.asServiceRole.entities.ReferralRewardLedger.update(entry.id, {
          credits_remaining: (entry.credits_remaining || 0) + 1,
          credit_state: 'earned',
        });
      }
    } else if (credit_source === 'pro_daily') {
      // Rollback pro daily slot
      await base44.asServiceRole.functions.invoke('releaseProGenerationSlot', { 
        success: false 
      }).catch(err => console.warn('[ReleaseQuota] Failed to release pro slot:', err.message));
    }

    // Mark reservation as cancelled
    await base44.asServiceRole.entities.AiGenerationEvent.update(res.id, {
      status: 'cancelled',
    });

    console.log(`[ReleaseQuota] Released quota for user=${user.id} source=${credit_source}`);

    return Response.json({ success: true, released: true });
  } catch (err) {
    console.error('[ReleaseQuota]', err.message);
    return Response.json({ error: err.message }, { status: 500 });
  }
});

function getWeekWindow(date, timezone) {
  const formatter = new Intl.DateTimeFormat('en-US', {
    timeZone: timezone,
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
    weekday: 'long',
  });

  const parts = formatter.formatToParts(date);
  const weekday = parts.find(p => p.type === 'weekday')?.value;
  const dayOfWeekNum = weekday === 'Monday' ? 1 : weekday === 'Tuesday' ? 2 : weekday === 'Wednesday' ? 3 : weekday === 'Thursday' ? 4 : weekday === 'Friday' ? 5 : weekday === 'Saturday' ? 6 : 0;
  const daysToSubtract = dayOfWeekNum === 0 ? 6 : dayOfWeekNum - 1;
  const periodStart = new Date(date);
  periodStart.setDate(periodStart.getDate() - daysToSubtract);
  periodStart.setUTCHours(0, 0, 0, 0);
  const offset = getTimezoneOffset(timezone);
  periodStart.setUTCHours(offset, 0, 0, 0);
  const periodEnd = new Date(periodStart);
  periodEnd.setDate(periodEnd.getDate() + 7);
  return { periodStart, periodEnd };
}

function getTimezoneOffset(timezone) {
  const formatter = new Intl.DateTimeFormat('en-US', {
    timeZone: timezone,
    hour: '2-digit',
    hour12: false,
  });
  const testDate = new Date('2000-01-01T00:00:00Z');
  const parts = formatter.formatToParts(testDate);
  return -parseInt(parts.find(p => p.type === 'hour')?.value || '0', 10);
}

import { createClientFromRequest } from 'npm:@base44/sdk@0.8.23';

/**
 * removeFollower — Remove a specific user from your followers.
 * This deletes the Follow edge where target_user_id follows the viewer (not vice versa).
 */
Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const viewer = await base44.auth.me();
    if (!viewer?.id) return Response.json({ error: 'Unauthorized' }, { status: 401 });

    const body = await req.json().catch(() => ({}));
    const { target_user_id } = body;
    if (!target_user_id) return Response.json({ error: 'target_user_id required' }, { status: 400 });

    const sr = base44.asServiceRole;

    // Find the Follow record where target_user_id follows the viewer
    const follows = await sr.entities.Follow.filter({
      follower_id: target_user_id,
      followed_id: viewer.id,
    }).catch(() => []);

    if (follows.length === 0) {
      return Response.json({ success: true, message: 'No follow relationship found' });
    }

    // Delete all matching follow records
    await Promise.all(follows.map(f => sr.entities.Follow.delete(f.id)));

    // Also remove any pending FollowRequest if it exists
    const requests = await sr.entities.FollowRequest.filter({
      requester_id: target_user_id,
      target_id: viewer.id,
    }).catch(() => []);
    if (requests.length > 0) {
      await Promise.all(requests.map(r => sr.entities.FollowRequest.delete(r.id)));
    }

    return Response.json({ success: true });
  } catch (error) {
    console.error('removeFollower error:', error);
    return Response.json({ error: error.message }, { status: 500 });
  }
});
